insert into platform_topic_master (subject_slug, topic_slug, page_name, sections)
values
('computer-science', '1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', '{"learn": {"enabled": true, "items": [{"title": "What is the purpose of the CPU?", "html": "<h4>The brain that follows instructions</h4>\n<ul>\n<li>The <strong>CPU (Central Processing Unit)</strong> is the part of the computer that carries out all the processing.</li>\n<li>Its purpose is to <strong>fetch, decode and execute instructions</strong> — every program you run, from a game to a spreadsheet, is just a long list of instructions the CPU works through one at a time.</li>\n<li>Think of a chef working through a recipe: read the next step (fetch), work out what it means (decode), then do it (execute) — and repeat until the dish is finished.</li>\n</ul>\n<h4>Where the instructions come from</h4>\n<ul>\n<li>Programs and their data are stored in <strong>main memory (RAM)</strong> while they are running.</li>\n<li>The CPU constantly pulls instructions out of memory, processes them, and sends the results back — billions of times every second.</li>\n<li>This design — the program stored in memory alongside its data, with one processor working through it — is called <strong>von Neumann architecture</strong>, and it is how almost every computer works.</li>\n</ul>\n<h4>Say it the exam way</h4>\n<ul>\n<li>If a question asks for the <em>purpose</em> of the CPU, the safe two-part answer is: it <strong>processes instructions</strong> by <strong>carrying out the fetch–execute cycle</strong>.</li>\n</ul>", "check": {"question": "Which of these best states the PURPOSE of the CPU?", "options": ["It fetches, decodes and executes instructions", "It permanently stores all the user''s files and programs", "It connects the whole computer to the internet", "It displays moving images on the screen"], "answer": 0, "explain": "The CPU is the processor — it works through program instructions using the fetch–decode–execute cycle. Storing files is the job of storage, not the CPU."}}, {"title": "The fetch–decode–execute cycle", "html": "<h4>The cycle the CPU repeats forever</h4>\n<ul>\n<li><strong>Fetch:</strong> the next instruction is copied from main memory into the CPU. The <strong>program counter</strong> holds the address of the instruction to fetch, and it <strong>increments</strong> (moves on by one) during each cycle so the CPU knows where the next instruction is.</li>\n<li><strong>Decode:</strong> the <strong>control unit</strong> works out what the instruction actually means — what operation is needed, and what data it needs.</li>\n<li><strong>Execute:</strong> the instruction is carried out — a calculation in the ALU, moving some data, or jumping to a different instruction.</li>\n<li>Then the cycle <strong>repeats</strong>, continuously, for as long as the computer is switched on.</li>\n</ul>\n<h4>Events the exam loves to ask for</h4>\n<ul>\n<li>\"Identify events that take place during the fetch–execute cycle\" is a classic question. Safe answers: an instruction is <strong>fetched from memory</strong>; the instruction is <strong>decoded</strong>; the instruction is <strong>executed</strong>; the <strong>program counter is incremented</strong>; the process <strong>repeats</strong>.</li>\n</ul>\n<h4>How fast does this happen?</h4>\n<ul>\n<li>The <strong>clock speed</strong> tells you how many cycles happen per second — a 3&nbsp;GHz CPU runs about 3 billion fetch–execute cycles every second (much more on this in 1.1.2).</li>\n</ul>", "check": {"question": "During the fetch–decode–execute cycle, what does the program counter do?", "options": ["It stores the actual data that has just been fetched from memory", "It increments each cycle to point to the next instruction", "It counts how many programs are currently open and running", "It performs the CPU''s mathematical calculations"], "answer": 1, "explain": "The program counter holds the ADDRESS of the next instruction and increments each cycle. It never counts programs — that''s the classic trap."}}, {"title": "Inside the CPU: ALU, CU, cache and registers", "html": "<h4>The four common components</h4>\n<ul>\n<li><strong>ALU (Arithmetic Logic Unit):</strong> performs the <strong>mathematical calculations</strong> (add, subtract…) and <strong>logical operations</strong> (comparisons like greater-than, AND/OR decisions).</li>\n<li><strong>CU (Control Unit):</strong> <strong>decodes instructions</strong> and sends signals to <strong>coordinate</strong> the rest of the processor — it directs the fetch–execute cycle and the flow of data. It doesn''t do the maths itself; it''s the conductor, not the orchestra.</li>\n<li><strong>Cache:</strong> a small amount of <strong>very fast memory inside the CPU</strong> that stores <strong>frequently used instructions and data</strong>, so the CPU doesn''t have to wait for the (slower) RAM every time.</li>\n<li><strong>Registers:</strong> tiny, extremely fast storage locations inside the CPU — each one holds <strong>a single piece of data or one address</strong> that the CPU is working with right now.</li>\n</ul>\n<h4>Storage sizes, smallest to biggest</h4>\n<ul>\n<li>Register (one value) → cache (small, inside the CPU) → RAM (all currently running programs). Speed goes the opposite way: registers are fastest, RAM is slowest of the three.</li>\n</ul>\n<h4>The wording that wins marks</h4>\n<ul>\n<li>Component questions are marked on precise verbs: the ALU <strong>performs</strong> calculations, the CU <strong>decodes and coordinates</strong>, cache and registers <strong>store</strong>. Mixing these up (e.g. \"the CU executes the instructions\") is the most common way to lose the mark.</li>\n</ul>", "check": {"question": "A computer program needs to check whether one number is bigger than another. Which CPU component carries out this comparison?", "options": ["The control unit", "The program counter", "The cache", "The ALU"], "answer": 3, "explain": "Comparisons are logical operations, and the ALU performs all mathematical calculations and logical operations. The CU decodes and coordinates; it doesn''t do the comparison itself."}}, {"title": "Von Neumann architecture: the four registers", "html": "<h4>The registers you must know by name</h4>\n<ul>\n<li><strong>Program counter (PC):</strong> stores the <strong>address</strong> of the <strong>next instruction</strong> to be fetched from memory. It increments during each fetch–execute cycle.</li>\n<li><strong>MAR (Memory Address Register):</strong> stores the <strong>address</strong> of the data or instruction that is about to be fetched from memory — or the address where data is about to be stored.</li>\n<li><strong>MDR (Memory Data Register):</strong> stores the actual <strong>data or instruction</strong> that has just been fetched from memory, or that is about to be written to memory.</li>\n<li><strong>Accumulator (ACC):</strong> stores the <strong>results of calculations</strong> carried out by the ALU.</li>\n</ul>\n<h4>The one distinction that decides the marks: address or data?</h4>\n<ul>\n<li>An <strong>address</strong> is the location — like a house number. <strong>Data</strong> is what''s actually stored there — like the people inside the house.</li>\n<li><strong>PC and MAR store addresses.</strong> <strong>MDR and ACC store data.</strong> If you remember only one thing from this card, make it that line.</li>\n</ul>\n<h4>A pair that works together</h4>\n<ul>\n<li>The MAR and MDR are a team: the MAR says <em>where</em> in memory to look, and the MDR holds <em>what</em> was found there. That''s why \"the MAR stores the data\" is always wrong — it only ever holds the location.</li>\n</ul>", "check": {"question": "Which pair of registers store an ADDRESS rather than data?", "options": ["MDR and MAR", "Accumulator and program counter", "Program counter and MAR", "MDR and accumulator"], "answer": 2, "explain": "PC and MAR hold addresses (locations in memory). The MDR holds the data/instruction itself, and the accumulator holds the results of ALU calculations."}}, {"title": "Putting it together: CPU, RAM and cache in action", "html": "<h4>What happens when you open an app</h4>\n<ul>\n<li>The program''s <strong>instructions and data are loaded into RAM</strong> (main memory) — the CPU cannot work on things directly from the hard drive or SSD.</li>\n<li>The CPU then <strong>fetches instructions from RAM</strong>, one at a time, and <strong>executes</strong> them using the fetch–decode–execute cycle.</li>\n<li>Instructions the CPU keeps coming back to are copied into <strong>cache</strong>, so next time they can be grabbed much faster than going back to RAM.</li>\n</ul>\n<h4>Why cache makes a CPU faster (the 2-mark version)</h4>\n<ul>\n<li>Cache stores frequently used instructions and data <strong>which can be accessed faster than RAM</strong> — so a bigger cache means the CPU waits less, improving performance.</li>\n<li>One subtle extra: a <em>huge</em> cache can bring diminishing returns, because it takes longer to search through more cache.</li>\n</ul>\n<h4>Answering \"describe how the CPU and RAM work together\"</h4>\n<ul>\n<li>Three-step structure: instructions/data are <strong>stored in RAM</strong> → they are <strong>fetched from RAM by the CPU</strong> → the CPU <strong>executes/processes</strong> them. Three steps, three marks.</li>\n</ul>", "check": {"question": "Why does cache memory speed up the CPU?", "options": ["It adds extra long-term storage space for the user''s own files", "It holds frequently used instructions, which load faster than from RAM", "It permanently stores a full backup copy of the entire operating system", "It physically increases the CPU''s underlying clock speed"], "answer": 1, "explain": "Cache holds the instructions and data the CPU uses most, inside the CPU itself — so they can be accessed far faster than going out to RAM. It doesn''t change the clock speed or store files."}}]}, "terms": {"enabled": true, "pairs": [{"term": "CPU", "definition": "Central Processing Unit — processes instructions via the fetch–execute cycle"}, {"term": "Fetch–decode–execute cycle", "definition": "The repeated cycle: get the instruction, work out what it means, carry it out"}, {"term": "Fetch", "definition": "Copy the next instruction from main memory into the CPU"}, {"term": "Decode", "definition": "The control unit works out what the instruction means"}, {"term": "Execute", "definition": "Carry out the instruction (calculation, data move or jump)"}, {"term": "ALU", "definition": "Arithmetic Logic Unit — performs calculations and logical operations"}, {"term": "Control unit (CU)", "definition": "Decodes instructions and coordinates the processor with control signals"}, {"term": "Cache", "definition": "Small, fast memory in the CPU storing frequently used instructions and data"}, {"term": "Register", "definition": "Tiny, very fast CPU storage holding one value or one address"}, {"term": "Program counter (PC)", "definition": "Stores the address of the next instruction; increments each cycle"}, {"term": "MAR", "definition": "Memory Address Register — stores the address to fetch from or write to"}, {"term": "MDR", "definition": "Memory Data Register — stores the data/instruction fetched from memory"}, {"term": "Accumulator (ACC)", "definition": "Stores the results of ALU calculations"}, {"term": "Von Neumann architecture", "definition": "Design where instructions and data share the same memory"}, {"term": "Main memory (RAM)", "definition": "Where a running program''s instructions and data are held for the CPU"}, {"term": "Address vs data", "definition": "PC and MAR store addresses; MDR and ACC store data/results"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is the purpose of the CPU?", "options": ["To supply power to every other component in the case", "To render and display graphics on the monitor", "To fetch, decode and execute instructions", "To permanently store the user''s files and documents"], "answer": 2, "explain": "The CPU processes instructions by running the fetch–decode–execute cycle continuously. Storage, power and display are handled by other components."}, {"question": "Put the three stages of the CPU''s cycle in the correct order.", "options": ["Decode → fetch → execute", "Fetch → execute → decode", "Execute → decode → fetch", "Fetch → decode → execute"], "answer": 3, "explain": "The instruction is fetched from memory first, then decoded by the control unit so the CPU knows what to do, then executed."}, {"question": "Which CPU component performs mathematical calculations and logical operations?", "options": ["Program counter", "Cache", "ALU", "Control unit"], "answer": 2, "explain": "The ALU (Arithmetic Logic Unit) does all the maths and logic — comparisons, additions, AND/OR operations. The CU coordinates; it doesn''t calculate."}, {"question": "Which CPU component decodes instructions and coordinates the actions of the processor?", "options": ["The ALU, which carries out calculations", "The control unit", "The MDR, which holds fetched data", "The accumulator, which stores results"], "answer": 1, "explain": "The control unit decodes each instruction and sends signals to synchronise and direct the other components. Remember: it directs the work, the ALU does the maths."}, {"question": "What does the program counter store?", "options": ["The actual data that was just fetched from memory", "The address of the next instruction to fetch", "The result of the most recent ALU calculation", "The number of programs currently open and running"], "answer": 1, "explain": "The PC stores the ADDRESS of the next instruction and increments each cycle. It counts nothing — despite the name."}, {"question": "Data has just been fetched from main memory. Which register is it now sitting in?", "options": ["Program counter", "MAR", "Accumulator", "MDR"], "answer": 3, "explain": "The MDR (Memory Data Register) holds the data or instruction just fetched from memory. The MAR held the address it came from."}, {"question": "The ALU has just added two numbers. Where is the result stored?", "options": ["In the program counter", "In the MAR", "In the accumulator", "In cache"], "answer": 2, "explain": "The accumulator stores the results of ALU calculations. The MAR and PC only ever hold addresses."}, {"question": "Which TWO registers store addresses rather than data?", "options": ["Accumulator and program counter", "Program counter and MAR", "MAR and MDR", "MDR and accumulator"], "answer": 1, "explain": "PC and MAR hold locations in memory (addresses); MDR holds the data/instruction itself and the accumulator holds calculation results."}, {"question": "What is cache?", "options": ["Slow, large-capacity memory outside the CPU, used for long-term file storage and backups", "A single register that stores one memory address for the CPU", "The part of the CPU that performs all calculations and logic", "Small, very fast memory inside the CPU holding frequently used instructions"], "answer": 3, "explain": "Cache is small, very fast memory inside the CPU holding frequently used instructions and data — so the CPU avoids waiting for RAM."}, {"question": "A register is best described as...", "options": ["A tiny, very fast CPU storage location holding one value or address", "A large area of memory used to hold currently running programs and their data", "A processing unit that decodes and interprets program instructions", "A type of secondary storage used to store files permanently"], "answer": 0, "explain": "Registers are tiny storage locations inside the CPU — each holds a single value or address the CPU is using right now."}, {"question": "During one fetch–execute cycle, which of these events happens?", "options": ["The program counter is incremented", "Every byte of RAM is cleared and reset", "The entire operating system reboots", "The hard drive is automatically defragmented"], "answer": 0, "explain": "Each cycle: an instruction is fetched, decoded, executed — and the program counter increments so the CPU knows where the next instruction is."}, {"question": "Why can the CPU access an instruction in cache faster than the same instruction in RAM?", "options": ["Cache has a much larger storage capacity than RAM", "Cache sits inside the CPU, so data travels a much shorter distance", "RAM only stores data while the computer is switched off", "Instructions stored in cache have already been executed once in advance"], "answer": 1, "explain": "Cache sits inside the CPU and is built from faster memory, so frequently used instructions don''t have to make the slower trip from RAM."}]}, "fib": {"enabled": true, "questions": [{"text": "The CPU''s purpose is to [fetch], decode and [execute] instructions."}, {"text": "Instructions are decoded by the [control] unit, while calculations are performed by the [ALU]."}, {"text": "The program counter stores the [address] of the next instruction, and it [increments] during each fetch–execute cycle."}, {"text": "The MAR stores an address, but the MDR stores the [data] fetched from memory."}, {"text": "The accumulator stores the [results] of calculations carried out by the ALU."}, {"text": "Cache is a small amount of [fast] memory inside the CPU that stores [frequently] used instructions."}, {"text": "While a program is running, its instructions and data are stored in main memory, also called [RAM]."}]}, "tf": {"enabled": true, "questions": [{"statement": "The program counter counts how many programs are currently running.", "answer": false, "explain": "Despite its name, the PC counts nothing — it stores the ADDRESS of the next instruction to be fetched, and increments each cycle."}, {"statement": "The MDR stores the data or instruction that has just been fetched from memory.", "answer": true, "explain": "That''s exactly its job — the MAR says where to look in memory, and the MDR holds what was found there."}, {"statement": "The control unit performs all the mathematical calculations in the CPU.", "answer": false, "explain": "Calculations and logical operations are the ALU''s job. The control unit decodes instructions and coordinates the processor."}, {"statement": "Cache is a small amount of fast memory located inside the CPU.", "answer": true, "explain": "Cache sits inside the CPU and stores frequently used instructions and data, so the CPU doesn''t have to keep fetching them from slower RAM."}, {"statement": "The MAR stores the data that has been fetched from memory.", "answer": false, "explain": "The MAR only ever stores an ADDRESS — the location to fetch from or write to. The data itself goes in the MDR."}, {"statement": "The accumulator stores the results of ALU calculations.", "answer": true, "explain": "Correct — the ALU does the maths and the accumulator holds the result. Saying it stores ''the calculations'' rather than the RESULTS is a known mark-loser."}, {"statement": "Registers are large stores of memory located on the motherboard.", "answer": false, "explain": "Registers are tiny — each holds one value or address — and they are inside the CPU itself, which is why they''re the fastest storage in the computer."}, {"statement": "The fetch–decode–execute cycle repeats continuously while the computer is running.", "answer": true, "explain": "The CPU never stops cycling: fetch, decode, execute, increment the program counter, repeat — billions of times per second."}]}, "misc": {"enabled": true, "items": [{"myth": "The program counter keeps track of how many programs are running (or counts the instructions processed).", "truth": "The program counter stores the ADDRESS of the next instruction to be fetched from memory, and it increments during each fetch–execute cycle. It is a signpost, not a tally. If your answer to any PC question doesn''t contain the word ''address'', it is almost certainly wrong.", "check": {"question": "Which answer would earn the mark for ''state the purpose of the program counter''?", "options": ["It stores the address of the next instruction to fetch", "It counts the total number of fetch–execute cycles completed", "It counts how many programs are currently open", "It stores every instruction that is currently running"], "answer": 0, "explain": "Only the address answer scores. Counting programs or cycles is the classic misconception, and ''stores the instructions'' confuses the PC with the MDR."}}, {"myth": "The control unit executes the instructions and does the processing itself.", "truth": "The control unit DECODES instructions and sends signals to coordinate and synchronise the rest of the processor — it directs the fetch–execute cycle but doesn''t do the calculations. Weak answer: ''the CU sends signals to components'' (what for?). Strong answer: ''the CU decodes instructions and sends signals to coordinate the flow of data through the processor.'' Say what the signals achieve.", "check": {"question": "Which is the BEST description of the control unit?", "options": ["It performs all the CPU''s mathematical operations directly", "It sends signals to synchronise the other components", "It decodes instructions and coordinates the processor", "It permanently stores the most frequently used program instructions"], "answer": 2, "explain": "Option B is the trap — it''s true but incomplete, because it only covers coordination and leaves out decoding. The full answer names decoding AND coordination."}}, {"myth": "''The MAR fetches the data from memory'' — describing registers with action verbs.", "truth": "Registers STORE; they don''t fetch, take or retrieve. Mark schemes explicitly refuse purposes written as actions. Level 0: ''the MAR fetches data''. Level 1: ''the MAR stores an address''. Full marks: ''the MAR stores the address of the data or instruction that is to be fetched from, or written to, memory.'' Always start a register''s purpose with ''stores...''.", "check": {"question": "A question asks for the purpose of the MDR. Which answer style earns the mark?", "options": ["\"The MDR stores the data fetched from memory\"", "\"The MDR actively moves data around the CPU\"", "\"The MDR is just a general register in the CPU\"", "\"The MDR actively fetches data from RAM\""], "answer": 0, "explain": "Registers store. Answers built on fetches/moves/takes describe actions the register doesn''t perform, and ''it is a register'' just restates the question."}}, {"myth": "The MAR and the PC store data, and the MDR stores an address — they''re all much the same.", "truth": "The address/data split is the whole game: PC and MAR store ADDRESSES (locations in memory); MDR and accumulator store DATA (the instruction/data itself, or a result). A typical error chain in table questions: writing MAR where PC belongs, then ''using up'' MDR on the next row too. Check the definition for the word ''address'' before you commit a register name.", "check": {"question": "A definition in an exam table reads: ''Stores the address of the next instruction to be fetched. Increments during each cycle.'' Which register is it?", "options": ["Program counter (PC)", "MAR (Memory Address Register)", "MDR (Memory Data Register)", "Accumulator (ACC)"], "answer": 0, "explain": "''Address of the NEXT INSTRUCTION'' plus ''increments'' can only be the program counter. The MAR stores the address currently being fetched from — no incrementing."}}, {"myth": "A dual-core processor is faster because it simply runs twice as many instructions per second.", "truth": "The mark is for the idea of the cores working AT THE SAME TIME: each core can execute a separate instruction (or a different part of the program) simultaneously — that''s parallel processing. ''It runs more instructions per second'' on its own could just describe a faster clock. And be ready for the twist: some software can''t be split across cores, so performance doesn''t always double.", "check": {"question": "Which sentence correctly explains why a dual-core CPU can improve performance?", "options": ["\"Having two cores automatically doubles the cache size\"", "\"It can process more instructions every single second\"", "\"Each core runs a separate instruction simultaneously\"", "\"Two cores always double the CPU''s clock speed\""], "answer": 2, "explain": "The winning idea is simultaneous execution — parallel processing. Doubling clock speed or cache isn''t what a second core does, and ''more instructions per second'' misses the ''at the same time'' requirement."}}]}, "tips": {"enabled": true, "items": [{"title": "Register questions: from 0 to full marks", "html": "<p>Here is the same answer to <em>\"State the purpose of the MAR\"</em> at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"The MAR is a register inside the CPU.\"</p>\n<ul>\n<li>True, but it just restates the question — no purpose given.</li>\n</ul>\n\n<p><strong>❌ 0 marks:</strong> \"The MAR fetches the data from memory.\"</p>\n<ul>\n<li>Registers <strong>store</strong> — purposes written as actions (fetches, takes, retrieves) are refused.</li>\n</ul>\n\n<p><strong>⚠️ Borderline:</strong> \"The MAR stores an address.\"</p>\n<ul>\n<li>The verb is right, but WHICH address? Too vague to be safe.</li>\n</ul>\n\n<p><strong>✅ Full marks:</strong> \"The MAR stores the address of the data or instruction that is to be fetched from, or written to, memory.\"</p>\n\n<p><strong>The pattern for all four registers:</strong> \"Stores the…\" + address or data + what it belongs to:</p>\n<ul>\n<li>PC → stores the <strong>address of the next instruction</strong> to be fetched (and increments each cycle)</li>\n<li>MAR → stores the <strong>address</strong> of the data/instruction being fetched or written</li>\n<li>MDR → stores the <strong>data/instruction</strong> fetched from memory</li>\n<li>ACC → stores the <strong>results</strong> of ALU calculations</li>\n</ul>", "check": {"question": "Why does \"the MAR fetches data from memory\" score 0?", "options": ["The MAR does not actually exist as a real CPU register", "The answer given is simply too short for the mark", "Registers STORE data — describing them as performing an action is wrong", "Register names must always be spelled out in full rather than abbreviated like MAR"], "answer": 2, "explain": "Registers are storage locations. The fetching is done by the CPU as a whole during the cycle — the register just holds the address or data involved."}}, {"title": "2-mark ''explain why it''s faster'' questions: the …which means… chain", "html": "<p>Performance explanations (clock speed, cache, cores) are marked as <strong>point + development</strong>. One fact = 1 mark; linking it to performance = the 2nd mark.</p>\n\n<p><strong>Example: \"Explain why a 3.2 GHz CPU usually runs faster than a 1.2 GHz CPU.\" [2]</strong></p>\n\n<p><strong>⚠️ 1 mark:</strong> \"3.2 GHz is a higher clock speed.\"</p>\n<ul>\n<li>Correct point, no development — the chain stops.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"3.2 GHz is a higher clock speed, so it runs more fetch–execute cycles per second, <strong>which means</strong> more instructions can be executed per second.\"</p>\n\n<p><strong>The same chain works for cache:</strong> \"Cache stores frequently used instructions → they can be accessed faster than from RAM → so the CPU spends less time waiting.\"</p>\n\n<p><strong>Two traps:</strong></p>\n<ul>\n<li>\"Cache is faster than RAM\" alone scores nothing — faster at <em>what</em>? Name the access to instructions/data.</li>\n<li>For dual core, the development must include <strong>at the same time</strong> (parallel execution) — \"more instructions per second\" alone reads like clock speed.</li>\n</ul>", "check": {"question": "\"More cache improves performance\" scores 1 out of 2. What''s missing?", "options": ["The specific brand and full model name of the CPU", "A fully labelled diagram showing every one of the CPU''s components", "The precise size of the cache, given exactly in megabytes or gigabytes", "The chain: cache stores instructions accessible faster than RAM"], "answer": 3, "explain": "The second mark is for developing the point: WHAT cache stores and WHY that speeds things up (faster access than RAM). Assertions about performance without the mechanism stay on 1 mark."}}, {"title": "Table and matching questions: play them like a puzzle", "html": "<p>1.1.1 is full of table-completion and match-the-definition questions. Technique matters as much as knowledge:</p>\n\n<p><strong>1. Scan the whole table before writing anything.</strong></p>\n<ul>\n<li>A classic error chain: writing MAR in the row that should be PC, then forcing MDR into the MAR row — one early slip wrecks three rows. Pencil in all rows mentally first.</li>\n</ul>\n\n<p><strong>2. Use the address/data keyword test.</strong></p>\n<ul>\n<li>Definition contains \"address of the next instruction\" + \"increments\" → PC. \"Address\" of data being fetched/stored → MAR. \"Data/instruction fetched\" → MDR. \"Result\" → accumulator. \"Calculations/logical operations\" → ALU. \"Coordinates/decodes/signals\" → CU.</li>\n</ul>\n\n<p><strong>3. In draw-one-line matching, count the boxes.</strong></p>\n<ul>\n<li>If there are more definitions than components, at least one definition is a decoy — expect something plausible-sounding like \"keeps the clock in sync\".</li>\n<li>Drawing two lines from one component scores 0 for that component. One from, one to.</li>\n</ul>\n\n<p><strong>4. In tick-grids, extra ticks kill the row.</strong></p>\n<ul>\n<li>Each row is marked as a whole: the correct ticks AND no extras. If unsure, tick only what you''re confident in — a stray extra tick turns a right answer into 0 for that row.</li>\n</ul>", "check": {"question": "In a tick-grid question, a student ticks the two correct boxes in a row PLUS one extra box. What happens?", "options": ["The examiner simply ignores the extra tick mark", "They still receive partial credit of 2 out of 3 for the row", "They score 0 for that row — extra ticks void it", "They simply lose 1 mark from their overall total"], "answer": 2, "explain": "Rows are all-or-nothing: right ticks with any extra tick scores 0 for that row. Tick with intent, not with hope."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>A CPU contains several registers.</p><p>Complete the table by naming <strong>two</strong> different registers and stating what each one stores.</p><table><tr><th>Register</th><th>What it stores</th></tr><tr><td>(1)</td><td>(2)</td></tr><tr><td>(3)</td><td>(4)</td></tr></table>", "marks": 2, "hint": "Pick the two registers you can describe most precisely. Start each answer with ''Stores...'' — never ''fetches'' or ''gets'' — and be exact about whether it stores an ADDRESS or DATA.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per correct register-and-purpose pair, to a maximum of 2)</h5>\n<ul>\n<li><strong>Program counter (PC)</strong> — stores the address of the next instruction to be fetched from memory.</li>\n<li><strong>Memory address register (MAR)</strong> — stores the address of the data or instruction currently being accessed in memory.</li>\n<li><strong>Memory data register (MDR)</strong> — stores the data or instruction that has just been fetched from memory, or is about to be written to it.</li>\n<li><strong>Accumulator (ACC)</strong> — stores the result of a calculation carried out by the ALU.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The purpose must describe what the register STORES, not an action such as \"fetches\" or \"gets\".</li>\n<li>Accept \"points to\" as an alternative to \"stores\".</li>\n<li>Accept CIR or IR (current instruction register / instruction register) as an alternative register, provided the purpose given is that it stores the instruction currently being decoded or executed.</li>\n<li>Accept \"memory buffer register\" as an alternative name for the MDR.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Students often name the MAR and MDR confidently but muddle their purposes — remember the MAR stores an ADDRESS (where to look), while the MDR stores the DATA found there. The program counter is also frequently confused with a simple counter of how many programs are open, rather than a register holding the address of the next instruction. The accumulator''s purpose is sometimes given as \"stores calculations\", which is too vague — it stores the RESULT of a calculation.</p>\n</div>"}, {"question": "<p>A student says: \"The CPU just runs the program.\"</p><p>Describe what actually happens during the fetch-execute cycle to make this possible.</p>", "marks": 2, "hint": "Give two separate stages of the cycle — where the instruction comes from, and what is then done with it. Use ''instructions/data'', not ''information'' or ''programs''.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point, to a maximum of 2)</h5>\n<ul>\n<li>An instruction (or data) is fetched from memory (RAM)</li>\n<li>The registers are used to hold the instruction and its address as it moves through the CPU, or a correctly named register storing an address or piece of data</li>\n<li>The instruction is decoded, e.g. split into the operation needed and the data it acts on</li>\n<li>The instruction is then executed/carried out</li>\n<li>The ALU performs any arithmetic or logical part of the instruction</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept \"carried out\" or \"processed\" as alternatives to \"executed\".</li>\n<li>Ignore inaccurate references to registers or components, unless a specific register is correctly described as storing an address or piece of data.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Many students can say that instructions are fetched from memory and then processed, but stop there. Stronger answers name a specific middle stage — decoding — rather than jumping straight from fetch to execute. A frequent slip is describing the CPU as processing \"information\" or \"programs\" rather than instructions or data, which is not precise enough to be credited.</p>\n</div>"}, {"question": "<p>Complete the table by naming <strong>two</strong> different registers used during the fetch-execute cycle and stating the purpose of each register.</p><table><tr><th>Register</th><th>Purpose</th></tr><tr><td>(1)</td><td>(2)</td></tr><tr><td>(3)</td><td>(4)</td></tr></table>", "marks": 4, "hint": "1 mark per register name, 1 per matching purpose. PC and MAR store ADDRESSES; MDR stores the DATA/INSTRUCTION; the accumulator stores RESULTS.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for naming each register, 1 mark for each matching purpose)</h5>\n<ul>\n<li><strong>Program counter (PC)</strong> — stores the address of the next instruction to be fetched from memory.</li>\n<li><strong>Memory address register (MAR)</strong> — stores the address of the data or instruction currently being accessed in memory.</li>\n<li><strong>Memory data register (MDR)</strong> — stores the data or instruction that has just been fetched from memory, or is about to be written to it.</li>\n<li><strong>Accumulator (ACC)</strong> — stores the result of a calculation performed by the ALU.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The purpose must describe what is stored, not an action such as fetches, takes or retrieves. Read the full purpose given and award a correct point wherever it appears.</li>\n<li>Accept CIR or IR (current instruction register / instruction register) as an alternative register, provided the purpose given is that it stores the instruction currently being decoded or executed. Accept \"memory buffer register\" for the MDR.</li>\n<li>If the register name given is incorrect, do not credit the purpose even if it is accurate.</li>\n<li>For the PC and MAR, accept \"pointer to\" as an alternative to \"stores the address\".</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Students can usually name at least one register correctly, but often struggle to give a purpose specific enough to be credited — \"the MAR stores an address\" is fine, but \"the MAR stores data\" is not, because that describes the MDR instead. A frequent misconception is describing the program counter as something that counts how many programs are running, rather than a register holding the address of the next instruction.</p>\n</div>"}, {"question": "<p>Complete the table by writing the missing name or definition for each CPU component or register.</p><table><tr><th>CPU component or register</th><th>Definition</th></tr><tr><td><strong>(A)</strong></td><td>Stores the data or instruction that has just been fetched from memory, ready to be used by the CPU.</td></tr><tr><td>Cache</td><td><strong>(B)</strong></td></tr><tr><td><strong>(C)</strong></td><td>Sends signals that coordinate the fetch-execute cycle and decodes instructions.</td></tr><tr><td><strong>(D)</strong></td><td>Performs the arithmetic and logical operations needed to carry out an instruction.</td></tr></table>", "marks": 4, "hint": "Read all four rows before answering — row A''s clue is ''just been fetched'', not ''about to be fetched''. For row C, the clues are about DIRECTING the cycle, not doing the maths itself.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each correct name or definition)</h5>\n<ul>\n<li><strong>A: Memory data register (MDR)</strong></li>\n<li><strong>B (cache definition):</strong> small amount of very fast memory inside the CPU that stores frequently or recently used instructions and data, so they do not have to be fetched from the (slower) RAM each time</li>\n<li><strong>C: Control unit (CU)</strong></li>\n<li><strong>D: Arithmetic logic unit (ALU)</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Read the whole answer given for B and award the point wherever it appears.</li>\n<li>\"Cache is fast memory\" alone is not enough for B — the answer must say what it stores and why that helps.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>This question asks students to work backwards from a definition to the correct name, which catches out anyone who has only learned the components in one direction. The MDR and MAR are the pair most often swapped here — remember the MDR holds the data that was FOUND, not the address used to find it. For the control unit, simply saying it \"controls the CPU\" is too vague; the definition needs to say what that control actually achieves, such as decoding instructions or coordinating the cycle.</p>\n</div>"}, {"question": "<p>This laptop''s processor uses Von Neumann architecture, which includes several registers.</p><p>Identify <strong>two</strong> registers used in Von Neumann architecture.</p>", "marks": 2, "hint": "Names only — no purposes needed here. There are four to choose from; write the two you''re surest of, one per line.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each, to a maximum of 2)</h5>\n<ul>\n<li>Program counter (PC)</li>\n<li>Memory address register (MAR)</li>\n<li>Memory data register (MDR)</li>\n<li>Accumulator (ACC)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept other correctly named registers, e.g. CIR or IR.</li>\n<li>Only credit the first two distinct registers given.</li>\n</ul>\n</div>"}, {"question": "<p>State the purpose of a CPU.</p>", "marks": 1, "hint": "One precise sentence — what does the CPU do with instructions?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>The CPU processes instructions, by carrying out the fetch-decode-execute cycle</li>\n</ul>\n</div>"}, {"question": "<p>State what is meant by a <strong>single-core, 3.6 GHz</strong> processor.</p>", "marks": 2, "hint": "Two separate definitions for two marks: one for what ''single-core'' means, one for what 3.6 GHz means in cycles per second.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point, to a maximum of 2)</h5>\n<ul>\n<li>Single-core means the processor has only one processing unit (core)</li>\n<li>3.6 GHz means it can carry out about 3.6 billion fetch-execute cycles every second</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept \"processor\" as an alternative to \"core\" for the first point.</li>\n<li>Accept \"instructions\" as an alternative to \"cycles\" for the second point.</li>\n</ul>\n</div>"}, {"question": "<p>Draw <strong>one</strong> line from each CPU part to its correct definition.</p><p>(There are more definitions than parts — one definition is not used.)</p>", "marks": 4, "hint": "One line from each part, exactly. There are five definitions for four parts, so one is a decoy — watch for the plausible-sounding one about keeping cores in sync.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per correct line from component to definition)</h5>\n<ul>\n<li>Cache → <strong>E</strong> (fast memory inside the CPU that stores recently used instructions and data)</li>\n<li>Control unit (CU) → <strong>B</strong> (sends signals that coordinate the fetch-execute cycle)</li>\n<li>Arithmetic logic unit (ALU) → <strong>A</strong> (performs arithmetic and logical operations)</li>\n<li>Register → <strong>D</strong> (a tiny storage location inside the CPU that holds a single piece of data or one address)</li>\n<li>C (\"keeps every core running at exactly the same clock speed\") is the unused decoy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Two lines drawn from the same component score 0 for that component.</li>\n</ul>\n</div>"}, {"question": "<p>The table has five parts of a computer, and four statements.</p><p>Tick (✓) <strong>one or more</strong> boxes in each row to identify which part(s) each statement describes.</p>", "marks": 4, "hint": "Some rows need more than one tick — but any EXTRA tick voids the whole row. ''Stores an address'' fits exactly two of these; ''is a register'' fits exactly three.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for correct ticks and correct gaps on each row)</h5>\n<ul>\n<li><strong>It stores an address:</strong> PC ✓, MAR ✓</li>\n<li><strong>It performs calculations:</strong> ALU ✓</li>\n<li><strong>It is a register:</strong> PC ✓, MDR ✓, MAR ✓</li>\n<li><strong>It stores frequently used data so the CPU doesn''t have to fetch it from RAM each time:</strong> Cache ✓</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Any extra tick on a row, or a missing correct tick, scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Identify the name of <strong>one</strong> register not given in part (i) and describe its purpose.</p>", "marks": 2, "hint": "Part (i) used the PC, MDR and MAR — so which of the four von Neumann registers is left? Purpose starts with ''Stores…''.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for register, e.g. accumulator</li>\n<li>1 mark for description, e.g. stores the result of a calculation carried out by the ALU</li>\n</ul>\n</div>"}, {"question": "<p>Computer X has a single-core, 2.8 GHz processor.</p><p>Computer Y has a single-core, 1.4 GHz processor.</p><p>Explain why Computer X will usually run faster than Computer Y.</p>", "marks": 2, "hint": "Point + development: name the higher clock speed, then chain it — more fetch-execute cycles per second, which means more instructions executed per second.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point, to a maximum of 2)</h5>\n<ul>\n<li>Computer X has a higher/faster clock speed</li>\n<li>A 2.8 GHz processor can carry out more fetch-execute cycles per second than a 1.4 GHz processor</li>\n<li>…so more instructions can be executed per second</li>\n</ul>\n</div>"}, {"question": "<p>Identify <strong>two</strong> events that take place during the fetch-execute cycle.</p>", "marks": 2, "hint": "Short, factual events — think of the three stage names plus what happens to the program counter.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark for each correct answer, to a maximum of 2)</h5>\n<ul>\n<li>An instruction is fetched from memory</li>\n<li>The instruction is then decoded</li>\n<li>The decoded instruction is then executed so that the CPU performs continuously</li>\n<li>The process is repeated</li>\n<li>The program counter is incremented</li>\n<li>The instruction is transferred to the MDR</li>\n<li>The address of the instruction to be fetched is placed in the MAR</li>\n</ul>\n</div>"}, {"question": "<p>The following sentences describe the purpose and main parts of a CPU.</p><p>Complete the sentences by filling in the missing words.</p>", "marks": 5, "hint": "Blank (2) is what the CPU actually executes — ''data'' on its own is too vague. Blank (3) is where a running program''s instructions and data are held.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks (1 mark for each completed word)</h5>\n<p>CPU stands for <strong>Central Processing Unit</strong>. Its purpose is to fetch, decode and execute the <strong>instructions</strong> that make up a running program.</p>\n<p>These are stored, along with their data, in main <strong>memory</strong> (RAM) while the program is running.</p>\n<p>Inside the CPU, the Arithmetic <strong>Logic</strong> Unit carries out calculations, and the <strong>Control</strong> Unit decodes instructions and coordinates the cycle.</p>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept RAM as an alternative to \"memory\". Accept \"and Logic\" as an alternative for blank 4.</li>\n<li>Do not accept \"programs\" or \"data\" alone for blank 2 — the CPU executes instructions, not data or whole programs.</li>\n<li>Accept \"central processor unit\" as an alternative to \"Central Processing Unit\".</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>This kind of gap-fill is usually completed well, but two blanks catch students out. \"Data\" is a common wrong answer for the instructions blank, but data on its own is not executed — only instructions are. For blank 3, some students name a register such as the MDR instead of memory, forgetting that a whole running program (not just the single instruction currently being processed) is held in RAM.</p>\n</div>"}, {"question": "<p>Priya is comparing two laptops: one has a single-core processor, the other has a dual-core processor.</p><p>Explain why having a dual-core processor might improve the performance of the laptop.</p>", "marks": 2, "hint": "The winning idea is the two cores working AT THE SAME TIME — each core executing a separate instruction simultaneously. ''More instructions per second'' alone won''t score.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point, to a maximum of 2)</h5>\n<ul>\n<li>A dual-core processor has two processing cores — double the number of a single-core processor</li>\n<li>Parallel processing can take place: each core can execute a separate instruction, or run a different part of a program, at the same time</li>\n<li>…which means the laptop can get through more work in the same amount of time</li>\n<li>This can also enable more effective multitasking, since different programs can run on different cores at the same time</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The answer needs the idea of the cores working at the same time — not just \"it can run twice as many instructions\" without \"at the same time\".</li>\n<li>Do not award \"more instructions per second\" alone — this could also be achieved with a faster clock speed rather than more cores.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>It is common to see an answer that restates the question — \"a dual-core processor performs better because it has two cores\" — without explaining why. The mark needs the idea that both cores can process instructions at the same time; without \"at the same time\" (or an equivalent), the point about extra processing power is too vague to credit.</p>\n</div>"}, {"question": "<p>One of the laptops Priya is comparing has 256 kilobytes of cache, and the other has 1 megabyte of cache.</p><p>Explain how the amount of cache can affect the performance of a CPU.</p>", "marks": 2, "hint": "Chain it: what cache stores → why that''s quicker than RAM → what a bigger cache therefore does for performance. ''Cache is faster than RAM'' alone scores nothing.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point, to a maximum of 2)</h5>\n<ul>\n<li>Cache stores frequently or recently used instructions or data that the CPU is likely to need again</li>\n<li>…these can be accessed more quickly than fetching them from RAM, so more cache means the CPU spends less time waiting, improving performance</li>\n<li>Too little cache means more instructions have to be fetched from the slower RAM, reducing performance</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Simply defining cache as \"fast memory\" or \"close to the CPU\" is not enough on its own.</li>\n<li>\"Cache is faster than RAM\" alone does not score — the answer must say faster AT WHAT (accessing instructions or data).</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Students usually know that cache stores frequently used data, but many stop there without explaining the performance link — that faster access to cache means less time spent waiting on RAM. A vague answer such as \"more cache is better\" without saying why will not pick up the second mark.</p>\n</div>"}, {"question": "<p>A systems designer is explaining a new computer''s Von Neumann architecture to a trainee.</p><p>Describe the purpose of <strong>two</strong> registers used in Von Neumann architecture.</p>", "marks": 4, "hint": "Name each register AND describe it fully — ''the MAR stores an address'' is not enough; say WHICH address. Up to 2 marks per register.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per bullet, to a maximum of 2 per register)</h5>\n<ul>\n<li><strong>MAR (memory address register)</strong> — stores the address/location of the data or instruction currently being accessed, or about to be read/written</li>\n<li><strong>MDR (memory data register)</strong> — stores the data or instruction that has just been fetched from memory, or is about to be written to it</li>\n<li><strong>Program counter</strong> — stores the address/location of the next instruction to be run</li>\n<li><strong>Accumulator</strong> — stores the result of a calculation performed by the ALU</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>\"The MAR stores an address\" alone is not specific enough for the description mark — it must say it is the address of the data/instruction being accessed.</li>\n<li>Accept CIR or IR as an alternative register, provided the purpose given is that it stores the instruction currently being executed. Accept \"memory buffer register\" for the MDR.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Most students can name two registers correctly, but fewer describe them precisely enough to earn both marks for each one. A very common near-miss is \"the memory address register stores the address\" — this repeats the register''s name without saying WHICH address, so the description mark is not awarded.</p>\n</div>"}, {"question": "<p>Identify <strong>four</strong> events that take place during the fetch-execute cycle.</p>", "marks": 4, "hint": "The three stages give you three events; the program counter incrementing (or the cycle repeating) gives you the fourth.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each correct answer, to a maximum of 4)</h5>\n<ul>\n<li>An instruction is fetched from memory</li>\n<li>The instruction is then decoded</li>\n<li>The decoded instruction is then executed so that the CPU performs continuously</li>\n<li>The process is repeated</li>\n<li>The program counter is incremented</li>\n<li>The instruction is transferred to the MDR</li>\n<li>The address of the instruction to be fetched is placed in the MAR</li>\n</ul>\n</div>"}, {"question": "<p>Describe how the CPU and RAM work together to allow the games console to run a game.</p>", "marks": 3, "hint": "Three steps, three marks: where the game''s instructions are STORED, who FETCHES them from there, and what then happens to them.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>The game''s instructions and data (while it is running) are stored in RAM</li>\n<li>…these are fetched from RAM by the CPU</li>\n<li>…where the instructions are then decoded and executed</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>If the CPU and RAM are described completely separately, only award the second point if it is clearly stated that instructions are fetched FROM RAM specifically.</li>\n<li>A reference to the fetch-execute cycle taking place inside the CPU is enough to award the third point.</li>\n</ul>\n</div>"}, {"question": "<p>The handheld console also uses cache memory. Describe the purpose of cache memory.</p>", "marks": 2, "hint": "What does cache store, and what does that save the CPU from having to do?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>Cache stores instructions or data that are used frequently, recently, or are likely to be needed again soon</li>\n<li>This means they do not need to be fetched from RAM each time, which speeds up access and improves performance</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-1-2-cpu-performance', '1.1.2 CPU Performance', '{"learn": {"enabled": true, "items": [{"title": "What actually makes a CPU fast?", "html": "<h4>The three characteristics you must know</h4>\n<ul>\n<li>OCR only ever asks about <strong>three</strong> characteristics of the CPU itself:</li>\n<li><strong>Clock speed</strong> — how many fetch–execute cycles it can run each second.</li>\n<li><strong>Cache size</strong> — how much very fast memory sits inside the CPU.</li>\n<li><strong>Number of cores</strong> — how many processing units the CPU has.</li>\n<li>Learn those three as a set. A question worth 3 marks that says \"give three characteristics of a CPU that affect its performance\" is asking for exactly this list.</li>\n</ul>\n<h4>Say the whole phrase, every time</h4>\n<ul>\n<li>The single most expensive mistake on this topic is writing half the term. <strong>\"Clock\" is not an answer — \"clock speed\" is.</strong> <strong>\"Cores\" is not an answer — \"number of cores\" is.</strong> \"Cache\" on its own is not an answer — \"cache size\" is.</li>\n<li>Why? Because a characteristic must be something that can be <em>measured or changed</em>. Every CPU has a clock and has cores; what differs between CPUs is the <strong>speed</strong> of the clock and the <strong>number</strong> of cores.</li>\n</ul>\n<h4>The CPU isn''t the whole story</h4>\n<ul>\n<li>Other parts of the computer also affect how fast it feels: <strong>RAM</strong>, <strong>secondary storage</strong> (an SSD instead of a hard disk drive), and the <strong>graphics card (GPU)</strong>.</li>\n<li>Keep these in a separate mental box. If a question says \"characteristics of <em>the CPU</em>\", RAM scores nothing. If it says \"other parts that could improve performance\", RAM/SSD/GPU are exactly what''s wanted.</li>\n</ul>", "check": {"question": "A question asks for three characteristics of a CPU that affect performance. Which answer would score full marks?", "options": ["Clock, cache and cores, without stating speed, size or number", "Clock speed, cache size, number of cores", "RAM capacity, SSD storage space, graphics card power", "Processing speed, internal memory, power consumption"], "answer": 1, "explain": "The three characteristics must be stated in full — it is the clock SPEED, the cache SIZE and the NUMBER of cores that vary between CPUs. RAM/SSD/GPU are other parts of the computer, not characteristics of the CPU."}}, {"title": "Clock speed — how many cycles per second?", "html": "<h4>What clock speed actually measures</h4>\n<ul>\n<li>The CPU has a <strong>clock</strong> that \"ticks\" at a fixed rate. On each tick the CPU carries out one <strong>fetch–execute cycle</strong>.</li>\n<li><strong>Clock speed is the number of fetch–execute cycles the CPU can carry out per second.</strong> It is measured in <strong>hertz (Hz)</strong>: 1 Hz = 1 cycle per second.</li>\n<li><strong>GHz (gigahertz) = billions of cycles per second.</strong> So a <strong>3.8 GHz</strong> processor performs about <strong>3.8 billion fetch–execute cycles every second</strong> (3,800,000,000).</li>\n</ul>\n<h4>The exam translation you must be able to do</h4>\n<ul>\n<li>\"Describe what is meant by a clock speed of 3.8 GHz\" wants <strong>two</strong> things: what clock speed <em>is</em> (cycles/instructions per second), and the <strong>number</strong> (3.8 billion per second).</li>\n<li>Notice the phrase <strong>\"per second\"</strong>. \"It can process 3.8 billion instructions\" means nothing without a time frame — and it will not be credited.</li>\n</ul>\n<h4>Higher clock speed → better performance</h4>\n<ul>\n<li>More cycles per second means more instructions executed per second, so programs run faster.</li>\n<li>Everyday example: a 3.2 GHz CPU gets through more work each second than a 1.2 GHz CPU, so the same program finishes sooner.</li>\n</ul>\n<h4>One core does one instruction at a time</h4>\n<ul>\n<li>A common misunderstanding: clock speed is <em>not</em> \"how many instructions it does at once\". A single core executes <strong>one instruction at a time</strong> — it just does them extremely quickly, one after another.</li>\n<li>Doing things genuinely <em>at the same time</em> is what extra cores are for (next card but one).</li>\n</ul>", "check": {"question": "Which answer best describes a clock speed of 2.5 GHz?", "options": ["The computer is 2.5 times faster than normal", "It can carry out 2.5 billion fetch–execute cycles per second", "It can process 2.5 billion instructions all at exactly the same moment", "It has 2.5 GB of cache memory built into the CPU"], "answer": 1, "explain": "Clock speed = fetch–execute cycles per second, and ''giga'' means billion — so 2.5 GHz is 2.5 billion cycles every second. Not ''at the same time'': one core handles one instruction at a time."}}, {"title": "Cache size — a small, fast shortcut", "html": "<h4>A quick recap of what cache is</h4>\n<ul>\n<li><strong>Cache</strong> is a small amount of <strong>very fast memory inside the CPU</strong>. It stores the instructions and data that are <strong>used most frequently</strong> (or are about to be used next).</li>\n<li>The point of it: fetching something from cache is <strong>much faster than fetching it from RAM</strong>. Less waiting = more work done.</li>\n</ul>\n<h4>Why a BIGGER cache improves performance</h4>\n<ul>\n<li>A bigger cache can hold <strong>more</strong> of those frequently used instructions and data.</li>\n<li>So the CPU finds what it needs in cache more often, and has to go out to the slower RAM less often.</li>\n<li>Less time waiting for RAM → the CPU spends more of its time actually processing → better performance. A computer with 512 KB of cache will generally outperform an identical one with 64 KB.</li>\n</ul>\n<h4>The chain the examiner wants</h4>\n<ul>\n<li>Never stop at \"cache is faster than RAM\" — <em>faster at what?</em> That alone earns nothing. Build the chain:</li>\n<li><strong>Cache stores frequently used instructions → these can be accessed faster than from RAM → so more cache means the CPU waits less and performance improves.</strong></li>\n</ul>\n<h4>The clever extra: more isn''t infinitely better</h4>\n<ul>\n<li>Cache is expensive, and a very large cache takes <strong>longer to search</strong> — so beyond a point, extra cache stops helping and can even slow things slightly.</li>\n<li>This is a genuinely creditworthy point in the mark scheme, and it''s the sort of nuance that separates a top answer.</li>\n</ul>", "check": {"question": "Why does a computer with 512 KB of cache usually outperform an identical one with 64 KB?", "options": ["Cache is directly faster than RAM, which alone speeds up every calculation", "More frequently used instructions fit in cache, so the CPU fetches from RAM less often", "A bigger cache increases the CPU''s clock speed, so more cycles run every second", "A bigger cache permanently stores the user''s files, so nothing needs to reload from disk"], "answer": 1, "explain": "The mark comes from the CHAIN: more cache holds more frequently used instructions → fewer trips to slower RAM → less waiting → better performance. ''Cache is faster than RAM'' on its own is not enough — faster at what?"}}, {"title": "Number of cores — doing things at the same time", "html": "<h4>What a core is</h4>\n<ul>\n<li>A <strong>core</strong> is a complete processing unit — it can run its own fetch–execute cycle. A <strong>dual core</strong> CPU has 2; a <strong>quad core</strong> has 4.</li>\n<li>Each core can execute <strong>a separate instruction at the same time</strong> as the others. This is called <strong>parallel processing</strong>.</li>\n</ul>\n<h4>Why more cores can improve performance</h4>\n<ul>\n<li>Work can be <strong>split between the cores</strong> and processed simultaneously, so more instructions are completed in the same period of time.</li>\n<li>It also makes <strong>multitasking</strong> smoother — one core can handle your game while another handles the music playing in the background.</li>\n</ul>\n<h4>The three words that earn the mark: \"at the same time\"</h4>\n<ul>\n<li>Examiners are strict here. \"A dual core can run twice as many instructions\" is <strong>not</strong> enough — that could just be a faster clock.</li>\n<li>You must say the cores act <strong>simultaneously</strong>: <em>each core can execute a separate instruction at the same time.</em> That is the idea being tested.</li>\n</ul>\n<h4>Why twice the cores ≠ twice the speed</h4>\n<ul>\n<li><strong>Some tasks cannot be split.</strong> If a job must be done in order — step 2 needs the answer from step 1 — extra cores sit idle.</li>\n<li><strong>Software must be written to use multiple cores.</strong> Older programs designed for one core get no benefit from three spare ones.</li>\n<li>So a quad core is <em>not</em> automatically twice as fast as a dual core. This exact claim is a favourite exam question.</li>\n</ul>", "check": {"question": "Which explanation of dual-core performance would earn the mark?", "options": ["It can run exactly twice as many instructions every single second", "Each core can execute a separate instruction at the same time", "It automatically doubles the CPU''s clock speed to run faster", "It gives the CPU twice as much cache to store instructions in"], "answer": 1, "explain": "The creditworthy idea is simultaneous execution — parallel processing. ''Twice as many instructions per second'' is refused because a faster clock could achieve that; it misses the ''at the same time'' point entirely."}}, {"title": "Putting the three together (and why it''s never simple)", "html": "<h4>Comparing two CPU specifications</h4>\n<ul>\n<li>Exam questions love giving you two spec boxes and asking which is faster, and why. The trick: <strong>the winner is rarely ahead on everything.</strong></li>\n<li>Worked example — Computer 1: 1 GHz, 4 cores. Computer 2: 1.4 GHz, 2 cores. Which runs a 3D flight simulator better?</li>\n<li>Computer 1, <strong>because it has more cores</strong>. A flight simulator is exactly the kind of demanding software written to split work across cores — so four cores working simultaneously beat a slightly faster clock on two.</li>\n<li>Notice what a full answer does: it names the characteristic that <em>differs and matters</em>, and links it to the task.</li>\n</ul>\n<h4>The characteristics interact</h4>\n<ul>\n<li>A high clock speed with a tiny cache means the CPU is fast but keeps waiting for RAM.</li>\n<li>Lots of cores with software that can''t use them is wasted silicon.</li>\n<li>That''s why the spec says you must understand the effect of these characteristics <strong>individually and in combination</strong>.</li>\n</ul>\n<h4>How to improve a computer''s performance (a whole-machine view)</h4>\n<ul>\n<li><strong>Increase the clock speed</strong> → more FE cycles per second → faster response, smoother action.</li>\n<li><strong>Add more cores</strong> → more tasks run simultaneously → better for software written for multi-core.</li>\n<li><strong>Increase cache size</strong> → more frequently used instructions held close to the CPU → faster access.</li>\n<li><strong>Add a better graphics card</strong> → takes graphics work off the CPU → improves speed and image quality.</li>\n<li><strong>Swap an HDD for an SSD</strong> → much faster read/write → programs and files load quicker.</li>\n<li>Each one only earns full marks when you say <strong>how</strong> it improves performance, not just that it does.</li>\n</ul>", "check": {"question": "Computer A: 1 GHz, 4 cores. Computer B: 1.4 GHz, 2 cores. Both have 2 MB cache. Why might A run a demanding 3D game better?", "options": ["It has a higher clock speed than Computer B, so each instruction runs faster", "It has more cores, so more of the work can be processed at the same time", "It has a bigger cache than Computer B, so it fetches from RAM less often", "It has more RAM installed than Computer B, so more of the game loads at once"], "answer": 1, "explain": "A''s only advantage is its core count — and demanding software like a 3D game is usually written to split work across cores, so four working simultaneously outweigh B''s slightly faster clock."}}, {"title": "RAM, virtual memory and why upgrading RAM helps", "html": "<h4>RAM is not a CPU characteristic — but it does affect performance</h4>\n<ul>\n<li>Exam questions on this topic often drift into RAM, because it is one of the \"other parts\" that changes how fast a computer feels. Know the difference between the two ideas.</li>\n<li><strong>RAM</strong> holds the programs and data that are <strong>currently running</strong>. The CPU fetches instructions from RAM.</li>\n</ul>\n<h4>Why more RAM improves performance</h4>\n<ul>\n<li><strong>More programs/data can be held in RAM at once</strong>, so more can run at the same time and they respond faster.</li>\n<li>It allows more memory-hungry software (video editing, 3D games) to run properly.</li>\n<li>Crucially: it <strong>reduces the use of virtual memory</strong>. When RAM fills up, the computer starts using space on the <strong>secondary storage</strong> as overflow — and that is far slower to access. Less swapping = a noticeably faster machine.</li>\n</ul>\n<h4>The RAM vs ROM difference (a guaranteed exam pair)</h4>\n<ul>\n<li><strong>Volatility:</strong> RAM is <strong>volatile</strong> (contents lost when power is off); ROM is <strong>non-volatile</strong> (contents kept).</li>\n<li><strong>Contents:</strong> RAM stores currently running programs, data and the OS; ROM stores the <strong>boot-up instructions</strong> (the BIOS).</li>\n<li><strong>Changeability:</strong> RAM can be written to and changed constantly; ROM normally cannot be changed.</li>\n<li>When asked for a <em>difference</em>, write <strong>both sides in the same space</strong>: \"RAM is volatile, whereas ROM is non-volatile.\" Describing only RAM in box 1 and only ROM in box 2 is the classic way to lose these marks.</li>\n</ul>", "check": {"question": "Why does adding more RAM usually make a computer feel faster?", "options": ["It increases the CPU''s clock speed, so more cycles are completed each second", "More running programs fit in RAM, so less virtual memory is used", "It adds more processing cores to the CPU, enabling parallel execution of tasks", "It permanently stores more files and programs even when the power is switched off"], "answer": 1, "explain": "More RAM means more currently running programs and data fit in fast memory, so the computer swaps out to virtual memory (on much slower secondary storage) far less often."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Three CPU characteristics", "definition": "Clock speed, cache size, number of cores"}, {"term": "Clock speed", "definition": "The number of fetch–execute cycles carried out per second"}, {"term": "Hertz (Hz)", "definition": "One cycle per second"}, {"term": "GHz", "definition": "Gigahertz — billions of cycles per second"}, {"term": "3.8 GHz means", "definition": "About 3.8 billion fetch–execute cycles every second"}, {"term": "Effect of higher clock speed", "definition": "More cycles per second, so more instructions executed per second"}, {"term": "Cache", "definition": "Small, very fast memory inside the CPU for frequently used instructions and data"}, {"term": "Effect of bigger cache", "definition": "More frequent instructions held close to the CPU, so fewer slow fetches from RAM"}, {"term": "Cache limit", "definition": "Too much cache takes longer to search, so the benefit tails off"}, {"term": "Core", "definition": "A processing unit that can run its own fetch–execute cycle"}, {"term": "Parallel processing", "definition": "Each core executing a separate instruction at the same time"}, {"term": "Effect of more cores", "definition": "Work can be split and processed simultaneously; better multitasking"}, {"term": "Why more cores ≠ more speed", "definition": "Some tasks can''t be split, and software must be written for multi-core"}, {"term": "Other parts affecting performance", "definition": "RAM, secondary storage (SSD vs HDD), graphics card (GPU)"}, {"term": "Why more RAM helps", "definition": "More running programs fit in RAM, so less use of slow virtual memory"}, {"term": "Virtual memory", "definition": "Secondary storage used as overflow when RAM is full — much slower"}, {"term": "RAM vs ROM", "definition": "RAM is volatile and holds running programs; ROM is non-volatile and holds boot-up instructions"}, {"term": "SSD upgrade", "definition": "Faster read/write than an HDD, so programs and files load quicker"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which three characteristics of a CPU affect its performance?", "options": ["Clock speed, cache size, number of cores", "RAM, ROM, cache", "Clock speed, RAM size, hard drive size", "Number of cores, screen size, graphics card"], "answer": 0, "explain": "Those are the only three the specification asks about. RAM, storage and the graphics card affect the computer''s performance, but they are not characteristics of the CPU itself."}, {"question": "Clock speed is measured in hertz. What does 1 Hz mean?", "options": ["One instruction stored in cache", "One fetch–execute cycle per second", "One billion fetch–execute cycles per second", "One core completing an instruction"], "answer": 1, "explain": "1 Hz = one cycle per second. So gigahertz (GHz) means billions of fetch–execute cycles every second."}, {"question": "A CPU has a clock speed of 3.8 GHz. How many fetch–execute cycles is that per second?", "options": ["3.8 thousand", "3.8 million", "3.8 billion", "3.8 trillion"], "answer": 2, "explain": "Giga means billion, so 3.8 GHz = 3.8 billion (3,800,000,000) cycles every second."}, {"question": "Why is ''it can process 3.8 billion instructions'' NOT a full answer for what 3.8 GHz means?", "options": ["The number is wrong — giga means million, not billion", "It leaves out the time frame — it must be per second", "It should say ''data'' instead of ''instructions'', since the CPU processes data", "GHz measures the size of the cache, not the number of instructions"], "answer": 1, "explain": "Without ''per second'' the statement means nothing — 3.8 billion instructions over what period? Examiners refuse answers with no time frame."}, {"question": "What does cache store?", "options": ["All of the user''s saved files and folders", "The instructions and data used most frequently", "The boot-up instructions used to start the computer", "A complete copy of everything currently running"], "answer": 1, "explain": "Cache holds frequently (or recently, or next-to-be) used instructions and data, right inside the CPU, so they can be fetched without going out to slower RAM."}, {"question": "Why does increasing the cache size usually improve performance?", "options": ["It raises the CPU''s clock speed, so more cycles happen every second", "More frequently used instructions sit closer to the CPU, so RAM is used less often", "It adds an extra processing core, so two separate instructions can run at exactly the same time", "It increases the amount of RAM installed inside the computer"], "answer": 1, "explain": "A bigger cache holds more of what the CPU keeps reaching for, so there are fewer slow trips out to RAM and less waiting."}, {"question": "Which statement about a very large cache is TRUE?", "options": ["More cache always improves performance without any limit whatsoever", "Beyond a point, extra cache helps less because it takes longer to search", "Cache size has no effect on performance, only clock speed and cores matter", "A large cache completely replaces the need for RAM in a modern computer"], "answer": 1, "explain": "Cache is expensive and a very large cache takes longer to search through, so the benefit tails off — a genuinely creditworthy point in the mark scheme."}, {"question": "What is a core?", "options": ["A block of cache memory used to store frequently accessed instructions", "A processing unit that can run its own fetch–execute cycle", "The internal clock inside the CPU that controls its cycle timing", "A type of RAM used to temporarily hold currently running programs"], "answer": 1, "explain": "Each core is a complete processing unit, so a dual-core CPU can execute two separate instructions at the same time."}, {"question": "A dual-core processor may improve performance because...", "options": ["it runs exactly twice as many instructions in every single second", "each core can execute a separate instruction at the same time", "it automatically doubles the clock speed of the entire processor", "it removes the need for any cache memory inside the CPU"], "answer": 1, "explain": "The creditworthy idea is parallel processing — the cores working simultaneously. ''Twice as many instructions per second'' is refused because a faster clock could do that too."}, {"question": "Alicia says a quad-core computer must run twice as fast as a dual-core one. Why is she not always right?", "options": ["Quad-core processors have no cache memory built into them at all", "Some tasks cannot be split across cores, and software must be written to use them", "Four cores will always run slower than two, whatever the software", "Clock speed makes no difference to performance at all, only the number of cores matters"], "answer": 1, "explain": "Extra cores only help when the work can actually be divided and the software is written for multiple cores. Clock speed, cache and RAM differences matter too."}, {"question": "Computer 1: 1 GHz, 4 cores. Computer 2: 1.4 GHz, 2 cores (same cache). Why might Computer 1 run a 3D flight simulator faster?", "options": ["It has a higher clock speed than Computer 2, so instructions run faster", "It has more cache than Computer 2, so it fetches from RAM less often", "It has more cores, so more work can be processed at the same time", "It has more RAM installed than Computer 2, so more can be loaded at once"], "answer": 2, "explain": "Core count is Computer 1''s only advantage — and demanding software like a flight simulator is written to split work across cores, outweighing the slightly faster clock."}, {"question": "Which of these is NOT a characteristic of the CPU, but WOULD improve a computer''s performance?", "options": ["Increasing the CPU''s cache size", "Increasing the CPU''s clock speed", "Adding more cores to the CPU", "Upgrading the amount of RAM"], "answer": 3, "explain": "RAM is one of the ''other parts'' of the computer. It improves performance (less reliance on slow virtual memory) but it is not a characteristic of the CPU."}]}, "fib": {"enabled": true, "questions": [{"text": "The three characteristics of a CPU that affect performance are clock [speed], cache [size] and the number of [cores]."}, {"text": "Clock speed is the number of fetch–execute [cycles] carried out per [second]."}, {"text": "A clock speed of 3.8 GHz means about 3.8 [billion] cycles every second."}, {"text": "Cache stores the instructions and data that are used most [frequently], and it can be accessed faster than [RAM]."}, {"text": "Each core can execute a separate instruction at the same [time] — this is called [parallel] processing."}, {"text": "Doubling the cores does not double the speed, because some tasks cannot be [split] and the [software] must be written to use several cores."}, {"text": "RAM is [volatile], whereas ROM is non-volatile and stores the [boot-up] instructions."}, {"text": "Adding more RAM improves performance because the computer relies less on [virtual] memory, which is stored on much slower secondary storage."}]}, "tf": {"enabled": true, "questions": [{"statement": "Writing ''clock'' as a characteristic of the CPU is enough to earn the mark.", "answer": false, "explain": "It must be ''clock speed''. Every CPU has a clock — what varies, and what affects performance, is how fast it ticks. The same applies to ''cores'' (say ''number of cores'') and ''cache'' (say ''cache size'')."}, {"statement": "A clock speed of 2 GHz means the CPU carries out 2 billion fetch–execute cycles per second.", "answer": true, "explain": "Correct — giga means billion, and hertz means cycles per second."}, {"statement": "A single core can execute several instructions at exactly the same time.", "answer": false, "explain": "One core handles one instruction at a time — it is simply very fast. Executing instructions genuinely simultaneously is what extra cores provide."}, {"statement": "A quad-core processor always runs twice as fast as a dual-core processor.", "answer": false, "explain": "Only if the work can be split and the software is written to use four cores. Clock speed, cache and RAM also differ between machines — this exact claim is a favourite exam question."}, {"statement": "Cache can be accessed faster than RAM.", "answer": true, "explain": "True — but on its own that sentence earns nothing in an exam. You must add what it leads to: fewer slow trips to RAM, so the CPU waits less and performance improves."}, {"statement": "Increasing cache size improves performance without limit — the more the better, always.", "answer": false, "explain": "Beyond a point the benefit tails off: a very large cache takes longer to search, and cache is expensive. Recognising that limit is a creditworthy point."}, {"statement": "RAM is volatile and ROM is non-volatile.", "answer": true, "explain": "Correct — RAM loses its contents when the power goes off; ROM keeps the boot-up instructions permanently."}, {"statement": "Adding more RAM helps because it reduces how much the computer has to use virtual memory.", "answer": true, "explain": "Yes — when RAM fills up the computer overflows onto secondary storage (virtual memory), which is far slower. More RAM means less of that swapping."}]}, "misc": {"enabled": true, "items": [{"myth": "Listing ''clock'', ''cache'' and ''cores'' as the three characteristics of a CPU.", "truth": "Each one is missing the part that actually varies. It is the clock <strong>speed</strong>, the cache <strong>size</strong> and the <strong>number of</strong> cores. Real candidates lost marks here for exactly this: writing ''clock'' or ''core'' without saying speed or number is too ambiguous to credit. Three words cost three marks.", "check": {"question": "Which list would score all 3 marks?", "options": ["Clock, cache and cores, missing the qualifying words", "Clock speed, cache size, number of cores", "Processing speed, internal memory, number of processors", "The CPU, RAM and ROM inside the computer"], "answer": 1, "explain": "The characteristic must be the measurable quantity — speed of the clock, size of the cache, number of the cores."}}, {"myth": "''A dual core processor is better because it can run twice as many instructions per second.''", "truth": "This is refused, because a faster clock speed could achieve the very same thing — so the sentence doesn''t show you understand cores at all. The mark needs the words <strong>at the same time</strong>: each core can execute a separate instruction simultaneously. Weak: ''more processes run per second.'' Strong: ''each of the two cores can process a different instruction at the same time.''", "check": {"question": "Why is ''it runs more instructions per second'' refused as an explanation of dual-core benefit?", "options": ["It is factually wrong, since dual cores never increase throughput", "A faster clock speed could also do that — it doesn''t show understanding of cores", "It should say ''per minute'' rather than ''per second'', since that''s how exams phrase timing", "Cores don''t affect how many instructions a CPU can process"], "answer": 1, "explain": "The examiner needs evidence you understand parallel processing specifically, and only ''at the same time'' shows that."}}, {"myth": "Explaining cache with ''cache is faster than RAM'' and stopping there.", "truth": "Faster at <em>what</em>? That question is exactly why this scores zero. Also refused: simply defining cache as ''fast memory close to the CPU''. Build the full chain instead: <strong>cache stores frequently used instructions → they can be accessed faster than from RAM → so more cache means less waiting and better CPU performance.</strong> Many candidates got the first link and stopped; the marks are in the last one.", "check": {"question": "Which answer completes the chain properly?", "options": ["Cache is fast memory located near the CPU, and simply being near the CPU is what improves performance, regardless of what it stores", "Cache is faster than RAM, so replacing all of a computer''s RAM with cache would make it run instructions with no waiting at all", "Cache holds frequently used instructions, which are fetched faster than from RAM, so the CPU waits less and performance improves", "Cache stores the boot-up instructions needed to start the computer, in the same way that ROM stores the BIOS permanently"], "answer": 2, "explain": "Only the third links what cache stores → why that''s quicker → what it does for performance. The others either overstate what mere proximity to the CPU does, misapply the idea (cache can''t simply replace RAM), or describe something cache doesn''t store."}}, {"myth": "''A clock speed of 3.8 GHz means the computer is fast'' — or ''it can process 3.8 billion instructions''.", "truth": "The first just repeats the question (''fast'' is not a measurement) and is explicitly not credited. The second forgets the <strong>time frame</strong> — 3.8 billion instructions over what period? A full answer has both halves: <strong>clock speed is the number of fetch–execute cycles per second</strong>, and <strong>3.8 GHz = 3.8 billion cycles every second</strong>. A further trap: it is not the number of instructions done <em>at a time</em> — one core does one instruction at a time.", "check": {"question": "Which is a full 2-mark answer for ''describe what is meant by a clock speed of 3.8 GHz''?", "options": ["The computer is very fast and can run any modern piece of software smoothly", "It performs 3.8 billion instructions in total, however long the program actually takes to run", "It is the number of fetch–execute cycles per second — 3.8 billion of them every second", "It can do 3.8 billion instructions at exactly the same time, using multiple cores"], "answer": 2, "explain": "Two marks, two halves: what clock speed measures (cycles per second) and the translation of the number (3.8 billion per second)."}}, {"myth": "For ''describe two differences between RAM and ROM'', writing everything about RAM in box 1 and everything about ROM in box 2.", "truth": "A <strong>difference</strong> needs both sides in the <em>same</em> space: ''RAM is volatile, whereas ROM is non-volatile.'' Candidates who described RAM fully in the first box and ROM fully in the second gave two descriptions, not two differences — and lost marks for it. Each difference space is marked as its own pair: 1 mark for the RAM side, 1 for the ROM side.", "check": {"question": "Which is properly written as ONE difference?", "options": ["Difference 1: RAM is volatile. Difference 2: ROM stores the BIOS.", "Difference 1: RAM is volatile, whereas ROM is non-volatile.", "Difference 1: RAM is memory. Difference 2: ROM is memory.", "Difference 1: RAM is fast."], "answer": 1, "explain": "One difference = both sides, contrasted, in the same answer space. The others give one side only, or two unrelated descriptions."}}, {"myth": "When asked how to improve a computer''s performance, suggesting a touchscreen, a printer, or a bigger hard drive.", "truth": "Peripherals don''t make the processor work faster, and extra <em>storage space</em> is not extra speed — candidates genuinely lost marks for both. Stick to changes that affect processing: increase the <strong>clock speed</strong>, add <strong>cores</strong>, increase <strong>cache</strong>, fit a better <strong>graphics card</strong>, or swap an HDD for an <strong>SSD</strong> (faster read/write). And always say <strong>how</strong> the change improves performance — naming it alone is only half the mark.", "check": {"question": "Which suggestion would earn marks for improving performance?", "options": ["Add a touchscreen, which lets the user interact with the screen directly and quickly", "Add a printer so the computer can produce paper copies of documents", "Replace the hard disk drive with an SSD, which has faster read/write speeds", "Buy a bigger monitor so more windows can be seen on the screen at once"], "answer": 2, "explain": "An SSD genuinely speeds up loading. Peripherals like touchscreens, printers and monitors change how you interact with the computer, not how fast it processes."}}]}, "tips": {"enabled": true, "items": [{"title": "2-mark ''explain'' questions: the …which means… chain", "html": "<p>Almost every 2-mark explain on this topic is marked as <strong>point + development</strong>: 1 mark for identifying the right thing, 1 mark for the consequence you link to it. Here is the same answer to <em>\"Explain one reason why the cache size affects the performance of the CPU\"</em> at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"Cache is fast memory close to the CPU.\"</p>\n<ul>\n<li>A definition, not a reason. Explicitly not creditworthy — the question asked about <em>performance</em>.</li>\n</ul>\n\n<p><strong>❌ 0 marks:</strong> \"Cache is faster than RAM.\"</p>\n<ul>\n<li>Faster at <em>what</em>? The examiner''s own objection. Nothing is linked to performance.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"Data can be transferred faster from cache.\"</p>\n<ul>\n<li>A correct identification — but the chain stops before it reaches performance.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"Data is transferred faster from cache than from RAM <strong>(1)</strong>, <strong>which means</strong> the CPU spends less time waiting and works more efficiently <strong>(1)</strong>.\"</p>\n\n<p><strong>The pattern for every 2-marker here:</strong> name the thing → \"…which means…\" → the effect on performance. If your answer has no linking phrase, you are probably on 1 mark.</p>", "check": {"question": "You''ve written ''a bigger cache stores more frequently used instructions''. What must you add for the second mark?", "options": ["The price of cache, since more expensive components always perform better", "The consequence — the CPU fetches from RAM less often, so performance improves", "The name of the CPU, so the examiner knows exactly which model you mean", "How many cores it has, since that is a completely separate CPU characteristic from cache"], "answer": 1, "explain": "The second mark is always the development: the effect your point has on performance. Use ''which means…'' to force yourself to write it."}}, {"title": "The 6-mark levelled question (marked with a *)", "html": "<p>A question like <em>\"*Identify the changes and explain how these changes would improve performance\"</em> is <strong>not</strong> point-marked — it is placed in a <strong>band</strong>, and your spelling, grammar and use of technical terms count.</p>\n\n<p><strong>The three bands, in plain terms:</strong></p>\n<ul>\n<li><strong>Low (1–2):</strong> upgrades are named, with little or no explanation of how they help. Points poorly expressed or not linked to the context.</li>\n<li><strong>Mid (3–4):</strong> upgrades identified, but <em>how</em> they improve performance is weak or thin.</li>\n<li><strong>High (5–6):</strong> <strong>several</strong> upgrades, each with a <strong>detailed explanation</strong> of its impact on <em>this</em> computer, written accurately with correct technical terms.</li>\n</ul>\n\n<p><strong>How to land in the top band — a repeatable structure.</strong> For each upgrade write two sentences:</p>\n<ul>\n<li><em>Upgrade:</em> \"Increase the clock speed.\" <em>Impact:</em> \"This runs more fetch–execute cycles per second, so the computer responds faster and is less likely to freeze.\"</li>\n<li><em>Upgrade:</em> \"Increase the cache size.\" <em>Impact:</em> \"More frequently used instructions are stored close to the CPU, so it fetches from slower RAM less often.\"</li>\n<li><em>Upgrade:</em> \"Replace the hard disk drive with an SSD.\" <em>Impact:</em> \"Read and write speeds are much faster, so programs and files load more quickly.\"</li>\n</ul>\n\n<p><strong>Three traps that cost real marks:</strong></p>\n<ul>\n<li><strong>Answering the previous question again.</strong> If an earlier part was about upgrading RAM, do not re-explain RAM here — that earns nothing.</li>\n<li><strong>Suggesting things that don''t affect performance</strong> — a touchscreen, a printer, a bigger monitor.</li>\n<li><strong>Naming without explaining.</strong> A list of five upgrades with no \"how\" sits in the low band; two upgrades explained well beat five listed.</li>\n</ul>", "check": {"question": "A student lists six upgrades but explains none of them. Which band is that?", "options": ["High (5–6) — they identified lots of upgrades, which is what matters most", "Mid (3–4) — several upgrades are identified, each with at least a brief attempt at explaining them", "Low (1–2) — upgrades named with little or no explanation of how they improve performance", "Full marks — every upgrade correctly named earns the maximum available"], "answer": 2, "explain": "The band descriptors reward DETAILED EXPLANATION of impact, not the number of items. A long unexplained list is the definition of the low band."}}, {"title": "The 8-mark ''Discuss'' — the one extended response on Paper 1", "html": "<p>Paper 1 has exactly one of these. On this topic it looks like: <em>\"Discuss the impact of people wanting to upgrade to the latest smartphone\"</em>, with bullets suggesting you consider <strong>stakeholders, technology, ethical issues and environmental issues</strong>.</p>\n\n<p><strong>Those bullets are the plan — use all of them.</strong> The top band explicitly requires \"reference to the impact on <strong>all</strong> areas\". Missing one caps you.</p>\n\n<p><strong>What each band needs:</strong></p>\n<ul>\n<li><strong>Band 1 (1–2):</strong> basic knowledge, unsupported assertions, unstructured.</li>\n<li><strong>Band 2 (3–5):</strong> reasonable knowledge applied to the context, but underdeveloped and one or two areas missed.</li>\n<li><strong>Band 3 (6–8):</strong> thorough and detailed; applied <strong>consistently</strong> to the context; <strong>weighs up both sides</strong>; a well-developed, logically structured line of reasoning.</li>\n</ul>\n\n<p><strong>A structure that reaches band 3:</strong></p>\n<ul>\n<li>Take each bullet in turn and make a <strong>chain</strong>: point → effect → consequence. E.g. <em>Environmental:</em> \"Phones are replaced while still working <strong>→</strong> they go to landfill as e-waste, often shipped abroad <strong>→</strong> toxic materials leak into the ground and precious metals are wasted.\"</li>\n<li><strong>Weigh both sides.</strong> Upgrading isn''t purely bad: manufacturers and phone shops gain business, and newer technology can be more efficient. A one-sided answer cannot reach the top band.</li>\n<li><strong>Finish with a short conclusion</strong> that actually judges the issue, rather than restating your points.</li>\n</ul>\n\n<p><strong>Timing:</strong> around 10–12 minutes. Spend the first minute jotting one idea under each of the four bullets — that plan is what produces the \"logically structured\" reasoning the band demands.</p>", "check": {"question": "An answer covers environmental impact in brilliant detail and ignores the other three bullets. What limits the mark?", "options": ["Nothing — depth on one bullet is all that the mark scheme actually requires", "The top band needs the impact on ALL the areas, weighed on both sides", "It should have been longer, since length alone determines the band awarded", "Environmental issues are not creditworthy in this particular exam question"], "answer": 1, "explain": "Band 3 requires thorough coverage across the areas AND weighing both sides. Brilliant depth on one bullet is a band 2 answer at best."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>A school is buying new computers for its computing suite.</p><p>State <strong>three</strong> characteristics of a CPU that determine how well it performs.</p>", "marks": 3, "hint": "Each answer must name the part AND what varies about it — one-word answers such as ''clock'' or ''cores'' will not be credited.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark for each correct characteristic, up to 3)</h5>\n<ul>\n<li>Clock speed</li>\n<li>Cache size</li>\n<li>Number of cores</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept the three characteristics in any order.</li>\n<li>Do not award a characteristic named without its qualifying word, such as \"clock\" alone instead of \"clock speed\", or \"cores\" alone instead of \"number of cores\".</li>\n</ul>\n</div>\n<div class=\"marks-section\"><h5>Common mistakes</h5><p>Many students shorten these terms to single words such as \"clock\", \"cache\" or \"cores\". That loses the mark, because every CPU has a clock, some cache and at least one core — it is the speed of the clock, the size of the cache and the number of cores that actually differ between processors and affect how fast one is compared with another.</p></div>"}, {"question": "<p>The specifications of two laptops are shown in Fig. 1.</p><p>Video editing software can split the work of rendering a finished clip across several parts of the CPU at once.</p><p>Using Fig. 1, identify <strong>one</strong> reason why Laptop A is likely to render video faster than Laptop B.</p>", "marks": 1, "hint": "Compare the two spec boxes and find the only characteristic where Laptop A is ahead.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>Laptop A has more cores (6 rather than 2).</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any answer that correctly identifies the higher core count as the reason, including reference to more parts of the rendering task being processed at once.</li>\n</ul>\n</div>"}, {"question": "<p>Identify <strong>two</strong> components of a laptop, not shown in Fig. 1, that could also affect how quickly it renders video.</p>", "marks": 2, "hint": "Fig. 1 only lists CPU characteristics — think about other hardware inside (or attached to) the laptop.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark for each valid component, up to 2)</h5>\n<ul>\n<li>RAM</li>\n<li>Graphics card (GPU)</li>\n<li>Storage type, e.g. SSD instead of HDD</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award marks for other reasonable hardware that affects processing speed, such as the motherboard.</li>\n</ul>\n</div>"}, {"question": "<p>Explain <strong>one</strong> reason why increasing the size of a CPU''s cache can improve its performance.</p>", "marks": 2, "hint": "Point + development. Say what a bigger cache lets the CPU do, then use ''which means…'' to link it to performance.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>Award 1 mark for a correct identification, such as: a bigger cache holds more of the instructions and data the CPU uses frequently.</li>\n<li>Award a further 1 mark for the linked explanation, such as: this means the CPU fetches from the slower RAM less often, so it spends less time waiting.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark for the identification and 1 mark for its explanation, to a maximum of 2 marks.</li>\n<li>\"Cache is faster than RAM\" alone, with no link to what this means for performance, does not score the second mark.</li>\n</ul>\n</div>"}, {"question": "<p>A new laptop is advertised with a processor clock speed of 2.6 GHz.</p><p>Describe what is meant by a clock speed of 2.6 GHz.</p>", "marks": 2, "hint": "Two halves for two marks: what clock speed actually measures, and what the number 2.6 GHz translates to. Don''t forget ''per second''.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per bullet, up to 2)</h5>\n<ul>\n<li>The number of fetch–execute cycles the CPU carries out per second, or the rate at which the CPU''s clock \"ticks\".</li>\n<li>2.6 billion cycles (or instructions) every second.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not award vague statements such as \"how fast the computer is\" with no reference to cycles per second.</li>\n<li>2.6 GHz = 2,600,000,000 cycles per second.</li>\n</ul>\n</div>\n<div class=\"marks-section\"><h5>Common mistakes</h5><p>A lot of students correctly say the CPU is \"fast\" or simply repeat the number 2.6 GHz without explaining what it measures — neither earns credit, because the question is asking what the figure means, not restating it. The other frequent slip is describing 2.6 billion instructions with no time frame attached, or describing it as instructions done \"at once\" rather than \"each second\" — a single core still only carries out one instruction at a time, however quickly it ticks through them.</p></div>"}, {"question": "<p>Ben currently owns a laptop with a dual-core processor. He is thinking of replacing it with a laptop that has a quad-core processor, and believes this will make every task run exactly twice as fast.</p><p>Explain why Ben''s belief is not always correct.</p>", "marks": 3, "hint": "Three marks need three separate reasons. Think about the type of task, the software, and the other CPU/component characteristics that could differ between the two laptops.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per valid point, up to 3)</h5>\n<ul>\n<li>Some tasks cannot be split across multiple cores, so extra cores are not always used; performance also depends on whether the software is written to make use of several cores.</li>\n<li>The two laptops may not have the same clock speed, so the new laptop could be slower for a single task if its clock speed is lower.</li>\n<li>The two laptops may not have the same cache size or amount of RAM, both of which also affect performance.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept reference to any other component that could differ between the two laptops and affect performance, such as storage type.</li>\n<li>Accept a description of tasks needing to run in a set order, where later steps depend on the result of earlier ones.</li>\n</ul>\n</div>\n<div class=\"marks-section\"><h5>Common mistakes</h5><p>Students often name only one reason, usually that \"not all software uses multiple cores\", and stop there — three marks needs three distinct points. A common gap is forgetting that the two laptops being compared are not identical apart from their core count: clock speed, cache size and RAM could easily differ too, and any of those could mean the quad-core laptop is not simply \"twice as fast\".</p></div>"}, {"question": "<p>Amara''s current laptop specification is shown in Fig. 2.</p><p>Describe how having a processor with more than one core, rather than a single core, could improve the performance of Amara''s laptop.</p>", "marks": 2, "hint": "Give the splitting/simultaneous-processing idea FIRST — saying it is simply ''faster'' only earns a mark once you''ve explained what makes it faster.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (2 from)</h5>\n<ul>\n<li>Work can be split between the cores, so more than one part of a task, or more than one program, can be processed at the same time, meaning more is completed in the same amount of time.</li>\n<li>It allows smoother multitasking, running more than one program or process at once, so tasks complete faster overall.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>An answer must state that work is split or run simultaneously between cores before \"faster\" can be credited.</li>\n<li>Simply stating \"it is faster\" without this idea is not enough.</li>\n</ul>\n</div>\n<div class=\"marks-section\"><h5>Common mistakes</h5><p>A common answer just says \"it will be faster\" or \"it can do more things\", without explaining what actually causes that. The mark only comes once a student says the cores act at the same time as each other — it isn''t that each individual instruction runs quicker, it''s that more than one instruction can be in progress simultaneously.</p></div>"}, {"question": "<p>Amara is considering upgrading the RAM in her laptop.</p><p>Describe <strong>two</strong> differences between RAM and ROM.</p>", "marks": 4, "hint": "Write BOTH sides of each difference in the same space — e.g. ''RAM is …, whereas ROM is …''. Describing only RAM in box 1 and only ROM in box 2 will not score both marks.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (up to 2 marks per difference: 1 for the RAM side, 1 for the ROM side)</h5>\n<ul>\n<li>RAM is volatile; ROM is non-volatile.</li>\n<li>RAM stores the programs, data and operating system currently running; ROM stores the boot-up instructions (BIOS).</li>\n<li>The contents of RAM can be changed; the contents of ROM normally cannot be changed.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each difference is marked as a pair — the RAM statement and its contrasting ROM statement.</li>\n<li>A box describing only RAM, or only ROM, with no comparison, scores at most 1 mark for that difference.</li>\n</ul>\n</div>\n<div class=\"marks-section\"><h5>Common mistakes</h5><p>Students often write a full description of RAM in the first answer space and a full, separate description of ROM in the second space. That gives two descriptions rather than two differences, and loses marks, because each difference needs both the RAM side and the ROM side written together so they are directly compared.</p></div>"}, {"question": "<p>Amara decides to upgrade her laptop''s RAM from 4GB to 16GB.</p><p>Explain why this is likely to improve her laptop''s performance.</p>", "marks": 2, "hint": "Look at Amara''s spec — she only has 4GB of RAM. Think about what happens once RAM fills up, and what the laptop has to rely on instead.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (2 from)</h5>\n<ul>\n<li>More programs, applications or data can be held in RAM and run at the same time.</li>\n<li>Programs open and respond faster, and more memory-intensive software (e.g. video editing, games) can run properly.</li>\n<li>It reduces reliance on virtual memory, meaning less use of the much slower hard disk drive as overflow storage.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not award vague answers referring only to more storage space for files, since that describes secondary storage rather than RAM.</li>\n</ul>\n</div>\n<div class=\"marks-section\"><h5>Common mistakes</h5><p>Some students confuse RAM with storage space and say the upgrade means \"more files can be saved\" — that describes the hard disk drive, not RAM. The credit-worthy idea is that more currently running programs and data can fit in fast memory at once, and the laptop needs to fall back on slow virtual memory (on the hard disk) far less often.</p></div>"}, {"question": "<p>*After upgrading her RAM, Amara could make further changes to improve her laptop''s performance.</p><p>Identify the changes Amara could make, and explain how each would improve her laptop''s performance.</p><p><em>The quality of your written communication will be assessed in your answer.</em></p>", "marks": 6, "hint": "Name several upgrades, each with a detailed ''how''. Don''t repeat the RAM answer, and avoid suggesting things that don''t affect processing, like a webcam or DVD drive.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks (levelled, quality of written communication assessed) — indicative content</h5>\n<ul>\n<li><strong>Increase the processor''s clock speed</strong> — runs more fetch–execute cycles every second, so the laptop responds faster and is less likely to freeze.</li>\n<li><strong>Add more cores</strong> — allows more tasks, or more parts of one task, to be processed at the same time, especially for software written to use multiple cores.</li>\n<li><strong>Increase the cache size</strong> — holds more of the frequently used instructions and data close to the CPU, so it needs to fetch from the slower RAM less often.</li>\n<li><strong>Upgrade the integrated graphics to a dedicated graphics card</strong> — takes graphics processing off the CPU, improving speed and image quality.</li>\n<li><strong>Replace the hard disk drive with an SSD</strong> — much faster read/write speeds, so programs and files load more quickly.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>High level (5–6 marks):</strong> Several upgrades are identified, each with a detailed and accurate explanation of how it would affect Amara''s laptop specifically. Few if any errors in spelling, grammar and punctuation; technical terms used correctly.</li>\n<li><strong>Mid level (3–4 marks):</strong> Upgrades are identified, but the explanation of how they improve performance is thinner or only partly developed. Occasional errors in spelling, grammar and punctuation; technical terms mostly correct.</li>\n<li><strong>Low level (1–2 marks):</strong> An attempt is made to name possible upgrades, with little or no explanation of how they improve performance, or points not clearly related to Amara''s laptop. Limited use of technical terms; errors in spelling, grammar and punctuation may be noticeable.</li>\n<li>Do not credit increasing the RAM again, since this has already been covered by the previous question.</li>\n<li>Do not credit upgrading components that do not affect performance, such as the webcam, DVD drive or USB ports.</li>\n</ul>\n</div>\n<div class=\"marks-section\"><h5>Common mistakes</h5><p>Some students repeat their answer about upgrading the RAM, which has already been credited on the previous question and earns nothing here. Others list peripherals such as the webcam, microphone or DVD drive — these change how Amara interacts with the laptop, not how quickly it processes data, so they don''t score. The strongest answers name a small number of genuine upgrades and explain, in detail, exactly how each one changes Amara''s laptop''s performance.</p></div>"}, {"question": "<p>A small design agency is deciding how to improve the performance of its office computers, which are now several years old and struggle to run modern design software.</p><p>Discuss the factors the agency should consider when choosing between upgrading the CPUs in its existing computers and buying entirely new computers.</p><p>In your answer you might consider:</p><ul><li>the effect on performance</li><li>cost</li><li>compatibility with existing software and components</li><li>environmental impact</li></ul>", "marks": 8, "hint": "Use all four bullets as your plan. Make chains: point → effect → consequence for the agency. Weigh both options against each other before reaching a conclusion.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (levelled) — indicative content</h5>\n<p>The following is indicative of possible points candidates may refer to, but is not a complete or required list:</p>\n<ul>\n<li><strong>Effect on performance</strong> — Upgrading just the CPU (or its clock speed, cache or core count) can improve processing speed, but other older components, such as RAM or storage, may still hold performance back; buying entirely new computers upgrades every component at once, giving a more complete performance boost.</li>\n<li><strong>Cost</strong> — Upgrading individual CPUs is likely to be cheaper in the short term than replacing whole machines, but it may only delay the need to buy new computers later; buying new computers is a bigger upfront cost but could mean fewer repairs and replacements for longer.</li>\n<li><strong>Compatibility</strong> — A new CPU may not be compatible with the agency''s existing motherboards, so the whole computer may need replacing anyway; buying new computers guarantees the CPU is compatible with all the other new components and the latest software.</li>\n<li><strong>Environmental impact</strong> — Upgrading only the CPU (or keeping the computers longer) reduces electronic waste compared with replacing whole computers; manufacturing brand new computers uses raw materials and energy, and the old computers may end up as waste if not reused or recycled responsibly.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>Band 3 — High level (6–8 marks):</strong> Thorough and detailed knowledge, applied consistently to the agency''s situation. Both options are compared and weighed against each other across the given areas, reaching a clear, justified overall view. Reasoning is well-developed and logically structured.</li>\n<li><strong>Band 2 — Mid level (3–5 marks):</strong> Reasonable knowledge, generally accurate but sometimes underdeveloped. Most of the given areas are addressed and applied to the agency, but the two options are not fully weighed against each other, or the conclusion is underdeveloped.</li>\n<li><strong>Band 1 — Low level (1–2 marks):</strong> Basic knowledge with limited understanding. Points may be unsupported assertions, poorly linked to the agency''s situation, and presented with little structure.</li>\n<li><strong>0 marks:</strong> No attempt to answer the question, or the response is not worthy of credit.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-1-3-embedded-systems', '1.1.3 Embedded Systems', '{"learn": {"enabled": true, "items": [{"title": "What is an embedded system?", "html": "<h4>The definition to learn word-for-word</h4>\n<ul>\n<li><strong>An embedded system is a computer system built into a larger device, dedicated to carrying out one specific task (or a small, limited set of tasks).</strong></li>\n<li>That single sentence has both halves examiners look for: it is <strong>built into</strong> something else, and it has <strong>one specific purpose</strong>.</li>\n<li>The washing machine on your kitchen floor contains a computer. You never think of it as a computer, because it only ever does one job — that''s exactly what makes it embedded.</li>\n</ul>\n<h4>Embedded doesn''t mean small or simple</h4>\n<ul>\n<li>An engine management system in a car is doing extraordinary work thousands of times a second. It''s still embedded, because it is <em>dedicated</em> to that one job inside a larger machine.</li>\n<li>The opposite of \"embedded\" is not \"big\" — it''s <strong>general purpose</strong>. A laptop is general purpose because you can install anything on it and make it do almost any task.</li>\n</ul>\n<h4>The word \"dedicated\"</h4>\n<ul>\n<li>You''ll see this word all over the mark schemes: <strong>dedicated hardware</strong>, <strong>dedicated microprocessor</strong>, <strong>dedicated to one function</strong>.</li>\n<li>It means \"reserved for this one job and nothing else\". The microprocessor inside a set of automatic headlights does nothing but check the light level and switch the lights — it will never run a spreadsheet.</li>\n</ul>", "check": {"question": "Which is the best definition of an embedded system?", "options": ["Any general-purpose computer that happens to be physically small", "A computer system built into a larger device to perform one specific task", "A computer system that has no screen or keyboard connected to it", "A computer that cannot connect to the internet or download any new software updates"], "answer": 1, "explain": "Both halves matter: built INTO a larger device, and dedicated to one specific (or limited) task. Size and screens have nothing to do with it — an engine management system is powerful, and plenty of general-purpose computers are small."}}, {"title": "The characteristics of an embedded system", "html": "<h4>The list that earns the marks</h4>\n<ul>\n<li><strong>One specific purpose</strong> — it performs a single task, or only a few limited functions.</li>\n<li><strong>Built into a larger device</strong> — it is part of a bigger machine, not a machine in its own right.</li>\n<li><strong>Dedicated hardware</strong> — its own microprocessor and sensors, used only for this system.</li>\n<li><strong>Hard to change</strong> — the program is usually stored in ROM as <strong>firmware</strong>, so it isn''t updated or replaced the way you install apps on a phone.</li>\n<li><strong>Often a control system</strong> — it senses something and responds automatically, without the user telling it to.</li>\n<li><strong>Few components</strong>, all essential to its purpose; typically small, cheap and low-power.</li>\n</ul>\n<h4>Why \"it has a microprocessor\" alone isn''t worth much</h4>\n<ul>\n<li>Every computer has a microprocessor — so that fact doesn''t distinguish anything. The creditworthy version is <strong>\"it has a <em>dedicated</em> microprocessor\"</strong>, i.e. one doing only this job.</li>\n</ul>\n<h4>Firmware — the reason your washing machine has no app store</h4>\n<ul>\n<li><strong>Firmware</strong> is software stored permanently in ROM. It boots instantly, never gets deleted, and normally cannot be changed by the user.</li>\n<li>That''s why you can''t install a game on your dishwasher: its instructions are fixed in hardware-level storage, not loaded from a disk like on a general-purpose computer.</li>\n</ul>", "check": {"question": "Which statement about an embedded system''s software is correct?", "options": ["Users install and update apps on it freely, just like on a phone", "Its program is usually firmware stored in ROM and is hard to change", "It has no software at all, only electronic circuits and wires", "It downloads and installs a brand new operating system every time it starts"], "answer": 1, "explain": "Embedded systems normally run firmware held in ROM — fixed, instant to start, and not something the user updates or replaces."}}, {"title": "Embedded vs general purpose — the question they always ask", "html": "<h4>The test to apply</h4>\n<ul>\n<li>Ask yourself: <strong>\"Can I install whatever I like on it and make it do a completely different job?\"</strong></li>\n<li><strong>Yes</strong> → it''s a <strong>general-purpose</strong> computer (laptop, desktop, tablet, smartphone).</li>\n<li><strong>No — it does its one job forever</strong> → it''s an <strong>embedded system</strong> (smart watch, washing machine, sat nav, microwave).</li>\n</ul>\n<h4>Worked comparison: smart watch vs laptop</h4>\n<ul>\n<li><strong>Smart watch = embedded.</strong> It is not a general-purpose computer: it has limited, dedicated functions; a microprocessor on a single circuit board; a built-in OS that you cannot really change; and few components, all essential to its purpose.</li>\n<li><strong>Laptop = general purpose.</strong> You can install any software you like and use it for any number of tasks; its hardware can be expanded; its OS can be updated or even replaced.</li>\n</ul>\n<h4>Is a tablet an embedded system? (No — and here''s the reasoning)</h4>\n<ul>\n<li>A tablet has <strong>multiple functions</strong> and is <strong>general purpose</strong>; an embedded system has one or few.</li>\n<li>A tablet is a <strong>self-contained system</strong>, not part of a larger machine.</li>\n<li>You can <strong>update or install software</strong> on a tablet freely.</li>\n</ul>\n<h4>The nuance that impresses: a phone <em>contains</em> embedded systems</h4>\n<ul>\n<li>A smartphone is a <strong>general-purpose computer</strong> — but the camera-stabilising module and the battery-management chip inside it <em>are</em> embedded systems.</li>\n<li>So the question \"is this device an embedded system?\" is different from \"does this device contain embedded systems?\". Read the question carefully.</li>\n</ul>", "check": {"question": "Why is a tablet NOT an embedded system?", "options": ["It is too small to contain a full operating system, storage chip or microprocessor", "It is general purpose — it has many functions and you can install new software", "It has a microprocessor, exactly like every embedded system does", "It uses electricity, exactly like every embedded system does too"], "answer": 1, "explain": "Embedded systems do one dedicated job inside a larger device and can''t easily be repurposed. A tablet is a self-contained, general-purpose computer you can install anything on."}}, {"title": "A range of examples (the spec wants breadth)", "html": "<h4>Around the house</h4>\n<ul>\n<li><strong>Washing machine</strong> — runs the chosen programme: fill, wash, spin, drain.</li>\n<li><strong>Microwave, dishwasher, fridge/freezer, oven</strong> — each with one job and a control panel.</li>\n<li><strong>Central heating thermostat</strong> — senses temperature, switches the boiler.</li>\n<li><strong>TV remote, printer, digital camera, MP3 player.</strong></li>\n</ul>\n<h4>Inside a car (a favourite exam context)</h4>\n<ul>\n<li><strong>Engine management system</strong>, <strong>anti-lock brakes</strong>, <strong>parking sensors</strong>, <strong>cruise control</strong> (including \"follow me\" adaptive systems), <strong>automatic lights</strong>, <strong>automatic windscreen wipers</strong>, <strong>climate control</strong>, <strong>sat nav / GPS</strong>, <strong>lane assist</strong>, <strong>auto-park</strong>, <strong>dashcam</strong>.</li>\n<li><strong>Watch the context.</strong> If the question says \"in a car\", answering \"a washing machine\" scores nothing — real candidates lost marks doing exactly that.</li>\n</ul>\n<h4>Worn, medical and industrial</h4>\n<ul>\n<li><strong>Smart watch</strong>, <strong>fitness tracker</strong>, <strong>pacemaker</strong>, <strong>insulin pump</strong>.</li>\n<li><strong>Traffic lights</strong>, <strong>manufacturing/robotic equipment</strong>, <strong>vending machines</strong>, <strong>ticket machines</strong>, <strong>lifts</strong>, <strong>security alarms</strong>.</li>\n</ul>\n<h4>Learn three you can always reach for</h4>\n<ul>\n<li>Keep a reliable trio in your head — <strong>washing machine, sat nav, traffic lights</strong> — for any \"identify three devices containing embedded systems\" question. Then swap them for context-appropriate ones when the question sets a scene.</li>\n</ul>", "check": {"question": "A question asks you to identify an embedded system found in a CAR. Which answer earns the mark?", "options": ["A washing machine used to wash clothes at home", "A microwave used to heat and cook food", "The engine management system fitted inside the car", "A desktop computer used for browsing and general office work"], "answer": 2, "explain": "The context is the car. Washing machines and microwaves are embedded systems, but they''re not in a car — candidates genuinely lost this mark by ignoring the scenario."}}, {"title": "How to answer: apply it, don''t define it", "html": "<h4>The single biggest mark-loser on this topic</h4>\n<ul>\n<li>Questions here almost always give you a <strong>scenario</strong> — Ali''s tablet, Xander''s smart watch, the car''s ''Follow Me'' system — and ask you to <strong>justify</strong> or <strong>explain</strong>.</li>\n<li>Writing a textbook definition of an embedded system earns <strong>nothing</strong>. The mark scheme is explicit: <em>answers must be applied to the scenario; do not award generic definitions.</em></li>\n</ul>\n<h4>The two-part sentence that always works</h4>\n<ul>\n<li><strong>Feature → applied to this device.</strong></li>\n<li>❌ Generic: \"An embedded system has limited functions.\"</li>\n<li>✅ Applied: \"An embedded system has limited functions, <strong>and the smart watch</strong> only tracks time, steps and heart rate — it cannot be used for any task you like.\"</li>\n<li>Same feature. The second one scores.</li>\n</ul>\n<h4>Don''t hand back the question</h4>\n<ul>\n<li>If the question already tells you the system is \"built into the car\", you cannot earn a mark by saying \"it is built into the car\". That point is <strong>in the question</strong>, so it shows no knowledge of your own.</li>\n<li>Reach for a different characteristic instead: dedicated microprocessor, limited functions, firmware that can''t be changed.</li>\n</ul>\n<h4>Count the marks, make that many points</h4>\n<ul>\n<li>A 3-mark \"explain why this is an embedded system\" wants <strong>three separate characteristics</strong>. Many candidates give one good point and stop — which caps them at 1.</li>\n<li>Have the list ready: specific purpose · built into a larger device · dedicated hardware/microprocessor · firmware, hard to change · automated control system.</li>\n</ul>", "check": {"question": "A 2-mark question asks you to justify why a smart watch is an embedded system. Which answer scores?", "options": ["An embedded system is a computer system that is built into a larger device and performs one specific purpose", "A smart watch is not a general-purpose computer — it has limited, dedicated functions", "Smart watches are small enough to be worn comfortably on a wrist", "It has a microprocessor, which every general-purpose computer also has"], "answer": 1, "explain": "Only the second applies the feature to THIS device. The first is a textbook definition — explicitly not credited on a justify question — and the last two say nothing that distinguishes an embedded system."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Embedded system", "definition": "A computer system built into a larger device to perform one specific task"}, {"term": "General-purpose computer", "definition": "Runs any software and performs many tasks — e.g. laptop, tablet, PC"}, {"term": "Purpose of an embedded system", "definition": "To carry out one dedicated function within a larger device"}, {"term": "Dedicated hardware", "definition": "Microprocessor and components reserved for this one system only"}, {"term": "Firmware", "definition": "Software stored permanently in ROM; normally cannot be changed by the user"}, {"term": "Why firmware matters", "definition": "Instructions are fixed, so an embedded system''s function is hard to change"}, {"term": "Control system", "definition": "Senses something and responds automatically, without user input"}, {"term": "Typical characteristics", "definition": "One purpose · built into a larger device · dedicated hardware · firmware · few components"}, {"term": "Household examples", "definition": "Washing machine, microwave, dishwasher, thermostat, printer"}, {"term": "Car examples", "definition": "Engine management, ABS, parking sensors, cruise control, automatic lights, sat nav"}, {"term": "Wearable / medical examples", "definition": "Smart watch, fitness tracker, pacemaker, insulin pump"}, {"term": "Industrial examples", "definition": "Traffic lights, manufacturing robots, vending machines, lifts"}, {"term": "Is a tablet embedded?", "definition": "No — it is self-contained, general purpose, and software can be installed"}, {"term": "Is a smart watch embedded?", "definition": "Yes — limited dedicated functions, built-in OS, few essential components"}, {"term": "Smartphone nuance", "definition": "General purpose overall, but contains embedded systems inside it"}, {"term": "Justify questions", "definition": "Apply the characteristic to the device — generic definitions score 0"}, {"term": "Never repeat the question", "definition": "If the stem says ''built into the car'', that point earns no mark"}, {"term": "3-mark explain", "definition": "Three separate characteristics, each applied to the scenario"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which best defines an embedded system?", "options": ["Any computer that has no physical keyboard attached to it at all", "A computer system built into a larger device to perform one specific task", "A computer that runs on rechargeable batteries instead of mains electricity", "A very small laptop with a stripped-down operating system already installed"], "answer": 1, "explain": "Two halves: built INTO a larger device, and dedicated to one specific (or limited) task. Size, batteries and keyboards are irrelevant."}, {"question": "Which of these is an embedded system?", "options": ["A desktop PC with a full operating system used for browsing and office work", "A laptop with a full operating system used for work and browsing", "A washing machine that runs one fixed wash programme automatically", "A tablet with a touchscreen used for apps, browsing and video streaming"], "answer": 2, "explain": "The washing machine''s computer does one job forever. The other three are general-purpose computers you can install any software on."}, {"question": "Why is a laptop NOT an embedded system?", "options": ["It is too expensive for an average household budget to justify", "It is general purpose — you can install any software you like", "It has a microprocessor, since every modern computer needs one", "It uses an operating system that loads fresh each time it boots"], "answer": 1, "explain": "General purpose is the opposite of embedded. Having a microprocessor or an OS doesn''t decide it — embedded systems have those too."}, {"question": "An embedded system''s program is usually stored as firmware in ROM. What does this mean in practice?", "options": ["The user can install and remove new apps whenever they like", "The instructions are fixed and normally cannot be changed by the user", "The program is deleted permanently every time the power is switched off", "The system needs a hard drive to store its operating system"], "answer": 1, "explain": "Firmware in ROM is permanent and non-volatile — it starts instantly and the user doesn''t update or replace it. That''s why there''s no app store on your dishwasher."}, {"question": "Which phrase would actually earn a mark when describing an embedded system?", "options": ["It has a microprocessor, just like any general-purpose computer", "It has a dedicated microprocessor doing only this job", "It is electronic and needs a power supply to work", "It has a circuit board holding its electronic components"], "answer": 1, "explain": "Every computer has a microprocessor, so that fact distinguishes nothing. ''Dedicated'' is the word that carries the meaning."}, {"question": "A question asks for an embedded system found in a car. Which answer earns the mark?", "options": ["A microwave used to heat food in the kitchen", "A washing machine used to wash clothes at home", "The anti-lock braking system fitted to the car", "A games console used to play video games at home"], "answer": 2, "explain": "Read the context. The first two ARE embedded systems, but they''re not in a car — candidates lost this exact mark in the real exam."}, {"question": "Ali says his tablet is an embedded system. Which reason shows he is incorrect?", "options": ["Tablets have touchscreens, and touchscreens are only found on embedded systems", "A tablet has multiple functions and is general purpose, unlike an embedded system", "Tablets are portable, and only embedded systems are designed to be portable", "Tablets use rechargeable batteries, whereas embedded systems always run on mains power only"], "answer": 1, "explain": "The deciding characteristic is purpose: an embedded system does one dedicated job; a tablet does anything you install on it."}, {"question": "Which statement is TRUE about a smartphone?", "options": ["It is an embedded system, since it only runs the apps that come pre-installed on it", "It is general purpose, but it contains embedded systems inside it", "It contains no embedded systems at all, only general-purpose software", "It is firmware — permanent software stored directly in its ROM chip"], "answer": 1, "explain": "A neat distinction: the phone itself is a general-purpose computer, but components inside it (battery management, camera stabilisation) are embedded systems."}, {"question": "Why is a smart watch classed as an embedded system?", "options": ["It is small enough to be worn comfortably on your wrist all day", "It is not a general-purpose computer — it has limited, dedicated functions", "It connects to a phone over Bluetooth to sync data, notifications and health tracking", "It has a touchscreen you can tap and swipe to interact with it"], "answer": 1, "explain": "Limited, dedicated function is the reason. Size, touchscreens and connectivity say nothing about whether something is embedded."}, {"question": "Which is a typical characteristic of an embedded system?", "options": ["It can be expanded with new hardware whenever the user wants", "It has few components, all essential to its purpose", "It runs any software the user installs", "It always has a large screen"], "answer": 1, "explain": "Embedded systems are built with only what the one job needs — few components, dedicated hardware, limited functions."}, {"question": "A cruise control system keeps a car at a set distance from the car in front, with no driver input. Which characteristic does this best show?", "options": ["It is general purpose, so it could be reprogrammed to do any task", "It is an automated control system with a specific purpose", "It can run any software the driver chooses to install on it", "It has a large amount of storage for the driver''s personal files"], "answer": 1, "explain": "It senses something and responds automatically without the user — an automated control system dedicated to that one task."}, {"question": "A 3-mark question asks you to explain why a system is embedded. What should your answer contain?", "options": ["One very detailed point about the system''s single specific purpose", "Three separate characteristics of embedded systems, each applied to the scenario", "A definition copied word-for-word from the textbook, with no reference to the scenario at all", "A list of other embedded systems found in similar everyday devices"], "answer": 1, "explain": "Three marks means three distinct points — and each must be applied to the scenario. Real candidates commonly gave one point and stopped."}]}, "fib": {"enabled": true, "questions": [{"text": "An embedded system is a computer built into a [larger] device, dedicated to one [specific] task."}, {"text": "Embedded systems have limited [functions] and often use [dedicated] hardware reserved for that one job."}, {"text": "The program of an embedded system is usually stored as [firmware] in [ROM], so the user cannot easily change it."}, {"text": "The opposite of an embedded system is a [general] purpose computer, such as a laptop or [tablet]."}, {"text": "Two household examples of embedded systems are a [washing] machine and a [microwave]."}, {"text": "In a car, the [engine] management system and the automatic [lights] are both embedded systems."}, {"text": "Saying ''it has a microprocessor'' earns nothing — you must say it has a [dedicated] microprocessor."}, {"text": "On a justify question you must [apply] the characteristic to the device in the question — a generic [definition] scores nothing."}]}, "tf": {"enabled": true, "questions": [{"statement": "An embedded system is any computer that is physically small.", "answer": false, "explain": "Size has nothing to do with it. An engine management system is powerful and complex, but it''s embedded because it''s dedicated to one job inside a larger machine."}, {"statement": "A washing machine contains an embedded system.", "answer": true, "explain": "Correct — a computer built into the machine, doing exactly one job: running the wash programme you selected."}, {"statement": "A tablet computer is an embedded system because it has a microprocessor and an operating system.", "answer": false, "explain": "Both are true of tablets, and neither makes something embedded. A tablet is self-contained, general purpose, and you can install whatever you like on it."}, {"statement": "The software in an embedded system is usually firmware stored in ROM.", "answer": true, "explain": "Yes — fixed, non-volatile, instant to start, and normally not changeable by the user. It''s why you can''t install apps on a microwave."}, {"statement": "A smartphone is a general-purpose computer, but it contains embedded systems inside it.", "answer": true, "explain": "A neat distinction worth knowing: the phone itself runs anything you install, but its battery-management and camera-stabilisation chips are dedicated embedded systems."}, {"statement": "Writing ''an embedded system has limited functions'' is enough to justify why a smart watch is embedded.", "answer": false, "explain": "That''s a generic definition, and the mark scheme explicitly refuses those on justify questions. Apply it: ''…and the smart watch only tracks time, steps and heart rate''."}, {"statement": "If a question says a system is ''built into the car'', you can earn a mark by saying it is built into the car.", "answer": false, "explain": "That point is already in the question, so it shows no knowledge of your own — it is explicitly not awarded. Use a different characteristic instead."}, {"statement": "Embedded systems are often control systems that respond automatically without the user.", "answer": true, "explain": "True — automatic headlights sense the light level and switch on by themselves; cruise control maintains speed and distance with no driver input."}]}, "misc": {"enabled": true, "items": [{"myth": "Answering a ''justify'' question with a textbook definition: ''An embedded system is built into a larger device and has one purpose.''", "truth": "The mark scheme for these questions says it outright: <strong>answers must be applied to the scenario; do not award generic definitions.</strong> Candidates who gave a perfect definition of an embedded system scored zero, because the question asked about <em>this</em> smart watch or <em>this</em> tablet. Use the two-part sentence: <strong>feature → applied to this device.</strong> Weak: ''embedded systems have limited functions.'' Strong: ''embedded systems have limited functions, and the smart watch only tracks time, steps and heart rate — it cannot be used for any task you like.''", "check": {"question": "Why does a flawless definition of an embedded system score 0 on a ''justify your choice'' question?", "options": ["Definitions are always wrong on every type of exam question", "The question needs the characteristic applied to the device in the scenario", "It is too short to cover all the required assessment objectives", "Definitions belong only in the conclusion, never at the start of an exam answer"], "answer": 1, "explain": "Justify and explain questions test application. The knowledge is only creditworthy once it is attached to the device in front of you."}}, {"myth": "Giving ''it is built into the car'' as a reason why a car system is embedded — when the question already told you it''s in the car.", "truth": "You cannot earn marks by handing the question back. This point is <strong>in the stem</strong>, so it is explicitly not awarded — real candidates repeated it and got nothing. Reach for a characteristic the question <em>hasn''t</em> given you: it has <strong>limited functions</strong> (the system only checks the light level and switches the lights), it has a <strong>dedicated microprocessor</strong>, or its function is <strong>hard to change</strong>.", "check": {"question": "The question states: ''A car comes with many embedded systems, for example parking sensors.'' Which explanation would earn a mark?", "options": ["It is built into the car, exactly as the question already states", "It is part of a larger machine, just like every embedded system is", "It has a dedicated microprocessor that only monitors the sensors", "The car contains it, along with many other embedded systems too"], "answer": 2, "explain": "The first, second and fourth are all just restating what the question already said. Only the dedicated-microprocessor point adds knowledge of your own."}}, {"myth": "For ''identify an embedded system in a car'', answering ''a washing machine'' or ''a microwave''.", "truth": "These <em>are</em> embedded systems — but they are not in a car, and the examiner report notes candidates genuinely gave them and scored nothing. <strong>The context sets the answer.</strong> For a car, use: engine management, anti-lock brakes, parking sensors, cruise control, automatic lights or wipers, climate control, sat nav, lane assist. Always re-read the scenario before you pick your example.", "check": {"question": "What went wrong when candidates answered ''washing machine'' to a question about embedded systems in a car?", "options": ["A washing machine is not an embedded system at all, in any context", "The answer ignored the context — it''s valid, just not an example found in a car", "Washing machines have no microprocessor or any dedicated hardware components at all", "The spelling of ''washing machine'' was wrong in the candidate''s answer"], "answer": 1, "explain": "The example itself is fine; it just doesn''t answer the question that was asked. Context-appropriate examples are the whole point of an applied question."}}, {"myth": "Saying ''it has a microprocessor'' as a characteristic that makes something embedded.", "truth": "Every computer has a microprocessor — a laptop, a games console, a server. So the fact distinguishes nothing and adds no knowledge. The creditworthy version is <strong>''it has a <em>dedicated</em> microprocessor''</strong>, i.e. one doing only this job and nothing else — better still, prove it with an example: ''there is a microprocessor that does nothing but check the light level''.", "check": {"question": "Which version of the microprocessor point is worth a mark?", "options": ["It has a microprocessor, just like every other type of computer", "It is controlled by electronics, like nearly all modern devices", "It has a dedicated microprocessor that only monitors the light level", "It contains a chip, which almost every modern electronic device also has"], "answer": 2, "explain": "''Dedicated'', ideally with an example of the one job it does, is what shows understanding of an embedded system."}}, {"myth": "Answering a 3-mark ''explain why this is an embedded system'' with one good point, written at length.", "truth": "Three marks means <strong>three separate characteristics</strong>. The examiner report is blunt: most candidates got the ''single purpose'' point, some added ''built into a larger system'', but <strong>few could produce a third</strong>. Keep the list ready and work down it: <strong>specific purpose · built into a larger device · dedicated hardware/microprocessor · firmware that is hard to change · automated control system</strong>. Three short applied sentences beat one long one every time.", "check": {"question": "A 3-mark question asks why the ''Follow Me'' cruise control is an embedded system. What''s the best structure?", "options": ["One very detailed paragraph focused only on its single specific purpose", "Three different characteristics, each linked to the Follow Me system", "A definition of an embedded system copied straight from a textbook", "A list of other cars that also come fitted with cruise control"], "answer": 1, "explain": "One mark per characteristic, to a maximum of three — so three distinct points, each applied to the system in the question."}}, {"myth": "Thinking that because a smartphone runs apps, nothing inside it can be an embedded system.", "truth": "Both things are true at once. The <strong>phone as a whole</strong> is a general-purpose computer — you install what you like. But <strong>inside it</strong> sit embedded systems: the battery-management chip, the camera-stabilisation module. So watch the exact wording: <em>''Is this device an embedded system?''</em> and <em>''Does this device contain embedded systems?''</em> have different answers for a phone.", "check": {"question": "Which statement about a smartphone is correct?", "options": ["It is an embedded system, since every part of it does one fixed job", "It is general purpose overall, but contains embedded systems inside it", "It contains no embedded systems anywhere inside it, only general-purpose software", "It is firmware — instructions stored permanently inside a ROM chip"], "answer": 1, "explain": "The device itself is general purpose; specific dedicated components inside it are embedded systems. Read whether the question asks ''is'' or ''contains''."}}]}, "tips": {"enabled": true, "items": [{"title": "''Justify'' and ''explain'' questions: from 0 to full marks", "html": "<p>Nearly every question on this topic gives you a scenario and asks you to justify or explain. Here is the same answer to <em>\"Justify why the smart watch is an example of an embedded system\"</em> <strong>[2]</strong> at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"An embedded system is a computer built into a larger device with one specific purpose.\"</p>\n<ul>\n<li>A textbook-perfect definition — and worth nothing. The mark scheme says: <em>answers must be applied to the scenario; do not award generic definitions.</em></li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"A smart watch is not a general-purpose computer.\"</p>\n<ul>\n<li>Applied to the device, so it scores — but it stops there. The second mark needs a development.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"A smart watch is not a general-purpose computer <strong>(1)</strong>, which means it only has limited, dedicated functions such as tracking your steps and heart rate — you cannot install any software you like on it <strong>(1)</strong>.\"</p>\n\n<p><strong>The formula:</strong> feature of an embedded system → <em>\"…and this device…\"</em> → the specific evidence from the scenario.</p>\n\n<p><strong>Bonus technique:</strong> you''re also allowed to argue the opposite way — \"a laptop <em>is</em> general purpose because you can install any software\" — as long as you don''t just repeat the same point twice in different words.</p>", "check": {"question": "You''ve written ''a smart watch is not a general-purpose computer''. What earns the second mark?", "options": ["Saying the exact same point again, just phrased in slightly different words", "Adding what its limited, dedicated functions actually are on this device", "Defining an embedded system in general, textbook terms", "Naming a completely different embedded system as an example"], "answer": 1, "explain": "The second mark is the development: the specific evidence from the scenario that proves your point."}}, {"title": "Counting the marks — and never repeating the question", "html": "<p><strong>1. The tariff tells you how many points to make.</strong></p>\n<ul>\n<li><em>\"Explain the reasons why the ''Follow Me'' system is an example of an embedded system\"</em> <strong>[3]</strong> = <strong>three</strong> separate characteristics, each applied.</li>\n<li>The examiner report on this exact question: most candidates got \"single purpose\", some added \"built into the car\", but <strong>few managed a third point</strong>. That third mark is sitting there for anyone with the list memorised.</li>\n<li><strong>Your list:</strong> specific purpose · built into a larger device · dedicated hardware / microprocessor · firmware, hard to change · automated control system.</li>\n</ul>\n\n<p><strong>2. Never hand the question back.</strong></p>\n<ul>\n<li>If the stem says \"A car comes with many embedded systems…\", then <strong>\"it is built into the car\"</strong> earns nothing — that point is in the question.</li>\n<li>Cross it off your list for that question and use the next characteristic instead.</li>\n</ul>\n\n<p><strong>3. Match the example to the context.</strong></p>\n<ul>\n<li>Asked for an embedded system <strong>in a car</strong>? Engine management, ABS, parking sensors, cruise control, automatic lights or wipers, climate control, sat nav.</li>\n<li>Candidates who wrote \"washing machine\" or \"microwave\" for a car question scored zero — right idea, wrong scene.</li>\n</ul>\n\n<p><strong>4. \"Identify three devices\" = three quick words.</strong></p>\n<ul>\n<li>No explanation needed, no marks for detail — just three valid devices. Keep a reliable trio ready: <strong>washing machine, sat nav, traffic lights</strong>.</li>\n</ul>", "check": {"question": "A question says: ''Parking sensors are an embedded system in a car. Identify one other embedded system in a car and explain why.'' Which explanation is refused?", "options": ["It has a dedicated microprocessor", "It only performs one limited function", "It is built into the car", "The user cannot change what it does"], "answer": 2, "explain": "''Built into the car'' is stated in the question itself, so it cannot earn a mark — it shows no knowledge of your own."}}, {"title": "The word-bank question: read the sentence, not just the list", "html": "<p>This topic often gives a paragraph with gaps and a <strong>bank of terms</strong> — with the warning <em>\"Not all terms are used\"</em>. Those spare terms are deliberate traps.</p>\n\n<p><strong>How to beat it:</strong></p>\n<ul>\n<li><strong>Read the whole sentence first</strong>, then choose. \"Embedded systems have limited ……\" — <em>functions</em> fits; <em>applications</em> and <em>range</em> are plausible-looking decoys.</li>\n<li><strong>Watch the grammar.</strong> \"built into a …… machine\" needs an adjective (<em>larger</em>), not a noun (<em>laptop</em>).</li>\n<li><strong>Use each term once</strong>, and expect several to be left over. If you''ve used every word, you''ve made a mistake.</li>\n<li><strong>Do the ones you''re sure of first</strong> — eliminating terms makes the harder gaps much easier.</li>\n</ul>\n\n<p><strong>Classic decoy pairs to watch for:</strong></p>\n<ul>\n<li><em>microprocessor</em> vs <em>processor</em> — both look right; the sentence decides.</li>\n<li><em>larger</em> vs <em>smaller</em> — an embedded system is built into a <strong>larger</strong> machine.</li>\n<li><em>functions</em> vs <em>applications</em> — embedded systems have limited <strong>functions</strong>.</li>\n</ul>", "check": {"question": "In ''They are often built into a …… machine'', which term fits and why?", "options": ["laptop — it is a type of general-purpose computing machine, so the word fits grammatically", "larger — the gap needs an adjective, and embedded systems sit inside bigger devices", "smaller — embedded systems are usually physically small in size", "processor — it is simply a computer part found inside a machine"], "answer": 1, "explain": "Grammar plus meaning: the gap needs an adjective before ''machine'', and the whole point of embedded is being built into something LARGER."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Explain the reasons why SmartPark is an example of an embedded system.</p>", "marks": 3, "hint": "Three marks means three DIFFERENT characteristics, each applied to SmartPark specifically — don''t just repeat ''it parks the car'' three times in different words.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark each, up to 3, for any of the following applied to SmartPark)</h5>\n<ul>\n<li>Has a specific or limited purpose — SmartPark can only park the car and cannot do anything else</li>\n<li>Is built into a larger device: the car</li>\n<li>Has dedicated hardware or sensors that are used only for this system, such as the bumper sensors</li>\n<li>Its instructions are stored as firmware, so its function is hard to change or update</li>\n<li>It is an automated control system that acts by itself, without the driver operating it</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award one mark for each distinct characteristic, up to a maximum of three.</li>\n<li>A characteristic must be linked to SmartPark to be credited — a definition with no reference to SmartPark at all should not be awarded more than one mark overall.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Students often score the first two marks quickly — a single purpose, and being built into the car — then run out of a third, different idea. Keep a short mental list of embedded-system features ready (specific purpose, built into a larger device, dedicated hardware, firmware that''s hard to change, automatic control) so you always have a fresh one to reach for, and make sure every point is tied to SmartPark rather than left as a general textbook definition.</p>\n</div>"}, {"question": "<p>Identify <strong>one other</strong> embedded system that could be found in Maya''s car, other than SmartPark, and explain why it is an embedded system.</p>", "marks": 3, "hint": "Pick an example that''s genuinely found IN A CAR — and for the explanation, reach for a characteristic other than ''it''s built into the car'', since that''s already true of SmartPark in the scenario.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark for a valid example; 1 mark each, up to 2, for the explanation)</h5>\n<p><strong>1 mark for a valid example, e.g.:</strong></p>\n<ul>\n<li>Automatic headlights</li>\n<li>Automatic windscreen wipers</li>\n<li>Sat nav or GPS</li>\n<li>Climate control</li>\n<li>Lane-keeping assist</li>\n<li>Engine management system</li>\n<li>Cruise control</li>\n<li>Dashcam</li>\n<li>Tyre-pressure monitor</li>\n</ul>\n<p><strong>1 mark each, up to 2, for the explanation:</strong></p>\n<ul>\n<li>Limited or specific function — ideally with an example, e.g. it only checks the light level and switches the headlights on or off</li>\n<li>Dedicated microprocessor or hardware, e.g. there is a microprocessor that does nothing except monitor the light sensor</li>\n<li>Hard to change function, e.g. the driver cannot make the headlight system do any other job</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept anything that could reasonably be found in a car.</li>\n<li>If the explanation is a fully generic definition with no link at all to the named example, cap the explanation at 1 mark.</li>\n<li>Do not award ''it is built into the car'' on its own — that idea already applies to SmartPark in the scenario, so it shows no new knowledge here.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>The most common slip is naming something that isn''t actually in a car — a washing machine or a microwave is a genuine embedded system, but it scores nothing here because the question is about Maya''s car specifically. The second common slip is writing ''it''s built into the car'' as if it were new information: the scenario already tells you that, so it earns nothing on its own. Aim for a second explanation point that''s genuinely different from the first, not the same idea in different words.</p>\n</div>"}, {"question": "<p>Freya''s tablet computer runs a full operating system, and she can install any app she likes from an app store.</p><p>Freya thinks her tablet is an embedded system.</p><p>State whether Freya is correct or incorrect, justifying your choice.</p>", "marks": 3, "hint": "Decide first, then justify with characteristics of an embedded system applied to the tablet — every point must mention the tablet itself, or it won''t be credited.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, up to 3) — e.g.</h5>\n<ul>\n<li>An embedded system has one or a few dedicated functions, but the tablet has many functions and is general purpose.</li>\n<li>An embedded system is built into a larger device, but the tablet is a self-contained device in its own right.</li>\n<li>An embedded system''s software is fixed firmware that is hard to change, but Freya can install and update apps on her tablet whenever she likes.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Cap the mark at 2 if none of the points are applied to the tablet.</li>\n</ul>\n</div>"}, {"question": "<p>The following paragraph describes embedded systems.</p><p>Complete the paragraph by selecting terms from the list and writing them in the correct places. <strong>Not all terms are used.</strong></p>", "marks": 4, "hint": "Read the whole sentence before choosing — ''limited'' and ''general'' are decoys for the first gap, and ''smaller'' is a decoy for the second. Several terms are not used at all.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each correct term)</h5>\n<p>Embedded systems have a <strong>specific</strong> purpose. They are usually built into a <strong>larger</strong> device. Their program is normally stored as <strong>firmware</strong>, which the user cannot easily <strong>change</strong>.</p>\n</div>"}, {"question": "<p>Tick (✓) <strong>one</strong> box to show which of Tariq''s two devices is an example of an embedded system.</p>", "marks": 1, "hint": "Which of the two can only ever do its own small set of jobs, and can''t be reprogrammed to do something completely different?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>PulseBand (the fitness tracker)</strong> is the correct answer.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; ticking both boxes scores 0.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Most students get this one right once they focus on function rather than size or price — a laptop can feel more \"ordinary\" than a fitness tracker, but ordinary isn''t the test. The real test is whether the device can be reprogrammed to do a completely different job: the laptop can, PulseBand can''t.</p>\n</div>"}, {"question": "<p>Justify your answer to part (i).</p>", "marks": 2, "hint": "Apply your reasoning specifically to PulseBand (or explain why the laptop doesn''t fit) — a generic definition of an embedded system with no reference to either device won''t be credited.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point, up to 2)</h5>\n<ul>\n<li>PulseBand is not a general-purpose computer — it has limited, dedicated functions, e.g. it only tracks heart rate, steps and sleep.</li>\n<li>PulseBand has a dedicated microprocessor built in, doing only this one job.</li>\n<li>PulseBand''s software is fixed firmware, so its function is hard for Tariq to change, unlike his laptop.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Answers must be applied to the scenario — a generic definition of an embedded system with no reference to PulseBand or the laptop is not credited.</li>\n<li>Allow the opposite argument (explaining why the laptop is not embedded) but do not credit the same point made twice.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>The most common way to lose both marks here is writing out the textbook definition of an embedded system without ever mentioning PulseBand or the laptop by name. A definition on its own shows you''ve learned the theory, but this question tests whether you can apply it — name the actual limited functions PulseBand has, or point out that Tariq can reprogram the laptop but not PulseBand.</p>\n</div>"}, {"question": "<p>Jodie''s robot vacuum cleaner contains an embedded system. Define what is meant by an ''embedded system''.</p>", "marks": 1, "hint": "One sentence. The examiner wants the ''built into another device, doing one job'' idea.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>A computer system that is built into another (larger) device to carry out one specific task, or a small number of dedicated tasks.</li>\n</ul>\n</div>"}, {"question": "<p>Identify <strong>three</strong> devices, other than a robot vacuum cleaner, that contain embedded systems.</p>", "marks": 3, "hint": "Three quick answers — no explanation needed, and no marks for detail. Just don''t repeat the robot vacuum.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks — any three from:</h5>\n<ul>\n<li>Washing machine</li>\n<li>Dishwasher</li>\n<li>Microwave</li>\n<li>Digital camera</li>\n<li>Fitness tracker or smart watch</li>\n<li>Traffic lights</li>\n<li>Vending machine</li>\n<li>Central heating thermostat</li>\n<li>Manufacturing/robotic equipment</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>1 mark for each correct, distinct device, up to a maximum of 3.</li>\n<li>Many other genuine examples of devices containing embedded systems are acceptable.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-2-1-primary-storage-memory', '1.2.1 Primary Storage (Memory)', '{"learn": {"enabled": true, "items": [{"title": "Why does a computer need primary storage?", "html": "<h4>Why can''t the CPU just use secondary storage?</h4>\n<ul>\n<li>A computer''s <strong>secondary storage</strong> — its SSD or hard drive — holds files and programs <em>permanently</em>, but it is far too <strong>slow</strong> for the CPU to work from directly.</li>\n<li><strong>Primary storage</strong> is the memory the CPU is wired to and can access almost instantly. Before any program can run, it must first be <strong>loaded</strong> from secondary storage into primary storage.</li>\n<li>Everyday example: double-clicking a game icon doesn''t run the game straight off the hard drive — it copies the game''s code and data into RAM first, which is why there''s a short pause while it \"loads\".</li>\n</ul>\n<h4>Two very different jobs</h4>\n<ul>\n<li>Primary storage actually covers <strong>two</strong> different types of memory with opposite jobs: <strong>RAM</strong>, which holds whatever is currently running, and <strong>ROM</strong>, which holds the fixed instructions needed to start the computer up.</li>\n<li>Both sit inside primary storage because both must be instantly accessible to the CPU — but what they store, and whether they can be changed, are completely different (next two cards).</li>\n</ul>", "check": {"question": "Why can''t a program run directly from an SSD or hard drive?", "options": ["Secondary storage can only hold data files, never the actual program code itself, so there is nothing to load", "Secondary storage is far too slow for the CPU to access directly, so the program is loaded into RAM first", "The CPU has no physical connection to secondary storage, so data cannot move between them at all", "Programs are always stored permanently in ROM instead of on secondary storage"], "answer": 1, "explain": "Secondary storage is permanent but slow. The CPU needs data at the speed of primary storage, so programs are loaded into RAM before they run."}}, {"title": "RAM — the computer''s working memory", "html": "<h4>What RAM actually holds</h4>\n<ul>\n<li><strong>RAM (Random Access Memory)</strong> holds the programs, data and parts of the operating system that are <strong>currently running</strong>. As soon as you open an app, its code and data are copied into RAM.</li>\n<li>RAM is <strong>volatile</strong> — everything inside it is <strong>lost the instant the power is switched off</strong>. That''s why unsaved work disappears if a computer suddenly loses power.</li>\n</ul>\n<h4>RAM can be read AND written</h4>\n<ul>\n<li>Unlike ROM, the CPU can both <strong>read from</strong> and <strong>write to</strong> RAM constantly — that''s essential, because the contents of RAM change every fraction of a second as programs run.</li>\n<li>Everyday example: typing this sentence changes the contents of RAM instantly; nothing is written to the hard drive until you actually save.</li>\n</ul>\n<h4>Why the amount of RAM matters</h4>\n<ul>\n<li>RAM has a fixed, limited size. The more RAM a computer has, the more programs and data it can hold <strong>at once</strong> without running out of space — which is exactly the problem virtual memory exists to solve (later card).</li>\n</ul>", "check": {"question": "Which of these is true about RAM?", "options": ["It is non-volatile, and keeps all of its contents safely even when the power is switched off", "It is volatile, and holds the programs and data currently in use", "It can only be read from by the CPU, and can never be written to at all", "It stores the fixed instructions that start the computer up when it is switched on"], "answer": 1, "explain": "RAM is volatile — its contents vanish without power — and it holds whatever is currently running, not permanent files (that''s secondary storage) or start-up instructions (that''s ROM)."}}, {"title": "ROM — the permanent, unchanging instructions", "html": "<h4>What ROM actually holds</h4>\n<ul>\n<li><strong>ROM (Read Only Memory)</strong> stores the <strong>boot-up instructions</strong> — the very first program a computer runs the moment it is switched on, sometimes called the <strong>bootstrap program</strong>. Its job is to start loading the operating system from secondary storage into RAM.</li>\n<li>ROM is <strong>non-volatile</strong> — its contents <strong>survive</strong> the power being switched off. That''s essential: the computer needs those instructions to be there, unchanged, every single time it starts.</li>\n</ul>\n<h4>Why \"read only\"?</h4>\n<ul>\n<li>ROM <strong>normally cannot be changed</strong> once it is set. The CPU can read from it, but not write new data to it.</li>\n<li>This is a deliberate design choice, not a limitation: if the boot-up instructions could be casually overwritten — by a virus, a bug, or a power cut mid-write — the computer might never start again.</li>\n</ul>\n<h4>ROM is not \"extra storage\"</h4>\n<ul>\n<li>ROM is tiny and dedicated to one job. It never stores your files, photos or installed apps — that is secondary storage''s job.</li>\n</ul>", "check": {"question": "Why must ROM be non-volatile?", "options": ["So it can permanently store all of the user''s saved files, documents and photos", "So the boot-up instructions needed to start the computer are always there, even after a power cut", "Because ROM is significantly faster to access than RAM for the CPU to use", "Because the entire operating system runs directly from ROM the whole time the computer is switched on"], "answer": 1, "explain": "The bootstrap/boot-up instructions in ROM must survive every power-off so the computer can always start up and begin loading the operating system."}}, {"title": "RAM vs ROM — the three differences", "html": "<h4>The three differences examiners ask for</h4>\n<table><tr><th></th><th>RAM</th><th>ROM</th></tr>\n<tr><td><strong>Volatility</strong></td><td>Volatile — loses contents when power is off</td><td>Non-volatile — keeps contents when power is off</td></tr>\n<tr><td><strong>Contents</strong></td><td>Currently running programs, data and parts of the OS</td><td>The boot-up (bootstrap) instructions</td></tr>\n<tr><td><strong>Changeability</strong></td><td>Can be written to and changed constantly</td><td>Normally cannot be changed</td></tr>\n</table>\n<h4>Answer BOTH sides, in the same space</h4>\n<ul>\n<li>A \"state the difference\" question is only worth full marks when you write <strong>both</strong> halves together: <em>\"RAM is volatile, whereas ROM is non-volatile.\"</em></li>\n<li>Writing everything about RAM first and everything about ROM afterwards, in separate sentences, is marked as <strong>two descriptions</strong>, not one difference — and it is a genuine, common way to lose the mark.</li>\n</ul>", "check": {"question": "Which answer correctly states ONE difference between RAM and ROM?", "options": ["RAM stores the programs and data that are currently running on the computer.", "ROM is non-volatile, so it does not need power to keep its contents safe.", "RAM is volatile, whereas ROM is non-volatile.", "RAM and ROM are both examples of memory used inside every modern computer."], "answer": 2, "explain": "A difference needs both sides contrasted together in the same sentence. The first two options only describe one side each; the last isn''t a difference at all."}}, {"title": "Virtual memory — borrowing space from secondary storage", "html": "<h4>The problem virtual memory solves</h4>\n<ul>\n<li>RAM is fast, but it is also limited in size and expensive. Sometimes a computer needs to run more programs and data <strong>at once</strong> than will physically fit in RAM.</li>\n<li><strong>Virtual memory</strong> is the operating system''s solution: it <strong>partitions a section of secondary storage</strong> to act as an overflow extension of RAM.</li>\n</ul>\n<h4>How data moves between RAM and virtual memory</h4>\n<ul>\n<li>When RAM is <strong>full, or nearly full</strong>, the operating system moves data that <strong>isn''t currently needed</strong> out of RAM and into virtual memory on secondary storage. This frees up space in RAM for whatever needs to run right now.</li>\n<li>When that data is needed again, it is transferred <strong>back</strong> from virtual memory into RAM. Virtual memory is a two-way system — data does not stay there forever.</li>\n<li>Everyday example: with many browser tabs and apps open at once, an older, untouched tab may be swapped out to virtual memory; switching back to it feels briefly slower while it''s swapped back into RAM.</li>\n</ul>\n<h4>The trade-off: it''s much slower</h4>\n<ul>\n<li>Secondary storage is dramatically slower to access than RAM. Using virtual memory heavily makes a computer feel sluggish, because the CPU keeps waiting for data to be swapped in and out.</li>\n<li>This is exactly why <strong>adding more RAM</strong> improves performance — it reduces how often the computer has to fall back on slow virtual memory.</li>\n</ul>", "check": {"question": "When does the operating system start using virtual memory?", "options": ["As soon as the computer is switched on", "When RAM is full or nearly full", "When ROM is full", "Whenever a file is saved"], "answer": 1, "explain": "Virtual memory is overflow space used specifically when RAM is running out — not something used constantly by default."}}, {"title": "Cache and the memory hierarchy", "html": "<h4>Where cache fits</h4>\n<ul>\n<li><strong>Cache</strong> is a small amount of very fast memory built into the CPU. It stores the instructions and data used <strong>most frequently</strong>, so the CPU can fetch them without the delay of going all the way out to RAM.</li>\n<li>Cache sits <strong>between the CPU and RAM</strong> in terms of both speed and size: faster and smaller than RAM, but slower and bigger than the CPU''s own registers.</li>\n</ul>\n<h4>The memory hierarchy</h4>\n<ul>\n<li>Every layer of storage trades <strong>speed</strong> against <strong>capacity and cost</strong>. Moving down the hierarchy, each layer gets <strong>slower, bigger and cheaper per byte</strong>:</li>\n</ul>\n<svg viewBox=\"0 0 480 230\" width=\"100%\" height=\"230\" role=\"img\" aria-label=\"Memory hierarchy diagram, fastest and smallest at the top narrowing down to slowest and largest at the bottom: registers, cache, RAM, secondary storage\">\n<rect x=\"160\" y=\"10\" width=\"160\" height=\"42\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"240\" y=\"36\" text-anchor=\"middle\" fill=\"currentColor\" font-size=\"14\">Registers</text>\n<rect x=\"130\" y=\"62\" width=\"220\" height=\"42\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"240\" y=\"88\" text-anchor=\"middle\" fill=\"currentColor\" font-size=\"14\">Cache</text>\n<rect x=\"90\" y=\"114\" width=\"300\" height=\"42\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"240\" y=\"140\" text-anchor=\"middle\" fill=\"currentColor\" font-size=\"14\">RAM (primary storage)</text>\n<rect x=\"30\" y=\"166\" width=\"420\" height=\"42\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"240\" y=\"192\" text-anchor=\"middle\" fill=\"currentColor\" font-size=\"14\">Secondary storage</text>\n<text x=\"10\" y=\"20\" fill=\"currentColor\" font-size=\"11\">faster</text>\n<text x=\"10\" y=\"215\" fill=\"currentColor\" font-size=\"11\">bigger &amp; cheaper</text>\n<line x1=\"10\" y1=\"28\" x2=\"10\" y2=\"200\" stroke=\"currentColor\" stroke-width=\"1\"/>\n</svg>\n<ul>\n<li><strong>Registers</strong> (inside the CPU) — tiny, fastest of all, hold the data being processed right now.</li>\n<li><strong>Cache</strong> — very fast, small, holds frequently used instructions and data.</li>\n<li><strong>RAM (primary storage)</strong> — fast, holds everything currently running.</li>\n<li><strong>Secondary storage</strong> — slow, but huge and permanent; also where virtual memory lives.</li>\n</ul>", "check": {"question": "Put these in order from fastest to slowest to access.", "options": ["Registers, cache, RAM, secondary storage", "Cache, registers, secondary storage, RAM", "RAM, cache, registers, secondary storage", "Secondary storage, cache, RAM, registers"], "answer": 0, "explain": "Registers (inside the CPU) are fastest, then cache, then RAM, then secondary storage — each step down trades speed for more (cheaper) capacity."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Primary storage", "definition": "Memory directly accessible to the CPU — needed to run any program or instruction"}, {"term": "Secondary storage", "definition": "Permanent storage for files and programs, too slow for the CPU to use directly"}, {"term": "RAM", "definition": "Volatile memory holding the programs, data and OS currently running"}, {"term": "ROM", "definition": "Non-volatile memory holding the boot-up instructions, normally unchangeable"}, {"term": "Volatile", "definition": "Loses its contents when the power is turned off"}, {"term": "Non-volatile", "definition": "Keeps its contents even when the power is turned off"}, {"term": "Boot-up (bootstrap) instructions", "definition": "The first program run when a computer starts, stored in ROM"}, {"term": "Why programs must load into RAM", "definition": "The CPU can''t work directly with secondary storage — it''s too slow"}, {"term": "Virtual memory", "definition": "A partitioned section of secondary storage used as overflow for RAM"}, {"term": "Why virtual memory is needed", "definition": "RAM is limited in size but a computer may need to run more than it can hold"}, {"term": "Paging out", "definition": "Moving data not currently needed from RAM into virtual memory to free up space"}, {"term": "Paging back in", "definition": "Moving data from virtual memory back into RAM when it''s needed again"}, {"term": "Effect of heavy virtual memory use", "definition": "The computer slows down, since secondary storage is much slower than RAM"}, {"term": "Cache", "definition": "Small, very fast memory inside the CPU holding frequently used instructions and data"}, {"term": "Memory hierarchy order", "definition": "Registers → cache → RAM → secondary storage (fastest to slowest)"}, {"term": "RAM vs ROM: changeability", "definition": "RAM can be written to constantly; ROM normally cannot be changed"}, {"term": "RAM vs ROM: contents", "definition": "RAM holds what''s currently running; ROM holds the fixed boot-up instructions"}, {"term": "Register", "definition": "Tiny, extremely fast storage location inside the CPU itself"}]}, "mcq": {"enabled": true, "questions": [{"question": "Why can''t the CPU run a program directly from secondary storage?", "options": ["Secondary storage only stores files, never the program code itself, so there is nothing to run directly", "Secondary storage is far slower to access than RAM, so the program is loaded into RAM first", "Secondary storage is a type of ROM, and ROM cannot be used to run user programs directly", "The operating system automatically deletes a program from secondary storage as soon as it starts running"], "answer": 1, "explain": "Secondary storage is permanent but too slow for the CPU to use directly, so a program''s code and data are loaded into RAM before it can run."}, {"question": "Which best describes RAM?", "options": ["Non-volatile memory that permanently stores the boot-up instructions needed to start the computer", "Volatile memory that holds the programs, data and parts of the OS currently in use", "A type of secondary storage device used to store the user''s files and programs permanently", "Memory built into the CPU that can never be written to once it has been manufactured"], "answer": 1, "explain": "RAM holds whatever is currently running and is volatile — it loses its contents when the power is off."}, {"question": "Which best describes ROM?", "options": ["Volatile memory that loses all of its contents every time the computer is switched off", "Non-volatile memory that stores the boot-up instructions and normally cannot be changed", "Memory used to store the user''s saved documents and files permanently, even after the power is off", "A partitioned section of secondary storage used as overflow space when RAM is full"], "answer": 1, "explain": "ROM is non-volatile and holds the fixed boot-up instructions the computer needs every time it starts."}, {"question": "What happens to the contents of RAM when the power is turned off?", "options": ["They are saved automatically to ROM", "They are lost", "They are compressed", "Nothing changes"], "answer": 1, "explain": "RAM is volatile, so everything in it disappears the instant power is removed."}, {"question": "A smart TV stores its start-up instructions somewhere that must survive being switched off and can''t normally be altered. Which type of memory is this?", "options": ["RAM", "ROM", "Virtual memory", "Cache"], "answer": 1, "explain": "Instructions that must survive power-off and stay fixed are stored in ROM, which is non-volatile and normally unchangeable."}, {"question": "Which of these would normally be found in RAM while a computer is running?", "options": ["The washing machine''s control program (embedded in ROM)", "The document currently open in a word processor", "A file saved permanently on the hard drive but not open", "The manufacturer''s original factory boot settings"], "answer": 1, "explain": "RAM holds what''s currently in use — an open document — not permanently stored, unopened files or fixed boot instructions."}, {"question": "Why does a computer use virtual memory?", "options": ["To physically increase the amount of RAM chips fitted inside the computer", "To give the CPU a small, extremely fast store for its most frequently used instructions", "To act as extra space when RAM is full or nearly full, using secondary storage", "To replace the boot-up instructions normally held in ROM when the computer starts"], "answer": 2, "explain": "Virtual memory is overflow space on secondary storage, used when RAM runs low — it doesn''t physically enlarge RAM."}, {"question": "Where does virtual memory physically exist?", "options": ["Inside the CPU, alongside the registers used to hold data being processed", "In a partitioned section of secondary storage, such as part of the hard drive or SSD", "Inside ROM, alongside the fixed boot-up instructions the computer needs every time it starts", "In the cache, next to the frequently used instructions and data stored there"], "answer": 1, "explain": "Virtual memory is a section of secondary storage (e.g. the SSD or hard drive) set aside to act as overflow for RAM."}, {"question": "When RAM starts to fill up, what does the operating system do?", "options": ["Permanently deletes whichever files it judges to be the least important, to free up space in RAM", "Moves data that isn''t currently needed out of RAM into virtual memory on secondary storage", "Increases the CPU''s clock speed so it can process the backlog of data more quickly", "Copies the extra data into ROM, since ROM has spare capacity to hold it temporarily"], "answer": 1, "explain": "Data not currently needed is swapped out of RAM into virtual memory, freeing up space for what''s needed right now."}, {"question": "Why can heavy use of virtual memory make a computer feel slower?", "options": ["Storing data in virtual memory uses noticeably more electricity than storing the same data in RAM", "Secondary storage is much slower to access than RAM, so swapping data in and out takes time", "Virtual memory permanently deletes any data that gets swapped out of RAM into it", "Using virtual memory automatically reduces the CPU''s clock speed while it is active"], "answer": 1, "explain": "Every swap in or out of virtual memory means waiting on secondary storage, which is far slower than RAM."}, {"question": "What is cache, and where does it sit in the memory hierarchy?", "options": ["The largest, slowest type of storage in the computer, used to hold permanent files", "A small, very fast store inside the CPU that sits between the CPU and RAM", "A partitioned section of secondary storage used as overflow space when RAM runs low", "The same non-volatile memory as ROM, just given a different name by manufacturers"], "answer": 1, "explain": "Cache is small, very fast memory inside the CPU that holds frequently used instructions and data — faster than RAM, but smaller."}, {"question": "Put these in order from FASTEST to SLOWEST to access:", "options": ["Registers, cache, RAM, secondary storage", "Secondary storage, RAM, cache, registers", "RAM, registers, secondary storage, cache", "Cache, secondary storage, RAM, registers"], "answer": 0, "explain": "Registers are fastest (inside the CPU), then cache, then RAM, then secondary storage, which is slowest but has by far the most capacity."}]}, "fib": {"enabled": true, "questions": [{"text": "RAM is [volatile], so its contents are lost the moment the power is switched off."}, {"text": "ROM is [non-volatile], so its contents survive being switched off and normally cannot be changed."}, {"text": "ROM stores the [boot-up] instructions that run the moment a computer is switched on."}, {"text": "Before the CPU can run a program, it must be loaded from secondary storage into [RAM]."}, {"text": "A section of secondary storage acts as [virtual] memory when RAM is full or nearly full."}, {"text": "Data that is moved out of RAM into virtual memory is brought back in again when it is next [needed]."}, {"text": "The small, very fast store inside the CPU that holds frequently used data is called the [cache]."}, {"text": "From fastest to slowest to access: registers, cache, RAM, then [secondary] storage."}]}, "tf": {"enabled": true, "questions": [{"statement": "RAM is non-volatile, so it keeps its contents when the power is off.", "answer": false, "explain": "RAM is volatile — it is ROM that is non-volatile. Everything in RAM is lost the instant the power is removed."}, {"statement": "ROM normally cannot be changed once the computer is manufactured.", "answer": true, "explain": "Correct — ROM is read-only. This is deliberate: it protects the boot-up instructions the computer relies on every time it starts."}, {"statement": "A computer could run all its programs directly from secondary storage without ever using RAM.", "answer": false, "explain": "Secondary storage is far too slow for the CPU to use directly. Programs must be loaded into RAM before they can run."}, {"statement": "Virtual memory is a section of secondary storage used as overflow when RAM is nearly full.", "answer": true, "explain": "Correct — the operating system partitions part of secondary storage to act as extra space for RAM when it''s running low."}, {"statement": "Once data is swapped out of RAM into virtual memory, it stays there permanently and never returns.", "answer": false, "explain": "Virtual memory is two-way. Data is transferred back into RAM whenever it is needed again."}, {"statement": "Cache sits between the CPU and RAM, storing frequently used instructions and data.", "answer": true, "explain": "Correct — cache is faster and smaller than RAM, and holds the instructions/data the CPU keeps reaching for."}, {"statement": "Using a lot of virtual memory usually makes a computer run faster.", "answer": false, "explain": "The opposite — secondary storage is far slower than RAM, so heavy swapping in and out of virtual memory slows the computer down."}, {"statement": "The instructions that start a computer up (the bootstrap program) are stored in ROM.", "answer": true, "explain": "Correct — ROM''s whole job is to hold these boot-up instructions safely, unchanged, across every power-off."}]}, "misc": {"enabled": true, "items": [{"myth": "''RAM is just extra storage space, like a bigger hard drive.''", "truth": "RAM and secondary storage do completely different jobs. RAM is <strong>temporary working memory</strong> — it loses everything when the power is off, and only holds what''s <em>currently</em> running. A hard drive or SSD stores files <strong>permanently</strong>. Wanting to store more photos and documents needs more secondary storage, not more RAM.", "check": {"question": "A student wants to permanently store thousands more photos. What should they upgrade?", "options": ["RAM, since more working memory helps programs run more smoothly", "ROM, since it can be reprogrammed to hold extra file storage", "Secondary storage, since it stores files permanently in large amounts", "Cache, since it can be expanded to hold as many extra photo files as needed"], "answer": 2, "explain": "Permanent files need more secondary storage. RAM is temporary working memory and is lost when the power is off."}}, {"myth": "''The computer can run programs directly from the SSD or hard drive without needing RAM.''", "truth": "The CPU cannot work directly with secondary storage — it is far too slow. Every program''s code and data must first be <strong>loaded into RAM</strong>, which the CPU can access almost instantly. That loading pause is exactly what you see when an app or game first opens.", "check": {"question": "Why does an app take a moment to ''load'' when you open it?", "options": ["It is being installed onto the computer for the very first time", "Its code and data are being copied from secondary storage into RAM", "It is checking an online server for the latest software updates", "The instructions stored in ROM are being rewritten to match the app"], "answer": 1, "explain": "The CPU needs the app in RAM before it can run it, since secondary storage is too slow to use directly."}}, {"myth": "''ROM can be freely rewritten by the user, just like RAM.''", "truth": "ROM normally <strong>cannot</strong> be changed once it is set. That''s the entire point — the boot-up instructions must be there, exactly the same, every single time the computer starts. RAM is the one that is constantly read and written to as programs run.", "check": {"question": "Why is ROM designed so it normally cannot be changed?", "options": ["To save money during manufacturing, since fixed memory chips are cheaper to produce", "So the boot-up instructions are always intact and reliable, even after a power cut or a fault", "Because ROM physically has no spare capacity left for any new data to ever be written into it at all", "Because the entire operating system is permanently stored and run from inside ROM"], "answer": 1, "explain": "If the boot-up instructions could be casually overwritten, the computer might fail to start at all — so ROM is fixed by design."}}, {"myth": "''Virtual memory makes the computer''s RAM permanently bigger.''", "truth": "Virtual memory does not create more real RAM. It is <strong>slow overflow space on secondary storage</strong>, used temporarily to hold data that isn''t needed right now. Because secondary storage is much slower than RAM, relying on virtual memory a lot makes a computer feel sluggish, not faster.", "check": {"question": "What is virtual memory actually made from?", "options": ["Extra RAM chips that are physically fitted inside the CPU itself", "A partitioned section of secondary storage, such as the hard drive", "A dedicated partition of ROM set aside for temporary overflow data", "The CPU''s cache memory, temporarily repurposed for overflow storage"], "answer": 1, "explain": "Virtual memory is space borrowed from secondary storage — it doesn''t physically add RAM to the computer."}}, {"myth": "''Once data is swapped into virtual memory, it stays there and never returns to RAM.''", "truth": "Virtual memory works <strong>both ways</strong>. Data is moved out of RAM into virtual memory to free up space, and moved <strong>back</strong> into RAM whenever it''s needed again — that back-and-forth is exactly why heavy use of virtual memory slows a computer down.", "check": {"question": "What happens when data that has been swapped into virtual memory is needed again?", "options": ["Nothing — it stays in virtual memory permanently", "It is transferred back into RAM", "It is deleted and reloaded from ROM", "The CPU reads it directly from secondary storage without using RAM"], "answer": 1, "explain": "Virtual memory is a two-way system: data is swapped back into RAM as soon as it''s needed again."}}, {"myth": "For ''state the difference between RAM and ROM'', writing everything about RAM first, then everything about ROM afterwards, as two separate points.", "truth": "A <strong>difference</strong> needs both sides written together in the <em>same</em> answer space: ''RAM is volatile, whereas ROM is non-volatile.'' Describing RAM fully and then describing ROM fully is marked as two separate descriptions, not one difference — real candidates lost marks for exactly this pattern, and others lost the mark by describing what RAM/ROM are <em>used for</em> rather than a fundamental difference between them.", "check": {"question": "Which is properly written as ONE difference between RAM and ROM?", "options": ["RAM stores currently running programs. ROM stores boot-up instructions.", "RAM is volatile, whereas ROM is non-volatile.", "RAM is fast.", "ROM is used to start the computer."], "answer": 1, "explain": "One difference = both sides, directly contrasted, in the same sentence. The others give only one side, or describe use rather than a fundamental difference."}}]}, "tips": {"enabled": true, "items": [{"title": "1-mark ''state the difference'' — both sides, one sentence", "html": "<p>When OCR asks you to <strong>state the difference</strong> between RAM and ROM, the mark is only released when your answer contrasts <strong>both sides together</strong>. Here''s the same idea at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"RAM is volatile.\"</p>\n<ul>\n<li>True, but it''s only half a difference. On its own this doesn''t say what ROM does differently.</li>\n</ul>\n\n<p><strong>❌ 0 marks (real candidate pattern):</strong> \"RAM stores the currently running programs. ROM stores the boot-up instructions.\"</p>\n<ul>\n<li>This describes what each one is <em>used for</em>, not a fundamental difference — and each sentence stands alone rather than being contrasted, so it reads as two descriptions, not one difference.</li>\n</ul>\n\n<p><strong>✅ 1 mark:</strong> \"RAM is volatile, <strong>whereas</strong> ROM is non-volatile.\"</p>\n<ul>\n<li>Both sides, one sentence, one direct contrast. \"Whereas\" (or \"but\"/\"while\") is doing the work here — it forces you to say both halves.</li>\n</ul>\n\n<p><strong>The pattern for every 1-mark difference:</strong> \"[RAM] is ___, whereas [ROM] is ___.\" If your sentence could be true without mentioning the other one at all, it isn''t a difference yet.</p>", "check": {"question": "Which answer would score the mark for ''state the difference between RAM and ROM''?", "options": ["ROM is non-volatile, so its contents survive a power cut.", "RAM is volatile, whereas ROM is non-volatile.", "RAM stores the operating system, while ROM stores the BIOS setup.", "RAM and ROM are both essential types of computer memory."], "answer": 1, "explain": "Only the second option contrasts both sides in one sentence. The others give one side only, describe use rather than a difference, or aren''t a difference at all."}}, {"title": "2-mark ''explain why both are needed'' — two separate reasons", "html": "<p>\"Explain why a computer needs both primary <strong>and</strong> secondary storage\" [2] is marked as <strong>two separate 1-mark reasons</strong> — one for primary, one for secondary. It is NOT a point-plus-development chain; you need to earn each side on its own.</p>\n\n<p><strong>❌ 0/2:</strong> \"Primary storage stores data and secondary storage stores files.\"</p>\n<ul>\n<li>This says <em>what</em> they store, not <em>why</em> each is needed — the examiner''s own note is explicit that this question is not about what they store.</li>\n</ul>\n\n<p><strong>⚠️ 1/2:</strong> \"A computer needs primary storage so the processor can access the data and instructions it''s currently using.\"</p>\n<ul>\n<li>A correct, creditworthy reason for primary — but nothing has been said about secondary storage yet, so only 1 mark is available.</li>\n</ul>\n\n<p><strong>✅ 2/2:</strong> \"Primary storage is needed so the processor can access the data, instructions and software it''s currently using <strong>(1)</strong>. Secondary storage is needed to store the user''s files and programs long-term, so they aren''t lost when the power is turned off <strong>(1)</strong>.\"</p>\n\n<p><strong>The trap examiners flagged:</strong> a common misconception is that secondary storage is \"only used as a backup\", or is \"used when primary storage is full\" — neither is the real reason. Secondary storage''s job is <strong>long-term, permanent</strong> storage of files, independent of how full RAM is.</p>", "check": {"question": "A student writes a strong reason for needing primary storage, but says nothing about secondary storage. What mark do they get?", "options": ["0 out of 2", "1 out of 2 — each side is worth its own mark", "2 out of 2, because primary is the harder half", "It depends on word count"], "answer": 1, "explain": "The two marks are independent — one for a correct reason for primary storage, one for a correct reason for secondary storage. Only covering one side caps you at 1."}}, {"title": "The virtual memory True/False table — precision matters", "html": "<p>A common 4-mark format gives four statements about virtual memory and asks you to tick the ones that are <strong>true</strong>, and <strong>rewrite</strong> the false ones to make them true — one mark per row.</p>\n\n<p><strong>What real candidates got right and wrong on this exact question:</strong></p>\n<ul>\n<li>Almost everyone correctly spotted \"VM is needed when RAM is full, or nearly full\" as <strong>true</strong> — that''s the easy row.</li>\n<li>\"A section of primary storage is partitioned to act as virtual memory\" was usually corrected well, to <strong>secondary</strong> storage.</li>\n<li>\"Data from ROM is transferred into VM\" was sometimes corrected to RAM — but sometimes wrongly changed to \"secondary storage\" instead, which misses the point (data moves <em>from RAM</em>, not from secondary storage, into virtual memory).</li>\n<li>\"Data from VM is transferred back to secondary storage when needed\" was frequently corrected to just \"<strong>primary storage</strong>\" — and that was <strong>not precise enough</strong>. Primary storage includes ROM and cache as well as RAM; the mark scheme specifically wants <strong>RAM</strong> named.</li>\n</ul>\n\n<p><strong>The rule this teaches:</strong> when you correct a VM statement, name <strong>RAM</strong> and <strong>secondary storage</strong> specifically — never the vaguer \"primary storage\" — because virtual memory is defined as data moving between RAM and secondary storage, not primary storage in general.</p>", "check": {"question": "A student corrects ''Data from VM is transferred back to secondary storage when needed'' by writing ''transferred back to primary storage''. Why does this not score the mark?", "options": ["It should have been left uncorrected, since the original statement was already true", "''Primary storage'' is too vague — it includes ROM and cache, not just RAM", "The word order in the correction is wrong and needs to be rearranged", "Virtual memory never transfers any data back into RAM once it has been swapped out"], "answer": 1, "explain": "The precise correction is RAM, not the broader term ''primary storage'', which also covers ROM and cache and so doesn''t accurately describe how VM works."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>State one difference between RAM and ROM.</p>", "marks": 1, "hint": "A ''difference'' question needs BOTH sides in one sentence — ''RAM is ___, whereas ROM is ___.'' Describing only one of them is not enough.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>Award 1 mark for a correct difference that covers both sides, for example: \"RAM is volatile and loses its contents when the power is off, whereas ROM is non-volatile and keeps its contents\" or \"the contents of RAM can be changed, whereas the contents of ROM (normally) cannot be changed\".</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Read the whole answer — both sides of the difference must be present to award the mark.</li>\n<li>Do not accept a description of only RAM or only ROM on its own.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Students often name only one side of the comparison, for example writing \"RAM is volatile\" without saying what ROM is instead — a difference needs both halves in the same answer. Another common slip is describing what RAM and ROM are used for rather than how they differ as types of memory; a difference in purpose is not the same as a fundamental difference between the two.</p>\n</div>"}, {"question": "<p>Give <strong>two</strong> examples of data that the digital radio could store in RAM while it is switched on.</p>", "marks": 2, "hint": "Think about what''s active right now — the station currently tuned in, the song title being displayed — not the app or the operating system as a whole.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each, up to 2)</h5>\n<ul>\n<li>Award 1 mark for each valid example of data currently in use, up to 2, for example:</li>\n<li>The radio station/frequency currently tuned in</li>\n<li>The name of the song or track currently playing/being displayed</li>\n<li>The current volume level</li>\n<li>Data being received from the broadcast signal</li>\n<li>The button most recently pressed by the user</li>\n<li>(Parts of) the operating system currently running</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any reasonable example, provided it is clearly data currently in use, not the app or firmware as a whole.</li>\n<li>Do not award \"the radio''s software\" or \"the operating system\" without specifying that it is the currently running part.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>A frequent error is naming something stored permanently rather than something currently in use, such as \"the list of saved stations\" instead of \"the station currently tuned in\". Students also sometimes give the same idea worded two different ways, which only counts as one valid example, not two.</p>\n</div>"}, {"question": "<p>Explain why the smart speaker needs both primary <strong>and</strong> secondary storage.</p>", "marks": 2, "hint": "Two separate reasons — one for why primary storage is needed, one for why secondary storage is needed. It''s asking WHY they''re needed, not what they store.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each)</h5>\n<ul>\n<li><strong>Primary storage</strong> — Award 1 mark for a correct reason, e.g. to hold the data, instructions or software the processor is currently using, or so the speaker has the start-up instructions needed to work at all.</li>\n<li><strong>Secondary storage</strong> — Award 1 mark for a correct reason, e.g. to store data or files (such as saved settings or downloaded content) long-term/permanently, so they are not lost when the power is turned off.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The question asks WHY each type of storage is needed, not what it stores — an answer that only names an example, without explaining the need, does not score.</li>\n<li>Do not accept \"to back up data\" for secondary storage unless it is linked to long-term/permanent storage.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Students often list an example of data for each type of storage instead of explaining why that type of storage is necessary — for example writing \"primary storage holds the volume setting\" rather than explaining that primary storage is needed because the processor must be able to access currently-used data directly and quickly. A common misconception is that secondary storage is only used once primary storage is full, rather than being needed for permanent storage regardless of how much RAM is available.</p>\n</div>"}, {"question": "<p>The table has four statements about how the laptop''s Virtual Memory (VM) works. Not all of the statements are correct.</p><p>Tick (✓) the <strong>True</strong> column for the statements that are correct.</p><p>Re-write any statement that is incorrect by changing it to make it true.</p>", "marks": 4, "hint": "Think about which type of memory is doing what: ROM never changes, RAM holds what''s active, and secondary storage is where the overflow really goes. Three of the four rows have one wrong word.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Row 1 — False: virtual memory actually works the other way round — a section of <strong>secondary</strong> storage is used to extend the space available to RAM</li>\n<li>Row 2 — False: the data that is moved out is <strong>RAM</strong>, not ROM</li>\n<li>Row 3 — True</li>\n<li>Row 4 — False: the data IS transferred back into <strong>RAM</strong> again when it is next needed</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Allow a description of the error in place of a full rewrite, e.g. row 1: \"RAM and secondary storage the wrong way round\".</li>\n<li>Do not accept \"primary storage\" as a substitute for RAM in row 2.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Students sometimes reverse the direction virtual memory works in, believing spare RAM is used to create extra permanent storage rather than spare secondary storage being borrowed to extend RAM. Confusing RAM with ROM in row 2 is also common, since both are examples of primary storage; remembering that ROM''s contents never change (so it cannot be swapped in and out) rules this out. Row 4 catches students who assume swapping is a one-way trip rather than a two-way process.</p>\n</div>"}, {"question": "<p>Refer to the games console described above.</p><p>The ROM inside the console stores a short program that runs automatically the moment the console is switched on, before the console''s operating system has loaded.</p><p>What is the correct term for this ROM-stored, start-up program?</p>", "marks": 1, "hint": "This is the fixed program ROM''s whole job is to store — the one instruction set that starts the computer up before anything else can run.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>The boot-up (bootstrap) program</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; there is no credit for a partial or vague description.</li>\n</ul>\n</div>"}, {"question": "<p>State why the weather station''s processor needs to load its measurement program into RAM, rather than running it directly from its permanent storage.</p>", "marks": 1, "hint": "Think about speed — one type of storage is far too slow for the processor to use directly.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>Permanent/secondary storage is too slow for the processor to access directly, so the program must be loaded into RAM, or RAM can be accessed (almost) instantly by the processor</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any answer that correctly identifies the speed difference between the two types of storage.</li>\n<li>Do not accept \"RAM is bigger\" or \"RAM never loses data\" — RAM is volatile, and size is not the reason given here.</li>\n</ul>\n</div>"}, {"question": "<p>While the student is editing a video, the PC''s power is suddenly cut and the PC switches off without warning.</p><p>Describe what happens to the unsaved edits in the video project, and explain why this happens.</p>", "marks": 2, "hint": "Two things to cover: WHAT happens to the unsaved edits, and WHY — one particular property of RAM is the reason.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark for what happens, 1 mark for why)</h5>\n<ul>\n<li>The unsaved edits are lost or deleted (1)</li>\n<li>Because RAM is volatile, so its contents are lost when the power is removed (1)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept \"the project reverts to the last save\" as equivalent to \"lost\".</li>\n<li>The reason must reference volatility/loss of power specifically, not a vague \"RAM stopped working\".</li>\n</ul>\n</div>"}, {"question": "<p>Give <strong>two</strong> examples of data that would be held in the weather station''s RAM while it is running.</p>", "marks": 2, "hint": "Think about what''s happening RIGHT NOW — the reading just taken, the measurement being sent — not data that has already been saved permanently.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each to max 2), e.g.</h5>\n<ul>\n<li>The temperature/rainfall/wind speed reading currently being measured</li>\n<li>The reading currently being prepared/sent to the school''s server</li>\n<li>(Parts of) the operating system/monitoring program currently running</li>\n<li>The time the next reading is due to be taken</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Allow anything reasonable that is clearly data in current use, not data already stored permanently on the server.</li>\n</ul>\n</div>"}, {"question": "<p>One of the 4GB laptops starts to run out of RAM during a lesson, so the operating system creates some virtual memory.</p><p>Where does this virtual memory actually exist?</p>", "marks": 1, "hint": "Virtual memory is not extra RAM — it''s borrowed space from somewhere else in the computer, somewhere with plenty of spare capacity.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>In a partitioned section of the laptop''s secondary storage</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores.</li>\n</ul>\n</div>"}, {"question": "<p>A player installs several new games, and the console''s 8GB of RAM becomes full while multiple games and apps are open at once.</p><p>Explain how virtual memory allows the console to keep running in this situation.</p>", "marks": 3, "hint": "Walk through it as a sequence: what triggers it, what moves where, and what happens when that data is needed again.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point to max 3)</h5>\n<ul>\n<li>RAM being full/nearly full triggers the operating system to act</li>\n<li>Data/instructions that are not currently needed are moved out of RAM into virtual memory on secondary storage, freeing up space in RAM</li>\n<li>This frees enough space in RAM for the game/app that needs to run right now</li>\n<li>That data is transferred back into RAM again when it is next needed</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award any 3 of the points above.</li>\n<li>Do not accept \"RAM gets bigger\" — virtual memory does not physically increase RAM.</li>\n</ul>\n</div>"}, {"question": "<p>The table has four statements about the weather station''s memory. Tick (✓) <strong>one</strong> box in each row to show which component the statement describes.</p>", "marks": 4, "hint": "Match each statement to exactly one component — this table has one correct answer per row, not several.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each correctly ticked row)</h5>\n<ul>\n<li>Non-volatile, stores the boot-up instructions: <strong>ROM</strong></li>\n<li>Volatile, holds the readings currently being processed: <strong>RAM</strong></li>\n<li>Overflow section of secondary storage when RAM is nearly full: <strong>Virtual memory</strong></li>\n<li>Small, extremely fast, built into the processor: <strong>Cache</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>If more than one box is ticked in a row, 0 marks for that row.</li>\n</ul>\n</div>"}, {"question": "<p>A student notices that one of the 4GB laptops feels slow and laggy when they have many browser tabs and apps open at once during a lesson.</p><p>Explain, in terms of RAM and virtual memory, why this happens.</p>", "marks": 4, "hint": "Build a chain: what state is RAM in → what the operating system does about it → what has to happen when an old tab is clicked on again → why that specific step is slow.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per point to max 4)</h5>\n<ul>\n<li>RAM becomes full or nearly full because so many tabs/apps are open at once</li>\n<li>The operating system moves data/tabs that aren''t currently being used out of RAM into virtual memory on secondary storage</li>\n<li>When the student switches back to one of those tabs, its data has to be transferred back into RAM</li>\n<li>This transfer is slow because secondary storage is much slower to access than RAM, which is why the laptop feels laggy</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not accept \"the laptop is old\" or \"too many tabs use up the internet\" — the explanation must be in terms of RAM/virtual memory.</li>\n</ul>\n</div>"}, {"question": "<p>The PC''s 16GB of RAM sometimes fills up when several large video files are open in the editing software at once, so the operating system uses virtual memory.</p><p>Explain how virtual memory allows the PC to keep working in this situation, <strong>and</strong> explain why relying on virtual memory heavily can make the video-editing software feel slow to use.</p>", "marks": 6, "hint": "Two halves, three marks each: first explain the MECHANISM of virtual memory (what moves, where, and back again), then explain the PERFORMANCE cost (why the swap itself takes time).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks (1 mark per point to max 3 in each half)</h5>\n<ul>\n<li><strong>How VM keeps the PC working (max 3)</strong> — virtual memory is a partitioned section of secondary storage used as overflow for RAM; footage not currently needed is moved out of RAM into virtual memory, freeing space; that data is transferred back into RAM when it is next needed</li>\n<li><strong>Why heavy use slows editing (max 3)</strong> — secondary storage is much slower to access than RAM; the software/CPU has to wait while data is swapped in and out; repeatedly swapping large video files causes noticeable lag/stutter while editing</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award up to 3 marks in each half independently — a strong answer on only one half is capped at 3.</li>\n<li>Do not accept \"the PC needs more RAM\" alone as an explanation of the slowdown — the point must describe the swapping mechanism.</li>\n</ul>\n</div>"}, {"question": "<p>The school is deciding whether to buy new laptops with 4GB of RAM, which are cheaper, or 8GB of RAM, which cost more.</p><p>Discuss the impact that the amount of RAM in the school''s laptops could have on students'' experience of using multiple applications during lessons.</p><p>In your answer you might consider:</p><ul><li>how RAM and virtual memory work</li><li>the effect on performance</li><li>the effect on students'' learning</li><li>the cost to the school</li></ul>", "marks": 8, "hint": "Use all four bullets as your plan. Explain the mechanism (RAM full → virtual memory → slower), then follow it through to a REAL consequence for a lesson, and weigh the RAM cost against that consequence for a top-band answer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (levelled) — indicative content</h5>\n<p>The following is indicative of possible factors/evidence that candidates may refer to but is not prescriptive or exhaustive:</p>\n<ul>\n<li><strong>How RAM/virtual memory work</strong> — RAM holds the data/instructions currently in use; with less RAM (4GB) it fills up sooner when several applications/tabs are open; the operating system then relies on virtual memory, swapping data out to (and back from) secondary storage more often.</li>\n<li><strong>Effect on performance</strong> — 8GB of RAM can hold more open applications at once without needing virtual memory, so it stays responsive; 4GB laptops will lag, freeze briefly or respond slowly as data is swapped in and out of the much slower secondary storage; the more applications open at once, the more noticeable this becomes.</li>\n<li><strong>Effect on students'' learning</strong> — lag/freezing during a lesson can interrupt a student''s work, waste lesson time, and cause frustration; students on 4GB laptops may be forced to keep fewer tabs/programs open at once, limiting what tasks they can do compared to peers on 8GB devices.</li>\n<li><strong>Cost to the school</strong> — 4GB laptops are cheaper, allowing the school to buy more devices or spend the savings elsewhere; 8GB laptops cost more per device, so the school may afford fewer of them or have to prioritise which students/subjects get them.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>Mark Band 3 — High Level (6–8 marks):</strong> Thorough knowledge and understanding of RAM/virtual memory, applied directly and consistently to the school laptop context. The response weighs up both sides (performance/learning impact against cost) and covers all four areas from the bullet list with clear, logically structured reasoning.</li>\n<li><strong>Mark Band 2 — Mid Level (3–5 marks):</strong> Reasonable knowledge of RAM/virtual memory, generally accurate but at times underdeveloped or only partly applied to the context. Most of the four areas are addressed, with some structure, though the discussion may not fully weigh both sides.</li>\n<li><strong>Mark Band 1 — Low Level (1–2 marks):</strong> Basic knowledge with limited understanding shown; the material may contain inaccuracies or barely refer to the laptop context. Little more than an unsupported assertion, e.g. \"4GB is worse than 8GB\" with no working explanation of why.</li>\n<li><strong>0 marks:</strong> No attempt to answer the question or response is not worthy of credit.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-2-2-secondary-storage', '1.2.2 Secondary Storage', '{"learn": {"enabled": true, "items": [{"title": "Why does a computer need secondary storage?", "html": "<h4>RAM alone isn''t enough</h4>\n<ul>\n<li><strong>RAM (primary storage) is volatile</strong> — everything held in it disappears the moment the power is switched off. If a computer only had RAM, every file, app and setting would vanish every time it was turned off.</li>\n<li><strong>Secondary storage is non-volatile</strong> — data written to it stays there permanently, whether the power is on or off, until it is deliberately changed or deleted.</li>\n</ul>\n<h4>What actually needs to be kept</h4>\n<ul>\n<li>The <strong>operating system</strong> itself, so the computer can start up again.</li>\n<li><strong>Installed software/apps</strong>, so they don''t need reinstalling every session.</li>\n<li><strong>The user''s own files</strong> — documents, photos, videos, saved games — anything created or downloaded that must still be there tomorrow.</li>\n<li>Everyday example: a game you install on a laptop is still there the next morning only because it was written to secondary storage, not RAM.</li>\n</ul>\n<h4>Answering \"why does it need secondary storage?\"</h4>\n<ul>\n<li>Exam questions want TWO things: a specific example of what is stored, and the reason it must survive being switched off (non-volatile, permanent storage).</li>\n<li>\"So it can store things\" on its own repeats the question and earns nothing — name what, and say why it must last.</li>\n</ul>", "check": {"question": "Why does a computer need secondary storage as well as RAM?", "options": ["Because RAM is too slow to run modern software without another device to help it", "Because RAM is volatile, so anything kept must survive the power being switched off", "Because secondary storage takes over some of the processor''s own calculations to speed it up", "Because RAM cannot be written to, so all new data must be saved somewhere else instead"], "answer": 1, "explain": "RAM loses everything when the power goes off. Secondary storage is non-volatile, so the OS, apps and files can still be there next time the device is switched on."}}, {"title": "The three families of secondary storage", "html": "<h4>Three technologies, one job</h4>\n<ul>\n<li>Every secondary storage device belongs to one of three families. The exam only needs you to know WHICH family a device belongs to and how it compares — not how the technology works inside.</li>\n<li><strong>Magnetic storage</strong> — stores data by magnetising tiny areas of a spinning disk or a length of tape. Example: a <strong>hard disk drive (HDD)</strong>.</li>\n<li><strong>Optical storage</strong> — stores data as a pattern read by a laser. Example: a <strong>CD, DVD or Blu-ray disc</strong>.</li>\n<li><strong>Solid-state storage</strong> — stores data electronically in flash memory chips, with <strong>no moving parts</strong>. Example: an <strong>SSD</strong>, a <strong>USB memory stick</strong>, or an <strong>SD memory card</strong>.</li>\n</ul>\n<h4>Device vs type — a real exam trap</h4>\n<ul>\n<li>A <strong>type</strong> is the family (magnetic / optical / solid-state). A <strong>device</strong> is the actual product (hard disk drive, DVD, SSD, USB stick).</li>\n<li>If a question asks for a <em>device</em>, \"magnetic\" on its own is not enough — you must name an actual device. If a question asks for a <em>type</em>, naming a specific device instead of the family is marked down too. Read the question carefully and answer with the right one.</li>\n</ul>\n<h4>What you don''t need to know (NR)</h4>\n<ul>\n<li>The specification does not require the <strong>internal component parts</strong> of each medium — you don''t need to explain how magnetism flips a bit, how a laser reads a pit, or how a flash memory cell traps a charge. Focus entirely on comparing the devices, not building them.</li>\n</ul>", "check": {"question": "Which of these is a solid-state storage device?", "options": ["Hard disk drive, commonly found inside older desktop computers and servers", "DVD or Blu-ray disc, commonly used to distribute films and software", "USB memory stick, commonly carried in a pocket or bag between computers", "Magnetic tape, commonly used for large-scale backup archives"], "answer": 2, "explain": "A USB memory stick stores data electronically in flash memory with no moving parts, which makes it solid-state. The hard disk drive is magnetic; the DVD and Blu-ray disc are optical."}}, {"title": "How do you judge which device suits a scenario?", "html": "<h4>The six factors you must know</h4>\n<ul>\n<li>Every \"choose a suitable device\" question is judged against the SAME six factors. Learn them as a set:</li>\n<li><strong>Capacity</strong> — how much data the device can hold.</li>\n<li><strong>Speed</strong> — how quickly data can be read from or written to the device.</li>\n<li><strong>Portability</strong> — how easily the device can be physically carried and used with different computers.</li>\n<li><strong>Durability</strong> — how well the device survives physical damage, such as being dropped, knocked, or used in extreme conditions.</li>\n<li><strong>Reliability</strong> — how consistently the device keeps working over time without failing or corrupting data, even if it''s never mishandled.</li>\n<li><strong>Cost</strong> — the price of the device, usually compared <strong>per gigabyte</strong> so devices of different sizes can be compared fairly.</li>\n</ul>\n<table><tr><th>Factor</th><th>Magnetic (HDD)</th><th>Optical (DVD/BD)</th><th>Solid-state (SSD/USB)</th></tr>\n<tr><td>Capacity</td><td>Very high</td><td>Low</td><td>High</td></tr>\n<tr><td>Speed</td><td>Medium</td><td>Slowest</td><td>Fastest</td></tr>\n<tr><td>Portability</td><td>Low</td><td>High</td><td>High</td></tr>\n<tr><td>Durability</td><td>Low (moving parts)</td><td>Medium (scratches)</td><td>High (no moving parts)</td></tr>\n<tr><td>Reliability</td><td>Good if undisturbed</td><td>Degrades over time</td><td>Very good</td></tr>\n<tr><td>Cost per GB</td><td>Lowest</td><td>Low per disc</td><td>Highest</td></tr>\n</table>\n<h4>Durability vs reliability — don''t merge these</h4>\n<ul>\n<li>They sound similar but test different things. Durability = survives being dropped or knocked. Reliability = keeps working correctly over time, even sitting still. A device can be durable but unreliable (survives drops, occasionally corrupts a file) — or reliable but not durable (never fails on a desk, but cracks the moment it''s dropped).</li>\n</ul>\n<h4>Turning a scenario into an answer</h4>\n<ul>\n<li>Read the scenario for clue words and match them to a factor: \"carried around\" → portability; \"dropped\" or \"outdoors\" → durability; \"large HD files\" → capacity; \"must feel responsive\" → speed; \"on a tight budget\" → cost.</li>\n<li>Worked example: a field researcher needs a device to carry between remote sites that might get knocked in a backpack. <strong>Solid-state</strong> fits, because it has no moving parts, so it survives being knocked far better than a magnetic drive (<strong>durability</strong>), and it''s small and light to carry (<strong>portability</strong>).</li>\n<li>Full marks always needs: ONE chosen type, then two or more reasons that are actually about THAT type, linked to THAT scenario — not a generic list of pros and cons for every storage family.</li>\n</ul>", "check": {"question": "A tablet aimed at young children needs a secondary storage device that will keep working if it''s dropped. Which factor matters most here?", "options": ["Cost", "Capacity", "Durability", "Portability"], "answer": 2, "explain": "Surviving being dropped is a durability question — how well the device withstands physical damage."}}, {"title": "Magnetic storage — hard disk drives", "html": "<h4>The strengths</h4>\n<ul>\n<li><strong>Capacity — very high.</strong> Magnetic hard disk drives are available in huge capacities (multiple terabytes) relatively cheaply, which makes them ideal for storing large amounts of data.</li>\n<li><strong>Cost — the lowest cost per gigabyte</strong> of the three families. This is the cheapest way to store a large amount of data.</li>\n</ul>\n<h4>The weaknesses</h4>\n<ul>\n<li><strong>Speed — slower</strong> than solid-state, because data has to be physically located by a moving read/write head on a spinning disk.</li>\n<li><strong>Durability — lower.</strong> The moving parts (a spinning disk and a read/write head) can be damaged if the drive is dropped or knocked, especially while it''s running.</li>\n<li><strong>Portability — lower.</strong> Magnetic drives are usually built into a machine that stays in one place, rather than being carried around.</li>\n</ul>\n<h4>When magnetic storage is the right answer</h4>\n<ul>\n<li>Whenever a scenario describes a device that <strong>stays in one place</strong> and needs to store <strong>a very large amount of data as cheaply as possible</strong> — a desktop PC, a server, or a smart TV that sits on a shelf.</li>\n</ul>", "check": {"question": "Why is a magnetic hard disk drive often chosen for a device that never moves and needs to store a lot of data cheaply?", "options": ["It has the fastest access speed of the three storage families available", "It has very high capacity at a low cost per gigabyte, suiting data that just sits still", "It has no moving parts, so it survives being dropped or knocked without damage", "It is the smallest and lightest of the three storage families, ideal for carrying around daily"], "answer": 1, "explain": "Magnetic storage''s strengths are high capacity and low cost per GB. Its weakness — lower durability from moving parts — stops mattering as much if the device is never moved."}}, {"title": "Optical storage — CDs, DVDs and Blu-ray discs", "html": "<h4>The strengths</h4>\n<ul>\n<li><strong>Cost — very cheap to produce</strong>, which makes optical discs ideal for distributing thousands or millions of identical copies of software, music or films.</li>\n<li><strong>Portability — high.</strong> Discs are small, thin and light, and can be played in any compatible drive.</li>\n</ul>\n<h4>The weaknesses</h4>\n<ul>\n<li><strong>Capacity — much lower</strong> than magnetic or solid-state storage. A CD holds around 700 MB, a DVD around 4.7 GB, and a Blu-ray disc up to around 50 GB — far less than a modern hard disk drive or SSD.</li>\n<li><strong>Speed — the slowest</strong> of the three families to read and write.</li>\n<li><strong>Durability/reliability — discs can be scratched</strong>, and their data layer can degrade over time (sometimes called \"disc rot\"), so they''re not the best choice for long-term, heavily-used storage.</li>\n</ul>\n<h4>When optical storage is the right answer</h4>\n<ul>\n<li>Whenever a scenario is about <strong>distributing many identical, cheap copies</strong> of something — a film studio releasing a movie, a magazine giving away a cover-mounted disc, or software being sold in a shop.</li>\n</ul>", "check": {"question": "A film studio wants to release millions of identical, cheap copies of a new movie to be sold in shops. Which storage technology best fits this?", "options": ["Magnetic hard disk drives", "Optical discs", "Solid-state drives", "RAM"], "answer": 1, "explain": "Optical discs are very cheap to mass-produce, which makes them the natural fit for distributing huge numbers of identical copies, even though their capacity and speed are lower than the alternatives."}}, {"title": "Solid-state storage — SSDs, USB sticks and memory cards", "html": "<h4>The strengths</h4>\n<ul>\n<li><strong>Speed — the fastest</strong> of the three families, because there''s nothing physically moving to locate the data.</li>\n<li><strong>Durability — the highest.</strong> With no moving parts, solid-state devices survive being dropped or knocked far better than a magnetic drive.</li>\n<li><strong>Portability — high.</strong> USB sticks and memory cards are small, light and robust enough to fit in a pocket.</li>\n<li>Other genuine advantages: they run <strong>silently</strong>, produce <strong>less heat</strong>, and use <strong>less power</strong> than magnetic drives.</li>\n</ul>\n<h4>The weakness</h4>\n<ul>\n<li><strong>Cost — usually more expensive per gigabyte</strong> than magnetic storage, especially at very large capacities (though the gap keeps narrowing).</li>\n</ul>\n<h4>When solid-state storage is the right answer</h4>\n<ul>\n<li>Whenever a scenario needs a device that is <strong>moved around</strong>, must <strong>feel fast and responsive</strong>, or has to <strong>survive rough handling</strong> — a laptop that travels with its owner, a smartphone, a camera, or a rugged tablet used by young children.</li>\n</ul>", "check": {"question": "A photographer needs a memory card to carry between locations that will keep working if it''s dropped in a camera bag. Which technology fits best?", "options": ["Magnetic hard disk drive", "Optical disc", "Solid-state storage", "Either magnetic or optical — they are equally durable"], "answer": 2, "explain": "Solid-state storage has no moving parts, so it is far more durable when knocked or dropped, and it''s small and light to carry — exactly what a portable memory card needs."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Secondary storage", "definition": "Storage that is non-volatile: it keeps data permanently, even when the power is off"}, {"term": "Non-volatile", "definition": "Data is not lost when the power supply is turned off"}, {"term": "Magnetic storage", "definition": "Stores data by magnetising areas of a disk or tape, e.g. a hard disk drive"}, {"term": "Optical storage", "definition": "Stores data as a pattern read by a laser, e.g. CD, DVD, Blu-ray disc"}, {"term": "Solid-state storage", "definition": "Stores data electronically in flash memory chips, with no moving parts"}, {"term": "Hard disk drive (HDD)", "definition": "A common magnetic secondary storage device"}, {"term": "SSD (solid-state drive)", "definition": "A fast, durable solid-state secondary storage device with no moving parts"}, {"term": "Capacity", "definition": "How much data a storage device can hold"}, {"term": "Speed", "definition": "How quickly data can be read from or written to a device"}, {"term": "Portability", "definition": "How easily a device can be carried and used with different computers"}, {"term": "Durability", "definition": "How well a device survives physical damage such as being dropped"}, {"term": "Reliability", "definition": "How consistently a device works over time without failing or corrupting data"}, {"term": "Cost", "definition": "The price of a device, often compared per gigabyte"}, {"term": "Cost per gigabyte", "definition": "A fairer way to compare storage cost across devices of different sizes"}, {"term": "Magnetic hard drive''s strength", "definition": "Very high capacity at low cost per gigabyte"}, {"term": "Magnetic hard drive''s weakness", "definition": "Moving parts make it less durable and slower than solid-state"}, {"term": "Optical disc''s strength", "definition": "Very cheap to produce and distribute in bulk"}, {"term": "Solid-state''s strength", "definition": "Fast, durable and portable, with no moving parts to fail"}]}, "mcq": {"enabled": true, "questions": [{"question": "Why does a computer need secondary storage as well as RAM?", "options": ["Because RAM is too slow to be useful without extra hardware assisting it", "Because RAM is volatile, so anything that must be kept has to survive being switched off", "Because secondary storage makes the CPU carry out instructions more quickly", "Because RAM can only hold a very small number of files compared to secondary storage devices"], "answer": 1, "explain": "RAM is volatile — its contents are lost when the power goes off. Secondary storage is non-volatile, so the OS, apps and files survive being switched off."}, {"question": "Which secondary storage technology has no moving parts?", "options": ["Magnetic", "Optical", "Solid-state", "All three have moving parts"], "answer": 2, "explain": "Solid-state devices store data electronically in flash memory chips — there is nothing spinning or moving inside."}, {"question": "A hard disk drive is an example of which storage technology?", "options": ["Optical", "Solid-state", "Magnetic", "Primary"], "answer": 2, "explain": "A hard disk drive stores data by magnetising tiny areas of a spinning disk, which makes it magnetic storage."}, {"question": "A DVD is an example of which storage technology?", "options": ["Magnetic", "Optical", "Solid-state", "Primary"], "answer": 1, "explain": "DVDs, CDs and Blu-ray discs store data as a pattern read by a laser, which makes them optical storage."}, {"question": "A film studio wants to distribute millions of identical, cheap copies of a new movie to shops. Which storage technology suits this best?", "options": ["Magnetic hard disk drives", "Optical discs", "Solid-state drives", "RAM"], "answer": 1, "explain": "Optical discs are very cheap to mass-produce, which is exactly what large-scale, low-cost distribution needs — even though their capacity and speed are lower."}, {"question": "A photographer needs a device to carry between locations that will keep working if it''s dropped in a camera bag. Which technology is the best fit?", "options": ["Magnetic hard disk drive", "Optical disc", "Solid-state drive", "Either magnetic or optical — they are equally durable"], "answer": 2, "explain": "Solid-state storage has no moving parts, so it survives being knocked or dropped far better than magnetic storage, and it''s small and light to carry."}, {"question": "Which factor describes how much data a storage device can hold?", "options": ["Speed", "Capacity", "Portability", "Reliability"], "answer": 1, "explain": "Capacity is how much data a device can store."}, {"question": "Which factor describes how quickly data can be read from or written to a device?", "options": ["Capacity", "Cost", "Speed", "Durability"], "answer": 2, "explain": "Speed is how quickly data can be transferred to or from the device."}, {"question": "Which factor is being tested when a device is dropped repeatedly to see if it survives?", "options": ["Reliability", "Durability", "Portability", "Cost"], "answer": 1, "explain": "Durability is how well a device withstands physical damage such as drops and knocks."}, {"question": "Which factor is being tested when a device is left running for a year to see how often it fails or corrupts files, even without being dropped?", "options": ["Durability", "Portability", "Reliability", "Capacity"], "answer": 2, "explain": "Reliability is how consistently a device keeps working correctly over time — a separate idea from surviving physical damage."}, {"question": "Which statement comparing an SSD to a magnetic hard disk drive is TRUE?", "options": ["The SSD is usually slower to access data but cheaper to buy per gigabyte", "The SSD is usually faster to access data but more expensive per gigabyte", "The SSD always has a lower storage capacity than any hard disk drive", "The hard disk drive has no moving parts, unlike the SSD"], "answer": 1, "explain": "SSDs have no moving parts, so they access data faster, but they typically cost more per gigabyte than magnetic storage."}, {"question": "A company''s server stores a huge, rarely-accessed archive and must keep the cost as low as possible. Which type of storage is the best fit?", "options": ["Solid-state, because it is the fastest of the three storage families to access", "Optical, because a single disc can hold more data than a magnetic hard disk drive", "Magnetic, because it offers very high capacity at a low cost per gigabyte", "None of these — only RAM should ever be used for long-term company archives"], "answer": 2, "explain": "For a huge, cheap, rarely-moved archive, magnetic storage''s high capacity and low cost per GB make it the natural fit — speed matters less if the data is rarely accessed."}]}, "fib": {"enabled": true, "questions": [{"text": "Secondary storage is [non-volatile], meaning it keeps its data even when the power is switched off."}, {"text": "Hard disk drives store data using [magnetic] storage technology."}, {"text": "CDs, DVDs and Blu-ray discs use [optical] storage, read by a laser."}, {"text": "SSDs and USB memory sticks use [solid-state] storage, which has no moving parts."}, {"text": "The six factors used to judge a storage device are capacity, speed, portability, durability, [reliability] and cost."}, {"text": "How much data a device can hold is called its [capacity]."}, {"text": "Compared to a magnetic hard drive, a solid-state drive is usually [faster] to access but [costlier] per gigabyte to buy."}, {"text": "Optical discs are cheap to produce, which makes them well suited to [distributing] software or films to many customers."}]}, "tf": {"enabled": true, "questions": [{"statement": "RAM counts as a type of secondary storage.", "answer": false, "explain": "RAM is primary storage. Secondary storage is a completely separate category — hard disk drives, SSDs, optical discs, USB sticks and memory cards."}, {"statement": "Secondary storage is non-volatile, meaning it keeps its data when the power is switched off.", "answer": true, "explain": "Correct — that permanence is exactly why the operating system, apps and files can still be there next time the device is turned on."}, {"statement": "Solid-state storage devices contain moving parts, just like magnetic hard disk drives.", "answer": false, "explain": "SSDs and USB sticks store data electronically in flash memory chips — there is nothing spinning or moving inside them, which is exactly why they are more durable."}, {"statement": "A single optical disc typically holds far less data than a modern magnetic hard disk drive.", "answer": true, "explain": "Correct — a Blu-ray disc holds around 50 GB at most, while hard disk drives are commonly sold in multiple-terabyte capacities."}, {"statement": "Solid-state drives are generally more durable than magnetic hard disk drives because they have no moving parts to damage if the device is knocked.", "answer": true, "explain": "Correct — without a spinning disk or moving read/write head, there is far less that can be damaged by a knock or a drop."}, {"statement": "Solid-state storage is always the cheapest option per gigabyte.", "answer": false, "explain": "Magnetic storage is usually the cheapest per gigabyte for very large capacities; solid-state typically costs more per GB, even though prices are falling."}, {"statement": "Durability and reliability mean exactly the same thing.", "answer": false, "explain": "Durability is about surviving physical damage (drops, knocks); reliability is about the device working consistently over time without failing or corrupting data, even if it is never dropped."}, {"statement": "If a question asks for a secondary storage device, naming a type such as ''magnetic'' instead of a specific device like ''hard disk drive'' is enough to earn the mark.", "answer": false, "explain": "Real exam answers were marked down for this. A type (magnetic/optical/solid-state) is a category, not a device. If the question asks for a device, name an actual product such as a hard disk drive, SSD, DVD or USB memory stick."}]}, "misc": {"enabled": true, "items": [{"myth": "''Secondary storage is only needed as a backup, in case something goes wrong.''", "truth": "This was a genuine misconception examiners saw in real answers. Secondary storage isn''t an emergency spare copy — it''s where the operating system, apps and files live permanently, all the time, in normal everyday use. Without it, nothing would still be there the next time the device is switched on.", "check": {"question": "Why is ''it''s needed as a backup'' not a full answer for why a device needs secondary storage?", "options": ["Backups are actually stored in RAM, so secondary storage doesn''t need to be mentioned in the answer at all", "It undersells the everyday role — the OS, apps and files live there permanently, not just for backup", "Secondary storage can''t actually hold backup copies of any files or programs", "It''s actually a complete and correct answer that earns full marks either way"], "answer": 1, "explain": "Secondary storage''s main job is everyday, permanent storage of the OS, apps and files — not just insurance against failure."}}, {"myth": "''Secondary storage is only used when RAM gets full'' — treating secondary storage in general as the same thing as virtual memory.", "truth": "This mixes up two different ideas. Virtual memory is a specific technique where RAM overflows onto secondary storage when RAM is nearly full — that''s a narrower topic (1.2.1). Secondary storage''s main job is much broader: it stores the OS, apps and every file permanently, all the time, whether or not RAM is full.", "check": {"question": "Which statement correctly separates secondary storage from virtual memory?", "options": ["They are the same thing, and exam answers can use either term to mean exactly the same idea", "Secondary storage holds data permanently; virtual memory just uses it as overflow when RAM is nearly full", "Virtual memory only exists on solid-state drives, and can never be used with a magnetic hard disk drive at all", "Secondary storage is only ever used once RAM has become completely full and cannot accept any more data"], "answer": 1, "explain": "Secondary storage is used constantly for permanent storage. Virtual memory is one specific, narrower use of it that only kicks in when RAM is nearly full."}}, {"myth": "Naming a TYPE of storage (e.g. ''magnetic'') when the question asks for a DEVICE.", "truth": "Real candidates lost marks for exactly this. A type is a category — magnetic, optical or solid-state. A device is an actual product — a hard disk drive, an SSD, a DVD, a USB memory stick. If the question says ''device'', name the device; if it says ''type'', name the type. The other direction catches people too: naming a specific device when a question explicitly asks for a type is also marked down.", "check": {"question": "A question asks ''give one example of a secondary storage device''. Which answer is correct?", "options": ["Magnetic storage", "Solid-state storage", "Hard disk drive", "Optical storage"], "answer": 2, "explain": "The question asks for a device (an actual product), not a type (a category). ''Hard disk drive'' is a device; the others are types."}}, {"myth": "''RAM'' or ''ROM'' given as an answer to a secondary storage question.", "truth": "RAM and ROM are always primary storage — never secondary storage, no matter how the question is worded. Real candidates who wrote RAM or ROM as their secondary storage device scored zero. Keep the two categories completely separate.", "check": {"question": "Which of these could correctly be given as an example of secondary storage?", "options": ["RAM, since it also stores data while the computer is switched on", "ROM, since it also stores data permanently inside the computer''s own chips", "A solid-state drive (SSD), since it is a genuine secondary storage device", "Cache, since it also holds data the processor is currently using"], "answer": 2, "explain": "RAM, ROM and cache are all primary storage. An SSD is a secondary storage device."}}, {"myth": "Justifying a choice of device with generic pros and cons of BOTH magnetic AND solid-state storage, instead of committing to one.", "truth": "The mark scheme requires you to pick ONE type first, then give reasons that support that specific choice for that specific scenario. Hedging with ''magnetic is cheap but solid-state is fast'' doesn''t commit to an answer and loses marks — and reasons that don''t match your chosen type score nothing, even if they''re true statements about the other type.", "check": {"question": "Why does listing pros of BOTH magnetic and solid-state storage lose marks in a ''justify your choice'' question?", "options": ["Because mark schemes never award any marks for cost or capacity, only ever for speed-related reasons", "Because the question needs ONE committed choice, with reasons that all match that same chosen type", "Because magnetic and solid-state storage are actually the exact same technology", "Because listing pros of both types is always worth full marks anyway"], "answer": 1, "explain": "Justification must match your chosen type. A hedged, two-sided answer doesn''t commit to a choice, so the reasons can''t be credited against it."}}, {"myth": "Durability and reliability are treated as the same idea.", "truth": "They test different things. Durability is about surviving physical punishment — drops, knocks, extreme temperatures. Reliability is about the device working consistently over time without failing or corrupting data, even if it''s never mishandled. A device can be one without being the other, so keep them as separate factors when you justify a choice.", "check": {"question": "A device survives being dropped repeatedly but occasionally corrupts files even when it''s never been knocked. Which factor is the problem?", "options": ["Durability", "Capacity", "Reliability", "Portability"], "answer": 2, "explain": "The device is durable (it survives drops) but not reliable (it fails on its own, without being mishandled)."}}]}, "tips": {"enabled": true, "items": [{"title": "The 2-mark ''why does it need secondary storage'' ladder", "html": "<p>A question like \"State, using an example, why the [device] needs secondary storage\" is marked as an example plus its reason — 1 mark for a correct example of what''s stored, 1 mark for the actual reason it must be kept. Watch this answer move up the ladder:</p>\n\n<p><strong>❌ 0 marks:</strong> \"So it can store things.\"</p>\n<ul>\n<li>No example, and \"store things\" just repeats the question without saying WHY.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"So it can store the operating system.\"</p>\n<ul>\n<li>A correct example — but no reason has been given for why it needs to be on secondary storage rather than RAM.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"So it can store the operating system, which needs to stay on the device permanently, even when it is switched off.\"</p>\n\n<p><strong>The pattern for every question shaped like this:</strong> name something specific that is stored → say why it needs to survive being switched off (or why it''s too big or too permanent for RAM alone).</p>", "check": {"question": "You''ve written ''so it can store apps''. What must you add for the second mark?", "options": ["The exact brand name and model number of the storage device that the apps happen to be installed on", "A reason why apps must survive the power being switched off, since they are needed permanently", "The exact price that the storage device originally cost when it was first purchased new", "A description of exactly how quickly the apps load once they have finally been opened"], "answer": 1, "explain": "The second mark is always the reason: apps must persist even when the power is off, which is exactly what non-volatile secondary storage provides."}}, {"title": "The 4-mark ''identify a type and justify'' ladder", "html": "<p>The most common exam question on this topic is shaped like: \"Identify an appropriate type of secondary storage for [scenario]. Justify your choice.\" It always needs TWO things in the right order: a type, then reasons that genuinely apply to THAT type in THIS scenario.</p>\n\n<p><strong>❌ 0 marks:</strong> \"A hard drive, because storage is good.\"</p>\n<ul>\n<li>Names a specific device rather than a type, and \"storage is good\" isn''t a reason at all.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"Solid state, because it''s the best kind of storage.\"</p>\n<ul>\n<li>A valid type — but \"best kind\" isn''t linked to anything about THIS scenario, so no justification marks are earned.</li>\n</ul>\n\n<p><strong>⚠️ 2 marks:</strong> \"Solid state, because it''s fast and doesn''t have moving parts.\"</p>\n<ul>\n<li>Two genuine solid-state facts, but neither is connected to the actual scenario — a strong answer explains WHY speed or durability matters HERE.</li>\n</ul>\n\n<p><strong>✅ Full marks (typical shape):</strong> \"Solid state, because it has no moving parts so it won''t be damaged if the device is knocked or moved <strong>(1)</strong>, it has fast data access so the device stays responsive <strong>(1)</strong>, it runs quietly and produces little heat, which suits a device that''s on constantly <strong>(1)</strong>, and its capacity is high enough for the files involved <strong>(1)</strong>.\"</p>\n\n<p>Two rules that catch real candidates out: name a TYPE first (magnetic/optical/solid-state), not a brand or model — and make sure every justification point clearly matches the type you chose. Some mark schemes even give a mark just for a valid type; others put all the marks into the justification and simply use your stated type to decide which list of reasons applies to you. Either way, get the type right first.</p>", "check": {"question": "You justify ''solid state'' using ''it''s cheap and it''s the newest technology.'' Why does this earn few or no marks?", "options": ["Because ''the newest technology'' is always automatically awarded marks in every single OCR mark scheme", "Neither reason is genuine: ''newest'' isn''t a real factor, and it isn''t usually the cheapest option", "The answer given is simply too short to be marked at all, regardless of what it says", "You must always choose magnetic storage over solid state for every single scenario"], "answer": 1, "explain": "Justification marks need genuine factors (capacity/speed/portability/durability/reliability/cost) linked to the scenario. ''Newest'' isn''t one of the six factors, and solid-state usually costs MORE per GB, not less."}}, {"title": "Reading a scenario for the right factor", "html": "<p>Before you write anything, scan the scenario for clue words and match them to one of the six factors — capacity, speed, portability, durability, reliability, cost.</p>\n<ul>\n<li><strong>\"carried around\" / \"moved between locations\" / \"fits in a bag\"</strong> → portability (and often durability too).</li>\n<li><strong>\"dropped\" / \"knocked\" / \"rough handling\" / \"outdoors\"</strong> → durability.</li>\n<li><strong>\"large files\" / \"high-definition\" / \"years of data\"</strong> → capacity.</li>\n<li><strong>\"responsive\" / \"loads quickly\" / \"no delay\"</strong> → speed.</li>\n<li><strong>\"budget\" / \"affordable\" / \"large numbers of them are needed\"</strong> → cost.</li>\n<li><strong>\"must not lose data\" / \"used constantly for years\"</strong> → reliability.</li>\n</ul>\n<p>Most 4-mark justify questions want you to spot two or three of these clues and build a reason around each — not to recite a generic list of pros and cons for every storage type. If the scenario doesn''t mention movement at all, don''t spend a mark on portability; if it says nothing about cost, don''t invent a cost point.</p>", "check": {"question": "A scenario says a device will ''sit inside a desktop PC on an office desk and store years of company records.'' Which factors are the strongest clues here?", "options": ["Portability and durability", "Capacity and cost", "Speed only", "Durability only"], "answer": 1, "explain": "''Years of company records'' points to capacity, and a device that just sits on a desk being stored cheaply points to cost — portability and durability barely matter here."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>State, using an example, why the digital photo frame needs secondary storage.</p>", "marks": 2, "hint": "Give ONE concrete example of what''s stored (the photos, the frame''s software) AND the reason it must survive being unplugged — both halves are needed for 2 marks.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each, up to max 2)</h5>\n<ul>\n<li>1 mark for an example of what is stored, e.g. the photograph files, the frame''s operating system, the display software</li>\n<li>1 mark for the reason: so the data is kept even when the photo frame is unplugged or switched off, or because secondary storage is non-volatile</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Allow both marks from a single sentence, e.g. \"The photograph files need to be stored so they are not lost when the frame is unplugged\" gets 1 mark for naming the photographs and 1 mark for not being lost when unplugged.</li>\n<li>Do not award a brand or model name on its own without an example of what is actually stored.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Students often give a sensible example of what is stored but forget to explain why it needs to survive the frame being switched off, so only one of the two marks is picked up. Some also confuse secondary storage with RAM, describing it as somewhere data is held only temporarily while the frame is switched on.</p>\n</div>"}, {"question": "<p>A journalist uses a laptop to write and edit news articles.</p><p>Give one example of a secondary storage device that the journalist''s laptop will have, and an example of the data that will be stored on it.</p>", "marks": 2, "hint": "Name an actual DEVICE (e.g. a hard drive or SSD), not just a type (e.g. ''solid state'') — and give data that would genuinely be created by a journalist.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark for device, 1 mark for data)</h5>\n<ul>\n<li>1 mark for a named device, e.g. hard drive, SSD, USB memory stick, flash memory card, CD, DVD</li>\n<li>1 mark for suitable example data, e.g. written articles, interview recordings, photographs, or data moved from RAM into virtual memory</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Allow any genuine secondary storage device, including an optical disc.</li>\n<li>The question asks for a device, not a type of device — magnetic, optical or solid state on its own is not enough.</li>\n<li>Award the data mark even if it is paired with an incorrect device.</li>\n<li>\"USB\" on its own is not enough; it must be clear a storage device is meant, e.g. \"USB memory stick\".</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Some students name a type of storage, such as \"magnetic\", instead of an actual device, such as \"hard drive\", which does not answer the question. Others confuse secondary storage with RAM or ROM, or give example data that would not realistically come from a journalist''s work.</p>\n</div>"}, {"question": "<p>Identify one appropriate type of secondary storage for the digital photo frame. Justify your choice.</p>", "marks": 4, "hint": "Name a TYPE (magnetic or solid state — optical isn''t suitable for a device that must access files directly and repeatedly) first, then give reasons that only make sense for that type in a device that stays in one place all day.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for choice of magnetic or solid state; 1 mark per point to max 3 for justification) e.g.</h5>\n<ul>\n<li><strong>Magnetic:</strong> enough storage capacity for a large family photo library; the frame is never moved, so durability and portability are not essential; low cost to purchase, keeping the frame affordable; the device is small enough to fit inside a slim frame; good long-term reliability.</li>\n<li><strong>Solid state:</strong> enough storage capacity for a large family photo library; still durable if the frame is ever knocked or moved; near-silent operation suits a device left running in a room; fast access means the next photo appears without a delay; uses little power; produces little heat; compact enough to fit inside a slim frame.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not award a specific device, e.g. hard disk — the question asks for a type. Follow-through justification marks are still allowed, to a max of 3. If both a device and a type are given, award it, e.g. solid state drive, SSD, magnetic hard disk drive.</li>\n<li>Mark the first secondary storage type given.</li>\n<li>If no secondary storage type is given, read the justification for a type — do not award the type mark, but still mark the justification (max 3).</li>\n<li>Justification must match the choice made.</li>\n<li>If the type is inappropriate, e.g. optical, do not award the type mark.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Some students name a specific device, such as \"a hard disk drive\", instead of a type, and lose the type mark even though the justification may be sound. Others mix reasons from both types in one answer, such as arguing for magnetic storage''s low cost and then solid state''s silent operation, which does not consistently justify a single choice.</p>\n</div>"}, {"question": "<p>A gamer has run out of storage space on their gaming PC and needs to buy a replacement secondary storage device to install more games. Identify whether the gamer should buy a magnetic secondary storage device or a solid state secondary storage device. Justify your choice.</p>", "marks": 4, "hint": "Pick a type first, then give up to 4 justification points that only make sense for the type you picked (not a generic list of pros and cons of both).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (no mark for the type itself; 1 mark per point matching the type, max 4)</h5><ul>\n<li><strong>Magnetic e.g.</strong> lower cost per gigabyte, so more storage for the same money; sufficient durability for the situation, since a desktop PC is not usually moved; very high capacity, suiting a large game library; reasonably fast once a game is installed and simply being loaded.</li>\n<li><strong>Solid state e.g.</strong> much faster read and write speed, so games install and load faster; no moving parts, so it is more durable if the PC is ever moved or knocked; produces less noise and heat than a spinning disk; still offers high capacity for a large game library, though usually at a greater cost per gigabyte; loading screens within games are shorter.</li>\n</ul></div><div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n<li>A cost point must specifically compare cost per gigabyte, not just state \"cheap\" or \"expensive\" without qualifying it against the amount of storage.</li>\n<li>Allow the reverse argument for each type, e.g. for solid state: \"it costs more, but the faster loading times are worth it for gaming\" gets credit for both the cost point and the speed point.</li>\n<li>If no type is stated at the start of the answer, read the whole answer to look for a type before awarding the justification marks. If no type is identified anywhere in the answer, award 0 marks.</li>\n</ul></div><div class=\"marks-section\"><h5>Common mistakes</h5><p>Students sometimes list generic facts about solid-state storage, such as \"it is faster\", without linking this to gaming, for example shorter loading screens or quicker installs. Others try to credit both magnetic and solid state in the same answer instead of committing to one type and justifying it consistently.</p></div>"}, {"question": "<p>Other than magnetic or solid-state storage, identify one further type of secondary storage.</p>", "marks": 1, "hint": "Name a storage TYPE (a category), not a brand or a specific device model.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><ul>\n<li><strong>Optical</strong></li>\n</ul></div><div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n<li>Accept \"optic\" or \"optical disc\". Do not award a specific example of optical storage, such as \"DVD\" or \"Blu-ray\", in place of the type itself.</li>\n</ul></div>"}, {"question": "<p>Refer to the library''s open day promotional disc described above.</p><p>Which type of secondary storage is most suitable for producing hundreds of cheap, identical copies of the demo to give away?</p>", "marks": 1, "hint": "Think about which factor matters most for handing out hundreds of cheap, identical copies — not overall capacity or access speed.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>Optical storage, because discs are very cheap to mass-produce identical copies of</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; there is no credit for a plausible-sounding reason attached to the wrong type.</li>\n</ul>\n</div>"}, {"question": "<p>Refer to the technician''s bootable installer described above.</p><p>The technician says her installer is stored on \"a solid-state device\". Which statement about this description is correct?</p>", "marks": 1, "hint": "A TYPE is the family (magnetic/optical/solid-state). A DEVICE is the actual product (USB stick, SSD, HDD, DVD). Which one is ''solid-state''?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>''Solid-state'' names the type; a USB memory stick/SSD would be the device</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how a magnetic hard disk drive stores data.</p>", "marks": 2, "hint": "Think about what physically changes on the disk itself, and how that pattern is then read back.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each)</h5>\n<ul>\n<li>Data is stored by magnetising tiny areas of a spinning disk (platter)</li>\n<li>A moving read/write head detects (or changes) the magnetised pattern to read (or write) the data</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept \"magnetic field\" for \"magnetised\".</li>\n<li>Do not accept a description of use instead of mechanism, e.g. \"it stores files\", without reference to magnetising the disk.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how a DVD stores data.</p>", "marks": 2, "hint": "Think about the physical pattern on the disc''s surface, and what device reads that pattern.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each)</h5>\n<ul>\n<li>Data is stored as a pattern of tiny pits and flat areas (lands) on the disc''s surface</li>\n<li>A laser reads the disc, detecting how light reflects differently off the pits and the lands</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept \"bumps\"/\"dents\" for pits.</li>\n<li>The second mark must reference a laser specifically, not just \"a sensor\".</li>\n</ul>\n</div>"}, {"question": "<p>Describe how a solid-state drive (SSD) stores data.</p>", "marks": 2, "hint": "Think about what an SSD is made of inside, and what it does NOT have compared to a hard disk drive.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each)</h5>\n<ul>\n<li>Data is stored electronically in flash memory cells/chips</li>\n<li>The SSD has no moving parts, unlike a magnetic hard disk drive</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept \"chips\"/\"transistors\" for flash memory cells.</li>\n<li>\"No moving parts\" must be stated explicitly for the second mark, not just implied.</li>\n</ul>\n</div>"}, {"question": "<p>Refer to the data centre described above.</p><p>A new employee says the data centre should avoid magnetic storage because \"one large hard disk drive costs more money to buy than one small USB stick.\" Explain why comparing the price of individual devices like this is misleading, and state which type of storage is actually cheaper for the data centre''s needs.</p>", "marks": 3, "hint": "Cost should be compared per gigabyte of storage, not per device — a bigger device naturally costs more to buy even if it works out cheaper for the amount of data it holds.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point to max 3)</h5>\n<ul>\n<li>Cost should be compared per gigabyte / per unit of storage, not by the price of a single whole device</li>\n<li>A large hard disk drive stores far more data than a small USB stick, so its higher price does not mean it is more expensive per gigabyte</li>\n<li>Magnetic storage is actually cheaper for the data centre, since it has the lowest cost per gigabyte at very large capacities</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not award simply restating that \"the employee is wrong\" without an explanation referencing cost per gigabyte/unit of storage.</li>\n<li>Allow reversed reasoning that reaches the same conclusion via capacity, e.g. discussing how much data each device holds for its price.</li>\n</ul>\n</div>"}, {"question": "<p>The table has four statements about secondary storage. Tick (✓) <strong>one</strong> box in each row to show which type of storage technology the statement describes.</p>", "marks": 4, "hint": "Match each statement to exactly one type — this table has one correct answer per row, not several.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each correctly ticked row)</h5>\n<ul>\n<li>Magnetises tiny areas of a spinning disk: <strong>Magnetic</strong></li>\n<li>Pattern of pits and lands, read by a laser: <strong>Optical</strong></li>\n<li>No moving parts, resistant to being dropped: <strong>Solid-state</strong></li>\n<li>Lowest cost per gigabyte at very high capacities: <strong>Magnetic</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>If more than one box is ticked in a row, 0 marks for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Refer to the wildlife photographer described above.</p><p>Explain why solid-state storage is generally more suitable than magnetic storage for the portable device she uses to back up her memory cards in the field. Refer to <strong>at least three</strong> different factors in your answer.</p>", "marks": 6, "hint": "Pick three different factors (e.g. durability, portability, speed, reliability) and for each one, explain WHY it matters specifically for working in remote, rough field conditions — a bare list of facts about solid-state storage isn''t enough on its own.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks (1 mark for a valid factor, 1 mark for linking it to the scenario, per factor, up to 3 factors)</h5>\n<ul>\n<li><strong>Durability</strong> — no moving parts, so it survives being dropped/knocked/exposed to dust or damp in the field without losing photos</li>\n<li><strong>Portability</strong> — small and light, so it is easy to carry between remote locations with limited luggage space</li>\n<li><strong>Speed</strong> — fast data access, so a full day''s memory cards can be backed up quickly each evening without wasting limited battery/generator time</li>\n<li><strong>Reliability</strong> — works consistently without corrupting files, so irreplaceable wildlife photos, taken once and never repeatable, are not lost</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not credit cost as an advantage — solid-state usually costs more per gigabyte than magnetic storage, so it would not support this argument.</li>\n<li>Each factor needs both the fact AND a link to the field-backup scenario for 2 marks; a fact alone scores 1.</li>\n<li>Award a maximum of 3 factors (6 marks); do not credit a repeated 4th idea.</li>\n</ul>\n</div>"}, {"question": "<p>Refer to the delivery fleet described above.</p><p>The logistics company is deciding whether to fit magnetic hard disk drives or solid-state drives inside the dashcams in its delivery vans.</p><p>Discuss which type of secondary storage the company should choose for the dashcams.</p><p>In your answer you might consider:</p><ul><li>how each type of storage works</li><li>the effect of vibration and constant use inside a moving vehicle</li><li>the capacity needed to record continuous video</li><li>the cost of fitting the chosen storage across the whole fleet</li></ul>", "marks": 8, "hint": "Use all four bullets as your plan. Explain the mechanism, weigh durability against constant vibration, weigh capacity for continuous recording, then weigh the cost of your choice ACROSS THE WHOLE FLEET (not just one van) for a top-band answer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (levelled) — indicative content</h5>\n<p>The following is indicative of possible factors/evidence that candidates may refer to but is not prescriptive or exhaustive:</p>\n<ul>\n<li><strong>How each type works</strong> — magnetic storage stores data by magnetising areas of a spinning disk, read by a moving head; solid-state storage stores data electronically in flash memory chips, with no moving parts.</li>\n<li><strong>Effect of vibration/constant use</strong> — a dashcam sits inside a vehicle that is constantly moving and vibrating while driving; a magnetic drive''s spinning disk and moving read/write head are more likely to be damaged or fail under constant vibration; solid-state has no moving parts, so it is far more durable in this environment and less likely to corrupt or lose footage.</li>\n<li><strong>Capacity for continuous recording</strong> — continuous video recording, especially if overwriting older footage in a loop, needs reasonably high capacity, but not as much as long-term archival; both technologies can offer enough capacity for this; solid-state capacities are now high enough for continuous dashcam footage without being excessive.</li>\n<li><strong>Cost across the fleet</strong> — solid-state usually costs more per gigabyte than magnetic storage; fitting one to every van in a large fleet multiplies this extra cost significantly, which the company must weigh against the reduced risk of a device failing on the road; magnetic storage is cheaper across a large fleet but carries a higher risk of failure/data loss from vibration, potentially losing footage needed as evidence after an incident.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>Mark Band 3 — High Level (6–8 marks):</strong> Thorough knowledge and understanding of magnetic and solid-state storage, applied directly and consistently to the dashcam/fleet context. The response weighs up both sides (durability/reliability under vibration against cost across the whole fleet) and covers all four bullet areas with clear, logically structured reasoning, reaching a justified conclusion.</li>\n<li><strong>Mark Band 2 — Mid Level (3–5 marks):</strong> Reasonable knowledge of magnetic and solid-state storage, generally accurate but at times underdeveloped or only partly applied to the vehicle context. Most of the four areas are addressed, with some structure, though the discussion may not fully weigh both sides or reach a clear conclusion.</li>\n<li><strong>Mark Band 1 — Low Level (1–2 marks):</strong> Basic knowledge with limited understanding shown; the material may contain inaccuracies or barely refer to the dashcam/fleet context. Little more than an unsupported assertion, e.g. \"solid-state is better\" with no working explanation of why.</li>\n<li><strong>0 marks:</strong> No attempt to answer the question or response is not worthy of credit.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-2-3-units', '1.2.3 Units', '{"learn": {"enabled": true, "items": [{"title": "Why must computer data be stored in binary?", "html": "<h4>The real reason — switches, not simplicity</h4>\n<ul>\n<li>Every value inside a computer — a number, a letter, a photo, a song — is ultimately stored as <strong>binary digits (bits)</strong>: 0s and 1s.</li>\n<li>The reason is physical, not a design choice made for convenience. Computers are built from millions of tiny electronic <strong>switches (transistors)</strong> that can only be in one of <strong>two states</strong>: <strong>on</strong> or <strong>off</strong>. \"On\" naturally represents 1; \"off\" represents 0.</li>\n<li>There is no reliable third or fourth state for a switch to sit in, so binary is the only form of data the hardware can physically represent. It isn''t that binary is \"easier\" — it''s the only option.</li>\n</ul>\n<h4>The building blocks, smallest to largest</h4>\n<ul>\n<li>A single <strong>bit</strong> is the smallest unit of data a computer can store — it holds exactly one 0 or one 1.</li>\n<li>A <strong>nibble</strong> is <strong>4 bits</strong>.</li>\n<li>A <strong>byte</strong> is <strong>8 bits</strong> — two nibbles. Almost every calculation in this topic ends with converting your answer into bytes (or a unit built from bytes).</li>\n</ul>\n<h4>Why the exam keeps coming back to this</h4>\n<ul>\n<li>OCR''s papers on this topic are <strong>non-calculator</strong>, so really they are testing whether you know the chain bit → nibble → byte → kilobyte… well enough to convert cleanly in your head, not whether you can do long division.</li>\n</ul>", "check": {"question": "Why is data stored in binary inside a computer?", "options": ["Because binary numbers are quicker for programmers to type out", "Because computers are built from switches that can only be on or off", "Because binary numbers always take up less storage space than denary", "Because early computer designers agreed on it as a shared standard"], "answer": 1, "explain": "It comes down to hardware, not convenience: a transistor can only be on or off, giving exactly two states — 1 and 0. There is no natural third state to build a switch around."}}, {"title": "The unit ladder: bit → nibble → byte → KB → MB → GB → TB → PB", "html": "<h4>Learn the ladder as one climbing sequence</h4>\n<table>\n<tr><th>Unit</th><th>Size</th></tr>\n<tr><td>Nibble</td><td>4 bits</td></tr>\n<tr><td>Byte</td><td>8 bits</td></tr>\n<tr><td>Kilobyte (KB)</td><td>1,000 bytes</td></tr>\n<tr><td>Megabyte (MB)</td><td>1,000 kilobytes</td></tr>\n<tr><td>Gigabyte (GB)</td><td>1,000 megabytes</td></tr>\n<tr><td>Terabyte (TB)</td><td>1,000 gigabytes</td></tr>\n<tr><td>Petabyte (PB)</td><td>1,000 terabytes</td></tr>\n</table>\n<h4>The step is always ×1,000</h4>\n<ul>\n<li>From kilobyte upwards, every step up the ladder is the same: <strong>multiply by 1,000</strong> to go up a unit, <strong>divide by 1,000</strong> to go down.</li>\n<li>So 3 kilobytes = 3,000 bytes; 2,000 megabytes = 2 gigabytes; 2,000 terabytes = 2 petabytes.</li>\n<li>Real candidates find the far ends of the ladder hardest — converting straight from terabytes to petabytes is where marks are most often lost, because it feels like \"too big a number\" to trust. Do the same ×1,000 / ÷1,000 step anyway.</li>\n</ul>\n<h4>The one exception you should know about</h4>\n<ul>\n<li>Some computer scientists instead treat each step as <strong>×1,024</strong> (because 1,024 = 2<sup>10</sup>, a \"round number\" in binary), which is technically how your operating system often reports file sizes.</li>\n<li>OCR''s specification uses the <strong>1,000× convention</strong> for this course, and that is what you should use by default. Mark schemes have occasionally also accepted an equivalent answer worked out using 1,024 — but 1,000 is the one to reach for first, and it produces far cleaner numbers on a non-calculator paper.</li>\n</ul>", "check": {"question": "Using the specification''s ×1,000 convention, how many kilobytes are in 5 megabytes?", "options": ["500 KB", "5,000 KB", "50,000 KB", "5 KB"], "answer": 1, "explain": "One megabyte is 1,000 kilobytes, so 5 megabytes is 5 × 1,000 = 5,000 kilobytes."}}, {"title": "Comparing file sizes and calculating storage capacity", "html": "<h4>Rule one: convert to the SAME unit before you compare</h4>\n<ul>\n<li>Exam questions love mixing units on purpose — \"which is bigger, 2,300 KB or 200 MB?\" You cannot compare the numbers 2,300 and 200 directly; you must convert them onto the same ladder step first.</li>\n<li>2,300 KB ÷ 1,000 = 2.3 MB. Now compare 2.3 MB against 200 MB — 200 MB is far bigger, even though \"2,300\" looked like the larger number.</li>\n<li>The trap only works if you compare the raw numbers without converting. Always ask \"same unit?\" before you tick an answer.</li>\n</ul>\n<h4>Worked example: calculating how much storage you need</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>A school stores 500 student photos, each averaging 4 MB. Find the TOTAL size in MB.</td><td>500 × 4 = 2,000 MB</td></tr>\n<tr><td>2</td><td>Convert MB into GB by dividing by 1,000 (the next step up the ladder).</td><td>2,000 ÷ 1,000 = 2 GB</td></tr>\n<tr><td>3</td><td>State the answer in the unit the question asked for, with working shown.</td><td>2 GB</td></tr>\n</table>\n<h4>The \"own-figure\" rule</h4>\n<ul>\n<li>OCR''s calculation questions usually give <strong>one mark for the correct final answer</strong> and a <strong>separate mark for showing valid working</strong> (e.g. the multiplication and the division step). If your working is sound but you slip on the arithmetic, you can still pick up the working mark — so always write every step down, even on a non-calculator paper.</li>\n</ul>", "check": {"question": "A phone stores 200 songs averaging 5 MB each. What is the total storage needed, in GB?", "options": ["1 GB", "0.1 GB", "10 GB", "100 GB"], "answer": 0, "explain": "200 × 5 = 1,000 MB. 1,000 MB ÷ 1,000 = 1 GB."}}, {"title": "Worked example: calculating a sound file''s size", "html": "<h4>The formula</h4>\n<ul>\n<li><strong>File size (bits) = sample rate (Hz) × duration (seconds) × bit depth (bits per sample)</strong></li>\n<li><strong>Sample rate</strong> is how many samples of the sound wave are taken every second, measured in <strong>hertz (Hz)</strong>.</li>\n<li><strong>Bit depth</strong> is how many bits are used to store the value of each sample. A bigger bit depth records the sound wave''s height more precisely.</li>\n</ul>\n<h4>Worked example</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>A 4-second recording is sampled at 10,000 Hz with an 8-bit depth. Multiply sample rate × duration × bit depth.</td><td>10,000 × 4 × 8 = 320,000 bits</td></tr>\n<tr><td>2</td><td>Always answer a file-size formula in BITS first, then convert. Divide by 8 to get bytes.</td><td>320,000 ÷ 8 = 40,000 bytes</td></tr>\n<tr><td>3</td><td>Convert bytes into a sensible unit by dividing by 1,000.</td><td>40,000 ÷ 1,000 = 40 KB</td></tr>\n</table>\n<h4>What increases the file size?</h4>\n<ul>\n<li>Increasing <strong>any</strong> of the three factors increases the file size: a <strong>higher sample rate</strong>, a <strong>longer duration</strong>, or a <strong>greater bit depth</strong> all mean more bits are stored.</li>\n<li>Sample rate and bit depth also affect <strong>quality</strong> — more samples and a more precise value per sample both make the digital copy closer to the original analogue sound wave.</li>\n</ul>", "check": {"question": "A sound is recorded for 2 seconds at a sample rate of 5,000 Hz with a bit depth of 8 bits. What is the file size in KB?", "options": ["10 KB", "80 KB", "1 KB", "800 KB"], "answer": 0, "explain": "5,000 × 2 × 8 = 80,000 bits. 80,000 ÷ 8 = 10,000 bytes. 10,000 ÷ 1,000 = 10 KB."}}, {"title": "Worked example: calculating an image file''s size", "html": "<h4>The formula</h4>\n<ul>\n<li><strong>File size (bits) = colour depth (bits per pixel) × height (pixels) × width (pixels)</strong></li>\n<li>An image is made of a grid of <strong>pixels</strong>. Each pixel stores a binary code for its colour — the number of bits used for that code is the <strong>colour depth</strong>.</li>\n<li><strong>Resolution</strong> is the number of pixels that make up the image (height × width) — more pixels means more detail, but also a bigger file.</li>\n</ul>\n<h4>Worked example</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>An image is 100 pixels tall and 200 pixels wide, with a colour depth of 8 bits. Multiply colour depth × height × width.</td><td>8 × 100 × 200 = 160,000 bits</td></tr>\n<tr><td>2</td><td>Convert bits into bytes by dividing by 8.</td><td>160,000 ÷ 8 = 20,000 bytes</td></tr>\n<tr><td>3</td><td>Convert bytes into a sensible unit by dividing by 1,000.</td><td>20,000 ÷ 1,000 = 20 KB</td></tr>\n</table>\n<h4>Quality vs file size — always a trade-off</h4>\n<ul>\n<li>A <strong>higher colour depth</strong> allows more possible colours per pixel (better quality) but stores more bits per pixel (bigger file).</li>\n<li>A <strong>higher resolution</strong> (more pixels) shows more detail but multiplies the file size directly — doubling both height and width roughly quadruples the file size.</li>\n<li><strong>Metadata</strong> (extra information stored with the image, such as its dimensions, the date it was taken or the camera used) adds a small amount on top of the pixel data itself.</li>\n</ul>", "check": {"question": "An image is 50 pixels tall and 100 pixels wide, with a colour depth of 8 bits. What is the file size in bytes?", "options": ["5,000 bytes", "40,000 bytes", "1,250 bytes", "800 bytes"], "answer": 0, "explain": "8 × 50 × 100 = 40,000 bits. 40,000 ÷ 8 = 5,000 bytes."}}, {"title": "Worked example: calculating a text file''s size", "html": "<h4>The formula</h4>\n<ul>\n<li><strong>File size (bits) = bits per character × number of characters</strong></li>\n<li>Every character in a text file (a letter, digit, space or punctuation mark) is stored as a binary code. The number of bits used for each character is given to you in the question — always use THAT number, not one you remember from elsewhere.</li>\n</ul>\n<h4>Worked example</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>A document has 500 characters, stored using 8 bits per character. Multiply bits per character × number of characters.</td><td>8 × 500 = 4,000 bits</td></tr>\n<tr><td>2</td><td>Convert bits into bytes by dividing by 8.</td><td>4,000 ÷ 8 = 500 bytes</td></tr>\n<tr><td>3</td><td>State the answer in the unit asked for (bytes here — the number is too small to need converting further).</td><td>500 bytes</td></tr>\n</table>\n<h4>The pattern across all three formulas</h4>\n<ul>\n<li>Notice all three file-size formulas share the same shape: a <strong>\"per unit\" factor</strong> (bits per sample / bits per pixel / bits per character) multiplied by <strong>however many of that unit there are</strong> (samples taken / pixels in the image / characters in the file).</li>\n<li>Work in <strong>bits first</strong>, every time — then convert (÷8 for bytes, ÷1,000 per step after that) into whatever unit the question wants.</li>\n</ul>", "check": {"question": "A text file has 1,000 characters stored at 8 bits per character. What is the file size in KB?", "options": ["1 KB", "8 KB", "0.1 KB", "125 KB"], "answer": 0, "explain": "8 × 1,000 = 8,000 bits. 8,000 ÷ 8 = 1,000 bytes. 1,000 ÷ 1,000 = 1 KB."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Bit", "definition": "The smallest unit of data a computer can store — a single 0 or 1"}, {"term": "Nibble", "definition": "4 bits"}, {"term": "Byte", "definition": "8 bits, or two nibbles"}, {"term": "Kilobyte (KB)", "definition": "1,000 bytes"}, {"term": "Megabyte (MB)", "definition": "1,000 kilobytes"}, {"term": "Gigabyte (GB)", "definition": "1,000 megabytes"}, {"term": "Terabyte (TB)", "definition": "1,000 gigabytes"}, {"term": "Petabyte (PB)", "definition": "1,000 terabytes"}, {"term": "Why binary is used", "definition": "Computer hardware is built from switches (transistors) that can only be on or off"}, {"term": "1,000 vs 1,024", "definition": "This course uses ×1,000 by default; 1,024 (2^10) is occasionally accepted as an alternative"}, {"term": "Sample rate", "definition": "The number of samples taken of a sound wave each second, measured in Hz"}, {"term": "Bit depth", "definition": "The number of bits used to store each sound sample (or each pixel''s colour)"}, {"term": "Colour depth", "definition": "The number of bits used to store the colour of one pixel"}, {"term": "Resolution", "definition": "The number of pixels making up an image — height × width"}, {"term": "Sound file-size formula", "definition": "Sample rate × duration (seconds) × bit depth"}, {"term": "Image file-size formula", "definition": "Colour depth × height (pixels) × width (pixels)"}, {"term": "Text file-size formula", "definition": "Bits per character × number of characters"}, {"term": "Capacity calculation method", "definition": "Work out the total in bits first, then divide by 8 for bytes and by 1,000 per unit after that"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is a nibble?", "options": ["2 bits", "4 bits", "8 bits", "16 bits"], "answer": 1, "explain": "A nibble is 4 bits — half of a byte."}, {"question": "How many bits make up a byte?", "options": ["4", "8", "10", "16"], "answer": 1, "explain": "A byte is 8 bits, or two nibbles."}, {"question": "Using the specification''s ×1,000 convention, which unit comes immediately after the megabyte on the ladder?", "options": ["Kilobyte", "Terabyte", "Gigabyte", "Petabyte"], "answer": 2, "explain": "The ladder runs bit → nibble → byte → kilobyte → megabyte → gigabyte → terabyte → petabyte."}, {"question": "Using the ×1,000 convention, how many bytes are in 3 kilobytes?", "options": ["30", "300", "3,000", "30,000"], "answer": 2, "explain": "1 kilobyte = 1,000 bytes, so 3 kilobytes = 3 × 1,000 = 3,000 bytes."}, {"question": "Using the ×1,000 convention, how many megabytes are in 2 gigabytes?", "options": ["20", "200", "2,000", "20,000"], "answer": 2, "explain": "1 gigabyte = 1,000 megabytes, so 2 gigabytes = 2 × 1,000 = 2,000 megabytes."}, {"question": "Why must a computer store all of its data as binary?", "options": ["Binary is quicker for a programmer to type than denary", "Its hardware is built from switches that can only be on or off", "Binary numbers use noticeably fewer digits than denary numbers do", "Binary makes every file automatically smaller and quicker to load"], "answer": 1, "explain": "A transistor only has two physical states — on and off — so binary (0/1) is the only form of data the hardware can represent."}, {"question": "A sound is recorded for 3 seconds at a sample rate of 20,000 Hz with an 8-bit depth. What is its file size in KB?", "options": ["60 KB", "6 KB", "48 KB", "480 KB"], "answer": 0, "explain": "20,000 × 3 × 8 = 480,000 bits. 480,000 ÷ 8 = 60,000 bytes. 60,000 ÷ 1,000 = 60 KB."}, {"question": "An image is 100 pixels tall and 100 pixels wide, with a colour depth of 4 bits. What is its file size in bytes?", "options": ["5,000 bytes", "40,000 bytes", "1,250 bytes", "10,000 bytes"], "answer": 0, "explain": "4 × 100 × 100 = 40,000 bits. 40,000 ÷ 8 = 5,000 bytes."}, {"question": "A text file has 2,000 characters stored at 8 bits per character. What is its file size in KB?", "options": ["2 KB", "16 KB", "0.2 KB", "250 KB"], "answer": 0, "explain": "8 × 2,000 = 16,000 bits. 16,000 ÷ 8 = 2,000 bytes. 2,000 ÷ 1,000 = 2 KB."}, {"question": "Which of these file sizes is the LARGEST?", "options": ["150,000 KB", "140 MB", "0.2 GB", "0.00013 TB"], "answer": 2, "explain": "Converting everything to MB: 150,000 KB = 150 MB; 140 MB; 0.2 GB = 200 MB; 0.00013 TB = 130 MB. 0.2 GB is the largest at 200 MB."}, {"question": "Which value have some OCR mark schemes also accepted as an alternative to ×1,000 when converting between units such as KB and MB?", "options": ["100", "500", "1,024", "10,000"], "answer": 2, "explain": "1,024 = 2 to the power 10, a value that fits neatly into binary. It is occasionally accepted as an alternative, but ×1,000 is the specification''s default and gives cleaner working."}, {"question": "A memory card holds 16 GB. Each photo is 2 MB. Roughly how many photos will fit?", "options": ["80", "800", "8,000", "80,000"], "answer": 2, "explain": "16 GB = 16,000 MB. 16,000 ÷ 2 = 8,000 photos."}]}, "fib": {"enabled": true, "questions": [{"text": "A [bit] is the smallest unit of data a computer can store, and it can only hold the value 0 or 1."}, {"text": "A nibble is made up of [4] bits, and a byte is made up of [8] bits."}, {"text": "Computers store data in binary because they are built from millions of tiny [switches] that can only be on or off."}, {"text": "Going up the unit ladder from kilobyte to petabyte, each step is [1000] times bigger than the one before."}, {"text": "The formula for a sound file''s size is sample rate × duration × [bit depth]."}, {"text": "The formula for an image file''s size is colour depth × height × [width]."}, {"text": "The formula for a text file''s size is bits per character × number of [characters]."}, {"text": "A file-size calculation should always be worked out in [bits] first, then converted into the unit the question asks for."}]}, "tf": {"enabled": true, "questions": [{"statement": "A byte is made up of 4 bits.", "answer": false, "explain": "4 bits is a nibble. A byte is 8 bits — two nibbles."}, {"statement": "Using the specification''s convention, 1 kilobyte is equal to 1,000 bytes.", "answer": true, "explain": "Correct — OCR''s default step between units on this course is ×1,000."}, {"statement": "A megabyte is larger than a gigabyte.", "answer": false, "explain": "The opposite is true: 1 gigabyte = 1,000 megabytes, so a gigabyte is far larger."}, {"statement": "Binary is used in computers because it is easier for programmers to type only two digits.", "answer": false, "explain": "The real reason is hardware, not typing convenience: a transistor can only be on or off, giving exactly two physical states."}, {"statement": "The image file-size formula multiplies colour depth by the image''s height and width in pixels.", "answer": true, "explain": "Correct — file size (bits) = colour depth × height × width."}, {"statement": "The sound file-size formula does not need to know how long the recording lasts.", "answer": false, "explain": "Duration is one of the three factors: file size (bits) = sample rate × duration × bit depth. Leaving it out gives the wrong answer."}, {"statement": "Some OCR mark schemes have also accepted answers calculated using 1,024 instead of 1,000.", "answer": true, "explain": "True — 1,000 is the specification''s default and gives cleaner non-calculator arithmetic, but 1,024 (2 to the power 10) has occasionally been accepted as an alternative."}, {"statement": "Before comparing or adding file sizes, you should convert every value onto the same unit.", "answer": true, "explain": "Correct — comparing ''2,300 KB'' with ''200 MB'' directly is meaningless until both are written in the same unit."}]}, "misc": {"enabled": true, "items": [{"myth": "Mixing up nibble and byte — remembering a byte as 4 bits.", "truth": "A <strong>nibble</strong> is 4 bits; a <strong>byte</strong> is 8 bits (two nibbles). If you always picture a nibble as \"half a byte\", the two stay locked together and you cannot swap them by accident.", "check": {"question": "Which pairing is correct?", "options": ["Nibble = 8 bits, byte = 4 bits", "Nibble = 4 bits, byte = 8 bits", "Nibble = 2 bits, byte = 4 bits", "Nibble and byte are the same size"], "answer": 1, "explain": "A nibble is 4 bits and a byte is 8 bits — a byte is exactly two nibbles."}}, {"myth": "Comparing file sizes written in different units without converting them onto the same unit first, and assuming the bigger-looking number wins — e.g. thinking 2,300 KB must be more than 200 MB because 2,300 is a bigger number than 200.", "truth": "You cannot compare the raw digits when the units are different. Convert both figures onto the same unit first: 2,300 KB ÷ 1,000 = <strong>2.3 MB</strong>, which is far smaller than <strong>200 MB</strong>. Always ask \"are these in the same unit?\" before deciding which is bigger.", "check": {"question": "Which is actually larger: 2,300 KB or 200 MB?", "options": ["2,300 KB, since 2,300 is a bigger raw number than 200", "200 MB, because 2,300 KB only converts to 2.3 MB", "The two values are exactly equal in size", "It cannot be worked out without a calculator"], "answer": 1, "explain": "2,300 KB = 2.3 MB, which is much smaller than 200 MB. Converting to the same unit is the only safe way to compare."}}, {"myth": "Believing the smallest whole number that can be stored in 8 bits is 1.", "truth": "It is <strong>0</strong> (represented as 00000000). Every bit can be 0, and a computer does not skip zero — it is a perfectly normal value to store, and often the smallest one available.", "check": {"question": "What is the smallest whole number that can be stored in 8 bits?", "options": ["0", "1", "8", "255"], "answer": 0, "explain": "00000000 represents 0, which is a valid value 8 bits can store — and the smallest one."}}, {"myth": "Finishing a file-size calculation and leaving the answer in bits, even though the question asked for the size in KB or MB.", "truth": "The three formulas always give you an answer in <strong>bits</strong> first — that is only the first step. You must then divide by 8 to reach bytes, and keep dividing by 1,000 for each unit up the ladder until you reach the unit the question actually asked for.", "check": {"question": "A calculation using the sound formula gives 80,000 bits. The question asks for the answer in KB. What should you do next?", "options": ["Write down 80,000 as the final answer, already correct in KB", "Divide by 8 to get bytes, then divide by 1,000 to get KB", "Multiply the bits total by 8 to reach bytes", "Divide the whole bits total by 1,000 only, then stop working"], "answer": 1, "explain": "80,000 bits ÷ 8 = 10,000 bytes, then ÷ 1,000 = 10 KB. Both conversion steps are needed to reach the unit asked for."}}, {"myth": "Believing binary is used in computers simply because it is a simpler or more convenient choice.", "truth": "It is not a preference — it is forced by the hardware. A computer is built from millions of transistors, and a transistor can only physically be <strong>on</strong> or <strong>off</strong>. Binary (1 and 0) is the only representation that fits that hardware.", "check": {"question": "Why can''t a computer use denary (0–9) internally instead of binary?", "options": ["Denary would make written programs far too easy to read", "Its switches (transistors) can only be in one of two physical states", "Denary numbers always take up noticeably more space than binary ones", "It could, but no manufacturer has ever built one"], "answer": 1, "explain": "The hardware itself only has two physical states available, so only a two-value (binary) system can be represented directly."}}, {"myth": "Assuming every unit conversion on this course must use ×1,024, and getting messy, error-prone arithmetic on a non-calculator paper as a result.", "truth": "Reach for <strong>×1,000</strong> first — it is this specification''s convention and produces clean numbers you can do in your head (exactly what a non-calculator paper needs). 1,024 is only occasionally accepted as an alternative, not the expected method.", "check": {"question": "On a non-calculator OCR paper, which conversion factor should you use by default between KB, MB, GB etc.?", "options": ["1,000", "1,024", "1,000 for KB→MB only, then 1,024 after that", "Either — the exam always accepts both with no working shown"], "answer": 0, "explain": "1,000 is the specification''s default convention and gives clean non-calculator arithmetic; 1,024 has only occasionally been accepted as an alternative."}}]}, "tips": {"enabled": true, "items": [{"title": "Show-your-working ladder: the 2-mark capacity calculation", "html": "<p>A typical question: <em>\"500 photos average 4 MB each. Calculate an estimate of the storage space in GB that the 500 files will require. Show your working out.\"</em> [2 marks] Here is the same answer at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"2 GB\"</p>\n<ul>\n<li>No working shown. Even a correct final answer with nothing behind it risks losing the working mark entirely if it happens to be wrong.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"500 × 4 = 2000 MB\"</p>\n<ul>\n<li>Valid working is shown (1 mark) but the answer was never converted into GB and stated as a final answer — the second mark is for the CONVERTED answer in the unit asked for.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"500 × 4 = 2000 MB <strong>(1)</strong>. 2000 ÷ 1000 = 2 GB <strong>(1)</strong>.\"</p>\n\n<p><strong>Why this matters even if your arithmetic slips:</strong> OCR marks the WORKING and the ANSWER as separate marks. If you multiply correctly but make a small slip converting units, you keep the working mark — but only if you actually wrote the working down. On a non-calculator paper, always show every step.</p>", "check": {"question": "You calculate 500 × 4 = 2000 MB correctly, but then wrongly divide by 100 instead of 1,000 and write ''20 GB''. What mark do you get out of 2?", "options": ["0, because the final stated answer is wrong", "1 — the working mark for the correct multiplication step", "2, since your working clearly shows you understood the method", "It depends entirely on which calculator you used"], "answer": 1, "explain": "The multiplication step (500 × 4 = 2000 MB) is valid working, so it earns the working mark even though the final conversion — and therefore the answer mark — was wrong."}}, {"title": "Comparing file sizes without a calculator: convert first, always", "html": "<p>Whenever a question gives you file sizes in different units and asks which is biggest, smallest, or equal, the trap is comparing the raw numbers before converting.</p>\n\n<p><strong>The three-step method:</strong></p>\n<ul>\n<li><strong>1. Pick ONE unit</strong> to convert everything into — usually whichever unit most of the options are already close to.</li>\n<li><strong>2. Convert every option</strong> using ×1,000 / ÷1,000 per step, writing the converted value next to each option.</li>\n<li><strong>3. Compare the converted values</strong>, not the original numbers.</li>\n</ul>\n\n<p><strong>Worked example — which of these is equal to 3 MB?</strong></p>\n<ul>\n<li>3,000 KB → ÷1,000... wait, KB→MB is ÷1,000, so 3,000 ÷ 1,000 = <strong>3 MB</strong>. Equal.</li>\n<li>0.003 GB → ×1,000 to get MB: 0.003 × 1,000 = <strong>3 MB</strong>. Also equal!</li>\n<li>Both convert to exactly 3 MB — a reminder that more than one option can be correct in a \"tick two boxes\" style question, and that the trick is almost always hiding an equivalent value in a different unit.</li>\n</ul>", "check": {"question": "A question gives four file sizes in four different units and asks you to tick the largest. What should you do FIRST?", "options": ["Tick whichever of the four raw numbers looks the biggest", "Convert every option into the same unit before comparing", "Add all four of the given numbers together", "Assume the very first option is a decoy"], "answer": 1, "explain": "Raw numbers in different units cannot be compared directly — converting everything onto the same unit first is the only reliable method."}}, {"title": "Tick-one-box unit questions: what the 1 mark actually needs", "html": "<p>Single tick-box questions on this topic are worth only 1 mark, but they are rarely a lucky guess — three of the four options are usually wrong for a specific, checkable reason.</p>\n\n<p><strong>❌ Common wrong pick:</strong> choosing an option because it \"sounds right\" or uses a familiar-looking number, without actually converting or checking it.</p>\n\n<p><strong>✅ The reliable method:</strong> work out (or convert) EVERY option before you tick anything, and eliminate the ones you can prove are wrong. For a \"which statement about binary is true\" style question, check each statement against something you know for certain — e.g. a binary digit can only ever be 0 or 1, so any statement mentioning a third digit value is automatically false.</p>\n\n<p><strong>One tick only.</strong> Every mark scheme on this topic states that ticking two or more boxes scores zero, even if one of them is correct — so if you are unsure, commit to your best-evidenced single answer rather than hedging.</p>", "check": {"question": "You are fairly confident the answer is box 3, but tick box 1 as well just in case. What mark do you get?", "options": ["1 mark, since box 3 is the box that was actually correct", "0 marks — two or more ticks always scores zero on these questions", "0.5 marks awarded automatically as partial credit", "It depends entirely on which of the two ticked boxes the examiner prefers"], "answer": 1, "explain": "OCR''s mark schemes for single tick-box questions award 0 marks the moment two or more boxes are ticked, regardless of whether the correct box is among them."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Computers represent data in binary form.</p><p>Tick (✓) <strong>one</strong> box in each row to identify the binary unit equivalent of each of the given file sizes.</p>", "marks": 4, "hint": "Work out each file size using ×1,000 steps (bytes→KB→MB→GB→TB→PB), then find the matching column. Two different rows can share the same correct column.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>3000 bytes → <strong>3 kilobytes</strong></li>\n<li>3000 terabytes → <strong>3 petabytes</strong></li>\n<li>24 bits → <strong>3 bytes</strong></li>\n<li>6 nibbles → <strong>3 bytes</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Students sometimes tick a column just because the number \"3\" appears in it, without actually converting the row''s value — for example ticking \"3 megabytes\" for \"3000 bytes\" purely because both mention 3. It also catches students out that two different rows (24 bits and 6 nibbles) both convert to the same answer, 3 bytes; some assume every row must point to a different column and talk themselves out of a correct answer to avoid a \"repeat\".</p>\n</div>"}, {"question": "<p>Computers represent data in binary form.</p><p>Tick (✓) <strong>one</strong> box to identify the statement about binary that is true.</p>", "marks": 1, "hint": "Each of the three wrong statements is wrong for a specific, checkable reason — test each one rather than guessing which ''feels'' right.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Binary is used because computer hardware is built from switches that can only be on or off</strong> (box 2)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept cross or other indication as long as clear which one they intend.</li>\n<li>2 or more ticks scores 0 marks.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Statement 1 catches students who forget that a binary digit can only be 0 or 1, never 2, and that computer hardware only has two physical states, not three. Statement 3 reverses the truth — it is the LEFT-most bit of a binary integer that holds the largest value, not the right-most. Statement 4 is the trickiest: with 4 bits the largest value is 1111, which is 15 in denary, not 9 — students sometimes pick a number that \"seems about right\" without actually working it out.</p>\n</div>"}, {"question": "<p>Tick (✓) <strong>one</strong> box to identify the largest file size.</p>", "marks": 1, "hint": "Convert every option into the same unit (try MB) before comparing.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>0.001 TB</strong> (box 3)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept cross or other indication as long as clear which one they intend.</li>\n<li>2 or more ticks scores 0 marks.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Students often tick 1200 KB or 1 500 000 bytes because the raw digits look bigger than \"0.001\". Converting everything to MB shows the truth: 1 500 000 bytes = 1.5 MB, 1200 KB = 1.2 MB and 150 MB stays 150 MB, but 0.001 TB = 1000 MB — by far the largest once it is actually converted.</p>\n</div>"}, {"question": "<p>Tick (✓) <strong>two</strong> boxes to identify the two file sizes that are equal to each other.</p>", "marks": 1, "hint": "Convert every option into the same unit before comparing — exactly two of the four will match.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark for both boxes</h5>\n<ul>\n<li><strong>3 600 000 bytes</strong> (box 1)</li>\n<li><strong>3.6 MB</strong> (box 3)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept cross or other indication as long as clear which ones they intend.</li>\n<li>Ticking one box only, or three or more boxes, scores 0 marks.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>360 KB is a deliberate near-miss: it looks close to \"3.6\" but is actually 0.36 MB once converted, not 3.6 MB. Students who spot the \"3.6\" pattern in the digits without converting sometimes tick 360 KB, instead of working out that 3 600 000 bytes ÷ 1 000 000 = 3.6 MB is the true match.</p>\n</div>"}, {"question": "<p>A cloud backup service stores photos with an average (mean) file size of 5 MB. A user has backed up 800 photos to the service.</p><p>Calculate an estimate of the storage space in GB that the 800 photos will require, assuming they are each 5 MB in size. Show your working out.</p>", "marks": 2, "hint": "Total size in MB first (5 × 800), then convert MB to GB (÷ 1000) — show both steps as your working.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for the answer <strong>4 GB</strong>.</li>\n<li>1 mark for working, e.g. 5 × 800 ÷ 1000, or 5 × 800, or 4000 ÷ 1000, or 5 ÷ 1000, or 0.005 × 800.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Allow 3.90625 (or an approximation) if dividing by 1024 instead of 1000.</li>\n<li>Not all of the working needs to be correct to get the working mark. Ignore mentions of MB/GB in the working.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Common mistakes</h5>\n<p>Students sometimes multiply 5 × 800 correctly to get 4000 MB but then forget the second step, writing \"4000 GB\" as their final answer instead of dividing by 1000 — losing the answer mark despite having earned the working mark.</p>\n</div>"}, {"question": "<p>Which list shows these four units in order from SMALLEST to LARGEST?</p>", "marks": 1, "hint": "Start from the smallest possible unit — the one that holds a single 0 or 1 — and climb the ladder one step at a time.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>bit, nibble, byte, kilobyte</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; there is no credit for a partially correct order.</li>\n</ul>\n</div>"}, {"question": "<p>The drone''s camera converts each photo directly into binary before storing it on the memory card. State why this data must be stored using binary (1s and 0s), rather than any other number system.</p>", "marks": 1, "hint": "Think about the physical hardware, not convenience — what are the only two states a switch inside a chip can be in?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>Computer/memory hardware is built from millions of tiny electronic components (transistors/switches) that can only be in one of two physical states — on or off — so only binary (two-value) data can be represented directly, or there is no reliable third or fourth physical state to represent extra digits</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any answer that correctly links binary to the two physical states of the hardware.</li>\n<li>Do not accept \"binary is simpler/easier for programmers\" or \"it saves space\" — neither is the real reason.</li>\n</ul>\n</div>"}, {"question": "<p>Each sensor reading is logged into the spreadsheet as a 25-character line of text, using 8 bits to store each character. Calculate the storage space, in bytes, needed for one logged reading. Show your working.</p>", "marks": 2, "hint": "Use the text file-size formula: bits per character × number of characters. Work the answer out in bits first, then convert to bytes.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working, e.g. 8 × 25 = 200 (bits), or 200 ÷ 8</li>\n<li>1 mark for the answer: 25 bytes</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any correct method that reaches bits first, then converts to bytes by dividing by 8.</li>\n<li>Award the working mark even if the final answer is wrong, provided the method shown is valid.</li>\n</ul>\n</div>"}, {"question": "<p>A sprite is 16 pixels tall and 16 pixels wide, using a colour depth of 4 bits per pixel. The developer wants every sprite file to be under 200 bytes.</p><p>Calculate the sprite''s file size in bytes, and state whether it is within the developer''s 200-byte budget. Show your working, including how much spare capacity (in bytes) is left if it is within budget.</p>", "marks": 4, "hint": "Use the image formula: colour depth × height × width, in bits first — then convert to bytes before comparing to the 200-byte budget.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark for working: 4 × 16 × 16 = 1024 (bits)</li>\n<li>1 mark for working: 1024 ÷ 8 = 128 (bytes)</li>\n<li>1 mark for the answer: 128 bytes</li>\n<li>1 mark for stating the sprite is within budget with the correct spare capacity: 200 − 128 = 72 bytes</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Own-figure/follow-through applies to the last two marks — if an earlier step is wrong, the comparison and spare-capacity marks can still be awarded using the candidate''s own (wrong) file size, provided the method used is correct.</li>\n<li>Do not award the spare-capacity mark if the within/over budget conclusion is missing or wrong.</li>\n</ul>\n</div>"}, {"question": "<p>Complete the table by converting each given value into the unit requested. Use the specification''s ×1,000 convention.</p>", "marks": 4, "hint": "Nibble → bits doesn''t use the ×1,000 rule (a nibble is 4 bits) — every other row does.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>3 nibbles = 12 bits</li>\n<li>5,000 bytes = 5 kilobytes</li>\n<li>2 gigabytes = 2,000 megabytes</li>\n<li>0.5 terabytes = 500 gigabytes</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept the numeric value with or without the unit written alongside it.</li>\n<li>Each row is marked independently.</li>\n</ul>\n</div>"}, {"question": "<p>The podcast host records a short clip lasting 30 seconds at a sample rate of 8,000 Hz, using an 8-bit depth. What is the resulting file size, in kilobytes, using the specification''s ×1,000 convention?</p>", "marks": 1, "hint": "Use the sound formula (sample rate × duration × bit depth) to get bits first, then divide by 8 for bytes and by 1,000 for kilobytes.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>240 KB</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores. Working: 8,000 × 30 × 8 = 1,920,000 bits ÷ 8 = 240,000 bytes ÷ 1,000 = 240 KB.</li>\n</ul>\n</div>"}, {"question": "<p>The podcast host uploads finished episodes to a hosting service that gives free accounts 2 GB of storage. Each episode is recorded at a sample rate of 16,000 Hz, with an 8-bit depth, and lasts 600 seconds (10 minutes). The host wants to upload 4 episodes recorded this way.</p><p>Calculate whether all 4 episodes will fit within the 2 GB of free storage, showing your full working and stating how much spare capacity (in MB) is left if they do fit.</p>", "marks": 6, "hint": "Work in stages: one episode''s size in bits → bytes → MB, then multiply by 4 episodes, then compare the total to 2 GB converted into MB.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks</h5>\n<ul>\n<li>1 mark: 16,000 × 600 × 8 = 76,800,000 (bits)</li>\n<li>1 mark: 76,800,000 ÷ 8 = 9,600,000 (bytes)</li>\n<li>1 mark: 9,600,000 ÷ 1,000 ÷ 1,000 = 9.6 (MB)</li>\n<li>1 mark: 9.6 × 4 = 38.4 (MB, for all four episodes)</li>\n<li>1 mark: 2 GB converted to 2,000 MB</li>\n<li>1 mark: correct conclusion — the episodes fit, with 2,000 − 38.4 = 1,961.6 MB spare</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Own-figure/follow-through applies throughout: each step''s mark can be awarded using the candidate''s own value carried forward from an earlier (even incorrect) step, provided the method used at that step is correct.</li>\n<li>The final conclusion mark requires both a correct fit/no-fit statement AND a spare-capacity figure consistent with their own total.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how increasing the colour depth used for a sprite, and increasing its resolution, would each affect the sprite''s file size and its visual quality.</p>", "marks": 3, "hint": "Two separate factors to describe — colour depth and resolution — linking each one back to both file size AND quality.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point to max 3)</h5>\n<ul>\n<li>A higher colour depth stores more bits per pixel, increasing the file size, but allows more possible colours per pixel (better/richer quality)</li>\n<li>A higher resolution (more pixels) increases the file size, because there is more pixel data to store, but shows more visual detail (better quality)</li>\n<li>Both a higher colour depth and a higher resolution increase file size — a real trade-off against visual quality, which matters for a retro-style game where sprites are deliberately kept small</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per point to a maximum of 3.</li>\n<li>Full marks needs both colour depth and resolution addressed, plus a valid comment on the size/quality trade-off (or an equally strong development of one factor).</li>\n</ul>\n</div>"}, {"question": "<p>The drone company is trying to decide on camera settings for a new model. Setting A uses a high resolution and high colour depth, producing the best-quality photos but larger files. Setting B uses a lower resolution and lower colour depth, producing smaller files but lower-quality photos.</p><p>Discuss the impact that choosing between Setting A and Setting B could have on a single flight, during which the drone''s memory card has a fixed, limited capacity.</p><p>In your answer you might consider:</p><ul><li>how colour depth and resolution affect file size</li><li>the effect on how many photos can be stored on the memory card during one flight</li><li>the effect on the usefulness of the photos once the drone lands</li><li>which setting you would recommend, and why</li></ul>", "marks": 8, "hint": "Use all four bullets as your plan. Explain the mechanism (bigger files → fewer photos fit), follow it through to a REAL consequence of the flight, and weigh photo quality against photo quantity for a top-band answer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (levelled) — indicative content</h5>\n<p>The following is indicative of possible factors/evidence that candidates may refer to but is not prescriptive or exhaustive:</p>\n<ul>\n<li><strong>How colour depth/resolution affect file size</strong> — Setting A''s higher colour depth stores more bits per pixel, and its higher resolution means more pixels overall; both increase file size (bits = colour depth × height × width). Setting B''s lower values mean a smaller file size per photo.</li>\n<li><strong>Effect on how many photos fit</strong> — the memory card''s capacity is fixed, so larger Setting A photos mean fewer photos can be stored during one flight; Setting B''s smaller photos mean many more can be stored before the card fills up.</li>\n<li><strong>Effect on the usefulness of the photos</strong> — Setting A''s higher quality/detail may matter for close inspection or publication, but running out of card space mid-flight could mean missing important later photos; Setting B captures more of the flight but each photo shows less fine detail, which may not be good enough for the drone''s purpose.</li>\n<li><strong>Recommendation</strong> — the better choice depends on the drone''s actual task: Setting A suits short flights needing a few high-quality images, Setting B suits long flights needing continuous coverage where running out of storage would be worse than lower detail.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>Mark Band 3 — High Level (6–8 marks):</strong> Thorough knowledge and understanding of colour depth, resolution and file-size capacity, applied directly and consistently to the drone context. The response weighs up both settings (quality against quantity/storage) and covers all four areas from the bullet list with clear, logically structured reasoning, ending in a justified recommendation.</li>\n<li><strong>Mark Band 2 — Mid Level (3–5 marks):</strong> Reasonable knowledge, generally accurate but at times underdeveloped or only partly applied to the drone context. Most of the four areas are addressed, with some structure, though the discussion may not fully weigh both settings or the recommendation may be unjustified.</li>\n<li><strong>Mark Band 1 — Low Level (1–2 marks):</strong> Basic knowledge with limited understanding shown; the material may contain inaccuracies or barely refer to the drone context. Little more than an unsupported assertion, e.g. \"Setting A is better\" with no working explanation of why.</li>\n<li><strong>0 marks:</strong> No attempt to answer the question or response is not worthy of credit.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-2-4-data-storage-numbers', '1.2.4 Data Storage: Numbers', '{"learn": {"enabled": true, "items": [{"title": "How do you convert between denary and 8-bit binary?", "html": "<h4>The 8-bit place-value ladder</h4>\n<ul>\n<li>Every position in an <strong>8-bit binary number</strong> stands for a fixed <strong>place value</strong>, exactly like the columns in a denary number stand for units, tens and hundreds.</li>\n<li>The eight place values, left to right, are always the same: <strong>128, 64, 32, 16, 8, 4, 2, 1</strong>.</li>\n<li>The left-most bit is called the <strong>most significant bit (MSB)</strong> — it carries the largest place value (128). The right-most bit is the <strong>least significant bit (LSB)</strong> — it carries the smallest place value (1).</li>\n</ul>\n<table>\n<tr><th>Place value</th><td>128</td><td>64</td><td>32</td><td>16</td><td>8</td><td>4</td><td>2</td><td>1</td></tr>\n</table>\n<h4>How do you convert denary to binary?</h4>\n<ul>\n<li>Starting from the largest place value (128), ask \"does this fit into my number?\" If yes, write a <strong>1</strong> and subtract it; if no, write a <strong>0</strong> and move on. Repeat all the way down to the 1s column.</li>\n<li>Always write the result as a full <strong>8 digits</strong>, adding leading zeros (<strong>padding</strong>) if the number doesn''t need every place — e.g. the 5-digit result 11010 must be padded to 00011010 to be a correctly-formatted 8-bit answer.</li>\n</ul>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>Convert denary 172. Find which place values from 128, 64, 32, 16, 8, 4, 2, 1 add up to 172.</td><td>128 + 32 + 8 + 4 = 172</td></tr>\n<tr><td>2</td><td>Write a 1 under every place value used, and a 0 under every place value not used.</td><td>1 0 1 0 1 1 0 0</td></tr>\n<tr><td>3</td><td>Read the 8 digits left to right as the final answer.</td><td>10101100</td></tr>\n</table>\n<h4>How do you convert binary to denary?</h4>\n<ul>\n<li>Do the reverse: line up the place values above each bit, then <strong>add together only the place values where there''s a 1</strong> — ignore every position that holds a 0.</li>\n<li>Example: 01011001 has 1s in the 64, 16, 8 and 1 columns, so 64 + 16 + 8 + 1 = <strong>89</strong>.</li>\n</ul>", "check": {"question": "What is the 8-bit binary number 01011001 in denary?", "options": ["89", "91", "93", "85"], "answer": 0, "explain": "The 1s sit in place values 64, 16, 8 and 1: 64 + 16 + 8 + 1 = 89."}}, {"title": "How do you add two 8-bit binary numbers, and what is overflow?", "html": "<h4>Adding binary numbers, column by column</h4>\n<ul>\n<li>Binary addition works exactly like denary column addition, except every column can only hold a 0 or a 1 — so whenever a column''s total reaches <strong>2</strong>, you write down the remainder and <strong>carry a 1</strong> into the next column left, exactly like carrying a ten in a denary sum.</li>\n<li>The four rules you need: 0+0=0, 0+1=1, 1+1=10 (write 0, carry 1), 1+1+1(carried)=11 (write 1, carry 1).</li>\n</ul>\n<pre class=\"code-block\">  01001101   (77)\n+ 00100011   (35)\n-----------\n  01110000   (112)</pre>\n<h4>What is overflow, and why does it happen?</h4>\n<ul>\n<li>An 8-bit register can only ever store the denary values <strong>0 to 255</strong>. If the TRUE result of an addition needs a 9th bit to be represented correctly, that extra bit has nowhere to go — this is called <strong>overflow</strong>.</li>\n<li>You can spot it two ways: the denary sum of the two original numbers is <strong>greater than 255</strong>, OR there is a <strong>carry left over out of the left-most (128) column</strong> once the addition finishes.</li>\n<li>When overflow happens, the 8 bits that ARE stored no longer represent the correct value — the result is simply wrong unless that extra bit is kept somewhere (e.g. a bigger register).</li>\n</ul>\n<pre class=\"code-block\">  11001000   (200)\n+ 01100100   (100)\n-----------\n1 00101100   (true result needs 9 bits: 300)</pre>\n<p>Only the right-hand 8 bits (00101100 = 44) can actually be stored in an 8-bit register — the leading 1 is lost, so the stored value (44) is not the true sum (300). That mismatch is overflow.</p>", "check": {"question": "Two 8-bit binary numbers are added and the true denary sum is 300. What happens when this is stored in an 8-bit register?", "options": ["An overflow error occurs, since 300 needs more than 8 bits to be stored correctly", "The register automatically resizes itself to become a full 9-bit register instead", "The computer rounds 300 down to the nearest value that is under 256", "Nothing unusual happens at all, because 300 fits comfortably into one byte"], "answer": 0, "explain": "8 bits can only store 0–255, so a true result of 300 needs a 9th bit — that''s overflow. Only the low 8 bits are actually stored, giving the wrong value."}}, {"title": "How do you convert between denary and 2-digit hexadecimal?", "html": "<h4>What is hexadecimal?</h4>\n<ul>\n<li><strong>Hexadecimal (hex)</strong> is a base-16 number system. It needs 16 different digits for each position — the familiar 0-9, then the letters <strong>A, B, C, D, E, F</strong> standing for the values 10-15.</li>\n<li>Any whole number from 0 to 255 can be written using exactly <strong>2 hexadecimal digits</strong> (00 to FF).</li>\n</ul>\n<table>\n<tr><th>Hex digit</th><td>A</td><td>B</td><td>C</td><td>D</td><td>E</td><td>F</td></tr>\n<tr><th>Value</th><td>10</td><td>11</td><td>12</td><td>13</td><td>14</td><td>15</td></tr>\n</table>\n<h4>Denary → hex</h4>\n<ul>\n<li>Divide the denary number by 16. The <strong>whole-number answer</strong> becomes the first hex digit; the <strong>remainder</strong> becomes the second hex digit (converting either one to a letter if it''s 10 or more).</li>\n</ul>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>Convert denary 219 to hex. Divide by 16.</td><td>219 ÷ 16 = 13 remainder 11</td></tr>\n<tr><td>2</td><td>Convert each part to a hex digit (13 → D, 11 → B).</td><td>D, B</td></tr>\n<tr><td>3</td><td>Write the two digits together as the final answer.</td><td>DB</td></tr>\n</table>\n<h4>Hex → denary</h4>\n<ul>\n<li>Reverse the process: multiply the FIRST hex digit''s value by 16, then add the SECOND hex digit''s value.</li>\n<li>Example: hex <strong>2F</strong> → (2 × 16) + 15 = 32 + 15 = <strong>47</strong>.</li>\n</ul>", "check": {"question": "What is the hexadecimal value 5A in denary?", "options": ["90", "85", "80", "95"], "answer": 0, "explain": "(5 × 16) + 10 = 80 + 10 = 90."}}, {"title": "How do you convert between binary and hexadecimal?", "html": "<h4>Why nibbles are the key</h4>\n<ul>\n<li>A <strong>nibble</strong> (4 bits) can represent exactly 16 different values (0000 to 1111) — precisely matching the 16 possible hexadecimal digits (0-F). That''s why hex conversion always works in groups of 4 bits.</li>\n<li>An 8-bit binary number splits into exactly <strong>two nibbles</strong>, and each nibble converts to <strong>one</strong> hex digit.</li>\n</ul>\n<h4>Binary → hex</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>Split 11010110 into two 4-bit nibbles.</td><td>1101 | 0110</td></tr>\n<tr><td>2</td><td>Convert each nibble to denary, then to a hex digit (8+4+1=13→D; 4+2=6→6).</td><td>D, 6</td></tr>\n<tr><td>3</td><td>Write the two hex digits together.</td><td>D6</td></tr>\n</table>\n<h4>Hex → binary</h4>\n<ul>\n<li>Reverse it: convert each hex digit into its own 4-bit nibble, then join the two nibbles together to make the full byte.</li>\n<li>Example: hex <strong>9F</strong> → 9 = 1001, F = 1111 → joined = <strong>10011111</strong>.</li>\n</ul>", "check": {"question": "What is the 8-bit binary equivalent of hexadecimal C4?", "options": ["11000100", "11000010", "10000100", "11010100"], "answer": 0, "explain": "C = 1100, 4 = 0100 — joined together that''s 11000100."}}, {"title": "What effect do logical binary shifts have?", "html": "<h4>What is a logical shift?</h4>\n<ul>\n<li>A <strong>logical shift</strong> moves every bit in a binary number a set number of places to the <strong>left</strong> or <strong>right</strong>. Whatever gap is left behind is always filled with <strong>0</strong>s.</li>\n<li>A <strong>left shift</strong> by n places has the mathematical effect of <strong>multiplying</strong> the original value by 2ⁿ.</li>\n<li>A <strong>right shift</strong> by n places has the effect of <strong>dividing</strong> the original value by 2ⁿ (any remainder is simply lost, since binary can''t show a fraction this way).</li>\n</ul>\n<pre class=\"code-block\">00001011  (11)  shift LEFT 2 places\n00101100  (44)  → 11 × 2² = 11 × 4 = 44</pre>\n<h4>Bits shifted off the end are lost</h4>\n<ul>\n<li>Whatever bit gets pushed off the left-hand or right-hand end of the register is <strong>discarded completely</strong> — it does NOT wrap around to the other side (that''s a different operation, called a rotate, which isn''t on this specification).</li>\n<li>If a shifted-off bit was a <strong>1</strong>, the ×2ⁿ / ÷2ⁿ rule stops giving the true mathematical answer, because real information has been thrown away — this can produce <strong>inaccurate results or overflow-like data loss</strong>.</li>\n</ul>\n<pre class=\"code-block\">11100000  (224)  shift LEFT 2 places\n10000000  (128)  ← the two leading 1s are lost, so this is NOT 224 × 4 (896)</pre>", "check": {"question": "An 8-bit binary number is shifted 1 place right using a logical shift. What fills the empty bit position that is created?", "options": ["A 0", "A 1", "Whatever bit was shifted off the opposite end", "Nothing — no gap is created by a logical shift"], "answer": 0, "explain": "Logical shifts always fill the vacated position with a 0 — the bit shifted off the far end is simply lost, not wrapped around."}}, {"title": "Why do computer scientists use hexadecimal at all?", "html": "<h4>Hexadecimal is a shorthand for binary, nothing more</h4>\n<ul>\n<li>Computers still store and process everything in pure <strong>binary</strong> — hexadecimal is never actually stored inside the hardware. It exists purely so that <strong>humans</strong> find binary values easier to work with on paper or on screen.</li>\n<li>Because 4 bits map exactly onto 1 hex digit, a full byte that would need <strong>8 binary digits</strong> to write out can instead be written using just <strong>2 hexadecimal digits</strong> — a much more compact shorthand.</li>\n</ul>\n<h4>Where this actually matters</h4>\n<ul>\n<li>Long strings of 0s and 1s are very easy to <strong>miscount or mistype</strong> by hand. Hex shortens the string, so there is far less to transcribe — and far less room for error.</li>\n<li>Hex shows up constantly in real computing: <strong>memory addresses</strong>, <strong>MAC addresses</strong>, and <strong>colour codes</strong> in web design (e.g. #FF00FF) are all just binary values written in a form that''s quicker for a person to read and communicate.</li>\n</ul>", "check": {"question": "What is the main reason hexadecimal is used instead of binary when a person reads or writes a value by hand?", "options": ["It gives a shorter, compact way to represent the same binary value, cutting down on transcription errors", "Hexadecimal numbers use noticeably less electricity for a processor to calculate with", "The computer''s memory physically stores and processes every byte as 2 hexadecimal digits, never as 8 individual binary bits", "Hexadecimal is simply an older number system that predates binary in computing history"], "answer": 0, "explain": "Hex is purely a human-readable shorthand for binary — 2 hex digits instead of 8 bits — making values easier and safer to read, write and copy by hand. The hardware itself still only ever stores binary."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Bit", "definition": "A single 0 or 1 — the smallest unit of binary data"}, {"term": "Nibble", "definition": "4 bits — maps exactly onto one hexadecimal digit (0-F)"}, {"term": "Byte", "definition": "8 bits — can always be written as exactly 2 hex digits"}, {"term": "MSB (most significant bit)", "definition": "The left-most bit of a binary number — carries the largest place value"}, {"term": "LSB (least significant bit)", "definition": "The right-most bit of a binary number — carries the smallest place value (1)"}, {"term": "8-bit place value ladder", "definition": "128, 64, 32, 16, 8, 4, 2, 1 — left to right"}, {"term": "Padding", "definition": "Adding leading zeros so a binary number fills the full number of bits required"}, {"term": "Range of an 8-bit unsigned number", "definition": "0 to 255 (256 possible values in total)"}, {"term": "Carry (binary addition)", "definition": "The extra 1 passed into the next column left when a column totals 2 or more"}, {"term": "Overflow", "definition": "An error where a calculation''s true result needs more bits than the register has available"}, {"term": "Hexadecimal", "definition": "A base-16 number system using digits 0-9 and letters A-F (values 10-15)"}, {"term": "Range of a 2-digit hex number", "definition": "00 to FF, equivalent to denary 0-255"}, {"term": "Denary → hex method", "definition": "Divide by 16 — the whole-number answer is the first digit, the remainder is the second"}, {"term": "Binary → hex method", "definition": "Split into two 4-bit nibbles and convert each nibble to its own hex digit"}, {"term": "Logical shift", "definition": "Moves every bit left or right by a set number of places, filling the gap with 0s"}, {"term": "Effect of a logical left shift", "definition": "Multiplies the original value by 2 for every place shifted"}, {"term": "Effect of a logical right shift", "definition": "Divides the original value by 2 for every place shifted; any remainder is lost"}, {"term": "Why hexadecimal is used", "definition": "It''s a compact, human-readable shorthand for binary — the hardware itself still only stores binary"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is the largest denary value that can be stored using 8 bits?", "options": ["255", "256", "128", "199"], "answer": 0, "explain": "8 bits give 2⁸ = 256 different values counted from 0, so the largest is 255."}, {"question": "What is the 8-bit binary number 01101011 in denary?", "options": ["107", "111", "103", "123"], "answer": 0, "explain": "The 1s sit in place values 64, 32, 8, 2 and 1: 64+32+8+2+1 = 107."}, {"question": "What is denary 137 written as an 8-bit binary number?", "options": ["10001001", "10010001", "10001010", "01001001"], "answer": 0, "explain": "137 = 128 + 8 + 1, so a 1 goes in the 128, 8 and 1 columns only: 10001001."}, {"question": "A register needs to store the denary value 9. Which 8-bit binary number correctly represents this, with leading zeros added?", "options": ["00001001", "00000101", "00010001", "10000001"], "answer": 0, "explain": "9 = 8 + 1, giving binary 1001 — padded out to a full 8 digits, that''s 00001001."}, {"question": "Which term describes the LEFT-most bit of an 8-bit binary number, the one carrying the largest place value?", "options": ["Most significant bit (MSB)", "Least significant bit (LSB)", "Overflow bit", "Carry bit"], "answer": 0, "explain": "The left-most bit carries the biggest place value (128) and is called the most significant bit; the right-most bit (value 1) is the least significant bit."}, {"question": "What is hexadecimal 3C in denary?", "options": ["60", "48", "54", "63"], "answer": 0, "explain": "(3 × 16) + 12 = 48 + 12 = 60."}, {"question": "What is denary 58 written as a 2-digit hexadecimal number?", "options": ["3A", "2E", "4A", "3F"], "answer": 0, "explain": "58 ÷ 16 = 3 remainder 10. 3 stays as 3, and 10 becomes A, giving 3A."}, {"question": "What is binary 11110000 written as a 2-digit hexadecimal number?", "options": ["F0", "0F", "FF", "E0"], "answer": 0, "explain": "Split into nibbles: 1111 = F, 0000 = 0, giving F0."}, {"question": "What is hexadecimal B2 written as an 8-bit binary number?", "options": ["10110010", "10100010", "11010010", "10110100"], "answer": 0, "explain": "B = 1011, 2 = 0010 — joined together that''s 10110010."}, {"question": "The 8-bit register values 210 and 90 are added together. What is the correct term for the error that occurs, since 210 + 90 exceeds 255?", "options": ["Overflow", "Underflow", "Rounding error", "Register mismatch"], "answer": 0, "explain": "210 + 90 = 300, which needs 9 bits to store correctly — an 8-bit register can''t hold it, so an overflow error occurs."}, {"question": "A value in an 8-bit register undergoes a logical LEFT shift of 3 places, and no 1-bits are lost off the end. What is the effect on the stored value?", "options": ["It is multiplied by 8", "It is divided by 8", "It is multiplied by 3", "It stays exactly the same value"], "answer": 0, "explain": "Each place shifted left doubles the value, so shifting left 3 places multiplies it by 2³ = 8 (as long as no significant bits are lost off the end)."}, {"question": "A logical RIGHT shift of 2 places is performed on an 8-bit value, and the two right-most bits shifted off are both 1s. What happens to those two bits?", "options": ["They are permanently lost, so the result is no longer an exact ÷4 of the value", "They move around and reappear as the new left-most bits at the opposite end of the register", "They are stored separately by the CPU so no data is actually lost", "They cause the shift operation to fail and return an error message"], "answer": 0, "explain": "A logical shift simply discards any bit pushed off the end — it does not wrap around. If those lost bits were 1s, the result is no longer an exact division by 4."}]}, "fib": {"enabled": true, "questions": [{"text": "In an 8-bit binary number, the left-most bit is called the [MSB], and the right-most bit is called the [LSB]."}, {"text": "Hexadecimal is a base-16 number system, so it uses [16] different digits in total: 0-9 and then A-F."}, {"text": "Each hexadecimal digit represents exactly one [nibble], a group of 4 bits."}, {"text": "An overflow error happens when the true result of a binary addition needs [more] than 8 bits to be stored correctly."}, {"text": "A logical shift LEFT by one place has the effect of [multiplying] the original value by 2."}, {"text": "A logical shift RIGHT by one place has the effect of [dividing] the original value by 2."}, {"text": "Bits that are pushed off the end of a register during a logical shift are simply [lost], not moved to the other end."}, {"text": "Hexadecimal is mainly used because it gives a [compact] way of writing binary values that is easier for humans to read and copy."}]}, "tf": {"enabled": true, "questions": [{"statement": "The largest denary value that can be stored using 8 bits is 255.", "answer": true, "explain": "Correct — 8 bits give 2⁸ = 256 possible values, counted from 0, so the highest is 255."}, {"statement": "Hexadecimal digits run from 0-9 and then continue upward as G, H, I, J, K and L.", "answer": false, "explain": "Hexadecimal only needs 16 digits in total: 0-9, then the letters A-F (representing 10-15). There is no G digit in hexadecimal."}, {"statement": "The most significant bit (MSB) of an 8-bit binary number is the right-most bit.", "answer": false, "explain": "The opposite is true — the MSB is the LEFT-most bit, carrying the largest place value (128). The right-most bit (value 1) is the least significant bit (LSB)."}, {"statement": "A logical left shift by 3 places multiplies the original value by 8, provided no significant bits are lost.", "answer": true, "explain": "Correct — each place shifted left doubles the value, so 3 places gives 2³ = 8 times the original value."}, {"statement": "When a bit is shifted off the end of a register during a logical shift, it wraps around and reappears at the opposite end.", "answer": false, "explain": "A logical shift simply discards the bit that is pushed off the end — it is lost completely. Wrapping a bit to the other side is a different operation (a rotate), not a logical shift."}, {"statement": "Overflow can occur when adding two 8-bit binary numbers if their true denary sum is greater than 255.", "answer": true, "explain": "Correct — an 8-bit register can only store values from 0 to 255, so any true sum above 255 needs a 9th bit, which causes overflow."}, {"statement": "Every possible byte (8 bits) can always be represented using exactly 2 hexadecimal digits.", "answer": true, "explain": "Correct — a byte splits into exactly two 4-bit nibbles, and each nibble maps onto exactly one hexadecimal digit (0-F)."}, {"statement": "Hexadecimal is used because computers internally store and process data as hexadecimal digits rather than binary.", "answer": false, "explain": "Computer hardware always stores and processes data in pure binary. Hexadecimal is purely a shorthand that humans use when reading or writing binary values — it is never actually stored that way inside the machine."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking hexadecimal digits carry on past 9 as two-character numbers like ''10'', ''11'', ''12''.", "truth": "Hexadecimal only has <strong>16</strong> single-character digits in total. After 9 it switches to letters: <strong>A</strong> (10) through to <strong>F</strong> (15) — never a two-digit number like ''10'' in a single hex position.", "check": {"question": "What single hexadecimal digit represents the denary value 13?", "options": ["D", "C", "E", "B"], "answer": 0, "explain": "A=10, B=11, C=12, D=13, E=14, F=15 — so 13 is represented by the digit D."}}, {"myth": "Believing the MSB (most significant bit) is the right-most bit of a binary number, since it ''looks'' like the last one written.", "truth": "The MSB is actually the <strong>left-most</strong> bit — it carries the largest place value (128 in an 8-bit number). The right-most bit, carrying the smallest place value (1), is the LSB.", "check": {"question": "Which place value does the most significant bit (MSB) of an 8-bit number carry?", "options": ["128", "256", "64", "16"], "answer": 0, "explain": "The MSB is the left-most bit, which always carries the largest place value in the number — 128 in an 8-bit binary number."}}, {"myth": "Assuming a bit that gets shifted off the end of a register during a logical shift wraps around to reappear at the other end.", "truth": "A logical shift simply <strong>discards</strong> any bit pushed off the end — it is gone completely. Making a bit reappear at the other side is a different operation entirely (a rotate), not a logical shift.", "check": {"question": "During a logical shift, what happens to a bit that is pushed off the end of the register?", "options": ["It is discarded completely and cannot be recovered", "It reappears at the opposite end of the register", "It is stored temporarily in a separate carry bit", "It causes the whole shift operation to be cancelled"], "answer": 0, "explain": "A logical shift throws away any bit pushed off the end — nothing is kept or wrapped around."}}, {"myth": "Assuming an overflow error will automatically show up as an obvious error message as soon as it happens.", "truth": "Overflow usually happens <strong>silently</strong> — the register simply stores the wrong, truncated value instead of the true result. Unless a program is specifically written to check for overflow, nothing will visibly alert you that anything went wrong.", "check": {"question": "What normally happens when an 8-bit addition overflows, if the program does not check for it?", "options": ["The register silently stores an incorrect, truncated value with no visible warning", "The computer automatically displays an on-screen overflow error message and halts the program", "The addition is cancelled and no result is stored anywhere at all", "The two 8-bit registers are automatically merged into one 16-bit register"], "answer": 0, "explain": "Without a specific check written into the program, an overflow simply produces a wrong stored value — there''s no automatic warning."}}, {"myth": "Believing hexadecimal makes a computer''s calculations run faster, or that data is actually stored as hex inside the processor.", "truth": "Hardware always stores and calculates using pure <strong>binary</strong> — hexadecimal never physically exists inside the machine. It is only ever used as a shorthand for humans reading or writing binary values on paper or on screen.", "check": {"question": "Why doesn''t using hexadecimal make a computer''s own calculations run any faster?", "options": ["Because the hardware only ever stores and processes data in binary, never hexadecimal", "Because hexadecimal numbers are actually larger in size than equivalent binary numbers", "Because most modern processors do not support hexadecimal arithmetic at all", "Because converting to hexadecimal always introduces small rounding errors"], "answer": 0, "explain": "Hexadecimal is purely a human-readable shorthand — the hardware itself always stores and works with binary, so hex cannot change how fast it calculates."}}, {"myth": "Applying the ×2ⁿ / ÷2ⁿ shift rule automatically, without checking whether any significant (1) bits were actually shifted off the end.", "truth": "The ×2ⁿ / ÷2ⁿ rule only gives the TRUE result when no 1-bits are lost off the end. If a 1-bit IS shifted off — especially during a left shift of a large value — the stored result no longer matches what ×2ⁿ would predict, because real information has been thrown away.", "check": {"question": "When does the ''left shift = multiply by 2ⁿ'' rule stop giving the mathematically correct answer?", "options": ["When a 1-bit is shifted off the left-hand end of the register and lost", "Whenever the shift is performed by more than one binary place at a single time", "Whenever the original value happens to be an even number", "It always gives the correct answer, with no exceptions at all"], "answer": 0, "explain": "If a 1-bit is pushed off the end during the shift, that information is lost — the stored result is then smaller than the true ×2ⁿ value would be."}}]}, "tips": {"enabled": true, "items": [{"title": "Show-your-working ladder: the 2-mark conversion question", "html": "<p>A typical question: <em>\"Convert denary 91 to a 2-digit hexadecimal number. Show your working.\"</em> [2 marks] Here is the same answer at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"5B\"</p>\n<ul>\n<li>No working shown. Even a correct final answer with nothing behind it risks losing the working mark entirely if a small mistake creeps in.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"91 ÷ 16 = 5 remainder 11\"</p>\n<ul>\n<li>Valid working is shown (1 mark) but the digits were never actually converted into the final hex answer and stated — the second mark is for the CONVERTED final answer.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"91 ÷ 16 = 5 remainder 11 <strong>(1)</strong>. 5 stays as 5, 11 becomes B, so the answer is 5B <strong>(1)</strong>.\"</p>\n\n<p><strong>Why this matters even if your arithmetic slips:</strong> marking splits the WORKING and the ANSWER into separate marks. If your division is correct but you mislabel a remainder as the wrong letter, you keep the working mark — but only if you actually wrote the working down.</p>", "check": {"question": "You correctly work out 91 ÷ 16 = 5 remainder 11, but then wrongly write the final answer as ''511'' instead of ''5B''. What mark do you get out of 2?", "options": ["0, because the final answer written down is wrong", "1 — the working mark for the correct division step", "2, because the working clearly shows the right method throughout", "It depends entirely on whether a calculator was used"], "answer": 1, "explain": "The division step (91 ÷ 16 = 5 remainder 11) is valid working, so it earns the working mark even though the final answer was never correctly converted into hex — so the answer mark is lost."}}, {"title": "Binary addition & overflow: the checklist to work through", "html": "<p>Whenever a question asks you to add two 8-bit binary numbers, work through this checklist before you write your final answer:</p>\n<ul>\n<li><strong>1. Add column by column from the RIGHT.</strong> Show every carry — even a 0+0 column is worth writing out, to prove you worked through it methodically.</li>\n<li><strong>2. Check the left-most (128) column for a leftover carry.</strong> If there''s a carry left over once you''ve finished that column, that''s your signal overflow has occurred.</li>\n<li><strong>3. State your answer as a full 8 digits</strong> (or 9, if you''re specifically asked to show the overflow bit) — never drop leading zeros.</li>\n<li><strong>4. If asked to explain overflow</strong>, don''t just say \"the numbers were too big\" — say WHY: the true result needs more than 8 bits, and an 8-bit register has nowhere to put that extra bit.</li>\n</ul>\n<p><strong>Common way to lose marks:</strong> getting every carry right, but then writing \"300\" or another denary figure as the final answer instead of the required binary string — always re-read what format the question actually wants.</p>", "check": {"question": "You correctly add two 8-bit binary numbers and get every carry right, but then write your final answer in denary instead of binary. What is the most likely outcome?", "options": ["You lose the answer mark, because the question specifically asked for a binary result", "You are automatically awarded both marks anyway, since your arithmetic was entirely correct", "You lose all marks, including the working mark, because the format is wrong", "You gain an extra mark for showing you can convert between formats"], "answer": 0, "explain": "Working is credited separately from the final answer — but the answer still has to be given in the format the question asked for, so writing denary instead of binary loses the answer mark."}}, {"title": "Binary shift questions: perform AND state, every time", "html": "<p>Shift questions almost always ask for TWO things, and it''s easy to only give one of them.</p>\n\n<p><strong>❌ Partial answer:</strong> \"01011100\"</p>\n<ul>\n<li>A correct shifted binary result is given, but the question also asked you to STATE the mathematical effect (e.g. \"multiplies by 4\"), which is missing entirely.</li>\n</ul>\n\n<p><strong>⚠️ The other half missing:</strong> \"Multiplies the value by 4\"</p>\n<ul>\n<li>States the effect correctly, but never actually performs the shift and writes the resulting binary number.</li>\n</ul>\n\n<p><strong>✅ Full answer:</strong> \"00010111 shifted left 2 places = 01011100. This multiplies the original value by 2² = 4.\"</p>\n\n<p><strong>Watch for bit loss:</strong> if any 1-bit gets pushed off the end during the shift, add a sentence noting this — e.g. \"the left-most 1 is lost during this shift, so the result is no longer an exact ×4 of the original value.\" That observation is specifically credited.</p>", "check": {"question": "A question asks you to perform a logical right shift AND state its effect, worth 2 marks. You correctly write the new 8-bit binary number but don''t mention the ÷2/÷4 effect at all. What mark do you most likely get?", "options": ["1 out of 2 — the shift itself is correct but the effect was never stated", "2 out of 2, since performing the shift correctly implies you understood the effect", "0 out of 2, because both parts of a two-part question must be attempted together", "It depends entirely on how neatly the binary digits were written"], "answer": 0, "explain": "The two parts are marked separately — a correct shifted value earns its own mark even if the effect statement is missing, but the effect mark itself is lost."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>One of the microcontroller''s registers needs to store the denary value 45.</p><p>Convert denary 45 into an 8-bit binary number, padding with leading zeros if needed. Show your working.</p>", "marks": 2, "hint": "Work down the place-value ladder (128, 64, 32, 16, 8, 4, 2, 1), writing a 1 wherever a place value fits into 45 and subtracting it, then 0 everywhere else. Pad your final answer out to a full 8 digits.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working, e.g. 45 = 32 + 8 + 4 + 1</li>\n<li>1 mark for the answer: 00101101</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any correct method that clearly shows which place values were used.</li>\n<li>The answer must be given as a full 8 digits, including leading zeros — 101101 alone would not score the answer mark.</li>\n</ul>\n</div>"}, {"question": "<p>Another register currently holds the 8-bit binary value 10011101.</p><p>Convert this binary value into denary. Show your working.</p>", "marks": 2, "hint": "Write out the place value above each bit (128, 64, 32, 16, 8, 4, 2, 1) and add together only the place values where there''s a 1.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working, e.g. 128+16+8+4+1</li>\n<li>1 mark for the answer: 157</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award the working mark even if the final total is wrong, provided the method (adding place values where the bit is 1) is valid.</li>\n</ul>\n</div>"}, {"question": "<p>One of the colours the designer wants to use has denary value 183 (out of 0-255) for its red component.</p><p>Convert denary 183 into a 2-digit hexadecimal number. Show your working.</p>", "marks": 2, "hint": "Divide 183 by 16. The whole-number part of the answer is the first hex digit; the remainder is the second hex digit (convert to a letter if it''s 10 or higher).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working, e.g. 183 ÷ 16 = 11 remainder 7</li>\n<li>1 mark for the answer: B7</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept the letter B written as an 11, provided the final 2-character hex answer is also given correctly.</li>\n</ul>\n</div>"}, {"question": "<p>The designer types the hexadecimal code 4C into the colour picker for the blue component.</p><p>Convert hexadecimal 4C into denary. Show your working.</p>", "marks": 2, "hint": "Multiply the value of the FIRST hex digit by 16, then add the value of the SECOND hex digit.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working, e.g. (4 × 16) + 12</li>\n<li>1 mark for the answer: 76</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award the working mark even if the final total is wrong, provided the method (first digit × 16, plus second digit) is valid.</li>\n</ul>\n</div>"}, {"question": "<p>A calculation leaves the binary value 01111010 stored in a register.</p><p>Convert this 8-bit binary number into a 2-digit hexadecimal number by splitting it into nibbles. Show your working.</p>", "marks": 2, "hint": "Split the 8 bits into two 4-bit nibbles first, then convert EACH nibble separately into its own single hex digit.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working: 0111 = 7, 1010 = A</li>\n<li>1 mark for the answer: 7A</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not award the answer mark if the nibbles are converted in the wrong order (e.g. A7 instead of 7A).</li>\n</ul>\n</div>"}, {"question": "<p>The designer types the hexadecimal code E3 into the colour picker for the green component.</p><p>Convert hexadecimal E3 into an 8-bit binary number using nibbles. Show your working.</p>", "marks": 2, "hint": "Convert EACH hex digit into its own separate 4-bit nibble, then join the two nibbles together to make the full 8-bit answer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working: E = 1110, 3 = 0011</li>\n<li>1 mark for the answer: 11100011</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not award the answer mark if the nibbles are joined in the wrong order.</li>\n</ul>\n</div>"}, {"question": "<p>Complete the table by converting each given value into the two missing representations.</p>", "marks": 4, "hint": "Convert one row at a time. Use the place-value ladder for binary, and split into nibbles for hex.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark each)</h5>\n<ul>\n<li>Row 1 (91): binary 01011011, hex 5B</li>\n<li>Row 2 (11000110): denary 198, hex C6</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each cell is marked independently.</li>\n<li>Accept binary answers with or without leading-zero padding shown, provided the value is correct.</li>\n</ul>\n</div>"}, {"question": "<p>Add these two 8-bit binary numbers using binary addition. Show your working out.</p><pre>  01001101\n+ 00100011</pre>", "marks": 2, "hint": "Add column by column from the right, carrying a 1 into the next column whenever a column totals 2 or more.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for correct working (carries shown correctly).</li>\n<li>1 mark for the answer 01110000.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not award the working mark for converting each number to denary and adding them together instead of adding in binary.</li>\n<li>Carries must be on the correct columns but may be shown above, below or to the side of the sum.</li>\n</ul>\n</div>"}, {"question": "<p>Two 8-bit registers hold the values 200 and 100. Add these two 8-bit binary numbers together, showing your working out. If the true result needs a 9th bit, write it in the left-most box provided and indicate that overflow has occurred.</p><pre>  11001000\n+ 01100100</pre>", "marks": 3, "hint": "Add column by column from the right. Once you reach the left-most (128) column, check whether there''s a carry left over — if there is, that extra bit goes in the 9th box and overflow has occurred.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark for correct working (carries shown correctly).</li>\n<li>1 mark for the answer 100101100 (9 digits, including the overflow bit).</li>\n<li>1 mark for correctly identifying that overflow HAS occurred.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>200 + 100 = 300, which needs 9 bits to store correctly — the true sum will not fit in a single 8-bit register.</li>\n<li>Do not award the working mark for converting each number to denary and adding them together instead of adding in binary.</li>\n</ul>\n</div>"}, {"question": "<p>Using your answer to the previous question, explain why an overflow error has occurred when adding these two register values (200 and 100) together.</p>", "marks": 2, "hint": "Think about the maximum value an 8-bit register can actually hold, and where the extra bit from the addition has to go.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>The true result of the addition, 300, is greater than 255 — the largest denary value an 8-bit register can store</li>\n<li>The addition produces a carry out of the left-most (128) column / needs a 9th bit, and the 8-bit register has nowhere to store it</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept either point made in the student''s own words, provided it correctly links the register''s 8-bit limit to the size of the true result.</li>\n</ul>\n</div>"}, {"question": "<p>A register holds the 8-bit binary value 00010110.</p><p>Perform a logical left shift of 1 place on this value, and state the mathematical effect this shift has on the original value.</p>", "marks": 2, "hint": "Shift every bit one place to the left, filling the new right-hand gap with a 0. Then state what a shift of 1 place to the left always does to a value mathematically.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for the shifted value: 00101100</li>\n<li>1 mark for stating the effect: multiplies the original value by 2</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept \"×2\" or \"doubles the value\" as equivalent to \"multiplies by 2\".</li>\n</ul>\n</div>"}, {"question": "<p>A register holds the 8-bit binary value 11010011.</p><p>Perform a logical right shift of 3 places on this value, state the mathematical effect this type of shift has, and explain what happens to the bits that are shifted off the end.</p>", "marks": 3, "hint": "Shift every bit three places to the right, filling the new left-hand gaps with 0s — the three right-most bits are pushed off the end. State the ÷2ⁿ effect, then explain what becomes of those lost bits.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark for the shifted value: 00011010</li>\n<li>1 mark for stating the effect: divides the original value by 8 (2³)</li>\n<li>1 mark for explaining that the bits shifted off the end (011) are lost/discarded and cannot be recovered, so the exact remainder of the division is not represented</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept \"÷8\" as equivalent to \"divides by 8\".</li>\n<li>The final mark requires the idea that the lost bits represent information that cannot be recovered, not simply that \"some bits changed\".</li>\n</ul>\n</div>"}, {"question": "<p>Which of these is the main reason hexadecimal is used when writing down binary values by hand?</p>", "marks": 1, "hint": "Think about who hexadecimal shorthand is actually FOR — the hardware, or the person reading and writing the value.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>It gives a much shorter way to write the same value, cutting down transcription errors</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores. The other three options wrongly suggest hex changes how the hardware itself works — it is purely a human-facing shorthand for binary.</li>\n</ul>\n</div>"}, {"question": "<p>Which of these is NOT a valid hexadecimal digit?</p>", "marks": 1, "hint": "Hexadecimal only ever uses 16 digits in total: 0-9, then the letters A through F.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>G</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores. Hexadecimal digits run from 0-9 and then A-F only; G is not a valid hexadecimal digit.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', '{"learn": {"enabled": true, "items": [{"title": "What is a character set, and why does every character need a unique code?", "html": "<h4>Every character needs its own binary code</h4>\n<ul>\n<li>Just like numbers, every <strong>character</strong> a computer can store or display — a letter, a digit, a punctuation mark, even a space — has to be represented using <strong>binary digits (bits)</strong>, because that is the only form of data computer hardware can physically store.</li>\n<li>A <strong>character set</strong> is the collection of characters a computer system can represent. Every character in that set is given its own <strong>unique binary code</strong> — no two characters in the same set share the same code, or the computer would not be able to tell them apart.</li>\n<li>When a computer stores text, it isn''t storing the letters themselves — it is storing a sequence of these binary codes, one per character, and looking each one up in the character set whenever it needs to display or process the text.</li>\n</ul>\n<h4>Encoding and decoding</h4>\n<ul>\n<li><strong>Encoding</strong> is converting a character into its binary code, using the character set as a lookup.</li>\n<li><strong>Decoding</strong> is the reverse: converting a binary code back into the character it represents.</li>\n<li>Both directions rely on every device involved using the <strong>same character set</strong>. If a file is encoded with one character set but decoded using a different one, the wrong characters (often strange symbols) can appear on screen.</li>\n</ul>", "check": {"question": "What is a character set?", "options": ["A single binary code value that is shared identically between every character a particular display device is able to show", "The collection of characters a computer can represent, where each character has its own unique binary code", "A complete list of every symbol that physically appears on a standard computer keyboard", "The maximum number of characters that are allowed to fit inside one text file"], "answer": 1, "explain": "A character set is the collection of characters a system can represent, with every character given its own unique binary code so the computer can tell them apart."}}, {"title": "How many characters can n bits represent — and how few bits do you need?", "html": "<h4>The 2ⁿ rule</h4>\n<ul>\n<li>If a character set uses <strong>n bits</strong> for every character''s code, the number of <strong>different characters</strong> it can represent is <strong>2 to the power of n (2ⁿ)</strong> — because each of the n bits can independently be 0 or 1.</li>\n<li>This is the same 2ⁿ rule used elsewhere on this course for counting how many different values a binary pattern can represent. It is not a special rule invented just for characters.</li>\n</ul>\n<table>\n<tr><th>Bits (n)</th><th>Characters (2ⁿ)</th></tr>\n<tr><td>1</td><td>2</td></tr>\n<tr><td>2</td><td>4</td></tr>\n<tr><td>3</td><td>8</td></tr>\n<tr><td>4</td><td>16</td></tr>\n<tr><td>5</td><td>32</td></tr>\n<tr><td>6</td><td>64</td></tr>\n<tr><td>7</td><td>128</td></tr>\n<tr><td>8</td><td>256</td></tr>\n</table>\n<h4>Working backwards: how many bits do you need?</h4>\n<ul>\n<li>Exam questions often flip the question around: <em>\"a system needs to represent 50 different characters — what is the minimum number of bits per character?\"</em></li>\n<li>The method: try increasing values of n in 2ⁿ until the result is <strong>greater than or equal to</strong> the number of characters needed. The FIRST n that works is the minimum.</li>\n</ul>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>A system needs 50 characters. Try n = 5: work out 2⁵.</td><td>32 — too small (32 &lt; 50)</td></tr>\n<tr><td>2</td><td>Try n = 6: work out 2⁶.</td><td>64 — big enough (64 ≥ 50)</td></tr>\n<tr><td>3</td><td>State the minimum n that works.</td><td>6 bits</td></tr>\n</table>", "check": {"question": "What is the minimum number of bits needed to represent 200 different characters?", "options": ["7 bits, since 2 to the power of 7 (128) is reasonably close to the target of 200 characters needed", "8 bits, since 2 to the power of 7 (128) is too small but 2 to the power of 8 (256) is enough", "200 bits, using exactly one separate bit for every character that is needed", "100 bits, using exactly half as many bits as the number of characters needed"], "answer": 1, "explain": "2^7 = 128 is too small (128 < 200). 2^8 = 256 is big enough (256 ≥ 200). So the minimum is 8 bits."}}, {"title": "ASCII: the standard 7-bit character set", "html": "<h4>What ASCII is</h4>\n<ul>\n<li><strong>ASCII</strong> (American Standard Code for Information Interchange) is a standard <strong>7-bit</strong> character set. Using the 2ⁿ rule, 7 bits can represent 2⁷ = <strong>128 different characters</strong>.</li>\n<li>Those 128 characters include the <strong>upper- and lower-case English letters</strong>, the <strong>digits 0–9</strong>, common <strong>punctuation marks</strong> (such as . , ! ?), and a set of <strong>control codes</strong> — non-printable codes that control a device rather than display a symbol (for example, codes that mean \"start a new line\" or \"delete the last character\").</li>\n</ul>\n<h4>How ASCII is actually stored</h4>\n<ul>\n<li>Although ASCII itself only needs 7 bits, modern computers store data in whole <strong>bytes (8 bits)</strong>. So an ASCII character is almost always stored using <strong>one byte</strong> per character, with the extra bit either left unused or used for another purpose (such as error-checking).</li>\n<li>This is why exam questions sometimes describe ASCII text as \"8 bits per character\" in a scenario. Always use the number of bits <strong>given in the question</strong> for any calculation, rather than assuming 7 or 8 from memory.</li>\n</ul>\n<h4>What you are NOT expected to know</h4>\n<ul>\n<li>You do not need to <strong>memorise</strong> the exact binary or denary code for any real ASCII character. Exam questions always give you the character set (real or invented) that you need for a particular task.</li>\n</ul>", "check": {"question": "How many characters can the standard 7-bit ASCII character set represent?", "options": ["128 characters, because 2 to the power of 7 equals 128", "256 characters, because one whole byte is made up of 8 bits", "64 characters, because 2 to the power of 6 equals 64", "There is no fixed limit on how many characters ASCII can represent"], "answer": 0, "explain": "ASCII is a 7-bit character set, and 2^7 = 128, so it can represent 128 different characters."}}, {"title": "Worked example: encoding and decoding with an invented code table", "html": "<h4>An invented character set for practice</h4>\n<p>The table below is a small, <strong>made-up</strong> 5-bit character set — the <strong>Sample Code Table (SCT-5)</strong> — invented for practice on this page. It is <strong>not</strong> the real ASCII code.</p>\n<table>\n<tr><th>Character</th><th>Denary</th><th>5-bit code</th></tr>\n<tr><td>A</td><td>0</td><td>00000</td></tr>\n<tr><td>B</td><td>1</td><td>00001</td></tr>\n<tr><td>C</td><td>2</td><td>00010</td></tr>\n<tr><td>D</td><td>3</td><td>00011</td></tr>\n<tr><td>E</td><td>4</td><td>00100</td></tr>\n<tr><td>…</td><td>…</td><td>…</td></tr>\n<tr><td>P</td><td>15</td><td>01111</td></tr>\n<tr><td>(space)</td><td>16</td><td>10000</td></tr>\n</table>\n<p>SCT-5 defines 20 characters in total (A–P, plus a space, full stop, comma and exclamation mark), assigned <strong>sequentially</strong> starting from denary 0. Since 2⁴ = 16 is too small for 20 characters but 2⁵ = 32 is enough, every code needs <strong>5 bits</strong>.</p>\n<h4>Worked example: encoding a word</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>Encode the word \"BE\" using SCT-5. Look up B.</td><td>B = denary 1 = 00001</td></tr>\n<tr><td>2</td><td>Look up E.</td><td>E = denary 4 = 00100</td></tr>\n<tr><td>3</td><td>Write the codes in order.</td><td>00001 00100</td></tr>\n</table>\n<h4>Worked example: decoding a binary string</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>Decode 01100 10000. Convert the first code to denary.</td><td>01100 = 12</td></tr>\n<tr><td>2</td><td>Look up denary 12 in the table.</td><td>12 = M</td></tr>\n<tr><td>3</td><td>Convert and look up the second code.</td><td>10000 = 16 = (space)</td></tr>\n</table>", "check": {"question": "Using SCT-5 (A=00000, B=00001, C=00010, D=00011…), what is the binary code for the character D?", "options": ["00011, since D is the 4th character in the table, denary 3, one place after C", "00010, the code that is actually used for the earlier character C, not the character D", "00100, the code that comes two full places after C in the table, not the character D", "00001, the code that is actually used for the earlier character B, not the character D"], "answer": 0, "explain": "D is the 4th character in SCT-5, denary 3, which is 00011 in 5-bit binary."}}, {"title": "Why character codes are sequential — working out an ''unknown'' character logically", "html": "<h4>Codes are assigned in order</h4>\n<ul>\n<li>In ASCII (and in most character sets, including the invented ones on this page), letters and digits are given <strong>sequential</strong> binary codes — the code for the next letter in the alphabet is exactly <strong>one more</strong> than the code for the letter before it.</li>\n<li>This means that if you are given the code for one character, you can work out the code for a nearby character just by counting how many places along the sequence it is. You do not need to memorise every individual code.</li>\n</ul>\n<h4>Worked example: a fixed offset between upper and lower case</h4>\n<p>Suppose a fictional character code, <strong>Code X</strong>, assigns uppercase <strong>A</strong> the denary code <strong>40</strong>, with every following letter one more than the last (B = 41, C = 42, and so on). Lowercase letters use the <strong>same code as the matching uppercase letter, plus a fixed offset of 50</strong>.</p>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>Find the code for uppercase D. Count how many letters after A it is (3), and add to 40.</td><td>40 + 3 = 43</td></tr>\n<tr><td>2</td><td>Find the code for lowercase d. Add the fixed lowercase offset of 50 to uppercase D''s code.</td><td>43 + 50 = 93</td></tr>\n</table>\n<h4>Why the exam tests this</h4>\n<ul>\n<li>Questions that give you one or two known codes from a set, then ask for a nearby one, are testing whether you understand that the codes are <strong>sequential</strong> and that related pairs (like upper/lower case) sit a <strong>fixed distance</strong> apart — not whether you have memorised any real code table.</li>\n</ul>", "check": {"question": "In a sequential character code, if the letter G has the code 38, what is the most likely code for the letter H (the very next letter)?", "options": ["39, since codes increase by 1 for each next letter", "37, since this mistakenly uses the code that came BEFORE G rather than after it", "76, since this doubles G''s code instead of simply adding one for the next letter", "19, since this halves G''s code instead of simply adding one for the next letter"], "answer": 0, "explain": "Sequential codes increase by exactly 1 for each following letter in the alphabet, so H would be 38 + 1 = 39."}}, {"title": "Unicode: a bigger character set for a multilingual world", "html": "<h4>Why ASCII wasn''t enough</h4>\n<ul>\n<li>ASCII''s 128 characters are enough for basic English text, but nowhere near enough to represent the letters used by <strong>every language in the world</strong> (such as Chinese, Arabic or Greek scripts), or the huge range of <strong>symbols and emoji</strong> used in modern digital communication.</li>\n<li><strong>Unicode</strong> is a much larger character set, designed to solve this problem by using <strong>more bits per character</strong> than ASCII — for example, 16 bits instead of ASCII''s 7. Using the 2ⁿ rule, 16 bits can represent 2¹⁶ = 65,536 different characters, far more than ASCII''s 128.</li>\n</ul>\n<h4>Unicode stays compatible with ASCII</h4>\n<ul>\n<li>Unicode was deliberately designed so that its <strong>first 128 character codes are identical</strong> to ASCII''s 128 codes. This means any text that was valid ASCII is automatically valid Unicode too — older ASCII files do not need to be converted or become unreadable.</li>\n</ul>\n<h4>The storage trade-off</h4>\n<ul>\n<li>Using more bits per character is not free: a Unicode character typically takes up <strong>more storage</strong> than the same character stored in ASCII, because more bits are needed for every single character in the file.</li>\n<li>This means a text file re-encoded from ASCII into Unicode, containing exactly the same characters, will usually become a <strong>larger file</strong>. Representing more possible characters comes at the cost of more bits needed per character.</li>\n</ul>", "check": {"question": "What is the main storage trade-off of using Unicode instead of ASCII?", "options": ["Unicode files are always smaller, because Unicode compresses data automatically as it is stored", "Unicode characters typically use more bits, so the same amount of text becomes a larger file", "Unicode removes the need to store any control codes at all, which saves storage space", "Unicode text can only ever be stored using exactly 8 bits per character"], "answer": 1, "explain": "Unicode characters typically use more bits per character than ASCII, so storing the same text in Unicode usually results in a larger file."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Character set", "definition": "The set of characters a computer can represent, each with a unique binary code"}, {"term": "Bit", "definition": "The smallest unit of data a computer stores, either a 0 or a 1"}, {"term": "n-bit character set", "definition": "A character set where each character''s code is n bits long"}, {"term": "2ⁿ", "definition": "The formula for how many different characters an n-bit code can represent"}, {"term": "Minimum bits needed", "definition": "The smallest n for which 2ⁿ is greater than or equal to the number of characters needed"}, {"term": "ASCII", "definition": "A standard 7-bit character set representing English letters, digits, punctuation and control codes"}, {"term": "128", "definition": "The number of characters the standard ASCII character set can represent"}, {"term": "Control code", "definition": "A non-printable ASCII code used to control a device rather than display a symbol"}, {"term": "Byte storage of ASCII", "definition": "ASCII characters are commonly stored using one byte (8 bits) per character"}, {"term": "Sequential character codes", "definition": "Codes assigned in alphabetical order, so consecutive characters have consecutive binary values"}, {"term": "Unicode", "definition": "A larger character set using more bits per character to represent many more characters and languages"}, {"term": "Unicode compatibility with ASCII", "definition": "Unicode''s first 128 codes are identical to ASCII''s, so ASCII text is valid Unicode text"}, {"term": "Storage trade-off", "definition": "Using more bits per character represents more possible characters but increases file size"}, {"term": "Emoji/multilingual support", "definition": "A key reason Unicode was introduced, since ASCII''s 128 codes cannot cover every language and symbol"}, {"term": "Encoding", "definition": "Converting a character into its binary code using a character set"}, {"term": "Decoding", "definition": "Converting a binary code back into the character it represents using a character set"}, {"term": "Character", "definition": "A single letter, digit, punctuation mark or control code stored as a unique binary code"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of these best defines a ''character set''?", "options": ["A single binary code value that is shared identically between every character a particular display device is able to show", "The set of characters a computer can represent, where each character has its own unique binary code", "A complete list of every symbol that physically appears on a standard computer keyboard", "The maximum number of characters that are allowed to fit inside one text file"], "answer": 1, "explain": "A character set is the set of characters a system can represent, with every character given its own unique binary code."}, {"question": "How many different characters can be represented using 8 bits?", "options": ["256, since 2 to the power of 8 equals 256", "128, since 2 to the power of 7 equals 128", "64, since 2 to the power of 6 equals 64", "512, since 2 to the power of 9 equals 512"], "answer": 0, "explain": "2^8 = 256, so 8 bits can represent 256 different characters."}, {"question": "What is the minimum number of bits needed to represent 100 different characters?", "options": ["7 bits, since 2 to the power of 7 (128) is enough but 2 to the power of 6 (64) is too small", "6 bits, since 100 is fairly close to 2 to the power of 6 (64) and rounds neatly to a whole byte value", "100 bits, using exactly one separate bit for every single character that is needed", "8 bits, chosen simply to match the size of one whole standard byte of memory"], "answer": 0, "explain": "2^6 = 64 is too small (64 < 100). 2^7 = 128 is big enough (128 ≥ 100). So the minimum is 7 bits."}, {"question": "The standard ASCII character set is usually described as using how many bits per character?", "options": ["7 bits, giving 2 to the power of 7 (128) possible characters", "8 bits, exactly matching the size of one whole byte", "16 bits, the same as a common Unicode encoding", "4 bits, exactly half of the eight bits used in one standard byte of memory"], "answer": 0, "explain": "ASCII is a 7-bit character set, giving 2^7 = 128 possible characters."}, {"question": "How many different characters does the standard 7-bit ASCII character set contain?", "options": ["128 characters, since 2 to the power of 7 equals 128", "256 characters, since one whole byte is made up of 8 bits", "64 characters, since 2 to the power of 6 equals 64", "100 characters, a round number chosen for convenience"], "answer": 0, "explain": "2^7 = 128, so the standard ASCII character set contains 128 characters."}, {"question": "ASCII characters are typically stored in modern computer memory using how many bits?", "options": ["8 bits (one byte) per character, even though ASCII itself only needs 7", "7 bits per character, with absolutely no extra bit ever used or reserved for anything else", "16 bits per character, exactly the same as a common Unicode encoding", "4 bits per character, exactly half of one whole byte"], "answer": 0, "explain": "Although ASCII itself only needs 7 bits, computers store data in whole bytes, so ASCII characters are typically stored using 8 bits (one byte) each."}, {"question": "A ticket machine uses a fictional code where letter A = 10, and each following letter increases by 1 (B = 11, C = 12, and so on). What code represents the letter D?", "options": ["13, since D is 3 letters after A in the sequence", "12, the code that is actually used for the letter C", "14, the code that comes two places after C", "10, the code that is actually used for the letter A"], "answer": 0, "explain": "D is 3 letters after A, so its code is 10 + 3 = 13."}, {"question": "A messaging app needs to display text in English, Japanese and Arabic, plus emoji, within the same message. Which character set is better suited to this task?", "options": ["Unicode, because it uses more bits per character and so can represent far more characters", "ASCII, because its 128 characters already cover every language and every emoji currently in use around the world", "Unicode, because it always uses fewer bits per character than ASCII does", "ASCII, because it was specifically designed for use inside messaging apps"], "answer": 0, "explain": "Unicode uses more bits per character than ASCII, allowing it to represent the huge range of characters needed for multiple languages and emoji, which ASCII''s 128 codes cannot cover."}, {"question": "A text file is re-encoded so that every character uses 16 bits instead of 8 bits, with no change to the number of characters. What effect does this have on the file''s size?", "options": ["The file size roughly doubles, since twice as many bits are stored per character", "The file size stays exactly the same, since the number of characters has not changed", "The file size is roughly halved, since Unicode compresses text as it is stored", "The file becomes exactly sixteen times larger than it was before"], "answer": 0, "explain": "Doubling the number of bits used per character (from 8 to 16), with the same number of characters, roughly doubles the total number of bits stored — and so roughly doubles the file size."}, {"question": "Which statement correctly describes the relationship between Unicode and ASCII?", "options": ["Unicode''s first 128 character codes are identical to the 128 codes used by ASCII", "Unicode and ASCII are completely unrelated character sets that share no codes at all", "ASCII is simply a shortened, 64-character version of the full Unicode character set", "Unicode replaced ASCII entirely, so ASCII codes are no longer valid anywhere today"], "answer": 0, "explain": "Unicode was designed so its first 128 codes exactly match ASCII''s 128 codes, keeping existing ASCII text valid within Unicode."}, {"question": "In a sequential character code, character M has the code 01100, and N is the very next character in the set. What binary code represents N?", "options": ["01101, one more than M''s own code of 01100", "01011, one less than M''s own code of 01100", "01110, two more than M''s own code of 01100", "01100, exactly the same code as M itself"], "answer": 0, "explain": "Sequential codes increase by 1 for the next character in the set, and 01100 (12) + 1 = 01101 (13)."}, {"question": "A retro games console can only spare 4 bits to store each character''s code. What is the maximum number of distinct characters it could support?", "options": ["16 characters, since 2 to the power of 4 equals 16", "4 characters, exactly one for each bit that is available", "8 characters, exactly half of the usual byte-sized total", "32 characters, exactly double the usual estimate given"], "answer": 0, "explain": "2^4 = 16, so a 4-bit code can support a maximum of 16 distinct characters."}]}, "fib": {"enabled": true, "questions": [{"text": "A [character set] is the set of characters a computer can represent, where each character has its own unique binary code."}, {"text": "Using 7 bits, a character set can represent up to [128] different characters."}, {"text": "Using 8 bits, a character set can represent up to [256] different characters."}, {"text": "The standard ASCII character set uses [7] bits to represent each character."}, {"text": "ASCII characters are commonly stored in computer memory using one [byte] (8 bits) per character."}, {"text": "Unicode uses more [bits] per character than ASCII, allowing it to represent many more characters."}, {"text": "Unicode''s first 128 character codes are identical to those used by [ASCII]."}, {"text": "Because Unicode characters can use more bits than ASCII characters, text files encoded in Unicode are often [larger] in size than the same text encoded in ASCII."}]}, "tf": {"enabled": true, "questions": [{"statement": "A character set is the collection of characters a computer can represent, each with its own unique binary code.", "answer": true, "explain": "Correct — that is exactly what a character set is."}, {"statement": "Using 5 bits, a computer could represent up to 64 different characters.", "answer": false, "explain": "5 bits gives 2^5 = 32 different characters, not 64. 64 would need 6 bits (2^6 = 64)."}, {"statement": "The standard ASCII character set itself uses 8 bits to represent every character.", "answer": false, "explain": "ASCII itself is a 7-bit character set (128 characters). It is commonly STORED using 8 bits (one byte), but the code itself only needs 7 bits."}, {"statement": "ASCII can represent letters, digits, punctuation marks and control codes.", "answer": true, "explain": "Correct — ASCII''s 128 characters include upper- and lower-case letters, digits 0–9, punctuation marks and non-printable control codes."}, {"statement": "Because character codes are usually assigned sequentially, the code for a letter is always exactly one more than the code for the letter before it in the alphabet.", "answer": true, "explain": "True for sequential character sets like ASCII — consecutive letters have consecutive binary codes."}, {"statement": "Unicode uses fewer bits per character than ASCII, which is why it can represent more characters.", "answer": false, "explain": "The opposite is true: Unicode uses MORE bits per character than ASCII, which is exactly why it can represent far more characters."}, {"statement": "The first 128 character codes in Unicode are identical to the 128 codes in ASCII.", "answer": true, "explain": "Correct — Unicode was deliberately designed this way, so existing ASCII text is automatically valid Unicode text too."}, {"statement": "Storing text using Unicode instead of ASCII can make a text file larger, because Unicode often uses more bits per character.", "answer": true, "explain": "Correct — more bits per character, with the same number of characters, means more bits (and so more storage) are needed overall."}]}, "misc": {"enabled": true, "items": [{"myth": "Believing you need to memorise the exact binary or denary code for every real ASCII character.", "truth": "OCR does <strong>not</strong> expect you to memorise real ASCII codes — exam questions always give you the character set (or the codes) you need, often an invented one. What you must understand instead is the <em>relationship</em> between bits and how many characters they can represent, and how sequential codes let you work out an ''unknown'' character logically.", "check": {"question": "Which of these does the OCR specification actually require you to know for this topic?", "options": ["The exact real ASCII code number for every single character, memorised completely off by heart", "How the number of bits used relates to the number of characters that can be represented", "The precise binary code used for every emoji defined inside Unicode", "The complete Unicode code for every written language used around the world"], "answer": 1, "explain": "You are not expected to memorise real codes — you are expected to understand the relationship between bits and representable characters, and how sequential codes work."}}, {"myth": "Assuming that using more bits per character makes text look better or higher quality, in the same way that a higher colour depth improves an image.", "truth": "Text doesn''t have a ''quality'' scale the way images and sound do. Using <strong>more bits per character</strong> simply means <strong>more different characters can be represented</strong> — a bigger character set covering more languages, symbols and emoji — it does not make any individual character look sharper or clearer on screen.", "check": {"question": "What does using MORE bits per character actually give a character set?", "options": ["Sharper, higher-quality looking text displayed on the screen for the user", "The ability to represent a larger number of different characters", "Noticeably faster processing of each individual character by the CPU", "A smaller file size for storing exactly the same amount of text"], "answer": 1, "explain": "More bits per character means more possible codes, so more different characters can be represented — it has no effect on how ''sharp'' text looks."}}, {"myth": "Thinking ASCII and Unicode are two totally separate, incompatible systems that cannot be mixed together.", "truth": "Unicode was deliberately designed so its <strong>first 128 character codes are identical</strong> to ASCII''s 128 codes. This means any valid ASCII text is automatically valid Unicode text too — Unicode extends ASCII rather than replacing it with something incompatible.", "check": {"question": "How does Unicode relate to the older ASCII character set?", "options": ["They are unrelated systems that were never designed to work together", "Unicode''s first 128 codes are identical to the 128 codes used by ASCII", "Unicode completely replaced ASCII, so ASCII text no longer works anywhere", "ASCII is a newer, improved version of Unicode released after it"], "answer": 1, "explain": "Unicode''s first 128 codes exactly match ASCII''s, which is why existing ASCII text remains valid Unicode text."}}, {"myth": "Believing the 2ⁿ rule for counting representable characters only works for the specific cases of n = 7 or n = 8 bits.", "truth": "2ⁿ is a <strong>general rule</strong> that works for any whole number of bits n — 3 bits give 2³ = 8 characters, 5 bits give 2⁵ = 32, and so on. 7 bits (ASCII) and 8 bits (one byte) are simply the two examples that come up most often, not special cases governed by a different rule.", "check": {"question": "Using the general 2ⁿ rule, how many different characters could a 3-bit character set represent?", "options": ["3 characters, one for every bit that is available", "6 characters, double the number of bits available", "8 characters, since 2 to the power of 3 equals 8", "9 characters, three squared using the number of bits"], "answer": 2, "explain": "2^3 = 8, so a 3-bit character set can represent 8 different characters."}}, {"myth": "When asked for the minimum number of bits needed to represent N characters, using N itself as the number of bits — for example saying ''50 characters needs 50 bits''.", "truth": "You need the <strong>smallest n</strong> for which 2ⁿ is <strong>greater than or equal to</strong> N — not N itself. For 50 characters: 2⁵ = 32 is too small, but 2⁶ = 64 is enough, so the answer is <strong>6 bits</strong>, not 50 bits.", "check": {"question": "What is the minimum number of bits needed to represent 20 different characters?", "options": ["20 bits, using exactly one separate bit for every single character that this needs to store", "4 bits, since 2 to the power of 4 (16) is reasonably close to the number 20", "5 bits, since 2 to the power of 4 (16) is too small but 2 to the power of 5 (32) is enough", "6 bits, simply one more than the previous minimum just to be extra safe"], "answer": 2, "explain": "2^4 = 16 is too small (16 < 20). 2^5 = 32 is enough (32 ≥ 20). So the minimum is 5 bits."}}]}, "tips": {"enabled": true, "items": [{"title": "Show-your-working ladder: the 2-mark ''how many bits'' calculation", "html": "<p>A typical question: <em>\"A system needs to represent 40 different characters. Calculate the minimum number of bits required per character. Show your working.\"</em> [2 marks] Here is the same answer at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"6\"</p>\n<ul>\n<li>No working shown at all. Even a correct final answer with nothing behind it risks losing the working mark entirely if a small slip means the number given is actually wrong.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"2^5 = 32, 2^6 = 64\"</p>\n<ul>\n<li>Valid working is shown, testing the powers of 2 against 40 (1 mark) — but no final answer is actually stated, so the second mark for the answer itself is not awarded.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"2^5 = 32, too small <strong>(1)</strong>. 2^6 = 64, big enough. Minimum = 6 bits <strong>(1)</strong>.\"</p>\n\n<p><strong>Why this matters even if your arithmetic slips:</strong> OCR-style marking splits the WORKING and the ANSWER into separate marks. If your method (testing powers of 2 against the target number) is correct but you make a small slip in one power of 2, you can still keep the working mark — but only if you actually wrote the working down.</p>", "check": {"question": "You correctly show that 2^5 = 32 is too small, but then wrongly calculate 2^6 as 60 instead of 64 and conclude ''minimum = 6 bits''. What mark do you get out of 2?", "options": ["0, because the working used to reach the final answer contained an arithmetic slip", "1, since valid working testing powers of 2 against the target is clearly shown", "2, since the final stated answer of 6 bits happens to still be correct", "It depends entirely on which specific exam paper the question came from"], "answer": 1, "explain": "Testing powers of 2 against the target number is valid working, so it earns the working mark even though one of the calculated values (2^6 = 60) was arithmetically wrong."}}, {"title": "Answering tick-one-box ASCII/Unicode fact questions: eliminate, don''t guess", "html": "<p>Single tick-box questions about ASCII and Unicode facts are worth only 1 mark, but they are rarely a lucky guess — three of the four options are usually wrong for a specific, checkable reason.</p>\n\n<p><strong>The reliable method:</strong> test EVERY option against something you know for certain before you tick anything:</p>\n<ul>\n<li>Does the option confuse the number of BITS with the number of CHARACTERS (e.g. mixing up \"7 bits\" with \"128 characters\")?</li>\n<li>Does the option get the direction of the ASCII/Unicode comparison backwards (saying Unicode uses FEWER bits, when it actually uses more)?</li>\n<li>Does the option claim ASCII and Unicode are unrelated, when Unicode''s first 128 codes are actually identical to ASCII''s?</li>\n</ul>\n\n<p><strong>One tick only.</strong> As with other tick-one-box questions on this course, ticking two or more boxes scores zero, even if one of them is correct — so commit to your single best-evidenced answer rather than hedging between two options.</p>", "check": {"question": "You are fairly confident the answer is option 2, but tick option 4 as well just in case. What mark do you get?", "options": ["1 mark, since option 2 was in fact the option that was correct", "0 marks — ticking two or more boxes always scores zero on these questions", "0.5 marks, awarded automatically for showing genuine uncertainty", "It depends entirely on which of the two ticked options the marker prefers"], "answer": 1, "explain": "Tick-one-box questions award 0 marks the moment two or more boxes are ticked, regardless of whether the correct option is among them."}}, {"title": "Command-word ladder: ''explain'' the ASCII/Unicode storage trade-off", "html": "<p>A typical question: <em>\"Explain why choosing to store text using Unicode instead of ASCII could increase the file size.\"</em> [up to 4 marks] \"Explain\" needs a point AND a development — \"…which means…\" — not just a fact on its own.</p>\n\n<p><strong>❌ 0–1 marks:</strong> \"Unicode uses more bits.\"</p>\n<ul>\n<li>A bare fact with no development. It is TRUE, but it does not explain why the file size increases as a result.</li>\n</ul>\n\n<p><strong>⚠️ 2 marks:</strong> \"Unicode uses more bits per character than ASCII, which means each character takes up more storage.\"</p>\n<ul>\n<li>One point developed with \"…which means…\" — a genuine explanation, but it stops short of a full comparison and a stated consequence for the whole file.</li>\n</ul>\n\n<p><strong>✅ 3–4 marks:</strong> \"Unicode uses more bits per character than ASCII (for example 16 bits instead of 7), which means every single character needs more storage space. Because a text file contains many characters, this extra amount per character adds up across the whole file, which means the total file size becomes larger than the same text stored in ASCII.\"</p>\n\n<p><strong>The pattern:</strong> fact (more bits per character) → development (more storage per character) → consequence (the WHOLE FILE grows, not just one character). Each arrow is worth developing into its own sentence.</p>", "check": {"question": "A student writes only ''Unicode uses more bits, so files are bigger'' for a 4-mark ''explain'' question. Roughly how many marks is this likely to gain?", "options": ["Full marks, since the key fact and its consequence are both technically present", "Only partial marks, since the chain of reasoning is not developed step by step", "Zero marks, since the statement given is factually incorrect", "It cannot be marked at all without a diagram accompanying the answer"], "answer": 1, "explain": "The statement is correct but underdeveloped — a full-marks ''explain'' answer needs each step in the chain (more bits per character → more storage per character → larger overall file) spelled out, not compressed into one bare sentence."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>State what is meant by the term \"character set\".</p>", "marks": 1, "hint": "Your definition should mention both the collection of characters AND that each one has its own code.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>The set/range of characters a computer (system) can represent or recognise, where each character is given its own unique binary code</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any answer that captures BOTH ideas: a defined collection of characters, and each one having a unique code.</li>\n<li>A definition that only says \"a list of letters\", without mentioning binary codes or uniqueness, does not gain the mark.</li>\n</ul>\n</div>"}, {"question": "<p>Calculate the number of different characters that can be represented using 6 bits. Show your working.</p>", "marks": 2, "hint": "Use the rule: n bits can represent 2 to the power of n different characters.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working, e.g. 2^6 or 2×2×2×2×2×2</li>\n<li>1 mark for the answer: 64</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any correct method that reaches 2 to the power of 6.</li>\n<li>Award the working mark even if the final answer is wrong, provided the method shown is valid.</li>\n</ul>\n</div>"}, {"question": "<p>A software company is designing a new fictional character set that must be able to represent 50 different characters. Calculate the minimum number of bits required per character. Show your working.</p>", "marks": 2, "hint": "Try increasing values of n in 2^n until the result is greater than or equal to 50 — the first n that works is your answer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working, e.g. 2^5 = 32 (too small) and 2^6 = 64 (enough)</li>\n<li>1 mark for the answer: 6 (bits)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any correct method that identifies 6 as the smallest n where 2^n ≥ 50.</li>\n<li>An answer of \"50\" or \"64\" instead of \"6\" does not gain the answer mark.</li>\n</ul>\n</div>"}, {"question": "<p>Which of these is the correct number of characters that can be represented by the standard ASCII character set?</p>", "marks": 1, "hint": "ASCII is a 7-bit character set — use the 2^n rule with n = 7.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>128</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores. 2^7 = 128.</li>\n</ul>\n</div>"}, {"question": "<p>State how many bits the standard ASCII character set uses to represent each character, and state how many bits ASCII characters are typically stored using in modern computer memory.</p>", "marks": 2, "hint": "These are two different numbers — one is the size of the ASCII code itself, the other is the size it is usually rounded up to for storage.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: ASCII uses <strong>7 bits</strong> per character</li>\n<li>1 mark: ASCII characters are typically stored using <strong>8 bits (one byte)</strong> per character</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both marks are independent — a candidate can gain either mark separately.</li>\n<li>Accept \"one byte\" as equivalent to \"8 bits\".</li>\n</ul>\n</div>"}, {"question": "<p>Using the Sample Code Table above, complete the table by writing the correct 5-bit binary code for each letter.</p>", "marks": 2, "hint": "Find each letter''s row in the Sample Code Table and copy its 5-bit binary code exactly, including any leading zeros.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark for each row)</h5>\n<ul>\n<li>B = 00001</li>\n<li>E = 00100</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently.</li>\n<li>Leading zeros must be included — \"1\" alone does not gain the mark for B.</li>\n</ul>\n</div>"}, {"question": "<p>Using the Sample Code Table above, decode the binary codes <strong>01111</strong> and <strong>10000</strong> into the two characters they represent. Write the two characters in the order given.</p>", "marks": 2, "hint": "Convert each 5-bit binary code back into a denary number first, then look up which character has that denary code.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: 01111 = P</li>\n<li>1 mark: 10000 = (space)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each code is marked independently.</li>\n<li>Accept \"space\" or a visible blank character for 10000.</li>\n</ul>\n</div>"}, {"question": "<p>Using Code X described above, calculate the code that represents uppercase <strong>E</strong>, then calculate the code that represents lowercase <strong>e</strong>. Explain the rule you used to work out the lowercase code.</p>", "marks": 3, "hint": "Count how many letters after A the target letter is, and add that to 40. Then apply the fixed offset for lowercase letters.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark: E = 44</li>\n<li>1 mark: e = 94</li>\n<li>1 mark: explains that lowercase letters use the same code as the matching uppercase letter, plus a fixed offset of 50</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept correct working shown even if the final number is mislabelled, provided the method is clearly the sequential-plus-offset rule.</li>\n<li>The explanation mark requires the idea of a FIXED offset applied to the matching uppercase code, not just \"lowercase letters have different codes\".</li>\n</ul>\n</div>"}, {"question": "<p>Using the Sample Code Table above, character <strong>B</strong> is 00001 and character <strong>C</strong> is 00010. Which binary code represents character <strong>D</strong>?</p>", "marks": 1, "hint": "D is the very next character after C in the table — its code follows the same sequential pattern.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>00011</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores. D is denary 3 = 00011.</li>\n</ul>\n</div>"}, {"question": "<p>Which of these statements about Unicode is TRUE?</p>", "marks": 1, "hint": "Think about how Unicode was designed to stay compatible with existing ASCII text.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Unicode''s first 128 character codes are identical to the 128 codes used by ASCII</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores. Unicode uses MORE bits per character than ASCII, not fewer, and can represent far more characters than ASCII, not the same set.</li>\n</ul>\n</div>"}, {"question": "<p>Explain why the messaging app''s developers chose to use Unicode, rather than ASCII, to store messages sent between users. Explain one disadvantage of this choice, in terms of file size.</p>", "marks": 4, "hint": "Cover why 128 ASCII characters is not enough for this app''s users, and what using more bits per character costs in storage.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (2 marks per point developed, max 4)</h5>\n<ul>\n<li>ASCII''s 128 characters cannot represent the many languages, symbols and emoji the app''s international users need</li>\n<li>Unicode uses more bits per character (e.g. 16 bits), so it can represent far more characters, including many different languages and emoji</li>\n<li>Unicode characters typically need more bits/storage than ASCII characters</li>\n<li>This means messages/files stored using Unicode take up more storage space than the same text stored using ASCII</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per point to a maximum of 4; full marks needs both the reason FOR choosing Unicode and the storage disadvantage addressed.</li>\n</ul>\n</div>"}, {"question": "<p>Complete the passage below about ASCII and Unicode using words from the word bank. Not all words will be used.</p>", "marks": 3, "hint": "One blank is a number of bits, one is about countries/languages, and one is the name of the older character set Unicode stays compatible with.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per correct blank)</h5>\n<ul>\n<li>Blank 1: 7</li>\n<li>Blank 2: languages</li>\n<li>Blank 3: ASCII</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each blank is marked independently.</li>\n<li>\"8\", \"16\", \"numbers\", \"Unicode\" and \"emoji\" are all distractor words that do not fit these three blanks.</li>\n</ul>\n</div>"}, {"question": "<p>Using the Sample Code Table above, tick (✓) <strong>one</strong> box in each row to identify the character represented by each binary code.</p>", "marks": 4, "hint": "Convert each binary code to denary first, then find the matching character in the Sample Code Table.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>00110 → G</li>\n<li>01011 → L</li>\n<li>10001 → . (full stop)</li>\n<li>01001 → J</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently. Extra ticks in a row void that row''s mark.</li>\n</ul>\n</div>"}, {"question": "<p>A message containing only English characters is stored using ASCII at 8 bits per character, and takes up exactly 200 bytes. Calculate the file size, in bytes, if the same message were re-encoded using Unicode at 16 bits per character instead. Show your working.</p>", "marks": 2, "hint": "First work out how many characters are in the message using the ASCII figures, then apply the Unicode bits-per-character to that same number of characters.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: finds 200 characters in the message (200 bytes × 8 = 1,600 bits; 1,600 ÷ 8 = 200 characters)</li>\n<li>1 mark: correct Unicode file size of 400 bytes (200 × 16 = 3,200 bits; 3,200 ÷ 8 = 400 bytes)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The second mark follows through from the candidate''s own character count, even if it is not 200.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-2-6-data-storage-images', '1.2.6 Data Storage: Images', '{"learn": {"enabled": true, "items": [{"title": "How is a bitmap image stored as binary?", "html": "<h4>Pixels: the grid that makes up a bitmap image</h4>\n<ul>\n<li>A <strong>bitmap image</strong> is made up of a grid of tiny coloured dots called <strong>pixels</strong> (\"picture elements\"). Zoom in far enough on any digital photo or icon and you can see the individual pixels that make it up.</li>\n<li>Every pixel stores a <strong>binary code</strong> that represents its own colour. The whole image is stored as one long sequence of these binary codes, one pixel after another.</li>\n<li>To display the image again, the software reads the binary codes back out in the same order and colours in each pixel accordingly — rebuilding the original grid.</li>\n</ul>\n<h4>A simple example: a 1-bit (monochrome) pixel grid</h4>\n<ul>\n<li>With a <strong>colour depth of just 1 bit</strong>, each pixel can only be one of <strong>two</strong> colours — shown below as a filled square (storing 1) or an outlined square (storing 0). This 5×5 grid stores a simple plus-sign shape this way:</li>\n</ul>\n<svg viewBox=\"0 0 172 172\" width=\"180\" height=\"180\" role=\"img\" aria-label=\"A 5 by 5 grid of pixels forming a plus-sign shape, where filled squares are pixels storing binary value 1 and outlined squares are pixels storing binary value 0\">\n<rect x=\"2\" y=\"2\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"36\" y=\"2\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"70\" y=\"2\" width=\"30\" height=\"30\" fill=\"currentColor\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"104\" y=\"2\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"138\" y=\"2\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"2\" y=\"36\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"36\" y=\"36\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"70\" y=\"36\" width=\"30\" height=\"30\" fill=\"currentColor\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"104\" y=\"36\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"138\" y=\"36\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"2\" y=\"70\" width=\"30\" height=\"30\" fill=\"currentColor\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"36\" y=\"70\" width=\"30\" height=\"30\" fill=\"currentColor\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"70\" y=\"70\" width=\"30\" height=\"30\" fill=\"currentColor\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"104\" y=\"70\" width=\"30\" height=\"30\" fill=\"currentColor\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"138\" y=\"70\" width=\"30\" height=\"30\" fill=\"currentColor\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"2\" y=\"104\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"36\" y=\"104\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"70\" y=\"104\" width=\"30\" height=\"30\" fill=\"currentColor\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"104\" y=\"104\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"138\" y=\"104\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"2\" y=\"138\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"36\" y=\"138\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"70\" y=\"138\" width=\"30\" height=\"30\" fill=\"currentColor\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"104\" y=\"138\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"138\" y=\"138\" width=\"30\" height=\"30\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n</svg>\n<p>Reading the middle row left to right gives the binary pattern <strong>1 1 1 1 1</strong> — five pixels, five bits. A real photograph works exactly the same way, just with a much bigger grid and many more bits stored per pixel.</p>\n<h4>Why the grid order matters</h4>\n<ul>\n<li>Every pixel''s binary code must be stored in the <strong>same fixed order</strong> (usually left-to-right, top-to-bottom) so the software knows exactly which code belongs to which position in the grid. Get the order wrong and the picture is scrambled, even if every individual colour code is correct.</li>\n</ul>", "check": {"question": "What is a pixel?", "options": ["The smallest single point of colour that makes up a bitmap image", "The total number of pixels used to measure an image''s resolution", "A unit used to measure how much free storage space is left on a device", "The file extension used to identify which image format has been used"], "answer": 0, "explain": "A bitmap image is built from a grid of pixels — each pixel is the smallest single point of colour in that grid, storing a binary code for its own colour."}}, {"title": "What is colour depth, and how many colours can it represent?", "html": "<h4>Colour depth: bits per pixel</h4>\n<ul>\n<li><strong>Colour depth</strong> is the number of <strong>bits</strong> used to store the colour of a <strong>single pixel</strong>. A bigger colour depth means more bits are spent describing each pixel''s colour.</li>\n<li>Because each extra bit doubles the number of different binary codes available, the number of possible colours a colour depth of <strong>n</strong> bits can represent is <strong>2<sup>n</sup></strong>.</li>\n</ul>\n<table>\n<tr><th>Colour depth</th><th>Calculation</th><th>Possible colours</th></tr>\n<tr><td>1 bit</td><td>2<sup>1</sup></td><td>2 (e.g. black and white)</td></tr>\n<tr><td>2 bits</td><td>2<sup>2</sup></td><td>4</td></tr>\n<tr><td>4 bits</td><td>2<sup>4</sup></td><td>16</td></tr>\n<tr><td>8 bits</td><td>2<sup>8</sup></td><td>256</td></tr>\n<tr><td>24 bits</td><td>2<sup>24</sup></td><td>16,777,216 (\"true colour\")</td></tr>\n</table>\n<h4>Worked example: finding the minimum colour depth needed</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>A designer needs each pixel to display at least 16 different colours. Try increasing colour depths and calculate 2 to the power of n until it reaches 16.</td><td>2<sup>4</sup> = 16</td></tr>\n<tr><td>2</td><td>State the minimum colour depth needed.</td><td>4 bits</td></tr>\n</table>\n<h4>Why this matters for the exam</h4>\n<ul>\n<li>You may be asked to go either direction: calculate <strong>how many colours</strong> a given colour depth allows (2<sup>n</sup>), or work out the <strong>minimum colour depth</strong> needed for a target number of colours (find the smallest n where 2<sup>n</sup> is big enough).</li>\n</ul>", "check": {"question": "A retro game uses a colour depth of 5 bits per pixel. How many different colours can each pixel display?", "options": ["16", "32", "64", "10"], "answer": 1, "explain": "2 to the power of the colour depth gives the number of possible colours: 2 to the power of 5 = 32."}}, {"title": "What is resolution, and how does it affect an image?", "html": "<h4>Resolution: the total pixel count</h4>\n<ul>\n<li><strong>Resolution</strong> is the total number of pixels that make up an image, found by multiplying its <strong>width</strong> (in pixels) by its <strong>height</strong> (in pixels).</li>\n<li>A higher resolution means the image is made up of <strong>more</strong>, smaller pixels — so it can show finer detail. A lower resolution means fewer, larger pixels, which can make the image look blocky when it is enlarged.</li>\n</ul>\n<h4>Worked example</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>An image is 150 pixels wide and 100 pixels tall. Multiply width × height.</td><td>150 × 100 = 15,000 pixels</td></tr>\n<tr><td>2</td><td>State the resolution.</td><td>15,000 pixels</td></tr>\n</table>\n<h4>Resolution is not the same as colour depth</h4>\n<ul>\n<li>These two terms are easy to mix up, but they describe completely different things: <strong>resolution</strong> is HOW MANY pixels there are; <strong>colour depth</strong> is how many BITS are used for each individual pixel''s colour. An image can have a high resolution with a low colour depth (lots of pixels, few colours), or the other way round.</li>\n</ul>", "check": {"question": "An image measures 150 pixels wide and 100 pixels tall. What is its resolution (total number of pixels)?", "options": ["15,000 pixels", "1,500 pixels", "25,000 pixels", "150,000 pixels"], "answer": 0, "explain": "Resolution = width × height = 150 × 100 = 15,000 pixels."}}, {"title": "Quality vs file size: the trade-off from colour depth and resolution", "html": "<h4>Both factors push quality and file size the same way</h4>\n<ul>\n<li>Increasing <strong>colour depth</strong> allows more possible colours per pixel, giving smoother, more realistic colour — but it means more bits are stored for every single pixel, so the file gets <strong>bigger</strong>.</li>\n<li>Increasing <strong>resolution</strong> shows more fine detail, because there are more pixels in the grid — but there is also more pixel data to store overall, so the file gets <strong>bigger</strong> too.</li>\n<li>There is no way to improve quality using either factor without also increasing the file size — it is always a trade-off.</li>\n</ul>\n<h4>Worked example: doubling resolution</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>An image is 100 × 100 pixels with an 8-bit colour depth. Find the file size in bits, then bytes, then KB.</td><td>8 × 100 × 100 = 80,000 bits → 10,000 bytes → 10 KB</td></tr>\n<tr><td>2</td><td>Double BOTH the height and width to 200 × 200 pixels, keeping the colour depth the same. Recalculate.</td><td>8 × 200 × 200 = 320,000 bits → 40,000 bytes → 40 KB</td></tr>\n<tr><td>3</td><td>Compare the two file sizes.</td><td>40 KB is 4× the original 10 KB</td></tr>\n</table>\n<h4>Why doubling resolution QUADRUPLES the file size</h4>\n<ul>\n<li>Doubling both height and width doesn''t just double the pixel count — it multiplies it by <strong>2 × 2 = 4</strong>, because BOTH dimensions have doubled. This is a common trap: many students expect doubling resolution to double the file size, when it actually roughly quadruples it (when both height and width are doubled).</li>\n</ul>", "check": {"question": "An image''s file size is 10 KB. If you double BOTH its height and width in pixels, keeping the colour depth the same, what is its new approximate file size?", "options": ["20 KB", "40 KB", "10 KB", "80 KB"], "answer": 1, "explain": "Doubling both dimensions multiplies the pixel count by 2 × 2 = 4, so the file size roughly quadruples: 10 KB × 4 = 40 KB."}}, {"title": "Metadata: why is extra information stored with an image file?", "html": "<h4>What is metadata?</h4>\n<ul>\n<li><strong>Metadata</strong> is extra information stored alongside an image''s pixel data, describing the image itself rather than being part of the picture. Typical metadata for an image file includes its <strong>width</strong>, <strong>height</strong>, <strong>colour depth</strong> and <strong>file type</strong> (the image format used).</li>\n</ul>\n<h4>Why metadata is essential, not optional</h4>\n<ul>\n<li>Without knowing the <strong>width</strong>, the software reading the file would have no way to tell where one row of pixels ends and the next one begins — the pixel data is really just one long string of bits with no natural breaks.</li>\n<li>Without knowing the <strong>colour depth</strong>, the software would not know how many bits to read for each individual pixel''s colour code, so it could not correctly split the pixel data into separate pixels at all.</li>\n<li>Without the <strong>file type</strong>, the software would not know which set of rules to use to interpret the stored bits in the first place.</li>\n<li>In short: the raw pixel data on its own is meaningless without the metadata needed to correctly reconstruct it back into a grid.</li>\n</ul>\n<h4>Metadata adds to the file size</h4>\n<ul>\n<li>Because metadata is extra information on top of the pixel data, a real image file is always <strong>slightly bigger</strong> than the size given by colour depth × height × width alone. Exam calculations usually ignore this small extra amount unless a question specifically tells you to include it.</li>\n</ul>", "check": {"question": "Which piece of information is stored as part of an image file''s metadata?", "options": ["The width and height of the image, in pixels", "The exact colour value of every single pixel in the image", "The name of the software currently being used to view the file", "The total amount of free storage space left on the device"], "answer": 0, "explain": "Metadata describes the image itself — such as its width, height, colour depth and file type — so the software can correctly rebuild the pixel grid. The pixel colour values are the picture data itself, not metadata."}}, {"title": "Worked example: calculating an image file''s size", "html": "<h4>The formula</h4>\n<ul>\n<li><strong>File size (bits) = colour depth (bits per pixel) × height (pixels) × width (pixels)</strong></li>\n<li>Always calculate the answer in <strong>bits</strong> first, then convert into whatever unit the question actually asks for.</li>\n</ul>\n<h4>Worked example</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>An image is 60 pixels tall and 50 pixels wide, with a colour depth of 8 bits. Multiply colour depth × height × width.</td><td>8 × 60 × 50 = 24,000 bits</td></tr>\n<tr><td>2</td><td>Convert bits into bytes by dividing by 8.</td><td>24,000 ÷ 8 = 3,000 bytes</td></tr>\n<tr><td>3</td><td>Convert bytes into a sensible unit by dividing by 1,000.</td><td>3,000 ÷ 1,000 = 3 KB</td></tr>\n</table>\n<h4>Show every step, every time</h4>\n<ul>\n<li>OCR-style marking usually splits calculation marks between the <strong>working</strong> and the <strong>final answer</strong> — so writing down all three steps (multiply, then ÷8, then ÷1,000) protects your marks even if you slip on the arithmetic somewhere along the way.</li>\n<li>Remember the real file will be a little bigger than this because of <strong>metadata</strong> — but unless a question tells you to include it, calculate using colour depth × height × width alone.</li>\n</ul>", "check": {"question": "An image is 40 pixels tall and 25 pixels wide, with a colour depth of 8 bits. What is its file size in bytes?", "options": ["1,000 bytes", "8,000 bytes", "125 bytes", "10,000 bytes"], "answer": 0, "explain": "8 × 40 × 25 = 8,000 bits. 8,000 ÷ 8 = 1,000 bytes."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Pixel", "definition": "The smallest single point of colour that makes up a bitmap image"}, {"term": "Bitmap image", "definition": "An image made of a grid of pixels, each pixel storing a binary colour value"}, {"term": "Colour depth", "definition": "The number of bits used to store the colour of a single pixel"}, {"term": "2 to the power of n rule", "definition": "A colour depth of n bits can represent 2 to the power of n different colours"}, {"term": "Resolution", "definition": "The total number of pixels that make up an image — its height × width"}, {"term": "Effect of higher colour depth", "definition": "More possible colours per pixel (better quality) but more bits stored per pixel (bigger file)"}, {"term": "Effect of higher resolution", "definition": "More pixels showing finer detail (better quality) but more pixel data stored (bigger file)"}, {"term": "Image file-size formula", "definition": "Colour depth × height (pixels) × width (pixels), giving the size in bits"}, {"term": "Metadata", "definition": "Extra information stored with an image, such as its width, height, colour depth and file type"}, {"term": "Why metadata is needed", "definition": "Software needs it to know how to split the binary data back into the correct grid of pixels"}, {"term": "Converting bits to bytes", "definition": "Divide the number of bits by 8"}, {"term": "Converting bytes to kilobytes", "definition": "Divide the number of bytes by 1,000 (this specification''s convention)"}, {"term": "Real file size vs raw pixel data", "definition": "A real image file is slightly bigger than colour depth × height × width because metadata is stored too"}, {"term": "Doubling both height and width", "definition": "Roughly quadruples the file size, since the total number of pixels increases four-fold"}, {"term": "Minimum colour depth for N colours", "definition": "The smallest n where 2 to the power of n is at least N"}, {"term": "1-bit colour depth", "definition": "Can represent only 2 colours (2 to the power of 1) — e.g. black and white with no shades"}, {"term": "8-bit colour depth", "definition": "Can represent 256 colours (2 to the power of 8)"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is a pixel?", "options": ["The smallest single point of colour in a bitmap image''s grid", "The total amount of storage space an image file takes up on a disk", "A unit used to measure how fast a graphics card can render images", "The file extension that identifies which image format has been used"], "answer": 0, "explain": "A bitmap image is built from a grid of pixels — each pixel is the smallest single point of colour in that grid."}, {"question": "What does ''colour depth'' measure?", "options": ["The number of bits used to store the colour of one pixel", "The number of pixels that make up the width of an image", "The number of separate image files a memory card can hold", "The number of colours a printer can physically produce"], "answer": 0, "explain": "Colour depth is the number of bits allocated to store each individual pixel''s colour value."}, {"question": "What does ''resolution'' measure in a bitmap image?", "options": ["The total number of pixels that make up the image (width × height)", "The number of bits that are used to store the colour value of a single individual pixel", "The physical size of the screen the image is being viewed on", "The amount of compression that has been applied to the file"], "answer": 0, "explain": "Resolution is the total number of pixels in the image, found by multiplying its width in pixels by its height in pixels."}, {"question": "A pixel is stored using a colour depth of 3 bits. How many different colours can that pixel display?", "options": ["6", "8", "3", "9"], "answer": 1, "explain": "2 to the power of the colour depth gives the number of possible colours: 2 to the power of 3 = 8."}, {"question": "An image uses a colour depth of 7 bits per pixel. How many different colours can each pixel represent?", "options": ["128", "64", "256", "14"], "answer": 0, "explain": "2 to the power of 7 = 128. A common mistake is confusing this with the previous or next power of 2 (2 to the power of 6 = 64, 2 to the power of 8 = 256)."}, {"question": "Which calculation correctly finds an image''s total resolution?", "options": ["Multiply the image''s height in pixels by its width in pixels", "Multiply the colour depth by the total number of pixels contained in just one single row of the image", "Divide the file size in bits by the colour depth used for each pixel", "Add the image''s height in pixels to its width in pixels"], "answer": 0, "explain": "Resolution = height (pixels) × width (pixels) — the total count of pixels in the grid."}, {"question": "Increasing an image''s colour depth, with resolution unchanged, has what effect?", "options": ["More possible colours per pixel and a larger file size", "More possible colours per pixel and a smaller file size", "More pixels in the image and a larger file size", "Fewer possible colours per pixel and no change in file size"], "answer": 0, "explain": "A higher colour depth stores more bits per pixel, so more colours can be represented — but more bits also means a bigger file."}, {"question": "Increasing an image''s resolution, with colour depth unchanged, has what effect?", "options": ["More pixels showing finer detail, and a larger file size", "Fewer pixels showing finer detail, and a smaller file size", "The same number of pixels, but each one stores more colours", "No change occurs to either the file size or the level of detail shown"], "answer": 0, "explain": "A higher resolution means more pixels are stored, showing more detail — but also increasing the file size, since there is more pixel data to store."}, {"question": "An icon is 30 pixels wide and 20 pixels tall, with a colour depth of 8 bits. What is its file size in bytes?", "options": ["600 bytes", "4,800 bytes", "2,400 bytes", "75 bytes"], "answer": 0, "explain": "8 × 30 × 20 = 4,800 bits. 4,800 ÷ 8 = 600 bytes."}, {"question": "A photo has a resolution of 200 × 100 pixels and a colour depth of 4 bits. What is its file size in KB?", "options": ["10 KB", "80 KB", "1.25 KB", "20 KB"], "answer": 0, "explain": "4 × 200 × 100 = 80,000 bits. 80,000 ÷ 8 = 10,000 bytes. 10,000 ÷ 1,000 = 10 KB."}, {"question": "Which of these is stored as metadata alongside an image''s pixel data, rather than being part of the pixel data itself?", "options": ["The image''s width and height in pixels", "The exact binary colour code of the very first pixel", "The exact binary colour code of the very last pixel", "The binary colour codes of every pixel in the middle row"], "answer": 0, "explain": "Metadata stores information ABOUT the image (like its width and height) — the pixel data itself is the actual grid of colour values, stored separately."}, {"question": "Which statement about metadata and file size is correct?", "options": ["Real image files are usually a little bigger than the pixel data alone", "Metadata replaces the need to store any of the image''s pixel data, shrinking the overall file size a great deal", "Metadata is only ever added to a file when the colour depth used is above 8 bits per pixel", "Storing metadata alongside an image removes any need to know its colour depth afterwards"], "answer": 0, "explain": "Metadata (width, height, colour depth, file type, etc.) is extra information stored on top of the pixel data, so real files are a little larger than colour depth × height × width alone suggests."}]}, "fib": {"enabled": true, "questions": [{"text": "A bitmap image is made up of a grid of [pixels], each one storing a binary colour value."}, {"text": "The number of bits used to store the colour of a single pixel is called the [colour depth]."}, {"text": "A colour depth of 5 bits can represent [32] different colours (2 to the power of 5)."}, {"text": "Resolution is calculated by multiplying an image''s width in pixels by its [height] in pixels."}, {"text": "The formula for an image''s file size in bits is colour depth × height × [width]."}, {"text": "To convert an image''s file size from bits into bytes, you divide by [8]."}, {"text": "Metadata stored with an image includes its width, height, colour depth and file [type]."}, {"text": "Doubling both the height and width of an image roughly [quadruples] its file size."}]}, "tf": {"enabled": true, "questions": [{"statement": "A bitmap image is made up of a grid of pixels.", "answer": true, "explain": "Correct — every bitmap image is a grid of pixels, each storing a binary colour value."}, {"statement": "Colour depth is the number of pixels that make up an image''s width.", "answer": false, "explain": "That describes part of resolution, not colour depth. Colour depth is the number of BITS used to store one pixel''s colour."}, {"statement": "A colour depth of 4 bits can represent 16 different colours.", "answer": true, "explain": "Correct — 2 to the power of 4 = 16."}, {"statement": "Increasing an image''s resolution, with colour depth unchanged, increases its file size.", "answer": true, "explain": "Correct — more pixels means more pixel data to store, so the file size increases."}, {"statement": "More pixels in an image always produces better quality, with no other consequence to consider.", "answer": false, "explain": "More pixels usually does improve detail, but it isn''t consequence-free — more pixels also means a bigger file size, which is why ''more pixels = better, full stop'' is a common misconception."}, {"statement": "The formula for an image''s file size in bits is colour depth × height × width.", "answer": true, "explain": "Correct — file size (bits) = colour depth × height × width."}, {"statement": "A file-size calculation for an image should be left in bits as the final answer, even if the question asks for KB.", "answer": false, "explain": "The formula gives bits first, but that is only the first step — you must convert (÷8 for bytes, ÷1,000 per unit after that) into whatever unit the question actually asks for."}, {"statement": "Metadata is not needed to correctly reconstruct an image from its stored binary data.", "answer": false, "explain": "Metadata (such as width, height and colour depth) is essential — without it, software could not correctly split the raw pixel data back into the right grid."}]}, "misc": {"enabled": true, "items": [{"myth": "Believing that more pixels always means a better image, without thinking about the resulting file size.", "truth": "More pixels (a higher resolution) does usually improve detail — but it also increases the <strong>file size</strong>, because there is more pixel data to store. Quality and file size always move together, so \"more pixels is always simply better\" ignores the real storage cost.", "check": {"question": "Is it true that increasing resolution improves an image with no downside at all?", "options": ["No — it also increases the file size, since more pixel data has to be stored", "Yes — resolution has no effect at all on an image''s file size, it only ever affects quality", "No — increasing resolution actually makes an image lower quality", "Yes — but only for images using a colour depth below 8 bits"], "answer": 0, "explain": "A higher resolution means more pixels, which means more pixel data to store — so the file size also increases. There is always a trade-off."}}, {"myth": "Thinking a colour depth of n bits gives n possible colours — e.g. assuming 4 bits means 4 colours.", "truth": "It is <strong>2 to the power of n</strong>, not n. A colour depth of 4 bits gives 2<sup>4</sup> = <strong>16</strong> possible colours, not 4. Each extra bit DOUBLES the number of colours available, rather than adding a fixed amount.", "check": {"question": "A colour depth of 4 bits is used. How many different colours can each pixel represent?", "options": ["4", "8", "16", "20"], "answer": 2, "explain": "2 to the power of 4 = 16, not 4. Colour depth and number of colours are related by 2 to the power of n, not a simple multiplication."}}, {"myth": "Confusing colour depth with resolution — describing colour depth as ''the number of pixels in the image''.", "truth": "<strong>Colour depth</strong> is the number of bits used for ONE pixel''s colour. <strong>Resolution</strong> is the total number of pixels in the whole image (height × width). They are independent — an image can have a high resolution with a low colour depth, or the other way round.", "check": {"question": "Which statement correctly distinguishes colour depth from resolution?", "options": ["Colour depth is bits per pixel; resolution is the total number of pixels in the image", "Colour depth and resolution both measure exactly the same thing", "Resolution is bits per pixel; colour depth is the total number of pixels in the image instead", "Colour depth measures screen size; resolution measures file type"], "answer": 0, "explain": "Colour depth = bits used per pixel''s colour. Resolution = total pixel count (height × width). They are two separate, independent properties of an image."}}, {"myth": "Leaving a file-size calculation answer in bits, because the multiplication already produced ''a number'' that looks like an answer.", "truth": "Colour depth × height × width always gives the answer in <strong>bits</strong> first — that is only the first step. You must then divide by 8 to reach bytes, and keep dividing by 1,000 for each unit up the ladder until you reach the unit the question actually asked for.", "check": {"question": "A calculation gives 24,000 bits, and the question asks for the answer in KB. What should you do next?", "options": ["Divide by 8 to get bytes, then divide by 1,000 to get KB", "Write down 24,000 as the final answer, already correct in KB", "Multiply the bits total by 8 to reach bytes", "Divide the bits total by 1,000 only, then stop working"], "answer": 0, "explain": "24,000 bits ÷ 8 = 3,000 bytes, then ÷ 1,000 = 3 KB. Both conversion steps are needed to reach the unit asked for."}}, {"myth": "Assuming doubling an image''s resolution (both height and width) only doubles the file size.", "truth": "Doubling BOTH height and width multiplies the total pixel count by <strong>2 × 2 = 4</strong>, not 2 — so the file size roughly QUADRUPLES, not doubles. Only doubling a single dimension (just the width, say) would double the pixel count.", "check": {"question": "An 8-bit image is 50 × 50 pixels. Both its height and width are doubled to 100 × 100 pixels. What happens to the file size?", "options": ["It roughly doubles", "It roughly quadruples", "It stays exactly the same", "It is cut roughly in half"], "answer": 1, "explain": "Doubling both dimensions multiplies the pixel count by 2 × 2 = 4, so the file size roughly quadruples, not doubles."}}, {"myth": "Thinking metadata is optional extra information that could be deleted without affecting how the image displays.", "truth": "Metadata (especially the <strong>width</strong>, <strong>height</strong> and <strong>colour depth</strong>) is required to correctly decode the pixel data. Without it, the software has no way to know where one row of pixels ends or how many bits belong to each pixel — the raw data becomes meaningless.", "check": {"question": "What would happen if an image file''s metadata (width, height, colour depth) were removed, leaving only the raw pixel data?", "options": ["The software could no longer correctly rebuild the pixel grid from the data", "Nothing at all — the image would carry on displaying exactly as it did before, with no problems", "The file size would increase to compensate", "The image would automatically display in black and white"], "answer": 0, "explain": "Without metadata like width and colour depth, software cannot tell where rows of pixels begin and end, or how many bits belong to each pixel — so it cannot correctly reconstruct the image."}}]}, "tips": {"enabled": true, "items": [{"title": "Show-your-working ladder: the image file-size calculation", "html": "<p>A typical question: <em>\"A photo is 40 pixels wide and 30 pixels tall, with a colour depth of 8 bits per pixel. Calculate the file size in bytes. Show your working.\"</em> [2 marks] Here is the same answer at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"1,200 bytes\"</p>\n<ul>\n<li>No working shown. Even a correct final answer with nothing behind it risks losing the working mark entirely if it happens to be wrong.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"8 × 40 × 30 = 9,600\"</p>\n<ul>\n<li>Valid working is shown (1 mark), but the answer was never converted into bytes and stated as a final answer — the second mark is for the CONVERTED answer in the unit asked for.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"8 × 40 × 30 = 9,600 bits <strong>(1)</strong>. 9,600 ÷ 8 = 1,200 bytes <strong>(1)</strong>.\"</p>\n\n<p><strong>Why this matters even if your arithmetic slips:</strong> OCR-style marking separates the WORKING mark from the ANSWER mark. If your method is correct but you slip on the final division, you can still keep the working mark — but only if you actually wrote the working down.</p>", "check": {"question": "You calculate 8 × 40 × 30 = 9,600 correctly, but then wrongly divide by 100 instead of 8 and write ''96 bytes''. What mark do you get out of 2?", "options": ["0, because the final stated answer is wrong", "1 — the working mark for the correct multiplication step", "2, since your working clearly shows you understood the method", "It depends entirely on which calculator you used"], "answer": 1, "explain": "The multiplication step (8 × 40 × 30 = 9,600 bits) is valid working, so it earns the working mark even though the final conversion — and therefore the answer mark — was wrong."}}, {"title": "2 to the power of n colours: don''t just double the colour depth", "html": "<p>Colour depth questions trip students up in one of two directions — going from colour depth to colours, or colours back to colour depth. Both need the SAME rule: <strong>2 to the power of the colour depth</strong>, never the colour depth multiplied by 2.</p>\n\n<p><strong>Direction 1 — colour depth → number of colours:</strong> raise 2 to the power of the given colour depth. A colour depth of 5 bits gives 2<sup>5</sup> = 32 colours, NOT 5 × 2 = 10.</p>\n\n<p><strong>Direction 2 — number of colours → minimum colour depth:</strong> try increasing colour depths and calculate 2<sup>n</sup> for each one until the result is big enough. Needing at least 100 colours? 2<sup>6</sup> = 64 (too few), 2<sup>7</sup> = 128 (enough) — so the minimum colour depth is 7 bits.</p>\n\n<p><strong>The trap to avoid:</strong> confusing colour depth (bits per pixel) with resolution (number of pixels). \"How many colours\" is always a colour depth question; \"how many pixels\" is always a resolution question — they never use the same formula.</p>", "check": {"question": "A colour depth of 4 bits is doubled to a colour depth of 8 bits. What happens to the number of possible colours?", "options": ["It rises from 16 to 256, not simply doubling to 32", "It exactly doubles, rising from 16 to 32", "It stays exactly the same at 16 colours", "It rises to 64 colours only, since 8 multiplied by 4 equals 32 which is then halved"], "answer": 0, "explain": "2 to the power of 4 = 16 and 2 to the power of 8 = 256. Doubling the colour depth does not double the number of colours — it multiplies it by a far bigger factor."}}, {"title": "Command-word ladder: ''state'' vs ''explain'' for the quality/size trade-off", "html": "<p>The same underlying knowledge — that increasing colour depth or resolution affects both quality and file size — is tested at very different tariffs depending on the command word used.</p>\n\n<p><strong>\"State\" (1–2 marks):</strong> a single, direct fact is enough. <em>\"State the effect of increasing an image''s colour depth on its file size.\"</em> → \"It increases the file size.\" One clear statement, no reasoning required.</p>\n\n<p><strong>\"Explain\" (3–4 marks):</strong> needs the full <em>point → …which means… → consequence</em> chain, not just the fact. <em>\"Explain the effect of increasing an image''s colour depth.\"</em></p>\n<ul>\n<li><strong>Point:</strong> \"A higher colour depth uses more bits to store each pixel''s colour…\"</li>\n<li><strong>…which means…:</strong> \"…so more possible colours can be represented per pixel, giving smoother, more realistic colour…\"</li>\n<li><strong>…but the consequence is…:</strong> \"…while also increasing the overall file size, because more bits are stored for every single pixel in the image.\"</li>\n</ul>\n\n<p><strong>Why the chain matters:</strong> a bare \"state\" answer scores 0 on an \"explain\" question, because it stops after the first link — the examiner is specifically paying for the \"…which means…\" development, not just the initial fact.</p>", "check": {"question": "A 3-mark ''explain'' question asks about the effect of increasing resolution. A student writes only ''It makes the file size bigger.'' How many of the 3 marks would this likely earn?", "options": ["Likely just 1 mark — a bare statement with no development chain", "All 3 marks, since the key fact given is completely correct", "0 marks, because the statement given is factually wrong", "2 marks, for correctly identifying file size as the affected factor"], "answer": 0, "explain": "An ''explain'' question needs the point developed with a ''which means...'' chain (more pixels → more detail, but also more data to store). A bare fact with no development usually only reaches the first mark."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick (✓) <strong>one</strong> box to identify the correct definition of an image''s <strong>colour depth</strong>.</p>", "marks": 1, "hint": "Colour depth is about ONE pixel''s storage, not the whole image or a printer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>The number of bits used to store the colour of a single pixel</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept cross or other indication as long as it is clear which one box is intended.</li>\n<li>2+ ticks = 0 marks.</li>\n</ul>\n</div>"}, {"question": "<p>A pixel is stored using a colour depth of 6 bits. Tick (✓) <strong>one</strong> box to identify how many different colours that pixel can display.</p>", "marks": 1, "hint": "Use 2 to the power of the colour depth, not the colour depth multiplied by 2.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>64</strong>. Working: 2 to the power of 6 = 64.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; there is no credit for a value calculated using the wrong method.</li>\n</ul>\n</div>"}, {"question": "<p>State what is meant by the term <strong>resolution</strong> when describing a bitmap image.</p>", "marks": 1, "hint": "Answer in terms of pixels, not physical screen size.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>The total number of pixels that make up the image (accept width × height, or \"how many pixels wide by how many pixels tall\")</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not accept a description of colour depth or a physical screen size instead of pixel count.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how one of the studio''s icons is represented and stored as binary data.</p>", "marks": 3, "hint": "Work through the chain: what makes up the grid, what each part of the grid stores, and what decides how many bits that is.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point to max 3)</h5>\n<ul>\n<li>The icon is made up of a grid of pixels</li>\n<li>Each pixel stores a binary code representing its own colour</li>\n<li>The number of bits used to store each pixel''s colour is set by the icon''s colour depth</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per point to a maximum of 3. Accept any equivalent correct wording.</li>\n</ul>\n</div>"}, {"question": "<p>A postage-stamp icon is 20 pixels wide and 20 pixels tall, using a colour depth of 8 bits. Tick (✓) <strong>one</strong> box to identify its file size in bytes.</p>", "marks": 1, "hint": "Work out bits first (8 × 20 × 20), then divide by 8 to reach bytes.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>400 bytes</strong>. Working: 8 × 20 × 20 = 3,200 bits; 3,200 ÷ 8 = 400 bytes.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores.</li>\n</ul>\n</div>"}, {"question": "<p>Each ID photo is 60 pixels wide and 40 pixels tall, saved with a colour depth of 8 bits. Calculate the file size of one photo in bytes. Show your working.</p>", "marks": 2, "hint": "Use colour depth × height × width to get bits first, then divide by 8 for bytes.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working, e.g. 8 × 60 × 40 = 19,200 (bits)</li>\n<li>1 mark for the answer: 2,400 bytes</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any correct method that reaches bits first, then converts to bytes by dividing by 8.</li>\n<li>Award the working mark even if the final answer is wrong, provided the method shown is valid.</li>\n</ul>\n</div>"}, {"question": "<p>The school wants to store the SAME photo but at a higher colour depth of 24 bits (to capture true colour), keeping the resolution the same (60 × 40 pixels).</p><p>Calculate the new file size in KB, and state how many times bigger it is than the original 8-bit photo, which was 2,400 bytes. Show your working.</p>", "marks": 4, "hint": "Find the new file size the same way as before (colour depth × height × width, then ÷8 and ÷1,000), then compare your new KB figure to the original 2.4 KB.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: 24 × 60 × 40 = 57,600 (bits)</li>\n<li>1 mark: 57,600 ÷ 8 = 7,200 (bytes); 7,200 ÷ 1,000 = 7.2 (KB)</li>\n<li>1 mark for the answer: 7.2 KB</li>\n<li>1 mark: correctly states this is 3 times bigger than the original 2.4 KB (7.2 ÷ 2.4 = 3)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Own-figure/follow-through applies to the comparison mark — it can be awarded using the candidate''s own file-size figure, provided the comparison method is correct.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how increasing the colour depth used for one of the studio''s icons, and increasing its resolution, would each affect the icon''s file size and its visual quality.</p>", "marks": 4, "hint": "Two separate factors — colour depth and resolution — and for EACH one you need both its effect on file size AND its effect on quality.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: higher colour depth increases file size (more bits per pixel)</li>\n<li>1 mark: higher colour depth improves quality (more possible colours per pixel)</li>\n<li>1 mark: higher resolution increases file size (more pixel data overall)</li>\n<li>1 mark: higher resolution improves quality (more pixels, finer detail)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Full marks needs both colour depth and resolution addressed, with both the file-size effect AND the quality effect given for each.</li>\n</ul>\n</div>"}, {"question": "<p>A camera sensor uses a colour depth of 6 bits per pixel. Calculate the number of different colours each pixel can display.</p>", "marks": 1, "hint": "2 to the power of the colour depth.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>64 (2 to the power of 6)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct value scores; no credit for a value found using the wrong method.</li>\n</ul>\n</div>"}, {"question": "<p>A designer needs each pixel in a new icon format to be able to display AT LEAST 100 different colours. Calculate the minimum colour depth, in bits, needed to achieve this. Show your working.</p>", "marks": 2, "hint": "Try increasing colour depths and calculate 2 to the power of n for each one until the result is at least 100.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working, e.g. 2 to the power of 6 = 64 (too few), 2 to the power of 7 = 128 (enough)</li>\n<li>1 mark for the answer: 7 bits</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award the working mark for any method that correctly tests powers of 2 against the 100-colour target, even if the final answer is wrong.</li>\n</ul>\n</div>"}, {"question": "<p>Complete the table by calculating the number of different colours that each colour depth can represent.</p>", "marks": 4, "hint": "Work out 2 to the power of each colour depth given in the left-hand column.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>1-bit = 2 colours</li>\n<li>3-bit = 8 colours</li>\n<li>5-bit = 32 colours</li>\n<li>10-bit = 1,024 colours</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept the numeric value with or without a comma.</li>\n<li>Each row is marked independently.</li>\n</ul>\n</div>"}, {"question": "<p>Tick (✓) <strong>one</strong> box in each row to identify the file size, in bytes, of the image described.</p>", "marks": 4, "hint": "Work out colour depth × height × width in bits for each row, then divide by 8 to reach bytes, before matching to a column. Two different rows can share the same correct column.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Row 1 (8-bit, 10 × 100): 8 × 10 × 100 = 8,000 bits = <strong>1,000 bytes</strong></li>\n<li>Row 2 (8-bit, 20 × 100): 8 × 20 × 100 = 16,000 bits = <strong>2,000 bytes</strong></li>\n<li>Row 3 (4-bit, 20 × 100): 4 × 20 × 100 = 8,000 bits = <strong>1,000 bytes</strong></li>\n<li>Row 4 (16-bit, 20 × 100): 16 × 20 × 100 = 32,000 bits = <strong>4,000 bytes</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Two different rows can share the same correct column (rows 1 and 3 are both 1,000 bytes).</li>\n<li>Extra ticks in a row score 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Explain why the satellite''s image files need to store metadata (such as width, height and colour depth) alongside the pixel data, rather than just the pixel data on its own.</p>", "marks": 2, "hint": "Think about what the receiving software would be missing if it only had one long string of pixel bits with no extra information.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point to max 2)</h5>\n<ul>\n<li>Without the width, the software could not tell where one row of pixels ends and the next begins, so it couldn''t correctly rebuild the grid</li>\n<li>Without the colour depth, the software would not know how many bits represent each pixel''s colour, so it couldn''t correctly split the data into individual pixels</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per valid point to a maximum of 2. Accept an equivalent point about the file type telling the software which rules to use to decode the data.</li>\n</ul>\n</div>"}, {"question": "<p>The satellite company is deciding on the camera settings to use for an upcoming mission. Setting A uses a high resolution and high colour depth, producing very detailed, true-colour images but large files. Setting B uses a lower resolution and lower colour depth, producing smaller files but less detailed images.</p><p>Discuss the effect that choosing between Setting A and Setting B could have on a single mission, during which the satellite''s onboard memory has a fixed, limited capacity.</p><p>In your answer you might consider:</p><ul><li>how colour depth and resolution affect file size</li><li>the effect on how many images can be stored during one mission</li><li>the effect on how useful the images are to farmers once downloaded</li><li>which setting you would recommend, and why</li></ul>", "marks": 8, "hint": "Use all four bullets as your plan. Explain the mechanism (bigger files → fewer images fit), follow it through to a REAL consequence of the mission, and weigh image quality against image quantity for a top-band answer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (levelled) — indicative content</h5>\n<p>The following is indicative of possible factors/evidence that candidates may refer to but is not prescriptive or exhaustive:</p>\n<ul>\n<li><strong>How colour depth/resolution affect file size</strong> — Setting A''s higher colour depth stores more bits per pixel, and its higher resolution means more pixels overall; both increase file size (bits = colour depth × height × width). Setting B''s lower values mean a smaller file size per image.</li>\n<li><strong>Effect on how many images fit</strong> — the satellite''s onboard memory has a fixed capacity, so larger Setting A images mean fewer images can be stored during one mission; Setting B''s smaller images mean many more can be stored before the memory fills up.</li>\n<li><strong>Effect on the usefulness of the images</strong> — Setting A''s higher quality/detail may let farmers spot small problems in their crops clearly, but running out of memory mid-mission could mean missing important later images of other fields; Setting B captures more of the mission but each image shows less fine detail, which may not be good enough to spot small crop problems.</li>\n<li><strong>Recommendation</strong> — the better choice depends on the mission''s actual purpose: Setting A suits a short mission needing a few highly detailed images, Setting B suits a long mission needing continuous coverage where running out of storage would be worse than lower detail.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>Mark Band 3 — High Level (6–8 marks):</strong> Thorough knowledge and understanding of colour depth, resolution and file-size capacity, applied directly and consistently to the satellite context. The response weighs up both settings (quality against quantity/storage) and covers all four areas from the bullet list with clear, logically structured reasoning, ending in a justified recommendation.</li>\n<li><strong>Mark Band 2 — Mid Level (3–5 marks):</strong> Reasonable knowledge, generally accurate but at times underdeveloped or only partly applied to the satellite context. Most of the four areas are addressed, with some structure, though the discussion may not fully weigh both settings or the recommendation may be unjustified.</li>\n<li><strong>Mark Band 1 — Low Level (1–2 marks):</strong> Basic knowledge with limited understanding shown; the material may contain inaccuracies or barely refer to the satellite context. Little more than an unsupported assertion, e.g. \"Setting A is better\" with no working explanation of why.</li>\n<li><strong>0 marks:</strong> No attempt to answer the question or response is not worthy of credit.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-2-7-data-storage-sound', '1.2.7 Data Storage: Sound', '{"learn": {"enabled": true, "items": [{"title": "How is analogue sound turned into digital data?", "html": "<h4>Analogue sound, digital storage</h4>\n<ul>\n<li>Real sound is an <strong>analogue</strong> signal — a smooth, continuous wave whose <strong>amplitude</strong> (its height, which corresponds to loudness) can take literally any value as it changes over time.</li>\n<li>A computer can only store <strong>binary</strong> data, so a continuous analogue wave cannot be stored directly — it has to be converted into a stream of binary numbers first. This process is called <strong>sampling</strong>.</li>\n</ul>\n<h4>What actually happens during sampling</h4>\n<ul>\n<li>An analogue-to-digital converter measures the wave''s <strong>amplitude</strong> at <strong>regular, fixed time intervals</strong> — one snapshot after another along the wave.</li>\n<li>Each individual measurement (a <strong>sample</strong>) is rounded to the nearest value that can be represented in binary, and stored as a <strong>binary number</strong>.</li>\n<li>Played back in order, one after another, these stored samples recreate an approximation of the original analogue wave — never a perfect copy, because sampling can only capture the wave''s height at particular instants, not every instant in between.</li>\n</ul>\n<svg viewBox=\"0 0 290 140\" width=\"290\" height=\"140\" role=\"img\" aria-label=\"A sound wave with six evenly spaced vertical sample lines, each ending in a dot showing the amplitude measured at that instant\">\n<line x1=\"10\" y1=\"130\" x2=\"280\" y2=\"130\" stroke=\"currentColor\" stroke-width=\"1.5\" opacity=\"0.35\"/>\n<polyline points=\"10,70 45,25 80,115 115,25 150,115 185,25 220,115 255,25 280,70\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/>\n<line x1=\"10\" y1=\"130\" x2=\"10\" y2=\"70\" stroke=\"currentColor\" stroke-width=\"1.5\" stroke-dasharray=\"3,3\" opacity=\"0.6\"/>\n<line x1=\"64\" y1=\"130\" x2=\"64\" y2=\"74\" stroke=\"currentColor\" stroke-width=\"1.5\" stroke-dasharray=\"3,3\" opacity=\"0.6\"/>\n<line x1=\"118\" y1=\"130\" x2=\"118\" y2=\"33\" stroke=\"currentColor\" stroke-width=\"1.5\" stroke-dasharray=\"3,3\" opacity=\"0.6\"/>\n<line x1=\"172\" y1=\"130\" x2=\"172\" y2=\"58\" stroke=\"currentColor\" stroke-width=\"1.5\" stroke-dasharray=\"3,3\" opacity=\"0.6\"/>\n<line x1=\"226\" y1=\"130\" x2=\"226\" y2=\"100\" stroke=\"currentColor\" stroke-width=\"1.5\" stroke-dasharray=\"3,3\" opacity=\"0.6\"/>\n<line x1=\"280\" y1=\"130\" x2=\"280\" y2=\"70\" stroke=\"currentColor\" stroke-width=\"1.5\" stroke-dasharray=\"3,3\" opacity=\"0.6\"/>\n<circle cx=\"10\" cy=\"70\" r=\"4\" fill=\"currentColor\"/>\n<circle cx=\"64\" cy=\"74\" r=\"4\" fill=\"currentColor\"/>\n<circle cx=\"118\" cy=\"33\" r=\"4\" fill=\"currentColor\"/>\n<circle cx=\"172\" cy=\"58\" r=\"4\" fill=\"currentColor\"/>\n<circle cx=\"226\" cy=\"100\" r=\"4\" fill=\"currentColor\"/>\n<circle cx=\"280\" cy=\"70\" r=\"4\" fill=\"currentColor\"/>\n</svg>\n<p>The dashed lines mark six regular instants in time; the dot on each one is the sample taken at that instant. Notice how much of the wave''s shape between the dots is simply never recorded — that missing detail is exactly what a higher sample rate reduces.</p>\n<h4>Why \"approximation\" matters</h4>\n<ul>\n<li>Because sampling only measures the wave at intervals, some information between samples is always lost. The more often — and more precisely — you sample, the closer the digital copy gets to the original. That is the whole idea behind sample rate and bit depth, covered next.</li>\n</ul>", "check": {"question": "Why must an analogue sound wave be sampled before a computer can store it?", "options": ["A computer can only store binary data, so the wave must be converted into binary numbers", "Sampling is a compression technique that shrinks the file so it takes up far less storage space", "Microphones only ever produce a digital electrical signal, so no conversion is required at all", "Sampling instantly removes background noise from a recording before it is saved as a file"], "answer": 0, "explain": "A computer can only store binary data. Sound starts out as a continuous analogue wave, so it must be sampled — measured at regular intervals and each measurement stored as binary — before it can be stored at all."}}, {"title": "Sample rate: how often the wave is measured", "html": "<h4>Sample rate: how often the wave is measured</h4>\n<ul>\n<li><strong>Sample rate</strong> is the number of samples taken from the analogue wave <strong>every second</strong>, measured in <strong>hertz (Hz)</strong> (or kilohertz, kHz, where 1 kHz = 1,000 Hz).</li>\n<li>A sample rate of 8,000 Hz means the wave''s amplitude is measured 8,000 separate times, evenly spaced, within a single second of audio.</li>\n</ul>\n<h4>Higher sample rate = closer to the original wave</h4>\n<ul>\n<li>The wave is constantly changing between samples, and none of that in-between detail is captured — it simply is not recorded at all.</li>\n<li>Taking MORE samples per second means the gaps between measurements are smaller, so less of the original wave''s detail is missed. The digital copy ends up a closer match to the real analogue sound — higher playback quality.</li>\n<li>Taking FEWER samples per second leaves bigger gaps, so more detail is lost, and the digital version is a rougher approximation of the original — this can be heard as a noticeably lower-quality recording.</li>\n</ul>\n<h4>Higher sample rate = bigger file</h4>\n<ul>\n<li>Every extra sample taken is another value that has to be stored as a binary number. A higher sample rate therefore always produces MORE samples for the same length of recording, which means a LARGER file size.</li>\n</ul>\n<table>\n<tr><th>Sample rate</th><th>Samples taken in 1 second</th></tr>\n<tr><td>4,000 Hz</td><td>4,000 samples</td></tr>\n<tr><td>8,000 Hz</td><td>8,000 samples</td></tr>\n<tr><td>44,100 Hz (44.1 kHz)</td><td>44,100 samples</td></tr>\n</table>\n<p>44.1 kHz is the sample rate used for standard audio CDs — a real-world example of a high sample rate chosen for good playback quality.</p>", "check": {"question": "A recording uses a sample rate of 6,000 Hz. How many samples are taken from the wave in 2 seconds?", "options": ["12,000 samples", "6,000 samples", "3,000 samples", "18,000 samples"], "answer": 0, "explain": "Samples per second × duration = 6,000 × 2 = 12,000 samples."}}, {"title": "Bit depth: how precisely each sample is measured", "html": "<h4>Bit depth: how precisely each sample is measured</h4>\n<ul>\n<li><strong>Bit depth</strong> (also called <strong>sample resolution</strong>) is the number of <strong>bits</strong> used to store the value of <strong>each individual sample</strong>.</li>\n<li>The number of bits available decides how many different amplitude values a single sample can be rounded to — a bit depth of n bits gives <strong>2<sup>n</sup></strong> possible levels, exactly the same \"2 to the power of n\" rule used for colour depth in images.</li>\n</ul>\n<svg viewBox=\"0 0 230 180\" width=\"230\" height=\"180\" role=\"img\" aria-label=\"Two vertical boxes comparing bit depth: a 2-bit box divided into 4 equal amplitude levels, and a 3-bit box divided into 8 equal amplitude levels, showing that more bits give more possible levels\">\n<rect x=\"10\" y=\"10\" width=\"90\" height=\"160\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"10\" y1=\"50\" x2=\"100\" y2=\"50\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n<line x1=\"10\" y1=\"90\" x2=\"100\" y2=\"90\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n<line x1=\"10\" y1=\"130\" x2=\"100\" y2=\"130\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n<rect x=\"130\" y=\"10\" width=\"90\" height=\"160\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"130\" y1=\"30\" x2=\"220\" y2=\"30\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n<line x1=\"130\" y1=\"50\" x2=\"220\" y2=\"50\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n<line x1=\"130\" y1=\"70\" x2=\"220\" y2=\"70\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n<line x1=\"130\" y1=\"90\" x2=\"220\" y2=\"90\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n<line x1=\"130\" y1=\"110\" x2=\"220\" y2=\"110\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n<line x1=\"130\" y1=\"130\" x2=\"220\" y2=\"130\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n<line x1=\"130\" y1=\"150\" x2=\"220\" y2=\"150\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n</svg>\n<p>Left: a 2-bit depth gives 2<sup>2</sup> = 4 possible amplitude levels for each sample. Right: a 3-bit depth gives 2<sup>3</sup> = 8 possible levels — roughly double the levels for just one extra bit, letting each sample record the wave''s true height far more precisely.</p>\n<h4>Higher bit depth = closer to the original wave</h4>\n<ul>\n<li>With only a few possible levels, each sample has to be rounded to the nearest available level, which can be some distance from the wave''s real height at that instant — this rounding error is heard as background hiss or distortion.</li>\n<li>A higher bit depth gives many more levels to round to, so each sample sits much closer to the wave''s true amplitude, giving a cleaner, higher-quality recording.</li>\n</ul>\n<h4>Higher bit depth = bigger file</h4>\n<ul>\n<li>Every sample stored using MORE bits takes up MORE space, regardless of the sample rate or duration. A higher bit depth therefore always produces a LARGER file size, for exactly the same recording.</li>\n</ul>", "check": {"question": "A sample is stored using a bit depth of 4 bits. How many different amplitude levels can that sample be rounded to?", "options": ["16", "8", "4", "32"], "answer": 0, "explain": "2 to the power of 4 = 16 possible levels."}}, {"title": "Quality vs file size: the trade-off from sample rate and bit depth", "html": "<h4>Both factors push quality and file size the same way</h4>\n<ul>\n<li>Increasing <strong>sample rate</strong> captures the wave more often, giving a closer match to the original — but it means more samples are taken for the same length of recording, so the file gets <strong>bigger</strong>.</li>\n<li>Increasing <strong>bit depth</strong> allows each sample to be measured more precisely — but it means more bits are stored for every single sample, so the file gets <strong>bigger</strong> too.</li>\n<li>There is no way to improve playback quality using either factor without also increasing the file size — it is always a trade-off, exactly as with colour depth and resolution for images.</li>\n</ul>\n<h4>Worked example: doubling the sample rate</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>A 4-second recording uses a sample rate of 5,000 Hz and a bit depth of 8 bits. Find the file size in bits, then bytes, then KB.</td><td>5,000 × 4 × 8 = 160,000 bits → 20,000 bytes → 20 KB</td></tr>\n<tr><td>2</td><td>Double ONLY the sample rate to 10,000 Hz, keeping duration and bit depth the same. Recalculate.</td><td>10,000 × 4 × 8 = 320,000 bits → 40,000 bytes → 40 KB</td></tr>\n<tr><td>3</td><td>Compare the two file sizes.</td><td>40 KB is exactly double the original 20 KB</td></tr>\n</table>\n<h4>Why this differs from the image-doubling trap</h4>\n<ul>\n<li>Doubling ONE sound factor (sample rate) doubles the file size directly — the sound formula multiplies three separate factors together, so doubling any ONE of them (sample rate, duration or bit depth) doubles the file size. This is different from an image, where doubling BOTH height and width together roughly quadruples the file size.</li>\n</ul>", "check": {"question": "A recording''s file size is 20 KB. If you double ONLY the bit depth, keeping sample rate and duration the same, what is the new approximate file size?", "options": ["40 KB", "20 KB", "80 KB", "10 KB"], "answer": 0, "explain": "Doubling any single factor in sample rate × duration × bit depth doubles the file size: 20 KB × 2 = 40 KB."}}, {"title": "Worked example: calculating a sound file''s size", "html": "<h4>The formula</h4>\n<ul>\n<li><strong>File size (bits) = sample rate (Hz) × duration (seconds) × bit depth (bits)</strong></li>\n<li>Always calculate the answer in <strong>bits</strong> first, then convert into whatever unit the question actually asks for.</li>\n</ul>\n<h4>Worked example</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>A 5-second recording is sampled at 8,000 Hz with an 8-bit depth. Multiply sample rate × duration × bit depth.</td><td>8,000 × 5 × 8 = 320,000 bits</td></tr>\n<tr><td>2</td><td>Convert bits into bytes by dividing by 8.</td><td>320,000 ÷ 8 = 40,000 bytes</td></tr>\n<tr><td>3</td><td>Convert bytes into a sensible unit by dividing by 1,000.</td><td>40,000 ÷ 1,000 = 40 KB</td></tr>\n</table>\n<h4>Show every step, every time</h4>\n<ul>\n<li>OCR-style marking usually splits calculation marks between the <strong>working</strong> and the <strong>final answer</strong> — so writing down all three steps (multiply, then ÷8, then ÷1,000) protects your marks even if you slip on the arithmetic somewhere along the way.</li>\n<li>Unless a question tells you otherwise, this formula assumes a single (<strong>mono</strong>) recording channel — see the next section for what changes with stereo sound.</li>\n</ul>", "check": {"question": "A sound is recorded for 3 seconds at a sample rate of 4,000 Hz with a bit depth of 8 bits. What is the file size in KB?", "options": ["12 KB", "96 KB", "1.5 KB", "1,200 KB"], "answer": 0, "explain": "4,000 × 3 × 8 = 96,000 bits. 96,000 ÷ 8 = 12,000 bytes. 12,000 ÷ 1,000 = 12 KB."}}, {"title": "Mono vs stereo: an extra factor in the formula", "html": "<h4>Mono: one channel, the formula as given</h4>\n<ul>\n<li>A <strong>mono</strong> (single-channel) recording stores just ONE stream of samples, so the file size is exactly sample rate × duration × bit depth, with nothing extra to add.</li>\n</ul>\n<h4>Stereo: two channels, double the data</h4>\n<ul>\n<li>A <strong>stereo</strong> recording stores TWO separate channels of samples at once (a \"left\" channel and a \"right\" channel, which is what lets headphones produce a sense of direction). Each channel is sampled using exactly the same sample rate and bit depth.</li>\n<li>Because there are two complete streams of samples instead of one, a stereo recording''s file size is exactly <strong>double</strong> the mono formula''s result: <strong>sample rate × duration × bit depth × 2</strong>.</li>\n</ul>\n<h4>Worked example</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>The same 5-second, 8,000 Hz, 8-bit recording from before is instead recorded in STEREO. Calculate the mono size in bits first.</td><td>8,000 × 5 × 8 = 320,000 bits</td></tr>\n<tr><td>2</td><td>Multiply by 2 for the second (stereo) channel.</td><td>320,000 × 2 = 640,000 bits</td></tr>\n<tr><td>3</td><td>Convert to bytes, then KB, as normal.</td><td>640,000 ÷ 8 = 80,000 bytes; ÷ 1,000 = 80 KB</td></tr>\n</table>\n<h4>Only apply the ×2 when the question says stereo</h4>\n<ul>\n<li>Unless a question specifically tells you the recording is in stereo, always assume <strong>mono</strong> and use the plain formula with no ×2. Adding an unrequested ×2 — or forgetting a genuinely stereo one — is one of the most common slips on this topic.</li>\n</ul>", "check": {"question": "A 2-second recording uses a sample rate of 10,000 Hz and an 8-bit depth, recorded in STEREO. What is its file size in KB?", "options": ["40 KB", "20 KB", "10 KB", "80 KB"], "answer": 0, "explain": "Mono: 10,000 × 2 × 8 = 160,000 bits → 20,000 bytes → 20 KB. Stereo doubles this: 20 × 2 = 40 KB."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Sample", "definition": "One measurement of a sound wave''s amplitude, taken at a single instant"}, {"term": "Sampling", "definition": "Measuring an analogue wave''s amplitude at regular intervals and storing each value as binary"}, {"term": "Analogue sound", "definition": "A continuous signal whose amplitude can take any value as it changes over time"}, {"term": "Sample rate", "definition": "The number of samples taken from a sound wave every second, measured in Hz"}, {"term": "Hertz (Hz)", "definition": "The unit sample rate is measured in — one sample per second"}, {"term": "Bit depth", "definition": "The number of bits used to store the value of each individual sample"}, {"term": "2 to the power of n rule (sound)", "definition": "A bit depth of n bits can represent 2 to the power of n amplitude levels"}, {"term": "Effect of higher sample rate", "definition": "Closer match to the original wave (better quality) but more samples stored (bigger file)"}, {"term": "Effect of higher bit depth", "definition": "Each sample rounded more precisely (better quality) but more bits stored per sample (bigger file)"}, {"term": "Sound file-size formula", "definition": "Sample rate × duration (seconds) × bit depth, giving the size in bits"}, {"term": "Mono recording", "definition": "A recording that stores a single channel of samples"}, {"term": "Stereo recording", "definition": "A recording that stores two channels of samples (left and right)"}, {"term": "Stereo file-size adjustment", "definition": "Double the mono formula''s result — one stream of samples for each channel"}, {"term": "Converting bits to bytes", "definition": "Divide the number of bits by 8"}, {"term": "Converting bytes to kilobytes", "definition": "Divide the number of bytes by 1,000 (this specification''s convention)"}, {"term": "Why sound must be sampled", "definition": "Computers can only store binary data; sampling converts the continuous wave into binary numbers"}, {"term": "Minimum bit depth for N levels", "definition": "The smallest n where 2 to the power of n is at least N"}]}, "mcq": {"enabled": true, "questions": [{"question": "What does ''sample rate'' measure?", "options": ["The number of samples taken from the wave every second", "The number of bits used to store each individual sample", "The total length of a recording, measured in seconds", "The number of separate audio channels a recording uses"], "answer": 0, "explain": "Sample rate is the number of samples taken from the wave every second, measured in Hz."}, {"question": "What does ''bit depth'' measure?", "options": ["The number of bits used to store each individual sample", "The number of samples taken from the wave every second", "The total duration of the recording, measured in seconds", "The number of channels used in a stereo recording"], "answer": 0, "explain": "Bit depth is the number of bits used to store the value of each individual sample."}, {"question": "Which unit is sample rate measured in?", "options": ["Hertz (Hz) — the number of samples taken every second", "Bits per second (bps) — the number of bits transferred every second", "Bytes (B) — the total file size once the recording is saved", "Decibels (dB) — a measurement of how loud the recording sounds"], "answer": 0, "explain": "Sample rate is measured in hertz (Hz) — each hertz means one sample taken per second."}, {"question": "A recording lasts 2 seconds, using a sample rate of 3,000 Hz. How many samples are taken in total?", "options": ["6,000 samples", "3,000 samples", "1,500 samples", "9,000 samples"], "answer": 0, "explain": "Samples per second × duration = 3,000 × 2 = 6,000 samples."}, {"question": "A sample is stored using a bit depth of 5 bits. How many different amplitude levels can it represent?", "options": ["32", "16", "8", "64"], "answer": 0, "explain": "2 to the power of 5 = 32."}, {"question": "Increasing a recording''s sample rate, with bit depth and duration unchanged, has what effect?", "options": ["A closer match to the original wave and a larger file size", "A closer match to the original wave and a smaller file size", "More possible amplitude levels per sample and a larger file size", "No change occurs to either the file size or the playback quality"], "answer": 0, "explain": "A higher sample rate captures the wave more often, giving a closer match to the original — but more samples also means a bigger file."}, {"question": "Increasing a recording''s bit depth, with sample rate and duration unchanged, has what effect?", "options": ["More possible amplitude levels per sample and a larger file size", "More possible amplitude levels per sample and a smaller file size", "More samples taken every second and a larger file size", "No change occurs to either the file size or the playback quality"], "answer": 0, "explain": "A higher bit depth gives more levels to round each sample to (better quality) but stores more bits per sample (bigger file)."}, {"question": "A sound is recorded for 4 seconds at a sample rate of 5,000 Hz with an 8-bit depth. What is the file size in bytes?", "options": ["20,000 bytes", "160,000 bytes", "2,500 bytes", "40,000 bytes"], "answer": 0, "explain": "5,000 × 4 × 8 = 160,000 bits. 160,000 ÷ 8 = 20,000 bytes."}, {"question": "A sound is recorded for 10 seconds at a sample rate of 4,000 Hz with an 8-bit depth. What is the file size in KB?", "options": ["40 KB", "320 KB", "5 KB", "400 KB"], "answer": 0, "explain": "4,000 × 10 × 8 = 320,000 bits. 320,000 ÷ 8 = 40,000 bytes. 40,000 ÷ 1,000 = 40 KB."}, {"question": "A 2-second mono recording at 8,000 Hz with an 8-bit depth is 16 KB. What would the SAME recording be, in KB, if recorded in stereo instead?", "options": ["32 KB", "16 KB", "8 KB", "64 KB"], "answer": 0, "explain": "A stereo recording doubles the mono file size: 16 KB × 2 = 32 KB."}, {"question": "Which statement about analogue and digital sound is correct?", "options": ["Analogue sound is continuous; sampling converts it into a stream of binary numbers", "Analogue sound is already stored as binary numbers before any sampling ever takes place", "Sampling converts an already-digital recording back into a continuous analogue wave again", "A microphone stores sound directly as a fixed sample rate and bit depth, with no wave"], "answer": 0, "explain": "Analogue sound is a continuous wave; sampling measures it at intervals and stores each measurement as binary — the reverse of options 2 and 3."}, {"question": "A memory card can hold 2,000 KB of audio. Each mono recording made on it is 40 KB. Roughly how many of these recordings will fit?", "options": ["50 recordings", "20 recordings", "80 recordings", "500 recordings"], "answer": 0, "explain": "2,000 ÷ 40 = 50 recordings."}]}, "fib": {"enabled": true, "questions": [{"text": "Real sound is an [analogue] signal, and its amplitude can take any value as it changes over time."}, {"text": "The process of measuring an analogue wave''s amplitude at regular intervals and storing each value as binary is called [sampling]."}, {"text": "Sample rate is measured in [hertz], the number of samples taken every second."}, {"text": "Bit depth is the number of [bits] used to store the value of each individual sample."}, {"text": "The formula for a sound file''s size is sample rate × duration × [bit depth]."}, {"text": "A higher sample rate and a higher bit depth both increase file size, but improve the recording''s playback [quality]."}, {"text": "A recording that stores two separate channels (left and right) is called [stereo], and its file size is double a mono recording''s."}, {"text": "A sound file-size calculation should always be worked out in [bits] first, then converted into the unit the question asks for."}]}, "tf": {"enabled": true, "questions": [{"statement": "Sound is an analogue signal before it is sampled.", "answer": true, "explain": "Correct — real sound is a continuous analogue wave; sampling converts it into digital data."}, {"statement": "Sample rate measures the number of bits used to store each sample.", "answer": false, "explain": "That describes bit depth, not sample rate. Sample rate is the number of samples taken every second, measured in Hz."}, {"statement": "A higher sample rate always produces a larger file, for the same duration and bit depth.", "answer": true, "explain": "Correct — more samples per second means more values to store, so the file size increases."}, {"statement": "A higher bit depth means each sample can be rounded to more possible amplitude levels.", "answer": true, "explain": "Correct — a bit depth of n bits gives 2 to the power of n possible levels, so more bits means more levels."}, {"statement": "Increasing bit depth improves quality with no effect on file size.", "answer": false, "explain": "There is always a trade-off — more bits stored per sample also increases the file size."}, {"statement": "The sound file-size formula is sample rate × duration × bit depth.", "answer": true, "explain": "Correct — file size in bits = sample rate × duration × bit depth."}, {"statement": "A stereo recording''s file size is calculated using exactly the same formula as a mono recording, with no adjustment.", "answer": false, "explain": "A stereo recording stores two channels, so its file size is double the mono formula''s result (× 2)."}, {"statement": "A file-size calculation using the sound formula should be left in bits as the final answer, even if the question asks for KB.", "answer": false, "explain": "The formula gives bits first, but that is only the first step — convert (÷8 for bytes, ÷1,000 per unit after that) into whatever unit the question actually asks for."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking sample rate and bit depth measure the same thing.", "truth": "<strong>Sample rate</strong> is how OFTEN the wave is measured (samples per second, in Hz). <strong>Bit depth</strong> is how PRECISELY each individual sample is measured (bits per sample). They are two separate, independent factors.", "check": {"question": "Which statement correctly distinguishes sample rate from bit depth?", "options": ["Sample rate is samples per second; bit depth is bits used per sample", "Sample rate and bit depth both measure exactly the same thing", "Bit depth is samples per second; sample rate is bits used per sample instead", "Sample rate measures loudness; bit depth measures the recording''s duration"], "answer": 0, "explain": "Sample rate = how often (Hz); bit depth = how precisely (bits per sample) — two separate properties of a digital recording."}}, {"myth": "Thinking a bit depth of n bits gives n possible amplitude levels — e.g. assuming 4 bits means 4 levels.", "truth": "It is <strong>2 to the power of n</strong>, not n. A bit depth of 4 bits gives 2<sup>4</sup> = <strong>16</strong> possible levels, not 4 — exactly the same rule used for colour depth in images.", "check": {"question": "A bit depth of 4 bits is used. How many different amplitude levels can each sample represent?", "options": ["4", "8", "16", "20"], "answer": 2, "explain": "2 to the power of 4 = 16, not 4. Bit depth and number of levels are related by 2 to the power of n, not a simple count."}}, {"myth": "Leaving a sound file-size calculation answer in bits, because the multiplication already produced ''a number'' that looks like an answer.", "truth": "Sample rate × duration × bit depth always gives the answer in <strong>bits</strong> first — that is only the first step. You must then divide by 8 to reach bytes, and keep dividing by 1,000 for each unit up the ladder until you reach the unit the question actually asked for.", "check": {"question": "A calculation gives 160,000 bits, and the question asks for the answer in KB. What should you do next?", "options": ["Divide by 8 to get bytes, then divide by 1,000 to get KB", "Write down 160,000 as the final answer, already correct in KB", "Multiply the bits total by 8 to reach bytes", "Divide the bits total by 1,000 only, then stop working"], "answer": 0, "explain": "160,000 bits ÷ 8 = 20,000 bytes, then ÷ 1,000 = 20 KB. Both conversion steps are needed to reach the unit asked for."}}, {"myth": "Forgetting to double the file size for a stereo recording, or doubling one that is actually mono.", "truth": "Only apply <strong>×2</strong> when a question specifically says the recording is <strong>stereo</strong> (two channels). A plain sample-rate × duration × bit-depth calculation already assumes <strong>mono</strong> (one channel) unless told otherwise.", "check": {"question": "A question gives a sample rate, duration and bit depth but does not mention stereo or mono. Which should you assume?", "options": ["Mono — use the plain formula with no ×2", "Stereo — always multiply the plain formula by 2", "It cannot be calculated without being told which one it is", "Both channels — divide the plain formula by 2 instead"], "answer": 0, "explain": "Unless a question specifically states the recording is stereo, assume mono and use the plain formula (no ×2)."}}, {"myth": "Believing that increasing sample rate only affects file size with no effect on quality, or that bit depth only affects quality with no effect on file size.", "truth": "Both factors affect BOTH things. A higher sample rate AND a higher bit depth each improve playback quality AND increase file size — neither factor affects only one of the two.", "check": {"question": "Which statement about sample rate and bit depth is correct?", "options": ["Both factors affect quality AND file size, not just one or the other", "Sample rate only ever affects file size; bit depth only ever affects quality", "Bit depth only ever affects file size; sample rate only ever affects quality", "Neither sample rate nor bit depth has any real effect on quality at all"], "answer": 0, "explain": "Both sample rate and bit depth affect BOTH playback quality and file size — that is exactly why the topic is a trade-off."}}, {"myth": "Assuming sound is already stored as binary before it reaches the computer, so no conversion process is needed.", "truth": "Real sound is an <strong>analogue</strong> signal — a continuous wave, not binary data. It must be <strong>sampled</strong> (its amplitude measured at regular intervals and each measurement stored as a binary number) before a computer can store it at all.", "check": {"question": "Why can''t a computer store an analogue sound wave directly, without first sampling it?", "options": ["The wave is continuous, but computers can only store data as binary numbers", "Microphones are only ever able to physically produce a binary electrical signal", "Analogue sound waves cannot physically be recorded by any microphone at all", "Computers can already store analogue waves directly, so sampling is not needed"], "answer": 0, "explain": "Analogue sound is a continuous signal; a computer can only store binary data, so the wave must be sampled and each measurement stored as a binary number."}}]}, "tips": {"enabled": true, "items": [{"title": "Show-your-working ladder: the sound file-size calculation", "html": "<p>A typical question: <em>\"A recording lasts 3 seconds, sampled at 5,000 Hz with an 8-bit depth. Calculate the file size in bytes. Show your working.\"</em> [2 marks] Here is the same answer at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"15,000 bytes\"</p>\n<ul>\n<li>No working shown. Even a correct final answer with nothing behind it risks losing the working mark entirely if it happens to be wrong.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"5,000 × 3 × 8 = 120,000\"</p>\n<ul>\n<li>Valid working is shown (1 mark), but the answer was never converted into bytes and stated as a final answer — the second mark is for the CONVERTED answer in the unit asked for.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"5,000 × 3 × 8 = 120,000 bits <strong>(1)</strong>. 120,000 ÷ 8 = 15,000 bytes <strong>(1)</strong>.\"</p>\n\n<p><strong>Why this matters even if your arithmetic slips:</strong> OCR-style marking separates the WORKING mark from the ANSWER mark. If your method is correct but you slip on the final division, you can still keep the working mark — but only if you actually wrote the working down.</p>", "check": {"question": "You calculate 5,000 × 3 × 8 = 120,000 correctly, but then wrongly divide by 100 instead of 8 and write ''1,200 bytes''. What mark do you get out of 2?", "options": ["0, because the final stated answer is wrong", "1 — the working mark for the correct multiplication step", "2, since your working clearly shows you understood the method", "It depends entirely on which calculator you used"], "answer": 1, "explain": "The multiplication step (5,000 × 3 × 8 = 120,000 bits) is valid working, so it earns the working mark even though the final conversion — and therefore the answer mark — was wrong."}}, {"title": "2 to the power of n levels: don''t just double the bit depth", "html": "<p>Bit depth questions trip students up in one of two directions — going from bit depth to levels, or levels back to bit depth. Both need the SAME rule: <strong>2 to the power of the bit depth</strong>, never the bit depth multiplied by 2.</p>\n\n<p><strong>Direction 1 — bit depth → number of levels:</strong> raise 2 to the power of the given bit depth. A bit depth of 5 bits gives 2<sup>5</sup> = 32 levels, NOT 5 × 2 = 10.</p>\n\n<p><strong>Direction 2 — number of levels → minimum bit depth:</strong> try increasing bit depths and calculate 2<sup>n</sup> for each one until the result is big enough. Needing at least 100 levels? 2<sup>6</sup> = 64 (too few), 2<sup>7</sup> = 128 (enough) — so the minimum bit depth is 7 bits.</p>\n\n<p><strong>The trap to avoid:</strong> confusing bit depth (precision of each sample) with sample rate (how often samples are taken). \"How many levels\" is always a bit depth question; \"how many samples per second\" is always a sample-rate question — they never use the same formula.</p>", "check": {"question": "A bit depth of 3 bits is doubled to a bit depth of 6 bits. What happens to the number of possible amplitude levels?", "options": ["It rises from 8 to 64, not simply doubling to 16", "It exactly doubles, rising from 8 to 16", "It stays exactly the same at 8 levels", "It rises to 24 levels only, since 3 multiplied by 6 equals 18 which is then rounded"], "answer": 0, "explain": "2 to the power of 3 = 8 and 2 to the power of 6 = 64. Doubling the bit depth does not double the number of levels — it multiplies it by a far bigger factor."}}, {"title": "Command-word ladder: ''state'' vs ''explain'' for the quality/size trade-off", "html": "<p>The same underlying knowledge — that increasing sample rate or bit depth affects both quality and file size — is tested at very different tariffs depending on the command word used.</p>\n\n<p><strong>\"State\" (1–2 marks):</strong> a single, direct fact is enough. <em>\"State the effect of increasing a recording''s sample rate on its file size.\"</em> → \"It increases the file size.\" One clear statement, no reasoning required.</p>\n\n<p><strong>\"Explain\" (3–4 marks):</strong> needs the full <em>point → …which means… → consequence</em> chain, not just the fact. <em>\"Explain the effect of increasing a recording''s sample rate.\"</em></p>\n<ul>\n<li><strong>Point:</strong> \"A higher sample rate takes more samples of the wave every second…\"</li>\n<li><strong>…which means…:</strong> \"…so less of the original wave''s detail is missed between samples, giving a closer match to the original sound…\"</li>\n<li><strong>…but the consequence is…:</strong> \"…while also increasing the overall file size, because more samples have to be stored for the same length of recording.\"</li>\n</ul>\n\n<p><strong>Why the chain matters:</strong> a bare \"state\" answer scores 0 on an \"explain\" question, because it stops after the first link — the examiner is specifically paying for the \"…which means…\" development, not just the initial fact.</p>", "check": {"question": "A 3-mark ''explain'' question asks about the effect of increasing bit depth. A student writes only ''It makes the file size bigger.'' How many of the 3 marks would this likely earn?", "options": ["Likely just 1 mark — a bare statement with no development chain", "All 3 marks, since the key fact given is completely correct", "0 marks, because the statement given is factually wrong", "2 marks, for correctly identifying file size as the affected factor"], "answer": 0, "explain": "An ''explain'' question needs the point developed with a ''which means...'' chain (more bits → more precise levels, but also more data to store). A bare fact with no development usually only reaches the first mark."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick (✓) <strong>one</strong> box to identify the correct definition of sampling.</p>", "marks": 1, "hint": "Sampling is about CAPTURING the wave, not compressing or playing it back.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Measuring an analogue wave''s amplitude at regular intervals and storing each as binary</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept cross or other indication as long as it is clear which one box is intended.</li>\n<li>2+ ticks = 0 marks.</li>\n</ul>\n</div>"}, {"question": "<p>A recording lasts 3 seconds at a sample rate of 4,000 Hz. Tick (✓) <strong>one</strong> box to identify how many samples are taken in total.</p>", "marks": 1, "hint": "Samples per second × duration in seconds.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>12,000 samples</strong>. Working: 4,000 × 3 = 12,000.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; there is no credit for a value calculated using the wrong method.</li>\n</ul>\n</div>"}, {"question": "<p>State what is meant by the term <strong>bit depth</strong> when describing a sampled sound.</p>", "marks": 1, "hint": "Answer in terms of bits per sample, not samples per second.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>The number of bits used to store the value of each individual sample</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not accept a description of sample rate instead of bits-per-sample.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how one of the app''s voice memos is represented and stored as binary data.</p>", "marks": 3, "hint": "Work through the chain: what kind of signal sound starts as, what happens to it at regular intervals, and what each measurement becomes.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point to max 3)</h5>\n<ul>\n<li>The voice memo begins as an analogue sound wave (continuous, not yet in binary)</li>\n<li>The wave''s amplitude is sampled — measured at regular time intervals</li>\n<li>Each sample is stored as a binary number, using the number of bits set by the bit depth</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per point to a maximum of 3. Accept any equivalent correct wording.</li>\n</ul>\n</div>"}, {"question": "<p>A memo is recorded for 6 seconds at a sample rate of 8,000 Hz with an 8-bit depth. Tick (✓) <strong>one</strong> box to identify its file size in bytes.</p>", "marks": 1, "hint": "Work out bits first (sample rate × duration × bit depth), then divide by 8 to reach bytes.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>48,000 bytes</strong>. Working: 8,000 × 6 × 8 = 384,000 bits; 384,000 ÷ 8 = 48,000 bytes.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores.</li>\n</ul>\n</div>"}, {"question": "<p>Each memo the app records lasts 4 seconds, using a sample rate of 6,000 Hz and a bit depth of 8 bits. Calculate the file size of one memo, in bytes. Show your working.</p>", "marks": 2, "hint": "Use sample rate × duration × bit depth to get bits first, then divide by 8 for bytes.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working, e.g. 6,000 × 4 × 8 = 192,000 (bits)</li>\n<li>1 mark for the answer: 24,000 bytes</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any correct method that reaches bits first, then converts to bytes by dividing by 8.</li>\n<li>Award the working mark even if the final answer is wrong, provided the method shown is valid.</li>\n</ul>\n</div>"}, {"question": "<p>The app developer wants to increase quality by raising the bit depth from 8 bits to 16 bits, keeping the sample rate (6,000 Hz) and duration (4 seconds) the same as the 24,000-byte (24 KB) memo calculated earlier.</p><p>Calculate the new file size in KB, and state how many times bigger it is than the original 24 KB memo. Show your working.</p>", "marks": 4, "hint": "Find the new file size the same way as before (sample rate × duration × bit depth, then ÷8 and ÷1,000), then compare your new KB figure to the original 24 KB.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: 6,000 × 4 × 16 = 384,000 (bits)</li>\n<li>1 mark: 384,000 ÷ 8 = 48,000 (bytes); 48,000 ÷ 1,000 = 48 (KB)</li>\n<li>1 mark for the answer: 48 KB</li>\n<li>1 mark: correctly states this is 2 times bigger than the original 24 KB (48 ÷ 24 = 2)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Own-figure/follow-through applies to the comparison mark — it can be awarded using the candidate''s own file-size figure, provided the comparison method is correct.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how increasing the sample rate used to record one of the radio drama''s episodes, and increasing its bit depth, would each affect the episode''s file size and its playback quality.</p>", "marks": 4, "hint": "Two separate factors — sample rate and bit depth — and for EACH one you need both its effect on file size AND its effect on quality.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: higher sample rate increases file size (more samples stored)</li>\n<li>1 mark: higher sample rate improves quality (closer match to the original wave)</li>\n<li>1 mark: higher bit depth increases file size (more bits per sample)</li>\n<li>1 mark: higher bit depth improves quality (each sample rounded more precisely)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Full marks needs both sample rate and bit depth addressed, with both the file-size effect AND the quality effect given for each.</li>\n</ul>\n</div>"}, {"question": "<p>A birdsong recorder uses a bit depth of 6 bits per sample. Calculate the number of different amplitude levels each sample can represent.</p>", "marks": 1, "hint": "2 to the power of the bit depth.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>64 (2 to the power of 6)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct value scores; no credit for a value found using the wrong method.</li>\n</ul>\n</div>"}, {"question": "<p>The charity''s software needs to store each sample using enough bits to represent AT LEAST 200 different amplitude levels. Calculate the minimum bit depth, in bits, needed to achieve this. Show your working.</p>", "marks": 2, "hint": "Try increasing bit depths and calculate 2 to the power of n for each one until the result is at least 200.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for valid working, e.g. 2 to the power of 7 = 128 (too few), 2 to the power of 8 = 256 (enough)</li>\n<li>1 mark for the answer: 8 bits</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award the working mark for any method that correctly tests powers of 2 against the 200-level target, even if the final answer is wrong.</li>\n</ul>\n</div>"}, {"question": "<p>Complete the table by calculating the number of different amplitude levels that each bit depth can represent.</p>", "marks": 4, "hint": "Work out 2 to the power of each bit depth given in the left-hand column.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>2-bit = 4 levels</li>\n<li>4-bit = 16 levels</li>\n<li>6-bit = 64 levels</li>\n<li>9-bit = 512 levels</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept the numeric value with or without a comma.</li>\n<li>Each row is marked independently.</li>\n</ul>\n</div>"}, {"question": "<p>Tick (✓) <strong>one</strong> box in each row to identify the file size, in bytes, of the recording described.</p>", "marks": 4, "hint": "Work out sample rate × duration × bit depth in bits for each row, then divide by 8 to reach bytes, before matching to a column. Two different rows can share the same correct column.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Row 1 (1,000 Hz, 4s, 8-bit): 1,000 × 4 × 8 = 32,000 bits = <strong>4,000 bytes</strong></li>\n<li>Row 2 (500 Hz, 4s, 8-bit): 500 × 4 × 8 = 16,000 bits = <strong>2,000 bytes</strong></li>\n<li>Row 3 (1,000 Hz, 2s, 8-bit): 1,000 × 2 × 8 = 16,000 bits = <strong>2,000 bytes</strong></li>\n<li>Row 4 (1,000 Hz, 4s, 2-bit): 1,000 × 4 × 2 = 8,000 bits = <strong>1,000 bytes</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Two different rows can share the same correct column (rows 2 and 3 are both 2,000 bytes).</li>\n<li>Extra ticks in a row score 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>The charity recorded two 2-second birdsong clips: Clip 1 was sampled at 4,000 Hz with an 8-bit depth; Clip 2 was sampled at 16,000 Hz with a 4-bit depth.</p><p>State which clip has the larger file size, and explain your reasoning by comparing the two calculations.</p>", "marks": 3, "hint": "Calculate (or compare) both file sizes fully — a higher bit depth alone does not automatically mean a bigger file if the sample rate is much lower.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point to max 3)</h5>\n<ul>\n<li>Clip 1''s file size is correctly found: 4,000 × 2 × 8 = 64,000 bits (8,000 bytes)</li>\n<li>Clip 2''s file size is correctly found: 16,000 × 2 × 4 = 128,000 bits (16,000 bytes)</li>\n<li>Correct conclusion that Clip 2 has the larger file size, because its higher sample rate outweighs its lower bit depth (16,000 bytes is greater than 8,000 bytes)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per point to a maximum of 3. The conclusion mark requires a correct comparison of the two calculated sizes, not just a guess.</li>\n</ul>\n</div>"}, {"question": "<p>The radio station is deciding on recording settings for the drama series. Setting A uses a high sample rate and high bit depth, producing the best-quality audio but larger files. Setting B uses a lower sample rate and lower bit depth, producing smaller files but lower-quality audio.</p><p>Discuss the impact that choosing between Setting A and Setting B could have on the station''s fixed server storage, across a full series of episodes.</p><p>In your answer you might consider:</p><ul><li>how sample rate and bit depth affect file size</li><li>the effect on how many episodes can be stored within the server''s fixed storage</li><li>the effect on the listening experience for the station''s audience</li><li>which setting you would recommend, and why</li></ul>", "marks": 8, "hint": "Use all four bullets as your plan. Explain the mechanism (bigger files → fewer episodes fit), follow it through to a REAL consequence for the station, and weigh audio quality against storage space for a top-band answer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (levelled) — indicative content</h5>\n<p>The following is indicative of possible factors/evidence that candidates may refer to but is not prescriptive or exhaustive:</p>\n<ul>\n<li><strong>How sample rate/bit depth affect file size</strong> — Setting A''s higher sample rate takes more samples every second, and its higher bit depth stores more bits per sample; both increase file size (bits = sample rate × duration × bit depth). Setting B''s lower values mean a smaller file size per episode.</li>\n<li><strong>Effect on how many episodes fit</strong> — the server''s storage is fixed, so larger Setting A episodes mean fewer episodes (or a shorter series) can be stored; Setting B''s smaller episodes mean many more can be stored before the server fills up.</li>\n<li><strong>Effect on the listening experience</strong> — Setting A''s higher quality audio may matter for a drama relying on subtle sound effects and music, but running out of server space could mean the station cannot upload later episodes; Setting B allows the whole series to be hosted but with audio that sounds noticeably less crisp or detailed.</li>\n<li><strong>Recommendation</strong> — the better choice depends on the station''s actual priorities: Setting A suits a shorter, high-production-value series where audio quality is central, Setting B suits a longer series where hosting every episode within the fixed storage matters more than the finest audio detail.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>Mark Band 3 — High Level (6–8 marks):</strong> Thorough knowledge and understanding of sample rate, bit depth and file-size capacity, applied directly and consistently to the radio station context. The response weighs up both settings (quality against storage/quantity) and covers all four areas from the bullet list with clear, logically structured reasoning, ending in a justified recommendation.</li>\n<li><strong>Mark Band 2 — Mid Level (3–5 marks):</strong> Reasonable knowledge, generally accurate but at times underdeveloped or only partly applied to the radio station context. Most of the four areas are addressed, with some structure, though the discussion may not fully weigh both settings or the recommendation may be unjustified.</li>\n<li><strong>Mark Band 1 — Low Level (1–2 marks):</strong> Basic knowledge with limited understanding shown; the material may contain inaccuracies or barely refer to the radio station context. Little more than an unsupported assertion, e.g. \"Setting A is better\" with no working explanation of why.</li>\n<li><strong>0 marks:</strong> No attempt to answer the question or response is not worthy of credit.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-2-8-compression', '1.2.8 Compression', '{"learn": {"enabled": true, "items": [{"title": "Why do computer files need to be compressed?", "html": "<h4>The three real-world pressures behind compression</h4>\n<ul>\n<li>A <strong>compressed</strong> file has been processed so that it takes up <strong>less storage space</strong> than the original, uncompressed file.</li>\n<li>Smaller files mean more of them fit on a limited storage device — a phone, a memory card, a company''s servers — without having to buy extra storage.</li>\n<li>Smaller files also <strong>transfer faster</strong>: they take less time to upload to a website, download onto a device, or send as an email attachment.</li>\n<li>Every network connection has a maximum <strong>bandwidth</strong> — the amount of data it can carry in a given time. Compressed files use less of that bandwidth, which matters when many people share the same connection (e.g. a school Wi-Fi network) or when a connection is slow.</li>\n<li><strong>Streaming</strong> video or music depends on compression: an uncompressed film would be far too large to send fast enough to play smoothly as it arrives, so it has to be compressed first.</li>\n</ul>\n<h4>The trade-off compression always involves</h4>\n<ul>\n<li>Compression is not free — reducing a file''s size always means changing HOW the data is stored, and, for one of the two methods you need to know, can mean losing some of the original data permanently.</li>\n<li>This is exactly why there are two different approaches, <strong>lossy</strong> and <strong>lossless</strong>, and why choosing the right one for a given file is itself an exam skill.</li>\n</ul>", "check": {"question": "A company wants to publish its training videos on its website. Which of these is a genuine reason to compress the video files first?", "options": ["It stops the videos from being copied or downloaded by any visitor to the site", "It reduces the video files'' size, so less server storage is used and streaming is faster", "It automatically improves the resolution and colour quality of every video without recompressing it", "It converts the videos into a file type that only the company''s own website is able to open"], "answer": 1, "explain": "Smaller video files need less server storage, transfer more quickly, and use less of the network''s limited bandwidth — the three real reasons files are compressed."}}, {"title": "What is lossy compression?", "html": "<h4>The definition</h4>\n<ul>\n<li><strong>Lossy compression</strong> permanently removes some of a file''s data during compression. It targets detail that people are <strong>less likely to notice</strong> — for example, very subtle colour differences in an image, or extremely high or low sound frequencies in an audio file.</li>\n<li>Because data is genuinely thrown away, the file <strong>cannot be restored to its exact original state</strong> once it has been compressed — decompressing it gives a close copy, not an identical one.</li>\n</ul>\n<h4>What lossy compression is good at</h4>\n<ul>\n<li>It produces a <strong>much smaller file size</strong> than lossless compression can usually achieve on the same content, because it isn''t forced to keep every bit.</li>\n<li>The trade-off is a <strong>reduction in quality</strong> — but for the file types it''s normally used on, that reduction is small enough that most people never notice it.</li>\n</ul>\n<h4>Where it is normally used</h4>\n<ul>\n<li>Lossy compression suits <strong>images, audio and video</strong> — files where a small, targeted loss of detail is very unlikely to be noticed, but a big drop in file size is extremely valuable (streaming, uploading photos, downloading music).</li>\n<li>It is not suitable for files where every bit matters, such as text documents or program code — that''s covered on the next card.</li>\n</ul>", "check": {"question": "Why can a file compressed with lossy compression never be restored to its exact original state?", "options": ["Because lossy compression always encrypts the file with a password", "Because some of the original data was permanently removed and cannot be recovered", "Because lossy compression can only ever be applied to files that were never saved correctly", "Because the file format automatically changes every time it is opened"], "answer": 1, "explain": "Lossy compression deletes some data as part of shrinking the file. That data is gone for good, so decompressing produces a close approximation, not the exact original."}}, {"title": "What is lossless compression?", "html": "<h4>The definition</h4>\n<ul>\n<li><strong>Lossless compression</strong> removes no data at all. Instead, it stores the same information in a more efficient way, so the file still shrinks — but nothing is thrown away.</li>\n<li>Because no data is lost, the original file can be <strong>reconstructed exactly</strong>, bit for bit, when it is decompressed.</li>\n</ul>\n<h4>What lossless compression is good at</h4>\n<ul>\n<li>It guarantees the decompressed file is <strong>identical</strong> to the file before it was compressed — every character, formula, pixel or instruction is preserved.</li>\n<li>The trade-off is that it usually achieves a <strong>smaller reduction</strong> in file size than lossy compression manages on the same content, since it isn''t allowed to discard anything.</li>\n</ul>\n<h4>Where it is normally used</h4>\n<ul>\n<li>Lossless compression is required for files where <strong>every bit matters</strong>: text documents, spreadsheets, program code, and some images where exact detail is essential (e.g. a company logo or a diagram with fine lines).</li>\n<li>If a spreadsheet''s formulas or a program''s code were compressed using a lossy method, even one permanently altered character could break the formula or stop the program running — which is why lossless is the only safe choice for these file types.</li>\n</ul>", "check": {"question": "A company''s source code for its main product must be compressed before being backed up. Why must lossless compression be used rather than lossy?", "options": ["Because lossless compression always produces a much smaller file size than lossy compression ever manages", "Because source code files are too large for lossy compression to work on", "Because even one permanently altered character could break the code, so nothing can be safely discarded", "Because lossy compression can only be applied to image and audio files"], "answer": 2, "explain": "Program code needs every character to be exact. Lossless compression guarantees the decompressed code is identical to the original, whereas lossy compression could permanently corrupt it."}}, {"title": "Lossy vs lossless: the real difference", "html": "<h4>Side by side</h4>\n<table>\n<tr><th>Factor</th><th>Lossy compression</th><th>Lossless compression</th></tr>\n<tr><td>Data removed?</td><td>Yes — permanently</td><td>No — none at all</td></tr>\n<tr><td>Can the original be restored exactly?</td><td>No — only a close approximation</td><td>Yes — exactly, bit for bit</td></tr>\n<tr><td>Typical size reduction</td><td>Much larger reduction</td><td>Smaller reduction</td></tr>\n<tr><td>Best suited to</td><td>Images, audio, video</td><td>Text, spreadsheets, program code, some images</td></tr>\n</table>\n<h4>The trap examiners set</h4>\n<ul>\n<li>Students often describe the difference by WHERE each type is used (\"lossy is for pictures, lossless is for documents\") instead of describing the actual mechanism — WHAT happens to the data itself. A full-marks \"explain the difference\" answer must state that one method removes data permanently and the other does not, before (or as well as) giving an example.</li>\n<li>Neither type is simply \"better\" than the other. Lossy compression is not a worse or broken version of lossless — it is the right tool when a smaller file matters more than keeping every bit, and lossless is the right tool when accuracy matters more than file size.</li>\n</ul>", "check": {"question": "Which sentence correctly explains the difference between lossy and lossless compression, rather than just naming where each is used?", "options": ["Lossy compression is for photos and music; lossless compression is for documents and code", "Lossy compression permanently removes data so it can''t be restored exactly; lossless removes none, so it can", "Lossy compression is simply an older and worse technique that lossless compression has now completely replaced everywhere", "Lossy compression makes files bigger, while lossless compression makes files smaller"], "answer": 1, "explain": "A full explanation describes the mechanism — whether data is permanently removed or not — not just a list of example file types."}}, {"title": "Choosing and justifying lossy or lossless for a scenario", "html": "<h4>The two questions to ask</h4>\n<ul>\n<li><strong>1. Does every bit of this file matter?</strong> If losing even a small amount of detail would make the file wrong, broken or unusable (text, spreadsheets, code, some images), lossless is required.</li>\n<li><strong>2. Would a small, unnoticeable loss of detail be an acceptable trade-off for a much smaller, faster-moving file?</strong> If so (typical images, audio, video, especially for streaming or upload/download), lossy is usually the better choice.</li>\n</ul>\n<h4>How to structure a \"choose and justify\" answer</h4>\n<ul>\n<li><strong>Commit to ONE type first</strong> — lossy OR lossless, stated clearly. Do not hedge by describing both types and refusing to pick.</li>\n<li><strong>Then give reasons that only make sense for that chosen type</strong>, linked to the specific scenario in the question (storage limits, network speed, how critical exact accuracy is).</li>\n<li>A reason that actually supports the OTHER type earns nothing, even if it''s a true statement — justification marks are awarded only when the reason matches the choice.</li>\n</ul>\n<h4>Worked example</h4>\n<table>\n<tr><th>Scenario detail</th><th>What it tells you</th></tr>\n<tr><td>\"Users expect a song to start playing within a couple of seconds\"</td><td>Points to lossy — a much smaller file streams and starts playing faster</td></tr>\n<tr><td>\"The documents must remain word-for-word readable forever\"</td><td>Points to lossless — no detail can ever be permanently lost</td></tr>\n</table>", "check": {"question": "A justify-your-choice answer states: ''Lossy compression, because it never loses any of the original data.'' Why does this earn no justification marks?", "options": ["Because lossy compression justification questions are never actually worth any marks on this topic at all", "Because the reason given actually describes lossless compression, not the lossy choice that was made", "Because the answer is too short to be marked at all", "Because only lossless compression can ever be justified in an exam answer"], "answer": 1, "explain": "The stated reason contradicts the chosen type — ''never loses any data'' describes lossless compression, so it cannot support a lossy choice and earns nothing."}}, {"title": "Compression in the real world", "html": "<h4>Formats you may see named in a question</h4>\n<ul>\n<li><strong>JPEG</strong> — a widely used <strong>lossy</strong> format for photographs, where a small loss of detail keeps file sizes manageable for cameras, phones and websites.</li>\n<li><strong>MP3</strong> — a widely used <strong>lossy</strong> format for music and audio, removing sound detail that is largely inaudible to most listeners.</li>\n<li><strong>PNG</strong> — a <strong>lossless</strong> image format, often chosen for logos, screenshots and diagrams where sharp, exact edges and colours must be kept.</li>\n<li><strong>ZIP</strong> — a <strong>lossless</strong> format for bundling and shrinking any file type, commonly used for documents, program files and email attachments where nothing can be safely discarded.</li>\n</ul>\n<h4>What the exam does and does not expect</h4>\n<ul>\n<li>You are expected to know that lossy and lossless compression exist, understand what each one does to the data, and be able to choose and justify one for a scenario.</li>\n<li>You are <strong>not</strong> expected to know the internal algorithm any of these formats actually use, or to perform a compression calculation by hand — the specification for this topic is conceptual, not calculation-based.</li>\n</ul>", "check": {"question": "Which pair correctly matches a real-world file format to the type of compression it is known for?", "options": ["ZIP uses lossy compression, and JPEG uses lossless compression", "MP3 uses lossless compression, and PNG uses lossy compression", "JPEG uses lossy compression, and PNG uses lossless compression", "ZIP and MP3 both use exactly the same lossy compression method"], "answer": 2, "explain": "JPEG (photos) and MP3 (audio) are well-known lossy formats; PNG (images needing exact detail) and ZIP (general files) are well-known lossless formats."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Compression", "definition": "Reducing a file''s size so it uses less storage or transfers faster"}, {"term": "Lossy compression", "definition": "Permanently removes some data — the file cannot be restored exactly"}, {"term": "Lossless compression", "definition": "Removes no data at all — the file can be restored exactly"}, {"term": "Bandwidth", "definition": "The maximum amount of data a network connection can carry in a given time"}, {"term": "Streaming", "definition": "Playing audio/video from the internet as it downloads, without saving the whole file first"}, {"term": "Why compression saves storage", "definition": "Smaller files mean more of them fit on a limited storage device"}, {"term": "Why compression speeds up transfer", "definition": "Smaller files upload, download and stream faster, using less bandwidth"}, {"term": "ZIP", "definition": "A real-world lossless compression format, often used for documents and program files"}, {"term": "JPEG", "definition": "A real-world lossy compression format, commonly used for photographs"}, {"term": "MP3", "definition": "A real-world lossy compression format, commonly used for music/audio"}, {"term": "PNG", "definition": "A real-world lossless image format, used where exact pixel detail matters"}, {"term": "Quality loss (lossy)", "definition": "The reduction in a file''s quality caused by permanently discarding some data"}, {"term": "Exact reconstruction (lossless)", "definition": "Decompressing recreates the file bit-for-bit identical to the original"}, {"term": "Files suited to lossy compression", "definition": "Images, audio and video, where minor detail loss often goes unnoticed"}, {"term": "Files suited to lossless compression", "definition": "Text, spreadsheets, program code, and images needing exact detail"}, {"term": "Upload", "definition": "Sending a file from a device to a server or website over a network"}, {"term": "Download", "definition": "Receiving a file from a server or website onto a device over a network"}, {"term": "The size vs quality trade-off", "definition": "Lossy compression trades a permanent quality loss for a much smaller file size"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is the main effect of compressing a computer file?", "options": ["The file becomes password protected so that only certain people can open it", "The file''s size is reduced, so it needs less storage space and transfers faster", "The file''s contents are automatically translated into a completely different language", "The file is permanently deleted from the device and moved into an online backup"], "answer": 1, "explain": "Compression reduces a file''s size, which means it uses less storage and transfers more quickly — it does not change what the file contains or does."}, {"question": "Which statement correctly describes lossy compression?", "options": ["It permanently removes some of the original data, so the file cannot be restored exactly afterwards", "It keeps every single piece of the original data, so nothing is ever removed from the file at any point", "It only ever works correctly on text files, and it cannot be applied to any images, audio or video files", "It automatically increases the resolution and quality of an image while shrinking its file size"], "answer": 0, "explain": "Lossy compression discards some data permanently to shrink the file — that data cannot be recovered, so the original state cannot be restored exactly."}, {"question": "Which statement correctly describes lossless compression?", "options": ["It removes any data that the file''s creator marks as unimportant before saving", "It shrinks a file by more than lossy compression does, on the exact same content", "It removes no data at all, so the original file can be reconstructed exactly", "It can only be applied once, and the file cannot be compressed a second time"], "answer": 2, "explain": "Lossless compression stores the same data more efficiently without discarding anything, so decompressing it gives back exactly the original file."}, {"question": "Which of these file types would usually be the WORST candidate for lossy compression?", "options": ["A photo taken on a smartphone camera and shared widely across several social media platforms", "Source code for a computer program that a company relies on every day", "A song downloaded onto a phone to listen to during a commute", "A short video clip recorded for a video-sharing app"], "answer": 1, "explain": "Program code needs every character to be exact — a single permanently altered character from lossy compression could stop the program working, so lossless compression is required instead."}, {"question": "A streaming service wants users to be able to start watching a film within a couple of seconds. Which type of compression best supports this?", "options": ["Lossless compression, because it guarantees the film''s every pixel is stored exactly", "Lossy compression, because it produces a much smaller file that downloads and streams faster", "No compression at all, because streaming always requires the full, completely uncompressed original file", "Lossless compression, because it always produces a smaller file than lossy compression"], "answer": 1, "explain": "Lossy compression usually achieves a far bigger size reduction, so the film''s data arrives and can start playing much sooner."}, {"question": "Which of these is a genuine reason for compressing files before sending them over the internet?", "options": ["Compressed files use less of the network''s limited bandwidth while being sent", "Compressed files can no longer be opened by the person receiving them", "Compressed files are automatically protected from computer viruses during transfer", "Compressed files always arrive at their destination in a completely different format"], "answer": 0, "explain": "Smaller, compressed files use less bandwidth and transfer faster — a genuine, practical reason for compressing files sent over a network."}, {"question": "Why is lossless compression essential for a company''s financial spreadsheet, rather than lossy compression?", "options": ["Because spreadsheets are always much larger in file size than photos or videos", "Because lossy compression cannot technically be applied to any file made in office software", "Because every number and formula must remain exact, or the figures could become wrong", "Because spreadsheets need to be compressed twice in a row to reach an acceptable size"], "answer": 2, "explain": "A spreadsheet''s numbers and formulas must stay perfectly accurate — lossless compression guarantees nothing is altered, whereas lossy compression could corrupt a value."}, {"question": "A digital photo is compressed using lossy compression before being emailed. What happens to the photo''s quality?", "options": ["The quality improves, because compression sharpens the details in every pixel", "The quality is unaffected, because lossy compression never changes any pixel data", "The quality is reduced, because some image detail has been permanently discarded", "The quality becomes impossible to predict until the photo is opened again"], "answer": 2, "explain": "Lossy compression permanently removes some image detail to shrink the file, which reduces quality — even if the loss is often hard to notice."}, {"question": "Which pair correctly matches a real-world file format to the type of compression it uses?", "options": ["MP3 uses lossless compression, and ZIP uses lossy compression", "JPEG uses lossy compression, and PNG uses lossless compression", "ZIP uses lossy compression, and JPEG uses lossless compression", "PNG uses lossy compression, and MP3 uses lossless compression"], "answer": 1, "explain": "JPEG is a widely used lossy image format; PNG is a widely used lossless image format — the two are commonly confused in the opposite direction."}, {"question": "A hospital stores medical scan images that doctors must be able to examine in full, exact detail. Which type of compression should it use?", "options": ["Lossy compression, because doctors will not notice any missing image detail", "No compression at all, because medical images cannot legally be compressed", "Lossless compression, because no detail in the scan can be permanently lost", "Lossy compression, because it is the only method that can be applied to images"], "answer": 2, "explain": "Where exact detail is critical for a decision (like a medical diagnosis), lossless compression is required so nothing is permanently discarded."}, {"question": "What is the main drawback of choosing lossy compression over lossless compression?", "options": ["Lossy compressed files always take up more storage space than the original", "Some of the original file''s data and quality is lost and cannot be recovered", "Lossy compression cannot legally be used for any type of file stored on the internet", "Lossy compressed files always take much longer to transfer over a network"], "answer": 1, "explain": "The trade-off for lossy compression''s much smaller file size is a permanent, unrecoverable loss of some data and quality."}, {"question": "A word-processed report needs to be edited and re-saved many times without any of its text or formatting being permanently damaged. Which type of compression is appropriate?", "options": ["Lossy compression, since text files are always small enough not to need lossless", "Either type works equally well, since repeatedly editing a document has no real effect on this", "Lossless compression, since every character and formatting detail must be kept exactly", "Lossy compression, since it always compresses text more effectively than lossless"], "answer": 2, "explain": "A document that must stay exactly correct through repeated edits needs lossless compression, which guarantees nothing is ever permanently lost."}]}, "fib": {"enabled": true, "questions": [{"text": "Compression makes a file [smaller], so it uses less storage space and transfers faster."}, {"text": "A method of compression that permanently removes some data, so the original cannot be restored exactly, is called [lossy] compression."}, {"text": "A method of compression that removes no data at all, so the original file can be reconstructed exactly, is called [lossless] compression."}, {"text": "Lossy compression is well suited to files such as images, audio and video, where some quality loss is unlikely to be [noticed] by most people."}, {"text": "Lossless compression must be used for files such as [text] documents, spreadsheets and program code, where every bit matters."}, {"text": "The maximum amount of data a network connection can carry in a given time is called its [bandwidth]."}, {"text": "[ZIP] is a common real-world example of a lossless compression format, often used for documents and program files."}, {"text": "Choosing lossy compression instead of lossless usually means accepting a reduction in file [quality] in exchange for a much smaller file size."}]}, "tf": {"enabled": true, "questions": [{"statement": "Compression makes a file smaller so it uses less storage and transfers faster.", "answer": true, "explain": "Correct — this is the core purpose of compression."}, {"statement": "Lossy compression can always be reversed to restore the exact original file.", "answer": false, "explain": "Lossy compression permanently removes some data — decompressing gives a close copy, not an exact one. Only lossless compression guarantees exact restoration."}, {"statement": "Lossless compression removes no data, so the original file can be reconstructed exactly.", "answer": true, "explain": "Correct — that is the defining feature of lossless compression."}, {"statement": "Lossless compression is generally suited to text documents, spreadsheets and program code.", "answer": true, "explain": "Correct — these are files where every bit matters, so nothing can be safely discarded."}, {"statement": "Lossy compression is generally suited to images, audio and video, where minor quality loss often goes unnoticed.", "answer": true, "explain": "Correct — a small, targeted loss of detail in these file types is often imperceptible to most people."}, {"statement": "Lossless compression usually reduces file size by more than lossy compression does on the same file.", "answer": false, "explain": "The opposite is generally true: lossy compression usually achieves a much bigger size reduction, because it permanently discards data rather than keeping everything."}, {"statement": "Bandwidth is the maximum amount of data a network connection can carry in a given time.", "answer": true, "explain": "Correct — and compressed files use less of that available bandwidth."}, {"statement": "JPEG and ZIP are both examples of lossless compression formats.", "answer": false, "explain": "JPEG is a lossy format (used for photos); ZIP is a lossless format (used for documents and program files) — they are not the same type."}]}, "misc": {"enabled": true, "items": [{"myth": "Believing lossy compression removes data completely at random, like deleting random parts of a file.", "truth": "It targets <strong>specific</strong> detail that people are least likely to notice — for example, very high or low sound frequencies, or subtle colour differences in an image. It is a deliberate, targeted reduction, not random deletion.", "check": {"question": "How does lossy compression decide which data to remove from a file?", "options": ["It removes data completely at random, picking bits and bytes with no pattern anywhere across the whole file", "It targets specific detail that people are unlikely to notice, such as subtle colour or sound differences", "It removes the first half of the file and keeps the second half unchanged", "It asks the user to manually select exactly which parts of the file to delete"], "answer": 1, "explain": "Lossy compression targets detail that is least likely to be noticed, rather than deleting data randomly."}}, {"myth": "Believing lossless compression achieves a smaller file size than lossy compression on the same file.", "truth": "The opposite is usually true. Lossless compression keeps every original bit of data, so it typically produces a <strong>bigger</strong> file than lossy compression on the same content, which permanently throws detail away to get much smaller.", "check": {"question": "On the same original file, which type of compression usually produces the smaller result?", "options": ["Lossless compression, because it is the more advanced of the two methods", "Lossy compression, because it permanently discards some data rather than keeping everything", "They always produce exactly the same file size, whichever method is used", "Neither — the resulting file size depends only on the file''s original format, not the method used"], "answer": 1, "explain": "Lossy compression usually achieves a much bigger reduction, since it is allowed to permanently discard data that lossless compression must keep."}}, {"myth": "Believing a file compressed with lossy compression can always be restored to its exact original state by decompressing it.", "truth": "It cannot. Data removed during lossy compression is gone permanently — decompressing produces a copy that is close to, but <strong>not identical</strong> to, the true original. Only lossless compression guarantees an exact restoration.", "check": {"question": "A photo is compressed using lossy compression, then later decompressed. What is true of the result?", "options": ["It is guaranteed to be pixel-for-pixel identical to the original photo", "It is a close copy of the original, but some detail has been permanently lost", "It becomes a completely different photo altogether, entirely unrelated to the original", "It is always restored to a higher quality than the original photo"], "answer": 1, "explain": "Lossy compression permanently discards some data, so decompressing it can never produce an exact match of the original file."}}, {"myth": "Believing any file type can safely use lossy compression, as long as the resulting file is smaller.", "truth": "Files where every bit matters — text documents, spreadsheets, program code — must use <strong>lossless</strong> compression, since lossy compression could permanently corrupt characters, formulas or code and make the file unusable.", "check": {"question": "Why is it unsafe to compress a spreadsheet of financial data using lossy compression?", "options": ["Because spreadsheets are always too large for any compression method to work on", "Because a permanently altered number or formula could make the figures wrong", "Because lossy compression only works on files stored on the internet", "Because spreadsheets automatically reject any attempt to compress them"], "answer": 1, "explain": "Lossy compression can permanently change data. In a spreadsheet, that could silently corrupt a number or formula, so lossless compression must be used instead."}}, {"myth": "Believing compression is only really about saving storage space.", "truth": "It is just as much about <strong>transfer</strong> — smaller files upload and download faster and use less of a network''s limited bandwidth, which is essential for streaming video or audio smoothly.", "check": {"question": "Besides saving storage space, what is another genuine reason files are compressed?", "options": ["Compression makes a file completely impossible for anyone else to ever open or copy", "Smaller files transfer faster and use less of a network''s limited bandwidth", "Compression automatically fixes any errors that exist inside the file", "Compression permanently increases the resolution of an image file"], "answer": 1, "explain": "Faster transfer and reduced bandwidth use are just as important a reason for compression as saving storage space."}}, {"myth": "Believing that because lossy compression reduces file size by more, it is always the better choice.", "truth": "The ''better'' choice depends entirely on whether losing some data permanently is acceptable for that file and its purpose — a bigger size reduction is worthless if the file becomes unusable, such as corrupted program code.", "check": {"question": "Why is lossy compression not automatically the ''better'' choice, even though it usually shrinks a file by more?", "options": ["Because lossy compression always takes noticeably longer to perform than lossless compression does", "Because permanently losing data can make some files (e.g. program code) unusable, even if smaller", "Because lossy compression can only ever be applied to text files", "Because lossy compression always costs money to use, unlike lossless compression"], "answer": 1, "explain": "A bigger size reduction is only useful if the permanent data loss doesn''t matter for that file''s purpose — for code or exact records, it does matter, so lossless is required instead."}}]}, "tips": {"enabled": true, "items": [{"title": "The 1–2 mark ''state/define'' ladder", "html": "<p>A typical question: <em>\"Define lossless compression.\"</em> [2 marks] Here is the same idea answered at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"It makes the file smaller.\"</p>\n<ul>\n<li>This is true of compression in general, but it doesn''t describe LOSSLESS compression specifically — it would also be true of lossy compression, so it can''t be credited as a definition of this particular method.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"It doesn''t lose any of the data.\"</p>\n<ul>\n<li>A genuinely correct point, but \"define\" needs the CONSEQUENCE too — what does not losing any data actually let you do? Without that second half, only one of the two marks is available.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"No data is removed during compression <strong>(1)</strong>, so the original file can be reconstructed/decompressed back to exactly what it was before <strong>(1)</strong>.\"</p>\n\n<p><strong>Why this matters:</strong> \"State/define\" answers on this topic need to name what happens to the data AND the consequence that follows from it — a one-line vague answer like \"makes it smaller\" applies to compression in general, not to the specific method being asked about.</p>", "check": {"question": "A student answers ''Lossless compression: it keeps the file''s quality the same'' for a 2-mark ''define lossless compression'' question. What is this likely to score?", "options": ["2 marks, because quality staying the same is a correct and complete definition", "0 marks, because the answer given is entirely unrelated to the topic of compression itself", "Partial marks at best — it hints at the idea but doesn''t clearly state that no data is removed", "Full marks, because any true statement made about lossless compression always scores the maximum"], "answer": 2, "explain": "The answer gestures at the right idea but doesn''t clearly state the two creditable points — no data removed, and exact reconstruction — so it is unlikely to reach full marks."}}, {"title": "The 2-mark ''explain the difference'' ladder", "html": "<p>A typical question: <em>\"Explain the difference between lossy and lossless compression.\"</em> [2 marks]</p>\n\n<p><strong>❌ 0 marks:</strong> \"Lossy is for pictures and lossless is for documents.\"</p>\n<ul>\n<li>This states WHERE each type is used, not WHAT the actual difference in the compression process is — it could be true and still miss the mechanism the question is asking about.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"Lossy loses some data but lossless doesn''t.\"</p>\n<ul>\n<li>A genuinely correct point, but \"explain the difference\" wants BOTH sides properly described, and this only develops the lossy half of the comparison.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"Lossy compression permanently removes some data so the file cannot be restored exactly <strong>(1)</strong>; lossless compression removes no data at all, so the file can be restored to exactly what it was before <strong>(1)</strong>.\"</p>\n\n<p><strong>The pattern:</strong> a 2-mark \"difference\" question on this topic almost always splits into one mark for each side of the comparison — write about lossy AND lossless, not just one of them.</p>", "check": {"question": "A 2-mark ''explain the difference'' question is answered with only ''Lossy compression removes some data permanently.'' What is the most likely outcome?", "options": ["Full marks, since the statement given is completely accurate", "Only 1 of the 2 marks, since the lossless side of the comparison is missing entirely", "0 marks, since the statement given doesn''t mention file size or bandwidth anywhere at all", "Full marks, since only one correct fact is needed to explain any difference"], "answer": 1, "explain": "A difference question needs both sides described. A correct statement about only lossy compression can earn at most half the marks."}}, {"title": "The ''choose + justify'' ladder (3–4 marks): commit to ONE type", "html": "<p>\"Justify a choice\" questions on this topic always need TWO things in the right order: a committed choice (lossy OR lossless), then reasons that genuinely apply to THAT choice in THIS scenario.</p>\n\n<p><strong>❌ 0–1 marks:</strong> \"Lossy compression is smaller but loses quality, and lossless keeps everything but is bigger, so it depends.\"</p>\n<ul>\n<li>This hedges between both types instead of committing to one, so the justification marks can''t be credited against a clear choice.</li>\n</ul>\n\n<p><strong>⚠️ Partial marks:</strong> \"Lossless, because it doesn''t lose any data.\"</p>\n<ul>\n<li>A valid, committed choice — but only ONE justification point is given where the question wants more, developed and linked to the scenario.</li>\n</ul>\n\n<p><strong>✅ Full marks:</strong> \"Lossless compression, because it removes no data <strong>(1)</strong>, so the archived legal documents can always be reconstructed exactly, with every word intact even after years of storage <strong>(1)</strong>, and no detail can be permanently altered, which matters for an official record <strong>(1)</strong>.\"</p>\n\n<p>Two rules that catch real candidates out: commit to ONE type first, not a brand or a vague \"it depends\" — and make sure every justification point clearly matches the type you chose. A reason that only applies to the OTHER type earns nothing, even if it''s a true statement.</p>", "check": {"question": "You justify ''lossy compression'' using ''it removes no data, so nothing is ever lost.'' Why does this earn no justification marks?", "options": ["Because lossy compression justification questions on this specific topic are never worth any marks whatsoever at all", "Because the reason given actually describes lossless compression, contradicting the lossy choice that was made", "Because the answer is too short to be marked, regardless of what it says", "Because only lossless compression can ever be justified correctly in an exam answer"], "answer": 1, "explain": "The stated reason contradicts the chosen type — ''removes no data'' describes lossless compression, so it cannot support a lossy choice and earns nothing."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick (✓) <strong>one</strong> box to identify the statement that correctly defines lossy compression.</p>", "marks": 1, "hint": "Think about what happens to the DATA itself, not just the file size.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>It permanently removes some data, so the original file cannot be restored exactly</strong> (box 1)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Tick (✓) <strong>one</strong> box to identify the statement that correctly defines lossless compression.</p>", "marks": 1, "hint": "Lossless means exactly what it says — nothing is lost.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>It removes no data at all, so the original file can be reconstructed exactly</strong> (box 2)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>State what happens to a file''s data when lossy compression is used.</p>", "marks": 1, "hint": "One clear sentence about the data itself, not about the file size.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>Some of the file''s data is permanently removed/discarded/lost</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any wording that clearly states data is permanently removed. Do not accept a vague \"the file gets smaller\" with no reference to data being removed.</li>\n</ul>\n</div>"}, {"question": "<p>Define lossless compression.</p>", "marks": 2, "hint": "Say what happens to the data, then say what that lets you do afterwards.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per bullet)</h5>\n<ul>\n<li>No data is removed/lost during compression</li>\n<li>The original file can be reconstructed/decompressed to be exactly the same as it was before compression</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both points are needed for full marks. A vague \"it keeps the quality the same\" without stating no data is removed AND exact reconstruction is possible scores at most 1.</li>\n</ul>\n</div>"}, {"question": "<p>Explain the difference between lossy and lossless compression.</p>", "marks": 2, "hint": "Write about BOTH types — one mark is usually for each side of the comparison.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per bullet)</h5>\n<ul>\n<li>Lossy compression permanently removes some data, so the file cannot be restored exactly</li>\n<li>Lossless compression removes no data, so the file can be restored/reconstructed exactly</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both sides of the comparison must be addressed for full marks. A correct statement about only one type scores a maximum of 1.</li>\n</ul>\n</div>"}, {"question": "<p>State two reasons why a company might choose to compress files before making them available to download from its website.</p>", "marks": 2, "hint": "Think about storage, transfer speed, and bandwidth — give any two distinct reasons.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per reason, up to 2)</h5>\n<ul>\n<li>The compressed files use less storage space on the company''s servers</li>\n<li>The compressed files download faster for visitors to the website</li>\n<li>The compressed files use less of the network''s/website''s available bandwidth</li>\n<li>Faster downloads/less storage means the company can serve more visitors or files without extra cost</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per distinct valid reason, up to a maximum of 2. Two versions of the same reason (e.g. \"saves space\" and \"uses less storage\") only score once.</li>\n</ul>\n</div>"}, {"question": "<p>A local council is archiving scanned copies of important planning permission documents. The documents must remain word-for-word readable, and their content must never be altered, even after being stored for many years.</p><p>State whether the council should compress these documents using lossy or lossless compression. Justify your choice.</p>", "marks": 4, "hint": "Think about what happens if even one detail is permanently changed — then pick the type that guarantees nothing is lost.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 for choice of lossless; 1 mark per bullet to max 3 for justification)</h5>\n<ul>\n<li>Lossless compression removes no data, so the document can always be reconstructed exactly</li>\n<li>Every word/character in the legal document must remain readable and unchanged — nothing can be permanently discarded</li>\n<li>A trustworthy, unaltered archive copy is needed even after years of storage; a lossy method risks permanently corrupting legal wording</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Justification must match the chosen type. If lossy is chosen instead, do not award any justification marks based on lossless reasoning.</li>\n<li>Mark the first compression type given.</li>\n</ul>\n</div>"}, {"question": "<p>A music streaming app sends songs to users'' phones over mobile data connections. Many users have a limited monthly data allowance and expect a song to start playing within a couple of seconds of pressing play.</p><p>State whether the app should compress its songs using lossy or lossless compression. Justify your choice.</p>", "marks": 4, "hint": "Think about file size versus data allowance and how quickly a song needs to start playing.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 for choice of lossy; 1 mark per bullet to max 3 for justification)</h5>\n<ul>\n<li>Lossy compression produces a much smaller file, using less of the user''s limited mobile data allowance</li>\n<li>The smaller file downloads/buffers fast enough for the song to start playing almost immediately</li>\n<li>The small loss of audio detail is usually not noticeable to most listeners, so the quality trade-off is acceptable</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Justification must match the chosen type. If lossless is chosen instead, do not award any justification marks based on lossy reasoning.</li>\n<li>Mark the first compression type given.</li>\n</ul>\n</div>"}, {"question": "<p>Describe one drawback of using lossy compression.</p>", "marks": 2, "hint": "State the effect on the file, then develop it by explaining why that effect cannot be undone.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 for the drawback, 1 for development)</h5>\n<ul>\n<li>The quality of the file is reduced / some detail is lost <strong>(1)</strong> … and this loss is permanent, so the original file cannot be restored/recovered exactly <strong>(1)</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any correctly developed drawback linked to the permanent, unrecoverable loss of data/quality.</li>\n</ul>\n</div>"}, {"question": "<p>For each file type below, tick (✓) <strong>one</strong> box to identify whether lossy or lossless compression is the more suitable choice.</p>", "marks": 4, "hint": "Ask: does every bit of this file matter, or would a small, unnoticeable loss of detail be an acceptable trade-off for a smaller file?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Word-processed report → <strong>Lossless</strong> (formatting/text must not be permanently altered)</li>\n<li>Holiday photo for social media → <strong>Lossy</strong> (small file size matters more than tiny, unnoticeable detail loss)</li>\n<li>Source code → <strong>Lossless</strong> (a single altered character could break the program)</li>\n<li>Live video call → <strong>Lossy</strong> (a much smaller data stream is needed to send video in real time)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently. Two or more ticks in the same row scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Draw <strong>one</strong> line from each real-world file example to the description that correctly matches it.</p><p>(There are more descriptions than examples — one description is not used.)</p>", "marks": 4, "hint": "Match each example to its type of compression AND the reason that type suits it — watch for the decoy that describes no compression at all.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per correct line from example to description)</h5>\n<ul>\n<li>ZIP archive → <strong>A</strong> (lossless — every byte of the documents must be restored exactly)</li>\n<li>JPEG photograph → <strong>B</strong> (lossy — discards unnoticeable visual detail)</li>\n<li>MP3 track → <strong>C</strong> (lossy — discards unnoticeable audio detail)</li>\n<li>PNG logo → <strong>D</strong> (lossless — needs sharp, exact detail)</li>\n<li>E (\"no compression at all\") is the unused decoy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Any 2 lines from 1 example scores 0 marks for that example.</li>\n</ul>\n</div>"}, {"question": "<p>Tick (✓) <strong>one</strong> box to identify a real-world example of a LOSSLESS compression format.</p>", "marks": 1, "hint": "Three of these options are either lossy formats or aren''t real formats at all.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>ZIP, commonly used for documents and program files</strong> (box 3)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>A photo-sharing app lets users upload as many photos as they like for free, but the company''s servers have a limited amount of storage space, and users on slow mobile connections expect their photos to upload quickly.</p><p>State whether the app should compress photos using lossy or lossless compression before storing them. Justify your choice.</p>", "marks": 3, "hint": "Think about storage across millions of uploaded photos, and upload speed on a slow connection.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 for choice of lossy; 1 mark per bullet to max 2 for justification)</h5>\n<ul>\n<li>Lossy compression reduces file size by much more than lossless, saving significant server storage across many uploaded photos</li>\n<li>The smaller file uploads faster on a slow connection, and the small loss of detail is usually unnoticeable on a phone screen</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Justification must match the chosen type. If lossless is chosen instead, do not award any justification marks based on lossy reasoning.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', '{"learn": {"enabled": true, "items": [{"title": "What''s the difference between a LAN and a WAN?", "html": "<h4>Two networks, defined by scale</h4>\n<ul>\n<li>A <strong>LAN (Local Area Network)</strong> connects devices across a small geographical area — usually a single site, such as one building or a small group of nearby buildings (a school, an office, a home).</li>\n<li>A <strong>WAN (Wide Area Network)</strong> connects devices across a large geographical area — different cities, different countries, or the whole globe.</li>\n<li>The <strong>Internet</strong> is itself the largest WAN in existence: a worldwide collection of interconnected networks, not owned by any single organisation.</li>\n</ul>\n<h4>Who owns and controls the infrastructure?</h4>\n<ul>\n<li>A LAN''s cabling, switches and other hardware are normally owned and fully controlled by the single organisation that uses it — a school''s IT department owns and manages its own LAN.</li>\n<li>A WAN usually relies on infrastructure that is NOT entirely owned by the organisation using it. Connecting distant sites means renting/leasing lines and equipment from telecommunications companies, who own and maintain the wider infrastructure in between.</li>\n</ul>\n<h4>Everyday examples</h4>\n<ul>\n<li><strong>LAN examples:</strong> the computers in one school building; a small office''s network; a home Wi-Fi network.</li>\n<li><strong>WAN examples:</strong> a bank''s network connecting branches in different cities; a supermarket chain linking its stores nationwide; the Internet itself.</li>\n</ul>", "check": {"question": "Which of these is the clearest example of a WAN rather than a LAN?", "options": ["A network spanning many cities, connecting a company''s branches nationwide", "A network inside a single small classroom connecting six laptops to one shared printer", "A network connecting the computers in one office to a shared local server", "A home network connecting a laptop and a phone to one Wi-Fi router"], "answer": 0, "explain": "A WAN covers a large geographical area — multiple cities in this case — whereas the other three options describe devices confined to a single site, which is a LAN."}}, {"title": "What factors affect how well a network performs?", "html": "<h4>Bandwidth — and sharing it</h4>\n<ul>\n<li><strong>Bandwidth</strong> is the maximum amount of data that can be transferred across a network connection in a given time.</li>\n<li>Bandwidth is <strong>shared</strong> between everyone using the connection at once. The more users or devices actively sending/receiving data at the same time, the smaller each one''s share becomes — which is why a school network can feel much slower at busy times of day.</li>\n</ul>\n<h4>Number of users and devices</h4>\n<ul>\n<li>Simply having more devices <strong>connected</strong> to a network does not by itself slow it down — but more devices <strong>actively transferring data at the same time</strong> means more competition for the same limited bandwidth, and therefore slower performance for everyone.</li>\n</ul>\n<h4>Transmission media</h4>\n<ul>\n<li><strong>Copper cable</strong> is cheap and widely used, but slower than fibre and more affected by electrical interference.</li>\n<li><strong>Fibre-optic cable</strong> sends data as pulses of light through glass strands — much faster than copper and unaffected by electrical interference, but more expensive to install.</li>\n<li><strong>Wireless</strong> connections are convenient (no cables needed) but are generally slower and less reliable than a wired connection of the same quality.</li>\n</ul>\n<h4>Interference, latency and distance from a wireless access point</h4>\n<ul>\n<li><strong>Interference</strong> — from other wireless devices, thick walls, or electrical equipment — can weaken or corrupt a signal, forcing data to be resent and slowing the network down.</li>\n<li><strong>Latency</strong> is the delay between data being sent and it arriving at its destination; a longer physical distance, or data passing through more devices along the way, increases latency.</li>\n<li>The <strong>further a wireless device is from its access point</strong>, the weaker its signal, which usually means a slower and less reliable connection.</li>\n</ul>", "check": {"question": "Why can a school''s wireless network feel noticeably slower at busy times of the school day?", "options": ["More devices are actively sharing the same limited bandwidth at once", "Wireless signals always slow down permanently once a school day begins", "The school''s router automatically reduces its own performance overnight", "Bandwidth only ever affects wired connections, never wireless ones"], "answer": 0, "explain": "Bandwidth is shared. When many devices are actively transferring data at the same time, each one gets a smaller share of the available bandwidth, so the network feels slower."}}, {"title": "Client-server vs peer-to-peer networks", "html": "<h4>The roles of the computers involved</h4>\n<ul>\n<li>In a <strong>client-server</strong> network, one or more dedicated, powerful central computers (<strong>servers</strong>) provide services and resources — such as storing files, managing user accounts, or controlling a shared printer. Other computers (<strong>clients</strong>) request and use those services.</li>\n<li>In a <strong>peer-to-peer (P2P)</strong> network, every computer (a <strong>peer</strong>, or node) has equal status. Each one can act as both a client and a server, sharing files or resources directly with other peers — there is no single dedicated managing machine.</li>\n</ul>\n<h4>Client-server: advantages and disadvantages</h4>\n<ul>\n<li><strong>Advantage:</strong> centralised control makes it far easier to manage security, user accounts and backups from one place.</li>\n<li><strong>Disadvantage:</strong> it needs a dedicated, often expensive server plus IT expertise to maintain it — and if the server fails, the whole network''s shared services can be disrupted.</li>\n</ul>\n<h4>Peer-to-peer: advantages and disadvantages</h4>\n<ul>\n<li><strong>Advantage:</strong> cheap and simple to set up, since no dedicated server or extra hardware is required.</li>\n<li><strong>Disadvantage:</strong> harder to keep secure and consistently backed up, since data is spread across many individual peers rather than managed centrally — this makes it unsuitable for large organisations.</li>\n</ul>\n<h4>Typical use cases</h4>\n<ul>\n<li><strong>Client-server</strong> suits schools, businesses and any setting where centralised control, security and reliability matter.</li>\n<li><strong>Peer-to-peer</strong> suits small, informal networks — a handful of home computers sharing files directly, or a small club with no budget for a dedicated server.</li>\n</ul>", "check": {"question": "In a client-server network, what is the role of the server?", "options": ["It provides shared services and resources that client computers request and use", "It is simply the first computer that was ever connected to the network", "It only stores a backup copy of data in case a client computer breaks", "It physically converts wireless radio signals into wired network signals for every other connected device"], "answer": 0, "explain": "The server is the dedicated computer that provides services (files, accounts, printing) which client computers then request and use — that is its defining role."}}, {"title": "What hardware connects stand-alone computers into a LAN?", "html": "<h4>NIC — Network Interface Card</h4>\n<ul>\n<li>A <strong>NIC</strong> is the hardware, built into or fitted inside a computer, that lets it physically connect to a network. Every networked device needs one, wired or wireless.</li>\n</ul>\n<h4>Switch vs router — the key distinction</h4>\n<ul>\n<li>A <strong>switch</strong> connects multiple wired devices together <strong>within the same LAN</strong>. It reads the destination address of each piece of data and forwards it only to the specific device it is meant for, rather than sending it to every device.</li>\n<li>A <strong>router</strong> connects <strong>different networks</strong> together — most commonly, it connects a LAN to another network such as the Internet, directing (routing) data between the two based on IP addresses.</li>\n<li><strong>The distinction that matters for the exam:</strong> a switch works within one LAN, joining devices to each other; a router works between networks, joining one network to another.</li>\n</ul>\n<h4>WAP — Wireless Access Point</h4>\n<ul>\n<li>A <strong>WAP</strong> allows wireless devices to join a wired LAN. It converts between the wired network''s signals and wireless radio signals, so a laptop or phone can connect without a cable.</li>\n</ul>\n<h4>Transmission media</h4>\n<ul>\n<li>The physical (or wireless) pathway the data actually travels along — <strong>copper cable</strong>, <strong>fibre-optic cable</strong>, or <strong>wireless</strong> radio signals — is what physically links all of this hardware together into one working LAN.</li>\n</ul>", "check": {"question": "A small office already has a working wired LAN. Which piece of hardware would let staff also connect their laptops wirelessly to that same LAN?", "options": ["A wireless access point (WAP)", "A second network interface card fitted inside the existing switch", "A router configured to only forward data to wired devices", "A longer length of fibre-optic transmission cable"], "answer": 0, "explain": "A wireless access point converts between the wired LAN''s signals and wireless radio signals, letting wireless devices join a network that was originally built using cables."}}, {"title": "The Internet, DNS and hosting", "html": "<h4>Web servers, clients, URLs and IP addresses</h4>\n<ul>\n<li>A <strong>web server</strong> stores a website''s files and sends them to a device when requested. The <strong>client</strong> is the user''s device (running a browser) making that request.</li>\n<li>A <strong>URL</strong> (e.g. www.example.com) is the human-readable web address a person types in. An <strong>IP address</strong> (e.g. 192.168.1.1) is the numerical address that computers actually use to find and communicate with each other across a network.</li>\n</ul>\n<h4>DNS — how a lookup actually works</h4>\n<ul>\n<li>The <strong>Domain Name System (DNS)</strong> is a distributed system of servers whose job is to convert a URL into the matching IP address, step by step:</li>\n<li><strong>Step 1:</strong> the browser first checks whether it already has that URL''s IP address stored (cached) from a previous visit.</li>\n<li><strong>Step 2:</strong> if not, the browser sends the URL to a DNS server.</li>\n<li><strong>Step 3:</strong> the DNS server looks up the matching IP address in its own records — or, if it does not hold that record, asks another DNS server on the DNS server''s behalf.</li>\n<li><strong>Step 4:</strong> the DNS server returns the correct IP address to the browser, which then uses it to request the actual webpage from the correct web server.</li>\n</ul>\n<h4>Hosting</h4>\n<ul>\n<li><strong>Hosting</strong> means storing a website''s files on a web server — usually rented space paid for by the website''s owner — so the site is accessible over the Internet at any time.</li>\n</ul>\n<h4>The Cloud: benefits and drawbacks</h4>\n<ul>\n<li><strong>The cloud</strong> means storing data, or running software, on remote servers accessed over the Internet, rather than on local hardware you own.</li>\n<li><strong>Benefits:</strong> data can be accessed from anywhere with an Internet connection; backups and maintenance are handled by the provider; storage can be scaled up easily without buying new hardware; several people can collaborate on the same files.</li>\n<li><strong>Drawbacks:</strong> a reliable Internet connection is required to access your own data; there is usually an ongoing subscription cost; you are trusting a third party with your data''s security and privacy; you have no control if an outage happens at the provider''s end.</li>\n</ul>", "check": {"question": "What job does a DNS server actually do?", "options": ["It converts a URL that a user types in into the matching IP address", "It permanently stores every website''s files so they load faster for everyone", "It physically connects a school''s wired LAN to its wireless devices", "It encrypts a user''s password before it is sent to a website"], "answer": 0, "explain": "DNS looks up the numerical IP address that matches the human-readable URL a user has typed, so the browser knows which web server to actually contact."}}, {"title": "Star topology", "html": "<h4>How a star topology is wired</h4>\n<ul>\n<li>Every device connects <strong>individually</strong> to one central device (usually a switch), each with its own dedicated cable. There are no direct connections between the other devices themselves.</li>\n<li>Data sent from one device to another always passes through the central device first, which then forwards it on to the correct destination.</li>\n</ul>\n<svg viewBox=\"0 0 240 220\" width=\"220\" height=\"202\" role=\"img\" aria-label=\"Star topology diagram: a central switch connected by its own individual cable to four separate PCs and a server, arranged around it — no device is connected directly to another device\">\n<line x1=\"120\" y1=\"120\" x2=\"120\" y2=\"24\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"120\" y1=\"120\" x2=\"211\" y2=\"90\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"120\" y1=\"120\" x2=\"176\" y2=\"198\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"120\" y1=\"120\" x2=\"64\" y2=\"198\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"120\" y1=\"120\" x2=\"29\" y2=\"90\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<rect x=\"104\" y=\"104\" width=\"32\" height=\"32\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"120\" y=\"124\" font-size=\"10\" text-anchor=\"middle\" fill=\"currentColor\">SW</text>\n<circle cx=\"120\" cy=\"24\" r=\"15\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"120\" y=\"28\" font-size=\"10\" text-anchor=\"middle\" fill=\"currentColor\">PC1</text>\n<circle cx=\"211\" cy=\"90\" r=\"15\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"211\" y=\"94\" font-size=\"10\" text-anchor=\"middle\" fill=\"currentColor\">PC2</text>\n<circle cx=\"176\" cy=\"198\" r=\"15\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"176\" y=\"202\" font-size=\"10\" text-anchor=\"middle\" fill=\"currentColor\">PC3</text>\n<circle cx=\"64\" cy=\"198\" r=\"15\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"64\" y=\"202\" font-size=\"10\" text-anchor=\"middle\" fill=\"currentColor\">PC4</text>\n<circle cx=\"29\" cy=\"90\" r=\"15\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"29\" y=\"94\" font-size=\"9\" text-anchor=\"middle\" fill=\"currentColor\">SRV</text>\n</svg>\n<h4>Advantages of a star topology</h4>\n<ul>\n<li>If one cable or one non-central device fails, only that single device is affected — the rest of the network keeps working normally.</li>\n<li>Performance stays consistent and fast, since each device has its own dedicated cable rather than sharing one single line with everyone else.</li>\n<li>New devices are easy to add — just run a new cable to the central device.</li>\n</ul>\n<h4>Disadvantages of a star topology</h4>\n<ul>\n<li>If the central device (the switch) fails, the <strong>whole network</strong> goes down, since every device relies on it.</li>\n<li>It needs more cabling overall than some alternative layouts, since every single device needs its own separate cable back to the centre.</li>\n<li>Adding a device requires a free port on the central switch — once the switch''s ports are full, it must be replaced or another switch added.</li>\n</ul>", "check": {"question": "In a star topology, what happens if the central switch fails completely?", "options": ["The whole network stops working, because every device depends on the switch", "Nothing at all changes, because every device is also already connected directly to each other", "Only the single closest device to the switch loses its connection", "The network automatically rewires itself into a mesh topology"], "answer": 0, "explain": "Every device''s own cable in a star topology leads only to the central switch, so if that one central device fails, the entire network loses its connections."}}, {"title": "Mesh topology", "html": "<h4>How a mesh topology is wired</h4>\n<ul>\n<li>In a (full) mesh topology, <strong>every device connects directly to every other device</strong> — there is no central device that the others depend on.</li>\n<li>The number of cables needed grows quickly as devices are added, following the rule <strong>n(n − 1) ÷ 2</strong> for n devices — 5 devices need 5 × 4 ÷ 2 = <strong>10</strong> separate cables.</li>\n</ul>\n<svg viewBox=\"0 0 240 220\" width=\"220\" height=\"202\" role=\"img\" aria-label=\"Mesh topology diagram: four PCs and a server, with every device connected directly to every other device by its own cable — ten cables in total, no central device\">\n<line x1=\"120\" y1=\"24\" x2=\"211\" y2=\"90\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"120\" y1=\"24\" x2=\"176\" y2=\"198\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"120\" y1=\"24\" x2=\"64\" y2=\"198\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"120\" y1=\"24\" x2=\"29\" y2=\"90\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"211\" y1=\"90\" x2=\"176\" y2=\"198\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"211\" y1=\"90\" x2=\"64\" y2=\"198\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"211\" y1=\"90\" x2=\"29\" y2=\"90\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"176\" y1=\"198\" x2=\"64\" y2=\"198\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"176\" y1=\"198\" x2=\"29\" y2=\"90\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<line x1=\"64\" y1=\"198\" x2=\"29\" y2=\"90\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<circle cx=\"120\" cy=\"24\" r=\"15\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"120\" y=\"28\" font-size=\"10\" text-anchor=\"middle\" fill=\"currentColor\">PC1</text>\n<circle cx=\"211\" cy=\"90\" r=\"15\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"211\" y=\"94\" font-size=\"10\" text-anchor=\"middle\" fill=\"currentColor\">PC2</text>\n<circle cx=\"176\" cy=\"198\" r=\"15\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"176\" y=\"202\" font-size=\"10\" text-anchor=\"middle\" fill=\"currentColor\">PC3</text>\n<circle cx=\"64\" cy=\"198\" r=\"15\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"64\" y=\"202\" font-size=\"10\" text-anchor=\"middle\" fill=\"currentColor\">PC4</text>\n<circle cx=\"29\" cy=\"90\" r=\"15\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n<text x=\"29\" y=\"94\" font-size=\"9\" text-anchor=\"middle\" fill=\"currentColor\">SRV</text>\n</svg>\n<h4>Advantages of a mesh topology</h4>\n<ul>\n<li>Highly <strong>resilient</strong> — if one cable or device fails, data can simply be re-routed along a different path, so the rest of the network keeps working.</li>\n<li>There is no single central device whose failure could bring down the whole network, unlike a star topology''s switch.</li>\n</ul>\n<h4>Disadvantages of a mesh topology</h4>\n<ul>\n<li>Needs <strong>far more cabling</strong> as devices are added — the n(n − 1) ÷ 2 rule means the number of cables grows much faster than the number of devices.</li>\n<li>More expensive and much more complex to install, wire and maintain than a star topology, especially as the network grows.</li>\n</ul>\n<h4>Choosing between them</h4>\n<ul>\n<li>A <strong>star</strong> topology suits most everyday offices and schools, where keeping cost and complexity down matters, and an occasional (rare) switch failure is an acceptable risk.</li>\n<li>A <strong>mesh</strong> topology suits systems that must almost never go down regardless of cost — for example, emergency-services communications or a data centre — because it has no single point of failure.</li>\n</ul>", "check": {"question": "Why is a mesh topology generally considered more resilient than a star topology?", "options": ["It has no single central device whose failure could bring down the whole network", "It always uses fewer cables in total than a star topology needs", "It only ever needs one shared cable connecting every device together", "It automatically detects and repairs any damaged cable itself, without any human intervention required"], "answer": 0, "explain": "Because every device connects directly to every other device, there is no central point (like a star''s switch) that the whole network depends on — one failure can be routed around."}}]}, "terms": {"enabled": true, "pairs": [{"term": "LAN", "definition": "A network confined to a single site — one building or a small group of nearby buildings"}, {"term": "WAN", "definition": "A network spanning a large geographical area, such as multiple cities or countries"}, {"term": "Bandwidth", "definition": "The maximum amount of data a connection can carry in a given time, shared between all active users"}, {"term": "Latency", "definition": "The delay between data being sent and it arriving at its destination"}, {"term": "Interference", "definition": "Disruption (walls, other devices, electrical equipment) that weakens or corrupts a signal"}, {"term": "Transmission media", "definition": "The physical or wireless pathway data travels along: copper, fibre-optic, or wireless"}, {"term": "Client-server network", "definition": "A network with dedicated server(s) providing services that client computers request and use"}, {"term": "Peer-to-peer network", "definition": "Every computer has equal status, acting as both client and server, with no dedicated central machine"}, {"term": "NIC", "definition": "Network interface card — hardware that lets a device physically connect to a network"}, {"term": "Switch", "definition": "Connects multiple wired devices within the same LAN, forwarding data to the addressed device only"}, {"term": "Router", "definition": "Connects one network to a different network, such as a LAN to the Internet"}, {"term": "WAP", "definition": "Wireless access point — lets wireless devices join a wired LAN"}, {"term": "DNS", "definition": "The system of servers that converts a URL into the matching IP address"}, {"term": "URL vs IP address", "definition": "A URL is the human-readable web address; an IP address is the numerical address devices use"}, {"term": "Web server", "definition": "Stores a website''s files and sends them to a client when requested"}, {"term": "Hosting", "definition": "Storing a website''s files on a web server so it is accessible over the Internet"}, {"term": "The cloud", "definition": "Storing data or running services on remote servers accessed over the Internet, not locally"}, {"term": "Star vs mesh topology", "definition": "Star: every device wired to one central device. Mesh: every device wired directly to every other device"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of these best describes a Wide Area Network (WAN)?", "options": ["A network spanning a large area, such as multiple cities or countries", "A network that only ever connects exactly two computers directly together, without any hardware", "A network confined to a single building or a small group of nearby buildings", "A network that can only ever be built using wireless access points and never any cables"], "answer": 0, "explain": "A WAN covers a large geographical area, unlike the other options, which either describe a LAN or describe made-up restrictions that don''t define any real network type."}, {"question": "A company owns and fully manages every switch and cable inside its head office network. What does this tell you about that network?", "options": ["It is most likely a LAN, since the organisation itself owns its infrastructure", "It must be a WAN, since owning hardware always means covering a large area", "It cannot be considered a genuine network at all unless it has a router connecting it out to the wider Internet", "It proves the company has no wireless devices anywhere on its premises"], "answer": 0, "explain": "Full ownership and control of the infrastructure by a single organisation, confined to one site, is characteristic of a LAN — WANs typically rely on infrastructure leased from telecoms providers."}, {"question": "Why does a network typically feel slower when many devices are actively transferring data at the same time?", "options": ["Because the available bandwidth is shared, so each device gets a smaller portion of it", "Because every device automatically and permanently halves its own processing speed once it first connects", "Because wireless connections switch off completely once ten devices are joined", "Because routers can only ever process data from a single connected device"], "answer": 0, "explain": "Bandwidth is the finite amount of data a connection can carry in a given time; more devices actively using it at once means less of it is available to each device."}, {"question": "Which transmission medium generally offers the fastest speeds and is unaffected by electrical interference?", "options": ["Fibre-optic cable, which carries data as pulses of light through glass", "Standard copper cable, since it has been used in networks for the longest time", "Wireless radio signals, since no cabling is involved at all", "Any transmission medium performs identically once installed correctly"], "answer": 0, "explain": "Fibre-optic cable sends data as light through glass strands, giving it very high speeds and immunity to the electrical interference that affects copper cable."}, {"question": "In a client-server network, what is the defining role of a client computer?", "options": ["It requests and makes use of services or resources provided by a server", "It permanently stores every other device''s files as an automatic backup", "It converts wireless signals into wired signals for the rest of the network", "It manages user accounts and security settings for the whole network"], "answer": 0, "explain": "Clients are the computers that request and use the services (files, printing, accounts) that a dedicated server provides — that request-and-use relationship is the defining feature."}, {"question": "What is a genuine disadvantage of a peer-to-peer network compared to a client-server network?", "options": ["It is generally harder to keep data secure and consistently backed up across all peers", "It always requires noticeably far more expensive specialist hardware than any client-server network ever needs", "It cannot physically connect more than two computers together at once", "It automatically stops working the moment more than one file is shared"], "answer": 0, "explain": "Without one dedicated, centrally managed server, security and backups depend on each individual peer, which is much harder to guarantee consistently than in a managed client-server setup."}, {"question": "What is the purpose of a NIC (network interface card)?", "options": ["It is the hardware that lets a computer physically connect to a network", "It converts a URL into the matching IP address for a website", "It permanently stores every one of a website''s files so browsers can request and load them instantly", "It boosts a wireless signal so it reaches devices much further away"], "answer": 0, "explain": "A NIC is the piece of hardware, built in or fitted, that allows a device to physically join a network — every networked device, wired or wireless, needs one."}, {"question": "What is the key difference between what a switch does and what a router does?", "options": ["A switch connects devices within one LAN; a router connects one network to another network", "A switch only works wirelessly, while a router only works using copper cable", "A switch and a router actually perform exactly the same underlying job, just marketed and sold under two completely different product names", "A switch stores webpages, while a router looks up IP addresses using DNS"], "answer": 0, "explain": "A switch forwards data between devices that are already part of the same LAN, whereas a router directs data between separate networks, such as a LAN and the Internet."}, {"question": "A wired office network wants to let staff connect their phones and laptops wirelessly. Which device makes this possible?", "options": ["A wireless access point (WAP)", "An additional length of fibre-optic transmission cable", "A second router configured to ignore all wireless requests", "A switch with its wireless functionality permanently disabled"], "answer": 0, "explain": "A WAP converts between the wired network''s signals and wireless radio signals, letting wireless devices join a network that was originally built using cables."}, {"question": "What is the main purpose of a DNS server on the Internet?", "options": ["To look up the IP address that matches a URL a user has typed in", "To permanently store the actual files of every website in the world", "To physically deliver data packets between two nearby wireless devices", "To decide which websites a school''s students are and aren''t allowed to visit"], "answer": 0, "explain": "DNS''s job is the lookup itself — converting the human-readable URL into the numerical IP address a browser needs in order to actually contact the correct web server."}, {"question": "How does a URL differ from an IP address?", "options": ["A URL is the human-readable address typed in; an IP address is the numerical address devices use", "A URL is always longer in length than any IP address could ever be", "An IP address is only ever used for accessing websites, while a URL can be used for absolutely any device on any network", "A URL and an IP address are simply two different names for the exact same thing"], "answer": 0, "explain": "A URL (like www.example.com) is written for people to read and type; the matching IP address is the numerical form that computers actually use to route data."}, {"question": "Why is a star topology generally considered less resilient than a mesh topology?", "options": ["A single failure of its central switch can bring down the entire network", "It requires far more total cabling than a mesh topology of the same size", "It cannot ever be used to connect more than two devices at once", "Every device in a star topology must share one single physical cable"], "answer": 0, "explain": "Because every device in a star topology depends on the one central switch, that single device failing takes the whole network down — a risk a mesh topology avoids by having no central point."}]}, "fib": {"enabled": true, "questions": [{"text": "A [LAN] connects devices within a single site, such as one building or a small group of nearby buildings."}, {"text": "A [WAN] connects devices across a large geographical area, such as different cities or countries."}, {"text": "The maximum amount of data that can be transferred across a network connection in a given time is called its [bandwidth]."}, {"text": "Every device needs a [network interface card] fitted before it can physically connect to a network."}, {"text": "A [switch] connects multiple wired devices within the same LAN and forwards data only to the device it is addressed to."}, {"text": "A [router] connects a LAN to a different network, such as the Internet."}, {"text": "The system of servers that converts a URL into the matching IP address is called [DNS]."}, {"text": "In a [mesh] topology, every device connects directly to every other device, giving high resilience but needing many more cables."}]}, "tf": {"enabled": true, "questions": [{"statement": "A LAN is normally confined to a single site, such as one building.", "answer": true, "explain": "Correct — a LAN''s defining feature is its small geographical scale, usually one site or a small group of nearby buildings."}, {"statement": "Bandwidth is unlimited, so having more users on a network never affects its performance.", "answer": false, "explain": "Bandwidth is finite and shared between everyone using the connection at once — more active users means a smaller share, and slower performance, for each."}, {"statement": "In a client-server network, every computer has exactly equal status, with no dedicated server.", "answer": false, "explain": "That describes a peer-to-peer network. In a client-server network, one or more dedicated servers provide services that client computers request and use."}, {"statement": "A switch connects devices together within a single LAN.", "answer": true, "explain": "Correct — a switch forwards data between wired devices that are already part of the same LAN."}, {"statement": "A router''s main job is to connect one network to a different network.", "answer": true, "explain": "Correct — a router directs data between separate networks, most commonly a LAN and the Internet, unlike a switch which works within one LAN."}, {"statement": "DNS stores the actual files of every website so browsers can display them instantly.", "answer": false, "explain": "DNS only looks up the IP address matching a URL — it does not store website content. The website''s files are stored on a web server."}, {"statement": "Storing data in the cloud means it is not stored on any physical hardware anywhere.", "answer": false, "explain": "Cloud storage still uses real physical servers — just ones owned and managed by someone else (a cloud provider), accessed over the Internet rather than stored locally."}, {"statement": "A mesh topology generally needs more cabling than a star topology connecting the same number of devices.", "answer": true, "explain": "Correct — a mesh topology''s n(n − 1) ÷ 2 cabling rule grows much faster than a star topology''s one-cable-per-device requirement."}]}, "misc": {"enabled": true, "items": [{"myth": "Believing a switch and a router do exactly the same job, just under two different names.", "truth": "A <strong>switch</strong> connects devices <em>within</em> the same LAN, forwarding data only to the device it''s addressed to. A <strong>router</strong> connects <em>different networks</em> together — most commonly, a LAN to the Internet. One works inside a network; the other works between networks.", "check": {"question": "Which statement correctly separates what a switch does from what a router does?", "options": ["A switch works within one LAN; a router connects that LAN to a different network", "A switch and a router perform identical jobs, just marketed under different names", "A router only ever works wirelessly, while a switch only works using cables", "A switch stores webpages, while a router looks up matching IP addresses"], "answer": 0, "explain": "A switch''s job is entirely within one LAN (device-to-device); a router''s job is connecting that LAN to a separate network, such as the Internet."}}, {"myth": "Assuming a wireless connection is always faster than a wired one, since Wi-Fi feels newer and more convenient.", "truth": "A good wired connection — especially fibre-optic cable — is generally <strong>faster and more reliable</strong> than wireless. Wireless is convenient because it removes cables, but it is more affected by interference and distance from the access point, and typically slower than an equivalent wired link.", "check": {"question": "Why is a wired fibre-optic connection generally considered faster and more reliable than a wireless one?", "options": ["It is less affected by interference and does not weaken with distance from an access point the way wireless does", "Wireless connections are physically and completely incapable of ever transferring more than a few tiny bytes of data at once", "All wired connections are automatically free, while every wireless connection has a cost", "Fibre-optic cable is a form of wireless technology that simply looks like a cable"], "answer": 0, "explain": "Wireless signals weaken with distance and can be disrupted by interference; a wired connection, especially fibre, avoids both issues, which is why it''s typically faster and more consistent."}}, {"myth": "Thinking a mesh topology, like a star, still relies on one central device that every connection passes through.", "truth": "A mesh topology has <strong>no central device</strong> at all — every device connects <em>directly</em> to every other device. It is a star topology that relies on one central device (usually a switch), which is exactly why a mesh is more resilient to a single point of failure.", "check": {"question": "Does a mesh topology rely on one central device that every other device connects through?", "options": ["No — every device connects directly to every other device, with no central device", "Yes — a mesh topology always uses a central switch device, exactly just like a star topology does", "Yes, but only when there are fewer than three devices connected", "No — a mesh topology uses no cables of any kind between its devices"], "answer": 0, "explain": "The defining feature of a mesh topology is direct device-to-device connections with no central point — that''s what makes it resilient to any single device failing."}}, {"myth": "Assuming more bandwidth always guarantees a faster network, no matter how many devices are using it at once.", "truth": "Bandwidth only sets the <strong>maximum</strong> a connection can carry. Real performance still depends on how many users or devices are <em>actively</em> competing for that same bandwidth at any one moment — a high-bandwidth connection shared by hundreds of active users can still feel slow.", "check": {"question": "A network has very high bandwidth, but 200 devices are streaming video on it at the same time. What is most likely to happen?", "options": ["Performance can still slow down, because the bandwidth is shared between all the active devices", "Performance is completely guaranteed to stay fast at all times, regardless of how many devices are actively connected", "The extra devices will have no effect at all on the network''s available bandwidth", "Bandwidth automatically increases itself whenever more devices connect"], "answer": 0, "explain": "Bandwidth is a shared, finite resource. Even a high-bandwidth connection can slow down once enough devices are actively competing for a share of it at the same time."}}, {"myth": "Believing the cloud is some kind of storage that exists without any physical hardware, literally ''in the sky''.", "truth": "Cloud storage is still stored on <strong>real, physical servers</strong> — just servers owned and managed by someone else, in a data centre, accessed remotely over the Internet rather than on hardware you own locally.", "check": {"question": "Is data stored ''in the cloud'' stored without using any physical storage hardware at all?", "options": ["No — it is stored on real physical servers owned by a cloud provider, accessed over the Internet", "Yes — cloud data exists purely as radio signals with no physical storage involved", "Yes, because cloud storage providers never use any physical data centres or storage equipment whatsoever", "No — but only for the first year of a paid cloud storage subscription"], "answer": 0, "explain": "Cloud storage is real, physical storage — just located on a provider''s own servers rather than the user''s local device — accessed remotely over an Internet connection."}}, {"myth": "Describing the LAN/WAN difference only by ''a WAN is just a really big LAN'', without mentioning ownership of the infrastructure.", "truth": "Scale is only half the answer. A LAN''s infrastructure is normally owned and controlled by the single organisation using it, while a WAN typically relies on infrastructure <strong>leased from telecommunications companies</strong> that connect distant sites together — a full answer should mention both scale AND who controls the infrastructure.", "check": {"question": "Besides geographical scale, what else usually distinguishes a WAN from a LAN?", "options": ["Who owns and controls the network infrastructure being used", "The total number of computers connected, regardless of location", "Whether the network uses electricity to transfer any of its data", "Whether the network was installed before or after the year 2000"], "answer": 0, "explain": "A full comparison includes ownership: a LAN''s infrastructure is usually owned by the one organisation using it, while a WAN typically relies on infrastructure leased from telecoms providers."}}]}, "tips": {"enabled": true, "items": [{"title": "Command-word ladder: a 4-mark ''describe'' on the DNS lookup process", "html": "<p>A typical question: <em>\"Describe how a DNS lookup converts a URL into the correct IP address.\"</em> [4 marks] The same idea, shown at every level:</p>\n\n<p><strong>❌ 0-1 marks:</strong> \"DNS finds the website''s address.\"</p>\n<ul>\n<li>True in spirit, but far too vague to be creditable — it doesn''t describe a PROCESS at all, just restates what DNS is for.</li>\n</ul>\n\n<p><strong>⚠️ 2 marks:</strong> \"The browser sends the URL to a DNS server, which looks up the matching IP address and sends it back.\"</p>\n<ul>\n<li>This captures the middle of the process, but skips the browser''s own cache check at the start and what happens once the IP address comes back.</li>\n</ul>\n\n<p><strong>✅ 4 marks:</strong> \"First the browser checks its own cache for the IP address. If it isn''t there, the browser sends the URL to a DNS server. The DNS server looks up the matching IP address in its records (asking another DNS server if needed). Finally, the DNS server returns the IP address to the browser, which uses it to request the page from the correct web server.\"</p>\n\n<p><strong>Why this matters:</strong> \"describe how X works\" questions on this topic are almost always marked as a numbered SEQUENCE of steps, one mark per genuine step. Naming DNS''s purpose is not the same as describing its process — write the steps in order, and don''t skip the first one (checking the cache) or the last one (using the IP address that comes back).</p>", "check": {"question": "A student answers ''Describe how a DNS lookup works'' by writing only ''DNS looks up IP addresses for websites''. Why does this likely score very few of the 4 marks?", "options": ["It states the purpose of DNS but doesn''t describe the actual step-by-step process", "It is factually incorrect about what DNS does for a website", "It is far too long and detailed an answer for a 4-mark question to ever reward fully", "DNS lookups cannot be described in words, only diagrams can be credited"], "answer": 0, "explain": "''Describe how'' questions need the actual sequence of steps — checking cache, contacting a DNS server, the lookup, returning the IP address — not just a restatement of DNS''s overall purpose."}}, {"title": "''Give one advantage and one disadvantage'' — don''t double up on one side", "html": "<p>This exact style of question appears constantly on this topic — comparing topologies, client-server vs peer-to-peer, cloud vs local storage, wired vs wireless. The trap is always the same.</p>\n\n<p><strong>❌ The trap:</strong> writing two advantages (or two disadvantages) because you''re more confident about one side, hoping both will count. They won''t — the mark scheme groups the marks as ONE for a genuine advantage and ONE for a genuine disadvantage, so two advantages score only half marks at best, never full marks.</p>\n\n<p><strong>✅ The reliable method:</strong> before writing anything, plan explicitly: \"Advantage: ___. Disadvantage: ___.\" One clear sentence for each, addressing BOTH sides the question actually asked for.</p>\n\n<p><strong>Worked example — cloud storage vs local storage:</strong></p>\n<ul>\n<li><strong>Advantage:</strong> data stored in the cloud can be accessed from any device with an Internet connection, not just the one it was saved on.</li>\n<li><strong>Disadvantage:</strong> accessing that data depends entirely on having a working Internet connection — no connection means no access, even to your own files.</li>\n</ul>", "check": {"question": "A question asks for one advantage and one disadvantage of cloud storage [2 marks]. A student writes two separate advantages, no disadvantage. What is the maximum they can score?", "options": ["1 mark, since only one genuine advantage can be credited without any disadvantage given", "2 marks, since two separate correct points about cloud storage were made in total across the answer", "0 marks, because the question specifically required exactly one sentence", "2 marks, as long as both advantages are longer than three lines each"], "answer": 0, "explain": "The mark scheme awards one mark for a genuine advantage and one for a genuine disadvantage. With no disadvantage attempted, only the advantage mark is available — maximum 1 of 2."}}, {"title": "The 8-mark ''discuss'' ladder: choosing between star and mesh", "html": "<p>An 8-mark discuss question gives you a scenario and asks you to weigh up a choice — here, star vs mesh topology for a given organisation. Roughly 10-12 minutes; plan before writing.</p>\n\n<p><strong>The structure that reaches the top band:</strong></p>\n<ul>\n<li><strong>1. How each topology is wired</strong> — briefly state the mechanism of both (star = central device, mesh = every device to every other device) so the marker knows you understand what you''re comparing.</li>\n<li><strong>2. A chain for topology A</strong> — factor → effect → consequence. E.g. \"a star topology needs less cabling (factor) → which keeps installation cost and complexity down (effect) → making it affordable for an organisation with a limited IT budget (consequence).\"</li>\n<li><strong>3. A counterpoint</strong> — the same factor from the OTHER topology''s side. E.g. \"however, the star topology''s single point of failure at the switch means one fault can take down the entire network.\"</li>\n<li><strong>4. A second, different issue</strong> — don''t just repeat cabling; also weigh resilience, or cost, or scalability, depending which you haven''t covered yet.</li>\n<li><strong>5. A separate, justified conclusion</strong> — state which topology suits THIS scenario specifically, and why, rather than which topology is \"better\" in general.</li>\n</ul>\n\n<p><strong>Why this matters:</strong> the top mark band on OCR''s discuss questions rewards weighing BOTH sides against the actual scenario given, not simply listing everything you know about star and mesh topologies in general.</p>", "check": {"question": "An 8-mark ''discuss'' answer lists five correct facts about star and mesh topologies, but never applies any of them to the scenario given in the question. Which band is this most likely to land in?", "options": ["A lower band, since the top band requires the discussion to be applied to the given scenario", "The top band automatically, since every single fact that was listed happens to be technically accurate", "Zero marks, since listing facts is never creditable on any exam question", "It cannot be marked at all without a diagram included in the answer"], "answer": 0, "explain": "Correct but generic facts, never applied to the specific scenario, are exactly what keeps a discuss answer out of the top band — application to context is what the higher bands reward."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Identify which of these networks is best described as a WAN rather than a LAN.</p>", "marks": 1, "hint": "Look for the option that covers a large geographical area spanning more than one site.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>A network connecting a supermarket chain''s stores in different cities across the country</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The other three options all describe a network confined to a single site, which is a LAN, not a WAN.</li>\n</ul>\n</div>"}, {"question": "<p>Keswick Design Studio wants a piece of hardware that will let its four PCs and one server share files and a printer within the same office. Identify the hardware that does this job.</p>", "marks": 1, "hint": "Think about which device connects multiple wired devices together within one LAN, rather than connecting to a different network.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>A switch</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>A router connects different networks together, and a DNS server/web server play no role in wiring devices together within one office LAN.</li>\n</ul>\n</div>"}, {"question": "<p>Identify what a DNS server converts a URL into.</p>", "marks": 1, "hint": "DNS''s entire job is one specific conversion — think about what a computer actually needs in order to contact a web server.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>The matching IP address</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>DNS performs a lookup only; it does not store files, encrypt data, or record physical locations.</li>\n</ul>\n</div>"}, {"question": "<p>Parkview Academy''s new sixth-form centre, in a nearby town, needs to connect back to the main school site''s network. State one reason why this connection would be classed as a WAN rather than a LAN.</p>", "marks": 1, "hint": "Think about the geographical scale involved, not the number of computers.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>The sixth-form centre and the main school site are in different geographical locations (different towns) or it connects two separate sites over a large distance, rather than devices within one site</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any answer that correctly links the WAN classification to geographical scale/distance between separate sites.</li>\n</ul>\n</div>"}, {"question": "<p>Describe what the switch in Keswick Design Studio''s office does.</p>", "marks": 2, "hint": "Two separate points: what it connects, and how it decides where to send data.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>Connects the multiple wired PCs and the server together within the studio''s own LAN</li>\n<li>Forwards each piece of data only to the specific device it is addressed to, rather than to every device</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both points must be about a switch specifically (not a router) to be credited.</li>\n</ul>\n</div>"}, {"question": "<p>Keswick Design Studio later adds a router so that staff can access the Internet. Describe what this router does.</p>", "marks": 2, "hint": "A router''s job is different from a switch''s job — think about which networks it connects, not which devices.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>Connects the studio''s own LAN to a different network — the Internet</li>\n<li>Directs (routes) data between the studio''s network and the Internet based on IP addresses</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both points must be about a router specifically; describing a switch''s job here earns no marks.</li>\n</ul>\n</div>"}, {"question": "<p>Parkview Academy''s student records system uses a client-server network, with one central server storing all student data. Identify the role of the client and the role of the server in this network.</p>", "marks": 2, "hint": "One role requests and uses data; the other role stores and provides it.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>The client (a teacher''s computer) requests and makes use of student data held on the server</li>\n<li>The server stores the student data centrally and provides/sends it to client computers when requested</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each role must be correctly matched to client or server, not swapped.</li>\n</ul>\n</div>"}, {"question": "<p>Parkview Academy''s after-school computing club has five laptops. The club wants to share files directly between the laptops without setting up a dedicated server. Justify why a peer-to-peer network would suit the club better than a client-server network.</p>", "marks": 2, "hint": "Give your choice, then a reason linked to the club''s situation (small, informal, no budget for a dedicated server).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: correctly chooses peer-to-peer</li>\n<li>1 mark: valid justification, e.g. cheap/simple to set up for a small number of devices with no dedicated server or IT expertise needed</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The justification mark requires a reason that fits THIS scenario (small, informal, no budget) — a generic unlinked fact about peer-to-peer alone is not enough.</li>\n</ul>\n</div>"}, {"question": "<p>Give one advantage and one disadvantage of using a wireless connection compared to a wired connection.</p>", "marks": 2, "hint": "One clear advantage, one clear disadvantage — don''t give two of the same side.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark for a genuine advantage, e.g. no cables needed, devices can move freely, easier to add devices</li>\n<li>1 mark for a genuine disadvantage, e.g. generally slower, more affected by interference/distance from the access point</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Two advantages (or two disadvantages) score a maximum of 1 mark, not 2.</li>\n</ul>\n</div>"}, {"question": "<p>Describe the difference between the URL the customer types in and the IP address used to actually locate Brightweb Shop''s web server.</p>", "marks": 2, "hint": "One is written for people; the other is used by computers to route data.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>The URL (www.brightweb-shop.co.uk) is the human-readable web address the customer types in</li>\n<li>The IP address is the numerical address that computers actually use to find and communicate with the correct web server</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both points must be present; simply naming \"URL\" and \"IP address\" without describing what each actually is scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Describe the roles of the web server and the client (browser) when the customer requests Brightweb Shop''s website.</p>", "marks": 2, "hint": "One side stores and sends the files; the other side asks for and displays them.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>The web server stores the website''s files and sends them when requested</li>\n<li>The client (the customer''s browser) requests the webpage and displays the files it receives back</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both roles must be correctly matched — swapping web server and client earns no marks.</li>\n</ul>\n</div>"}, {"question": "<p>At busy times of the school day, many students at Parkview Academy connect to the wireless network at once. Explain how this affects the network''s performance.</p>", "marks": 3, "hint": "Link the number of active users to the shared, limited resource, then to the effect students would actually notice.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, to a maximum of 3)</h5>\n<ul>\n<li>Bandwidth (the maximum amount of data the connection can carry) is a shared, limited resource</li>\n<li>When many students are actively using the network at the same time, each device gets a smaller share of that bandwidth</li>\n<li>This results in slower performance for everyone — e.g. webpages and files take longer to load</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Full marks needs the chain from \"shared bandwidth\" through to a real, noticeable effect, not just naming bandwidth alone.</li>\n</ul>\n</div>"}, {"question": "<p>Parkview Academy''s wireless network sometimes performs badly in classrooms with thick stone walls, even when few students are connected. Explain how interference could cause this.</p>", "marks": 3, "hint": "Link the physical cause (walls/interference) to what happens to the signal, then to the effect on performance.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, to a maximum of 3)</h5>\n<ul>\n<li>Thick walls and other electrical equipment can cause interference with the wireless radio signal</li>\n<li>This interference weakens or corrupts the signal as it travels between the device and the wireless access point</li>\n<li>Data may need to be resent as a result, which slows down the network''s performance in that classroom</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award marks for the chain from cause (interference) to mechanism (weakened/corrupted signal) to effect (resending data, slower performance).</li>\n</ul>\n</div>"}, {"question": "<p>Keswick Design Studio is deciding how to wire its five devices (four PCs and one server) into a star topology, using its existing switch as the central device. Draw a diagram to show how these five devices should be connected in a star topology.</p><p>(This question is best answered by sketching your diagram on paper — describe it clearly in words if you are typing your answer.)</p>", "marks": 3, "hint": "Every device needs its own individual cable running to the central switch, and to nowhere else.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, to a maximum of 3)</h5>\n<ul>\n<li>Shows one central device (the switch), drawn once</li>\n<li>Shows each of the other five devices connected to the central switch by its own individual cable</li>\n<li>Shows no direct connections between any of the five other devices themselves (only to the switch)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>A diagram with any device wired directly to another device (other than the switch) loses the third mark, since that would not be a true star topology.</li>\n</ul>\n</div>"}, {"question": "<p>Keswick Design Studio is also considering rewiring its five devices into a mesh topology instead. Describe how a mesh topology would connect these devices.</p>", "marks": 3, "hint": "Say what connects to what, then use the cabling rule to say how many cables this would actually need for five devices.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, to a maximum of 3)</h5>\n<ul>\n<li>Every device connects directly to every other device</li>\n<li>There is no central device (no switch needed) that the connections depend on</li>\n<li>For 5 devices this needs n(n − 1) ÷ 2 = 5 × 4 ÷ 2 = 10 separate cables</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept the correct cable total (10) shown either using the formula or by systematic counting.</li>\n</ul>\n</div>"}, {"question": "<p>Sunnyside Bakery is deciding whether to move its sales records and staff rotas from the single computer in its main shop to a cloud storage service instead. Justify which option you would recommend, giving one advantage and one disadvantage of your chosen option.</p>", "marks": 3, "hint": "State your recommendation first, then a reason it suits a small business with three shops, then a genuine advantage and disadvantage of that option.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark: a clear recommendation (cloud storage or local storage)</li>\n<li>1 mark: a justification linked to the bakery having three separate shops</li>\n<li>1 mark: a further genuine advantage or disadvantage of the recommended option</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both cloud storage and local storage can score full marks if justified consistently and correctly for the bakery''s situation.</li>\n</ul>\n</div>"}, {"question": "<p>Describe, step by step, how a DNS lookup converts the URL the customer typed in into the IP address needed to actually reach Brightweb Shop''s web server.</p>", "marks": 4, "hint": "There are four distinct steps: what the browser checks first, what it does next, what the DNS server does, and what happens once the address comes back.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per step)</h5>\n<ul>\n<li>The browser first checks whether it already has the matching IP address stored (cached) from an earlier visit</li>\n<li>If not found, the browser sends the URL to a DNS server</li>\n<li>The DNS server looks up the matching IP address in its records, asking another DNS server if it does not hold that record itself</li>\n<li>The DNS server returns the IP address to the browser, which then uses it to request the page from the correct web server</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each of the four steps is credited independently, in any order they are described, provided the overall sequence is logically consistent.</li>\n</ul>\n</div>"}, {"question": "<p>Parkview Academy''s IT technician is classifying different parts of the school''s network. Tick (✓) <strong>one</strong> box in each row to identify whether each example is best described as a LAN or a WAN.</p>", "marks": 4, "hint": "Ask whether each example is confined to one site (LAN) or spans a large geographical area between separate sites (WAN).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Sixth-form centre link → <strong>WAN</strong> (separate town/site)</li>\n<li>Three on-site buildings → <strong>LAN</strong> (one site)</li>\n<li>Exam board network across cities → <strong>WAN</strong> (large geographical area)</li>\n<li>Single classroom wireless network → <strong>LAN</strong> (confined to one site)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently. Two ticks in the same row scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Keswick Design Studio is choosing between a star topology and a mesh topology for its five devices. Give one advantage and one disadvantage of a star topology, and one advantage and one disadvantage of a mesh topology.</p>", "marks": 4, "hint": "Four separate points needed — plan them as a 2x2 grid before you write: star advantage, star disadvantage, mesh advantage, mesh disadvantage.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per point)</h5>\n<ul>\n<li>Star advantage: a single cable/device failure only affects that one device or consistent, fast performance or easy to add new devices</li>\n<li>Star disadvantage: the whole network fails if the central switch fails or needs more cabling than some alternative layouts</li>\n<li>Mesh advantage: highly resilient — no single point of failure, since data can be re-routed if a cable/device fails</li>\n<li>Mesh disadvantage: needs far more cabling as devices are added (n(n − 1) ÷ 2) or expensive and complex to install</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each of the four points is marked independently against its own cell — extra points on one topology cannot substitute for a missing point on the other.</li>\n</ul>\n</div>"}, {"question": "<p>Draw <strong>one</strong> line from each piece of network hardware to the job it actually performs.</p><p>(There are more job descriptions than hardware items — one description is not used.)</p>", "marks": 5, "hint": "Match each device to what it actually DOES, not just where it sounds like it belongs — watch for the DNS-lookup description, which belongs to none of these five items.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks (1 mark per correct line)</h5>\n<ul>\n<li>NIC → <strong>F</strong> (lets a device physically connect to a network at all)</li>\n<li>Switch → <strong>B</strong> (connects multiple wired devices within the same LAN)</li>\n<li>Router → <strong>C</strong> (connects one network to a different network, such as the Internet)</li>\n<li>WAP → <strong>A</strong> (connects wireless devices to a wired LAN)</li>\n<li>Fibre-optic cable → <strong>E</strong> (carries data as pulses of light through glass, at high speed)</li>\n<li>D (\"looks up the IP address matching a URL\") is the unused decoy — that is DNS''s job, not any of these five items.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Any 2 lines from 1 hardware item scores 0 marks for that item.</li>\n</ul>\n</div>"}, {"question": "<p>Explain the benefits and drawbacks of Sunnyside Bakery moving its sales records and staff rotas to cloud storage, instead of keeping them on the single computer it currently uses.</p>", "marks": 6, "hint": "Cover several distinct benefits AND several distinct drawbacks — don''t repeat the same idea reworded, and don''t only argue one side.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks (up to 3 for benefits, up to 3 for drawbacks)</h5>\n<ul>\n<li>Benefit: staff at all three shops can access the same up-to-date records from any device with an Internet connection</li>\n<li>Benefit: backups and maintenance are handled by the cloud provider, not the bakery</li>\n<li>Benefit: storage can be scaled up easily without buying new local hardware</li>\n<li>Drawback: access depends entirely on having a reliable Internet connection</li>\n<li>Drawback: an ongoing subscription cost is likely, rather than a one-off purchase</li>\n<li>Drawback: the bakery must trust a third party with the security/privacy of its sales data</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award up to 3 marks for genuinely distinct benefits and up to 3 for genuinely distinct drawbacks; a sixth benefit cannot be credited in place of a missing drawback.</li>\n</ul>\n</div>"}, {"question": "<p>Keswick Design Studio is expanding and must choose how to wire its network: a star topology (using its existing switch) or a mesh topology connecting all its devices directly to each other.</p><p>Discuss which topology Keswick Design Studio should choose for its office network.</p><p>In your answer you might consider:</p><ul><li>how each topology is wired, and the cabling this requires as the studio grows</li><li>the effect on the network''s resilience if a cable or device fails</li><li>the cost and complexity of installing and maintaining each topology</li><li>which topology you would recommend for this studio, and why</li></ul>", "marks": 8, "hint": "Use all four bullets as your plan. Explain how each topology works, follow the mechanism through to a REAL consequence for a growing design studio, and weigh cost against resilience for a top-band answer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (levelled) — indicative content</h5>\n<p>The following is indicative of possible factors/evidence that candidates may refer to but is not prescriptive or exhaustive:</p>\n<ul>\n<li><strong>How each topology is wired and cabling required</strong> — a star topology connects every device individually to the central switch (one cable per device); a mesh topology connects every device directly to every other device, needing n(n − 1) ÷ 2 cables, which grows much faster as the studio adds more devices.</li>\n<li><strong>Effect on resilience</strong> — in a star topology, a single device/cable failure only affects that device, but the central switch failing brings down the whole network; in a mesh topology, there is no single point of failure, since data can be re-routed around any failed cable or device.</li>\n<li><strong>Cost and complexity</strong> — a star topology is cheaper and simpler to install and maintain, especially for a smaller studio; a mesh topology is far more expensive and complex to wire and maintain as more devices are added, since every new device needs a cable to every existing device.</li>\n<li><strong>Recommendation</strong> — the better choice depends on how much Keswick Design Studio values guaranteed uptime versus cost: a star topology suits a growing but budget-conscious studio where an occasional switch failure is an acceptable risk; a mesh topology would only be justified if the studio''s work could never tolerate any network downtime, regardless of the extra cost and cabling complexity.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>Mark Band 3 — High Level (6–8 marks):</strong> Thorough knowledge and understanding of star and mesh topologies, applied directly and consistently to Keswick Design Studio''s situation. The response weighs up both topologies (resilience against cost/complexity) and covers all four areas from the bullet list with clear, logically structured reasoning, ending in a justified recommendation.</li>\n<li><strong>Mark Band 2 — Mid Level (3–5 marks):</strong> Reasonable knowledge, generally accurate but at times underdeveloped or only partly applied to the studio''s context. Most of the four areas are addressed, with some structure, though the discussion may not fully weigh both topologies or the recommendation may be unjustified.</li>\n<li><strong>Mark Band 1 — Low Level (1–2 marks):</strong> Basic knowledge with limited understanding shown; the material may contain inaccuracies or barely refer to the studio''s context. Little more than an unsupported assertion, e.g. \"star is better\" with no working explanation of why.</li>\n<li><strong>0 marks:</strong> No attempt to answer the question or response is not worthy of credit.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', '{"learn": {"enabled": true, "items": [{"title": "What is Ethernet, and where is it used?", "html": "<h4>Ethernet: the standard for wired networking</h4>\n<ul>\n<li><strong>Ethernet</strong> is the most widely used standard for connecting devices to a network using cables.</li>\n<li>Ethernet connections normally use <strong>twisted pair copper cable</strong> (fibre-optic cable is sometimes used instead for longer runs, such as a connection between two buildings).</li>\n<li>A device joins the network by plugging an Ethernet cable into its network port and into a switch (or a router with built-in switch ports).</li>\n</ul>\n<h4>Typical uses</h4>\n<ul>\n<li>Ethernet suits devices that stay in one place and need a fast, reliable connection — desktop PCs in a computer suite, servers, and network printers.</li>\n<li>Because the cable carries a dedicated signal straight to that one device, a wired Ethernet connection is not affected by the interference or distance problems that can weaken a wireless connection.</li>\n</ul>", "check": {"question": "Which of these is the most typical use for a wired Ethernet connection?", "options": ["A desktop PC that stays in one fixed place in a school computer suite", "A phone that a student carries around the building all day between lessons", "A laptop being used on a bench outside during an outdoor lesson", "A delivery driver''s handheld scanner being used out on their delivery round"], "answer": 0, "explain": "Ethernet is a wired standard, so it suits fixed devices that stay connected to one cable — not devices that need to move around freely."}}, {"title": "How do Wi-Fi and Bluetooth differ?", "html": "<h4>Wi-Fi — wireless access to a LAN</h4>\n<ul>\n<li><strong>Wi-Fi</strong> lets a device connect wirelessly to a LAN through a <strong>wireless access point (WAP)</strong>, doing the same job wirelessly that an Ethernet cable does for a wired device.</li>\n<li>A single WAP can normally serve many devices at once, and Wi-Fi typically covers a whole room, building or site.</li>\n</ul>\n<h4>Bluetooth — short-range device pairing</h4>\n<ul>\n<li><strong>Bluetooth</strong> creates a short-range wireless connection directly <em>between two nearby devices</em> — no WAP or router is involved at all.</li>\n<li>Typical examples: pairing wireless headphones to a phone, a wireless keyboard to a laptop, or a phone to a car''s speaker system.</li>\n<li>Bluetooth''s range is much shorter than Wi-Fi''s, and it is designed for a small number of devices connecting directly, not for joining a whole LAN.</li>\n</ul>", "check": {"question": "A student pairs their wireless earbuds directly with their phone, with no router or access point involved at all. Which technology is this?", "options": ["Bluetooth", "Wi-Fi, connecting through a wireless access point", "Ethernet, using a wireless-enabled cable", "A fibre-optic wireless connection"], "answer": 0, "explain": "Bluetooth creates a short-range connection directly between two nearby devices without needing a wireless access point — exactly what''s being described here."}}, {"title": "Wired vs wireless: weighing up the trade-offs", "html": "<h4>Comparing wired and wireless connections</h4>\n<table>\n<tr><th>Factor</th><th>Wired (e.g. Ethernet)</th><th>Wireless (e.g. Wi-Fi)</th></tr>\n<tr><td>Speed</td><td>Generally faster and more consistent</td><td>Generally slower, and can vary</td></tr>\n<tr><td>Reliability / interference</td><td>Not affected by walls or radio interference</td><td>Can be weakened by walls, distance and other wireless signals</td></tr>\n<tr><td>Security</td><td>Harder to intercept — needs a physical connection to the cable</td><td>Signals travel through the air and can be intercepted by anyone in range</td></tr>\n<tr><td>Mobility</td><td>Device must stay near its cable</td><td>Device can move freely within range</td></tr>\n<tr><td>Cost / installation</td><td>Cabling can be expensive and disruptive to install in an existing building</td><td>Cheaper and quicker to set up, with no cabling needed</td></tr>\n</table>\n<h4>So which is \"better\"?</h4>\n<ul>\n<li>Neither is better in every situation. A fixed desktop PC in an office usually benefits from a wired connection''s speed and security, while a laptop or phone that needs to move around a building needs wireless.</li>\n<li>Most real networks use both: wired connections for fixed, high-demand devices, and wireless for mobile ones.</li>\n</ul>", "check": {"question": "Why is a wired connection generally considered more secure than an equivalent wireless connection?", "options": ["Intercepting it needs physical access to the cable, unlike a signal broadcast through the air", "Wired connections automatically encrypt every byte of data, while wireless connections never can", "Wireless signals are physically incapable of carrying any data that a hacker could want", "Wired connections cannot be used by more than one device at the same time"], "answer": 0, "explain": "A wired signal stays inside the cable, so intercepting it needs a physical connection to that cable. A wireless signal is broadcast through the air and can be picked up by any device in range."}}, {"title": "How does encryption protect data sent wirelessly?", "html": "<h4>What encryption actually does</h4>\n<ul>\n<li><strong>Encryption</strong> means scrambling data into an unreadable form, using a <strong>key</strong>, before it is sent.</li>\n<li>Only a device that has the correct key can unscramble (decrypt) the data back into its original, readable form.</li>\n</ul>\n<h4>Why wireless networks need it</h4>\n<ul>\n<li>Wireless signals travel through the air in every direction, so anyone within range — not just the intended recipient — can potentially pick up (intercept) the data being sent.</li>\n<li>A wired connection is much harder to intercept, since it would need a physical connection to the cable itself.</li>\n</ul>\n<h4>The key exam point</h4>\n<ul>\n<li>Encryption does <strong>NOT</strong> stop data from being intercepted — a nearby device can still pick up the encrypted signal travelling through the air.</li>\n<li>What encryption does is make any intercepted data <strong>unreadable and useless</strong> to whoever intercepted it, unless they also have the correct key.</li>\n</ul>", "check": {"question": "A hacker intercepts data being sent over an encrypted wireless network. What is actually true?", "options": ["They have the data, but cannot read it without the correct decryption key", "They cannot have intercepted it at all, since encryption blocks interception completely", "They can read it instantly, since encryption only hides who originally sent it", "Encryption stops the wireless signal from ever leaving the sending device"], "answer": 0, "explain": "Encryption doesn''t stop a wireless signal being intercepted — it just makes the intercepted data meaningless without the correct key to unscramble it."}}, {"title": "What does an IP address identify?", "html": "<h4>What an IP address is for</h4>\n<ul>\n<li>An <strong>IP address</strong> identifies a device on a network (and which network it belongs to), so that data sent across the network reaches the correct destination.</li>\n<li>Every device communicating over a network — including the Internet — needs an IP address.</li>\n</ul>\n<h4>IP addresses can change</h4>\n<ul>\n<li>Unlike some hardware identifiers, an IP address is <strong>assigned by the network</strong> the device is connected to, rather than being fixed permanently to the device itself.</li>\n<li>A device''s IP address can change — for example, if it connects to a different network, or if the same network assigns it a new address the next time it connects.</li>\n</ul>", "check": {"question": "Which statement correctly describes an IP address?", "options": ["It is assigned by the network a device connects to, and can change between connections", "It is a fixed hardware code that is burned into a device''s network card and never changes", "It is a password that must be entered before a device is allowed onto a wireless network", "It is a brand name given by a manufacturer to one specific model of router"], "answer": 0, "explain": "An IP address is assigned by whichever network a device joins, which is exactly why it can change — that description belongs to a MAC address instead."}}, {"title": "IPv4 vs IPv6 — two address formats", "html": "<h4>IPv4</h4>\n<ul>\n<li>Written as four <strong>denary (decimal)</strong> numbers, each between 0 and 255, separated by dots — for example, 192.168.1.1.</li>\n<li>Each of the four numbers is called an <strong>octet</strong>.</li>\n</ul>\n<h4>IPv6</h4>\n<ul>\n<li>Written as eight groups of <strong>hexadecimal</strong> digits, separated by colons — for example, 2001:0db8:0000:0000:0000:ff00:0042:8329.</li>\n</ul>\n<h4>Why IPv6 exists</h4>\n<ul>\n<li>IPv4 only allows a limited number of unique addresses, and the huge growth in the number of devices connecting to the Internet meant the supply of available IPv4 addresses has been running out.</li>\n<li>IPv6 provides a vastly larger range of possible addresses, so there are enough unique addresses for every device that needs one, now and in future.</li>\n</ul>", "check": {"question": "Why was IPv6 introduced alongside IPv4?", "options": ["IPv4 only offers a limited number of unique addresses, and these were running out", "IPv4 addresses were found to be far too easily intercepted on wireless networks", "IPv6 exists purely to make addresses easier for people to memorise and type", "IPv4 stopped working correctly once mobile phones first connected to the Internet"], "answer": 0, "explain": "IPv4''s address space is limited, and the growing number of Internet-connected devices used up the available supply — IPv6 provides a far larger range of addresses instead."}}, {"title": "What is a MAC address?", "html": "<h4>A hardware identifier</h4>\n<ul>\n<li>A <strong>MAC (Media Access Control) address</strong> is a unique identifier assigned to a device''s network interface card (NIC).</li>\n<li>It is written in <strong>hexadecimal</strong>, usually shown as six pairs of digits separated by colons or hyphens — for example, 00:1B:44:11:3A:B7.</li>\n</ul>\n<h4>Set once, and never changed</h4>\n<ul>\n<li>A MAC address is <strong>burned into the NIC by its manufacturer</strong> at the point of manufacture — it is not assigned by whichever network the device happens to join.</li>\n<li>This makes a MAC address <strong>unique to that one physical device</strong>, and it stays the same for the device''s whole lifetime, unlike an IP address.</li>\n<li>MAC addresses are used to identify devices on a LAN — for example, a switch reads the destination MAC address to work out which device on the LAN to forward data to.</li>\n</ul>", "check": {"question": "What is true about a device''s MAC address?", "options": ["It is burned into the network interface card by its manufacturer, and never changes", "It is assigned fresh by whichever network the device connects to each time", "It is chosen freely by the user the first time they set up a network connection", "It exists only for wireless devices, since wired devices use their IP address instead"], "answer": 0, "explain": "A MAC address is fixed permanently by the manufacturer when the network card is made — every networked device, wired or wireless, has one."}}, {"title": "IP address vs MAC address — the exam''s favourite comparison", "html": "<h4>Two different addresses, two different jobs</h4>\n<table>\n<tr><th>Feature</th><th>IP address</th><th>MAC address</th></tr>\n<tr><td>Assigned by</td><td>The network the device connects to</td><td>The manufacturer, burned into the NIC</td></tr>\n<tr><td>Can it change?</td><td>Yes — it can change between networks or sessions</td><td>No — it is permanent for the life of the device</td></tr>\n<tr><td>Format</td><td>Denary (IPv4) or hexadecimal (IPv6)</td><td>Hexadecimal</td></tr>\n<tr><td>Main purpose</td><td>Routing data between different networks</td><td>Identifying a specific device on a LAN</td></tr>\n</table>\n<h4>The line examiners look for</h4>\n<ul>\n<li>Say it as a contrast: an IP address is <strong>logical</strong> and can change, because the network assigns it; a MAC address is <strong>physical</strong> and permanent, because the manufacturer burns it into the hardware.</li>\n</ul>", "check": {"question": "Which address is assigned by the network a device connects to, meaning it can change?", "options": ["The IP address", "The MAC address", "Both addresses always change together at the same time", "Neither address is ever assigned to a device"], "answer": 0, "explain": "The IP address is assigned by the network, so it can change — the MAC address is fixed permanently by the manufacturer and never changes."}}, {"title": "What is a standard, and why do networks need them?", "html": "<h4>An agreed specification</h4>\n<ul>\n<li>A <strong>standard</strong> is an agreed set of rules or specifications that hardware and software are designed to follow.</li>\n</ul>\n<h4>Why they matter</h4>\n<ul>\n<li>Without standards, a network card made by one manufacturer might not be able to communicate at all with a switch or router made by a completely different manufacturer.</li>\n<li>Standards mean that hardware and software from <strong>different manufacturers can work together</strong> — a laptop, a router and a web server, all made by entirely different companies, can all communicate because they follow the same agreed standards.</li>\n</ul>", "check": {"question": "Why do computer networks rely on agreed standards?", "options": ["So hardware and software made by different manufacturers can work together successfully", "So every network in the whole world is forced to buy its hardware from one single manufacturer", "So a network''s speed automatically increases every time a new standard is published", "So governments can charge companies a licence fee before they can sell networking hardware"], "answer": 0, "explain": "A standard is an agreed specification. Following it means equipment from different manufacturers can still communicate and interoperate successfully."}}, {"title": "What is a protocol?", "html": "<h4>An agreed set of rules for communication</h4>\n<ul>\n<li>A <strong>protocol</strong> is an agreed set of rules that governs how devices communicate with each other — for example, the format the data must be sent in, and how errors are handled.</li>\n<li>Different protocols exist for different jobs on a network — sending a webpage, sending an email, and transferring a file each use different protocols.</li>\n<li>For two devices to communicate successfully, both must be using — and correctly following — the same protocol.</li>\n</ul>", "check": {"question": "Which of these best defines a protocol?", "options": ["An agreed set of rules that governs how devices communicate with each other", "A physical networking device that connects several separate computers together within one single office", "A password that must be entered before a device can join a network", "A brand name that a manufacturer gives to its own range of routers"], "answer": 0, "explain": "A protocol is a set of communication rules, not a physical device, a password, or a brand name."}}, {"title": "TCP/IP — how data actually gets across a network", "html": "<h4>A suite, not a single protocol</h4>\n<ul>\n<li><strong>TCP/IP</strong> is a <strong>suite (collection) of protocols</strong> that work together — it is not one single protocol.</li>\n</ul>\n<h4>TCP''s job</h4>\n<ul>\n<li><strong>TCP (Transmission Control Protocol)</strong> splits data into smaller pieces called <strong>packets</strong> before it is sent.</li>\n<li>At the receiving end, TCP reassembles the packets back into their correct order.</li>\n<li>TCP also checks whether any packets are missing or have arrived corrupted, and requests that they be resent if so.</li>\n</ul>\n<h4>IP''s job</h4>\n<ul>\n<li><strong>IP (Internet Protocol)</strong> handles addressing and routing — making sure each packet is sent to the correct IP address and finds its way across the network (or between networks) to its destination.</li>\n</ul>", "check": {"question": "Why is it inaccurate to describe TCP/IP as a single protocol?", "options": ["It''s a suite of protocols, including TCP and IP, that each do a different job", "TCP and IP are actually just two different names for the exact same one protocol", "TCP/IP isn''t a protocol of any kind — it is only a type of network cable", "IP handles email while TCP handles web pages, so they can''t be one protocol"], "answer": 0, "explain": "TCP/IP is a suite: TCP handles splitting data into packets and reassembling them, while IP handles addressing and routing those packets — two different jobs working together."}}, {"title": "Protocols for the web: HTTP, HTTPS and FTP", "html": "<h4>HTTP and HTTPS</h4>\n<ul>\n<li><strong>HTTP (HyperText Transfer Protocol)</strong> is used to request and transfer web pages between a web server and a browser.</li>\n<li><strong>HTTPS (HTTP Secure)</strong> does the same job as HTTP, but adds <strong>encryption</strong> — so the data being transferred cannot be read even if it is intercepted. Websites that handle passwords, bank details or online payments should always use HTTPS.</li>\n</ul>\n<h4>FTP</h4>\n<ul>\n<li><strong>FTP (File Transfer Protocol)</strong> is used to transfer files between computers over a network — for example, uploading a website''s files onto a web server.</li>\n</ul>", "check": {"question": "What is the relationship between HTTP and HTTPS?", "options": ["HTTPS is HTTP with encryption added, for secure data transfer", "HTTPS and HTTP are two completely unrelated protocols with different jobs", "HTTPS completely replaced HTTP, so HTTP is no longer used by any website", "HTTPS is only used for sending email, while HTTP is only used for web pages"], "answer": 0, "explain": "HTTPS performs the same job as HTTP — requesting and transferring web pages — but adds encryption to protect the data being transferred."}}, {"title": "Email protocols: SMTP, POP and IMAP", "html": "<table>\n<tr><th>Protocol</th><th>Job</th></tr>\n<tr><td>SMTP</td><td>Sends email — from a user to their mail server, and between mail servers</td></tr>\n<tr><td>POP</td><td>Retrieves email from a server, and typically removes it from the server once downloaded</td></tr>\n<tr><td>IMAP</td><td>Retrieves email but keeps it on the server, syncing the same mailbox across multiple devices</td></tr>\n</table>\n<h4>The exam trap</h4>\n<ul>\n<li>SMTP is the only one of the three that <strong>sends</strong> email — POP and IMAP are both about <strong>retrieving</strong> email that has already arrived.</li>\n<li>POP and IMAP are easy to mix up: POP usually removes the message from the server once it has downloaded to one device, while IMAP keeps the message on the server so it stays in sync across a phone, a laptop and a tablet all checking the same account.</li>\n</ul>", "check": {"question": "A user wants the same mailbox to stay in sync when they check it from both their phone and their laptop. Which protocol suits this best?", "options": ["IMAP, because it keeps mail on the server and syncs it across every device", "POP, because it downloads a fresh copy of every message to each device it checks", "SMTP, because it is responsible for retrieving mail from a server", "FTP, because it can transfer the same file to more than one device at once"], "answer": 0, "explain": "IMAP keeps messages on the server and syncs the mailbox across devices, whereas POP typically downloads and removes each message from the server once."}}, {"title": "Why are networks divided into layers?", "html": "<h4>The concept</h4>\n<ul>\n<li>A network''s protocols are organised into <strong>layers</strong>. Each layer has its own specific role and its own set of protocols, and handles one part of the overall job of getting data from one device to another.</li>\n<li>Data passes down through the layers on the sending device, across the network, and back up through the matching layers on the receiving device.</li>\n</ul>\n<h4>Benefits of using layers</h4>\n<ul>\n<li><strong>Manageable, self-contained parts:</strong> breaking a complex system into layers makes it far easier to design, understand and build than tackling the whole thing as one enormous system.</li>\n<li><strong>Independent development:</strong> a layer can be updated, redesigned or replaced without needing to change any of the other layers, as long as it still does its job in the same way.</li>\n<li><strong>Standardisation and interoperability:</strong> because each layer follows agreed standards, hardware and software made by different manufacturers can all work together, layer by layer.</li>\n<li><strong>Easier troubleshooting:</strong> if something goes wrong, engineers can test and isolate the fault to one specific layer, rather than searching through the whole system.</li>\n</ul>", "check": {"question": "What is one genuine benefit of dividing a network''s protocols into layers?", "options": ["Each layer can be developed or changed independently, without redesigning the other layers", "Every single layer must always be built and maintained by the exact same one single manufacturer", "Data no longer needs to pass through every layer at all before reaching its destination", "Layers remove the need for any hardware or software standards to ever be followed"], "answer": 0, "explain": "Because each layer only depends on the layers around it doing their own job correctly, it can be updated or replaced on its own without needing every other layer to change too."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Ethernet", "definition": "The standard used for wired network connections, typically over twisted pair copper cable"}, {"term": "Bluetooth", "definition": "A short-range wireless connection directly between two nearby devices, e.g. earbuds to a phone"}, {"term": "Wi-Fi", "definition": "Lets a device connect wirelessly to a LAN through a wireless access point (WAP)"}, {"term": "Encryption", "definition": "Scrambling data into an unreadable form using a key; doesn''t stop interception, but makes intercepted data unreadable"}, {"term": "IP address", "definition": "Identifies a device on a network; assigned by the network, and can change"}, {"term": "IPv4", "definition": "Written as four denary numbers separated by dots, e.g. 192.168.1.1"}, {"term": "IPv6", "definition": "Written as eight groups of hexadecimal digits, introduced because IPv4 addresses were running out"}, {"term": "MAC address", "definition": "A unique hardware identifier, burned into a device''s NIC by its manufacturer, that never changes"}, {"term": "Standard", "definition": "An agreed set of rules/specifications letting hardware and software from different manufacturers work together"}, {"term": "Protocol", "definition": "An agreed set of rules that governs how devices communicate with each other"}, {"term": "TCP", "definition": "Splits data into packets, reassembles them in order, and requests any lost or corrupted packets again"}, {"term": "IP (Internet Protocol)", "definition": "Handles the addressing and routing of packets between networks"}, {"term": "HTTP", "definition": "Requests and transfers web pages between a browser and a web server"}, {"term": "HTTPS", "definition": "HTTP with encryption added, protecting data such as passwords or payment details in transit"}, {"term": "SMTP", "definition": "Sends email, from a user to their mail server and between mail servers"}, {"term": "POP", "definition": "Retrieves email from a server, typically removing it from the server once downloaded"}, {"term": "IMAP", "definition": "Retrieves email but keeps it on the server, syncing the same mailbox across multiple devices"}, {"term": "Layers", "definition": "Dividing a network''s protocols so each layer has its own role; allows independent development and standardisation"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which type of cable is most commonly used for a wired Ethernet connection?", "options": ["Twisted pair copper cable", "A wireless-only radio antenna cable, since Ethernet never uses physical cabling", "An HDMI cable connecting a monitor to a computer", "A coaxial cable used for a television aerial signal"], "answer": 0, "explain": "Ethernet connections typically use twisted pair copper cable (fibre for some longer runs); the other options are used for completely different jobs or aren''t real Ethernet cabling."}, {"question": "A shop''s Wi-Fi network is encrypted. What does this actually achieve?", "options": ["It stops anyone who intercepts the data from being able to read it, without stopping the interception itself", "It makes the wireless signal completely impossible for any other nearby device to ever detect, pick up or intercept in the first place", "It guarantees that only customers who ask staff for the Wi-Fi password can ever connect a device", "It automatically doubles the amount of bandwidth available to every connected device"], "answer": 0, "explain": "Encryption scrambles the data using a key. It doesn''t stop the signal being intercepted — it stops the intercepted data from being readable without that key."}, {"question": "Which of these correctly describes an IP address?", "options": ["An address, assigned by the network, that identifies a device so that data reaches it correctly", "A fixed hardware code, burned into a network card, that never changes for the life of the device", "A password required before a device is allowed to join any wireless network", "A brand name given by a manufacturer to one specific model of router"], "answer": 0, "explain": "An IP address identifies a device and is assigned by the network — the second option actually describes a MAC address instead."}, {"question": "Why does an IPv6 address use a completely different format from an IPv4 address?", "options": ["IPv4''s denary format was running out of unique addresses, so IPv6 uses a far larger hexadecimal format", "IPv6 was designed purely to make network addresses shorter and much quicker for ordinary people to type out", "IPv4 addresses became too easy for hackers to guess correctly, so the format itself had to change", "IPv6 replaced IPv4''s format purely to remove the need for DNS to look up any address at all"], "answer": 0, "explain": "IPv4''s four-denary-number format only allows a limited number of unique addresses. IPv6''s eight-group hexadecimal format provides a vastly larger address space instead."}, {"question": "What is true about a device''s MAC address?", "options": ["It is burned into the network interface card by its manufacturer and stays fixed for the device''s life", "It is assigned freshly by whichever network the device happens to connect to, and can change between different networks", "It is chosen freely by the device''s user the first time a network connection is set up", "It only exists for wireless devices, since wired devices are identified by their IP address instead"], "answer": 0, "explain": "A MAC address is fixed by the manufacturer when the network interface card is made — it does not change when the device joins a different network."}, {"question": "A technician says a device''s IP address can change, but its MAC address cannot. Why is this correct?", "options": ["The IP address is assigned by the network the device joins, while the MAC address is fixed by the manufacturer", "Both addresses are actually fixed completely permanently, so the technician''s statement here must be incorrect", "The MAC address only ever applies to a device''s very first network connection, then it changes", "IP addresses cannot change once a device has connected to any network for the very first time"], "answer": 0, "explain": "An IP address is assigned fresh by whichever network a device joins, so it can change. A MAC address is burned in at manufacture and never changes."}, {"question": "Why do networks rely on agreed standards?", "options": ["So hardware and software made by different manufacturers can work together and communicate", "So that every network in the world must use hardware bought from one single manufacturer", "So that a network''s speed automatically increases each time a new standard is published", "So governments can charge a licence fee to any company wanting to sell networking hardware"], "answer": 0, "explain": "Standards are agreed specifications. Following them lets equipment from completely different manufacturers still communicate and work together successfully."}, {"question": "What best defines a protocol?", "options": ["An agreed set of rules that governs how devices communicate with each other", "A physical device that connects multiple computers together within one office", "A password that must be entered before a device can join a network", "A brand name that one manufacturer gives to its own range of routers"], "answer": 0, "explain": "A protocol is a set of communication rules, not a physical device, a password, or a manufacturer''s brand name."}, {"question": "What does TCP do to data before IP routes it across a network?", "options": ["Splits it into packets, then reassembles them in order and requests any lost or corrupted ones again", "Permanently deletes the original data from the sender''s device the moment it has finished being sent", "Converts the data into a completely different file format that any device on any network can open", "Physically boosts the strength of a wireless signal so that it is able to travel much further"], "answer": 0, "explain": "TCP''s role is splitting data into packets, reassembling them correctly at the destination, and checking for lost or corrupted packets to be resent."}, {"question": "A website lets customers pay for goods online. Which protocol should its checkout page use, and why?", "options": ["HTTPS, because it adds encryption to protect the customer''s payment data in transit", "FTP, because it was specifically designed to transfer card payment details securely between banks", "SMTP, because it is the protocol responsible for handling secure online payments", "HTTP, because encryption would only slow down how quickly the checkout page loads"], "answer": 0, "explain": "HTTPS does the same job as HTTP but adds encryption, protecting sensitive data such as payment details from being read if intercepted."}, {"question": "A user reads the same email account on their phone and their laptop, and every message stays in sync on both devices. Which protocol is most likely retrieving their mail?", "options": ["IMAP, because it keeps messages on the server and syncs them across every device", "POP, because it downloads a separate independent copy of each message to every device", "SMTP, because it is the protocol responsible for retrieving mail from a server", "HTTP, because it is used for retrieving any content stored on any kind of server"], "answer": 0, "explain": "IMAP keeps mail on the server and keeps every device''s view of the mailbox in sync — POP typically downloads and removes each message from the server instead."}, {"question": "What is one genuine benefit of dividing a network''s protocols into layers?", "options": ["Each layer can be developed or changed independently without needing to redesign the other layers", "It removes the need for absolutely any device anywhere on the whole network to ever follow an agreed standard", "It means data no longer needs to travel through more than one single layer to be delivered", "It guarantees that a network''s overall bandwidth automatically increases every single year"], "answer": 0, "explain": "As long as a layer still does its job the same way, it can be updated or replaced on its own — that independence is one of layering''s core benefits."}]}, "fib": {"enabled": true, "questions": [{"text": "[Ethernet] is the standard most commonly used for wired network connections, usually over twisted pair copper cable."}, {"text": "[Bluetooth] creates a short-range wireless connection directly between two nearby devices, such as a phone and a wireless speaker."}, {"text": "Scrambling data into an unreadable form using a key is called [encryption]."}, {"text": "An IPv4 address is written as four [denary] numbers separated by dots."}, {"text": "A [MAC] address is a unique hardware identifier, burned into a device''s network interface card by its manufacturer."}, {"text": "TCP splits data into smaller pieces called [packets] before sending them across a network."}, {"text": "[IMAP] retrieves email from a server but keeps it there, syncing the same mailbox across multiple devices."}, {"text": "Dividing a network''s protocols into [layers] means each one has its own role, and can be developed independently of the others."}]}, "tf": {"enabled": true, "questions": [{"statement": "Bluetooth is designed to create a short-range connection directly between two nearby devices.", "answer": true, "explain": "Correct — Bluetooth pairs two devices directly, without needing a wireless access point or router."}, {"statement": "A wireless access point (WAP) lets wireless devices join the same LAN that wired devices are already connected to.", "answer": true, "explain": "Correct — a WAP converts between wired and wireless signals, letting wireless devices join an existing LAN."}, {"statement": "Encrypting a wireless network stops the data from being intercepted by anyone else.", "answer": false, "explain": "Encryption does not stop interception — a wireless signal can still be picked up by any device in range. It makes the intercepted data unreadable without the correct key."}, {"statement": "An IPv4 address is written as four denary numbers separated by dots.", "answer": true, "explain": "Correct — for example, 192.168.1.1. IPv6 addresses use eight groups of hexadecimal digits instead."}, {"statement": "A device''s MAC address can change if the device is moved to a different network.", "answer": false, "explain": "A MAC address is burned into the network interface card by its manufacturer and stays the same for the device''s whole life — it is the IP address that can change between networks."}, {"statement": "TCP/IP is a single protocol, rather than a suite of protocols working together.", "answer": false, "explain": "TCP/IP is a suite (collection) of protocols, including TCP and IP, which each do a different job."}, {"statement": "POP typically removes an email from the server once it has been downloaded to a device.", "answer": true, "explain": "Correct — this is the key difference from IMAP, which keeps email on the server and syncs it across devices instead."}, {"statement": "Dividing a network into layers makes it harder to update one part of the system without affecting the rest.", "answer": false, "explain": "The opposite is true — layering means a layer can usually be updated or replaced on its own, without needing to redesign the other layers."}]}, "misc": {"enabled": true, "items": [{"myth": "Mixing up IP addresses and MAC addresses — being unsure which one ''is the one that changes''.", "truth": "It is the <strong>IP address</strong> that can change, since it''s assigned by whichever network the device connects to. The <strong>MAC address</strong> is fixed permanently by the manufacturer when the network card is made, and never changes for that device.", "check": {"question": "Which address is assigned by the network, and can therefore change?", "options": ["The IP address", "The MAC address", "Both addresses change together every time a device connects", "Neither address is ever assigned to a device at all"], "answer": 0, "explain": "The network assigns the IP address, so it can change. The MAC address is fixed permanently by the manufacturer."}}, {"myth": "Thinking SMTP is the protocol used to check an inbox and download new emails.", "truth": "SMTP''s job is to <strong>send</strong> email — from a user to their mail server, and between mail servers. Retrieving email that has already arrived uses a different protocol: POP or IMAP.", "check": {"question": "Which protocol is responsible for SENDING an email?", "options": ["SMTP", "POP", "IMAP", "HTTP"], "answer": 0, "explain": "SMTP sends email. POP and IMAP are both used to retrieve email that has already arrived on a server."}}, {"myth": "Assuming POP and IMAP do exactly the same job, since they''re both used to ''get your email''.", "truth": "Both retrieve email, but differently: POP typically <strong>downloads and removes</strong> the message from the server, so it only exists on the one device it was downloaded to. IMAP <strong>keeps</strong> the message on the server, syncing it across every device that checks the account.", "check": {"question": "A user wants the same mailbox to stay in sync across their phone and laptop. Which protocol suits this best?", "options": ["IMAP", "POP", "SMTP", "FTP"], "answer": 0, "explain": "IMAP keeps mail on the server and syncs it across devices, unlike POP, which typically removes each message from the server once downloaded."}}, {"myth": "Believing HTTPS is a completely separate protocol from HTTP, unrelated to it.", "truth": "HTTPS is simply <strong>HTTP with encryption added</strong>. It does exactly the same job — requesting and transferring web pages — but encrypts the data so it cannot be read if intercepted.", "check": {"question": "What is the relationship between HTTP and HTTPS?", "options": ["HTTPS is HTTP with encryption added, for secure data transfer", "HTTPS and HTTP are two completely unrelated protocols with different jobs", "HTTPS replaced HTTP entirely, so HTTP is no longer used by any website", "HTTPS is used only for sending email, while HTTP is used only for web pages"], "answer": 0, "explain": "HTTPS performs HTTP''s job with encryption added — it is not a separate, unrelated protocol."}}, {"myth": "Believing that encrypting a wireless network stops the data from being intercepted in the first place.", "truth": "Encryption does <strong>not</strong> stop data being intercepted — a wireless signal can still be picked up by any device in range. What encryption does is make the intercepted data <strong>unreadable</strong> without the correct key.", "check": {"question": "A hacker intercepts encrypted data sent over a shop''s Wi-Fi. What is true?", "options": ["They have the data, but cannot read it without the correct key", "They cannot have intercepted the data at all, since it was encrypted", "They can read the data instantly, since encryption only hides who sent it", "Encryption prevents the Wi-Fi signal from ever reaching the hacker''s device"], "answer": 0, "explain": "Encryption doesn''t prevent interception — it makes the intercepted data meaningless without the decryption key."}}, {"myth": "Referring to ''the TCP/IP protocol'' as if it were one single protocol.", "truth": "TCP/IP is a <strong>suite</strong> — a collection of protocols working together, not one protocol. TCP handles splitting data into packets and reassembling them; IP handles addressing and routing those packets between networks.", "check": {"question": "Why is it inaccurate to call TCP/IP ''a single protocol''?", "options": ["It''s a suite of protocols (including TCP and IP) that each do a different job", "TCP and IP are simply two completely different names used for the exact same one protocol", "TCP/IP is not actually a protocol of any kind, only a cable type", "IP handles email while TCP handles web pages, so they can''t be one protocol"], "answer": 0, "explain": "TCP/IP is a suite made up of separate protocols — TCP and IP — that each do a different job."}}]}, "tips": {"enabled": true, "items": [{"title": "Command-word ladder: a 2-mark ''describe'' on POP vs IMAP", "html": "<p>A typical question: <em>\"Describe the difference between how POP and IMAP handle an email once it has been retrieved.\"</em> [2 marks] The same idea, shown at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"POP and IMAP are both used to get your emails.\"</p>\n<ul>\n<li>True, but this doesn''t describe any DIFFERENCE at all — it just restates what both protocols are broadly for.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"POP deletes the email from the server.\"</p>\n<ul>\n<li>Correct about POP, but the question asked for a difference — IMAP''s contrasting behaviour is missing entirely.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"POP typically downloads an email and removes it from the server, so it only exists on that one device. IMAP retrieves the email but keeps it on the server, so it stays synced across every device that checks the account.\"</p>\n\n<p><strong>Why this matters:</strong> \"describe the difference\" questions on this topic need BOTH sides stated, ideally directly contrasted. Naming only one protocol''s behaviour, even correctly, only earns half the marks available.</p>", "check": {"question": "A student answers ''Describe the difference between POP and IMAP'' by writing only ''POP removes the email from the server''. Why does this likely score half marks?", "options": ["It only describes one side of the difference — IMAP''s contrasting behaviour is missing", "It is factually incorrect about what POP actually does to an email once it is downloaded", "It is far too long an answer for a 2-mark question to ever reward fully", "POP and IMAP cannot be compared in an exam answer, only defined separately"], "answer": 0, "explain": "''Describe the difference'' needs both sides — what POP does AND what IMAP does differently — not just one protocol''s behaviour on its own."}}, {"title": "Command-word ladder: a 3-mark ''explain'' on why TCP splits data into packets", "html": "<p>A typical question: <em>\"Explain why TCP splits data into packets before sending it across a network.\"</em> [3 marks] Explain questions need a chain of reasoning, not just a fact.</p>\n\n<p><strong>❌ 0-1 marks:</strong> \"TCP splits data into packets.\"</p>\n<ul>\n<li>This just restates the question — it doesn''t explain WHY splitting into packets is useful, so there''s very little to credit.</li>\n</ul>\n\n<p><strong>⚠️ 1-2 marks:</strong> \"TCP splits data into packets so it can check whether any have gone missing.\"</p>\n<ul>\n<li>This links splitting to ONE genuine reason (checking for loss), but stops short of a full three-step chain.</li>\n</ul>\n\n<p><strong>✅ 3 marks:</strong> \"TCP splits data into smaller packets so that each one can be sent and numbered separately. This means individual packets can be checked for loss or corruption once they arrive. If a packet is missing or corrupted, only that one packet needs to be resent, rather than resending the entire file again from scratch.\"</p>\n\n<p><strong>Why this matters:</strong> \"explain why\" questions on TCP/IP are marked as a chain: mechanism → what it allows → the practical benefit. Naming the fact that TCP splits data into packets is only the first link — follow it through to why that actually helps.</p>", "check": {"question": "Why does a 3-mark ''explain'' question about TCP splitting data into packets need more than the single sentence ''TCP splits data into packets''?", "options": ["It restates the question without explaining WHY splitting the data helps at all", "TCP does not actually split data into packets, so the sentence is factually wrong", "The sentence is too short to fit inside the exam''s printed answer box", "Explain questions about TCP/IP are always levelled 6-8 mark questions"], "answer": 0, "explain": "An ''explain why'' answer needs a chain of reasoning — restating the fact from the question doesn''t explain the reasoning behind it."}}, {"title": "The IP-vs-MAC trap: read the command word AND the address type twice", "html": "<p>Questions that ask you to explain something about BOTH an IP address and a MAC address in the same answer are a very common trap on this topic — it''s easy to accidentally write correct facts about the wrong address.</p>\n\n<p><strong>❌ The trap:</strong> writing \"the MAC address is assigned by the network and can change\" — this sentence is completely correct, just about the wrong address. It''s actually describing an IP address. Marks are lost not because the fact is wrong, but because it''s attached to the wrong label.</p>\n\n<p><strong>✅ The reliable method:</strong> use a simple memory device before you write a single word — <strong>\"M for MAC = Manufacturer = fixed for life\"</strong> and <strong>\"I for IP = In the network''s hands = can change\"</strong>. Say which address you''re describing out loud (or underline it) before writing each sentence.</p>\n\n<p><strong>Worked example — \"explain why a device''s IP address might change, but its MAC address never will\":</strong></p>\n<ul>\n<li><strong>IP:</strong> assigned fresh by whichever network the device joins, so a new network (or reconnecting) can give it a different address.</li>\n<li><strong>MAC:</strong> burned into the network interface card by its manufacturer at production, so it stays fixed for the device''s entire life regardless of which network it joins.</li>\n</ul>", "check": {"question": "A student writes ''the MAC address is assigned by the network and can change'' in answer to an IP-vs-MAC question. What has most likely gone wrong?", "options": ["A true fact about an IP address has been attached to the wrong address''s label", "The sentence is entirely factually incorrect about both IP and MAC addresses", "MAC addresses genuinely are assigned by the network, so this is actually correct", "The student has confused a MAC address with a wireless access point"], "answer": 0, "explain": "The fact described — assigned by the network, can change — correctly describes an IP address, not a MAC address. The content is right; it''s attached to the wrong term."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Northfield College''s computer lab has twenty desktop PCs that never move. Identify which cable type is most likely used to connect them to the network.</p>", "marks": 1, "hint": "Think about the cable type Ethernet connections normally use for fixed, wired devices.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>Twisted pair copper cable</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The other options are either not genuine Ethernet cabling or are used for a completely different job.</li>\n</ul>\n</div>"}, {"question": "<p>A member of staff at Northfield College pairs their wireless headphones directly with their phone. Identify which wireless technology is being used.</p>", "marks": 1, "hint": "Think about which wireless technology creates a short-range connection directly between two nearby devices, without needing a WAP.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>Bluetooth</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Wi-Fi involves a wireless access point; the other two options describe technologies that don''t apply to this direct device-to-device pairing.</li>\n</ul>\n</div>"}, {"question": "<p>State which of these best defines what a protocol is on a computer network.</p>", "marks": 1, "hint": "Think about communication rules, not physical hardware, passwords or branding.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>An agreed set of rules that allows devices to communicate with each other</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The other three options describe hardware, security or branding — none of which is what a protocol actually is.</li>\n</ul>\n</div>"}, {"question": "<p>A new scanner at Meadow Hospital is given the address 192.168.4.17 when it joins the hospital''s network. Identify which type of address this is.</p>", "marks": 1, "hint": "Count how many numbers there are, and check whether they are written in denary or hexadecimal.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>An IPv4 address</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Four denary numbers separated by dots is the IPv4 format; IPv6 uses eight hexadecimal groups, and a MAC address is written in hexadecimal pairs.</li>\n</ul>\n</div>"}, {"question": "<p>PetalCare''s website relies on several network protocols to work correctly. Complete the table by giving the purpose of each protocol.</p>", "marks": 4, "hint": "Match each protocol to the ONE job it actually performs — HTTP and HTTPS are closely related but not identical.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per row)</h5>\n<ul>\n<li>HTTP → requests and transfers web pages between a browser and a web server</li>\n<li>HTTPS → the same job as HTTP, but with encryption added for secure transfer</li>\n<li>FTP → transfers files between computers over a network</li>\n<li>SMTP → sends email, from a user to their mail server and between mail servers</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently. HTTPS must mention encryption to be distinguished from HTTP; naming \"sends email\" for SMTP without any further detail is sufficient.</li>\n</ul>\n</div>"}, {"question": "<p>Meadow Hospital''s IT team is reviewing device records. Tick (✓) <strong>one</strong> box in each row to identify whether each statement describes an IP address or a MAC address.</p>", "marks": 4, "hint": "Ask whether each statement is about something the manufacturer fixes forever, or something the network assigns and can change.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Burned in by the manufacturer, never changes → <strong>MAC address</strong></li>\n<li>Can change if the device joins a different network → <strong>IP address</strong></li>\n<li>Used to route data between different networks → <strong>IP address</strong></li>\n<li>Identifies one specific device, always hexadecimal → <strong>MAC address</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently. Two ticks in the same row scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Draw <strong>one</strong> line from each protocol to the job it actually performs.</p><p>(There are more job descriptions than protocols — one description is not used.)</p>", "marks": 5, "hint": "Match each protocol to what it actually DOES — watch for the description of scrambling data with a key, which belongs to encryption, not to any of these five protocols.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks (1 mark per correct line)</h5>\n<ul>\n<li>TCP → <strong>B</strong> (splits data into packets, reassembles them, and requests any lost or corrupted ones again)</li>\n<li>IP → <strong>C</strong> (handles addressing and routes packets between networks)</li>\n<li>HTTP → <strong>A</strong> (requests and transfers web pages between a browser and a server)</li>\n<li>SMTP → <strong>D</strong> (sends email from a user to their mail server)</li>\n<li>POP → <strong>E</strong> (retrieves email from a server, typically removing it once downloaded)</li>\n<li>F (\"scrambles data into an unreadable form using a key\") is the unused decoy — that is encryption''s job, not any of these five protocols.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Any 2 lines from 1 protocol scores 0 marks for that protocol.</li>\n</ul>\n</div>"}, {"question": "<p>Meadow Hospital''s network engineers describe their system as being divided into layers. Describe what is meant by dividing a network''s communication into layers.</p>", "marks": 2, "hint": "Two separate points: what each layer has of its own, and how data actually moves through them.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>Each layer has its own specific role, and its own set of protocols</li>\n<li>Data passes down through the layers when it is sent, and back up through the matching layers when it is received</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both points must be present for full marks; simply saying \"layers exist\" without describing their role or how data moves scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Describe the benefits of using layers in a network like Meadow Hospital''s.</p>", "marks": 4, "hint": "List up to four distinct benefits — don''t repeat the same idea reworded.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per benefit, to a maximum of 4)</h5>\n<ul>\n<li>Breaks a complex system into smaller, manageable, self-contained parts</li>\n<li>Each layer can be developed, updated or replaced independently, without needing to change the other layers</li>\n<li>Standardisation within each layer lets hardware and software made by different manufacturers work together</li>\n<li>Makes it easier to identify and fix (troubleshoot) faults, by isolating the problem to one layer</li>\n<li>Hides the complexity of the lower layers from the layers above them</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Any four distinct, genuine benefits from the list (or an equivalent correct benefit) score full marks; repeating the same benefit reworded only counts once.</li>\n</ul>\n</div>"}, {"question": "<p>Meadow Hospital''s equipment is made by many different manufacturers, but it can still all communicate over the same network. Explain how using layers, and the standards followed within them, makes this possible.</p>", "marks": 3, "hint": "Build a chain: what each layer follows, then what that lets different manufacturers do.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, to a maximum of 3)</h5>\n<ul>\n<li>Each layer follows its own agreed standard for the job it does</li>\n<li>This means equipment made by different manufacturers can follow the same rules at that layer</li>\n<li>So hardware and software made by different companies can successfully work together, layer by layer, even though no single company made all of it</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Full marks needs the chain from \"standards within a layer\" through to \"different manufacturers'' equipment working together\" — naming standards alone is not enough.</li>\n</ul>\n</div>"}, {"question": "<p>Describe the difference between how POP and IMAP handle an email once it has been retrieved from Granby Veterinary Clinic''s mail server.</p>", "marks": 2, "hint": "One protocol typically removes the message from the server; the other keeps it there.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>POP typically downloads the email and removes it from the server, so it only exists on the one device that downloaded it</li>\n<li>IMAP retrieves the email but keeps it on the server, syncing the same mailbox across every device that checks the account</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both protocols'' behaviour must be stated to earn both marks; describing only one protocol earns a maximum of 1.</li>\n</ul>\n</div>"}, {"question": "<p>Give the name of the protocol Granby Veterinary Clinic''s computers use to send a booking confirmation email, and the name of a protocol used to retrieve email from the server.</p>", "marks": 2, "hint": "One protocol only ever sends; the other two only ever retrieve.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>Sending: SMTP</li>\n<li>Retrieving: POP or IMAP (either is acceptable)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Either POP or IMAP is accepted for the retrieving mark, since both are genuine retrieval protocols.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how TCP prepares Riverbend Games'' large update file to be sent across the network, and how it is put back together correctly at each player''s console.</p>", "marks": 5, "hint": "Five distinct steps: what happens to the file first, what''s added to each piece, how it travels, how it''s rebuilt, and what happens if something goes wrong.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks (1 mark per point, to a maximum of 5)</h5>\n<ul>\n<li>TCP splits the large update file into smaller pieces called packets before it is sent</li>\n<li>Each packet is given information (such as its sequence) so it can be identified and put back in order later</li>\n<li>The packets are sent across the network towards the correct destination (using IP for addressing/routing)</li>\n<li>At the receiving console, TCP reassembles the packets back into the correct order to rebuild the original file</li>\n<li>TCP checks whether any packets are missing or arrived corrupted, and requests that they be resent if so</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each of the five steps is credited independently, in any order they are described, provided the overall sequence is logically consistent.</li>\n</ul>\n</div>"}, {"question": "<p>Riverbend Games'' network engineer describes TCP/IP as \"a protocol suite\". Define what is meant by a protocol suite, using TCP and IP as your example.</p>", "marks": 2, "hint": "First define the general term, then name what TCP and IP each actually do.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>A protocol suite is a collection/group of protocols that work together, rather than a single protocol</li>\n<li>Example: TCP handles splitting data into packets and reassembling them, while IP handles addressing and routing those packets</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The second mark requires a correct example showing TCP and IP doing two DIFFERENT jobs, not just naming both protocols.</li>\n</ul>\n</div>"}, {"question": "<p>PetalCare''s website uses HTTPS rather than HTTP for its checkout page. Describe what HTTPS provides that HTTP does not.</p>", "marks": 2, "hint": "Say what HTTPS adds to HTTP, then what that addition actually protects.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>HTTPS performs the same job as HTTP (requesting/transferring web pages) but adds encryption</li>\n<li>This means data such as the customer''s card details is scrambled and cannot be read if it is intercepted</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Simply stating \"HTTPS is more secure\" without mentioning encryption specifically does not earn the first mark.</li>\n</ul>\n</div>"}, {"question": "<p>Give one reason why PetalCare''s checkout page should use HTTPS rather than HTTP.</p>", "marks": 1, "hint": "Think about what would happen to a customer''s card details if the page used HTTP instead.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>Any valid reason, e.g. HTTPS encrypts the data, protecting the customer''s card/payment details from being read if intercepted</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any answer that correctly links HTTPS to encryption protecting sensitive customer data.</li>\n</ul>\n</div>"}, {"question": "<p>Meadow Hospital''s IT department is running out of available addresses for its growing number of connected devices, and is planning to introduce IPv6 alongside IPv4. Give two reasons why IPv6 was introduced.</p>", "marks": 2, "hint": "Both reasons should relate to the number of available addresses, not to speed or security.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per reason, to a maximum of 2)</h5>\n<ul>\n<li>IPv4 only offers a limited number of unique addresses</li>\n<li>The number of devices connecting to networks (and the Internet) has grown hugely, using up the available IPv4 addresses</li>\n<li>IPv6 provides a vastly larger range of possible addresses than IPv4</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Any two of the listed reasons (or an equivalent correct reason) score full marks.</li>\n</ul>\n</div>"}, {"question": "<p>Meadow Hospital''s IT team is labelling each device''s MAC address as part of a stock check. Describe what a MAC address is, including how it is assigned and its format.</p>", "marks": 3, "hint": "Three separate points: who assigns it, what format it''s written in, and how unique/permanent it is.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, to a maximum of 3)</h5>\n<ul>\n<li>It is burned into (assigned to) the device''s network interface card by its manufacturer, at the point of manufacture</li>\n<li>It is written in hexadecimal</li>\n<li>It is unique to that one physical device, and never changes for the device''s whole life</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>All three points are independently creditable; a description that only covers the format, for example, scores a maximum of 1.</li>\n</ul>\n</div>"}, {"question": "<p>Define the term \"MAC address\".</p>", "marks": 2, "hint": "One part identifies what it is; the other part says how it is given to the device.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>A unique identifier (written in hexadecimal) assigned to a device''s network interface card</li>\n<li>Burned in by the manufacturer, so it is permanent and cannot be changed</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Naming it as simply \"an address for a device\" without both the uniqueness/hardware point and the permanence point scores a maximum of 1.</li>\n</ul>\n</div>"}, {"question": "<p>A Meadow Hospital technician says: \"This scanner''s MAC address will never change, but its IP address might.\" Explain why this statement is correct.</p>", "marks": 4, "hint": "Explain the MAC address side fully, then explain the IP address side fully — four separate judgements in total.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (up to 2 for the MAC address, up to 2 for the IP address)</h5>\n<ul>\n<li>MAC: burned into the network interface card by the manufacturer (1) — so it stays fixed for the device''s whole life (1)</li>\n<li>IP: assigned by whichever network the device connects to (1) — so it can change between networks or reconnections (1)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each address is marked independently; strong explanation of one side cannot substitute for a missing point on the other.</li>\n</ul>\n</div>"}, {"question": "<p>Meadow Hospital buys network equipment from several different manufacturers. Explain why agreed standards are important for this equipment to work together.</p>", "marks": 2, "hint": "Build a two-step chain: what a standard actually is, then what following it lets different manufacturers do.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>A standard is an agreed set of rules/specifications that manufacturers design their hardware and software to follow</li>\n<li>Because different manufacturers'' equipment all follows the same standard, it can successfully communicate and work together, even though it wasn''t all made by the same company</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Simply stating \"standards make things work\" without explaining the link to different manufacturers scores a maximum of 1.</li>\n</ul>\n</div>"}, {"question": "<p>Describe what happens to data sent over Northfield College''s encrypted wireless network.</p>", "marks": 2, "hint": "Two points: what happens to the data before it is sent, and what is needed to turn it back into readable form.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per point)</h5>\n<ul>\n<li>The data is scrambled into an unreadable form, using a key, before it is sent</li>\n<li>Only a device that has the correct key can unscramble (decrypt) it back into readable form</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Simply saying \"the data is encrypted\" without describing what encryption actually does to the data scores a maximum of 1.</li>\n</ul>\n</div>"}, {"question": "<p>A student at Northfield College says that because the college''s Wi-Fi is encrypted, nobody else can ever access the data being sent over it. Explain why this student is mistaken, and explain what encryption actually achieves instead.</p>", "marks": 4, "hint": "Four steps: what can still happen to the signal, why the student''s claim is wrong, what encryption does instead, and why that still protects the data.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per point, to a maximum of 4)</h5>\n<ul>\n<li>Wireless signals travel through the air and can still be intercepted by another device within range, even on an encrypted network</li>\n<li>So the student is wrong — encryption does not stop the data being intercepted (accessed) in that sense</li>\n<li>What encryption actually does is scramble the data into an unreadable form, using a key</li>\n<li>This means any intercepted data is unreadable and useless to whoever intercepted it, unless they also have the correct key</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Full marks needs both halves: correctly explaining why the student is wrong AND correctly explaining what encryption does instead.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', '{"learn": {"enabled": true, "items": [{"title": "What is malware, and what can it actually do?", "html": "<h4>Malware = malicious software</h4>\n<ul>\n<li><strong>Malware</strong> is any software that has been deliberately written to damage, disrupt, or gain unauthorised access to a computer system or network.</li>\n<li>It is defined by what it was designed to DO, not by how it arrives — malware can reach a victim through an email attachment, an infected download, a fake app, or an infected USB stick.</li>\n<li>Once it is running, malware can: <strong>delete or corrupt</strong> files, <strong>lock a user out</strong> of their own data, <strong>steal</strong> personal or financial information, <strong>spy</strong> on what a user types or does, or quietly use the victim''s computer to help attack somebody else.</li>\n</ul>\n<h4>One family, several very different shapes</h4>\n<ul>\n<li>\"Malware\" is an umbrella term. A <strong>virus</strong>, a <strong>worm</strong>, a <strong>trojan</strong>, <strong>ransomware</strong> and <strong>spyware</strong> are all different shapes of malware — each one spreads in a different way and does a different job once it is running.</li>\n<li>The exam skill across this whole family is telling these shapes apart: HOW each one spreads, and WHAT it actually does to the victim.</li>\n</ul>", "check": {"question": "Which of these is the best definition of malware?", "options": ["Any fault in a computer''s hardware that causes it to run more slowly than usual over time", "Software deliberately written to damage, disrupt or gain unauthorised access to a system", "A weak password that is easy for an attacker to guess correctly", "Any file that has become too large for its storage device to hold comfortably"], "answer": 1, "explain": "Malware is defined by its deliberate, malicious purpose — the other options describe unrelated hardware or password issues, not malicious software."}}, {"title": "Computer viruses — how do they spread?", "html": "<h4>A virus needs a host — and needs the user to run it</h4>\n<ul>\n<li>A <strong>virus</strong> is malware that attaches itself to a legitimate file or program (its \"host\").</li>\n<li>Crucially, a virus <strong>cannot spread on its own</strong> — it only starts spreading once a user runs (opens or executes) the infected host file, for example by opening an infected document or launching an infected program.</li>\n<li>Once run, it can copy itself into other files or programs on the same computer, and often tries to spread further when an infected file is shared, e.g. emailed to someone else or copied onto a USB stick.</li>\n<li>Because it depends on user action, avoiding suspicious downloads and attachments is a genuinely effective defence against a virus.</li>\n</ul>", "check": {"question": "What must happen before a virus can start to spread?", "options": ["A user must run (open) the infected file it is attached to", "The computer must be connected to the internet for more than an hour", "Another piece of malware must already be installed on the computer", "The computer''s antivirus software must be switched off completely"], "answer": 0, "explain": "A virus is inactive until the infected host file is actually run — that single action is what triggers it to start copying itself."}}, {"title": "Worms — spreading without any help from the user", "html": "<h4>Self-replicating, and needs no user action at all</h4>\n<ul>\n<li>A <strong>worm</strong> is malware that can copy (replicate) itself and spread across a network entirely <strong>by itself</strong>.</li>\n<li>Unlike a virus, a worm does <strong>not</strong> need a user to open an infected file, click a link, or take any action whatsoever — it can move from computer to computer on its own, often by exploiting a weakness (vulnerability) in software or in how a network is set up.</li>\n<li>Because it spreads unaided, a worm can infect huge numbers of computers extremely quickly once it is loose on a network.</li>\n</ul>\n<h4>The exam''s favourite contrast</h4>\n<ul>\n<li><strong>Virus</strong> = needs the user to run an infected file. <strong>Worm</strong> = spreads completely on its own. If a question describes malware spreading \"without the user doing anything\", it is describing a worm, not a virus.</li>\n</ul>", "check": {"question": "What makes a worm different from a virus?", "options": ["A worm only affects computers that are not connected to any network", "A worm can spread across a network by itself, without any user action", "A worm cannot copy itself onto any other computer at all", "A worm always needs a matching virus to already be present before it is able to run at all"], "answer": 1, "explain": "A worm is fully self-replicating and self-spreading — it needs no user action, which is exactly what separates it from a virus."}}, {"title": "Trojans — malware in disguise", "html": "<h4>Willingly installed, not self-replicating</h4>\n<ul>\n<li>A <strong>trojan</strong> disguises itself as legitimate, useful or wanted software — a free game, a \"helpful\" tool, a cracked version of paid software — so the victim installs it <strong>willingly</strong>, believing it is safe.</li>\n<li>Once installed, a trojan can do many things: open a hidden \"backdoor\" for an attacker, steal data, or quietly install further malware.</li>\n<li>The key exam fact: a trojan does <strong>NOT</strong> self-replicate. Unlike a virus or a worm, it does not copy itself onto other files or other computers — it relies entirely on tricking a person into installing it in the first place.</li>\n</ul>", "check": {"question": "Which statement about trojans is correct?", "options": ["A trojan copies itself onto other files completely automatically, spreading in exactly the same way as a virus does", "A trojan disguises itself as wanted software and does not copy itself onto other files", "A trojan can only run on computers that are not connected to the internet", "A trojan always encrypts a victim''s files and demands a ransom payment"], "answer": 1, "explain": "A trojan tricks the user into installing it by pretending to be something wanted — but unlike a virus or worm, it does not self-replicate."}}, {"title": "Ransomware — locking a victim out of their own files", "html": "<h4>Encrypts first, then demands payment</h4>\n<ul>\n<li><strong>Ransomware</strong> is malware that <strong>encrypts</strong> the victim''s files, scrambling them using a key that only the attacker holds.</li>\n<li>Once the files are encrypted, the victim can no longer open or use them — the attacker then demands a <strong>ransom payment</strong> (often in cryptocurrency) in exchange for the decryption key needed to unlock the files again.</li>\n<li>The files are not deleted or stolen in the usual sense — they still exist on the victim''s computer, just locked. Paying the ransom is never guaranteed to actually restore access, which is why businesses are advised to keep secure backups instead of relying on payment.</li>\n</ul>", "check": {"question": "What does ransomware specifically do to a victim''s files?", "options": ["It permanently deletes every file stored on the infected computer", "It encrypts the files and demands payment for the key to unlock them", "It slowly and permanently corrupts each individual file until none of them will open properly", "It copies every file onto a hidden folder on the same hard drive"], "answer": 1, "explain": "Ransomware''s defining feature is encryption plus a ransom demand — the files still exist, but the victim cannot access them without the attacker''s key."}}, {"title": "Spyware and keyloggers — watching in secret", "html": "<h4>Designed to go unnoticed</h4>\n<ul>\n<li><strong>Spyware</strong> is malware that secretly monitors a user''s activity — which websites they visit, what files they open, even what is shown on their screen — and sends that information back to an attacker.</li>\n<li>A <strong>keylogger</strong> is a specific type of spyware that records every key a user presses. Because it captures exactly what is typed, a keylogger is especially effective at stealing <strong>passwords</strong> and other sensitive text the moment the victim types it in.</li>\n<li>Both are dangerous specifically because they are hard to notice — unlike ransomware, which announces itself with a ransom demand, spyware works best when the victim has no idea it is there at all.</li>\n</ul>", "check": {"question": "What is a keylogger specifically designed to record?", "options": ["Every key a user presses on their keyboard, including passwords", "The total number of hours a computer has been switched on", "How many files are currently saved on the computer''s hard drive", "The exact temperature of the computer''s processor over time"], "answer": 0, "explain": "A keylogger records keystrokes — that means it can capture passwords, messages and other sensitive text exactly as the victim types them."}}, {"title": "What is social engineering, and why do people matter so much?", "html": "<h4>Attacking the person, not the software</h4>\n<ul>\n<li><strong>Social engineering</strong> means manipulating a PERSON, rather than exploiting a weakness in software, into revealing information or breaking normal security procedures.</li>\n<li>It works because people can be trusting, busy, polite, or afraid of getting into trouble — an attacker exploits exactly those very human instincts.</li>\n<li>This is why people are often called <strong>\"the weakest link\"</strong> in security: even the strongest encryption, firewall or password policy is useless if a person can simply be talked into handing over access voluntarily.</li>\n</ul>", "check": {"question": "What does a social engineering attack primarily target?", "options": ["A weakness in a website''s encryption algorithm", "A person, by manipulating them into giving up information or access", "A gap in a network''s physical cabling", "An out-of-date version of an operating system that has never been patched or updated"], "answer": 1, "explain": "Social engineering bypasses technical security entirely by targeting a person''s trust, habits or fear — not a flaw in the software itself."}}, {"title": "Phishing — the most common social engineering attack", "html": "<h4>Fake messages from a ''trusted'' source</h4>\n<ul>\n<li><strong>Phishing</strong> uses fake emails, text messages or websites that <strong>impersonate a trusted organisation</strong> — a bank, a delivery company, a school, an online shop — to trick the victim.</li>\n<li>The goal is usually to get the victim to click a malicious link, download an infected attachment, or type their username, password or card details directly into a fake login page.</li>\n<li>Common warning signs: an urgent or threatening tone (\"your account will be closed\"), a sender address that looks almost right but isn''t, generic greetings (\"Dear Customer\"), and links that don''t quite match the real organisation''s website.</li>\n</ul>", "check": {"question": "What is phishing?", "options": ["Automatically guessing thousands of different password combinations very quickly using software", "Fake messages that impersonate a trusted organisation to trick a victim", "Physically watching someone type their password over their shoulder", "Flooding a website with traffic so genuine users cannot access it"], "answer": 1, "explain": "Phishing is a type of social engineering built entirely around impersonating a trusted sender to trick the victim into acting."}}, {"title": "Blagging and shouldering — two more social engineering tricks", "html": "<h4>Blagging (pretexting) — inventing a story</h4>\n<ul>\n<li><strong>Blagging</strong>, also called pretexting, means inventing a false scenario — a \"pretext\" — to persuade a victim into handing over information or access. For example, an attacker phones pretending to be from the IT department and asks a member of staff to \"confirm\" their password.</li>\n</ul>\n<h4>Shouldering (shoulder surfing) — watching, not talking</h4>\n<ul>\n<li><strong>Shouldering</strong> means simply watching over someone''s shoulder as they type a password, PIN or other sensitive information — at an ATM, on a laptop on a train, or at a login screen.</li>\n<li>It requires no technical skill at all, just observation, which makes it easy to defend against (shielding the keypad, being aware of who is nearby) but easy to fall for if a victim isn''t paying attention.</li>\n</ul>", "check": {"question": "An attacker phones an employee, pretends to be from the company''s IT support team, and persuades them to reveal their password. What is this an example of?", "options": ["Shouldering", "Blagging (pretexting)", "A brute-force attack", "A denial of service attack"], "answer": 1, "explain": "Inventing a false scenario — posing as IT support — to talk a victim out of information is exactly what blagging (pretexting) means."}}, {"title": "Brute-force attacks — guessing at speed", "html": "<h4>Trying every possible combination</h4>\n<ul>\n<li>A <strong>brute-force attack</strong> uses software to automatically try huge numbers of possible password combinations, one after another, until it finds the one that works.</li>\n<li>It doesn''t rely on tricking a person at all, unlike social engineering — it is a purely technical attack on the login system itself.</li>\n<li>A short, simple password has far fewer possible combinations, so it can be cracked quickly. A long password mixing upper/lower case letters, numbers and symbols has vastly more possible combinations, making the attack take far longer — often long enough to be impractical.</li>\n<li>Systems can defend against brute-force attacks by locking an account after a small number of failed attempts, or by slowing down each login attempt.</li>\n</ul>", "check": {"question": "What does a brute-force attack do?", "options": ["It tricks a victim into revealing their password directly", "It automatically tries huge numbers of password combinations until one works", "It floods a login page with an overwhelming amount of traffic so that nobody at all can access it", "It secretly records every key a victim presses while they type"], "answer": 1, "explain": "A brute-force attack is a purely automated, technical guessing attack — it does not involve tricking the victim or flooding a server."}}, {"title": "Denial of Service and DDoS — making a service unavailable", "html": "<h4>DoS: flooding, not stealing</h4>\n<ul>\n<li>A <strong>Denial of Service (DoS)</strong> attack floods a server with an overwhelming number of requests, using up its resources until it can no longer respond to genuine users.</li>\n<li>Crucially, a DoS attack does <strong>NOT</strong> steal, read or change any data — the goal is purely to make a service <strong>unavailable</strong>, not to break into it.</li>\n</ul>\n<h4>DDoS: the same idea, from many directions at once</h4>\n<ul>\n<li>A <strong>Distributed</strong> Denial of Service (DDoS) attack is the same idea, but the flood of traffic comes from <strong>many different computers at once</strong> — usually a <strong>botnet</strong>, a large network of computers that have already been infected with malware and are being secretly controlled by the attacker.</li>\n<li>A DDoS attack is much harder to stop than a single-source DoS attack, because the traffic arrives from thousands of different addresses simultaneously — blocking one source does nothing, since traffic keeps arriving from all the others.</li>\n</ul>", "check": {"question": "What is the main purpose of a Denial of Service attack?", "options": ["To read, copy and secretly transfer sensitive data stored on the target server", "To make a server or service unavailable to its genuine users", "To secretly install spyware onto the target''s computer", "To trick a specific employee into revealing their password"], "answer": 1, "explain": "A DoS/DDoS attack is about availability, not data — it floods a service so genuine users cannot use it, without stealing or altering anything."}}, {"title": "Data interception and theft", "html": "<h4>Catching data as it travels</h4>\n<ul>\n<li><strong>Data interception</strong> means capturing data while it is travelling across a network, rather than attacking the computer that stores it — sometimes called <strong>packet sniffing</strong> or eavesdropping.</li>\n<li>This is a particular risk on <strong>unsecured (unencrypted) networks</strong>, such as open public Wi-Fi in a café or airport, where data can travel in a form an attacker can simply read.</li>\n<li>Intercepted data might include login details, card or payment information, or private messages — anything the victim sends while connected.</li>\n<li>Encrypting data before it is sent, so it looks scrambled to anyone intercepting it, is the main defence — which is why sites using HTTPS are considered much safer for entering sensitive information than ones that don''t.</li>\n</ul>", "check": {"question": "Why is sending sensitive data over an unsecured public Wi-Fi network risky?", "options": ["Public Wi-Fi automatically shares your files with every other connected device", "An attacker can more easily intercept and read data as it travels across the network", "Unsecured networks can physically damage any device that attempts to connect to them at all", "Public Wi-Fi routers can only be used by one device at any given time"], "answer": 1, "explain": "Without encryption, data travelling across the network can be captured (''sniffed'') and read directly by anyone intercepting it."}}, {"title": "SQL injection — attacking a database through an input box", "html": "<h4>Typing code where data was expected</h4>\n<ul>\n<li>Many websites store information — usernames, orders, product details — in a <strong>database</strong>, and use a language called <strong>SQL</strong> to read from and write to it.</li>\n<li>A <strong>SQL injection</strong> attack means typing malicious SQL code into a website''s input box, such as a login box or a search box, instead of the data the box was expecting.</li>\n<li>If the website doesn''t check its input properly, that malicious code gets passed straight into the database''s real command — letting the attacker <strong>view</strong>, <strong>change</strong> or <strong>delete</strong> data they should never see, or even log in without knowing a real password at all.</li>\n</ul>", "check": {"question": "What does a SQL injection attack involve?", "options": ["Flooding a database server with an enormous, continuous number of requests all at once", "Entering malicious SQL code into a website''s input box to attack its database", "Physically stealing the hard drive that a database is stored on", "Guessing a database administrator''s password using automated software"], "answer": 1, "explain": "SQL injection specifically exploits an input box that doesn''t check its data properly, letting malicious SQL code reach the real database command."}}, {"title": "Why people and poor policy really are the weakest link", "html": "<h4>Technology can only do so much</h4>\n<ul>\n<li>A business can install the best anti-malware, firewalls and encryption available — and still be compromised, because so many attacks target <strong>people</strong> and <strong>policy</strong> rather than the technology itself.</li>\n<li>Common weak points: <strong>weak or reused passwords</strong> that a brute-force attack can crack quickly; <strong>unpatched (out-of-date) software</strong> that still has known vulnerabilities a worm or attacker can exploit; and a lack of <strong>user access levels</strong>, meaning any single compromised account can reach far more data than it should.</li>\n<li>This is exactly why social engineering attacks like phishing remain so effective: no software flaw is required at all if a person can simply be persuaded to hand over what an attacker needs.</li>\n<li>This topic sets up the next one directly — <strong>1.4.2</strong> covers the specific defences (passwords, access levels, firewalls, training and more) that exist to close each of these weak points.</li>\n</ul>", "check": {"question": "Why can a business with strong technical security still be successfully attacked?", "options": ["Because firewalls and anti-malware software automatically stop working properly after about one year", "Because attacks like social engineering target people and policy, not just technology", "Because encryption always slows a network down too much to be practical", "Because antivirus software cannot be installed on more than one computer"], "answer": 1, "explain": "Weak passwords, unpatched software and susceptible people all create openings that no amount of purely technical security can close on its own."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Malware", "definition": "Software deliberately written to damage, disrupt or gain unauthorised access to a system"}, {"term": "Virus", "definition": "Malware that attaches to a file and spreads once a user runs that infected file"}, {"term": "Worm", "definition": "Self-replicating malware that spreads across a network by itself, without user action"}, {"term": "Trojan", "definition": "Malware disguised as wanted software; installed willingly; does not self-replicate"}, {"term": "Ransomware", "definition": "Encrypts a victim''s files and demands payment for the decryption key"}, {"term": "Spyware", "definition": "Secretly monitors a user''s activity and sends the information to an attacker"}, {"term": "Keylogger", "definition": "Spyware that records every key a user presses, capturing passwords as they''re typed"}, {"term": "Social engineering", "definition": "Manipulating a person into revealing information or breaking security procedures"}, {"term": "Phishing", "definition": "Fake emails, texts or websites impersonating a trusted organisation to trick a victim"}, {"term": "Blagging (pretexting)", "definition": "Inventing a false scenario to persuade a victim into giving up information"}, {"term": "Shouldering", "definition": "Watching over someone''s shoulder as they type a password or PIN"}, {"term": "Brute-force attack", "definition": "Automatically trying huge numbers of password combinations until one works"}, {"term": "Denial of Service (DoS)", "definition": "Flooding a server with traffic so genuine users cannot access it"}, {"term": "Distributed Denial of Service (DDoS)", "definition": "A DoS attack launched from many computers at once, usually a botnet"}, {"term": "Botnet", "definition": "A network of infected computers secretly controlled by an attacker"}, {"term": "Data interception", "definition": "Capturing data as it travels across a network, especially an unsecured one"}, {"term": "Packet sniffing", "definition": "Using software to intercept and read data packets travelling across a network"}, {"term": "SQL injection", "definition": "Entering malicious SQL code into an input box to attack a database"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which type of malware needs a user to run an infected file before it can spread to other files?", "options": ["A worm, since it copies itself and spreads automatically across an entire network without any user action", "A virus, since it attaches to a file and needs that file to be run", "A trojan, since it disguises itself as wanted software", "Ransomware, since it encrypts files as soon as it is downloaded"], "answer": 1, "explain": "A virus depends entirely on the user running its infected host file — that is what separates it from a worm, which spreads unaided."}, {"question": "Which statement about worms is correct?", "options": ["A worm needs the user to open an infected file before it can spread", "A worm copies itself across a network without any action from the user", "A worm disguises itself as useful software the user chooses to install", "A worm can only infect one single computer and cannot spread further"], "answer": 1, "explain": "A worm is self-replicating and spreads across a network entirely by itself, with no user action required."}, {"question": "What makes a trojan different from a virus or a worm?", "options": ["A trojan spreads automatically across a network with no user action", "A trojan does not copy itself onto other files or other computers", "A trojan can only affect files stored on a removable USB drive", "A trojan is not capable of stealing or damaging any data at all"], "answer": 1, "explain": "A trojan tricks a user into installing it by disguising itself as wanted software, but unlike a virus or worm it does not self-replicate."}, {"question": "What does ransomware do to a victim''s files?", "options": ["It permanently deletes every file stored on the computer, leaving nothing behind to recover", "It encrypts the files and demands payment for the decryption key", "It slows the computer down until the files can no longer open", "It copies the files onto the attacker''s own computer only"], "answer": 1, "explain": "Ransomware encrypts the victim''s files and holds the decryption key to ransom — the files still exist, but cannot be opened without paying."}, {"question": "What is the main purpose of spyware?", "options": ["To secretly monitor a user''s activity and steal information such as passwords", "To flood a server with an overwhelming amount of traffic so real users cannot access it at all", "To display unwanted adverts whenever the user opens a browser", "To physically damage the storage device a computer is using"], "answer": 0, "explain": "Spyware is designed to go unnoticed while it secretly monitors what a user does and sends that information back to an attacker."}, {"question": "Why are people often described as ''the weakest link'' in computer security?", "options": ["Because most computers are physically weaker and more prone to hardware failure than the software running on them", "Because a person can be tricked or manipulated into bypassing strong technical security", "Because human passwords are always stored using weaker encryption than files", "Because people are legally not allowed to report a suspected cyber-attack"], "answer": 1, "explain": "Even the strongest technical defences are useless if an attacker can simply persuade a person to hand over access voluntarily."}, {"question": "An employee receives an email that looks like it is from their bank, asking them to click a link and confirm their account password. What type of attack is this?", "options": ["Brute-force attack", "Phishing", "Denial of Service", "SQL injection"], "answer": 1, "explain": "A fake message impersonating a trusted organisation (the bank) to trick the victim into revealing details is a classic phishing attack."}, {"question": "What is ''blagging'' (pretexting) in the context of social engineering?", "options": ["Automatically guessing thousands of possible password combinations very quickly using software", "Inventing a false scenario to persuade a victim into giving up information", "Watching over someone''s shoulder as they type in a password", "Flooding a company''s server with fake requests until it crashes"], "answer": 1, "explain": "Blagging (pretexting) means making up a believable false story to talk a victim into handing over information or access."}, {"question": "A website locks a user''s account for ten minutes after five incorrect password attempts in a row. Which attack is this rule specifically designed to slow down?", "options": ["Phishing", "SQL injection", "Brute-force attack", "A denial of service attack"], "answer": 2, "explain": "Locking an account after repeated failed logins directly targets brute-force attacks, which rely on trying combination after combination quickly."}, {"question": "A shopping website suddenly becomes very slow and eventually stops responding after receiving an enormous, coordinated surge of traffic from thousands of different computers at once. What is this attack most likely to be?", "options": ["A virus infection", "A distributed denial of service (DDoS) attack", "A single trojan that was secretly installed on the server by an employee", "A SQL injection attack"], "answer": 1, "explain": "Traffic arriving from thousands of different computers at once, aimed at overwhelming the server, is the defining feature of a DDoS attack."}, {"question": "Why is using an unsecured public Wi-Fi network risky for sending personal data?", "options": ["The Wi-Fi signal automatically deletes any data sent over it", "Data sent over the network can more easily be intercepted and read by an attacker", "Unsecured networks always run at a much slower connection speed than properly secured ones", "Public Wi-Fi routers cannot connect to more than one device at a time"], "answer": 1, "explain": "Without encryption, data travelling across an unsecured network can be captured and read by anyone intercepting it."}, {"question": "What does a SQL injection attack involve?", "options": ["Overloading a server with an enormous number of simultaneous requests until it can no longer respond", "Entering malicious code into a website''s input box to manipulate its database", "Physically watching a user type their password into a system", "Sending a fake email that pretends to be from a trusted organisation"], "answer": 1, "explain": "SQL injection means typing malicious SQL code into an input box so the database runs the attacker''s command instead of the expected one."}]}, "fib": {"enabled": true, "questions": [{"text": "A [virus] attaches itself to a file or program and can only spread once a user runs that infected file."}, {"text": "A [worm] is malware that self-replicates and spreads across a network on its own, without the user doing anything."}, {"text": "A [trojan] disguises itself as wanted, legitimate software, but unlike a virus or worm it does not copy itself onto other files."}, {"text": "[ransomware] encrypts a victim''s files and demands a payment before the attacker will provide the key to unlock them again."}, {"text": "[spyware] secretly monitors what a user does, often to steal passwords or other personal data."}, {"text": "[phishing] is a type of social engineering that uses fake emails, texts or websites pretending to be a trusted organisation."}, {"text": "A [brute-force] attack tries huge numbers of password combinations automatically until it finds the correct one."}, {"text": "A distributed denial of service attack uses a [botnet], a network of infected computers controlled by an attacker, to flood a server with traffic from many directions at once."}]}, "tf": {"enabled": true, "questions": [{"statement": "A worm needs the user to open an infected file before it can spread.", "answer": false, "explain": "That describes a virus. A worm spreads across a network entirely by itself, without needing any action from the user."}, {"statement": "A trojan copies itself onto other files, spreading in the same way as a virus.", "answer": false, "explain": "A trojan does NOT self-replicate. It relies on tricking the user into installing it by disguising itself as wanted software."}, {"statement": "Ransomware encrypts a victim''s files rather than simply hiding or deleting them.", "answer": true, "explain": "Correct — ransomware scrambles the files with an encryption key and demands payment for the key needed to unlock them."}, {"statement": "Social engineering attacks target weaknesses in software, rather than weaknesses in people.", "answer": false, "explain": "It''s the opposite — social engineering deliberately targets a PERSON, manipulating them, rather than exploiting a technical software flaw."}, {"statement": "Phishing is a type of social engineering attack.", "answer": true, "explain": "Correct — phishing tricks a person using a fake message impersonating a trusted organisation, which makes it a form of social engineering."}, {"statement": "A Denial of Service attack is designed to steal data from a server.", "answer": false, "explain": "A DoS attack does not steal or alter any data — it floods a server so genuine users cannot access it. Stealing data is not its purpose."}, {"statement": "A brute-force attack tries many possible passwords automatically until one works.", "answer": true, "explain": "Correct — brute-force attacks are a purely automated, technical guessing attack against a login system."}, {"statement": "SQL injection involves entering malicious code into an input box to attack a database.", "answer": true, "explain": "Correct — the attacker types SQL code into a box like a login or search field, hoping the website passes it straight into a database command."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking a virus and a worm are basically the same thing because both ''infect'' a computer.", "truth": "A <strong>virus</strong> attaches to a file and only spreads once a user RUNS that infected file — it needs human action. A <strong>worm</strong> is fully self-replicating: it spreads across a network by itself, with no user action needed at all. That difference — needs the user, or doesn''t — is the exam''s favourite trap on this pair.", "check": {"question": "What is the key difference between a virus and a worm?", "options": ["A virus only affects mobile devices, while a worm only affects desktop computers", "A virus needs the user to run an infected file; a worm spreads by itself", "A worm can be removed by antivirus software, but a virus cannot", "A virus always demands a ransom payment, while a worm never does"], "answer": 1, "explain": "A virus depends on the user running an infected host file; a worm spreads across a network entirely on its own."}}, {"myth": "Believing a trojan copies itself onto other files and spreads like a virus, because it''s ''in the malware family''.", "truth": "A <strong>trojan</strong> does NOT self-replicate. It disguises itself as software the user actually WANTS and installs willingly — a free game, a ''useful'' tool. The trick is in the disguise, not in copying itself onto other files.", "check": {"question": "Why doesn''t a trojan need to copy itself onto other files to spread?", "options": ["Because it relies on the user willingly installing it, believing it is wanted software", "Because it can only ever infect a single computer before being destroyed immediately afterwards", "Because trojans are always removed automatically within a few minutes", "Because trojans only exist as physical malware on USB sticks"], "answer": 0, "explain": "A trojan''s method is deception, not replication — the victim installs it themselves because it looks like something they want."}}, {"myth": "Assuming ransomware just hides or deletes a victim''s files.", "truth": "Ransomware specifically <strong>encrypts</strong> the victim''s files, scrambling them with a key only the attacker holds, then demands a ransom payment in exchange for that key. The files still exist — they are locked, not gone — though there is no guarantee paying gets them back.", "check": {"question": "What actually happens to a victim''s files during a ransomware attack?", "options": ["They are permanently and irreversibly deleted from every location on the computer", "They are encrypted, so they still exist but cannot be opened without a key", "They are copied to a public website for anyone to view", "They are automatically backed up to a secure server"], "answer": 1, "explain": "Ransomware locks files using encryption — the files are not deleted, but they cannot be used without the attacker''s decryption key."}}, {"myth": "Thinking social engineering means hacking into a system using code.", "truth": "Social engineering has nothing to do with exploiting software — it means manipulating a PERSON into handing over information or access voluntarily, using a fake phone call, email or pretext. It is called ''the weakest link'' precisely because these tricks bypass technical security altogether.", "check": {"question": "Why is social engineering not considered a technical (software-based) attack?", "options": ["Because it always requires very expensive, specialist hacking equipment to carry out successfully", "Because it works by manipulating a person, not by exploiting a flaw in software", "Because it can only be carried out over a telephone, never online", "Because social engineering attacks are illegal in every country in the world"], "answer": 1, "explain": "Social engineering succeeds by tricking a human being, so it bypasses technical defences completely — no software vulnerability is required."}}, {"myth": "Believing a Denial of Service attack steals or damages the data on a server.", "truth": "A DoS attack does not touch the data at all — it floods the server with so many requests that it cannot respond to genuine users. The goal is to make a service UNAVAILABLE, not to read, copy or change anything stored on it.", "check": {"question": "What does a Denial of Service attack actually achieve if it succeeds?", "options": ["It quietly steals and copies the login details of every user who happens to visit the site", "It makes the service unavailable to genuine users, without touching the data", "It quietly rewrites the data stored in the server''s database", "It installs ransomware onto every device that connects to the server"], "answer": 1, "explain": "A DoS attack''s entire goal is denying access — it overwhelms the server''s resources rather than interacting with the data stored on it."}}, {"myth": "Assuming SQL injection is a network-based attack, like intercepting data as it travels.", "truth": "SQL injection targets a website''s <strong>database</strong> through an input field, such as a login box, not the network connection. The attacker types malicious SQL code instead of a normal username, tricking the database into running a command it shouldn''t.", "check": {"question": "What does a SQL injection attack actually target?", "options": ["Data as it travels across a network connection", "A website''s database, through an input box such as a login or search field", "The physical cabling and hardware connecting a server directly to the internet", "A user''s keyboard, by recording every key they press"], "answer": 1, "explain": "SQL injection exploits a website input field that fails to check its data properly, letting malicious code reach the real database command."}}]}, "tips": {"enabled": true, "items": [{"title": "Command-word ladder: a 3-mark ''Describe how a worm spreads''", "html": "<p>A typical question: <em>\"Describe how a worm is able to spread from one computer to another across a network.\"</em> [3 marks] Here is the same answer at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"A worm is a type of virus that spreads to other computers.\"</p>\n<ul>\n<li>Calling a worm \"a type of virus\" is itself a factual error, and nothing about the MECHANISM of spreading is explained.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"A worm copies itself and spreads to other computers.\"</p>\n<ul>\n<li>Technically true, but far too vague for 3 marks. It doesn''t say HOW it spreads (across a network) or that it needs no user action — the two facts that actually earn the extra marks.</li>\n</ul>\n\n<p><strong>✅ 3 marks:</strong> \"A worm is able to make copies of itself <strong>(1)</strong>. It spreads across a network entirely by itself, without needing a user to open a file or take any action <strong>(1)</strong>. It typically does this by exploiting a weakness in software or in the network to move from one computer to the next <strong>(1)</strong>.\"</p>\n\n<p><strong>Why this matters:</strong> \"Describe\" at 3 marks nearly always wants a chain of separate, specific facts — not one vague sentence repeated in different words. Naming the mechanism (self-replication), the key distinguishing detail (no user action) and how it actually moves (exploiting a weakness) is what separates 1 mark from full marks.</p>", "check": {"question": "A student writes only ''A worm copies itself and spreads to other computers'' for this 3-mark question. What is most likely missing for full marks?", "options": ["Nothing at all — the answer already explains the full spreading mechanism perfectly clearly", "The detail that it spreads without user action, and how it moves across the network", "A diagram showing the worm''s binary code in full", "The exact date the first computer worm was ever created"], "answer": 1, "explain": "The answer is too vague — it needs the specific facts that a worm needs no user action and typically exploits a weakness to move between computers."}}, {"title": "Telling virus, worm and trojan apart under exam pressure", "html": "<p>These three are constantly mixed up under exam pressure because they all \"spread\" or \"infect\" — but each one is defined by ONE precise, testable detail.</p>\n\n<p><strong>Ask these three questions, in order:</strong></p>\n<ul>\n<li><strong>1. Does it need the user to run an infected file before it does anything?</strong> If yes → it''s a <strong>virus</strong>.</li>\n<li><strong>2. Does it spread across a network completely on its own, with no user action at all?</strong> If yes → it''s a <strong>worm</strong>.</li>\n<li><strong>3. Does it disguise itself as wanted software, and NOT copy itself onto other files?</strong> If yes → it''s a <strong>trojan</strong>.</li>\n</ul>\n\n<p><strong>Worked example:</strong> \"Malware spreads across a school''s network overnight without anyone opening a single file.\" → Question 2 answers yes immediately: this is a <strong>worm</strong>, because it needed no user action at all.</p>\n\n<p>Ransomware and spyware are usually easier to spot because they name their OWN effect directly — \"encrypts files and demands payment\" is always ransomware; \"secretly records what the user does\" is always spyware.</p>", "check": {"question": "A piece of malware only starts working once an employee opens an infected email attachment. Using the three-question method, what is it most likely to be?", "options": ["A worm, since malware always spreads across networks", "A virus, since it depends on the user running the infected file", "Ransomware, since all malware eventually asks for a payment of some kind", "A DDoS attack, since it affects more than one computer"], "answer": 1, "explain": "Needing the user to open (run) an infected file before anything happens is the defining test for a virus, not the other options."}}, {"title": "The 8-mark ''Discuss'' ladder: weighing up more than one threat", "html": "<p>An 8-mark \"discuss\" question on threats always gives you several bullet points to structure your answer around, and always rewards WEIGHING UP more than one threat or factor, not just describing them one after another.</p>\n\n<p><strong>A reliable structure (~10–12 minutes):</strong></p>\n<ul>\n<li><strong>1. Explain the mechanism</strong> of each relevant threat — HOW it actually works, in your own words.</li>\n<li><strong>2. Follow each mechanism through to a real consequence</strong> for the specific scenario in the question (lost data, downed website, stolen money, damaged reputation) — a factor → effect → consequence chain, not just a one-word label.</li>\n<li><strong>3. Weigh the threats against each other</strong> — which is more likely, more costly, or more damaging for THIS business, and why? This comparison step is what separates a Band 2 answer from a Band 3 answer.</li>\n<li><strong>4. Reach a separate, justified conclusion</strong> — don''t let your final recommendation just repeat what you already said; add a clear \"therefore…\" sentence.</li>\n</ul>\n\n<p><strong>The band descriptors, in plain English:</strong></p>\n<ul>\n<li><strong>Band 3 (6–8 marks):</strong> thorough, accurate knowledge applied directly to the scenario, multiple threats properly weighed against each other, clear structure, justified conclusion.</li>\n<li><strong>Band 2 (3–5 marks):</strong> generally accurate but a bit generic or one-sided; most bullet points covered but the threats aren''t really compared against each other.</li>\n<li><strong>Band 1 (1–2 marks):</strong> basic, unsupported statements with little real explanation or application to the scenario given.</li>\n</ul>", "check": {"question": "What is most likely to separate a Band 3 (top-band) answer from a Band 2 answer on an 8-mark ''discuss the threats'' question?", "options": ["Using noticeably longer and more grammatically complicated sentences throughout the whole answer", "Explicitly weighing the threats against each other, not just describing them separately", "Naming as many different technical terms as possible, in any order", "Writing the answer in bullet points instead of full sentences"], "answer": 1, "explain": "Top-band ''discuss'' answers actively compare and weigh up the threats against each other and the scenario — description alone caps the mark in the middle band."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick <strong>one</strong> box to identify the type of malware that disguises itself as a legitimate, wanted program but does not copy itself onto other files.</p>", "marks": 1, "hint": "Focus on the two facts given: disguised as something wanted, and does NOT self-replicate — only one of the four options fits both.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Trojan</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box to identify the type of attack that floods a server with a huge number of requests so that real users cannot access the service, without stealing or changing any data.</p>", "marks": 1, "hint": "The question tells you the goal is stopping ACCESS, not reading or changing data — that rules out three of the four options straight away.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Denial of Service (DoS)</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Give <strong>two</strong> examples of malware.</p>", "marks": 2, "hint": "Name two different TYPES from the malware family — e.g. two of virus, worm, trojan, ransomware, spyware — not two examples of the same type.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per correct example, max 2)</h5>\n<ul>\n<li>Virus</li>\n<li>Worm</li>\n<li>Trojan</li>\n<li>Ransomware</li>\n<li>Spyware / keylogger</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any two distinct named types of malware from the list above (or another genuine example of malware).</li>\n<li>Do not accept phishing, brute-force attack, denial of service or SQL injection — these are attacks, not malware.</li>\n</ul>\n</div>"}, {"question": "<p>Write down <strong>two</strong> features of a phishing email that should make a recipient suspicious.</p>", "marks": 2, "hint": "Think about the sender, the tone, and the links — three good places a fake message usually gives itself away.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per correct feature, max 2)</h5>\n<ul>\n<li>An urgent or threatening tone, e.g. \"your account will be closed\"</li>\n<li>A sender address that looks similar to a real one but is not exactly right</li>\n<li>A generic greeting rather than the recipient''s actual name, e.g. \"Dear Customer\"</li>\n<li>A link that does not match the real organisation''s website when hovered over/checked</li>\n<li>A request to reveal a password or personal/financial details directly</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any two distinct valid warning signs from the list above, or an equally valid alternative.</li>\n</ul>\n</div>"}, {"question": "<p>State <strong>two</strong> consequences a business could face after a successful ransomware attack.</p>", "marks": 2, "hint": "Think beyond just ''losing files'' — consider the knock-on effects on the business itself.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per correct consequence, max 2)</h5>\n<ul>\n<li>Important files/data become inaccessible (encrypted)</li>\n<li>Business operations are disrupted or halted while files remain locked</li>\n<li>Financial cost of a ransom payment, with no guarantee the files are returned</li>\n<li>Cost and time of recovery, e.g. restoring systems from backups</li>\n<li>Reputational damage or loss of customer trust</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any two distinct valid consequences from the list above, or an equally valid alternative.</li>\n</ul>\n</div>"}, {"question": "<p>Name <strong>two</strong> techniques an attacker could use as part of a social engineering attack.</p>", "marks": 2, "hint": "These are techniques that manipulate a PERSON, not a technical flaw in software.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark per correct technique, max 2)</h5>\n<ul>\n<li>Phishing</li>\n<li>Blagging / pretexting</li>\n<li>Shouldering / shoulder surfing</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any two distinct named techniques from the list above.</li>\n<li>Do not accept brute-force attack, denial of service or SQL injection — these do not manipulate a person.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how a worm is able to spread from one computer to another across a network.</p>", "marks": 3, "hint": "Give three separate facts: what it does to itself, whether the user is involved, and how it actually moves between computers.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, max 3)</h5>\n<ul>\n<li>A worm is self-replicating / makes copies of itself</li>\n<li>It spreads across a network on its own, without needing a user to open a file or take any action</li>\n<li>It typically spreads by exploiting a weakness (vulnerability) in software or a network connection to move from one computer to the next</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per distinct valid point, to a maximum of 3.</li>\n<li>The \"no user action\" point is central and should be explicit, not just implied.</li>\n</ul>\n</div>"}, {"question": "<p>Explain why a brute-force attack is much less likely to succeed against a long, complex password than against a short, simple one.</p>", "marks": 3, "hint": "Explain the method first (trying combinations), then link password length to how many combinations there are to try.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, max 3)</h5>\n<ul>\n<li>A brute-force attack works by automatically trying combination after combination of characters until the correct password is found</li>\n<li>A short/simple password has far fewer possible combinations, so it can be tried (and found) much faster</li>\n<li>A long password mixing character types (letters, numbers, symbols) has vastly more possible combinations, so trying every one takes far longer — often long enough to make the attack impractical</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per distinct valid point, to a maximum of 3.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how a phishing attack tries to trick its victim.</p>", "marks": 3, "hint": "Cover what is sent, who it pretends to be from, and what it is actually trying to get the victim to do.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, max 3)</h5>\n<ul>\n<li>Sends a fake email, text message or website</li>\n<li>That impersonates a trusted organisation or person the victim is likely to trust, e.g. a bank, a workplace, a delivery company</li>\n<li>To trick the victim into clicking a malicious link, downloading an infected attachment, or revealing personal or financial details directly</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per distinct valid point, to a maximum of 3.</li>\n</ul>\n</div>"}, {"question": "<p>Outline how \"shoulder surfing\" could allow an attacker to steal a person''s PIN or password.</p>", "marks": 3, "hint": "This technique needs no software or technical skill at all — describe exactly what the attacker physically does.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, max 3)</h5>\n<ul>\n<li>The attacker physically watches the victim, over their shoulder, as they type</li>\n<li>This happens in a location where the victim is entering sensitive information, e.g. at an ATM, on a laptop in a public place, or at a login screen</li>\n<li>The attacker directly observes and memorises the characters being typed, without needing any technical skill or software at all</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per distinct valid point, to a maximum of 3.</li>\n</ul>\n</div>"}, {"question": "<p>Name <strong>three</strong> warning signs that an email might be a phishing attempt.</p>", "marks": 3, "hint": "Think about the sender''s address, the tone of the message, and what it is asking the reader to do.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per correct sign, max 3)</h5>\n<ul>\n<li>A sender address that looks similar to a real one but is not exactly right</li>\n<li>An urgent or threatening tone, e.g. \"your account will be closed\"</li>\n<li>A generic greeting rather than the recipient''s actual name</li>\n<li>A link that does not match the real organisation''s website</li>\n<li>A request to reveal a password or personal/financial details directly</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Accept any three distinct valid warning signs from the list above, or an equally valid alternative.</li>\n</ul>\n</div>"}, {"question": "<p>Complete the table by writing one thing each threat DOES once it successfully attacks a computer.</p>", "marks": 4, "hint": "Keep each row specific to THAT threat — a worm''s answer is about how it moves on, not what it does once it arrives; the other three rows are about their effect on the victim.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Worm — copies/spreads itself onto other computers across the network, without user action</li>\n<li>Trojan — lets an attacker in by disguising itself as wanted software the user installs (e.g. opens a backdoor, delivers other malware)</li>\n<li>Ransomware — encrypts the victim''s files and demands payment for the decryption key</li>\n<li>Spyware — secretly monitors or records the user''s activity to steal data such as passwords</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently against its own threat.</li>\n<li>Do not credit an answer that describes a different threat''s behaviour in the wrong row.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to identify which type of malware each statement describes.</p>", "marks": 4, "hint": "Match each statement to the ONE precise, defining detail it describes — user action needed, no user action needed, encrypts + ransom, or disguise + no self-replication.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Row 1 → <strong>Worm</strong></li>\n<li>Row 2 → <strong>Virus</strong></li>\n<li>Row 3 → <strong>Ransomware</strong></li>\n<li>Row 4 → <strong>Trojan</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently; 2+ ticks in a single row scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Draw <strong>one</strong> line from each threat to the description that correctly matches it.</p><p>(There are more descriptions than threats — one description is not used.)</p>", "marks": 4, "hint": "Match each threat to what it actually DOES — watch for the description of flooding a server, which belongs to Denial of Service, not to any of these four threats.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per correct line)</h5>\n<ul>\n<li>Phishing → <strong>A</strong> (fake emails or websites that impersonate a trusted organisation to trick a user into revealing details)</li>\n<li>Brute-force attack → <strong>B</strong> (automatically trying huge numbers of password combinations until the correct one works)</li>\n<li>Data interception → <strong>C</strong> (capturing data as it travels across a network, especially on an unsecured connection)</li>\n<li>SQL injection → <strong>D</strong> (entering malicious code into a website''s input box to read or damage its database)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>1 mark for each correct line. Two lines drawn from one threat score 0 for that threat.</li>\n<li>Description E (flooding a server) is a decoy describing Denial of Service, not used by any of the four threats.</li>\n</ul>\n</div>"}, {"question": "<p>Describe <strong>two</strong> differences between a virus and a worm.</p>", "marks": 4, "hint": "Write BOTH sides of each difference in the same space — ''a virus needs X, whereas a worm doesn''t'' — not just a fact about one of them.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: a virus needs the user to run the infected file before it can spread</li>\n<li>1 mark: a worm spreads across a network by itself, without any user action</li>\n<li>1 mark: a virus attaches to (needs) an existing file or program to spread</li>\n<li>1 mark: a worm is a standalone program and does not need to attach itself to another file</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each difference must correctly state BOTH sides (the virus fact and the contrasting worm fact) to earn both of its marks.</li>\n<li>A difference given the wrong way round (virus and worm facts swapped) does not earn credit.</li>\n</ul>\n</div>"}, {"question": "<p>Explain how a DDoS attack differs from a DoS attack, and why a DDoS attack can be more difficult for a website to defend against.</p>", "marks": 4, "hint": "First explain the source of the traffic (one computer vs many), then explain why that specifically makes blocking the attack harder.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: DoS comes from a single computer/source</li>\n<li>1 mark: DDoS comes from many computers at once, usually a botnet</li>\n<li>1 mark: traffic arrives from many different computers/addresses simultaneously</li>\n<li>1 mark: blocking one source does not stop the attack, since traffic keeps arriving from many others</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Full marks requires both the correct DoS/DDoS distinction AND a valid explanation of why that specifically makes DDoS harder to defend against.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how data interception could take place on an unsecured public Wi-Fi network, and describe one piece of information an attacker could steal as a result.</p>", "marks": 4, "hint": "Explain HOW the interception is possible on an unsecured network, then give a specific example of what gets stolen and why that matters.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: attacker uses software to intercept (''sniff'') data as it travels across the network</li>\n<li>1 mark: on an unsecured/unencrypted network, the data travels in a readable form</li>\n<li>1 mark: identifies a specific type of data that could be stolen, e.g. login or card details</li>\n<li>1 mark: states a plausible consequence, e.g. account takeover or financial loss</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Full marks needs both a correct explanation of the mechanism AND a specific, plausible example of the consequence.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how an employee at Bright Futures College falling for a phishing email could lead to a ransomware infection spreading through the college''s network, and the impact this could have on the college.</p>", "marks": 6, "hint": "Trace the whole chain step by step: the phishing email, what the employee does, how the ransomware then spreads and locks files, and finally the real-world impact on the college.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks</h5>\n<ul>\n<li>1 mark: the phishing email tricks the employee into clicking a link/opening an attachment</li>\n<li>1 mark: this installs ransomware onto the employee''s device</li>\n<li>1 mark: the ransomware spreads to/encrypts files on the shared central server</li>\n<li>1 mark: the affected files become encrypted/locked and inaccessible</li>\n<li>1 mark: a specific impact on the college is identified, e.g. staff/students losing access to work, ransom/recovery cost, reputational damage</li>\n<li>1 mark: the impact is linked back to the college''s specific situation (shared server/shared access)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Marks are awarded for a logically ordered chain from the phishing email through to a real consequence, not for isolated facts about phishing or ransomware in general.</li>\n</ul>\n</div>"}, {"question": "<p>Discuss why social engineering attacks can be difficult for a business to prevent using technical security measures alone.</p>", "marks": 6, "hint": "Explain WHY technical measures don''t stop this type of attack, then explain what kind of measure actually does help.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks</h5>\n<ul>\n<li>1 mark: technical measures defend against software-based attacks, not a person being deceived</li>\n<li>1 mark: social engineering targets the person directly, bypassing technical defences</li>\n<li>1 mark: strong passwords/encryption are useless if the victim hands over information voluntarily</li>\n<li>1 mark: staff training/awareness is needed so people can recognise a scam</li>\n<li>1 mark: clear procedures/policies help, e.g. verifying identity before sharing information</li>\n<li>1 mark: technical measures still play a supporting role, e.g. spam filters</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per distinct valid point across both groups, up to the group maximum.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how a SQL injection attack could allow an attacker to view or change data stored in GreenLeaf Grocers'' customer database, giving an example of what could go wrong.</p>", "marks": 6, "hint": "Explain the mechanism step by step (what the attacker types, and why that reaches the database), then give one concrete, GreenLeaf-specific example of the consequence.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks</h5>\n<ul>\n<li>1 mark: attacker enters malicious SQL code into an input box (e.g. login/search box) instead of expected data</li>\n<li>1 mark: this is possible because the website does not check/validate the input properly</li>\n<li>1 mark: the malicious code is passed into the database''s real command, running the attacker''s command</li>\n<li>1 mark: a plausible consequence is given, e.g. viewing customer names, addresses or saved card details</li>\n<li>1 mark: the consequence is linked to GreenLeaf''s own database (stores customer/payment data)</li>\n<li>1 mark: a further consequence is identified, e.g. data changed/deleted, or bypassing login</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Full marks needs both an accurate mechanism AND a consequence clearly linked to GreenLeaf''s own scenario, not a generic example.</li>\n</ul>\n</div>"}, {"question": "<p>GreenLeaf Grocers is reviewing the security risks facing its website and customer database.</p><p>Discuss the threats an online business like GreenLeaf Grocers faces, and how serious each one is.</p><p>In your answer you might consider:</p><ul><li>malware, including how it could reach GreenLeaf''s systems</li><li>social engineering, including phishing aimed at GreenLeaf''s staff or customers</li><li>a Denial of Service attack against GreenLeaf''s website</li><li>SQL injection against GreenLeaf''s customer database</li><li>which threat(s) you believe are most serious for a business like GreenLeaf, and why</li></ul>", "marks": 8, "hint": "Use the bullet list as your plan. For each threat: explain the mechanism, follow it through to a real consequence FOR GREENLEAF specifically, then weigh the threats against each other before giving a justified overall view.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (levelled) — indicative content</h5>\n<p>The following is indicative of possible factors/evidence that candidates may refer to but is not prescriptive or exhaustive:</p>\n<ul>\n<li><strong>Malware</strong> — malware could reach GreenLeaf''s systems through infected email attachments, malicious downloads or infected devices connecting to the network; a virus or trojan could steal or damage data, while ransomware could encrypt GreenLeaf''s order/customer database and halt trading until it is unlocked or restored.</li>\n<li><strong>Social engineering / phishing</strong> — an attacker could send a phishing email pretending to be from a supplier, a delivery partner, or GreenLeaf''s own IT team, tricking a staff member into revealing login details or installing malware; because this targets a person rather than the technology, it can succeed even if GreenLeaf''s technical security is strong.</li>\n<li><strong>Denial of Service</strong> — a DoS/DDoS attack could flood GreenLeaf''s website with traffic, taking it offline; for an online-only supermarket this directly stops customers from placing orders, causing an immediate and highly visible loss of sales while the site is down, though no customer data is stolen.</li>\n<li><strong>SQL injection</strong> — an attacker could exploit GreenLeaf''s website input boxes to reach the customer database directly, potentially viewing or stealing customers'' saved names, addresses and payment details; this is especially serious because it risks a wide-reaching data breach and lasting loss of customer trust, not just a temporary outage.</li>\n<li><strong>Weighing seriousness</strong> — a strong answer compares the threats rather than just listing them, e.g. arguing SQL injection or a major ransomware attack pose the greatest long-term risk (large-scale data loss, legal/reputational consequences, cost of recovery) versus a DoS attack, which is disruptive and costly in lost sales but temporary and does not compromise stored customer data.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>Mark Band 3 — High Level (6–8 marks):</strong> Thorough, accurate knowledge of multiple threats, applied directly and consistently to GreenLeaf''s situation as an online business. The response weighs the threats against each other (e.g. by likelihood, cost, or scale of consequence) and reaches a clear, justified view on which is most serious, with logically structured reasoning throughout.</li>\n<li><strong>Mark Band 2 — Mid Level (3–5 marks):</strong> Reasonable, generally accurate knowledge of more than one threat, but application to GreenLeaf may be generic or only partly developed. Some structure is present, and most bullet points are addressed, but the threats are not fully weighed against each other, or the concluding view is underdeveloped or unjustified.</li>\n<li><strong>Mark Band 1 — Low Level (1–2 marks):</strong> Basic knowledge shown, with limited understanding or accuracy, and little clear reference to GreenLeaf''s own situation. The response may name threats without explaining how they work or what their consequence would be.</li>\n<li><strong>0 marks:</strong> No attempt to answer the question, or response is not worthy of credit.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', '{"learn": {"enabled": true, "items": [{"title": "Why prevention needs layers", "html": "<h4>No single defence stops every threat</h4>\n<ul>\n<li><strong>1.4.1</strong> covered the <strong>threats</strong> (malware, social engineering, brute force, DoS, data interception, SQL injection). This topic covers the <strong>defences</strong> that limit them.</li>\n<li>Each prevention method is good at stopping <strong>particular</strong> threats, but no single method stops them all. For example, a firewall filters network traffic but does nothing about a member of staff being tricked by a phishing phone call.</li>\n<li>So real systems use <strong>several methods together</strong> — often called a \"layered\" or \"defence in depth\" approach — so that if one layer is bypassed, others still protect the system.</li>\n</ul>\n<h4>The exam skill</h4>\n<ul>\n<li>The key skill for this topic is matching a <strong>defence to the threat it limits</strong>, and explaining <strong>how</strong> it does so — not just naming methods.</li>\n</ul>", "check": {"question": "Why do secure systems usually combine several different prevention methods?", "options": ["Because using more methods always makes a computer run faster over time", "Because no single method stops every threat, so layers cover each other''s gaps", "Because the law requires every business to install exactly five security tools", "Because one method is enough on its own if it is the newest one available"], "answer": 1, "explain": "Each method limits only particular threats, so combining them (defence in depth) means a threat that slips past one layer can still be stopped by another."}}, {"title": "Penetration testing — what it is", "html": "<h4>Attacking your own system, on purpose and with permission</h4>\n<ul>\n<li><strong>Penetration testing</strong> (pen testing) is a deliberate, <strong>authorised</strong> attack on a system, carried out by specialists to find <strong>weaknesses (vulnerabilities)</strong> before a real attacker does.</li>\n<li>The testers try to break in using the same techniques a criminal would, then <strong>report</strong> the weaknesses they found so the organisation can <strong>fix them</strong>.</li>\n<li>The crucial point for the exam: it is <strong>legal and requested by the organisation itself</strong> — the goal is to identify and close gaps, not to cause harm or steal data.</li>\n</ul>", "check": {"question": "What is the main purpose of penetration testing?", "options": ["To permanently delete any data that an attacker might one day want to steal from the system", "To find weaknesses in a system so they can be fixed before a real attacker exploits them", "To flood a company''s own website with traffic to see how fast it runs", "To replace the need for any anti-malware software on the network"], "answer": 1, "explain": "Pen testing is an authorised, simulated attack whose whole point is to find and report vulnerabilities so the organisation can close them first."}}, {"title": "Penetration testing — internal vs external", "html": "<h4>Two viewpoints an attack can come from</h4>\n<ul>\n<li><strong>Internal testing</strong> simulates an attacker who already has some <strong>inside access</strong> — for example a disgruntled employee, or someone who has stolen a staff login. It checks how much damage could be done <strong>from inside</strong> the network.</li>\n<li><strong>External testing</strong> simulates an attacker with <strong>no inside knowledge or access</strong>, attacking from <strong>outside</strong> the organisation (over the internet) — testing the defences that face the outside world, such as the firewall.</li>\n<li>Running both gives a fuller picture: some weaknesses only matter to an outsider, others only become dangerous once an attacker is already inside (which is exactly why <strong>user access levels</strong> matter).</li>\n</ul>", "check": {"question": "What does internal penetration testing simulate?", "options": ["An attacker who has absolutely no prior knowledge of the system, and no access to any part of it whatsoever", "An attacker who already has some access from inside, such as a rogue employee or stolen login", "A hardware fault inside one of the company''s servers", "A power cut affecting the whole building at once"], "answer": 1, "explain": "Internal testing models a threat from inside the network (e.g. a malicious insider or a stolen account) to see how far that access could reach."}}, {"title": "Anti-malware software", "html": "<h4>Finding and removing malicious software</h4>\n<ul>\n<li><strong>Anti-malware</strong> (including antivirus) software <strong>scans</strong> files and the system, looking for <strong>malware</strong>.</li>\n<li>It recognises known malware by comparing files against a <strong>database of known malware signatures</strong>. When it finds a match, it <strong>quarantines</strong> (isolates) or <strong>removes/deletes</strong> the malicious file.</li>\n<li>It can also run in the background, checking files as they are opened or downloaded and <strong>warning</strong> the user about suspicious ones.</li>\n<li><strong>Why it must be kept up to date:</strong> new malware appears constantly, so the signature database must be updated regularly — out-of-date anti-malware cannot recognise the newest threats.</li>\n</ul>", "check": {"question": "Why must anti-malware software be kept up to date?", "options": ["Because updates make the computer''s hardware physically last much longer", "Because new malware appears all the time and out-of-date software cannot recognise it", "Because the software stops running completely after exactly one week without an update", "Because updates are the only way to change the desktop background colour"], "answer": 1, "explain": "Anti-malware spots threats by comparing them against a database of known malware, so it can only catch the latest threats if that database is regularly updated."}}, {"title": "Firewalls", "html": "<h4>A filter between a network and the outside world</h4>\n<ul>\n<li>A <strong>firewall</strong> sits between a device or network and the internet, and <strong>monitors and filters</strong> the <strong>incoming and outgoing</strong> traffic that tries to pass through.</li>\n<li>It checks traffic against a set of <strong>rules</strong>, then <strong>allows</strong> traffic that is permitted and <strong>blocks</strong> traffic that is not — helping to keep out <strong>unauthorised access</strong> and unwanted connections.</li>\n<li>A firewall controls <strong>traffic</strong>; it is <strong>not</strong> the same as anti-malware. It does not scan files for viruses — the two do different jobs and are used together.</li>\n</ul>", "check": {"question": "What does a firewall do?", "options": ["It scans all of the files already saved on the computer''s hard drive and deletes any viruses that it finds", "It monitors and filters incoming and outgoing network traffic against a set of rules", "It encrypts every document so that it cannot be read without a key", "It makes automatic backup copies of important files onto a second drive"], "answer": 1, "explain": "A firewall''s job is to filter network traffic (in and out) using rules, blocking unauthorised connections — scanning files for viruses is the job of anti-malware."}}, {"title": "User access levels", "html": "<h4>Not everyone should be able to see or change everything</h4>\n<ul>\n<li><strong>User access levels</strong> (permissions) control what each user is allowed to do with data and systems — for example <strong>read-only</strong>, <strong>read and write</strong>, or no access at all.</li>\n<li>Users are given only the access they actually need for their role. A student might read a resource but not edit it; only certain staff can change grades.</li>\n<li><strong>Why it matters:</strong> it prevents accidental or deliberate damage, and it <strong>limits how far an attack can reach</strong> — if one account is compromised, the attacker can only access what that account was allowed to, not the whole system.</li>\n</ul>", "check": {"question": "How do user access levels help if an attacker steals one employee''s login?", "options": ["They instantly and automatically delete the attacker''s own computer from a distance", "They limit the attacker to only what that one account was allowed to access", "They make the stolen password start working for every account in the company", "They guarantee the attacker can never read any file of any kind at all"], "answer": 1, "explain": "Access levels contain the damage: a compromised account can only reach the data and actions it was permitted, so the attacker cannot automatically reach everything."}}, {"title": "Passwords — strong passwords", "html": "<h4>Making a password hard to guess or crack</h4>\n<ul>\n<li>A <strong>strong password</strong> is <strong>long</strong> and mixes <strong>upper and lower case letters, numbers and symbols</strong>, and is not an obvious word, name or date.</li>\n<li>Each extra character and character type massively increases the number of <strong>possible combinations</strong>, so a <strong>brute-force attack</strong> (trying combinations automatically) takes far longer — often long enough to be impractical.</li>\n<li>Passwords should also be <strong>unique</strong> to each account: if the same password is reused everywhere, one leak exposes every account.</li>\n</ul>", "check": {"question": "Why does making a password longer and more varied help protect an account?", "options": ["It makes the whole computer start up and shut down noticeably more quickly each and every morning without fail", "It hugely increases the number of possible combinations, so a brute-force attack takes far longer", "It stops the user from ever forgetting the password again", "It automatically encrypts every file the user owns"], "answer": 1, "explain": "More length and more character types mean far more possible combinations to try, so an automated brute-force attack takes much longer to succeed."}}, {"title": "Passwords — extra protection", "html": "<h4>Backing up a password with more than just the password</h4>\n<ul>\n<li><strong>Account lockout:</strong> the system locks an account (or adds a delay) after a set number of <strong>failed login attempts</strong>. This directly slows or stops a brute-force attack, which relies on trying many guesses quickly.</li>\n<li><strong>Two-step / two-factor verification (2FA):</strong> as well as the password, the user must provide a second thing — usually a <strong>code sent to a separate device</strong> such as their phone. Even if an attacker steals the password, they still cannot log in without that second factor.</li>\n<li>These protect against the ways a password alone can fail — being guessed, cracked, or even stolen.</li>\n</ul>", "check": {"question": "How does two-step (two-factor) verification protect an account even if the password is stolen?", "options": ["It quietly changes the account''s password back to the previous one automatically every single night", "The attacker still needs a second factor, such as a code sent to the user''s own phone", "It makes the account impossible for the real owner to ever log in to as well", "It hides the account from the internet so no data ever leaves the device"], "answer": 1, "explain": "2FA requires a second factor the attacker does not have (e.g. a code on the user''s phone), so a stolen password on its own is not enough to log in."}}, {"title": "Encryption — the principle", "html": "<h4>Scrambling data so intercepted data is useless</h4>\n<ul>\n<li><strong>Encryption</strong> uses an <strong>algorithm</strong> and a <strong>key</strong> to <strong>scramble</strong> data into a form that cannot be understood.</li>\n<li>Only someone with the correct <strong>key</strong> can <strong>decrypt</strong> it back into the original, readable data.</li>\n<li><strong>What it does and does not do:</strong> encryption does <strong>not stop</strong> data being intercepted or stolen — but if intercepted, the data is <strong>meaningless</strong> to the attacker without the key. This is why it is the main defence against <strong>data interception</strong>, and why it protects data on a lost or stolen device too.</li>\n</ul>", "check": {"question": "What does encryption actually achieve if an attacker intercepts the data anyway?", "options": ["It physically prevents the data from ever leaving the sender''s own computer in the first place", "The intercepted data is scrambled and meaningless without the correct decryption key", "It automatically reports the attacker''s location to the police", "It makes a second, identical copy of the data as a backup"], "answer": 1, "explain": "Encryption doesn''t prevent interception; it makes the intercepted data unreadable, so it is useless to anyone who does not hold the key."}}, {"title": "Encryption — a Caesar cipher example", "html": "<h4>A very simple cipher that shows the idea</h4>\n<ul>\n<li>A <strong>Caesar cipher</strong> is a simple form of encryption: <strong>shift every letter</strong> along the alphabet by a fixed number of places — the number of places is the <strong>key</strong>.</li>\n<li>Example with a key of <strong>1</strong>: A→B, B→C, … so <strong>HELLO</strong> becomes <strong>IFMMP</strong>. To decrypt, shift each letter back by the same key.</li>\n<li>Letters near the end wrap around: with a key of 1, Z→A.</li>\n<li><strong>Why real systems don''t use it:</strong> a Caesar cipher is extremely weak — there are only 25 possible shifts, so it can be cracked almost instantly. It is only useful for showing how encryption works; real encryption uses far more complex keys and algorithms.</li>\n</ul>", "check": {"question": "Using a Caesar cipher with a key (shift) of 1, what does the word CAT become?", "options": ["DBU", "BZS", "CAT", "EDV"], "answer": 0, "explain": "Shift each letter forward by 1: C→D, A→B, T→U, giving DBU."}}, {"title": "Physical security", "html": "<h4>Protecting the hardware itself</h4>\n<ul>\n<li>Not every attack happens over a network — some need the attacker to be <strong>physically present</strong>. <strong>Physical security</strong> protects the computers, servers and the rooms they are in.</li>\n<li>Common methods: <strong>locks</strong> on doors and equipment, <strong>keypad / swipe-card / keycard</strong> entry, <strong>biometric</strong> entry (fingerprint or face), <strong>CCTV</strong>, <strong>alarms</strong>, <strong>security staff</strong>, and keeping servers in a <strong>locked server room</strong>.</li>\n<li>This limits threats such as <strong>hardware theft</strong>, tampering, or someone walking up to a machine — and works alongside digital defences, not instead of them.</li>\n</ul>", "check": {"question": "Which of these is an example of physical security?", "options": ["Installing anti-malware software on every computer in the office", "A biometric fingerprint lock on the door of the server room", "Choosing a long, complex password for an online account", "Encrypting the data before it is sent across the network"], "answer": 1, "explain": "A biometric door lock physically controls who can reach the hardware — the other options are all digital/software measures, not physical security."}}, {"title": "Network policies & staff training", "html": "<h4>The human layer technology can''t cover</h4>\n<ul>\n<li>Because people are often the weakest link, organisations use <strong>network / acceptable-use policies</strong>: written rules about passwords, what software may be installed, and how systems may be used.</li>\n<li><strong>Staff training</strong> teaches people to <strong>recognise</strong> phishing emails and other <strong>social engineering</strong> tricks, and to follow procedures such as verifying a caller before sharing information — the one thing a firewall or anti-malware cannot do.</li>\n<li>Sensible policy also includes keeping <strong>backups</strong>, so that if ransomware or another attack does strike, data can be <strong>restored</strong> without paying a ransom.</li>\n</ul>", "check": {"question": "Why is staff training an important security measure alongside technical ones?", "options": ["It completely replaces the need for a firewall, anti-malware software and encryption all at the same time", "It helps people recognise social engineering, such as phishing, which technical tools cannot stop", "It makes the office internet connection noticeably faster for everyone", "It is the only way to make backups of important company data"], "answer": 1, "explain": "Social engineering targets people, not software, so only awareness and training help staff spot and resist it — technical tools can''t stop a person being tricked."}}, {"title": "Matching the defence to the threat", "html": "<h4>The mapping the exam keeps testing</h4>\n<ul>\n<li><strong>Anti-malware</strong> → detects and removes <strong>malware</strong> (viruses, worms, trojans, ransomware, spyware).</li>\n<li><strong>Firewall</strong> → blocks <strong>unauthorised access</strong> and unwanted traffic trying to enter or leave the network.</li>\n<li><strong>Encryption</strong> → makes <strong>intercepted data</strong> unreadable, defeating data interception/theft.</li>\n<li><strong>Strong passwords + account lockout</strong> → defeat <strong>brute-force</strong> attacks.</li>\n<li><strong>Two-step verification</strong> → protects against a <strong>stolen or guessed password</strong>.</li>\n<li><strong>User access levels</strong> → limit the <strong>damage/spread</strong> of a compromised account or a malicious insider.</li>\n<li><strong>Physical security</strong> → stops <strong>theft</strong>, tampering and shouldering by someone physically present.</li>\n<li><strong>Staff training / anti-phishing</strong> → resists <strong>social engineering</strong>.</li>\n<li><strong>Penetration testing</strong> → finds <strong>all kinds of weaknesses</strong> first, so they can be fixed.</li>\n</ul>", "check": {"question": "Which prevention method most directly protects against data being read if it is intercepted while travelling across a network?", "options": ["A strong, complex and regularly changed password on the sender''s own user account", "Encryption, which scrambles the data so it is unreadable without the key", "A biometric lock on the door of the office", "Anti-malware software scanning the hard drive"], "answer": 1, "explain": "Encryption is the defence aimed squarely at interception — the data can still be captured, but it is meaningless without the key."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Penetration testing", "definition": "An authorised, simulated attack to find weaknesses before real attackers do"}, {"term": "Internal pen testing", "definition": "Simulates an attacker who already has some inside access, e.g. a rogue employee"}, {"term": "External pen testing", "definition": "Simulates an attacker with no inside knowledge, attacking from outside the organisation"}, {"term": "Anti-malware software", "definition": "Scans files, detects malware by its signature, and quarantines or removes it"}, {"term": "Malware signature", "definition": "A known pattern used by anti-malware to recognise a piece of malware"}, {"term": "Firewall", "definition": "Monitors and filters incoming and outgoing network traffic against a set of rules"}, {"term": "User access levels", "definition": "Permissions (e.g. read-only, read-write) controlling what each user may do with data"}, {"term": "Strong password", "definition": "A long, varied, unique password that resists guessing and brute-force attacks"}, {"term": "Account lockout", "definition": "Locking an account after a set number of failed logins to slow brute force"}, {"term": "Two-step verification", "definition": "Requiring a second factor (e.g. a phone code) as well as the password"}, {"term": "Encryption", "definition": "Scrambling data with an algorithm and key so intercepted data is unreadable"}, {"term": "Decryption key", "definition": "The key needed to turn encrypted data back into its original readable form"}, {"term": "Caesar cipher", "definition": "Simple encryption that shifts each letter along the alphabet by a fixed key"}, {"term": "Physical security", "definition": "Locks, keycards, biometrics, CCTV and alarms that protect the hardware itself"}, {"term": "Biometric entry", "definition": "Using a fingerprint or face scan to control physical access to a room or device"}, {"term": "Acceptable-use policy", "definition": "Written rules on how systems, passwords and software may be used"}, {"term": "Staff training", "definition": "Teaching people to recognise phishing and other social engineering attacks"}, {"term": "Backup", "definition": "A spare copy of data used to restore it after loss or a ransomware attack"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is penetration testing?", "options": ["An unauthorised attack carried out by criminals that a company has never agreed to, and cannot see coming or control", "An authorised, simulated attack used to find weaknesses before real attackers do", "A tool that automatically writes strong passwords for every employee", "A backup process that copies data to a second location every night"], "answer": 1, "explain": "Penetration testing is a deliberate, authorised attack whose purpose is to find and report vulnerabilities so they can be fixed first."}, {"question": "Which task is carried out by anti-malware software?", "options": ["Filtering the network traffic that passes in and out of the network, according to a set of rules", "Scanning files and removing or quarantining software identified as malicious", "Scrambling data so it cannot be read without the correct key", "Controlling which doors an employee''s swipe card can open"], "answer": 1, "explain": "Anti-malware scans for malware and quarantines/removes it — filtering traffic is a firewall''s job and scrambling data is encryption."}, {"question": "What does a firewall mainly control?", "options": ["The traffic allowed to travel between a network and the internet", "The strength of every password chosen by the company''s employees", "The temperature inside the locked server room", "The order in which files are saved onto the hard drive"], "answer": 0, "explain": "A firewall monitors and filters network traffic against rules, blocking unauthorised connections — it does not manage passwords, cooling or storage."}, {"question": "A company gives most staff read-only access to the customer records, and only two managers read-and-write access. What kind of security measure is this?", "options": ["Encryption", "User access levels", "A brute-force attack", "Penetration testing"], "answer": 1, "explain": "Giving different users different rights (read-only vs read-write) is exactly what user access levels (permissions) means."}, {"question": "Which of these best describes what encryption does to data?", "options": ["It deletes the data so that nobody, including the owner, can ever recover it again", "It scrambles the data so it is meaningless to anyone without the key", "It copies the data to a backup server in a different building", "It makes the data download much faster over the network"], "answer": 1, "explain": "Encryption uses an algorithm and key to scramble data so that, even if intercepted, it cannot be understood without the correct key."}, {"question": "A login system locks an account for ten minutes after five wrong passwords in a row. Which attack is this designed to slow down?", "options": ["A phishing email scam", "A brute-force attack", "Data interception and theft", "Shouldering someone"], "answer": 1, "explain": "Locking the account after repeated failed attempts directly targets brute-force attacks, which depend on trying many password guesses quickly."}, {"question": "Which measure most directly protects against a social engineering attack such as phishing?", "options": ["Installing a much more powerful and expensive firewall on the company''s main office network", "Training staff to recognise and question suspicious messages and requests", "Encrypting all of the files stored on the central server", "Fitting biometric locks to every door in the building"], "answer": 1, "explain": "Social engineering targets people, so staff training and awareness — not a technical tool — is the defence that actually helps against it."}, {"question": "Which of the following is an example of physical security?", "options": ["A firewall configured to block all incoming connections from unknown addresses", "A locked server room that can only be entered with a swipe card", "A password policy requiring at least twelve characters", "Anti-malware software set to scan every file automatically"], "answer": 1, "explain": "A swipe-card-controlled locked room physically restricts access to the hardware — the others are all software or policy measures."}, {"question": "Using a Caesar cipher with a key (shift) of 3, what does the word DOG become?", "options": ["GRJ", "AKD", "DOG", "HSK"], "answer": 0, "explain": "Shift each letter forward by 3: D→G, O→R, G→J, giving GRJ."}, {"question": "Why is two-step (two-factor) verification stronger than a password on its own?", "options": ["It means the user never again has to remember any password, PIN or security question of any kind", "It needs a second factor, such as a phone code, that a password thief would not have", "It automatically makes the password longer every time it is typed", "It hides the login page so that attackers cannot find the website"], "answer": 1, "explain": "2FA adds a second factor the attacker is unlikely to have, so even a stolen password alone is not enough to get in."}, {"question": "What is the main reason organisations keep regular backups as part of good security policy?", "options": ["To make the whole network connection run at a noticeably higher speed for every member of staff", "So that data can be restored after an attack such as ransomware, without paying", "To prevent employees from ever choosing a weak password again", "To stop any data from being intercepted while it travels across a network"], "answer": 1, "explain": "Backups let an organisation recover its data after ransomware or data loss, avoiding paying a ransom — they don''t affect speed, passwords or interception."}, {"question": "Which pairing correctly matches a threat to a method that limits it?", "options": ["Data interception → a biometric lock on the server-room door", "Brute-force attack → strong passwords plus account lockout", "Phishing → encrypting all of the files on the hard drive", "Malware infection → giving every user read-and-write access"], "answer": 1, "explain": "Strong passwords and account lockout directly defeat brute-force attacks; the other three pair a threat with a method that does not actually address it."}]}, "fib": {"enabled": true, "questions": [{"text": "[penetration] testing is an authorised, simulated attack used to find weaknesses in a system before a real attacker does."}, {"text": "A [firewall] monitors and filters the traffic passing between a network and the internet, blocking connections that are not allowed."}, {"text": "Anti-malware software recognises known malware by comparing files against a database of known [signatures]."}, {"text": "[encryption] scrambles data using an algorithm and a key, so that intercepted data cannot be understood without the key."}, {"text": "User access [levels] control what each person is allowed to do with data, such as read-only or read-and-write."}, {"text": "Locking an account after several failed login attempts is designed to slow down a [brute-force] attack."}, {"text": "Two-step verification asks for a second factor, such as a [code] sent to the user''s phone, as well as the password."}, {"text": "A Caesar cipher encrypts a message by [shifting] each letter along the alphabet by a fixed key."}]}, "tf": {"enabled": true, "questions": [{"statement": "Penetration testing is carried out with the organisation''s permission to find weaknesses before real attackers do.", "answer": true, "explain": "Correct — pen testing is an authorised, legal test whose purpose is to identify and report vulnerabilities so they can be fixed."}, {"statement": "A firewall scans files stored on the hard drive and removes any viruses it finds.", "answer": false, "explain": "That is the job of anti-malware software. A firewall filters network traffic; it does not scan files for viruses."}, {"statement": "Anti-malware software only needs to be installed once and never needs updating.", "answer": false, "explain": "New malware appears constantly, so the signature database must be updated regularly, or the software cannot recognise the newest threats."}, {"statement": "Encryption prevents data from ever being intercepted as it travels across a network.", "answer": false, "explain": "Encryption does not stop interception — it makes the intercepted data unreadable without the key, so it is useless to the attacker."}, {"statement": "Giving users only the access levels they need limits how far a compromised account can reach.", "answer": true, "explain": "Correct — if an account is stolen, access levels mean the attacker can only reach what that account was permitted, not the whole system."}, {"statement": "A longer, more varied password makes a brute-force attack take much longer to succeed.", "answer": true, "explain": "Correct — more length and character variety means far more possible combinations to try, so brute force is much slower."}, {"statement": "A Caesar cipher is strong enough to protect real bank data because it is impossible to crack.", "answer": false, "explain": "A Caesar cipher is very weak — there are only 25 possible shifts, so it is cracked almost instantly. It only demonstrates the idea of encryption."}, {"statement": "Staff training helps protect against social engineering attacks such as phishing.", "answer": true, "explain": "Correct — social engineering targets people, so training them to recognise and question suspicious requests is the defence that works."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking a firewall stops viruses and other malware, just like antivirus software does.", "truth": "A <strong>firewall</strong> filters network <strong>traffic</strong> against rules — it decides what is allowed in and out of the network. It does <strong>not</strong> scan files for viruses; that is <strong>anti-malware''s</strong> job. They do different jobs and are used together.", "check": {"question": "What is the difference between a firewall and anti-malware software?", "options": ["There is no real difference at all — they are simply two different names for exactly the same program", "A firewall filters network traffic; anti-malware scans files for and removes malware", "A firewall scans files, while anti-malware only controls door locks", "A firewall encrypts data, while anti-malware chooses passwords"], "answer": 1, "explain": "A firewall controls what traffic may pass in and out of the network; anti-malware scans files and removes malicious ones — two separate roles."}}, {"myth": "Believing that encryption stops data from being stolen or intercepted in the first place.", "truth": "Encryption does <strong>not</strong> prevent data being intercepted or copied. What it does is <strong>scramble</strong> the data so that, if intercepted, it is <strong>meaningless</strong> without the key. The attacker can still capture it — they just cannot understand it.", "check": {"question": "If an attacker intercepts encrypted data, what happens?", "options": ["The data is automatically and permanently deleted before the attacker is able to save it anywhere at all", "The attacker captures scrambled data that is meaningless without the decryption key", "The attacker is immediately blocked from the network by the firewall", "The data turns back into plain text as soon as it is intercepted"], "answer": 1, "explain": "Encryption doesn''t block interception; it ensures that intercepted data is unreadable without the key, so it is useless to the attacker."}}, {"myth": "Assuming penetration testing is an illegal attack carried out by criminals.", "truth": "Penetration testing is <strong>authorised</strong> — the organisation asks for it. Testers use the same techniques as attackers, but the goal is to <strong>find and report weaknesses</strong> so they can be fixed, not to cause harm or steal data.", "check": {"question": "Why is penetration testing not the same as a criminal attack, even though similar techniques are used?", "options": ["Because penetration testers are never able to actually break into anything at all", "Because it is authorised by the organisation and aims to find and fix weaknesses", "Because it can only ever be done on computers that are switched off", "Because it does not use any real hacking techniques whatsoever"], "answer": 1, "explain": "The techniques may be similar, but pen testing is requested by the organisation and its purpose is to identify and close vulnerabilities safely."}}, {"myth": "Thinking a strong password alone is enough to keep an account completely safe.", "truth": "A strong password defeats <strong>guessing and brute force</strong>, but it does nothing if the user is <strong>tricked into revealing it</strong> (phishing), has it captured by a <strong>keylogger</strong>, or is watched typing it (shouldering). That is why <strong>two-step verification</strong> and <strong>staff training</strong> matter too.", "check": {"question": "Why is a strong password not enough on its own to secure an account?", "options": ["Because even the strongest passwords always stop working completely after just a single day of being used", "Because it can still be phished, keylogged or shoulder-surfed, so extra measures are needed", "Because long passwords are actually easier to guess than short ones", "Because passwords have no effect on brute-force attacks at all"], "answer": 1, "explain": "A strong password resists guessing, but it can still be stolen or given away, so 2FA and training are needed alongside it."}}, {"myth": "Believing physical security has nothing to do with keeping data safe.", "truth": "If an attacker can <strong>physically reach</strong> a computer or server, many digital defences can be bypassed — they could <strong>steal the hardware</strong>, tamper with it, or watch someone type a password. <strong>Locks, keycards, biometrics and CCTV</strong> protect against exactly these physical routes to the data.", "check": {"question": "Why does physical security matter for protecting data?", "options": ["Because software and networks can never actually be attacked in any real way, only the physical hardware can be", "Because someone who can physically reach a machine can steal it or tamper with it", "Because CCTV cameras encrypt all of the company''s files automatically", "Because physical locks are the only security a computer ever needs"], "answer": 1, "explain": "Physical access can defeat digital protections — stolen hardware or a watched password is a real breach, so physical security is part of protecting data."}}, {"myth": "Mixing up user access levels with encryption, thinking both simply ''protect the files''.", "truth": "They protect files in <strong>different ways</strong>. <strong>Access levels</strong> control <strong>who is allowed</strong> to open or change a file. <strong>Encryption</strong> scrambles the file''s <strong>contents</strong> so it is unreadable without a key. A file can use both: only certain users may open it, and it is scrambled if it is stolen.", "check": {"question": "How do user access levels differ from encryption?", "options": ["They are really two completely identical security measures that simply happen to have two different names", "Access levels control who may use a file; encryption scrambles the file''s contents", "Access levels scramble data, while encryption chooses who can log in", "Neither has anything to do with protecting files"], "answer": 1, "explain": "Access levels decide who is permitted to open or edit data; encryption makes the data itself unreadable without a key — different, complementary protections."}}]}, "tips": {"enabled": true, "items": [{"title": "Always name the threat a method stops — and how", "html": "<p>The single most common question style in this topic gives you a threat (or a scenario) and asks for a suitable prevention method. A one-word method name rarely gets full marks — the mark scheme wants the <strong>method + the threat it addresses + how it helps</strong>.</p>\n\n<p><strong>❌ 1 mark:</strong> \"Use encryption.\"</p>\n<p><strong>✅ 2–3 marks:</strong> \"Use <strong>encryption</strong> <strong>(method)</strong>, which scrambles the data using a key <strong>(how)</strong>, so that if it is <strong>intercepted</strong> on the network it cannot be understood without the key <strong>(threat addressed)</strong>.\"</p>\n\n<p><strong>Quick self-check:</strong> for every prevention method you name, silently finish the sentence \"…which stops/limits ___ by ___.\" If you can''t, add the detail before moving on.</p>", "check": {"question": "A 3-mark question asks how a company could protect data sent over a network. A student just writes ''use encryption''. What is most likely missing?", "options": ["Nothing at all — the phrase ''use encryption'' completely answers any 3-mark question on its own", "How encryption works and which threat it addresses (unreadable if intercepted)", "The exact price of encryption software from three different suppliers", "A drawing of the network cables used in the office"], "answer": 1, "explain": "Naming the method alone is about 1 mark; the extra marks come from explaining how it works and the specific threat (interception) it addresses."}}, {"title": "Firewall vs anti-malware vs encryption — don''t mix them up", "html": "<p>Questions love to check whether you really know which method does which job, because students often blur the three together. Keep them separate:</p>\n<ul>\n<li><strong>Firewall</strong> — filters network <strong>traffic</strong> (what is allowed in/out). Stops unauthorised access.</li>\n<li><strong>Anti-malware</strong> — scans <strong>files</strong> and removes <strong>malware</strong>. Stops viruses, worms, trojans, ransomware, spyware.</li>\n<li><strong>Encryption</strong> — scrambles <strong>data</strong> so intercepted data is unreadable. Stops data interception being useful.</li>\n</ul>\n<p>If a question says \"scan and remove a virus\" the answer is anti-malware, never a firewall. If it says \"so intercepted data can''t be read\" the answer is encryption, never anti-malware.</p>", "check": {"question": "A question asks which method would ''scan the computer and remove a trojan that had been downloaded''. What is the correct method?", "options": ["A firewall, because it automatically blocks every single download coming from the internet", "Anti-malware software, because it scans files and removes malware", "Encryption, because it scrambles the trojan''s code", "User access levels, because they stop downloads completely"], "answer": 1, "explain": "Scanning for and removing malware such as a trojan is anti-malware''s job — a firewall filters traffic and encryption scrambles data."}}, {"title": "The structured ''threat + prevention'' extended question", "html": "<p>A longer question on this topic often asks you to <strong>identify several threats and describe how each can be prevented</strong> — for example three threats, each with a prevention method, worth several marks in total.</p>\n\n<p><strong>How it is marked:</strong> the marks are split across the threat–prevention <strong>pairs</strong>. For each pair you typically earn marks for (1) naming a valid, <strong>distinct</strong> threat and (2) <strong>describing</strong> a prevention that genuinely addresses <em>that</em> threat.</p>\n\n<p><strong>Where students lose marks:</strong></p>\n<ul>\n<li>Giving three threats but the <strong>same</strong> prevention for all of them (or three preventions that don''t match the threats).</li>\n<li>Only <strong>naming</strong> a prevention (\"a firewall\") instead of <strong>describing</strong> what it does.</li>\n<li>Repeating the same threat twice in slightly different words — each pair must be <strong>different</strong>.</li>\n</ul>\n<p><strong>Safe approach:</strong> pick three clearly different threats (e.g. malware, brute force, data interception) and give each its natural, well-described defence (anti-malware; strong passwords + lockout; encryption).</p>", "check": {"question": "On a ''identify three threats and describe how to prevent each'' question, what is a common way students lose marks?", "options": ["Choosing three clearly different threats, each one with its own separate matching prevention method", "Naming a prevention without describing it, or repeating the same threat twice", "Writing in full sentences instead of single words", "Describing exactly how each prevention method works in detail"], "answer": 1, "explain": "Marks come from distinct threat–prevention pairs that are described, so just naming a method or repeating a threat wastes the marks on offer."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick <strong>one</strong> box to identify the security method that monitors and filters the traffic passing between a network and the internet.</p>", "marks": 1, "hint": "Focus on the key word ''traffic'' — only one of these methods is about what is allowed in and out of the network.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Firewall</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box to identify the security method that scrambles data so that it cannot be understood if it is intercepted.</p>", "marks": 1, "hint": "The clue is ''scrambles data … cannot be understood'' — that points to one specific method.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Encryption</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Give <strong>two</strong> features of a strong password.</p>", "marks": 2, "hint": "Think about what makes a password hard to guess or crack — length and the variety of characters used are a good start.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each, max 2)</h5>\n<ul>\n<li>It is long / uses many characters</li>\n<li>It mixes upper and lower case letters, numbers and symbols</li>\n<li>It is unique (not reused on other accounts)</li>\n<li>It is not an obvious word, name or date</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award any two different valid features. Two ways of saying the same thing score 1 mark only.</li>\n</ul>\n</div>"}, {"question": "<p>Identify <strong>two</strong> methods of physical security a company could use to protect the computers in its office.</p>", "marks": 2, "hint": "Physical security is about stopping someone physically reaching the hardware — think doors, entry systems and monitoring.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each, max 2)</h5>\n<ul>\n<li>Locks (on doors or equipment)</li>\n<li>Keycard / swipe-card / keypad entry</li>\n<li>Biometric entry (fingerprint or face)</li>\n<li>CCTV</li>\n<li>Alarms</li>\n<li>Security staff / guards</li>\n<li>Locked server room</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award any two different valid physical methods. Do not credit software measures such as passwords or anti-malware.</li>\n</ul>\n</div>"}, {"question": "<p>Describe how anti-malware software helps to protect a computer system.</p>", "marks": 3, "hint": "Cover what it does to files, how it recognises malware, and what it does when it finds some — three separate points.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per point, max 3)</h5>\n<ul>\n<li>Scans files / the system for malware</li>\n<li>Recognises known malware by comparing against a database of known signatures</li>\n<li>Quarantines or removes/deletes any malware it finds</li>\n<li>Must be kept up to date to recognise new malware</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award any three of the above valid points.</li>\n</ul>\n</div>"}, {"question": "<p>A message is encrypted using a Caesar cipher with a key (shift) of <strong>2</strong>.</p><p>(a) Encrypt the word <strong>CODE</strong> using this cipher. <strong>[2]</strong><br>(b) State <strong>one</strong> reason a Caesar cipher would not be secure enough to protect real data. <strong>[1]</strong></p>", "marks": 3, "hint": "For (a), shift each letter forward by 2 places (C→E, and so on). For (b), think about how many different shifts an attacker would have to try.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>(a) <strong>EQFG</strong> — 2 marks for all correct; 1 mark if the shift-of-2 method is clearly used but one letter is wrong</li>\n<li>(b) 1 mark: only 25 possible shifts, so it can be cracked almost instantly by trying each one (or equivalent)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>(a) C→E, O→Q, D→F, E→G. Accept the answer in lower case.</li>\n<li>(b) Any one valid reason about how easily a Caesar cipher can be broken.</li>\n</ul>\n</div>"}, {"question": "<p>Complete the table by writing one prevention method that would most directly limit each threat. Each method must be different.</p>", "marks": 4, "hint": "Match each threat to the method aimed at it: think about what scans files, what defeats guessing, what makes intercepted data useless, and what helps people spot a scam.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Malware → anti-malware / antivirus software</li>\n<li>Brute-force attack → strong passwords and/or account lockout (accept two-step verification)</li>\n<li>Data interception → encryption</li>\n<li>Social engineering → staff training / awareness</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked against its own threat. A method that fits a different row does not earn credit in this one.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to identify the prevention method that most directly limits each threat.</p>", "marks": 4, "hint": "Each threat has one method aimed squarely at it — what removes malware, what makes intercepted data useless, what stops repeated guessing, and what helps people spot a scam.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Row 1 (virus in a download) → <strong>Anti-malware</strong></li>\n<li>Row 2 (intercepted data being read) → <strong>Encryption</strong></li>\n<li>Row 3 (repeated password guessing) → <strong>Account lockout</strong></li>\n<li>Row 4 (phishing email) → <strong>Staff training</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently; 2+ ticks in a single row scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Draw <strong>one</strong> line from each prevention method to the threat it most directly limits.</p><p>(There are more threats than methods — one threat is not used.)</p>", "marks": 4, "hint": "Match each method to the threat it targets. Watch the last option — a power cut is not a security threat any of these methods is designed to prevent.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per correct line)</h5>\n<ul>\n<li>Firewall → <strong>A</strong> (unauthorised access / unwanted traffic entering the network)</li>\n<li>Encryption → <strong>B</strong> (data being understood after it is intercepted)</li>\n<li>Two-step verification → <strong>C</strong> (a stolen password being used to log in)</li>\n<li>User access levels → <strong>D</strong> (one compromised account reaching the whole system)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>1 mark per correct line. Two lines from one method score 0 for that method.</li>\n<li>Threat E (a power cut) is a decoy — it is not a method-limited security threat here.</li>\n</ul>\n</div>"}, {"question": "<p>Explain how giving staff different user access levels helps to protect an organisation''s data.</p>", "marks": 4, "hint": "Explain what access levels are, then explain the two things they limit — everyday mistakes/misuse, and the reach of a compromised account.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: each user is given only the rights they need (e.g. read-only vs read-write)</li>\n<li>1 mark: this controls who can view or change particular data</li>\n<li>1 mark: prevents accidental or deliberate damage by those who should not have access</li>\n<li>1 mark: limits the reach of a compromised account to only what it was permitted</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Full marks needs both what access levels do AND why that protects the data.</li>\n</ul>\n</div>"}, {"question": "<p>Explain how a firewall and anti-malware software protect a computer system in <strong>different</strong> ways.</p>", "marks": 4, "hint": "Describe what each one actually acts on — one works on network traffic, the other on files — and the threat each addresses. Make the difference clear.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: a firewall monitors/filters network traffic in and out against rules</li>\n<li>1 mark: this blocks unauthorised access/unwanted connections</li>\n<li>1 mark: anti-malware scans files/the system for malware</li>\n<li>1 mark: it quarantines or removes malware such as viruses and trojans</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The answer must make clear that a firewall acts on network traffic while anti-malware acts on files/malware — not treat them as the same thing.</li>\n</ul>\n</div>"}, {"question": "<p>Staff at PixelForge connect to the company''s systems from home over the internet.</p><p>Explain how encryption and two-step verification each help to keep this remote access secure.</p>", "marks": 4, "hint": "Take each method in turn: say what it does, and the specific risk of remote access it reduces.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: encryption scrambles the data sent between home and the company using a key</li>\n<li>1 mark: intercepted data cannot be understood without the key</li>\n<li>1 mark: two-step verification requires a second factor as well as the password</li>\n<li>1 mark: a stolen/guessed password alone is not enough to log in</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each method must be linked to the risk it reduces for remote access, not just defined in isolation.</li>\n</ul>\n</div>"}, {"question": "<p>MediSync keeps its server in a cupboard in the reception area, which staff and visitors share.</p><p>Describe the security risks of storing the server this way, and describe how physical security could reduce them.</p>", "marks": 5, "hint": "First explain why the reception location is risky (who can reach it), then give physical security measures and say what each one prevents.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks</h5>\n<ul>\n<li>1 mark: visitors/unauthorised people can physically reach the server in reception</li>\n<li>1 mark: consequence — the server or patient data could be stolen, tampered with or switched off</li>\n<li>1 mark: move the server to a locked room / lock the cupboard so only authorised staff can reach it</li>\n<li>1 mark: control entry with keycard/keypad or biometric access</li>\n<li>1 mark: monitor or deter with CCTV, alarms or visitor sign-in</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Credit the risks of the location AND physical measures that clearly reduce them. Digital-only measures (e.g. passwords) are not physical security.</li>\n</ul>\n</div>"}, {"question": "<p>Explain what penetration testing is, and describe how it helps an organisation improve its security.</p>", "marks": 6, "hint": "Define it (authorised, simulated attack), then trace what happens: testers find weaknesses, report them, and the organisation fixes them before real attackers strike.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks</h5>\n<ul>\n<li>1 mark: a deliberate, simulated attack on the system</li>\n<li>1 mark: authorised/requested by the organisation (legal)</li>\n<li>1 mark: testers use the same techniques a real attacker would</li>\n<li>1 mark: it finds/identifies weaknesses in the system</li>\n<li>1 mark: the weaknesses are reported to the organisation</li>\n<li>1 mark: they can be fixed before a real attacker exploits them</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award 1 mark per distinct valid point across both groups, up to each group maximum.</li>\n</ul>\n</div>"}, {"question": "<p>PixelForge is worried about brute-force attacks against its customer login page.</p><p>Explain how PixelForge could reduce the risk of a brute-force attack succeeding, and why each measure helps.</p>", "marks": 6, "hint": "Cover more than one measure — strong password rules, account lockout, and two-step verification — and for each explain WHY it makes brute force harder.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks (max 6 across the measures below)</h5>\n<ul>\n<li>Strong passwords — enforce long, varied passwords; increases combinations so brute force takes far longer</li>\n<li>Account lockout — lock/delay after failed attempts; prevents the rapid repeated guessing brute force needs</li>\n<li>Two-step verification — second factor (e.g. phone code); a guessed password alone still cannot log in</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each measure scores for naming it AND explaining why it makes a brute-force attack harder. A named measure with no explanation scores 1.</li>\n</ul>\n</div>"}, {"question": "<p>MediSync stores sensitive patient records. Explain why relying on only <strong>one</strong> security method would not be enough, and describe how using several methods together would better protect the records.</p>", "marks": 6, "hint": "Show that different threats need different defences, then describe two or three methods and the different threat each one addresses for MediSync.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks</h5>\n<ul>\n<li>1 mark: different threats need different defences, so one method leaves gaps</li>\n<li>1 mark: a specific example gap (e.g. a firewall does not stop phishing or physical theft)</li>\n<li>1 mark: encryption so stolen/intercepted records are unreadable</li>\n<li>1 mark: user access levels so only authorised staff reach the records</li>\n<li>1 mark: anti-malware and/or firewall against malware and unauthorised access</li>\n<li>1 mark: physical security and/or staff training for the server and against social engineering</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Reward the layered-defence argument: several methods, each addressing a different threat to MediSync''s records.</li>\n</ul>\n</div>"}, {"question": "<p>PixelForge wants to improve the security of its website and customer accounts.</p><p>Identify <strong>three</strong> different threats PixelForge could face, and for each one describe a prevention method that would limit it. Each threat and prevention must be different.</p>", "marks": 9, "hint": "Pick three clearly different threats (for example malware, brute force, and data interception). For each: name the threat, then DESCRIBE a prevention that genuinely limits it — say what the method does, not just its name.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 9 marks (up to 3 for each of three threat–prevention pairs)</h5>\n<p>For EACH of three different threat–prevention pairs:</p>\n<ul>\n<li>1 mark: a valid, distinct threat is identified</li>\n<li>1 mark: a prevention method that genuinely limits that threat is named</li>\n<li>1 mark: how that prevention works / limits the threat is described</li>\n</ul>\n<p>Examples of acceptable pairs:</p>\n<ul>\n<li>Malware → anti-malware software (scans files, removes malware, kept up to date)</li>\n<li>Brute-force attack → strong passwords + account lockout / two-step verification (stops rapid guessing / blocks a stolen password)</li>\n<li>Data interception → encryption (intercepted data is unreadable without the key)</li>\n<li>SQL injection → validating/checking input so malicious code cannot reach the database</li>\n<li>Phishing / social engineering → staff training so employees recognise and question scams</li>\n<li>Unauthorised network access → firewall (filters traffic, blocks unauthorised connections)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each pair is capped at 3 marks. The three threats must be different, and each prevention must genuinely address its own threat.</li>\n<li>Repeating a threat, or giving the same prevention for more than one threat, does not earn the repeated marks.</li>\n<li>Naming a prevention without describing it earns the naming mark only.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-5-1-operating-systems', '1.5.1 Operating Systems', '{"learn": {"enabled": true, "items": [{"title": "What is an operating system?", "html": "<h4>The software that runs the whole computer</h4>\n<ul>\n<li>An <strong>operating system (OS)</strong> is <strong>system software</strong> that manages the computer''s hardware and software and provides a platform (a base) for application software to run on.</li>\n<li>It sits <strong>between the user and applications on one side and the hardware on the other</strong> — when a program wants to save a file or print, it asks the OS, and the OS deals with the hardware.</li>\n<li>It runs <strong>automatically</strong> when the computer starts and works in the background the whole time the computer is on. Examples include Windows, macOS, Linux, Android and iOS.</li>\n</ul>\n<h4>The five functions you must know</h4>\n<ul>\n<li>This topic is really about the <strong>jobs (functions)</strong> an OS does: the <strong>user interface</strong>, <strong>memory management &amp; multitasking</strong>, <strong>peripheral management &amp; drivers</strong>, <strong>user management</strong> and <strong>file management</strong>. The exam skill is knowing what each one does.</li>\n</ul>", "check": {"question": "Which statement best describes an operating system?", "options": ["A piece of application software, such as a word processor, that a user chooses to open in order to complete one particular task", "System software that manages the computer''s hardware and provides a platform for applications to run on", "A physical hardware component fitted inside the computer''s case to make it run more quickly", "A single file that stores all of the user''s personal documents, photos and settings together"], "answer": 1, "explain": "The OS is system software that manages the hardware and provides a platform for applications — it is not an application itself, nor a hardware part."}}, {"title": "The user interface", "html": "<h4>How the user interacts with the computer</h4>\n<ul>\n<li>One job of the OS is to provide a <strong>user interface</strong> — the means by which a person <strong>interacts</strong> with the computer, giving it instructions and seeing its output.</li>\n<li>A <strong>graphical user interface (GUI)</strong> uses <strong>windows, icons, menus and a pointer</strong> (sometimes called WIMP). It is easy for beginners because you click and tap visible options rather than remembering commands.</li>\n<li>A <strong>command line interface (CLI)</strong> needs the user to <strong>type text commands</strong>. It is harder to learn, but can be faster and more powerful for experienced users.</li>\n</ul>", "check": {"question": "What is the main difference between a GUI and a command line interface (CLI)?", "options": ["A GUI uses windows, icons, menus and a pointer, whereas a CLI needs the user to type text commands", "A GUI can only ever be used on a mobile phone or a tablet, while a CLI can only be used on a desktop computer", "A GUI is a piece of hardware, whereas a CLI is a completely separate physical device from it", "A GUI runs without any operating system at all, but a CLI always requires one to be installed"], "answer": 0, "explain": "A GUI is interacted with visually (windows, icons, menus, pointer); a CLI requires typed text commands — both are just styles of user interface."}}, {"title": "Memory management", "html": "<h4>Sharing out RAM between programs</h4>\n<ul>\n<li><strong>Memory management</strong> controls how the computer''s <strong>main memory (RAM)</strong> is used.</li>\n<li>It <strong>moves programs and data into and out of RAM</strong> as they are needed, and <strong>allocates</strong> (gives out) a share of memory to each running program.</li>\n<li>It keeps each program''s memory <strong>separate</strong>, so one program cannot overwrite or interfere with another''s data, and <strong>frees up</strong> memory again when a program is closed so it can be reused.</li>\n</ul>", "check": {"question": "What does the memory management function of an operating system do?", "options": ["It permanently stores all of the user''s saved files and documents on the computer''s hard drive", "It allocates RAM to each running program and moves programs and data into and out of memory", "It controls exactly which websites the user is allowed to visit while they are online", "It physically increases the total amount of RAM that is fitted inside the computer"], "answer": 1, "explain": "Memory management allocates RAM to programs and moves programs/data in and out of memory — it does not deal with permanent storage or add physical RAM."}}, {"title": "Multitasking", "html": "<h4>Running several programs ''at once''</h4>\n<ul>\n<li><strong>Multitasking</strong> lets the computer <strong>appear</strong> to run several programs at the same time — for example a browser, music player and word processor all open together.</li>\n<li>A single processor can only actually run <strong>one instruction at a time</strong>, so the OS <strong>switches very rapidly between the programs</strong>, giving each a tiny slice of processor time in turn (time-slicing).</li>\n<li>Because the switching happens so fast, it <strong>looks</strong> to the user as though everything is running simultaneously. Multitasking works closely with memory management, which keeps each program''s memory separate.</li>\n</ul>", "check": {"question": "How does an operating system with a single processor manage to multitask?", "options": ["It genuinely runs every single open program at exactly the same instant, using no switching of any kind at all", "It switches very rapidly between the programs, giving each a small slice of processor time in turn", "It shuts every program except one, and only reopens the others when the user asks for them again", "It permanently splits the processor into several smaller, separate physical processors inside the chip"], "answer": 1, "explain": "A single processor runs one instruction at a time, so the OS rapidly switches between programs (time-slicing) so they appear to run at once."}}, {"title": "Peripheral management", "html": "<h4>Controlling the devices connected to the computer</h4>\n<ul>\n<li><strong>Peripheral management</strong> controls communication between the computer and its <strong>peripherals</strong> — input, output and storage devices such as keyboards, printers, monitors and external drives.</li>\n<li>It <strong>manages the transfer of data to and from</strong> these devices, so that each one receives or sends data correctly.</li>\n<li>Because a device (like a printer) is usually much slower than the processor, the OS uses a <strong>buffer</strong> (a small store of data waiting to be processed) and a <strong>queue</strong> so the processor does not have to wait around for the device.</li>\n</ul>", "check": {"question": "What is the role of peripheral management in an operating system?", "options": ["It decides exactly which programs are allowed to appear in the computer''s start-up menu each and every morning", "It manages communication and the transfer of data between the computer and its connected devices", "It scans every file on the computer for viruses and other kinds of malicious software", "It chooses the strong passwords that each different user of the computer must use to log in"], "answer": 1, "explain": "Peripheral management handles communication and data transfer between the computer and its peripherals (input, output and storage devices)."}}, {"title": "Device drivers", "html": "<h4>Software that lets the OS ''talk to'' a device</h4>\n<ul>\n<li>A <strong>device driver</strong> is a piece of <strong>software</strong> that lets the operating system <strong>communicate with a specific piece of hardware</strong>, such as a particular printer, graphics card or webcam.</li>\n<li>It <strong>translates</strong> the operating system''s general instructions into the exact commands that <strong>that</strong> device understands.</li>\n<li>Each different device needs its <strong>own correct driver</strong>. If a driver is missing or out of date, the device may not work properly — which is why installing a new printer usually means installing its driver too.</li>\n</ul>", "check": {"question": "What is a device driver?", "options": ["A physical cable that is used to connect a peripheral device securely to the main computer unit", "Software that allows the operating system to communicate with a specific piece of hardware", "The person whose job it is to install and repair the computers within a large organisation", "A backup copy of the operating system that is used if the main copy ever becomes damaged"], "answer": 1, "explain": "A driver is software (not a cable or a person) that lets the OS communicate with, and control, a specific hardware device."}}, {"title": "User management", "html": "<h4>Controlling accounts and who can do what</h4>\n<ul>\n<li><strong>User management</strong> lets the OS support <strong>different user accounts</strong>, each with its own <strong>login</strong> (username and password).</li>\n<li>It keeps each user''s <strong>files and settings separate</strong>, so one person''s documents and preferences do not mix with another''s.</li>\n<li>It sets <strong>access rights (permissions)</strong> — deciding what each user is allowed to see or do — and handles <strong>security</strong>, such as requiring a password to log in. This is how a shared computer can give a teacher more control than a student.</li>\n</ul>", "check": {"question": "Which of these is part of the user management function of an operating system?", "options": ["Moving programs and all of their data into and out of the computer''s main memory as they are needed to run", "Setting up user accounts with logins and giving each user their own access rights and permissions", "Sending pages of data to a printer''s buffer so they can be printed one after another in order", "Organising the computer''s saved files neatly into a structure of named folders and sub-folders"], "answer": 1, "explain": "User management deals with accounts, logins and access rights. The other options describe memory management, peripheral management and file management."}}, {"title": "File management", "html": "<h4>Organising the files stored on the computer</h4>\n<ul>\n<li><strong>File management</strong> organises the files stored on the computer into a <strong>structure of folders (directories)</strong> so they can be found again easily.</li>\n<li>It lets the user (and programs) <strong>create, open, save, rename, move, copy and delete</strong> files and folders.</li>\n<li>It keeps track of <strong>where each file is physically stored</strong> on the disk, and can control <strong>who is allowed to access</strong> particular files, working alongside user management.</li>\n</ul>", "check": {"question": "What does the file management function of an operating system do?", "options": ["It rapidly switches the single processor between several open programs so they appear to run at once", "It organises files into folders and lets them be created, renamed, moved, copied, opened and deleted", "It translates the operating system''s instructions into commands that one specific printer understands", "It shares out the available space in RAM between all of the programs that are currently running"], "answer": 1, "explain": "File management organises files into folders and handles creating, naming, moving, copying and deleting them. The others describe multitasking, drivers and memory management."}}, {"title": "Matching the function to the task", "html": "<h4>The mapping the exam keeps testing</h4>\n<p>Questions very often give you a <strong>task</strong> and ask which <strong>function</strong> is responsible. Learn these signature links:</p>\n<ul>\n<li><strong>User interface</strong> → how the user <strong>interacts</strong> with the computer (clicking icons, typing commands).</li>\n<li><strong>Memory management</strong> → moving programs/data in and out of <strong>RAM</strong>; allocating memory.</li>\n<li><strong>Multitasking</strong> → switching between <strong>several open programs</strong> so they appear to run at once.</li>\n<li><strong>Peripheral management</strong> → transferring data <strong>to and from devices</strong>; using buffers.</li>\n<li><strong>Device drivers</strong> → letting the OS <strong>communicate with a specific device</strong> (e.g. installing a printer driver).</li>\n<li><strong>User management</strong> → <strong>accounts</strong>, logins, passwords and <strong>access rights</strong>.</li>\n<li><strong>File management</strong> → organising <strong>files and folders</strong> (create, rename, move, delete).</li>\n</ul>", "check": {"question": "A computer is ''transferring data to and from RAM as programs run''. Which operating system function is responsible?", "options": ["File management, because the data being transferred will eventually be saved into a folder somewhere", "Memory management, because it moves programs and data into and out of RAM and allocates memory", "User management, because only a logged-in user is able to run the programs on the computer at all", "Peripheral management, because RAM is a device that is connected to the rest of the computer system"], "answer": 1, "explain": "Moving programs and data in and out of RAM is the defining task of memory management."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Operating system (OS)", "definition": "System software that manages the hardware and provides a platform for applications"}, {"term": "System software", "definition": "Software that runs and manages the computer itself, e.g. the OS and utilities"}, {"term": "Application software", "definition": "Software for user tasks (word processor, browser) that runs on top of the OS"}, {"term": "User interface", "definition": "The means by which a user interacts with the computer"}, {"term": "GUI", "definition": "Graphical user interface using windows, icons, menus and a pointer (WIMP)"}, {"term": "Command line interface (CLI)", "definition": "An interface controlled by typing text commands"}, {"term": "Memory management", "definition": "Allocates RAM to programs and moves programs and data in and out of memory"}, {"term": "Multitasking", "definition": "Rapidly switching one processor between programs so they appear to run at once"}, {"term": "Time-slicing", "definition": "Giving each program a small slice of processor time in turn during multitasking"}, {"term": "Peripheral management", "definition": "Controls communication and data transfer between the computer and its devices"}, {"term": "Buffer", "definition": "A temporary store for data waiting to be sent to a slower device"}, {"term": "Device driver", "definition": "Software that lets the OS communicate with a specific piece of hardware"}, {"term": "User management", "definition": "Provides accounts, logins, passwords and access rights, keeping users separate"}, {"term": "Access rights", "definition": "Permissions deciding what a particular user is allowed to see or do"}, {"term": "File management", "definition": "Organises files into folders and handles creating, renaming, moving and deleting"}, {"term": "Directory / folder", "definition": "A named container used to organise files within the file structure"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of the following is an example of an operating system?", "options": ["A spreadsheet program that a user opens whenever they need to work with numbers and charts", "Linux", "A device driver that has been installed so the computer can print to a new office printer", "A backup utility that automatically copies important files to an external drive each night"], "answer": 1, "explain": "Linux is an operating system. A spreadsheet is application software, and a driver or backup utility is other system software — not the OS itself."}, {"question": "What is the main purpose of the user interface provided by an operating system?", "options": ["To permanently increase the amount of storage space available on the computer''s hard drive", "To provide the means by which a user interacts with the computer and gives it instructions", "To scan the computer for malware and remove any harmful programs that it happens to find", "To keep a spare copy of every file so that nothing is ever lost if the computer breaks down"], "answer": 1, "explain": "The user interface is how the user interacts with the computer (e.g. a GUI or CLI) — it does not manage storage, malware or backups."}, {"question": "A single-processor computer has a browser, a game and a music player all open at the same time. Which operating system function makes this possible?", "options": ["File management", "Multitasking", "User management", "Peripheral management"], "answer": 1, "explain": "Multitasking rapidly switches the processor between the open programs so they appear to run at the same time."}, {"question": "Which task is carried out by the memory management function?", "options": ["Organising the user''s saved documents and photos neatly into a set of clearly named folders", "Allocating space in RAM to each running program and moving data in and out of memory", "Requiring every user to enter a password before they are allowed to log in to the computer", "Sending data to a printer''s buffer so that several documents can be printed one after another"], "answer": 1, "explain": "Allocating RAM and moving data in and out of memory is memory management. The others are file management, user management and peripheral management."}, {"question": "Why does an operating system need a device driver for a new printer?", "options": ["Because the printer will physically refuse to switch on until a matching driver has been bought", "Because the driver is the software that lets the OS communicate with that specific printer", "Because a driver is the only thing that supplies electrical power to the printer while it runs", "Because without a driver the printer would print every document in completely the wrong order"], "answer": 1, "explain": "A driver is the software that lets the OS communicate with and control that specific device — it does not supply power or physically switch the printer on."}, {"question": "On a shared family computer, each person has their own login, their own files and their own settings. Which operating system function provides this?", "options": ["File management", "User management", "Memory management", "Multitasking"], "answer": 1, "explain": "Separate accounts, logins and settings are provided by user management, which also controls each user''s access rights."}, {"question": "Which of these is a task performed by file management?", "options": ["Switching the processor rapidly between several different programs that the user has opened at once", "Creating, renaming, moving and deleting files within a structure of folders on the computer", "Translating the operating system''s instructions into commands a specific graphics card understands", "Deciding how much of the computer''s RAM each currently running program is allowed to use"], "answer": 1, "explain": "Creating, renaming, moving and deleting files in folders is file management. The others describe multitasking, drivers and memory management."}, {"question": "What does peripheral management use a buffer for?", "options": ["To permanently store all of the user''s most important files in case the computer ever breaks down completely", "To temporarily hold data waiting to be sent to a slower device, so the processor need not wait", "To make the processor run at a much higher clock speed than it was originally designed for", "To decide which of the computer''s several users is currently allowed to print their documents"], "answer": 1, "explain": "A buffer temporarily holds data waiting to be processed by a slower peripheral, so the fast processor is not held up waiting for it."}, {"question": "Which two functions must work together so that several programs can run at once without their data getting mixed up?", "options": ["File management and user management, because both of them deal with keeping things neatly separated", "Memory management and multitasking, because one keeps each program''s memory separate as the other switches between them", "Peripheral management and device drivers, because both of them handle the various hardware devices attached to the computer", "The user interface and file management, because both of them are things the user can see on the screen"], "answer": 1, "explain": "Multitasking switches between programs while memory management keeps each program''s memory separate, so their data does not get mixed up."}, {"question": "A user types text commands to control a computer instead of clicking on icons. Which type of user interface are they using?", "options": ["A graphical user interface (GUI)", "A command line interface (CLI)", "A peripheral management interface", "A file management interface"], "answer": 1, "explain": "Typing text commands to control the computer is a command line interface (CLI); a GUI is controlled by clicking windows, icons, menus and a pointer."}, {"question": "Which of the following best describes what a graphical user interface (GUI) uses?", "options": ["Typed text commands that the user has to learn and remember before they can do anything at all", "Windows, icons, menus and a pointer that the user can click on to control the computer", "A single flashing cursor on an otherwise completely blank screen with no other options shown", "A printed paper manual that lists every command the computer is able to understand and carry out"], "answer": 1, "explain": "A GUI uses windows, icons, menus and a pointer (WIMP). Typed commands describe a CLI, not a GUI."}, {"question": "Which operating system function is responsible for setting each user''s access rights?", "options": ["Memory management", "User management", "File management", "Multitasking"], "answer": 1, "explain": "Setting access rights and permissions for each account is part of user management."}]}, "fib": {"enabled": true, "questions": [{"text": "An operating system is [system] software that manages the computer''s hardware and provides a platform for applications."}, {"text": "A graphical user interface uses windows, icons, menus and a [pointer] that the user clicks to control the computer."}, {"text": "Memory management allocates space in [RAM] to each running program and moves data into and out of it."}, {"text": "Because one processor runs a single instruction at a time, [multitasking] makes several programs appear to run at once by switching between them."}, {"text": "A device [driver] is software that lets the operating system communicate with a specific piece of hardware."}, {"text": "Peripheral management uses a [buffer] to hold data waiting to be sent to a slower device such as a printer."}, {"text": "[user] management provides separate user accounts, logins and access rights on a shared computer."}, {"text": "File management organises files into a structure of [folders] so they can be found again easily."}]}, "tf": {"enabled": true, "questions": [{"statement": "An operating system is an example of application software.", "answer": false, "explain": "An operating system is system software. Application software (like a word processor) runs on top of the operating system."}, {"statement": "A command line interface requires the user to type text commands to control the computer.", "answer": true, "explain": "Correct — a CLI is controlled by typed commands, unlike a GUI which uses windows, icons, menus and a pointer."}, {"statement": "Memory management is responsible for organising the user''s saved files into folders.", "answer": false, "explain": "That is file management. Memory management deals with RAM — allocating it to programs and moving data in and out of it."}, {"statement": "During multitasking, a single processor rapidly switches between programs so they appear to run at the same time.", "answer": true, "explain": "Correct — one processor runs one instruction at a time, so it time-slices between programs, making them appear simultaneous."}, {"statement": "A device driver is a physical cable that connects a peripheral to the computer.", "answer": false, "explain": "A device driver is software, not hardware. It lets the operating system communicate with a specific device."}, {"statement": "Peripheral management can use a buffer so the fast processor does not have to wait for a slower device.", "answer": true, "explain": "Correct — a buffer temporarily holds data for a slower peripheral, letting the processor carry on with other work."}, {"statement": "User management is what keeps different users'' files and settings separate and controls their access rights.", "answer": true, "explain": "Correct — user management provides separate accounts with their own logins, settings and access rights."}, {"statement": "The user interface is the physical monitor and keyboard attached to the computer.", "answer": false, "explain": "The user interface is the software layer (such as a GUI or CLI) through which the user interacts — not the physical hardware itself."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking the operating system is the same thing as the applications, e.g. that a web browser or word processor is part of the OS.", "truth": "The <strong>operating system</strong> is <strong>system software</strong> that manages the computer and provides a platform. <strong>Applications</strong> (browser, word processor, games) are separate software that <strong>runs on top of</strong> the OS. The OS is what lets those applications use the hardware.", "check": {"question": "How is an operating system different from an application such as a web browser?", "options": ["There is no real difference between them, because both of them are simply types of application software", "The OS is system software that manages the computer; applications run on top of the OS", "The OS is a physical hardware component, while an application is a piece of software", "An application manages the hardware, while the operating system is only ever used for browsing the web"], "answer": 1, "explain": "The OS is system software that manages the machine and provides a platform; applications are separate software that runs on top of it."}}, {"myth": "Believing that multitasking means a single processor genuinely runs many programs at exactly the same instant.", "truth": "A single processor runs <strong>one instruction at a time</strong>. Multitasking works by <strong>switching very rapidly</strong> between the open programs, giving each a tiny slice of time. It only <strong>appears</strong> simultaneous because the switching is so fast.", "check": {"question": "Why is it wrong to say a single-processor computer runs all its open programs at exactly the same instant?", "options": ["Because a single processor can only run one instruction at a time, so it must switch rapidly between them", "Because a single-processor computer can never actually have more than one separate program open at the same time at all", "Because programs never actually run on the processor, only ever on the RAM and the hard drive together", "Because the programs are really all run by the user manually, one instruction at a time, using the mouse"], "answer": 0, "explain": "One processor executes one instruction at a time; multitasking rapidly switches between programs so they only appear to run simultaneously."}}, {"myth": "Confusing memory management (RAM) with managing the hard drive or saved files.", "truth": "<strong>Memory management</strong> is about <strong>RAM</strong> — allocating it to running programs and moving programs and data in and out of it. Organising <strong>saved files</strong> in folders on storage is <strong>file management</strong>. Keep ''memory = RAM'' and ''files = storage'' separate.", "check": {"question": "A question describes ''moving programs and data into and out of RAM''. Which function is this?", "options": ["File management, because anything to do with data on the computer counts as managing its files", "Memory management, because it is specifically about allocating and using RAM (main memory)", "User management, because a user must be logged in before any program can use the RAM at all", "Peripheral management, because RAM is treated as just another peripheral device by the computer"], "answer": 1, "explain": "Moving programs and data in and out of RAM is memory management; organising saved files on storage is the separate job of file management."}}, {"myth": "Thinking a device driver is a physical part of the computer, or the person who installs it.", "truth": "A <strong>device driver</strong> is <strong>software</strong>. It lets the operating system <strong>communicate with a specific piece of hardware</strong> by translating the OS''s instructions into commands that device understands. It is not a cable, a chip, or a person.", "check": {"question": "Which statement about a device driver is correct?", "options": ["It is the wire that carries the electrical signal from the computer to a connected peripheral device", "It is software that lets the operating system communicate with a specific piece of hardware", "It is the member of IT staff whose job is to keep all of the school''s printers working properly", "It is a small physical chip that must be fitted inside every peripheral before it can be used"], "answer": 1, "explain": "A driver is software that lets the OS communicate with a specific device — not a cable, a chip or a person."}}, {"myth": "Mixing up user management and file management because both ''control access'' in some way.", "truth": "<strong>User management</strong> is about the <strong>people</strong> — accounts, logins, passwords and each user''s access rights. <strong>File management</strong> is about the <strong>files</strong> — organising them into folders and creating, renaming, moving or deleting them. They work together but do different jobs.", "check": {"question": "Which task belongs to user management rather than file management?", "options": ["Sorting all of the user''s saved documents and photographs neatly into a well-organised structure of named folders", "Setting up a new account with a login and giving that user their own access rights and permissions", "Renaming a file from ''draft'' to ''final'' after the user has finished working on the document", "Deleting an old folder full of files that the user says they no longer need to keep at all"], "answer": 1, "explain": "Creating accounts and setting access rights is user management; the other three tasks (organising, renaming and deleting files/folders) are file management."}}, {"myth": "Assuming the user interface means the physical screen, mouse and keyboard.", "truth": "The <strong>user interface</strong> is the <strong>software</strong> layer you interact through — a <strong>GUI</strong> (windows, icons, menus, pointer) or a <strong>CLI</strong> (typed commands). The monitor, mouse and keyboard are the hardware you use to work the interface, but they are not the interface itself.", "check": {"question": "What is the user interface of an operating system?", "options": ["The physical monitor, keyboard and mouse that are plugged into the computer''s main unit by the user", "The software layer, such as a GUI or CLI, through which the user interacts with the computer", "The internal processor that carries out all of the instructions given to the computer by its user", "The broadband router that connects the whole computer to the internet and to other devices nearby"], "answer": 1, "explain": "The user interface is the software (GUI or CLI) you interact through; the physical devices are hardware used to operate it, not the interface itself."}}]}, "tips": {"enabled": true, "items": [{"title": "Match the function to the task — the tick-grid and table skill", "html": "<p>The most common question style here gives you a <strong>task</strong> and asks which <strong>function</strong> does it — as a tick-one-box grid, or a table you complete. You have to know each function''s signature task cold:</p>\n<ul>\n<li>Transfer data to/from <strong>RAM</strong> → <strong>memory management</strong></li>\n<li>Install a printer''s <strong>driver</strong> / send data to a device → <strong>peripheral management</strong></li>\n<li>Create a <strong>user account</strong> / set a password → <strong>user management</strong></li>\n<li>Rename or move a <strong>folder</strong> → <strong>file management</strong></li>\n<li>Switch between several <strong>open programs</strong> → <strong>multitasking</strong></li>\n</ul>\n<p><strong>Watch the traps:</strong> \"memory\" means RAM, not storage — a saved file is <em>file</em> management. And installing a driver is <em>peripheral</em> management, even though the driver itself is software.</p>", "check": {"question": "In a tick-grid question, the task is ''renaming a folder''. Which function should you tick?", "options": ["Memory management, because the folder and its contents are stored somewhere in the computer''s memory", "File management, because renaming a folder is part of organising files and folders", "User management, because only a logged-in user is able to rename a folder in the first place", "Peripheral management, because the folder has to be shown on the monitor while it is renamed"], "answer": 1, "explain": "Renaming a folder is organising files and folders, which is file management — ''memory'' here would mean RAM, which is not involved."}}, {"title": "''Identify and describe two functions'' — name AND describe", "html": "<p>A frequent question asks you to <strong>identify and describe</strong> two (or more) functions of an operating system. The marks split into two halves for each function:</p>\n<ul>\n<li><strong>Identify (1 mark):</strong> name a valid function — e.g. \"memory management\".</li>\n<li><strong>Describe (1 mark):</strong> say what it actually does — e.g. \"it allocates RAM to each running program and moves data in and out of memory\".</li>\n</ul>\n<p><strong>❌ Half marks:</strong> just listing \"memory management, file management\" with no description.</p>\n<p><strong>✅ Full marks:</strong> each function <strong>named</strong> and then <strong>described</strong> with what it does. Pick functions you can clearly describe, and make sure your two functions are genuinely <strong>different</strong> — don''t give memory management twice in different words.</p>", "check": {"question": "A student answers a 4-mark ''identify and describe two functions'' question by writing only ''memory management and file management''. What is missing?", "options": ["Nothing is missing — naming the two functions is enough to earn all four of the available marks", "A description of what each named function actually does, which is where half of the marks are", "The exact year in which each of those two operating system functions was first invented", "A labelled diagram showing the inside of the processor while each function is running"], "answer": 1, "explain": "Naming the functions earns the ''identify'' marks only; the ''describe'' marks need you to say what each function does."}}, {"title": "Don''t blur memory, files, drivers and the interface", "html": "<p>Four pairs get mixed up constantly. Keep each one crisp:</p>\n<ul>\n<li><strong>Memory management</strong> = RAM (main memory). <strong>File management</strong> = saved files/folders on storage. \"Memory\" ≠ \"storage\".</li>\n<li><strong>Peripheral management</strong> = the OS controlling devices. A <strong>device driver</strong> = the software that lets it talk to one specific device.</li>\n<li><strong>User interface</strong> = the software layer you interact through (GUI/CLI), not the physical screen or keyboard.</li>\n<li><strong>User management</strong> = accounts, logins and access rights (the people). <strong>File management</strong> = the files themselves.</li>\n</ul>\n<p>If a question mentions RAM, think memory management; if it mentions folders, think file management; if it mentions a specific printer or webcam, think drivers/peripheral management.</p>", "check": {"question": "A question mentions ''installing the software needed for the computer to use a new webcam''. Which term fits best?", "options": ["Memory management, because the webcam''s software will first need to be loaded into the computer''s RAM in order to run", "A device driver, because it is the software that lets the OS communicate with that specific webcam", "File management, because the webcam will end up saving its captured video files into a folder", "The user interface, because the user has to click on the webcam''s icon before they can use it"], "answer": 1, "explain": "The software that lets the OS use one specific device (the webcam) is its device driver."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick <strong>one</strong> box to identify the operating system function that provides the means by which a user interacts with the computer.</p>", "marks": 1, "hint": "Which function is about how a person gives the computer instructions and sees its output?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>The user interface</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box to identify the operating system function responsible for allocating RAM to programs and moving data into and out of main memory.</p>", "marks": 1, "hint": "The clue is ''RAM'' and ''main memory'' — only one function is about managing that.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Memory management</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box to identify which of these is a task performed by file management.</p>", "marks": 1, "hint": "File management is about organising files and folders on the computer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Renaming a folder</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>State <strong>two</strong> functions of an operating system.</p>", "marks": 2, "hint": "Just name two — for example from the user interface, memory management, multitasking, peripheral management, user management or file management.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each, max 2)</h5>\n<ul>\n<li>Providing a user interface</li>\n<li>Memory management</li>\n<li>Multitasking</li>\n<li>Peripheral management (and device drivers)</li>\n<li>User management</li>\n<li>File management</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award any two different valid functions. Two ways of naming the same function score 1 mark only.</li>\n</ul>\n</div>"}, {"question": "<p>Describe what a device driver is and why an operating system needs one.</p>", "marks": 2, "hint": "Say what kind of thing a driver is (hardware or software?), and what job it does for a specific device.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: a device driver is software</li>\n<li>1 mark: it lets the OS communicate with (or control) a specific piece of hardware</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both marks require the idea of software AND communicating with a specific device.</li>\n</ul>\n</div>"}, {"question": "<p>Describe <strong>one</strong> difference between a graphical user interface (GUI) and a command line interface (CLI).</p>", "marks": 2, "hint": "Say how the user controls each one — clicking visible things versus typing something.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: a GUI uses windows, icons, menus and a pointer (clicked/tapped)</li>\n<li>1 mark: a CLI requires the user to type text commands</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both sides of the difference are needed for 2 marks. Accept other valid contrasts (e.g. GUI easier for beginners / CLI faster for experts).</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to identify the operating system function that carries out each task.</p>", "marks": 5, "hint": "Match each task to its signature function: RAM → memory, a driver/device → peripheral, an account → user, a folder → file, several open programs → multitasking.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks (1 mark for each row)</h5>\n<ul>\n<li>Transferring data to and from RAM → <strong>Memory management</strong></li>\n<li>Installing the driver for a new printer → <strong>Peripheral management</strong></li>\n<li>Creating a new user account → <strong>User management</strong></li>\n<li>Renaming a folder → <strong>File management</strong></li>\n<li>Switching rapidly between two open programs → <strong>Multitasking</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently; 2+ ticks in a single row scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to identify which operating system function deals with each action.</p>", "marks": 4, "hint": "Password/login → user; folder → file; buffer/printer → peripheral; RAM → memory.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Setting the password needed to log in → <strong>User management</strong></li>\n<li>Saving a document into the correct folder → <strong>File management</strong></li>\n<li>Sending data to a printer''s buffer → <strong>Peripheral management</strong></li>\n<li>Freeing up RAM when a program is closed → <strong>Memory management</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently; 2+ ticks in a single row scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>The paragraph below describes the functions of an operating system.</p><p>Complete the paragraph by selecting terms from the list and writing them in the correct places. <strong>Not all terms are used.</strong></p>", "marks": 8, "hint": "Read each whole sentence before choosing. Several terms are deliberate decoys — if you use every word, something has gone wrong.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (1 mark for each completed term)</h5>\n<p>An operating system is <strong>system</strong> software that manages the whole computer. It provides a user <strong>interface</strong> so a person can interact with the machine. <strong>Memory</strong> management moves programs and data into and out of <strong>RAM</strong> so they can run. <strong>Multitasking</strong> lets several programs appear to run at the same time on one processor. To communicate with hardware such as a printer, the operating system uses device <strong>drivers</strong>. User management controls accounts, passwords and access <strong>rights</strong>, and file management organises files into <strong>folders</strong>.</p>\n</div>"}, {"question": "<p>Identify and describe <strong>two</strong> functions of an operating system.</p>", "marks": 4, "hint": "For each function: name it, then say what it actually does. Choose two different functions you can describe clearly.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (2 per function: 1 identify + 1 describe)</h5>\n<ul>\n<li>Memory management — allocates RAM to programs and moves data in and out of memory</li>\n<li>Multitasking — rapidly switches the processor between programs so they appear to run at once</li>\n<li>Peripheral management — controls the transfer of data to and from connected devices</li>\n<li>User management — provides accounts, logins and access rights</li>\n<li>File management — organises files into folders and handles creating, renaming, moving and deleting them</li>\n<li>User interface — provides the means for the user to interact with the computer</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each function scores 1 for being named and 1 for a correct description. Two descriptions of the same function score only one function''s marks.</li>\n</ul>\n</div>"}, {"question": "<p>Leah runs several programs at the same time on her laptop.</p><p>Explain how memory management and multitasking work together to make this possible.</p>", "marks": 4, "hint": "Explain what each function does, then how they combine — one keeps the programs'' memory apart while the other shares out processor time.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: the processor runs one instruction at a time, so multitasking switches rapidly between programs</li>\n<li>1 mark: this makes the programs appear to run at the same time</li>\n<li>1 mark: memory management allocates a share of RAM to each running program</li>\n<li>1 mark: it keeps each program''s memory separate so they do not interfere with each other</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Full marks needs both functions explained AND the idea that together they let several programs run without their data clashing.</li>\n</ul>\n</div>"}, {"question": "<p>Leah connects a new printer to her laptop.</p><p>Explain how peripheral management and a device driver allow her laptop to use the printer.</p>", "marks": 4, "hint": "Explain what peripheral management does with the data going to the printer, and what job the driver does for that specific printer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>1 mark: peripheral management controls communication/data transfer between the laptop and the printer</li>\n<li>1 mark: it can use a buffer/queue so the processor does not wait for the slower printer</li>\n<li>1 mark: a driver is software that lets the OS communicate with that specific printer</li>\n<li>1 mark: it translates the OS''s instructions into commands the printer understands</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Credit both the peripheral management role AND the specific job of the driver.</li>\n</ul>\n</div>"}, {"question": "<p>Oakwood Library''s computers are shared by many people, and staff accounts can do more than public accounts.</p><p>Explain how user management and file management help keep the library''s computers organised and secure.</p>", "marks": 5, "hint": "Cover user management (accounts, logins, access rights) and file management (folders, controlling access), and link each to the shared-computer scenario.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks</h5>\n<ul>\n<li>1 mark: user management gives each person their own account and login</li>\n<li>1 mark: it keeps each user''s files and settings separate</li>\n<li>1 mark: access rights let staff do more than public users / control who can do what</li>\n<li>1 mark: file management organises files into folders so they can be found</li>\n<li>1 mark: file management (with user management) controls access to files / handles create-rename-move-delete</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Reward points from BOTH functions, applied to the shared-computer situation. Max 5.</li>\n</ul>\n</div>"}, {"question": "<p>Leah uses her laptop to write essays, listen to music and browse the web, often at the same time, saving her work as she goes.</p><p>Explain how <strong>three</strong> functions of the operating system help Leah use her laptop. You should describe a different function each time.</p>", "marks": 6, "hint": "Choose three clearly different functions (for example the user interface, multitasking and file management). For each: name it, describe what it does, and link it to something Leah does.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks (up to 2 for each of three different functions)</h5>\n<p>For EACH of three different functions:</p>\n<ul>\n<li>1 mark: the function is named and correctly described</li>\n<li>1 mark: it is linked to Leah''s use of the laptop</li>\n</ul>\n<p>Examples of acceptable functions and links:</p>\n<ul>\n<li>User interface — its GUI lets Leah click icons and menus to open and control her programs</li>\n<li>Multitasking — lets Leah run her browser, music player and word processor at the same time</li>\n<li>Memory management — allocates RAM to each program so they can all run together</li>\n<li>File management — lets Leah save, name and organise her essays in folders</li>\n<li>Peripheral management / drivers — lets Leah use devices such as a printer or headphones</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each of three DIFFERENT functions can score up to 2 (description + link). Repeating a function does not earn the repeated marks.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-5-2-utility-software', '1.5.2 Utility Software', '{"learn": {"enabled": true, "items": [{"title": "What is utility software?", "html": "<h4>Small tools that help maintain the computer</h4>\n<ul>\n<li><strong>Utility software</strong> is a type of <strong>system software</strong>: programs that help to <strong>maintain, configure and optimise</strong> a computer so it keeps running smoothly. This is often called <strong>\"housekeeping\"</strong> or maintenance.</li>\n<li>Each utility does one specific maintenance job — for example tidying up the hard disk, making files smaller, keeping data safe, or checking the system for problems.</li>\n<li>Utilities are <strong>not</strong> application software: applications (like a word processor) are for the user''s own tasks, whereas utilities work behind the scenes to look after the <strong>computer itself</strong>.</li>\n</ul>\n<h4>The utilities you should know</h4>\n<ul>\n<li>The three named in the specification are <strong>defragmentation</strong>, <strong>data compression</strong> and <strong>encryption software</strong>. Exam questions also use others: <strong>backup</strong>, <strong>system information</strong>, <strong>diagnosis</strong>, and security tools such as <strong>anti-malware</strong> and <strong>firewalls</strong>.</li>\n</ul>", "check": {"question": "Which statement best describes utility software?", "options": ["Application software that a user opens to carry out a personal task such as writing a letter or editing a photograph", "System software that helps to maintain, configure and optimise the computer so it keeps running well", "A physical hardware component that is fitted inside the computer to speed up how quickly it can run", "The single main program that manages all of the computer''s hardware and runs every other program"], "answer": 1, "explain": "Utility software is system software that maintains and optimises the computer (housekeeping) — it is not an application, hardware, or the operating system itself."}}, {"title": "Why does a hard disk become fragmented?", "html": "<h4>Files get split up and scattered over time</h4>\n<ul>\n<li>When a file is first saved, its data is usually stored in one continuous run of space on the disk.</li>\n<li>But as files are <strong>edited, deleted and new ones saved</strong>, gaps of free space appear all over the disk. To use that space, the computer starts <strong>splitting files into pieces (fragments)</strong> and storing the pieces in whatever gaps are available.</li>\n<li>Over time, a single file can end up <strong>scattered across many different parts of the disk</strong>, and the free space becomes scattered too. This is called <strong>fragmentation</strong>.</li>\n</ul>", "check": {"question": "Why does a hard disk gradually become fragmented?", "options": ["Because the computer deliberately damages old files to free up extra space for new ones it needs", "Because as files are edited, deleted and saved, files get split into pieces stored in scattered gaps", "Because the read/write head physically wears down the surface of the disk a little more each day", "Because fragmentation is something the user has to switch on manually before it can ever happen at all"], "answer": 1, "explain": "Editing, deleting and saving files leaves scattered gaps, so the computer stores files in pieces across those gaps — that scattering is fragmentation."}}, {"title": "What defragmentation does — and why it speeds things up", "html": "<h4>Putting each file''s pieces back together</h4>\n<ul>\n<li>A <strong>defragmentation</strong> utility reorganises the data on the disk so that all the pieces of each file are stored <strong>together (contiguously)</strong>, one after another, and the <strong>free space is collated</strong> (gathered) into one area.</li>\n<li><strong>Why files are then accessed faster:</strong> when a file is fragmented, the read/write head has to <strong>move to many different places</strong> on the disk to gather all its pieces. After defragmentation, each file''s pieces are together, so the head <strong>moves far less</strong> to read the whole file — making access quicker.</li>\n<li><strong>Important:</strong> defragmentation is mainly useful for <strong>magnetic hard disk drives (HDDs)</strong>, which have a moving read/write head. <strong>Solid state drives (SSDs)</strong> have no moving parts, so defragmentation gives little benefit and is generally not done on them.</li>\n</ul>", "check": {"question": "Why can a computer access files more quickly after its hard disk has been defragmented?", "options": ["Because defragmentation permanently deletes any of the files that the user has not opened recently, so as to save room", "Because each file''s pieces are now stored together, so the read/write head moves less to read the whole file", "Because defragmentation physically increases the total speed at which the disk itself is able to spin round", "Because the computer is given a completely new and much faster hard disk during the defragmentation process"], "answer": 1, "explain": "Defragmentation stores each file''s fragments contiguously, so the read/write head travels much less to read a whole file — that is what speeds up access."}}, {"title": "Data compression", "html": "<h4>Making files smaller</h4>\n<ul>\n<li><strong>Data compression</strong> software <strong>reduces the size</strong> of a file — the number of bytes it takes up — by encoding the same data more efficiently.</li>\n<li><strong>Why it is useful:</strong> smaller files take up <strong>less storage space</strong>, and they are <strong>faster to send</strong> across a network or the internet (uploading, downloading or emailing), because there is less data to transfer.</li>\n<li>Common examples: creating a <strong>ZIP</strong> file, and the compression built into image, audio and video formats (such as JPEG or MP3).</li>\n</ul>", "check": {"question": "Why is it useful to compress a file before emailing it to someone?", "options": ["Because compressing the file will automatically translate it into a different language for the person receiving it", "Because a compressed file is smaller, so it uses less storage and is faster to send across the internet", "Because compression permanently protects the file so that it can never be opened by the wrong person again", "Because a compressed file will always open much more quickly on absolutely any computer that receives it later"], "answer": 1, "explain": "Compression reduces file size, so the file uses less storage and there is less data to transfer, making it faster to send."}}, {"title": "Encryption software", "html": "<h4>Scrambling data so it cannot be understood</h4>\n<ul>\n<li><strong>Encryption software</strong> scrambles data using an algorithm and a <strong>key</strong>, so that the data cannot be understood by anyone who does not have the key.</li>\n<li>Only someone with the correct <strong>key</strong> can <strong>decrypt</strong> the data back into its original, readable form.</li>\n<li><strong>Why it is used:</strong> if the data is <strong>intercepted or stolen</strong>, it is meaningless to the attacker without the key — so encryption is a <strong>security</strong> utility, protecting data both while it is stored and while it is being sent. (You met encryption as a defence in <strong>1.4.2</strong>.)</li>\n</ul>", "check": {"question": "What does encryption software do to a file?", "options": ["It makes the file much smaller so that it takes up noticeably less room on the computer''s hard drive", "It scrambles the data using a key so it cannot be understood by anyone who does not have that key", "It reorganises the pieces of the file so that they are all stored together in one place on the disk", "It creates a second copy of the file and stores that copy safely on a completely separate storage device"], "answer": 1, "explain": "Encryption scrambles the data with a key so it is unreadable without the key. Making files smaller is compression; reorganising pieces is defragmentation; a spare copy is backup."}}, {"title": "Backup software", "html": "<h4>Keeping a spare copy of your data</h4>\n<ul>\n<li><strong>Backup software</strong> makes a <strong>spare copy</strong> of files and data, usually stored <strong>separately</strong> (for example on an external drive or in the cloud), so the data can be <strong>restored</strong> if the original is lost.</li>\n<li>It protects against data loss from <strong>hardware failure, accidental deletion, theft, or a malware attack</strong> such as ransomware.</li>\n<li>Backups can be <strong>scheduled</strong> to run automatically (e.g. every night), so the copy is kept up to date without the user having to remember.</li>\n</ul>", "check": {"question": "What is the main purpose of backup software?", "options": ["To make each of the original files a good deal smaller so that many more of them can fit onto the same storage device", "To keep a spare copy of data, stored separately, so it can be restored if the original is lost or damaged", "To scramble the data using a secret key so that nobody without the key is able to read the files", "To reorganise the files on the disk so that each one is stored together and can be opened more quickly"], "answer": 1, "explain": "Backup keeps a separate spare copy so data can be restored after loss. Making files smaller is compression, scrambling is encryption, and reorganising is defragmentation."}}, {"title": "Full vs incremental backups", "html": "<h4>Two ways of making a backup</h4>\n<ul>\n<li>A <strong>full backup</strong> copies <strong>every</strong> file and all of the data, every time. It is <strong>complete</strong>, but it is <strong>slow</strong> and uses a <strong>lot of storage</strong>.</li>\n<li>An <strong>incremental backup</strong> copies <strong>only the files that have changed</strong> since the last backup. It is much <strong>faster</strong> and uses <strong>less storage</strong> each time.</li>\n<li><strong>The catch:</strong> an incremental backup can only be done <strong>after a full backup</strong> has been made. And to <strong>restore</strong> everything you need the full backup <strong>plus every incremental</strong> since — so restoring is more complicated.</li>\n<li>Many people use <strong>both</strong>: an occasional full backup, then quick incremental backups in between — getting complete cover without backing up everything every single time.</li>\n</ul>", "check": {"question": "How does an incremental backup differ from a full backup?", "options": ["An incremental backup copies absolutely every file and all of the data on the computer every single time it runs", "An incremental backup copies only the files that have changed since the last backup, so it is faster", "An incremental backup permanently deletes the older files once it has finished copying the newest ones across", "An incremental backup can be made before any full backup has ever been carried out on the computer at all"], "answer": 1, "explain": "An incremental backup copies only what has changed since the last backup (faster, less storage); a full backup copies everything every time."}}, {"title": "System information & diagnosis utilities", "html": "<h4>Checking on the computer''s health</h4>\n<ul>\n<li>A <strong>system information</strong> utility <strong>reports details about the computer</strong> — such as the processor, how much RAM is fitted, the operating system version, and how much storage is free. This helps a user or technician check the specification and see how the system is set up.</li>\n<li>A <strong>diagnosis</strong> (diagnostic) utility helps to <strong>find faults and problems</strong> — for example testing hardware, checking for errors, and reporting what is wrong so it can be fixed.</li>\n<li>Together they let you <strong>see what a computer has</strong> (system information) and <strong>find out what is wrong with it</strong> (diagnosis).</li>\n</ul>", "check": {"question": "What is the purpose of a diagnosis (diagnostic) utility?", "options": ["To display a simple list showing the processor, the amount of RAM and the version of the operating system", "To test the system and find faults or errors, then report what is wrong so that it can be fixed", "To make a spare copy of the user''s important files and store it safely on a separate external drive", "To reduce the size of the largest files on the computer so that they take up much less storage space"], "answer": 1, "explain": "A diagnosis utility finds and reports faults/errors. Listing the specification is what a system information utility does; the others describe backup and compression."}}, {"title": "Classifying utilities: security or maintenance?", "html": "<h4>Sorting utilities by what they are for</h4>\n<p>A common question gives you a list of utilities and asks you to sort them by <strong>purpose</strong>. Learn which group each one belongs to:</p>\n<ul>\n<li><strong>Security utilities</strong> — protect data and the system from attack: <strong>anti-malware/antivirus</strong>, <strong>firewall</strong>, and <strong>encryption software</strong>.</li>\n<li><strong>Disk organisation / maintenance utilities</strong> — keep the storage tidy and efficient: <strong>defragmentation</strong>, <strong>data compression</strong>, and <strong>file transfer/management</strong> tools.</li>\n<li><strong>Backup</strong> keeps your data safe from loss, and <strong>system information / diagnosis</strong> keep the computer healthy and help fix problems.</li>\n</ul>\n<p>If a question asks whether a utility is used for <strong>security</strong> or <strong>disk organisation</strong>, think: does it protect against attackers (security), or tidy/manage the storage (disk organisation)?</p>", "check": {"question": "In a ''security or disk organisation'' sorting question, which utility belongs under disk organisation?", "options": ["A firewall, because it carefully monitors and filters all of the traffic coming into and out of the network", "A defragmenter, because it reorganises the files on the disk so they are stored together and tidily", "An antivirus, because it scans the computer''s files and then removes any malicious software that it finds", "Encryption software, because it scrambles the data so that it cannot be read by an attacker without a key"], "answer": 1, "explain": "A defragmenter organises the disk, so it is a disk-organisation utility. A firewall, antivirus and encryption are all security utilities."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Utility software", "definition": "System software that helps maintain, configure and optimise the computer (housekeeping)"}, {"term": "Defragmentation", "definition": "Reorganises a disk so each file''s pieces are stored together and free space is collated"}, {"term": "Fragmentation", "definition": "When a file''s data is split into pieces stored in scattered places on a disk"}, {"term": "Why defrag speeds access", "definition": "Pieces stored together means the read/write head moves less to read a whole file"}, {"term": "Data compression", "definition": "Reduces the size of a file so it uses less storage and transfers faster"}, {"term": "Encryption software", "definition": "Scrambles data using a key so it cannot be understood without the key"}, {"term": "Backup software", "definition": "Makes a spare copy of data, stored separately, so it can be restored if lost"}, {"term": "Full backup", "definition": "Copies every file and all data every time (complete but slow, lots of storage)"}, {"term": "Incremental backup", "definition": "Copies only files changed since the last backup (fast, less storage; needs a full backup first)"}, {"term": "System information utility", "definition": "Reports details about the computer: processor, RAM, OS version, free storage"}, {"term": "Diagnosis utility", "definition": "Tests the system to find faults and errors and report what is wrong"}, {"term": "Security utilities", "definition": "Anti-malware, firewall and encryption — protect data and the system from attack"}, {"term": "Disk organisation utilities", "definition": "Defragmentation, compression and file transfer — keep storage tidy and efficient"}, {"term": "Anti-malware", "definition": "Scans for and removes malicious software"}, {"term": "Firewall", "definition": "Monitors and filters network traffic against a set of rules"}, {"term": "Lossless compression", "definition": "Compression where the original data is restored exactly when decompressed (e.g. ZIP)"}]}, "mcq": {"enabled": true, "questions": [{"question": "Utility software is best described as which type of software?", "options": ["Application software that the user opens to complete their own personal tasks, such as writing an essay", "System software that helps to maintain and optimise the computer", "A hardware upgrade that is fitted inside the computer to make it run faster and store much more data", "A programming language that is used by developers to write brand new programs from scratch each time"], "answer": 1, "explain": "Utility software is system software that maintains and optimises the computer — not application software, hardware or a programming language."}, {"question": "What does a defragmentation utility do?", "options": ["It makes a second copy of every file and stores that copy safely on a separate drive in case of loss", "It reorganises the disk so each file''s pieces are stored together and the free space is collated", "It reduces the size of large files so that they take up much less space on the computer''s hard disk", "It scrambles the data on the disk using a key so that it cannot be understood by an attacker who steals it"], "answer": 1, "explain": "Defragmentation reorganises the disk so each file''s fragments are contiguous and free space is gathered. The others describe backup, compression and encryption."}, {"question": "Why can files be accessed more quickly after a hard disk has been defragmented?", "options": ["Because the total amount of free space on the hard disk is permanently and significantly increased by the process", "Because each file''s pieces are now together, so the read/write head moves less to read the whole file", "Because the hard disk is made to spin around at a much higher speed than it did before it was defragmented", "Because all of the files that had not been used for a long time are deleted to make everything else run faster"], "answer": 1, "explain": "With each file''s fragments stored together, the read/write head travels far less to read a whole file, so access is quicker. Defrag does not add free space or speed up the disk itself."}, {"question": "On which type of storage is defragmentation most useful?", "options": ["A solid state drive (SSD), because it has no moving parts and so benefits the most from being reorganised", "A magnetic hard disk drive (HDD), which has a moving read/write head", "A read-only optical disc such as a DVD that has already been finalised and cannot be written to again", "Cloud storage, because the files there are always physically fragmented across many far-apart servers"], "answer": 1, "explain": "Defragmentation helps HDDs, which have a moving read/write head. SSDs have no moving parts, so they gain little and are generally not defragmented."}, {"question": "What does data compression software do to a file?", "options": ["It permanently protects the file so that only a person who has the correct secret key can ever open it", "It reduces the size of the file so it uses less storage and is faster to transfer", "It reorganises the pieces of the file so that they are all stored together in one continuous run on the disk", "It keeps a spare copy of the file on a separate device so that it can be restored if the original is lost"], "answer": 1, "explain": "Compression reduces file size (less storage, faster transfer). The other options describe encryption, defragmentation and backup."}, {"question": "Which utility software would help protect data so that it cannot be understood if it is stolen?", "options": ["A defragmentation utility, because it tidies up the disk and makes the files harder for a thief to locate", "Encryption software", "A system information utility, because it can display exactly which files are currently stored on the computer", "A data compression utility, because it makes the files so small that an attacker would not notice them at all"], "answer": 1, "explain": "Encryption scrambles data so it is unreadable without the key — the correct security utility here. The others do not protect data from being understood."}, {"question": "A company copies only the files that have changed since its last backup. Which type of backup is this?", "options": ["A full backup", "An incremental backup", "A compressed daily backup", "An encrypted backup"], "answer": 1, "explain": "Copying only what has changed since the last backup is an incremental backup; a full backup copies everything every time."}, {"question": "Which of these is a disadvantage of using only full backups every time?", "options": ["They copy only the files that have recently changed, so a lot of important older data is never actually saved", "They are slow to make and use a large amount of storage, because everything is copied every time", "They cannot be used to restore data at all if the computer''s original hard drive completely fails one day", "They can only ever be carried out after an incremental backup of the same data has first been completed"], "answer": 1, "explain": "A full backup copies everything each time, so it is slow and storage-heavy. (Incremental copies only changes; and incremental — not full — needs a prior full backup.)"}, {"question": "What does a system information utility do?", "options": ["It scrambles the computer''s data with a key so that it stays completely private and secure from any attacker", "It reports details about the computer, such as its processor, amount of RAM and operating system version", "It reorganises the files stored on the hard disk so that each one is kept together and loads more quickly", "It automatically copies the user''s most important files to a separate drive every night while they are asleep"], "answer": 1, "explain": "A system information utility reports details about the computer''s hardware and software. The others describe encryption, defragmentation and backup."}, {"question": "A utility tests a computer''s hardware, finds errors and reports what is wrong. Which utility is this?", "options": ["A defragmentation utility", "A diagnosis (diagnostic) utility", "A data compression and archiving utility", "An encryption utility"], "answer": 1, "explain": "Finding faults and reporting what is wrong is the job of a diagnosis (diagnostic) utility."}, {"question": "Which list contains only utilities that are used for security?", "options": ["Defragmenter, data compression and a file transfer tool that moves files between two different folders", "Antivirus, firewall and encryption software", "Data compression, a system information utility and a diagnosis utility used for finding hardware faults", "Backup software, defragmentation software and a utility that reports how much RAM the computer has fitted"], "answer": 1, "explain": "Antivirus, firewall and encryption are all security utilities. The other lists contain disk-organisation, information and backup utilities."}, {"question": "Why might a user run both full and incremental backups rather than only full backups?", "options": ["Because incremental backups are able to copy files even when the computer is switched completely off at the wall", "Because the incremental backups are much faster and use less storage in between the occasional full backups", "Because an incremental backup does not need any full backup to have been made before it at any point at all", "Because full backups are the only kind that can ever be restored, so the incremental ones are just extra copies"], "answer": 1, "explain": "Incremental backups are quick and storage-light between fuller backups, giving complete cover without copying everything every time."}]}, "fib": {"enabled": true, "questions": [{"text": "Utility software is a type of [system] software that helps to maintain and optimise the computer."}, {"text": "Over time a file can be split into pieces stored in scattered places on a disk; this is called [fragmentation]."}, {"text": "After defragmentation each file''s pieces are stored [together], so the read/write head moves less and files load faster."}, {"text": "Data [compression] reduces the size of a file so it uses less storage and is faster to send across a network."}, {"text": "Encryption software scrambles data using a [key] so that it cannot be understood if it is intercepted."}, {"text": "A [full] backup copies every file and all data, whereas an incremental backup copies only what has changed."}, {"text": "An [incremental] backup is faster and uses less storage because it only copies the files that have changed since the last backup."}, {"text": "A [diagnosis] utility tests the system to find faults and reports what is wrong so it can be fixed."}]}, "tf": {"enabled": true, "questions": [{"statement": "Utility software is a type of application software used for tasks like writing documents.", "answer": false, "explain": "Utility software is system software that maintains the computer. Applications (like a word processor) are for the user''s own tasks."}, {"statement": "Defragmentation reorganises a disk so that each file''s pieces are stored together.", "answer": true, "explain": "Correct — defragmentation collates each file''s fragments so they are contiguous, and gathers the free space together."}, {"statement": "Files can be accessed faster after defragmentation because the read/write head has to move less.", "answer": true, "explain": "Correct — with each file''s pieces together, the head travels far less to read the whole file, so access is quicker."}, {"statement": "Defragmentation increases the total amount of free space on the hard disk.", "answer": false, "explain": "Defragmentation does not create extra free space — it reorganises existing data so files are contiguous and free space is gathered together."}, {"statement": "Data compression reduces the size of a file so it uses less storage and transfers faster.", "answer": true, "explain": "Correct — compression encodes the data more efficiently, so the file is smaller and there is less data to send."}, {"statement": "An incremental backup copies every file on the computer each time it runs.", "answer": false, "explain": "That describes a full backup. An incremental backup copies only the files that have changed since the last backup."}, {"statement": "An incremental backup can only be made after a full backup has already been completed.", "answer": true, "explain": "Correct — incremental backups record changes since the last backup, so there must be a full backup to build on first."}, {"statement": "A system information utility is used to find and remove malware from the computer.", "answer": false, "explain": "A system information utility reports details about the computer (processor, RAM, OS). Removing malware is the job of anti-malware software."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking defragmentation creates extra free space or deletes files to make room.", "truth": "Defragmentation does <strong>not</strong> add free space or delete your files. It <strong>reorganises</strong> the data that is already there so each file''s pieces are stored <strong>together</strong>, and gathers the scattered free space into one area. The benefit is <strong>faster access</strong>, not more storage.", "check": {"question": "What is the real benefit of defragmentation?", "options": ["It permanently increases the total amount of free storage space that is currently available on the computer''s own hard disk", "It reorganises files so their pieces are together, letting the read/write head move less and access them faster", "It deletes all of the files that the user has not opened for a long time in order to free up extra room", "It creates an extra backup copy of every file so that nothing can ever be lost from the computer again"], "answer": 1, "explain": "Defragmentation reorganises existing data for faster access — it does not add free space, delete files, or make backups."}}, {"myth": "Believing that compressing a file loses or deletes some of your data.", "truth": "Compression <strong>reduces the size</strong> of a file by storing the same information more efficiently. With <strong>lossless</strong> compression (like a ZIP file) the original data is restored <strong>exactly</strong> when it is decompressed — your files are not deleted or lost, just packed more tightly.", "check": {"question": "What happens to a file when it is compressed using lossless compression?", "options": ["Some of the file''s data is permanently thrown away, so the file can never be returned to how it was before", "The file is made smaller by storing the same data more efficiently, and can be restored exactly later", "The file is scrambled with a secret key so that nobody is able to read it without first being given the key", "The file is copied onto a completely separate storage device and the original version is then deleted for good"], "answer": 1, "explain": "Lossless compression makes the file smaller by encoding it more efficiently and restores the original exactly — nothing is lost. Scrambling is encryption; copying is backup."}}, {"myth": "Confusing utility software with the operating system or with applications.", "truth": "The <strong>operating system</strong> manages the whole computer; <strong>applications</strong> are for the user''s own tasks; <strong>utility software</strong> is a set of smaller <strong>system</strong> tools that <strong>maintain and optimise</strong> the computer (defrag, compression, backup, etc.). They are all software, but they do different jobs.", "check": {"question": "How is utility software different from an application such as a photo editor?", "options": ["There is no real difference at all, because a photo editor is simply one very common everyday example of utility software", "Utility software maintains and optimises the computer itself, while an application is for the user''s own tasks", "Utility software is a physical part of the computer, whereas an application is a piece of software", "Utility software can only ever run while the computer is not connected to the internet in any way at all"], "answer": 1, "explain": "Utilities are system tools that look after the computer; applications like a photo editor are for the user''s own tasks."}}, {"myth": "Thinking an incremental backup copies everything, just like a full backup.", "truth": "An <strong>incremental</strong> backup copies <strong>only the files that have changed</strong> since the last backup — that is exactly why it is <strong>faster</strong> and uses <strong>less storage</strong>. A <strong>full</strong> backup is the one that copies everything every time.", "check": {"question": "Why is an incremental backup faster than a full backup?", "options": ["Because an incremental backup quietly skips any files that it decides are not really that important to the user", "Because an incremental backup only copies the files that have changed since the last backup, not everything", "Because an incremental backup compresses every single file down to almost nothing before it starts copying them", "Because an incremental backup is always carried out while the computer is switched off, which makes it much quicker"], "answer": 1, "explain": "An incremental backup only copies what has changed since the last backup, so there is far less data to copy than a full backup."}}, {"myth": "Assuming defragmentation should be run regularly on every drive, including SSDs.", "truth": "Defragmentation helps a <strong>magnetic hard disk drive (HDD)</strong>, because it has a <strong>moving read/write head</strong> that benefits from files being together. A <strong>solid state drive (SSD)</strong> has <strong>no moving parts</strong>, so defragmenting it gives little benefit and can cause unnecessary wear.", "check": {"question": "Why is defragmentation not usually needed on a solid state drive (SSD)?", "options": ["Because a solid state drive is far too small to ever store enough files for it to become fragmented at all", "Because an SSD has no moving read/write head, so storing files together gives little speed benefit", "Because solid state drives are not able to run any kind of utility software of any sort whatsoever", "Because the files on a solid state drive are automatically encrypted, which stops them fragmenting"], "answer": 1, "explain": "Defragmentation speeds up drives with a moving head (HDDs); an SSD has no moving parts, so reorganising files gives little benefit."}}, {"myth": "Mixing up the system information utility with the diagnosis utility.", "truth": "A <strong>system information</strong> utility <strong>reports what the computer has</strong> — its processor, RAM, OS version, free storage. A <strong>diagnosis</strong> utility <strong>finds what is wrong</strong> — testing the system for faults and errors and reporting them. One describes the setup; the other troubleshoots problems.", "check": {"question": "Which utility would you use to find out what is causing a hardware fault on a computer?", "options": ["A system information utility, because it lists the processor and the amount of RAM the computer has fitted", "A diagnosis utility, because it tests the system for faults and errors and reports what is wrong", "A data compression utility, because it makes the faulty files small enough for the computer to cope with", "A backup utility, because it keeps a spare copy of the files while the hardware fault is being investigated"], "answer": 1, "explain": "A diagnosis utility tests for and reports faults. A system information utility only reports the specification, not what is wrong."}}]}, "tips": {"enabled": true, "items": [{"title": "The signature question: why files load faster after defragmentation", "html": "<p>This is the single most common question on the topic — usually <em>\"Explain why the computer can access files faster after defragmentation\"</em> [3 marks]. It wants the <strong>mechanism</strong>, as a chain:</p>\n<p><strong>❌ 1 mark:</strong> \"Because defragmentation makes the computer faster.\"</p>\n<ul><li>True but empty — it just repeats the question without explaining <em>why</em>.</li></ul>\n<p><strong>✅ 3 marks:</strong> \"Before defragmentation the file is <strong>fragmented</strong>, so its pieces are <strong>scattered</strong> across the disk <strong>(1)</strong>. Defragmentation reorganises the disk so all the pieces of the file are stored <strong>together (contiguously)</strong> <strong>(1)</strong>. This means the read/write head has to <strong>move less</strong> to read the whole file, so it is accessed faster <strong>(1)</strong>.\"</p>\n<p><strong>Key words examiners want:</strong> fragments <strong>scattered</strong> → stored <strong>together/contiguously</strong> → read/write head <strong>moves less</strong>. Don''t say defragmentation \"adds free space\" or \"speeds up the disk\" — that loses marks.</p>", "check": {"question": "In the ''why is access faster after defragmentation'' question, which point earns a mark?", "options": ["That defragmentation permanently increases the total amount of free storage space available on the hard disk", "That each file''s pieces are then stored together, so the read/write head has to move less to read the file", "That the hard disk is made to physically spin around at a noticeably higher speed than it did before", "That all rarely used files are deleted during defragmentation so there is less for the computer to search"], "answer": 1, "explain": "The mark is for the mechanism: pieces stored together means the read/write head moves less. ''Adds free space'' and ''spins faster'' are wrong."}}, {"title": "Full vs incremental — the ''justify your choice'' question", "html": "<p>Questions often give a scenario and ask which backup method to use, <strong>justifying your choice</strong>, or to explain why someone uses <strong>both</strong>. You get the marks for the <strong>trade-offs</strong>, not just the definitions:</p>\n<ul>\n<li><strong>Full backup</strong> — copies <strong>everything</strong>; complete and simple to restore, but <strong>slow</strong> and uses <strong>lots of storage</strong>.</li>\n<li><strong>Incremental backup</strong> — copies <strong>only what changed</strong>; <strong>fast</strong> and <strong>storage-light</strong>, but needs a full backup first and is more complex to restore (you need the full backup <strong>plus every increment</strong>).</li>\n</ul>\n<p><strong>Using both:</strong> an occasional full backup gives a complete base, and quick incremental backups in between keep it up to date without copying everything every time. Always <strong>link your reasons to the scenario</strong> (how often data changes, how much storage they have).</p>", "check": {"question": "Why might someone perform a full backup occasionally and incremental backups in between?", "options": ["Because incremental backups do not actually save any real data, so a full backup is always needed as a backup to them", "Because the full backup gives a complete base while the fast incremental backups keep it up to date with less storage", "Because a full backup can only ever be restored if an incremental backup of the very same data was made first", "Because incremental backups automatically delete the full backup once they have finished running each night"], "answer": 1, "explain": "A full backup provides a complete base; incremental backups then capture changes quickly using little storage — the reason to combine them."}}, {"title": "Sort utilities by purpose — and know the definition trap", "html": "<p>Two things get tested a lot here. First, <strong>classifying</strong> utilities (often a tick-grid):</p>\n<ul>\n<li><strong>Security</strong> → anti-malware, firewall, encryption.</li>\n<li><strong>Disk organisation / maintenance</strong> → defragmentation, data compression, file transfer.</li>\n</ul>\n<p>Second, the <strong>definition trap</strong>: \"State the need for utility software\" wants the <em>general purpose</em> — to <strong>maintain and optimise the computer</strong> (keep it secure, organised and running well) — <strong>not</strong> just naming one utility like \"defragmentation\". Name the role, then you can give an example.</p>\n<p>And remember: a utility is <strong>system software</strong>, never application software.</p>", "check": {"question": "A question asks you to ''state the need for utility software''. What kind of answer earns the mark?", "options": ["Simply naming one specific utility, such as ''defragmentation'', without saying anything at all about what it is for", "Saying that it is needed to maintain and optimise the computer, keeping it running well", "Explaining in detail exactly how the read/write head moves across the surface of a magnetic hard disk drive", "Listing the full technical specification of the computer, including its processor model and amount of RAM"], "answer": 1, "explain": "''The need'' means the general purpose — maintaining and optimising the computer. Just naming a single utility does not answer why utility software is needed."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick <strong>one</strong> box to identify the utility software that reorganises a disk so that each file''s pieces are stored together.</p>", "marks": 1, "hint": "Which utility is about tidying up how files are stored on the disk?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Defragmentation software</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box to identify the utility software that reduces the size of a file so it uses less storage.</p>", "marks": 1, "hint": "The clue is ''reduces the size'' — only one utility makes files smaller.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Data compression software</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box to identify which of these is a utility used for <strong>security</strong>.</p>", "marks": 1, "hint": "Which one protects data from being understood or attacked?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Encryption software</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>State the <strong>need</strong> for utility software on a computer.</p>", "marks": 2, "hint": "Say what utility software is FOR in general (its purpose for the computer) — not just the name of one utility.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: to maintain / look after (do housekeeping on) the computer</li>\n<li>1 mark: to keep it running efficiently / optimised / organised / secure</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Reward the general purpose. Simply naming a utility (e.g. \"defragmentation\") is not, by itself, a statement of the need.</li>\n</ul>\n</div>"}, {"question": "<p>State <strong>two</strong> utilities that can be used for <strong>security</strong>.</p>", "marks": 2, "hint": "Think about which utilities protect data or the system from attackers.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each, max 2)</h5>\n<ul>\n<li>Anti-malware / antivirus</li>\n<li>Firewall</li>\n<li>Encryption software</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award any two different valid security utilities. Disk-organisation utilities (defragmenter, compression) do not score.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to show whether each utility is used for <strong>security</strong> or for <strong>disk organisation</strong>.</p>", "marks": 4, "hint": "Security = protects against attackers (antivirus, firewall). Disk organisation = tidies or manages the storage (defragmenter, compression).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Antivirus → <strong>Used for security</strong></li>\n<li>Defragmenter → <strong>Used for disk organisation</strong></li>\n<li>Firewall → <strong>Used for security</strong></li>\n<li>Data compression → <strong>Used for disk organisation</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently; 2 ticks in a single row scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>The paragraph below describes some utility software.</p><p>Complete the paragraph by selecting terms from the list and writing them in the correct places. <strong>Not all terms are used.</strong></p>", "marks": 4, "hint": "Read each whole sentence before choosing. Several terms are deliberate decoys — if you use every word, something has gone wrong.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each completed term)</h5>\n<p>Utility software helps to <strong>maintain</strong> the computer. A defragmentation utility reorganises the disk so that each file''s pieces are stored <strong>together</strong>, which lets them be accessed more quickly. Compression software reduces the <strong>size</strong> of a file so it uses less storage. Encryption software scrambles data using a <strong>key</strong> so it cannot be understood if it is stolen.</p>\n</div>"}, {"question": "<p>After Arun runs a defragmentation utility, his laptop can open his files more quickly.</p><p>Explain why the files can be accessed faster after defragmentation.</p>", "marks": 3, "hint": "Trace the chain: what state the fragmented file was in, what defragmentation changes, and why that makes reading the file quicker.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark: the file was fragmented, with its pieces scattered across the disk</li>\n<li>1 mark: defragmentation reorganises the disk so the pieces are stored together (contiguously)</li>\n<li>1 mark: the read/write head then moves less to read the whole file, so access is faster</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not credit \"adds free space\" or \"makes the disk spin faster\" — these are incorrect.</li>\n</ul>\n</div>"}, {"question": "<p>Explain how the hard disk in Arun''s laptop is likely to have become fragmented over the years.</p>", "marks": 3, "hint": "Think about what happens on the disk as files are saved, edited and deleted repeatedly.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark: editing and deleting files leaves gaps of free space across the disk</li>\n<li>1 mark: new/larger files are split into pieces to fit into the available gaps</li>\n<li>1 mark: over time files'' pieces (and the free space) become scattered across the disk</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Reward a clear account of files being split to fit scattered gaps.</li>\n</ul>\n</div>"}, {"question": "<p>Explain why compressing large files before uploading them to the internet is useful.</p>", "marks": 3, "hint": "Say what compression does to the file, then link that to two benefits when uploading.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark: compression reduces the size of the file</li>\n<li>1 mark: less data to transfer, so uploading is faster</li>\n<li>1 mark: uses less storage/bandwidth (or allows more to be sent)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Reward the size reduction AND at least one clear benefit for uploading.</li>\n</ul>\n</div>"}, {"question": "<p>Delta Design''s files change often during a project. Explain the reasons why the studio performs both <strong>full</strong> and <strong>incremental</strong> backups.</p>", "marks": 3, "hint": "Say what each type copies, then explain the benefit of combining them for files that change often.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark: the full backup copies every file/all data (a complete base)</li>\n<li>1 mark: the incremental backup copies only files changed since the last backup</li>\n<li>1 mark: the incremental backups are faster and use less storage, suiting frequently changing files</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Reward the contrast plus the benefit of combining them for this scenario.</li>\n</ul>\n</div>"}, {"question": "<p>Delta Design only has time to make one type of backup at the end of each busy working day, and its files change a lot during the day.</p><p>Identify the backup method the studio should use for this daily backup, and justify your choice.</p>", "marks": 4, "hint": "Choose full or incremental, then justify it using the daily time limit and how much the files change — link the trade-offs to the scenario.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 identify + up to 3 justify)</h5>\n<ul>\n<li>1 mark: identifies incremental backup (accept full with a valid justification)</li>\n<li>1 mark: it only copies the files changed that day</li>\n<li>1 mark: so it is quick, fitting the limited time at the end of the day</li>\n<li>1 mark: it uses less storage each day / a daily full backup would be too slow and storage-heavy</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The justification must be linked to the scenario (limited daily time, files changing a lot). A prior full backup is assumed to exist.</li>\n</ul>\n</div>"}, {"question": "<p>A new laptop comes with a <strong>system information</strong> utility and a <strong>diagnosis</strong> utility.</p><p>Describe, using examples, the purpose of each of these two utilities.</p>", "marks": 4, "hint": "For each: say what it is for, and give an example of what it would show or do.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (2 per utility: purpose + example)</h5>\n<ul>\n<li>System information — reports details about the computer; example: processor, RAM, OS version, free storage</li>\n<li>Diagnosis — finds/detects faults and errors; example: testing hardware or reporting a problem to be fixed</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each utility scores 1 for its purpose and 1 for a relevant example.</li>\n</ul>\n</div>"}, {"question": "<p>Explain how encryption software helps to keep a user''s data secure.</p>", "marks": 3, "hint": "Say what encryption does to the data, what is needed to reverse it, and why that keeps the data safe if it is stolen.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark: encryption scrambles the data using a key</li>\n<li>1 mark: only someone with the correct key can decrypt it</li>\n<li>1 mark: if stolen/intercepted, the data is meaningless without the key</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Reward the idea of scrambling with a key AND that stolen data is unreadable without it.</li>\n</ul>\n</div>"}, {"question": "<p>Delta Design wants to keep its data <strong>safe</strong>, keep its storage <strong>tidy and efficient</strong>, and be able to <strong>send files to clients quickly</strong>.</p><p>Explain how <strong>three</strong> different types of utility software could help Delta Design meet these needs. Describe a different utility each time.</p>", "marks": 6, "hint": "Choose three different utilities (for example backup, defragmentation and compression). For each: name it, say what it does, and link it to one of the studio''s needs.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks (up to 2 for each of three different utilities)</h5>\n<p>For EACH of three different utilities:</p>\n<ul>\n<li>1 mark: the utility is named and correctly described</li>\n<li>1 mark: it is linked to one of Delta Design''s needs</li>\n</ul>\n<p>Examples of acceptable utilities and links:</p>\n<ul>\n<li>Backup software — keeps a spare copy so the important, often-changing data is safe from loss (keep data safe)</li>\n<li>Encryption software — scrambles the client data so it is secure if stolen (keep data safe)</li>\n<li>Defragmentation — reorganises the HDD so files are stored together and load faster (tidy, efficient storage)</li>\n<li>Data compression — reduces file size so large images/videos send to clients quickly (send files quickly)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each of three DIFFERENT utilities can score up to 2 (description + link to a need). Repeating a utility does not earn the repeated marks.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', '{"learn": {"enabled": true, "items": [{"title": "What we mean by the ''impacts'' of digital technology", "html": "<h4>Every technology brings good and bad</h4>\n<ul>\n<li>Digital technology changes the way we live, work and communicate. Almost every change brings <strong>benefits (positive impacts)</strong> AND <strong>problems (negative impacts)</strong> — often at the same time.</li>\n<li>The specification groups these impacts into five areas: <strong>ethical</strong>, <strong>legal</strong>, <strong>cultural</strong>, <strong>environmental</strong> and <strong>privacy</strong>. This page covers the ethical, cultural, environmental and privacy impacts; the <strong>laws</strong> (legal side) are covered in <strong>1.6.1b Legislation</strong>.</li>\n<li>The exam skill is to <strong>weigh up</strong> these impacts — to <strong>discuss</strong> both sides and reach a balanced, justified view, rather than just listing good points or bad points.</li>\n</ul>", "check": {"question": "What does it mean to consider the ''impacts'' of a piece of digital technology?", "options": ["Working out only the good things about it so that a business can advertise the product to as many people as possible", "Weighing up both its positive and negative effects on different people, society and the environment", "Measuring exactly how fast the technology runs compared with the older technology that it is replacing", "Deciding whether the technology is legal to sell in the country where it was originally manufactured"], "answer": 1, "explain": "Considering impacts means weighing the positive AND negative effects on people, society and the environment — not just the benefits."}}, {"title": "Stakeholders — who is affected?", "html": "<h4>Different groups feel different impacts</h4>\n<ul>\n<li>A <strong>stakeholder</strong> is any person or group <strong>affected by</strong> a technology or a decision about it.</li>\n<li>Typical stakeholders include: <strong>individuals</strong> (users, customers, employees), <strong>businesses/organisations</strong>, wider <strong>society</strong>, and the <strong>environment</strong>.</li>\n<li>The same change can be <strong>good for one stakeholder and bad for another</strong>. For example, a company releasing a new phone every year <strong>increases its profits</strong> (good for the business) but <strong>adds to e-waste</strong> (bad for the environment) and <strong>costs customers more</strong>.</li>\n<li>Strong exam answers deliberately consider <strong>more than one stakeholder</strong>.</li>\n</ul>", "check": {"question": "Why is it useful to think about different stakeholders when discussing a technology''s impact?", "options": ["Because only the company that makes the technology is ever really affected by the decisions that are made about it", "Because the same change can be positive for one group and negative for another, giving a balanced view", "Because stakeholders are the engineers who physically build the technology inside the factory each day", "Because it lets you ignore the environmental effects and focus only on how much money is being made"], "answer": 1, "explain": "Different stakeholders experience different impacts — a change good for a business can be bad for customers or the environment, which gives a balanced discussion."}}, {"title": "Ethical impacts", "html": "<h4>Is it the right thing to do?</h4>\n<ul>\n<li><strong>Ethical</strong> impacts are about what is <strong>right or wrong, fair or unfair</strong> — the moral side of a decision. Something can be <strong>legal but still unethical</strong>.</li>\n<li>Examples of ethical questions raised by digital technology: Is it fair for <strong>AI to replace people''s jobs</strong>? Is it right for companies to <strong>track users</strong> to sell them things? Is it fair that <strong>only some people can afford</strong> the latest technology? Should devices be designed to <strong>stop working</strong> so people buy new ones?</li>\n<li>There is often <strong>no single correct answer</strong> — the exam wants you to see both sides of the ethical argument.</li>\n</ul>", "check": {"question": "What makes an issue an ''ethical'' issue rather than simply a legal one?", "options": ["An ethical issue is only ever about whether a company can make a large enough profit from selling the technology", "An ethical issue is about whether something is right, fair or moral — even if it happens to be perfectly legal", "An ethical issue is always automatically illegal, which is exactly what makes it an ethical problem in the first place", "An ethical issue only affects the environment, whereas a legal issue only ever affects individual people"], "answer": 1, "explain": "Ethics is about right/wrong and fairness. Something can be legal yet still raise an ethical concern — the two are not the same."}}, {"title": "Cultural impacts", "html": "<h4>How technology changes the way groups of people live</h4>\n<ul>\n<li><strong>Cultural</strong> impacts are the effects on <strong>how groups of people live, work and interact</strong> — on society as a whole.</li>\n<li>Positive examples: people can <strong>stay connected</strong> across the world, work <strong>from home</strong>, access <strong>information and education</strong> online, and form <strong>online communities</strong>.</li>\n<li>Negative examples: <strong>jobs lost</strong> to automation, less <strong>face-to-face</strong> contact, the spread of <strong>misinformation</strong>, pressure from <strong>social media</strong>, and the <strong>digital divide</strong> (covered next).</li>\n</ul>", "check": {"question": "Which of these is a cultural impact of digital technology?", "options": ["The exact amount of electrical energy that a large data centre uses to keep all of its servers running each year", "The way social media has changed how people communicate, work and form communities across society", "The specific programming language that a software developer chooses to write a brand new application in", "The number of transistors that engineers are able to fit onto a single modern processor chip nowadays"], "answer": 1, "explain": "Cultural impacts are about how technology changes the way groups of people live and interact — such as social media changing communication. Energy use is environmental."}}, {"title": "The digital divide", "html": "<h4>Not everyone has the same access</h4>\n<ul>\n<li>The <strong>digital divide</strong> is the <strong>gap between people who have good access</strong> to digital technology and the internet, and those who <strong>do not</strong>.</li>\n<li>Causes include <strong>cost</strong> (not everyone can afford devices or broadband), <strong>location</strong> (some areas have poor or no internet), and <strong>skills/age</strong> (some people lack the confidence or training to use it).</li>\n<li>It matters because so many services — <strong>banking, job applications, school work, government services</strong> — are now online. People on the wrong side of the divide can be <strong>left behind</strong>, which is both a cultural and an ethical concern.</li>\n</ul>", "check": {"question": "What is the digital divide?", "options": ["The physical distance between two computers that are trying to communicate with each other over a large network", "The gap between people who have good access to digital technology and the internet and those who do not", "The difference in processing speed between an expensive new computer and a much cheaper older one", "The point at which a hard disk becomes so fragmented that files can no longer be opened by the computer"], "answer": 1, "explain": "The digital divide is the gap in access to digital technology and the internet, caused by factors such as cost, location and skills."}}, {"title": "Environmental impacts — the problems", "html": "<h4>Making, powering and throwing away devices</h4>\n<ul>\n<li><strong>Manufacturing</strong> devices uses <strong>raw materials</strong> (including scarce metals) and lots of <strong>energy</strong>, and can cause <strong>pollution</strong>.</li>\n<li><strong>Running</strong> devices, and especially large <strong>data centres</strong>, uses a great deal of <strong>electricity</strong>, much of which still comes from fossil fuels — adding to the <strong>carbon footprint</strong>.</li>\n<li><strong>Disposal</strong> creates <strong>e-waste</strong>: discarded electronics that often contain <strong>toxic materials</strong> and end up in landfill if not recycled.</li>\n</ul>", "check": {"question": "Which of these is a negative environmental impact of digital technology?", "options": ["People are able to work from home and hold video meetings instead of driving to a distant office each day", "Discarded electronic devices create e-waste that can contain toxic materials and end up in landfill", "Online shops let customers compare the prices of many different products before deciding what to buy", "Cloud storage means a user can open their files from almost any device with an internet connection"], "answer": 1, "explain": "E-waste from discarded devices is a negative environmental impact. Working from home is actually a positive environmental impact (less travel)."}}, {"title": "Environmental impacts — e-waste and ''throwaway'' culture", "html": "<h4>Frequent upgrades make the problem worse</h4>\n<ul>\n<li>When companies release <strong>new devices very often</strong> (for example a new phone every year), people replace working devices more frequently, so <strong>more are thrown away</strong> — increasing e-waste.</li>\n<li>This is worsened if devices are hard to repair or are designed to have a <strong>short life</strong> (sometimes called planned obsolescence) — an <strong>ethical</strong> concern as well as an environmental one.</li>\n<li><strong>Ways to reduce the harm:</strong> <strong>recycle</strong> old devices for their components/materials, <strong>donate or redistribute</strong> working devices to people who need them, design products to be <strong>repairable</strong>, and choose <strong>digital downloads</strong> over physical discs (fewer materials, smaller carbon footprint from distribution).</li>\n</ul>", "check": {"question": "How does releasing a new version of a device every year tend to affect the environment?", "options": ["It has no environmental effect at all, because the old devices simply disappear on their own over time", "It increases e-waste, because people replace working devices more often, so more are thrown away", "It reduces e-waste, because manufacturers always collect and fully recycle every single old device by law", "It only affects the environment if the new device is physically larger than the one it is replacing"], "answer": 1, "explain": "Frequent new releases lead people to replace working devices more often, so more are discarded — increasing e-waste."}}, {"title": "Environmental impacts — the positives", "html": "<h4>Technology can also help the planet</h4>\n<ul>\n<li>Not all environmental impacts are negative. Digital technology also <strong>reduces</strong> some environmental harm:</li>\n<li><strong>Less travel:</strong> video calls and remote working mean fewer journeys, lowering emissions.</li>\n<li><strong>Less paper:</strong> digital documents, email and online forms reduce paper use and printing.</li>\n<li><strong>Digital distribution:</strong> downloading software, music and films means <strong>fewer discs manufactured</strong>, less packaging, and a <strong>smaller carbon footprint</strong> than shipping physical copies.</li>\n<li>A good discussion mentions <strong>both</strong> the harm and these benefits.</li>\n</ul>", "check": {"question": "Which of these is a positive environmental impact of digital technology?", "options": ["The very large amount of electricity that data centres need in order to keep their many servers running all day long", "Distributing software as downloads instead of on discs, which means fewer discs and less packaging are made", "The toxic materials that can leak out of discarded electronic devices when they are left in landfill sites", "The scarce metals and raw materials that have to be mined in order to manufacture brand new devices"], "answer": 1, "explain": "Digital downloads mean fewer discs and less packaging are manufactured, a positive environmental impact. The other options are all negative impacts."}}, {"title": "Privacy impacts", "html": "<h4>Technology knows a lot about us</h4>\n<ul>\n<li>Digital technology <strong>collects and stores personal data</strong> — what we search, buy, watch and where we go (location).</li>\n<li>This brings <strong>convenience</strong> (personalised recommendations, targeted services), but raises <strong>privacy</strong> concerns: who can see this data, how securely is it stored, and could it be used to <strong>track or profile</strong> us without our knowledge?</li>\n<li>Concerns include <strong>surveillance</strong>, data being <strong>shared or sold</strong>, and large <strong>data breaches</strong>. This is why the law (the <strong>Data Protection Act</strong>, covered in 1.6.1b) exists to control how personal data is handled.</li>\n</ul>", "check": {"question": "Why does collecting large amounts of personal data raise privacy concerns?", "options": ["Because personal data always makes a computer run much more slowly than it otherwise would have done", "Because the data could be used to track or profile people, or be shared, sold or exposed in a breach", "Because collecting personal data is the only way that a website is ever able to load its pages correctly", "Because personal data takes up so much storage space that there is no room left for anything else at all"], "answer": 1, "explain": "Stored personal data can be used to track or profile people, and could be shared, sold or exposed in a breach — the core privacy concern."}}, {"title": "The ''Discuss'' 8-mark question", "html": "<h4>The most important skill on this topic</h4>\n<ul>\n<li>This topic is the home of the <strong>8-mark \"Discuss\"</strong> question. It always gives a scenario and usually a bullet list of things to <strong>include</strong>.</li>\n<li>It is <strong>levelled (banded)</strong>, so marks reward a <strong>balanced, developed argument</strong>, not a list. To reach the top band you should:</li>\n<li><strong>1.</strong> Cover <strong>positive AND negative</strong> impacts.</li>\n<li><strong>2.</strong> Consider <strong>more than one stakeholder</strong> (e.g. the company AND its customers AND the environment).</li>\n<li><strong>3.</strong> <strong>Apply</strong> each point to the specific scenario, following it through to a consequence.</li>\n<li><strong>4.</strong> Reach a <strong>justified conclusion</strong> — an overall view with a reason.</li>\n</ul>", "check": {"question": "What most separates a top-band answer on an 8-mark ''Discuss the impact'' question from a weaker one?", "options": ["Writing down as many separate points as you possibly can, all on the positive side, without spending any time on the drawbacks", "Giving a balanced argument with positives and negatives, more than one stakeholder, and a justified conclusion", "Using the longest and most complicated technical words that the student can possibly think of throughout", "Writing the entire answer as a single long bullet-point list with no full sentences used anywhere in it"], "answer": 1, "explain": "Top-band ''Discuss'' answers are balanced (both sides), consider more than one stakeholder, apply to the scenario, and reach a justified conclusion."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Impact of technology", "definition": "A positive or negative effect on people, society or the environment"}, {"term": "Stakeholder", "definition": "Any person or group affected by a technology or a decision about it"}, {"term": "Ethical impact", "definition": "About what is right, fair or moral — even if it is legal"}, {"term": "Legal impact", "definition": "About whether something is lawful (see 1.6.1b for the specific laws)"}, {"term": "Cultural impact", "definition": "Effects on how groups of people live, work and interact"}, {"term": "Environmental impact", "definition": "Effects on the planet: energy, raw materials, e-waste"}, {"term": "Privacy impact", "definition": "Concerns about personal data being collected, tracked, shared or exposed"}, {"term": "Digital divide", "definition": "The gap between those with good access to technology and those without"}, {"term": "E-waste", "definition": "Discarded electronic devices, which can contain toxic materials"}, {"term": "Planned obsolescence", "definition": "Designing a product to have a short life so it is replaced sooner"}, {"term": "Carbon footprint", "definition": "The greenhouse gas produced by an activity, e.g. powering devices"}, {"term": "Digital distribution", "definition": "Delivering software/media as downloads rather than on physical discs"}, {"term": "Surveillance", "definition": "Monitoring people''s activity or location, often through their data"}, {"term": "Automation", "definition": "Using technology to do work previously done by people (can cost jobs)"}, {"term": "Discuss (command word)", "definition": "Weigh positives and negatives from several viewpoints and give a justified view"}, {"term": "Justified conclusion", "definition": "An overall view supported by a clear reason, needed for the top band"}]}, "mcq": {"enabled": true, "questions": [{"question": "A company designs its phones so that the battery cannot be replaced and stops holding charge after two years. What kind of impact does this MOST raise?", "options": ["Only a purely technical impact, because it is simply a normal design choice about the battery inside the phone", "An ethical and environmental impact, because it pushes people to replace working phones, adding to e-waste", "No real impact at all, since customers can always just buy a completely different phone from another company", "Only a cultural impact, because it changes the specific way that people talk to each other using their phones"], "answer": 1, "explain": "Designing devices to fail sooner is an ethical concern (is it fair?) and an environmental one (more e-waste) — it pushes people to replace working phones."}, {"question": "Which of the following is the best example of a privacy impact of digital technology?", "options": ["A shopping website builds a detailed profile of a user by tracking everything they view, buy and search for", "A shopping website is temporarily unavailable because too many customers are trying to use it at once", "A shopping website loads its product pages more slowly on an older phone than it does on a brand new one", "A shopping website offers its products in several different languages so more customers around the world can use it"], "answer": 0, "explain": "Building a profile by tracking a user''s activity is a privacy impact. The others are about availability, performance and accessibility."}, {"question": "Which is a positive cultural impact of digital technology?", "options": ["Electronic devices that are thrown away add to the growing global problem of dangerous electronic waste", "People can work together and stay in contact with others all over the world without having to travel", "Manufacturing new devices uses up scarce raw materials that have to be mined out of the ground first", "Companies can track exactly what their customers are doing online in order to sell them more products"], "answer": 1, "explain": "Being able to connect and collaborate worldwide is a positive cultural impact. The others are environmental or privacy concerns."}, {"question": "A rural village finally gets a fast internet connection for the first time. Which stakeholder benefit is most directly a cultural one?", "options": ["The internet company that installed the connection is now able to make a larger profit from the village", "Villagers can now access online education, jobs and services that they were previously shut out from", "The copper and fibre cables that were laid down will slowly wear out and need replacing in the future", "The new equipment installed in the village will use some electrical energy while it is switched on and running"], "answer": 1, "explain": "Gaining access to online education, jobs and services changes how the community lives — a cultural impact (and it reduces the digital divide)."}, {"question": "Which of these actions would most help REDUCE the environmental impact of digital technology?", "options": ["Releasing a brand new model of a device every few months so that customers always have the very latest one", "Recycling old devices for their materials and donating working ones to people who need them", "Designing devices so that they cannot be repaired and have to be completely replaced when anything breaks", "Encouraging every customer to buy several backup devices in case their main device ever stops working one day"], "answer": 1, "explain": "Recycling and donating devices reduces e-waste and the need to manufacture new ones — reducing environmental impact."}, {"question": "What does ''e-waste'' refer to?", "options": ["Emails and other electronic messages that a person receives but then chooses to delete without ever reading them", "Discarded electronic devices, which can contain toxic materials and often end up in landfill", "Electrical energy that is wasted when a computer is accidentally left switched on overnight by its owner", "Errors in a program''s code that stop it from running correctly until they are found and fixed by a developer"], "answer": 1, "explain": "E-waste is discarded electronic equipment, which can contain harmful materials and cause environmental damage if not recycled."}, {"question": "Why can something be legal but still raise an ethical concern?", "options": ["Because ethics is about what is right or fair, which is not always the same as what the law happens to allow", "Because anything that is legal is automatically also ethical, so the two ideas can never disagree with each other", "Because ethical concerns only ever apply to technology that has not yet been invented or released to the public", "Because the law changes so often that nothing can really be considered either legal or ethical for very long"], "answer": 0, "explain": "Legality and ethics are different: a practice can follow the law yet still be seen as unfair or morally questionable."}, {"question": "A social media company uses AI to decide which posts each user sees. Which pair of impacts does this MOST clearly involve?", "options": ["Only the physical size of the data centre and the total length of the network cables running into it", "Ethical impacts (fairness, influence over users) and privacy impacts (how much user data is collected)", "Only the exact programming language and the specific operating system used to build the AI system itself", "Only the clock speed of the processors and the amount of RAM installed in each of the company''s servers"], "answer": 1, "explain": "AI choosing what users see raises ethical questions (fairness, influence) and privacy questions (the data used to make those choices)."}, {"question": "Which statement about the impacts of a new technology is the most balanced?", "options": ["Streaming films online is completely good because it is convenient and no discs ever need to be produced", "Streaming films online saves discs and packaging, but the data centres that power it still use a lot of energy", "Streaming films online is completely bad, simply because the data centres that make it all possible use up electrical energy", "Streaming films online has absolutely no positive or negative impact of any kind on anybody, anywhere, at all"], "answer": 1, "explain": "A balanced view recognises both a benefit (fewer discs/packaging) and a drawback (energy use) — the skill the Discuss question rewards."}, {"question": "Which of these best describes a stakeholder?", "options": ["The single member of staff who physically assembles a device on the production line inside the factory", "Any person or group who is affected by a technology or by a decision that is made about it", "Only the customer who finally buys the finished technology from a shop or from an online store", "The piece of software that is used to control and monitor the machines in an automated factory"], "answer": 1, "explain": "A stakeholder is anyone affected by the technology or decision — individuals, businesses, society or the environment."}, {"question": "A company moves from selling software on physical discs to selling it only as downloads. Which is a genuine ENVIRONMENTAL benefit of this?", "options": ["The company can now charge each of its customers a much higher price for exactly the same piece of software", "Fewer discs and less packaging need to be manufactured and shipped, lowering the carbon footprint", "Customers are now completely unable to ever share a copy of the software with any of their friends at all", "The download will always install far more quickly than the software would have done from a physical disc"], "answer": 1, "explain": "Digital distribution means fewer discs and less packaging are made and shipped, reducing the carbon footprint — an environmental benefit."}, {"question": "In an 8-mark ''Discuss'' question about a company releasing frequent new devices, which point best considers a DIFFERENT stakeholder from the company itself?", "options": ["The company can increase its sales and profits each time it brings out an exciting new model of the device", "Customers face higher costs, and the environment suffers from the extra e-waste that the old devices create", "The company can advertise the new features of the device to build up excitement before it is finally released", "The company might see its reputation improve because it is always seen to have the very newest technology"], "answer": 1, "explain": "Customers and the environment are stakeholders separate from the company — considering them gives the balance a top-band answer needs."}]}, "fib": {"enabled": true, "questions": [{"text": "A [stakeholder] is any person or group affected by a technology or a decision made about it."}, {"text": "[ethical] impacts are about what is right, fair or moral, even when something is perfectly legal."}, {"text": "[cultural] impacts are the effects of technology on how groups of people live, work and interact."}, {"text": "The digital [divide] is the gap between people who have good access to digital technology and those who do not."}, {"text": "Discarded electronic devices that can contain toxic materials are known as [e-waste]."}, {"text": "Using video calls instead of travelling to meetings is a [positive] environmental impact of digital technology."}, {"text": "Collecting and tracking users'' personal data raises [privacy] concerns about who can see and use that data."}, {"text": "An 8-mark [discuss] question asks you to weigh up positive and negative impacts and reach a justified conclusion."}]}, "tf": {"enabled": true, "questions": [{"statement": "Something can be legal but still be considered unethical.", "answer": true, "explain": "Correct — ethics is about what is right or fair, which is not always the same as what the law allows."}, {"statement": "The digital divide describes the physical distance between two networked computers.", "answer": false, "explain": "The digital divide is the gap between people who have good access to digital technology and those who do not — not a physical distance."}, {"statement": "E-waste is a negative environmental impact of digital technology.", "answer": true, "explain": "Correct — discarded electronics can contain toxic materials and add to landfill, a clear negative environmental impact."}, {"statement": "Digital technology only ever has negative impacts on the environment.", "answer": false, "explain": "It has positives too, such as less travel from video calls and fewer discs/packaging from digital downloads."}, {"statement": "A good ''Discuss'' answer only lists the positive impacts of a technology.", "answer": false, "explain": "A top-band ''Discuss'' answer is balanced — it weighs positives AND negatives and reaches a justified conclusion."}, {"statement": "Releasing new devices very frequently tends to increase e-waste.", "answer": true, "explain": "Correct — people replace working devices more often, so more are thrown away, increasing e-waste."}, {"statement": "Considering more than one stakeholder helps make a discussion of impacts more balanced.", "answer": true, "explain": "Correct — a change can be good for one group and bad for another, so covering several stakeholders gives balance."}, {"statement": "Tracking a user''s browsing to build a profile of them is a privacy impact.", "answer": true, "explain": "Correct — collecting and profiling personal data is a privacy concern about who can see and use that data."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking a ''Discuss'' answer should just list as many good points (or as many bad points) as possible.", "truth": "A <strong>Discuss</strong> question is <strong>levelled</strong> and rewards a <strong>balanced argument</strong>: cover <strong>positive AND negative</strong> impacts, consider <strong>more than one stakeholder</strong>, apply each point to the <strong>scenario</strong>, and finish with a <strong>justified conclusion</strong>. A one-sided list stays in the lower bands.", "check": {"question": "What should a top-band answer to a ''Discuss the impacts'' question always include?", "options": ["A long one-sided list of only the advantages, because that is what shows the examiner the most knowledge", "Both positive and negative impacts, more than one stakeholder, and a justified overall conclusion", "The full technical specification of every device that is mentioned anywhere in the question scenario", "A promise that the technology will definitely never cause any problems for anybody at any time in the future"], "answer": 1, "explain": "Balance is the key: both sides, more than one stakeholder, applied to the scenario, with a justified conclusion."}}, {"myth": "Believing that if something is legal, there is nothing left to discuss ethically.", "truth": "Legal and ethical are <strong>different</strong>. A company can act <strong>within the law</strong> and still do something many people think is <strong>unfair or wrong</strong> — for example designing devices to fail sooner, or tracking users to sell their data. Ethics asks ''is it <strong>right</strong>?'', not just ''is it <strong>allowed</strong>?''.", "check": {"question": "A company tracks its users within the law but many people feel it is unfair. What does this show?", "options": ["That there can be no problem at all, because the company has not actually broken any law by doing this", "That something can be legal yet still raise an ethical concern about whether it is fair or right", "That the company must have broken the law, because tracking users is always completely illegal everywhere", "That ethics and the law are exactly the same thing, so if it is legal it must automatically also be ethical"], "answer": 1, "explain": "Acting within the law does not settle the ethics — a legal practice can still be seen as unfair, which is an ethical concern."}}, {"myth": "Assuming digital technology is only ever bad for the environment.", "truth": "There are real <strong>negatives</strong> (manufacturing, energy use, e-waste) but also real <strong>positives</strong>: <strong>less travel</strong> (video calls), <strong>less paper</strong>, and <strong>digital distribution</strong> meaning fewer discs and less packaging. A balanced answer gives <strong>both</strong> sides.", "check": {"question": "Which is a genuine positive environmental impact of digital technology?", "options": ["The rare metals and all of the other raw materials that must be mined out from deep underground in order to build brand new devices", "Working and holding meetings from home over video calls, which reduces the need to travel and cuts emissions", "The dangerous toxic substances that can escape from electronic devices left to rot in a landfill site", "The large amount of electricity that busy data centres consume in order to stay running around the clock"], "answer": 1, "explain": "Remote working via video calls reduces travel and emissions — a genuine positive. The others are all negative environmental impacts."}}, {"myth": "Confusing cultural impacts with environmental impacts.", "truth": "<strong>Cultural</strong> impacts are about <strong>people and society</strong> — how we live, work, communicate and who has access (the digital divide). <strong>Environmental</strong> impacts are about the <strong>planet</strong> — energy, raw materials and e-waste. Ask: is this point about <strong>people</strong> or about the <strong>environment</strong>?", "check": {"question": "Which of these is a cultural impact rather than an environmental one?", "options": ["The amount of electricity used by the millions of servers running inside the world''s largest data centres", "The way that social media has changed how people communicate and form communities across society", "The e-waste created when people throw away their old and unwanted electronic devices such as phones", "The scarce raw materials that must be mined out of the ground in order to manufacture new devices"], "answer": 1, "explain": "Social media changing how people communicate is a cultural (people/society) impact; the others are all environmental (planet) impacts."}}, {"myth": "Thinking the digital divide is only about who owns the newest, most expensive gadgets.", "truth": "The digital divide is about <strong>access</strong> to digital technology and the internet, driven by <strong>cost, location and skills</strong>. It matters because essential services — <strong>banking, jobs, education, government</strong> — are online, so people without access are genuinely <strong>left behind</strong>, not just missing out on gadgets.", "check": {"question": "Why does the digital divide matter so much today?", "options": ["Because people without the latest gadgets are unable to play the newest and most demanding video games", "Because so many essential services are now online, so people without access can be left behind", "Because the newest devices are always noticeably faster than the older ones that some people still use", "Because it decides which country will manufacture the largest number of new devices in the coming year"], "answer": 1, "explain": "Essential services (banking, jobs, education, government) are online, so lacking access has serious real-world consequences — not just missing new gadgets."}}]}, "tips": {"enabled": true, "items": [{"title": "How to structure the 8-mark ''Discuss'' answer", "html": "<p>Almost every 8-marker on this topic is a <strong>Discuss</strong> question with a scenario and a bullet list of things to <strong>include</strong>. Use the bullets as your plan and follow this structure:</p>\n<ul>\n<li><strong>Both sides:</strong> give <strong>positive</strong> impacts and <strong>negative</strong> impacts — never one-sided.</li>\n<li><strong>More than one stakeholder:</strong> e.g. the company, its customers, wider society, the environment. This is the fastest way to add balance.</li>\n<li><strong>Apply + develop:</strong> take each point back to the specific scenario and follow it through to a consequence (point → because → so…).</li>\n<li><strong>Justified conclusion:</strong> end with an overall view and a reason (\"On balance… because…\").</li>\n</ul>\n<p><strong>Band 3 (6–8):</strong> balanced, developed, applied to the scenario, justified conclusion. <strong>Band 2 (3–5):</strong> some points but one-sided or generic. <strong>Band 1 (1–2):</strong> a few simple, unexplained statements.</p>", "check": {"question": "A student''s 8-mark ''Discuss'' answer only gives negative impacts, all about the company. What two things would most improve it?", "options": ["Making the sentences much longer, and repeating each of the negative points a second time in different words", "Adding some positive impacts as well, and considering other stakeholders such as customers or the environment", "Removing the conclusion entirely, and listing the negative points as single words rather than in full sentences", "Adding the full technical specification of the company''s product and the date it was first released to the public"], "answer": 1, "explain": "Balance is what lifts the band: add positives as well as negatives, and bring in other stakeholders beyond the company."}}, {"title": "Sort every point: ethical, cultural, environmental or privacy?", "html": "<p>Questions sometimes ask specifically for, say, the <strong>environmental</strong> impacts. Don''t drift into the wrong area. A quick test for each point:</p>\n<ul>\n<li><strong>Ethical</strong> — is it about right/wrong or fairness? (\"Is it fair to…\")</li>\n<li><strong>Cultural</strong> — is it about how people live, work or communicate? (jobs, the digital divide, social media)</li>\n<li><strong>Environmental</strong> — is it about the planet? (energy, raw materials, e-waste)</li>\n<li><strong>Privacy</strong> — is it about personal data being collected, tracked or shared?</li>\n</ul>\n<p>If a question says \"environmental\", write about energy, materials and e-waste — not about jobs or fairness, which are cultural and ethical.</p>", "check": {"question": "A question asks only for the ENVIRONMENTAL impacts of a decision. Which point should you include?", "options": ["The fact that some workers might lose their jobs if the company decides to automate part of its factory", "The increase in e-waste and the energy used to manufacture and run the new devices being produced", "The worry that the company could unfairly track its customers in order to sell them even more products", "The way that the new technology might change how people in a community communicate with one another"], "answer": 1, "explain": "Environmental impacts are about the planet — e-waste and energy use. Jobs are cultural, tracking is privacy, fairness is ethical."}}, {"title": "Learn the stakeholder trick for instant balance", "html": "<p>The quickest way to make a discussion balanced is to run through the <strong>stakeholders</strong> and ask how the decision affects each one:</p>\n<ul>\n<li><strong>The company/organisation</strong> — profit, sales, reputation, costs.</li>\n<li><strong>Customers/individuals</strong> — cost, convenience, choice, privacy.</li>\n<li><strong>Society</strong> — jobs, the digital divide, how people live.</li>\n<li><strong>The environment</strong> — energy, materials, e-waste.</li>\n</ul>\n<p>Even naming <strong>two or three</strong> of these and giving one impact for each turns a one-sided answer into a balanced one — exactly what the top band needs.</p>", "check": {"question": "How does thinking about stakeholders quickly make a discussion more balanced?", "options": ["It lets you focus entirely on the company, which is the only stakeholder that the examiner is interested in", "A decision often helps one stakeholder while harming another, so covering several naturally gives both sides", "It means you never have to mention any negative impacts, because stakeholders only ever gain from technology", "It replaces the need for a conclusion, since simply naming the stakeholders is enough to reach the top band"], "answer": 1, "explain": "Different stakeholders gain or lose differently, so running through them naturally surfaces both positive and negative impacts."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>State <strong>two</strong> different types of impact that digital technology can have on people or the world around them.</p>", "marks": 2, "hint": "Think of the impact areas: ethical, cultural, environmental, privacy (or legal).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark each, max 2)</h5>\n<ul>\n<li>Ethical</li><li>Legal</li><li>Cultural</li><li>Environmental</li><li>Privacy</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award any two different valid impact types.</li>\n</ul>\n</div>"}, {"question": "<p>Describe the <strong>environmental</strong> impacts of NovaPhone bringing out a new phone every year.</p>", "marks": 3, "hint": "Focus only on the environment (energy, materials, e-waste). Give more than one distinct point.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>Increase in e-waste as working phones are thrown away to upgrade</li>\n<li>More raw materials and energy used to manufacture the extra devices</li>\n<li>Old devices could be recycled for components or donated to reduce waste (mitigation)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Reward distinct environmental points. Do not credit non-environmental points (e.g. cost to customers) here.</li>\n</ul>\n</div>"}, {"question": "<p>A town installs free public Wi-Fi in all its parks and libraries.</p><p>Describe <strong>one positive</strong> and <strong>one negative</strong> impact of this decision.</p>", "marks": 4, "hint": "Pick one clear benefit and one clear drawback, and explain each briefly (not just name it).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (2 positive + 2 negative)</h5>\n<ul>\n<li>Positive: more people gain internet access, reducing the digital divide (+ development: free access to services/education/jobs)</li>\n<li>Negative: security/privacy risk of public Wi-Fi, or the cost/energy of running it (+ development)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each side scores 1 for a valid impact and 1 for developing it.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to identify the main type of impact each example shows.</p>", "marks": 4, "hint": "Environmental = the planet; Cultural = how people live/interact; Privacy = personal data; Ethical = fairness/right vs wrong.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>E-waste in landfill → <strong>Environmental</strong></li>\n<li>Social media changing how a community keeps in touch → <strong>Cultural</strong></li>\n<li>An app secretly tracking and selling location → <strong>Privacy</strong></li>\n<li>Designing a device to fail early → <strong>Ethical</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently; 2+ ticks in a row scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Discuss the issues surrounding Riverford Academy asking every student to bring their own device to school.</p><p>In your answer, consider the impact on <strong>students and families</strong> as well as on the <strong>school</strong>.</p>", "marks": 5, "hint": "Give positives and negatives, and cover more than one stakeholder (families AND the school). Link points to the fact that not all families can afford a device.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks (balanced across stakeholders, max 5)</h5>\n<ul>\n<li>School positive: saves the cost of buying and maintaining shared computers</li>\n<li>School negative: must support many different devices and manage security/network access</li>\n<li>Families negative: not all can afford a device, widening the digital divide (unfair/ethical)</li>\n<li>Students positive: familiar device; can continue the same work at home</li>\n<li>Further developed points, e.g. risk of theft/damage; students without a device left disadvantaged</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Reward positives AND negatives across BOTH stakeholders, applied to the scenario. Max 5.</li>\n</ul>\n</div>"}, {"question": "<p>NovaPhone releases a new smartphone every year and encourages customers to upgrade.</p><p><strong>Discuss</strong> the positive and negative impacts of NovaPhone''s strategy of releasing a new phone every year.</p><p>In your answer you might consider:</p><ul><li>the impact on NovaPhone as a company</li><li>the impact on its customers</li><li>the environmental impact</li><li>an overall conclusion with a justification</li></ul>", "marks": 8, "hint": "Use the bullets as your plan. Give positives and negatives for each stakeholder, apply them to NovaPhone, and finish with a justified conclusion.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (levelled) — indicative content</h5>\n<p>The following is indicative of points candidates may raise; it is not exhaustive or prescriptive:</p>\n<ul>\n<li><strong>NovaPhone (company):</strong> more frequent sales and increased profit; keeps the brand looking modern and competitive. But high development/advertising costs each year, and a risk to reputation if seen as wasteful or as pressuring customers.</li>\n<li><strong>Customers:</strong> access to the newest features; but higher cost, pressure to upgrade, and frustration if batteries can''t be replaced so working phones must be discarded.</li>\n<li><strong>Environmental:</strong> more e-waste from discarded phones; more raw materials and energy used in manufacturing. Could be reduced by recycling components or donating/redistributing old phones.</li>\n<li><strong>Conclusion:</strong> a justified overall view, e.g. the strategy benefits NovaPhone''s profits in the short term but the environmental harm and cost to customers make it hard to defend unless paired with recycling/repair schemes.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>Band 3 (6–8):</strong> thorough, balanced discussion of positives and negatives across more than one stakeholder, applied directly to NovaPhone, with a clear justified conclusion.</li>\n<li><strong>Band 2 (3–5):</strong> reasonable points but one-sided, generic, or covering only one stakeholder; conclusion weak or missing.</li>\n<li><strong>Band 1 (1–2):</strong> a few simple, unexplained statements with little application.</li>\n<li><strong>0 marks:</strong> nothing worthy of credit.</li>\n</ul>\n</div>"}, {"question": "<p>MedLink''s new app uses AI to check patients'' symptoms and stores their medical history so they can get advice at home.</p><p><strong>Discuss</strong> the positive and negative impacts of MedLink''s app.</p><p>In your answer you might consider:</p><ul><li>the benefits to patients and the health service</li><li>privacy and ethical concerns about the data and the AI</li><li>who might be left out</li><li>an overall conclusion with a justification</li></ul>", "marks": 8, "hint": "Balance the benefits (convenience, faster advice, less strain on doctors) against privacy/ethical risks (sensitive data, AI mistakes) and the digital divide (who can''t use it). End with a justified conclusion.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (levelled) — indicative content</h5>\n<p>Indicative points (not exhaustive):</p>\n<ul>\n<li><strong>Benefits:</strong> patients get quick advice at home without travelling or waiting; reduces pressure on doctors/surgeries; medical history stored in one place for convenience and continuity of care.</li>\n<li><strong>Privacy:</strong> medical data is highly sensitive — concerns about how securely it is stored, who can access it, and whether it could be shared, sold or exposed in a breach (links to the Data Protection Act, 1.6.1b).</li>\n<li><strong>Ethical / AI:</strong> is it right to rely on AI for health decisions? The AI could make mistakes or miss something a doctor would catch; who is responsible if it gives wrong advice?</li>\n<li><strong>Who is left out:</strong> people without a suitable device or internet access, or who lack the skills, cannot use it — the digital divide, which is especially serious for healthcare.</li>\n<li><strong>Conclusion:</strong> a justified view, e.g. the app is valuable for convenience and easing pressure on services, but only if data is kept secure, the AI supports rather than replaces doctors, and alternatives remain for those who cannot use it.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>Band 3 (6–8):</strong> thorough, balanced, applied to MedLink, covering benefits and privacy/ethical concerns across stakeholders, with a justified conclusion.</li>\n<li><strong>Band 2 (3–5):</strong> reasonable but one-sided or generic; limited application; weak conclusion.</li>\n<li><strong>Band 1 (1–2):</strong> a few simple, unexplained statements.</li>\n<li><strong>0 marks:</strong> nothing worthy of credit.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-6-1b-legislation', '1.6.1b Legislation', '{"learn": {"enabled": true, "items": [{"title": "Why we need laws for computers", "html": "<h4>Technology created new ways to cause harm</h4>\n<ul>\n<li>Computers made it possible to <strong>store huge amounts of personal data</strong>, <strong>break into systems</strong>, and <strong>copy other people''s work perfectly</strong> — so the law had to keep up.</li>\n<li>You need to know <strong>three key Acts</strong> for the exam, and what each one is <strong>for</strong>:</li>\n<li><strong>Data Protection Act 2018</strong> — protects people''s <strong>personal data</strong>.</li>\n<li><strong>Computer Misuse Act 1990</strong> — makes <strong>hacking</strong> and misuse of computers illegal.</li>\n<li><strong>Copyright, Designs and Patents Act 1988</strong> — protects people''s <strong>original work</strong> (intellectual property).</li>\n<li>A fourth, the <strong>Freedom of Information Act 2000</strong>, sometimes appears too. The key exam skill is picking the <strong>right law for a given situation</strong>.</li>\n</ul>", "check": {"question": "Why were new laws such as the Computer Misuse Act needed?", "options": ["Because computers were becoming so expensive that the government had to control exactly who was allowed to buy one", "Because computers created new ways to cause harm, such as hacking, that older laws did not clearly cover", "Because computers use a large amount of electricity and the law had to limit how much energy each one could use", "Because computers were making too many older jobs disappear and a law was needed to bring all of them back again"], "answer": 1, "explain": "Computers created new kinds of harm (hacking, data misuse, easy copying) that existing laws didn''t cover, so new legislation was introduced."}}, {"title": "Data Protection Act 2018 — what it is for", "html": "<h4>Controlling how personal data is handled</h4>\n<ul>\n<li>The <strong>Data Protection Act 2018 (DPA)</strong> controls how organisations <strong>collect, store and use people''s personal data</strong> (information about identifiable living people).</li>\n<li>It gives people <strong>rights</strong> over their own data — for example the right to <strong>see</strong> what an organisation holds about them, and to have <strong>mistakes corrected</strong>.</li>\n<li>It applies whenever a business, school or club <strong>stores data about people</strong> — so it is the law that covers customer records, student records, and so on.</li>\n</ul>", "check": {"question": "What does the Data Protection Act 2018 mainly control?", "options": ["The maximum number of computers that any single organisation is legally allowed to own and use at one time", "How organisations collect, store and use people''s personal data, and the rights people have over it", "Whether it is legal for a person to copy and share a piece of software that somebody else has written", "The amount of electricity that a large company''s data centre is permitted to use over the course of a year"], "answer": 1, "explain": "The DPA controls how organisations handle personal data and gives individuals rights over their own data."}}, {"title": "Data Protection Act — what organisations must do", "html": "<h4>The organisation''s responsibilities</h4>\n<ul>\n<li>Personal data must be <strong>kept secure</strong> from unauthorised access — for example using passwords, access rights, encryption and firewalls.</li>\n<li>Data must only be <strong>collected and used with consent</strong>, kept for the <strong>stated purpose</strong>, be <strong>accurate</strong>, and <strong>not kept for longer than needed</strong>.</li>\n<li>Organisations must <strong>not share or sell</strong> personal data without permission, and larger ones may need to appoint a <strong>data protection officer</strong> to make sure the rules are followed.</li>\n</ul>", "check": {"question": "Which of these is a requirement of the Data Protection Act 2018 for an organisation storing personal data?", "options": ["It must publish all of the personal data it holds on its public website so that anyone is able to check it", "It must keep the data secure and not share or sell it without the person''s consent", "It must delete every piece of personal data it holds at the end of each and every working day without fail", "It must store the personal data of as many people as it possibly can in order to grow the business quickly"], "answer": 1, "explain": "The DPA requires personal data to be kept secure and not shared or sold without consent — publishing it or selling it freely would breach the Act."}}, {"title": "Computer Misuse Act 1990 — what it is for", "html": "<h4>Making hacking and misuse illegal</h4>\n<ul>\n<li>The <strong>Computer Misuse Act 1990 (CMA)</strong> makes it a crime to <strong>access or change a computer system without permission</strong> — in other words, it makes <strong>hacking</strong> illegal.</li>\n<li>It covers three main offences:</li>\n<li><strong>1. Unauthorised access</strong> to computer material (e.g. logging into someone''s account without permission).</li>\n<li><strong>2. Unauthorised access with intent</strong> to commit a further crime (e.g. hacking in to steal money or data).</li>\n<li><strong>3. Unauthorised modification</strong> of data (e.g. deleting or changing files, or spreading malware such as a virus).</li>\n</ul>", "check": {"question": "Which action would break the Computer Misuse Act 1990?", "options": ["A person taking a photograph on their own phone and then choosing to share it with a few of their friends", "A person logging into someone else''s email account without permission to read their private messages", "A company keeping a secure, encrypted backup of its own customers'' data on a separate storage device", "A student writing their own computer program from scratch and then running it on their own home computer"], "answer": 1, "explain": "Accessing someone else''s account without permission is unauthorised access — a clear breach of the Computer Misuse Act."}}, {"title": "Copyright, Designs and Patents Act 1988 — what it is for", "html": "<h4>Protecting people''s original work</h4>\n<ul>\n<li>The <strong>Copyright, Designs and Patents Act 1988 (CDPA)</strong> protects <strong>intellectual property</strong> — a person''s or company''s <strong>original work</strong>.</li>\n<li>It covers things like <strong>software, music, films, images, writing and designs</strong>. The creator automatically owns the <strong>copyright</strong>.</li>\n<li>It is <strong>illegal to copy, use, share or sell</strong> someone''s copyrighted work <strong>without their permission</strong> — this includes <strong>software piracy</strong> (illegally copying programs) and using someone''s image or logo without permission.</li>\n</ul>", "check": {"question": "What does the Copyright, Designs and Patents Act 1988 protect?", "options": ["The amount of personal data that a large online company is allowed to collect about each of its customers", "People''s original work, such as software, music, images and writing, from being copied without permission", "Computer systems from being accessed or hacked into by someone who does not have the owner''s permission", "The right of any member of the public to request information that is held by a local council or a school"], "answer": 1, "explain": "The CDPA protects original work (intellectual property) such as software, music and images from being copied or used without permission."}}, {"title": "Freedom of Information Act 2000", "html": "<h4>The public''s right to request information</h4>\n<ul>\n<li>The <strong>Freedom of Information Act 2000 (FoI)</strong> gives members of the public the <strong>right to request information</strong> held by <strong>public authorities</strong> — such as councils, schools, hospitals and government departments.</li>\n<li>The authority must normally <strong>respond and provide the information</strong>, unless there is a good reason not to (for example if it would breach someone''s data protection or national security).</li>\n<li>It is about <strong>openness of public bodies</strong> — very different from the Data Protection Act, which protects <strong>personal</strong> data about individuals.</li>\n</ul>", "check": {"question": "What does the Freedom of Information Act 2000 allow?", "options": ["It allows absolutely any company to freely share and then go on to sell the personal data of its own customers to any other company", "It allows members of the public to request information held by public authorities such as councils and schools", "It allows a person to copy and reuse any piece of software as long as they do not try to sell it for a profit", "It allows the police to access any computer system they wish without needing to obtain any permission first"], "answer": 1, "explain": "The Freedom of Information Act lets the public request information held by public authorities — it is about openness of public bodies."}}, {"title": "Choosing the right law for a scenario", "html": "<h4>The exam''s favourite question</h4>\n<p>You are very often given a situation and asked <strong>which law applies</strong>. Use these quick tests:</p>\n<ul>\n<li>Is it about <strong>personal data</strong> being mishandled, shared or leaked? → <strong>Data Protection Act 2018</strong>.</li>\n<li>Is it about <strong>accessing or changing a system without permission</strong> (hacking, malware)? → <strong>Computer Misuse Act 1990</strong>.</li>\n<li>Is it about <strong>copying someone''s work</strong> (software, image, music, logo) without permission? → <strong>Copyright, Designs and Patents Act 1988</strong>.</li>\n<li>Is it about <strong>asking a public body for information</strong>? → <strong>Freedom of Information Act 2000</strong>.</li>\n</ul>\n<p>Watch the trap: storing customer data is <strong>Data Protection</strong>, <strong>not</strong> Computer Misuse or Copyright — a very common mistake.</p>", "check": {"question": "A company shares its customers'' personal data with another company without the customers'' permission. Which law does this break?", "options": ["The Computer Misuse Act 1990, because sharing any kind of data always counts as misusing a computer system", "The Data Protection Act 2018, because it controls how personal data may be stored, used and shared", "The Copyright, Designs and Patents Act 1988, because the customer list was created by the company itself", "The Freedom of Information Act 2000, because the customers have a right to request their own information back"], "answer": 1, "explain": "Mishandling or sharing personal data without consent breaches the Data Protection Act 2018 — the law that governs personal data."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Data Protection Act 2018", "definition": "Controls how organisations collect, store and use people''s personal data"}, {"term": "Computer Misuse Act 1990", "definition": "Makes it illegal to access or modify a computer system without permission"}, {"term": "Copyright, Designs and Patents Act 1988", "definition": "Protects original work such as software, music, images and writing"}, {"term": "Freedom of Information Act 2000", "definition": "Gives the public the right to request information held by public authorities"}, {"term": "Personal data", "definition": "Information about an identifiable living person (protected by the DPA)"}, {"term": "Consent", "definition": "Permission a person gives for their data to be collected and used"}, {"term": "Unauthorised access", "definition": "Getting into a system or account without permission (CMA offence 1)"}, {"term": "Access with intent", "definition": "Unauthorised access to commit a further crime (CMA offence 2)"}, {"term": "Unauthorised modification", "definition": "Changing/deleting data or spreading malware (CMA offence 3)"}, {"term": "Intellectual property", "definition": "Original work that belongs to its creator, protected by the CDPA"}, {"term": "Software piracy", "definition": "Illegally copying or sharing software (breaks the CDPA)"}, {"term": "Copyright", "definition": "The automatic right of a creator to control copying of their work"}, {"term": "Data protection officer", "definition": "Person who ensures an organisation follows data protection rules"}, {"term": "Public authority", "definition": "A body such as a council or school an FoI request can be made to"}, {"term": "''Data, system, work''", "definition": "Shortcut: DPA = data, Computer Misuse = system, Copyright = work"}, {"term": "GDPR", "definition": "EU data protection rules the UK''s Data Protection Act 2018 is based on"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which law makes it illegal to access a computer system without permission?", "options": ["The Data Protection Act 2018", "The Computer Misuse Act 1990", "The Copyright, Designs and Patents Act 1988", "The Freedom of Information Act 2000"], "answer": 1, "explain": "The Computer Misuse Act 1990 makes unauthorised access to computer systems (hacking) illegal."}, {"question": "Which law would a school be following when it keeps its students'' personal records secure and private?", "options": ["The Copyright, Designs and Patents Act, because the school created the records and therefore owns them fully", "The Data Protection Act 2018", "The Computer Misuse Act, because the records are stored on one of the school''s own computer systems", "The Freedom of Information Act, because parents are allowed to request to see their own child''s school records"], "answer": 1, "explain": "Keeping personal data (student records) secure and private is required by the Data Protection Act 2018."}, {"question": "A person downloads and shares a paid-for game for free without the creator''s permission. Which law does this break?", "options": ["The Data Protection Act 2018, because the game will contain some personal data about the people who made it", "The Copyright, Designs and Patents Act 1988", "The Computer Misuse Act 1990", "The Freedom of Information Act 2000"], "answer": 1, "explain": "Copying and sharing someone''s software without permission (software piracy) breaches the Copyright, Designs and Patents Act 1988."}, {"question": "Which of these is one of the offences covered by the Computer Misuse Act 1990?", "options": ["Keeping personal data for a little longer than the organisation that collected it actually needed to keep it", "Making an unauthorised modification to data, for example by deleting files or spreading a virus", "Selling a piece of software that you wrote entirely yourself to as many customers as you possibly can", "Requesting information from a local council about how it has chosen to spend its money over the last year"], "answer": 1, "explain": "Unauthorised modification of data (e.g. deleting files or spreading malware) is one of the Computer Misuse Act''s offences."}, {"question": "A member of the public asks their local council how much it spent on new computers last year. Which law gives them the right to ask?", "options": ["The Data Protection Act 2018", "The Freedom of Information Act 2000", "The Computer Misuse Act 1990", "The Copyright, Designs and Patents Act 1988"], "answer": 1, "explain": "The Freedom of Information Act 2000 lets the public request information held by public authorities such as a council."}, {"question": "Which of these is a responsibility placed on an organisation by the Data Protection Act 2018?", "options": ["It must give a free copy of any software it has created to anybody who politely asks the company for one", "It must keep personal data secure and must not share or sell it without the person''s consent", "It must allow anyone at all to access its computer systems so long as they do not change any of the data", "It must release a brand new version of its product every single year to keep its customers fully up to date"], "answer": 1, "explain": "The DPA requires personal data to be kept secure and not shared or sold without consent."}, {"question": "A designer copies another company''s logo and uses it on their own product without asking. Which law does this break?", "options": ["The Computer Misuse Act 1990, because copying the logo means gaining access to the other company''s systems", "The Copyright, Designs and Patents Act 1988", "The Data Protection Act 2018", "The Freedom of Information Act 2000"], "answer": 1, "explain": "A logo is an original work protected by copyright, so copying it without permission breaches the Copyright, Designs and Patents Act 1988."}, {"question": "An employee logs into their manager''s account without permission to read confidential emails. Which law is broken?", "options": ["The Copyright, Designs and Patents Act 1988", "The Computer Misuse Act 1990", "The Freedom of Information Act 2000", "The Data Protection Act 2018"], "answer": 1, "explain": "Accessing an account without permission is unauthorised access — an offence under the Computer Misuse Act 1990."}, {"question": "Why is storing customer data covered by the Data Protection Act rather than the Computer Misuse Act?", "options": ["Because the Computer Misuse Act only ever applies to computers that are connected to the public internet", "Because the Data Protection Act is the law that specifically governs how personal data is stored and used", "Because the Computer Misuse Act only applies to schools and colleges, never to ordinary private businesses", "Because storing any data at all is always automatically a form of misusing a computer under the older law"], "answer": 1, "explain": "The Data Protection Act specifically governs personal data; the Computer Misuse Act is about unauthorised access, not routine data storage."}, {"question": "The Copyright, Designs and Patents Act 1988 protects which of the following?", "options": ["The personal contact details and payment information of every customer stored in a company''s database", "Original work such as software, music, images and writing created by a person or company", "Computer networks and systems from being broken into by someone who does not have permission to use them", "The right of members of the public to see information that is held about them by government departments"], "answer": 1, "explain": "The CDPA protects original work (intellectual property) such as software, music, images and writing."}, {"question": "Which pairing of a situation with the correct law is right?", "options": ["Spreading a virus that deletes a company''s files → the Freedom of Information Act, because files are information", "Spreading a virus that deletes a company''s files → the Computer Misuse Act 1990", "Losing a laptop full of unencrypted customer data → the Copyright, Designs and Patents Act 1988", "Copying a song and selling it without permission → the Data Protection Act, because a song is personal to its writer"], "answer": 1, "explain": "Spreading a virus to delete files is unauthorised modification — a Computer Misuse Act offence. The other pairings are matched to the wrong law."}, {"question": "Which of these best describes the difference between the Data Protection Act and the Freedom of Information Act?", "options": ["They are really just one and the same single law, only written down with two completely different names by two separate parts of the government", "Data Protection protects individuals'' personal data; Freedom of Information lets the public access public bodies'' information", "Data Protection applies only to schools, while Freedom of Information applies only to large private companies", "Data Protection is about copying software, while Freedom of Information is about hacking into computer systems"], "answer": 1, "explain": "The DPA protects personal data about individuals; the FoI Act opens up information held by public authorities — opposite purposes."}]}, "fib": {"enabled": true, "questions": [{"text": "The [Computer Misuse] Act 1990 makes it illegal to access or change a computer system without permission."}, {"text": "The Data [Protection] Act 2018 controls how organisations collect, store and use people''s personal data."}, {"text": "The Copyright, Designs and Patents Act 1988 protects original work such as software, music and [images]."}, {"text": "Illegally copying and sharing software is called software [piracy] and breaks the Copyright Act."}, {"text": "Under the Data Protection Act, personal data must be kept [secure] from unauthorised access."}, {"text": "Spreading a virus that deletes files is ''unauthorised [modification]'' under the Computer Misuse Act."}, {"text": "The Freedom of [Information] Act 2000 lets the public request information held by public authorities."}, {"text": "Under the Data Protection Act, an organisation must get a person''s [consent] before collecting their personal data."}]}, "tf": {"enabled": true, "questions": [{"statement": "The Computer Misuse Act 1990 makes hacking into a computer system illegal.", "answer": true, "explain": "Correct — the Computer Misuse Act makes unauthorised access to computer systems (hacking) a criminal offence."}, {"statement": "The Data Protection Act 2018 is the law that protects people''s personal data.", "answer": true, "explain": "Correct — the DPA controls how organisations collect, store and use personal data and gives individuals rights over it."}, {"statement": "Copying and selling someone''s software without permission breaks the Data Protection Act.", "answer": false, "explain": "It breaks the Copyright, Designs and Patents Act 1988, which protects original work such as software from being copied."}, {"statement": "Under the Data Protection Act, an organisation can freely sell customers'' personal data to anyone it likes.", "answer": false, "explain": "The DPA forbids sharing or selling personal data without the person''s consent — this would breach the Act."}, {"statement": "Spreading a virus that deletes files is an offence under the Computer Misuse Act.", "answer": true, "explain": "Correct — this is unauthorised modification of data, one of the Computer Misuse Act''s offences."}, {"statement": "The Freedom of Information Act lets the public request information held by public authorities.", "answer": true, "explain": "Correct — the FoI Act gives the public the right to request information from bodies such as councils and schools."}, {"statement": "The Copyright, Designs and Patents Act protects computer systems from being hacked.", "answer": false, "explain": "Protecting systems from hacking is the Computer Misuse Act. The CDPA protects original work such as software and music."}, {"statement": "A logo is an original work that is protected by the Copyright, Designs and Patents Act.", "answer": true, "explain": "Correct — a logo is intellectual property, so copying it without permission breaches the CDPA."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking that storing or losing customer data is covered by the Computer Misuse Act.", "truth": "The <strong>Computer Misuse Act</strong> is about <strong>unauthorised access</strong> (hacking) and changing systems without permission. Handling <strong>personal data</strong> — storing it, keeping it secure, sharing it — is the <strong>Data Protection Act 2018</strong>. Mixing these two up is one of the most common exam errors.", "check": {"question": "A company accidentally leaks its customers'' personal data. Which law has it most likely failed to follow?", "options": ["The Computer Misuse Act 1990, because a leak means someone must have hacked into the company''s systems", "The Data Protection Act 2018, because it requires personal data to be kept secure", "The Copyright, Designs and Patents Act 1988, because the customer list is the company''s own original work", "The Freedom of Information Act 2000, because the customers have a right to know that the leak has happened"], "answer": 1, "explain": "Failing to keep personal data secure is a Data Protection Act failing — not the Computer Misuse Act, which is about hacking."}}, {"myth": "Believing the Copyright Act protects computer systems from hackers.", "truth": "The <strong>Copyright, Designs and Patents Act</strong> protects <strong>original work</strong> (software, music, images, writing) from being <strong>copied</strong>. Protecting <strong>systems</strong> from being <strong>hacked</strong> is the <strong>Computer Misuse Act</strong>. One is about copying work; the other is about breaking in.", "check": {"question": "Which law is broken by illegally copying and distributing a piece of paid-for software?", "options": ["The Computer Misuse Act, because copying the software means gaining access to the company''s private systems", "The Copyright, Designs and Patents Act 1988, because the software is original work protected by copyright", "The Data Protection Act, because the software will contain some of the personal data of the people who made it", "The Freedom of Information Act, because customers have the right to a free copy of any software they want"], "answer": 1, "explain": "Copying software without permission is software piracy — a breach of the Copyright, Designs and Patents Act, not the Computer Misuse Act."}}, {"myth": "Confusing the Data Protection Act with the Freedom of Information Act.", "truth": "They point in <strong>opposite directions</strong>. The <strong>Data Protection Act</strong> <strong>protects</strong> individuals'' <strong>personal</strong> data (keeping it private and secure). The <strong>Freedom of Information Act</strong> <strong>opens up</strong> information held by <strong>public bodies</strong> so the public can request it. One keeps data private; the other makes information public.", "check": {"question": "Which law would a member of the public use to ask their local hospital how it spends its budget?", "options": ["The Data Protection Act 2018, because the budget information is personal data belonging to the hospital itself", "The Freedom of Information Act 2000, because it lets the public request information held by public authorities", "The Computer Misuse Act 1990, because the budget figures are all stored on the hospital''s computer systems", "The Copyright, Designs and Patents Act 1988, because the hospital created the budget report as its own work"], "answer": 1, "explain": "Requesting information from a public body (the hospital) is exactly what the Freedom of Information Act allows."}}, {"myth": "Getting the Acts'' names or years muddled (e.g. ''Data Misuse Act'').", "truth": "Learn the exact names and years: <strong>Data Protection Act 2018</strong>, <strong>Computer Misuse Act 1990</strong>, <strong>Copyright, Designs and Patents Act 1988</strong>. Examiners usually allow small slips, but knowing them precisely avoids confusing two different laws — the years also help you keep them apart.", "check": {"question": "Which of these is the correct name of a real piece of UK computer legislation?", "options": ["The Data Misuse and Hacking Prevention Act, which is used to protect all personal data held by companies", "The Computer Misuse Act 1990", "The Digital Privacy and Software Copying Act, which covers both personal data and the copying of software", "The Internet Safety and Information Freedom Act, which controls what can be posted onto social media websites"], "answer": 1, "explain": "The Computer Misuse Act 1990 is a real Act. The other names are invented — knowing the correct names and years prevents this mistake."}}, {"myth": "Thinking the Data Protection Act stops an organisation from storing ANY personal data at all.", "truth": "The DPA does <strong>not</strong> ban storing personal data — organisations need it to function. It sets <strong>rules</strong>: get <strong>consent</strong>, keep it <strong>secure</strong>, use it only for the <strong>stated purpose</strong>, keep it <strong>accurate</strong>, and <strong>not longer than needed</strong>. It controls <strong>how</strong> data is handled, not whether it can be held at all.", "check": {"question": "What does the Data Protection Act require of an organisation that stores personal data?", "options": ["That it must never store any personal data about any person under any circumstances whatsoever at all", "That it handles the data properly — with consent, kept secure, accurate, and only for as long as needed", "That it publishes all of the personal data it holds so that the information is open to the general public", "That it sells the personal data on to another company as soon as it has finished using the data itself"], "answer": 1, "explain": "The DPA controls HOW data is handled (consent, security, accuracy, retention) — it does not ban storing personal data outright."}}]}, "tips": {"enabled": true, "items": [{"title": "The scenario → law matching skill", "html": "<p>The most common question gives a scenario and asks which law applies — as a tick-grid, or \"Identify the legislation…\". Learn these signature links:</p>\n<ul>\n<li><strong>Personal data</strong> mishandled/shared/leaked → <strong>Data Protection Act 2018</strong></li>\n<li><strong>Accessing/changing a system</strong> without permission (hacking, malware) → <strong>Computer Misuse Act 1990</strong></li>\n<li><strong>Copying someone''s work</strong> (software, image, music, logo) → <strong>Copyright, Designs and Patents Act 1988</strong></li>\n<li><strong>Requesting info from a public body</strong> → <strong>Freedom of Information Act 2000</strong></li>\n</ul>\n<p><strong>The classic trap:</strong> \"a company storing customers'' data\" is <strong>Data Protection</strong> — students often wrongly pick Computer Misuse or Copyright here. Read for the key idea: <em>data</em>, <em>access</em>, <em>copying</em>, or <em>public information</em>?</p>", "check": {"question": "A youth centre stores personal data about the young people who attend. Which legislation must it follow?", "options": ["The Computer Misuse Act 1990, because the data is being kept on the youth centre''s own computer systems", "The Data Protection Act 2018, because it governs how organisations must handle people''s personal data", "The Copyright, Designs and Patents Act 1988, because the youth centre created the records that it is storing", "The Freedom of Information Act 2000, because the young people can ask to see the data that is held on them"], "answer": 1, "explain": "Storing personal data means following the Data Protection Act — the classic trap is wrongly choosing Computer Misuse or Copyright."}}, {"title": "Describe a law''s purpose — say what it protects and forbids", "html": "<p>When asked to \"identify one piece of legislation… and describe it\", you need <strong>two things</strong>:</p>\n<ul>\n<li><strong>Identify (1 mark):</strong> the correct, named Act.</li>\n<li><strong>Describe (1+ marks):</strong> what it <strong>protects</strong> or what it makes <strong>illegal</strong>, ideally with a relevant detail.</li>\n</ul>\n<p><strong>Example (data storage):</strong> \"The <strong>Data Protection Act 2018</strong> <em>(identify)</em>. It controls how organisations store and use people''s <strong>personal data</strong>, requiring it to be kept <strong>secure</strong> and only used with <strong>consent</strong> <em>(describe)</em>.\"</p>\n<p>Just naming the Act is usually only half the marks — always add what it does.</p>", "check": {"question": "A 2-mark question says ''Identify one law the club must follow when storing members'' data, and describe it.'' What earns the second mark?", "options": ["Writing the name of the Act a second time in slightly different words to make the answer look longer", "Describing what the Act does, e.g. it requires personal data to be kept secure and used only with consent", "Giving the exact date and time at which the law was originally passed by parliament many years ago", "Naming a second, completely different law that has nothing to do with the storing of personal data at all"], "answer": 1, "explain": "The first mark is naming the Act; the second comes from describing what it does — e.g. keeping personal data secure, used with consent."}}, {"title": "Keep the three main Acts crisply apart", "html": "<p>One line each — memorise these and you''ll rarely pick the wrong law:</p>\n<ul>\n<li><strong>Data Protection Act 2018</strong> = my <strong>data</strong> (personal information kept safe).</li>\n<li><strong>Computer Misuse Act 1990</strong> = my <strong>system</strong> (no hacking or malware).</li>\n<li><strong>Copyright, Designs and Patents Act 1988</strong> = my <strong>work</strong> (no copying software, music, images).</li>\n</ul>\n<p>Three words: <strong>data, system, work</strong>. Match the scenario to one of those, and you''ve almost certainly found the right Act.</p>", "check": {"question": "Using the ''data, system, work'' shortcut, which Act covers someone hacking into a company''s network?", "options": ["The Data Protection Act, because a network always contains at least some personal data about people", "The Computer Misuse Act 1990, because hacking into a system without permission is misusing that system", "The Copyright, Designs and Patents Act, because the company''s network setup is its own original design work", "The Freedom of Information Act, because the hacker was only ever trying to find out information they wanted"], "answer": 1, "explain": "Hacking a system is the ''system'' case — the Computer Misuse Act 1990, which forbids unauthorised access."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick <strong>one</strong> box to identify the law that makes it illegal to access a computer system without permission.</p>", "marks": 1, "hint": "Which law is about hacking / accessing systems without permission?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Computer Misuse Act 1990</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box to identify the law that protects original work such as software, music and images from being copied.</p>", "marks": 1, "hint": "Which law is about copying someone''s original work without permission?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Copyright, Designs and Patents Act 1988</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to show which law applies to each action.</p>", "marks": 4, "hint": "Copying work → Copyright; accessing without permission → Computer Misuse; personal data → Data Protection.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Using another artist''s picture as a logo without permission → <strong>Copyright, Designs and Patents Act 1988</strong></li>\n<li>Opening a colleague''s email account without permission → <strong>Computer Misuse Act 1990</strong></li>\n<li>Sharing customers'' personal data without consent → <strong>Data Protection Act 2018</strong></li>\n<li>Accidentally publishing pupils'' home addresses → <strong>Data Protection Act 2018</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently; 2+ ticks in a row scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Identify <strong>one</strong> piece of legislation that Bright Sparks must follow when storing the young people''s data, and describe what it requires.</p>", "marks": 2, "hint": "Name the correct Act (it''s about personal data), then say one thing it requires the centre to do.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: Data Protection Act 2018</li>\n<li>1 mark: a valid requirement — keep data secure, only use with consent, do not share without permission, keep accurate, not keep longer than needed</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Do not credit the Computer Misuse Act or Copyright Act here — the scenario is about storing personal data.</li>\n</ul>\n</div>"}, {"question": "<p>Describe the three offences covered by the Computer Misuse Act 1990.</p>", "marks": 3, "hint": "There are three levels: simple unauthorised access; access with a further criminal intent; and changing/modifying data.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>Unauthorised access to computer material</li>\n<li>Unauthorised access with intent to commit a further offence</li>\n<li>Unauthorised modification of data (e.g. spreading a virus)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>1 mark for each of the three offences. An example alone (without the type of offence) may still be credited if it clearly matches.</li>\n</ul>\n</div>"}, {"question": "<p>A student copies a paragraph from a website into their own project and sells the project online, without permission.</p><p>Identify the law this breaks and give a reason.</p>", "marks": 2, "hint": "The student is copying someone''s original written work — which law protects that?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: Copyright, Designs and Patents Act 1988</li>\n<li>1 mark: the writing is original work protected by copyright, copied/sold without permission</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The reason must link to copying original work without permission.</li>\n</ul>\n</div>"}, {"question": "<p>Describe what the Data Protection Act 2018 requires an organisation to do with the personal data it collects.</p>", "marks": 3, "hint": "Give three distinct requirements — think about consent, security, purpose, accuracy and how long data is kept.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>Keep data secure from unauthorised access</li>\n<li>Collect/use it only with consent and for the stated purpose</li>\n<li>Keep it accurate; not keep it longer than needed; not share/sell without permission</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award any three distinct valid requirements.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to identify the legislation that covers each event.</p>", "marks": 4, "hint": "Requesting public info → Freedom of Information; virus/hacking → Computer Misuse; personal data → Data Protection; copying a film → Copyright.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Requesting spending figures from a council → <strong>Freedom of Information Act 2000</strong></li>\n<li>Spreading a virus that deletes files → <strong>Computer Misuse Act 1990</strong></li>\n<li>Selling customers'' data after being told not to → <strong>Data Protection Act 2018</strong></li>\n<li>Downloading and sharing a film without permission → <strong>Copyright, Designs and Patents Act 1988</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Each row is marked independently; 2+ ticks in a row scores 0 for that row.</li>\n</ul>\n</div>"}, {"question": "<p>Explain the difference between the Data Protection Act 2018 and the Freedom of Information Act 2000.</p>", "marks": 2, "hint": "One keeps certain information private; the other makes certain information public. Say what each does.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: Data Protection Act protects individuals'' personal data (keeps it private/secure)</li>\n<li>1 mark: Freedom of Information Act lets the public access information held by public authorities</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Both sides of the contrast are needed for 2 marks.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '1-6-1c-software-licensing', '1.6.1c Software Licensing', '{"learn": {"enabled": true, "items": [{"title": "What is a software licence?", "html": "<h4>You buy permission to use software, not the software itself</h4>\n<ul>\n<li>A <strong>software licence</strong> is the set of <strong>legal terms</strong> that says <strong>how you are allowed to use</strong> a piece of software — for example how many computers you can install it on, and whether you may change or share it.</li>\n<li>When you \"buy\" software you are really buying (or agreeing to) a <strong>licence to use it</strong>; the <strong>creator keeps the copyright</strong>.</li>\n<li>The two main types you must know are <strong>proprietary (closed source)</strong> and <strong>open source</strong>. A third idea, <strong>Creative Commons</strong>, is a way of licensing creative work such as videos and images.</li>\n</ul>", "check": {"question": "What is a software licence?", "options": ["A physical certificate printed on paper that must always be kept inside the box the software was sold in", "The legal terms that set out how you are allowed to use a piece of software", "A special piece of hardware that has to be plugged into the computer before the software will run", "A guarantee that the software will never contain any bugs or errors of any kind for as long as it is used"], "answer": 1, "explain": "A software licence is the legal terms setting out how you may use the software — the creator keeps the copyright even after you buy a licence."}}, {"title": "Proprietary (closed source) software", "html": "<h4>Owned by a company, source code hidden</h4>\n<ul>\n<li><strong>Proprietary</strong> (or <strong>closed source</strong>) software is owned by the company that made it. You usually <strong>pay</strong> for a licence to use it.</li>\n<li>The <strong>source code is kept secret</strong> — users <strong>cannot see or change</strong> it — and you are <strong>not allowed to copy or redistribute</strong> the software.</li>\n<li>Examples include <strong>Microsoft Windows</strong>, <strong>Microsoft Office</strong> and <strong>Adobe Photoshop</strong>.</li>\n</ul>", "check": {"question": "Which statement is true of proprietary (closed source) software?", "options": ["Its source code is freely available, so any user is able to read it, change it and then share their new version", "You usually pay for it, and its source code is kept secret so users cannot change it", "It is always completely free of charge, but it can only ever be installed on one single computer at a time", "It can be legally copied and given away to as many other people as the user likes, at absolutely no cost"], "answer": 1, "explain": "Proprietary software is usually paid for and keeps its source code secret, so users cannot view or change it or freely redistribute it."}}, {"title": "Open source software", "html": "<h4>Source code available, free to use and change</h4>\n<ul>\n<li><strong>Open source</strong> software is released with its <strong>source code available</strong> to everyone.</li>\n<li>It is usually <strong>free</strong>, and users are allowed to <strong>view, modify (change) and redistribute</strong> it. It is often developed and improved by a <strong>community</strong> of volunteers.</li>\n<li>Examples include the <strong>Linux</strong> operating system, the <strong>Firefox</strong> browser and the <strong>GIMP</strong> image editor.</li>\n</ul>", "check": {"question": "What is a key feature of open source software?", "options": ["It is owned by a single company that keeps the source code completely secret from every one of its users", "Its source code is available, so users can view, change and redistribute it, and it is usually free", "It can only be used by professional software developers who have first paid for an expensive yearly licence", "It is a physical product that is always sold on a disc rather than being made available to download online"], "answer": 1, "explain": "Open source software makes its source code available so users can view, change and redistribute it, and it is usually free."}}, {"title": "Proprietary software — benefits and drawbacks", "html": "<h4>Weighing up closed source software</h4>\n<ul>\n<li><strong>Benefits:</strong> it is usually <strong>well tested and reliable</strong>, comes with <strong>official support</strong> and <strong>regular updates</strong>, and is often <strong>polished and easy to use</strong> — good for a business that needs dependable software.</li>\n<li><strong>Drawbacks:</strong> it <strong>costs money</strong> (sometimes a lot), you <strong>cannot change or customise</strong> it to your own needs because the source code is hidden, and you depend on the company to keep supporting it.</li>\n</ul>", "check": {"question": "Which is a benefit of proprietary software compared with open source?", "options": ["It can always be copied and shared freely with anyone, at no cost, because the company positively encourages it", "It usually comes with official support and regular updates from the company that made it", "Its source code can be freely changed by the user to add any new feature that they happen to want", "It is developed only by unpaid community volunteers, which is what makes it so reliable and well tested"], "answer": 1, "explain": "A key benefit of proprietary software is official support and regular updates from the company — the other options actually describe open source."}}, {"title": "Open source software — benefits and drawbacks", "html": "<h4>Weighing up open source software</h4>\n<ul>\n<li><strong>Benefits:</strong> it is usually <strong>free</strong>, you can <strong>change and customise</strong> it because the source code is available, and a <strong>community</strong> can improve it and fix problems.</li>\n<li><strong>Drawbacks:</strong> there may be <strong>no official support</strong> if something goes wrong, quality can <strong>vary</strong>, and you may need <strong>technical skill</strong> to set it up or modify it. Its security relies on the community spotting and fixing issues.</li>\n</ul>", "check": {"question": "Which is a drawback of open source software compared with proprietary?", "options": ["It usually costs a very large amount of money to buy before a person is allowed to install and use it", "There may be no official support to turn to if something goes wrong, and quality can vary between versions", "Its source code is kept completely hidden, so it is impossible for anyone to fix a problem with the program", "It can never be changed or customised in any way at all, because doing so is against the terms of its licence"], "answer": 1, "explain": "Open source may lack official support and its quality can vary — the other options describe proprietary software or are simply untrue of open source."}}, {"title": "Choosing and recommending a licence", "html": "<h4>Match the licence to the situation</h4>\n<ul>\n<li>Questions often ask you to <strong>recommend</strong> a licence for a scenario and <strong>justify</strong> it. There is no single right answer — it depends on what the user <strong>needs</strong>.</li>\n<li>Lean <strong>proprietary</strong> when the user needs <strong>reliability and official support</strong>, has money to spend, and does not need to change the software — e.g. a <strong>business</strong> that needs dependable, supported tools.</li>\n<li>Lean <strong>open source</strong> when the user wants to <strong>save money</strong>, values being able to <strong>adapt</strong> the software, and has the <strong>skills</strong> (or a community) to support it — e.g. a <strong>developer</strong> building on top of it.</li>\n<li>Remember: <strong>both</strong> types are still protected by <strong>copyright</strong>.</li>\n</ul>", "check": {"question": "A business needs reliable, well-supported software and is happy to pay for it. Which licence is the better fit, and why?", "options": ["Open source, because a large community of unpaid volunteers will always fix any problem far faster than a company ever possibly could", "Proprietary, because it typically offers reliability and official support, which the business values and can pay for", "Open source, because the business will definitely want to rewrite the software''s source code to suit its own needs", "Proprietary, because it is the only kind of software that it is actually legal for a business to use at work"], "answer": 1, "explain": "A business that values reliability and support, and can pay, is a good fit for proprietary software. Both licence types are legal to use."}}, {"title": "Creative Commons licences", "html": "<h4>Sharing creative work with conditions</h4>\n<ul>\n<li>A <strong>Creative Commons (CC)</strong> licence is a way for a creator of work such as <strong>videos, images, music or writing</strong> to let <strong>others use and share it</strong>, while <strong>keeping some rights</strong>.</li>\n<li>The creator chooses the <strong>conditions</strong>. Common ones include: others must give <strong>credit (attribution)</strong> to the creator; the work may or may not be used for <strong>commercial (money-making)</strong> purposes; and any new version may have to be <strong>shared under the same licence</strong>.</li>\n<li>It sits between \"all rights reserved\" (normal copyright) and fully free — the creator says in advance <strong>what others are allowed to do</strong>, so they don''t have to ask permission each time.</li>\n</ul>", "check": {"question": "How does releasing a video under a Creative Commons licence affect how others can use it?", "options": ["It means absolutely nobody else is ever allowed to watch, use or share the video without paying a fee first", "It lets others use and share the video under conditions the creator sets, such as giving credit", "It transfers the full copyright of the video to whoever downloads it first, so the creator loses all rights", "It guarantees that the video can only ever be used by large companies for their paid advertising campaigns"], "answer": 1, "explain": "A Creative Commons licence lets others use and share the work under conditions the creator chooses (such as attribution) — the creator keeps some rights."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Software licence", "definition": "The legal terms setting out how you may use a piece of software"}, {"term": "Proprietary software", "definition": "Company-owned, paid-for software with hidden source code you cannot change"}, {"term": "Closed source", "definition": "Another name for proprietary — source code not made available"}, {"term": "Open source software", "definition": "Software released with its source code available; usually free to use, change, share"}, {"term": "Source code", "definition": "The human-readable program instructions written by developers"}, {"term": "Proprietary — benefit", "definition": "Reliable, well tested, official support and regular updates"}, {"term": "Proprietary — drawback", "definition": "Costs money; cannot be customised (source code hidden)"}, {"term": "Open source — benefit", "definition": "Usually free; can be customised; improved by a community"}, {"term": "Open source — drawback", "definition": "May lack official support; variable quality; needs skill"}, {"term": "Creative Commons", "definition": "A licence letting creators share work under conditions they choose"}, {"term": "Attribution", "definition": "A Creative Commons condition requiring users to credit the creator"}, {"term": "Copyright (both types)", "definition": "Protects both proprietary and open source software"}, {"term": "Example: proprietary", "definition": "Windows, Microsoft Office, Adobe Photoshop"}, {"term": "Example: open source", "definition": "Linux, Firefox, GIMP"}, {"term": "Choosing a licence", "definition": "Depends on the user''s needs: support/reliability vs cost/customising"}, {"term": "Feature vs benefit", "definition": "Feature = a fact about it; benefit = why that fact helps the user"}]}, "mcq": {"enabled": true, "questions": [{"question": "What does a software licence actually give the person who buys it?", "options": ["Full ownership of the software''s source code, which they are then completely free to sell on to somebody else", "Permission to use the software under certain terms, while the creator keeps the copyright", "A physical piece of hardware that must be connected before the software is allowed to run on the computer", "A promise from the developer that the software will always run perfectly and never once need to be updated"], "answer": 1, "explain": "A licence grants permission to use the software under set terms; the creator keeps the copyright — you don''t own the software itself."}, {"question": "Which of these is a feature of open source software?", "options": ["The company that made it keeps the source code completely secret so that no user is ever able to see it", "Its source code is available, and users are allowed to change it and redistribute it", "It always costs a large one-off fee, which must be paid before it can be downloaded and installed", "It can only be installed and used on one single computer, which must be registered with the developer first"], "answer": 1, "explain": "Open source software provides its source code and allows users to modify and redistribute it — usually for free."}, {"question": "Which of these is a feature of proprietary software?", "options": ["Anyone at all is free to view its source code, change it however they wish, and then redistribute their version", "You usually pay for it, and its source code is kept secret so users cannot change it", "It is always written and maintained entirely by unpaid volunteers working together in an online community", "It must, by law, be given away completely free of charge to any person or business that asks the company for it"], "answer": 1, "explain": "Proprietary (closed source) software is usually paid for and keeps its source code hidden, so users cannot change it."}, {"question": "A company needs software that is reliable and comes with professional support and regular updates. Which is the better fit?", "options": ["Open source software", "Proprietary software", "Software with no licence of any kind", "Software that is still only a rough, unfinished test version"], "answer": 1, "explain": "Proprietary software typically offers reliability, official support and regular updates — a good fit for a business that needs dependability."}, {"question": "Which is a genuine benefit of open source software?", "options": ["It always comes with a guaranteed telephone support line staffed by the original developers around the clock", "It is usually free and can be changed and customised because its source code is available", "It is always more secure than proprietary software because absolutely nobody can ever see how it works inside", "It can never contain any bugs, because so many different community volunteers have looked at all of the code"], "answer": 1, "explain": "Open source is usually free and can be customised because its source code is open — but it does not guarantee support, security or a bug-free program."}, {"question": "Which is a drawback of proprietary software?", "options": ["Its source code is available for anyone to change, which can make different copies behave inconsistently", "It usually costs money and you cannot change it, because the source code is kept hidden from you", "It is developed only by volunteers, so there is never anyone available to provide official support for it", "It can be freely copied and shared, which makes it very hard for the company to earn any money from it"], "answer": 1, "explain": "Proprietary software costs money and cannot be customised (its source code is hidden) — the other options actually describe open source."}, {"question": "Which statement about copyright and these licence types is correct?", "options": ["Only proprietary software is protected by copyright; open source software has no copyright protection at all", "Both proprietary and open source software are protected by copyright", "Neither proprietary nor open source software is ever protected by copyright once it has been released to users", "Copyright applies to open source software but is completely removed from proprietary software when it is sold"], "answer": 1, "explain": "Both types are protected by copyright — open source simply grants users more permissions (to view, change and share) than proprietary does."}, {"question": "A developer wants software they can adapt and build on, and they want to avoid licence costs. Which is the better fit?", "options": ["Proprietary software", "Open source software", "Software that has had all of its copyright legally and permanently removed by the developer", "A trial version of proprietary software that stops working completely after only thirty days"], "answer": 1, "explain": "Open source suits a developer who wants to adapt the software and avoid cost, because the source code is available and it is usually free."}, {"question": "What is a Creative Commons licence used for?", "options": ["Permanently removing all copyright from a piece of work so that it belongs to nobody and can never be owned again", "Letting a creator share work such as videos or images under conditions they choose, like requiring credit", "Guaranteeing that a piece of open source software will always keep working on every future operating system", "Forcing everyone who wants to view a creator''s work to pay a fee to the creator before they are allowed to see it"], "answer": 1, "explain": "A Creative Commons licence lets a creator share their work under chosen conditions (such as attribution) while keeping some rights."}, {"question": "William releases his videos under a Creative Commons licence that requires attribution. What must other people do to use them?", "options": ["Nothing at all is required of them, because a Creative Commons licence removes every single condition on the work", "Give William credit as the creator when they use his videos, following the licence''s conditions", "Pay William a fixed licence fee each and every time that they choose to use one of his videos anywhere", "Ask William for his written permission in advance before they are allowed to use any of the videos at all"], "answer": 1, "explain": "An attribution Creative Commons licence requires users to credit the creator — that is the condition William has set, so no separate permission is needed."}, {"question": "Why might a school with little money and skilled IT staff choose open source software?", "options": ["Because open source software is the only type that is actually legal for a school to install on its computers", "Because it is usually free and the staff have the skills to set it up and customise it themselves", "Because open source software always comes with a paid support contract that a school is required to buy", "Because open source software cannot be changed, which makes it much simpler for the school to manage safely"], "answer": 1, "explain": "Open source is usually free and can be customised; a school with skilled staff can support it themselves, saving on licence costs."}, {"question": "Which pairing of a user with the most suitable licence is best justified?", "options": ["A hospital that needs guaranteed, reliable support → open source, because a community will always help quickly", "A large business that needs dependable, supported software → proprietary, because it offers official support", "A developer wanting to freely adapt the code → proprietary, because the hidden source code is easier to change", "A charity with no money and skilled staff → proprietary, because paying for software is always the safest choice"], "answer": 1, "explain": "A business needing dependable, supported software is well matched to proprietary. The other pairings match the user to the wrong licence."}]}, "fib": {"enabled": true, "questions": [{"text": "A software [licence] sets out the legal terms of how you are allowed to use a piece of software."}, {"text": "[proprietary] software is owned by a company, is usually paid for, and keeps its source code secret."}, {"text": "Open [source] software is released with its source code available so users can change and share it."}, {"text": "A benefit of proprietary software is that it usually comes with official [support] and regular updates."}, {"text": "A benefit of open source software is that it is usually [free] and can be customised."}, {"text": "The human-readable program instructions written by developers are called the source [code]."}, {"text": "A Creative [Commons] licence lets a creator share work under conditions such as requiring attribution."}, {"text": "Both proprietary and open source software are still protected by [copyright]."}]}, "tf": {"enabled": true, "questions": [{"statement": "When you buy proprietary software you are buying a licence to use it, not the copyright.", "answer": true, "explain": "Correct — you buy permission to use it under set terms; the creator keeps the copyright."}, {"statement": "Open source software makes its source code available so users can change and redistribute it.", "answer": true, "explain": "Correct — that is the defining feature of open source, and it is usually free as well."}, {"statement": "Proprietary software lets users freely view and edit its source code.", "answer": false, "explain": "Proprietary (closed source) software keeps its source code secret — users cannot view or change it."}, {"statement": "A benefit of proprietary software is that it usually comes with official support and updates.", "answer": true, "explain": "Correct — reliable official support and regular updates are key benefits of proprietary software."}, {"statement": "A drawback of open source software is that there may be no official support if something goes wrong.", "answer": true, "explain": "Correct — open source often lacks a company to provide official support, and its quality can vary."}, {"statement": "Open source software has no copyright protection at all.", "answer": false, "explain": "Both open source and proprietary software are protected by copyright — open source simply grants users more permissions."}, {"statement": "A Creative Commons licence lets a creator share their work while keeping some rights.", "answer": true, "explain": "Correct — Creative Commons lets creators set conditions (like attribution) for how others may use and share their work."}, {"statement": "Proprietary software is always the best choice for every situation.", "answer": false, "explain": "There is no single best choice — it depends on the user''s needs. Open source can be better when cost and customisation matter."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking open source software is exactly the same as ''freeware'' — just free software.", "truth": "The key point of <strong>open source</strong> is that the <strong>source code is available</strong> to view, change and share — not just that it is free. Some free software (freeware) is still <strong>closed source</strong>: you can use it for free but you <strong>cannot see or change</strong> its code. Open source is about <strong>openness of the code</strong>, not only price.", "check": {"question": "What most defines open source software?", "options": ["Simply that it does not cost any money, which is the only thing that really separates it from other software", "That its source code is available for users to view, change and redistribute", "That it can only ever be used by large companies who employ their own team of professional programmers", "That it is always more powerful and more reliable than any proprietary software could possibly ever be"], "answer": 1, "explain": "Open source is defined by its source code being available to view, change and share — not merely by being free of charge."}}, {"myth": "Believing open source software has no copyright, so you can do anything you like with it.", "truth": "Open source software <strong>is</strong> protected by <strong>copyright</strong> — the licence simply <strong>grants users permission</strong> to view, change and share the code, often on conditions (like keeping it open source). It is not a free-for-all; you must still follow the terms of its licence.", "check": {"question": "Is open source software protected by copyright?", "options": ["No — releasing software as open source completely removes all of its copyright protection straight away", "Yes — it is protected by copyright, and its licence grants users permission to view, change and share it", "No — copyright only ever applies to music and films, and it has never applied to computer software at all", "Yes — but only if the user pays an additional fee to the developer in order to activate that protection"], "answer": 1, "explain": "Open source software is protected by copyright; the licence grants extra permissions, but users must still follow its terms."}}, {"myth": "Assuming proprietary software is always better because you pay for it.", "truth": "Paying does bring real benefits — <strong>reliability, support, updates</strong> — but proprietary software also has <strong>drawbacks</strong> (cost, no customisation). For some users, <strong>open source is the better choice</strong>. The ''best'' licence <strong>depends on the situation</strong>: what the user needs, their budget and their skills.", "check": {"question": "When might open source software be a better choice than proprietary?", "options": ["Never — proprietary software is always the better choice because it is the only option that costs any money", "When the user wants to save money and be able to customise the software, and can support it themselves", "Only when the user has absolutely no interest in the software working reliably or being supported at all", "Only when the user is legally banned from buying any proprietary software for some particular reason"], "answer": 1, "explain": "Open source suits users who want to save money and customise the software and who can support it themselves — the best choice depends on the situation."}}, {"myth": "Confusing ''closed source'' and ''open source'' — mixing up which one hides the code.", "truth": "<strong>Closed source (proprietary)</strong> = code is <strong>hidden</strong>, you can''t change it. <strong>Open source</strong> = code is <strong>open</strong>, you can change it. The name tells you: is the source code <strong>open</strong> (visible) or <strong>closed</strong> (hidden)?", "check": {"question": "Which type of software keeps its source code hidden from users?", "options": ["Open source software, because the word ''open'' actually refers to it being openly available to buy in shops", "Proprietary (closed source) software, because its source code is kept secret and cannot be changed", "Both types keep their source code hidden, so there is no real difference between them for the user at all", "Neither type hides its source code, because by law all software code must be published when it is released"], "answer": 1, "explain": "Proprietary (closed source) software hides its source code; open source makes it available. The name signals whether the code is open or closed."}}, {"myth": "Thinking a Creative Commons licence means the work is free to use however you want.", "truth": "Creative Commons lets a creator <strong>share</strong> their work, but usually <strong>with conditions</strong> — most commonly requiring <strong>attribution</strong> (crediting the creator), and sometimes forbidding <strong>commercial use</strong> or requiring you to <strong>share alike</strong>. You must <strong>follow the specific conditions</strong> the creator chose, not just do anything you like.", "check": {"question": "Someone finds a photo under a Creative Commons licence that requires attribution. What must they do to use it?", "options": ["Nothing — a Creative Commons licence means the photo can be used in any way at all with no conditions", "Credit the photographer as the creator, following the attribution condition the licence sets", "Buy the full copyright to the photo from the photographer before they are allowed to use it anywhere", "Change the photo so much that the original photographer would no longer be able to recognise it as theirs"], "answer": 1, "explain": "An attribution licence requires the user to credit the creator — Creative Commons work comes with conditions that must be followed."}}]}, "tips": {"enabled": true, "items": [{"title": "Feature vs benefit vs drawback — know which the question wants", "html": "<p>Licensing questions ask for <strong>features</strong>, <strong>benefits</strong>, <strong>drawbacks</strong>, or a <strong>recommendation</strong> — and they are different things:</p>\n<ul>\n<li><strong>Feature</strong> = a fact about it (\"the source code is available\").</li>\n<li><strong>Benefit</strong> = why that is good for the user (\"so it can be customised for free\").</li>\n<li><strong>Drawback</strong> = why it could be a problem (\"but there may be no official support\").</li>\n</ul>\n<p>If a question asks for a <strong>benefit</strong>, don''t just state a feature — say <strong>why it helps the user</strong>. And a \"give one benefit and one drawback\" question needs <strong>one of each</strong>, not two benefits.</p>", "check": {"question": "A question asks for one BENEFIT of open source software. Which answer earns the mark?", "options": ["Stating only the plain feature that the source code of the software happens to be available to look at", "Saying it is free and can be customised, so the user saves money and can adapt it to their needs", "Listing a clear drawback instead, such as the fact that there may be no official support available for it", "Naming a completely different piece of open source software without explaining anything about it at all"], "answer": 1, "explain": "A benefit says why the feature helps the user (free + customisable → saves money, can adapt it) — not just the bare feature, and not a drawback."}}, {"title": "The ''recommend a licence and justify it'' question", "html": "<p>A common question describes a scenario and asks you to <strong>recommend</strong> open source or proprietary and <strong>justify</strong> your choice. There is <strong>no single right answer</strong> — the marks are for the <strong>justification linked to the scenario</strong>.</p>\n<ul>\n<li>Pick the licence that fits the user''s <strong>needs</strong>: reliability + support + budget → <strong>proprietary</strong>; low cost + wanting to adapt it + having the skills → <strong>open source</strong>.</li>\n<li>Justify with the <strong>benefits</strong> of your choice AND, ideally, why the <strong>drawbacks</strong> of the other option matter for this user.</li>\n<li>Always tie it to the <strong>specific scenario</strong> (a business, a school, a solo developer…).</li>\n</ul>", "check": {"question": "On a ''recommend and justify a licence'' question, what earns the marks?", "options": ["Simply naming either open source or proprietary, without giving any reason at all for the particular choice", "A justification linked to the scenario, explaining why the chosen licence suits that user''s needs", "Explaining in detail how the computer''s processor runs the machine code of the software while it is in use", "Always recommending proprietary software, because it is the only choice that could ever be marked correct"], "answer": 1, "explain": "The marks are for the justification tied to the scenario — why the chosen licence fits that user — not just naming one, and either choice can be valid."}}, {"title": "Explaining a Creative Commons licence", "html": "<p>If asked how a <strong>Creative Commons</strong> licence affects the use of someone''s work, cover:</p>\n<ul>\n<li>It lets <strong>other people use and share</strong> the work <strong>without asking permission each time</strong>…</li>\n<li>…but <strong>under conditions the creator chooses</strong> — commonly <strong>attribution</strong> (give credit), sometimes <strong>non-commercial</strong> (no money-making use) or <strong>share-alike</strong> (share any new version the same way)…</li>\n<li>…and the creator still <strong>keeps some rights</strong> (it is not the same as giving up copyright).</li>\n</ul>\n<p>A strong answer names at least one <strong>specific condition</strong>, not just \"people can use it\".</p>", "check": {"question": "Which point would strengthen an answer about how a Creative Commons licence affects others'' use of a video?", "options": ["That the licence removes the creator''s copyright entirely, so the video now belongs to whoever downloads it", "That others may use and share it without asking each time, but must follow conditions such as giving credit", "That the video can only be watched by people who have first paid the creator a monthly subscription fee", "That the video will automatically stop playing after a set number of views unless it is bought outright"], "answer": 1, "explain": "A strong answer notes that others can use/share it without asking each time but must meet the creator''s conditions (e.g. attribution), and the creator keeps some rights."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Give <strong>one</strong> benefit and <strong>one</strong> drawback for Layla of releasing her game as <strong>open source</strong>.</p>", "marks": 2, "hint": "One good thing about open source, and one problem with it — from Layla''s point of view as the creator.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 benefit + 1 drawback)</h5>\n<ul>\n<li>Benefit: others can see and improve the code; a community may develop it; free, so more people play it</li>\n<li>Drawback: harder to make money from it; others could copy or change her work; little or no income</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>1 mark for a valid benefit AND 1 mark for a valid drawback — two benefits (or two drawbacks) score 1.</li>\n</ul>\n</div>"}, {"question": "<p>Describe <strong>three</strong> features of <strong>proprietary</strong> software.</p>", "marks": 3, "hint": "Think about who owns it, whether you pay, and whether you can see or change the code.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>Owned by a company / usually paid for (a licence to use)</li>\n<li>Source code is kept secret</li>\n<li>Users cannot change it / cannot copy or redistribute it</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Award any three distinct valid features.</li>\n</ul>\n</div>"}, {"question": "<p>A large hospital needs software that is reliable and comes with guaranteed support.</p><p>Explain why a <strong>proprietary</strong> licence is a more appropriate choice than open source for the hospital.</p>", "marks": 3, "hint": "Link the benefits of proprietary (support, reliability) to the hospital''s needs, and say why an open source drawback matters here.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>Proprietary usually comes with official/guaranteed support the hospital can rely on</li>\n<li>It is well tested, reliable and regularly updated — important for critical systems</li>\n<li>Open source may lack official support / have variable quality, too risky here; the hospital can afford to pay</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Reward reasons tied to the hospital''s need for reliability and support.</li>\n</ul>\n</div>"}, {"question": "<p>Explain how releasing his videos under a <strong>Creative Commons</strong> licence will affect how other people can use William''s videos.</p>", "marks": 3, "hint": "Say what others are allowed to do, the kind of condition the licence can set, and what happens to William''s rights.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>Others can use and share the videos without asking permission each time</li>\n<li>But only under conditions William sets (e.g. attribution / non-commercial)</li>\n<li>William keeps some rights / still owns the copyright</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Credit at least one specific condition, not just \"people can use them\".</li>\n</ul>\n</div>"}, {"question": "<p>Compare open source and proprietary software by giving <strong>one benefit and one drawback of each</strong>.</p>", "marks": 4, "hint": "One good point and one bad point for open source, and the same for proprietary — four points in total.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks</h5>\n<ul>\n<li>Open source benefit: free / customisable (source code available)</li>\n<li>Open source drawback: no official support / variable quality</li>\n<li>Proprietary benefit: reliable / official support / regular updates</li>\n<li>Proprietary drawback: costs money / cannot be customised</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>1 mark for each of the four points; must include a benefit AND a drawback for each type.</li>\n</ul>\n</div>"}, {"question": "<p>Layla must decide whether to release her new game as <strong>open source</strong> or <strong>proprietary</strong> software.</p><p><strong>Discuss</strong> the features, benefits and drawbacks of each type of licence for Layla''s game, and make a recommendation.</p><p>In your answer you might consider:</p><ul><li>the features of open source and proprietary software</li><li>the benefits and drawbacks of each for Layla</li><li>the fact that Layla wants others to improve the game but also needs to earn money</li><li>a recommendation with a justification</li></ul>", "marks": 8, "hint": "Cover both licence types (features + benefits + drawbacks), apply them to Layla''s two aims (letting others improve it AND earning money), then recommend one with a clear reason.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (levelled) — indicative content</h5>\n<p>Indicative points (not exhaustive):</p>\n<ul>\n<li><strong>Open source — features/benefits:</strong> source code available and usually free, so other programmers could improve and extend Layla''s game and a community could grow around it; more people may play it because it is free.</li>\n<li><strong>Open source — drawbacks:</strong> hard for Layla to earn money as it is usually free; others could copy, change or even sell versions of her work; she may get little income.</li>\n<li><strong>Proprietary — features/benefits:</strong> Layla charges for a licence and keeps the source code secret, so she can earn money and keep control of her game; she can offer official support.</li>\n<li><strong>Proprietary — drawbacks:</strong> others cannot help improve it, so it grows only as fast as Layla can develop it; a price may put some players off.</li>\n<li><strong>Recommendation:</strong> a justified choice, e.g. proprietary best meets her need to earn money and keep control, though it limits community improvement; or a middle path (charge for the game but release some parts openly). The key is a reason linked to her two aims.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given — levels of response</h5>\n<ul>\n<li><strong>Band 3 (6–8):</strong> thorough, balanced discussion of both licence types (features, benefits, drawbacks) applied to Layla''s aims, with a clear justified recommendation.</li>\n<li><strong>Band 2 (3–5):</strong> reasonable points but one-sided or generic, or covering only one licence type; recommendation weak or unjustified.</li>\n<li><strong>Band 1 (1–2):</strong> a few simple, unexplained statements.</li>\n<li><strong>0 marks:</strong> nothing worthy of credit.</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '2-1-1-computational-thinking', '2.1.1 Computational Thinking', '{"learn": {"enabled": true, "items": [{"title": "What is computational thinking?", "html": "<h4>Working out how to solve a problem before you code it</h4>\n<ul>\n<li><strong>Computational thinking</strong> is a set of thinking skills used to work out how to solve a problem — <strong>before</strong> any program code is written.</li>\n<li>It uses three main techniques: <strong>abstraction</strong> (removing unnecessary detail), <strong>decomposition</strong> (breaking a problem into smaller parts) and <strong>algorithmic thinking</strong> (working out the steps needed).</li>\n<li>Together, these techniques help a programmer <strong>define</strong> a problem (work out exactly what it involves) and <strong>refine</strong> it (simplify it), so that it becomes easier to solve.</li>\n<li>Computational thinking is not only used by programmers — it is a general way of tackling any large or complex problem, on a computer or off one.</li>\n</ul>", "check": {"question": "Which of the following best describes computational thinking?", "options": ["A set of thinking skills used to work out how to solve a problem, applied before any program code is written", "A programming language used to write the final version of a solution once every step has already been planned out", "A single technique for removing unnecessary detail from a problem", "The process of testing a finished program to find and fix any bugs"], "answer": 0, "explain": "Computational thinking is the set of thinking skills (abstraction, decomposition, algorithmic thinking) used to plan a solution before any code is written."}}, {"title": "Abstraction", "html": "<h4>Removing or hiding unnecessary detail</h4>\n<ul>\n<li><strong>Abstraction</strong> means removing or hiding the detail that is <strong>not needed</strong> to solve a problem, so that only the parts that matter are left.</li>\n<li>A road map is a classic example: it shows the roads you need for a journey, but leaves out every building, tree and fence along the way. Those details are real, but they are <strong>not relevant</strong> to finding a route.</li>\n<li>A <strong>model</strong> of something (a diagram, a plan, a set of program data) is a simplified version created using abstraction — it keeps the features that matter for the task and ignores the rest.</li>\n</ul>", "check": {"question": "What does abstraction mean in computational thinking?", "options": ["Removing or hiding unnecessary detail so that only the parts of a problem that matter are kept", "Adding as much extra detail as possible so that every single feature of a real situation is represented", "Breaking a large problem down into smaller, more manageable sub-problems", "Working out the exact order of steps needed to solve a problem"], "answer": 0, "explain": "Abstraction means removing or hiding unneeded detail. Adding more detail is the opposite of abstraction; splitting into parts is decomposition; working out steps is algorithmic thinking."}}, {"title": "Abstraction in practice", "html": "<h4>Deciding what to keep and what to leave out</h4>\n<ul>\n<li>Abstraction is a <strong>choice</strong>: for any real problem there are far more details than a program (or a person) actually needs.</li>\n<li>Example: a school''s student record system needs a student''s <strong>name, ID number and year group</strong> — but it does not need their shoe size or favourite colour. Leaving those out is abstraction.</li>\n<li>Example: a bus tracking app shows <strong>which stop a bus is near and when it will arrive</strong> — the driver''s exact GPS coordinates and engine data are hidden from the passenger, because they add nothing useful.</li>\n<li>Good abstraction keeps a problem <strong>simple enough to work with</strong>, without losing anything that is actually needed.</li>\n</ul>", "check": {"question": "A programmer designing a school library system decides to store each book''s title, author and shelf number, but not the exact minute it was printed. What is this an example of?", "options": ["Abstraction — irrelevant detail (the exact printing time) is left out because it is not needed to find a book", "Decomposition — the library system has been broken down into smaller, separate parts that can be solved one at a time", "Algorithmic thinking — the steps needed to search for a book have been listed", "An error, because a complete system must always store every single piece of data that could possibly exist"], "answer": 0, "explain": "Leaving out detail that isn''t needed (the printing time) so that only the useful fields remain is abstraction, not decomposition or algorithmic thinking."}}, {"title": "Decomposition", "html": "<h4>Breaking a big problem into smaller pieces</h4>\n<ul>\n<li><strong>Decomposition</strong> means breaking a large, complex problem down into <strong>smaller, more manageable sub-problems</strong> that can be tackled one at a time.</li>\n<li>Example: building a quiz app is a big problem. Decomposed, it becomes several smaller ones: \"show a question\", \"check the answer\", \"keep score\", \"show the final result\".</li>\n<li>If a sub-problem is still too complex, it can be <strong>decomposed again</strong> into even smaller sub-problems, until each one is simple enough to solve directly.</li>\n</ul>", "check": {"question": "What does decomposition mean?", "options": ["Breaking a large, complex problem down into smaller, more manageable sub-problems", "Removing or hiding every possible piece of detail so that literally nothing about the original problem is left to consider", "Working out the step-by-step sequence of instructions needed to solve a problem", "Testing every sub-problem at the very end, once the whole program has already been completed"], "answer": 0, "explain": "Decomposition splits a large problem into smaller sub-problems. Removing detail is abstraction; working out steps is algorithmic thinking."}}, {"title": "Decomposition in practice", "html": "<h4>Why smaller pieces are easier to solve</h4>\n<ul>\n<li>Each sub-problem can be <strong>looked at, solved and tested on its own</strong>, without having to think about the whole problem at the same time.</li>\n<li>Different sub-problems can sometimes be <strong>shared out between different people</strong> in a team, so several parts can be worked on at once.</li>\n<li>A solution to one sub-problem can sometimes be <strong>reused</strong> elsewhere — for example, a \"check the answer\" sub-problem from a quiz app could be reused in a different quiz.</li>\n<li>Decomposition does not solve the problem by itself — it just makes the problem <strong>easier to plan and to solve</strong>.</li>\n</ul>", "check": {"question": "A team of three programmers is building a booking system. They agree that one person will build the login screen, one will build the search screen, and one will build the payment screen. What allowed them to split the work like this?", "options": ["Decomposition — the overall problem had already been broken down into separate, more manageable sub-problems", "Abstraction — every unnecessary detail about the booking system had been removed before any work started at all", "Algorithmic thinking — the exact order of steps for the whole system had been written out for everyone to follow", "A coincidence, since a booking system cannot actually be split into separate parts by different programmers"], "answer": 0, "explain": "Splitting an overall problem into separate parts that different people can work on is decomposition."}}, {"title": "Algorithmic thinking", "html": "<h4>Working out the steps to follow</h4>\n<ul>\n<li><strong>Algorithmic thinking</strong> means working out the <strong>step-by-step sequence of instructions</strong> — the logic — needed to solve a problem, or a sub-problem.</li>\n<li>It is usually applied <strong>after</strong> a problem has been decomposed, one sub-problem at a time: for each sub-problem, work out exactly what steps need to happen, and in what order.</li>\n<li>The finished sequence of steps is called an <strong>algorithm</strong>. It can be written in plain English, as a diagram, or later turned into program code.</li>\n</ul>", "check": {"question": "What does algorithmic thinking mean?", "options": ["Working out the step-by-step sequence of instructions needed to solve a problem", "Removing detail from a problem so that only the features which are actually needed for a solution are kept", "Breaking a problem down into smaller sub-problems that can be solved one at a time", "Running a finished program many times to check that it produces the correct result"], "answer": 0, "explain": "Algorithmic thinking is working out the ordered steps (the logic) needed to solve a problem. The other options describe abstraction, decomposition and testing."}}, {"title": "Algorithmic thinking in practice", "html": "<h4>From steps to a working algorithm</h4>\n<ul>\n<li>Take the sub-problem \"check whether a number is a valid exam mark (0 to 100)\". Algorithmic thinking works out the steps: <em>ask for the number → check it is 0 or more → check it is 100 or less → if both are true, accept it, otherwise reject it</em>.</li>\n<li>Writing the steps out clearly, in the right order, <strong>before</strong> touching a keyboard makes it far easier to spot mistakes in the logic — and far easier to translate into any programming language afterwards.</li>\n<li>A good algorithm is <strong>precise</strong> (each step has one clear meaning) and <strong>complete</strong> (it covers every case the problem needs, not just the obvious one).</li>\n</ul>", "check": {"question": "Why is it useful to work out the steps of an algorithm before writing any program code?", "options": ["It makes it easier to spot mistakes in the logic first, and easier to turn the steps into code in any language afterwards", "It is not useful at all, because a programmer should always start by typing code directly into an editor without planning anything out in advance first", "It removes the need to ever test the program once it has finally been written and completed", "It automatically translates the steps into working code without a programmer needing to type anything"], "answer": 0, "explain": "Planning the steps first makes mistakes easier to spot and the algorithm easier to turn into code afterwards — it does not remove the need for testing or write the code for you."}}, {"title": "Defining and refining a problem", "html": "<h4>Using all three techniques together</h4>\n<ul>\n<li>The three techniques are not used in strict isolation — they work together to help a programmer <strong>define</strong> a problem (work out exactly what it involves) and <strong>refine</strong> it (make it simpler and clearer) before any code is written.</li>\n<li>A typical order: use <strong>abstraction</strong> to strip away detail that does not matter, use <strong>decomposition</strong> to split what is left into sub-problems, then use <strong>algorithmic thinking</strong> to work out the steps needed for each sub-problem.</li>\n<li>This does not have to be a one-way process — a programmer might return to an earlier technique if a sub-problem still turns out to be too complex, and decompose it further.</li>\n</ul>", "check": {"question": "Which of these best describes how abstraction, decomposition and algorithmic thinking are normally used together?", "options": ["Abstraction removes unneeded detail, decomposition splits what is left into sub-problems, and algorithmic thinking works out the steps for each sub-problem", "They must always be used in exactly the reverse order every single time, starting with algorithmic thinking, then decomposition, and only finally using abstraction at the very end", "Only one of the three techniques is ever needed to solve any given problem, so a programmer simply picks whichever one they prefer", "They are three completely unrelated skills that are never used on the same problem at the same time"], "answer": 0, "explain": "The three techniques normally work together in this order: abstraction removes detail, decomposition splits what''s left into parts, and algorithmic thinking works out each part''s steps."}}, {"title": "Why computational thinking makes problems easier to solve", "html": "<h4>The benefits of thinking before coding</h4>\n<ul>\n<li><strong>Simpler problems</strong> — a huge, complicated problem is hard to hold in your head all at once; abstraction and decomposition turn it into small pieces that are easy to understand.</li>\n<li><strong>Easier to test</strong> — each small sub-problem can be checked on its own, so mistakes are easier to find and fix than in one giant block of logic.</li>\n<li><strong>Easier to share out</strong> — separate sub-problems can be divided between different people, so a team can work on a problem at the same time.</li>\n<li><strong>Reusable solutions</strong> — a well-defined sub-problem, and the algorithm that solves it, can sometimes be reused in a different program.</li>\n</ul>", "check": {"question": "Which of these is a genuine benefit of using decomposition on a large problem?", "options": ["Each sub-problem is small enough to be solved, tested and understood on its own", "The overall problem magically disappears completely, so that no further work of any kind is ever required from anyone", "It guarantees that the final program will never contain a single bug or mistake of any kind whatsoever", "It means every sub-problem must always be solved by exactly one single programmer working entirely alone"], "answer": 0, "explain": "Decomposition makes each sub-problem small enough to solve, test and understand on its own — it does not remove the problem, guarantee no bugs, or force one programmer to work alone."}}, {"title": "Spotting the right technique in a scenario", "html": "<h4>How to tell abstraction, decomposition and algorithmic thinking apart</h4>\n<ul>\n<li>Exam scenarios describe someone solving a problem and ask which technique is being used. Look for these cues:</li>\n<li><strong>Abstraction</strong> — the scenario talks about <em>leaving out, ignoring, hiding or simplifying</em> detail that isn''t needed.</li>\n<li><strong>Decomposition</strong> — the scenario talks about <em>splitting, dividing or breaking the problem into separate parts</em> or stages.</li>\n<li><strong>Algorithmic thinking</strong> — the scenario talks about working out the <em>order of steps</em>, or planning what happens <em>first, next and last</em>.</li>\n<li>Answer using the exact term the mark scheme expects (e.g. \"decomposition\", not just \"breaking it up\") and, where asked, explain your choice using detail from the scenario.</li>\n</ul>", "check": {"question": "A scenario says a student ''listed the exact order in which the robot should turn, move forward, and stop.'' Which technique does this describe?", "options": ["Algorithmic thinking — the student worked out the ordered sequence of steps the robot must follow", "Abstraction — the student removed every unnecessary detail about the robot before listing anything at all", "Decomposition — the student split the robot''s overall task into several completely separate, smaller sub-problems", "None of these — listing steps in order is not part of computational thinking in any way"], "answer": 0, "explain": "Listing an ordered sequence of steps (turn, move, stop) is algorithmic thinking — working out the logic to follow, not removing detail or splitting into sub-problems."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Computational thinking", "definition": "The set of thinking skills used to plan how to solve a problem, before any code is written"}, {"term": "Abstraction", "definition": "Removing or hiding unnecessary detail so that only what matters is kept"}, {"term": "Decomposition", "definition": "Breaking a large, complex problem down into smaller, more manageable sub-problems"}, {"term": "Algorithmic thinking", "definition": "Working out the step-by-step sequence of instructions needed to solve a problem"}, {"term": "Algorithm", "definition": "The finished set of step-by-step instructions produced by algorithmic thinking"}, {"term": "Sub-problem", "definition": "A smaller part of a larger problem, created by decomposition"}, {"term": "Model", "definition": "A simplified representation of something real, created using abstraction"}, {"term": "Define a problem", "definition": "Work out exactly what a problem involves before trying to solve it"}, {"term": "Refine a problem", "definition": "Simplify or improve the understanding of a problem so it becomes easier to solve"}, {"term": "Benefit — easier to test", "definition": "Each small sub-problem can be tested on its own, rather than testing everything at once"}, {"term": "Benefit — sharing work", "definition": "Separate sub-problems can be divided between different people in a team"}, {"term": "Benefit — reuse", "definition": "A solution to a well-defined sub-problem can sometimes be reused elsewhere"}, {"term": "Road map example", "definition": "A road map is abstraction — it shows roads but hides buildings and other unneeded detail"}, {"term": "Typical order", "definition": "Decomposition usually splits a problem first; algorithmic thinking then works out each part''s steps"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which technique means breaking a large, complex problem into smaller, more manageable sub-problems?", "options": ["Decomposition", "Abstraction, because it always removes every piece of detail from a problem until nothing at all is left to solve", "Algorithmic thinking", "Testing"], "answer": 0, "explain": "Decomposition splits a large problem into smaller sub-problems. Abstraction removes detail; algorithmic thinking works out the steps."}, {"question": "Which technique means working out the step-by-step sequence of instructions needed to solve a problem?", "options": ["Algorithmic thinking", "Decomposition, because it always breaks the problem into an ordered list of numbered instructions to follow", "Abstraction", "Testing, since it always finds every single step required to solve the whole problem correctly"], "answer": 0, "explain": "Algorithmic thinking is working out the ordered steps (the logic) needed to solve a problem."}, {"question": "Which technique means removing or hiding detail that is not needed to solve a problem?", "options": ["Abstraction", "Decomposition, because it removes every unnecessary sub-problem until only one single detail about the task is left", "Algorithmic thinking", "Refinement"], "answer": 0, "explain": "Abstraction removes or hides unneeded detail so only what matters is kept."}, {"question": "A programmer chooses to store only a customer''s name and order number, and leaves out their exact home address. Which technique is this?", "options": ["Abstraction — irrelevant detail has been left out because it is not needed", "Decomposition — the customer record has been split into two entirely separate smaller programs that must be built one after another", "Algorithmic thinking — the steps needed to look up a customer have been listed", "Testing — the programmer is checking that the data is stored correctly"], "answer": 0, "explain": "Leaving out unneeded detail (the address) is abstraction, not decomposition, algorithmic thinking or testing."}, {"question": "A large ''build a school website'' problem is split into ''homepage'', ''staff pages'' and ''contact form''. Which technique is this?", "options": ["Decomposition — the overall problem has been broken into smaller, more manageable sub-problems", "Abstraction, because every website has to have unnecessary detail removed before any of its pages can possibly be built at all", "Algorithmic thinking — the exact steps for building the whole website have been written out", "An algorithm, which is the finished set of instructions that solves a problem"], "answer": 0, "explain": "Splitting an overall problem into separate parts (homepage, staff pages, contact form) is decomposition."}, {"question": "A student writes out, in order: ''ask for two numbers, add them together, then display the result.'' Which technique is this?", "options": ["Algorithmic thinking — the ordered steps needed to solve the problem have been worked out", "Decomposition, because the single task of adding two numbers has somehow been split into several completely separate sub-problems", "Abstraction — unnecessary detail about the two numbers has been removed", "Debugging — mistakes in a finished program are being found and corrected"], "answer": 0, "explain": "Writing out an ordered sequence of steps (ask, add, display) is algorithmic thinking."}, {"question": "What is an algorithm?", "options": ["A finished set of step-by-step instructions that solves a problem", "A thinking skill used to remove unnecessary detail from a large and complicated real-world problem before it is solved", "A named store in memory whose value can change while a program runs", "A simplified diagram that shows only the roads in a particular area"], "answer": 0, "explain": "An algorithm is the finished, ordered set of instructions produced by algorithmic thinking."}, {"question": "Which of these is the best definition of ''define a problem'' in computational thinking?", "options": ["Working out exactly what a problem involves before trying to solve it", "Writing the final working program code in a specific programming language such as Python or Java", "Testing a finished solution to check that it produces the correct result every time", "Removing every single feature of a problem so that literally nothing about it remains to be solved"], "answer": 0, "explain": "Defining a problem means working out exactly what it involves before attempting a solution."}, {"question": "Why might a programmer decompose a sub-problem even further, into smaller sub-problems?", "options": ["Because the sub-problem is still too complex to solve or understand as a single piece", "Because computational thinking rules require exactly three levels of decomposition for absolutely every problem, with no exceptions", "Because abstraction can only be used once on any given problem, no matter how complicated it is", "Because algorithms are not allowed to contain more than one single step in total"], "answer": 0, "explain": "A sub-problem can be decomposed again if it is still too complex to tackle directly — there is no fixed number of levels."}, {"question": "A programmer is planning a solution and works out the order: ''check stock is available, THEN take payment, THEN confirm the order.'' What has the programmer produced?", "options": ["An algorithm — the ordered steps needed to solve the problem", "A model, which is a simplified representation of something real created using only abstraction and nothing else", "A sub-problem, which is one smaller part of a larger overall problem", "A decomposition diagram that shows every possible detail about the order in full"], "answer": 0, "explain": "An ordered sequence of steps that solves a problem is an algorithm — the result of algorithmic thinking."}]}, "fib": {"enabled": true, "questions": [{"text": "[abstraction] means removing or hiding unnecessary detail so that only the parts of a problem that matter are left."}, {"text": "[decomposition] means breaking a large, complex problem down into smaller, more manageable sub-problems."}, {"text": "[algorithmic thinking] is working out the step-by-step sequence of instructions needed to solve a problem."}, {"text": "A road map is an everyday example of [abstraction], because it leaves out buildings and shows only the roads that matter for a journey."}, {"text": "Splitting the job of building an entire app into a login screen, a menu screen and a save screen is an example of [decomposition]."}, {"text": "A smaller part of a larger problem, produced by decomposition, is called a [sub-problem]."}, {"text": "The thinking skills used to work out how to solve a problem, before any code is written, are together called [computational thinking]."}, {"text": "The finished set of step-by-step instructions produced by algorithmic thinking is called an [algorithm]."}]}, "tf": {"enabled": true, "questions": [{"statement": "Abstraction means adding more detail to a problem so that it becomes more accurate.", "answer": false, "explain": "Abstraction means the opposite — removing or hiding unnecessary detail so that only the parts that matter are kept."}, {"statement": "Decomposition means breaking a large problem into smaller, more manageable sub-problems.", "answer": true, "explain": "Correct — that is exactly what decomposition means."}, {"statement": "Algorithmic thinking is the process of writing the final program code in a specific language such as Python.", "answer": false, "explain": "Algorithmic thinking is working out the step-by-step logic needed to solve a problem — writing it in a specific language comes afterwards."}, {"statement": "A road map is an example of abstraction, because it leaves out details that are not needed, such as the exact height of every building.", "answer": true, "explain": "Correct — a map keeps the roads (what''s needed for a journey) and hides irrelevant detail."}, {"statement": "Decomposition can be applied more than once, breaking a sub-problem down into even smaller sub-problems.", "answer": true, "explain": "Correct — if a sub-problem is still too complex, it can be decomposed again."}, {"statement": "Computational thinking is only used by professional programmers once they have already started writing code.", "answer": false, "explain": "Computational thinking is used to plan a solution BEFORE any code is written, and can be applied to any complex problem, not just programming."}, {"statement": "Breaking a big problem into smaller sub-problems can make it possible to share the work between several people.", "answer": true, "explain": "Correct — separate sub-problems can be divided between different people in a team."}, {"statement": "Algorithmic thinking must always be applied before decomposition, in every case.", "answer": false, "explain": "Usually decomposition happens first, splitting the problem into sub-problems; algorithmic thinking is then applied to work out the steps for each sub-problem."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking abstraction means adding more detail to a problem, to make it more accurate.", "truth": "Abstraction means the opposite — it means <strong>removing or hiding</strong> detail that is not needed, so that only the parts of a problem that matter are left.", "check": {"question": "Which of these correctly describes abstraction?", "options": ["Removing or hiding detail that is not needed, so only the important parts of a problem remain", "Adding as much extra detail as possible so that a problem is represented completely and perfectly, with nothing left out at all", "Splitting a problem into smaller, more manageable sub-problems", "Working out the order of steps needed to solve a problem"], "answer": 0, "explain": "Abstraction removes or hides unneeded detail — it does not add detail, split a problem into parts, or work out steps."}}, {"myth": "Thinking decomposition and algorithmic thinking are the same thing.", "truth": "They are different: <strong>decomposition</strong> splits a problem into smaller <em>sub-problems</em>; <strong>algorithmic thinking</strong> works out the <em>steps</em> needed to solve a problem (or sub-problem).", "check": {"question": "What is the difference between decomposition and algorithmic thinking?", "options": ["Decomposition splits a problem into sub-problems; algorithmic thinking works out the steps to solve a problem", "There is no real difference at all — the two terms are simply two completely different names that programmers use for exactly the same single technique", "Decomposition removes unnecessary detail; algorithmic thinking splits a problem into smaller parts", "Algorithmic thinking is only used once a program has already been completely finished and tested"], "answer": 0, "explain": "Decomposition splits a problem into sub-problems; algorithmic thinking works out the ordered steps needed to solve it. They are different techniques."}}, {"myth": "Believing decomposition can only ever be applied once to a problem.", "truth": "A sub-problem can be <strong>decomposed again</strong> if it is still too complex — decomposition can be applied more than once, breaking a problem down as many times as needed.", "check": {"question": "A sub-problem is still too complicated to solve directly. What should a programmer do?", "options": ["Decompose the sub-problem again, breaking it into even smaller sub-problems", "Give up on decomposition completely, since it is only ever allowed to be used a single time on any one problem", "Apply abstraction instead, because decomposition cannot be used more than once under any circumstances", "Write the final program code immediately, without doing any further planning"], "answer": 0, "explain": "Decomposition can be applied more than once — a sub-problem that is still too complex can be broken down further."}}, {"myth": "Believing computational thinking is only relevant once you are already writing code.", "truth": "Computational thinking is used <strong>before</strong> code is written, to plan and simplify a solution — and it applies to solving <em>any</em> complex problem, not only programming ones.", "check": {"question": "When is computational thinking used?", "options": ["Before any code is written, to plan and simplify a solution to a problem", "Only after a program has already been fully written, in order to test whether it works correctly", "Only while a program is actually running, to control how fast it processes data", "Only by professional programmers, and only when they are using a single specific programming language"], "answer": 0, "explain": "Computational thinking is used before any code is written, to plan and simplify a solution to a problem."}}, {"myth": "Thinking an algorithm and algorithmic thinking are the same thing.", "truth": "<strong>Algorithmic thinking</strong> is the thinking <em>process</em> of working out the steps needed. An <strong>algorithm</strong> is the <em>result</em> — the finished sequence of steps itself.", "check": {"question": "What is the difference between an algorithm and algorithmic thinking?", "options": ["Algorithmic thinking is the process of working out the steps; an algorithm is the finished sequence of steps produced", "There is no difference — an algorithm and algorithmic thinking are simply two different names that always mean precisely the same single idea", "An algorithm is a computer, and algorithmic thinking is a type of computer program", "Algorithmic thinking is only used in maths lessons, and algorithms are only used in computing lessons"], "answer": 0, "explain": "Algorithmic thinking is the process of working out the steps; an algorithm is the result — the finished sequence of steps itself."}}, {"myth": "Believing computational thinking techniques must always be used in one fixed order and never revisited.", "truth": "In practice the three techniques are used <strong>flexibly</strong> — a programmer might return to abstraction or decomposition again if a sub-problem turns out to be too complex, rather than moving through them only once.", "check": {"question": "Must abstraction, decomposition and algorithmic thinking always be used in a strict, one-way order?", "options": ["No — a programmer can return to an earlier technique, such as decomposing a sub-problem further, if needed", "Yes, they must always be used in the exact same fixed order, with absolutely no exceptions ever allowed at all", "No, because only one of the three techniques is ever needed to solve any problem at all", "Yes, but only when the problem being solved involves numbers rather than any other kind of data"], "answer": 0, "explain": "The techniques are used flexibly — a programmer can revisit an earlier one (e.g. decomposing further) if a sub-problem is still too complex."}}]}, "tips": {"enabled": true, "items": [{"title": "Naming the right technique — look for the cue words", "html": "<p>\"Identify the technique used\" questions are answered by spotting <strong>cue words</strong> in the scenario, not by guessing.</p>\n<ul>\n<li><strong>Abstraction</strong> — look for words like <em>ignore, leave out, hide, simplify</em>, or \"only the detail that matters\".</li>\n<li><strong>Decomposition</strong> — look for words like <em>split, divide, break down</em>, or a problem described as several separate parts.</li>\n<li><strong>Algorithmic thinking</strong> — look for an <em>ordered list of steps</em>, or words like \"first, then, finally\".</li>\n</ul>\n<p>Always answer using the <strong>exact term</strong> the mark scheme expects — \"decomposition\", not \"breaking it into bits\" — and back it up with a short reason from the scenario.</p>", "check": {"question": "A scenario says an app designer ''decided the app did not need to record every user''s exact age, only whether they were under or over 18.'' Which cue tells you this is abstraction?", "options": ["The unnecessary detail (the exact age) has been simplified down to only what is needed", "The overall design task has been split into several separate, smaller sub-problems for different people to build", "The exact order of steps needed to check a user''s age has been written out in full", "The finished algorithm has been tested to make sure it works correctly every time"], "answer": 0, "explain": "Simplifying detail down to only what is needed (exact age → under/over 18) is the cue for abstraction, not decomposition, algorithmic thinking or testing."}}, {"title": "Explaining a benefit — always link it back to the problem", "html": "<p>\"State/explain one benefit of decomposition\" answers lose marks when they just repeat the definition. Structure your answer in <strong>two parts</strong>:</p>\n<ul>\n<li>1) Name the benefit — e.g. easier to test, easier to share between people, or a sub-problem can be reused.</li>\n<li>2) Explain <strong>why</strong> it helps, linked to the sub-problems being smaller and simpler than the whole problem.</li>\n</ul>\n<p><strong>Example:</strong> \"Decomposition makes a solution easier to test, because each small sub-problem can be checked on its own, rather than trying to test the whole complicated program all at once.\"</p>", "check": {"question": "Which answer best explains a benefit of decomposition, rather than just naming it?", "options": ["It is easier to test, because each small sub-problem can be checked separately rather than testing the whole program at once", "Testing", "It makes the entire problem completely disappear, meaning that no testing of any kind is ever required from anyone at all, under any circumstances", "Decomposition"], "answer": 0, "explain": "A full answer names the benefit AND explains why it happens (smaller sub-problems are easier to check individually) — a single word does not explain anything."}}, {"title": "Answering a longer ''apply computational thinking'' scenario question", "html": "<p>Longer questions describe a real problem and ask you to describe how computational thinking could be used to plan a solution. Structure your answer around the <strong>three techniques</strong>, one paragraph each:</p>\n<ul>\n<li><strong>Abstraction</strong> — say which details from the scenario would be kept, and which would be left out, and why.</li>\n<li><strong>Decomposition</strong> — say how the scenario''s problem could be split into named sub-problems.</li>\n<li><strong>Algorithmic thinking</strong> — say that the steps for one of those sub-problems would then be worked out in order.</li>\n</ul>\n<p>Use details from the <strong>scenario itself</strong> in each paragraph — a generic definition with no reference to the scenario will not gain full marks.</p>", "check": {"question": "A 6-mark question gives a scenario and asks how computational thinking could be applied to it. What is the best way to structure the answer?", "options": ["Cover each of abstraction, decomposition and algorithmic thinking in turn, applying each one to details from the scenario", "Write out only the plain dictionary definitions of the three separate terms, without referring to any specific detail from the scenario given in the question at all", "Focus entirely on writing the final program code needed to solve the scenario in a specific language", "Describe only decomposition in detail, since it is the single most important of the three techniques"], "answer": 0, "explain": "The strongest answers cover all three techniques and apply each one to the scenario''s own details, rather than giving generic definitions or code."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick <strong>one</strong> box to identify what <strong>abstraction</strong> means.</p>", "marks": 1, "hint": "Think about what is left OUT, not what is added.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Removing or hiding unnecessary detail so that only what matters is kept</strong></li></ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Only the correct option scores; 2 or more ticks scores 0.</li></ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box to identify what <strong>decomposition</strong> means.</p>", "marks": 1, "hint": "Think about splitting a problem into parts, not removing detail or writing steps.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Breaking a large, complex problem down into smaller, more manageable sub-problems</strong></li></ul>\n</div>"}, {"question": "<p>State what is meant by <strong>algorithmic thinking</strong>.</p>", "marks": 2, "hint": "Think about steps, order and logic — not about a finished program written in a particular language.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>Award 1 mark for: working out the step-by-step sequence of instructions / the logic.</li>\n<li>Award 1 mark for: needed to solve a problem (or sub-problem).</li>\n</ul>\n</div>"}, {"question": "<p>State <strong>one</strong> benefit of using decomposition when solving a large, complex problem.</p>", "marks": 2, "hint": "Name the benefit, then explain why breaking the problem into smaller sub-problems causes it.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>Award 1 mark for: a valid benefit (e.g. easier to test, easier to share between people, reusable solutions).</li>\n<li>Award 1 mark for: an explanation linking the benefit to sub-problems being smaller/simpler than the whole problem.</li>\n</ul>\n</div>"}, {"question": "<p>A student is planning a new solution. Tick <strong>one</strong> box in each row to identify which computational thinking technique is being used.</p>", "marks": 4, "hint": "Ask: is detail being removed (abstraction), is the problem being split into parts (decomposition), or is an order of steps being worked out (algorithmic thinking)?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Row 1 → <strong>Abstraction</strong></li>\n<li>Row 2 → <strong>Decomposition</strong></li>\n<li>Row 3 → <strong>Algorithmic thinking</strong></li>\n<li>Row 4 → <strong>Abstraction</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Each row is marked independently; 2+ ticks in a row scores 0 for that row.</li></ul>\n</div>"}, {"question": "<p>Draw <strong>one</strong> line from each term to what it means.</p><p>(There are more descriptions than terms — one description is not used.)</p>", "marks": 4, "hint": "Watch the decoy: ''translating into program code'' describes writing a program, which is not one of the four terms listed.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per correct line)</h5>\n<ul>\n<li>Abstraction → <strong>A</strong> (removing/hiding unnecessary detail)</li>\n<li>Decomposition → <strong>B</strong> (breaking a problem into smaller parts)</li>\n<li>Algorithmic thinking → <strong>C</strong> (working out the step-by-step sequence)</li>\n<li>Sub-problem → <strong>D</strong> (a smaller part of a larger problem)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>1 mark per correct line. Description E (''translating into program code'') is a decoy and is not used.</li></ul>\n</div>"}, {"question": "<p>Complete the paragraph about computational thinking by selecting terms from the list. <strong>Not all terms are used.</strong></p>", "marks": 3, "hint": "Removes detail → one term; splits into parts → one term; works out steps → one term. Iteration, selection and sequence are decoys from a different topic.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark for each completed term)</h5>\n<p>Before writing any code, a programmer uses computational thinking to plan a solution. <strong>Abstraction</strong> removes unnecessary detail so the important parts of the problem stand out. <strong>Decomposition</strong> then breaks the problem into smaller sub-problems. Finally, <strong>Algorithmic thinking</strong> works out the exact steps needed to solve each sub-problem.</p>\n</div>"}, {"question": "<p>Explain how decomposition can make a large, complex problem easier to solve. Give <strong>three</strong> separate points in your answer.</p>", "marks": 3, "hint": "Think about the size of each part, whether it can be tested alone, and whether it can be shared between people.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark: breaks the problem into smaller, more manageable sub-problems.</li>\n<li>1 mark: each sub-problem can be worked on/tested/understood on its own.</li>\n<li>1 mark: sub-problems can be shared between people, or tackled one at a time, reducing how much must be thought about at once.</li>\n</ul>\n</div>"}, {"question": "<p>A student says: \"An algorithm and algorithmic thinking are the same thing.\" Explain why the student is <strong>incorrect</strong>.</p>", "marks": 2, "hint": "One of them is a process; the other is the result of that process.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: algorithmic thinking is the process of working out the steps needed to solve a problem.</li>\n<li>1 mark: an algorithm is the result — the finished sequence of steps itself.</li>\n</ul>\n</div>"}, {"question": "<p>A school wants a new computer program that lets students book a library computer for a 30-minute slot.</p><p>Describe how a programmer could use computational thinking to plan a solution to this problem. Refer to <strong>abstraction</strong>, <strong>decomposition</strong> and <strong>algorithmic thinking</strong> in your answer.</p>", "marks": 6, "hint": "Cover all three techniques separately, and use details from the library booking scenario in each part — not just the dictionary definition.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks (2 marks per technique)</h5>\n<ul>\n<li><strong>Abstraction (2):</strong> keeps only needed detail (e.g. student ID, computer number, time slot), ignoring irrelevant detail (1); this simplifies the problem (1).</li>\n<li><strong>Decomposition (2):</strong> splits the problem into sub-problems, e.g. checking availability, checking for an existing booking, recording the booking (1); this makes each part easier to solve and test separately (1).</li>\n<li><strong>Algorithmic thinking (2):</strong> works out the ordered steps for a sub-problem, e.g. checking availability then saving a booking (1); this produces a clear algorithm that can become program code (1).</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Credit any equivalent, sensible application of each technique to the library booking scenario — the exact sub-problems named do not have to match the mark scheme.</li></ul>\n</div>"}]}}'::jsonb),
('computer-science', '2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', '{"learn": {"enabled": true, "items": [{"title": "Analysing a problem: Inputs, Processes, Outputs (IPO)", "html": "<h4>Break the problem down before you write any code</h4>\n<ul>\n<li>Before writing pseudocode, a programmer analyses the problem in terms of its <strong>Inputs, Processes and Outputs (IPO)</strong>.</li>\n<li><strong>Inputs</strong> — the data that must be entered or read in (from the user, a file, a sensor…).</li>\n<li><strong>Processes</strong> — what the program must DO to that data: calculations, decisions, repeats.</li>\n<li><strong>Outputs</strong> — what the program must produce or display as a result.</li>\n</ul>\n<p><strong>Example:</strong> \"Write a program that asks for three test scores and prints the average.\"</p>\n<div class=\"code-block\">Inputs:    three test scores\nProcesses: add the three scores together, then divide by 3\nOutputs:   the average score</div>\n<ul><li>Doing this FIRST stops you missing a requirement — and it is often asked for directly in the exam as an IPO table.</li></ul>", "check": {"question": "A program asks for a rectangle''s length and width, then displays its area. What is the PROCESS?", "options": ["Reading in the length and width values that the user has entered", "Multiplying the length by the width to work out the area", "Displaying the calculated area on the screen", "Storing the length and width as two separate named variables in memory, ready for later use"], "answer": 1, "explain": "The process is what the program DOES to the data — here, multiplying length by width. Reading in the values is the input; displaying the result is the output."}}, {"title": "Structure diagrams", "html": "<h4>Top-down design: breaking a big problem into small tasks</h4>\n<ul>\n<li>A <strong>structure diagram</strong> shows how a problem is broken down into smaller sub-tasks, drawn as a <strong>hierarchy chart</strong> with the whole problem at the top.</li>\n<li>This process is called <strong>top-down design (decomposition)</strong>: start with the overall task, split it into a few major sub-tasks, then split each of those into smaller steps if needed.</li>\n<li>Example: \"Print a school report\" might decompose into <strong>Get student data</strong>, <strong>Calculate grades</strong>, <strong>Format report</strong> and <strong>Print report</strong> — each shown as a box beneath the main task.</li>\n</ul>\n<div class=\"code-block\">            Print School Report\n          /       |         |        \\\n   Get data   Calculate   Format    Print\n              grades      report    report</div>\n<ul><li>Each box can later be developed as its own sub-program (subroutine) — this is why structure diagrams and subroutines link together.</li></ul>", "check": {"question": "What does a structure diagram show?", "options": ["How a problem is broken down into smaller sub-tasks, arranged as a hierarchy", "The exact pseudocode that will be typed to solve the whole problem, line by line", "The order that variables are declared and given their very first starting values", "The flow of data backwards and forwards between every input and output device used"], "answer": 0, "explain": "A structure diagram (hierarchy chart) shows top-down decomposition — how a big problem splits into smaller sub-tasks. It does not show pseudocode, declaration order or literal data flow."}}, {"title": "Flowchart symbols", "html": "<h4>The shapes used to draw an algorithm</h4>\n<ul>\n<li>A <strong>flowchart</strong> shows an algorithm using standard symbols, joined by <strong>flow lines (arrows)</strong> that show the order the steps happen in.</li>\n<li><strong>Terminal (stadium / rounded rectangle)</strong> — marks the <strong>start</strong> or <strong>stop</strong> of the algorithm. There is exactly one start and at least one stop.</li>\n<li><strong>Parallelogram</strong> — an <strong>input</strong> (reading a value in) or an <strong>output</strong> (displaying a value).</li>\n<li><strong>Rectangle</strong> — a <strong>process</strong> step: a calculation or an assignment.</li>\n<li><strong>Diamond</strong> — a <strong>decision</strong>: asks a yes/no question, and the flow splits into two branches (used for selection AND for loop conditions).</li>\n<li><strong>Rectangle with double side bars</strong> — a <strong>sub-program (subroutine)</strong> call: a separate, named piece of the algorithm defined elsewhere.</li>\n<li><strong>Arrow (flow line)</strong> — shows the <strong>direction</strong> the algorithm runs in, connecting one symbol to the next.</li>\n</ul>", "check": {"question": "Which flowchart symbol is used for a decision, such as testing IF a value is greater than 10?", "options": ["A diamond, which splits the flow into a Yes branch and a No branch", "A rectangle with double side bars, because that shape always represents any kind of decision", "A parallelogram, because the value being tested must first be read in as an input", "A terminal (stadium) shape, since decisions always happen at the very start of a flowchart"], "answer": 0, "explain": "A decision is always shown with a diamond, with the flow splitting into two branches depending on the answer. Rectangles with side bars are sub-programs, parallelograms are input/output, and terminals mark start/stop."}}, {"title": "Flowcharts: sequence and selection", "html": "<h4>Sequence and selection drawn as a flowchart</h4>\n<ul>\n<li>In a flowchart, <strong>sequence</strong> is shown by process/input/output boxes joined one after another by arrows, top to bottom.</li>\n<li><strong>Selection</strong> is shown by a <strong>diamond</strong>: the flow arrives, the diamond asks a yes/no question, and the flow splits into a <strong>Yes</strong> branch and a <strong>No</strong> branch. The branches usually re-join further down before the flowchart continues.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Flowchart (in words)</p><div class=\"code-block\">Start\n→ Input: age\n→ Decision: age &gt;= 18 ?\n   Yes → Output: \"Adult\"\n   No  → Output: \"Minor\"\n→ Stop</div></div>\n<div><p class=\"code-label\">Pseudocode (ERL)</p><div class=\"code-block\">age = input(\"Enter age: \")\nif age &gt;= 18 then\n  print(\"Adult\")\nelse\n  print(\"Minor\")\nendif</div></div>\n</div>", "check": {"question": "In a flowchart, how many arrows normally leave a decision (diamond) symbol?", "options": ["Two — one for the Yes branch and one for the No branch", "Just one, because a decision can only ever lead to a single outcome no matter what", "None at all, because a diamond always marks the very end of the whole flowchart", "Four, one for each of the possible answers a decision could ever have"], "answer": 0, "explain": "A decision diamond always has two exits — a Yes branch and a No branch — which is what makes selection possible in a flowchart."}}, {"title": "Flowcharts: iteration", "html": "<h4>Showing a loop in a flowchart</h4>\n<ul>\n<li><strong>Iteration</strong> is shown using a diamond too — but this time one branch loops <strong>back</strong> to an earlier point in the flowchart instead of moving on, creating a cycle.</li>\n<li>A <strong>pre-condition loop</strong> (like <code>while</code>) puts the diamond <strong>before</strong> the repeated steps — the flow can skip the loop entirely if the condition is already false.</li>\n<li>A <strong>post-condition loop</strong> (like <code>do…until</code>) puts the diamond <strong>after</strong> the repeated steps — those steps always run at least once before the condition is tested.</li>\n</ul>\n<div class=\"code-block\">Start\n→ count = 0\n→ Decision: count &lt; 3 ?\n   Yes → Output: count → count = count + 1 → (back to Decision)\n   No  → Stop</div>", "check": {"question": "In a flowchart for a while loop, where is the decision diamond drawn relative to the repeated steps?", "options": ["Before the steps, so the loop can be skipped if the condition is already false", "After the steps, so that the repeated steps are always guaranteed to run through at least one time first", "In the middle of the steps, splitting them exactly in half every single time", "Nowhere, because loops in a flowchart never use a decision diamond at all"], "answer": 0, "explain": "A while (pre-condition) loop puts the diamond BEFORE the repeated steps, so the flow can skip the loop entirely if the condition is already false. A do…until loop puts it after, guaranteeing at least one pass."}}, {"title": "Creating an algorithm: from problem to pseudocode", "html": "<h4>Turning a decomposed problem into pseudocode</h4>\n<ul>\n<li>Once a problem is broken into IPO and a structure diagram, each part is written up as <strong>pseudocode</strong> using the three constructs — sequence, selection, iteration — in <strong>ERL</strong>.</li>\n<li>A useful method: write each sub-task from the structure diagram as a short block of pseudocode, then put the blocks together in the right order.</li>\n</ul>\n<div class=\"code-block\">// Sub-task: get three scores and find the average\ntotal = 0\nfor i = 1 to 3\n  score = input(\"Enter score: \")\n  total = total + score\nnext i\naverage = total / 3\nprint(average)</div>\n<ul><li>Keep it simple and readable: use meaningful variable names (<code>total</code>, not <code>x</code>), and only use the constructs you actually need.</li></ul>", "check": {"question": "What is a sensible method for turning a structure diagram into pseudocode?", "options": ["Write each sub-task as a short block of pseudocode, then combine the blocks in the right order", "Write the whole algorithm in one single line so that it runs as fast as possible", "Start with the last sub-task in the diagram and work backwards to the first one", "Guess the pseudocode first without planning, and only draw the structure diagram afterwards once the code already works"], "answer": 0, "explain": "Writing each sub-task from the structure diagram as its own short block, then assembling the blocks in order, keeps the algorithm organised and matches how the problem was decomposed."}}, {"title": "Interpreting an algorithm — determining its purpose", "html": "<h4>Reading someone else''s code and working out what it does</h4>\n<ul>\n<li>The exam often gives you a short algorithm and asks you to state its <strong>purpose</strong> — what problem it solves — not to describe it line by line.</li>\n<li>Method: <strong>trace it mentally with a simple example</strong>, then describe the pattern in the outputs, not the individual steps.</li>\n</ul>\n<div class=\"code-block\">total = 0\ncount = 0\nfor i = 1 to 5\n  n = input(\"Enter a number: \")\n  total = total + n\n  count = count + 1\nnext i\nprint(total / count)</div>\n<ul><li>This algorithm reads 5 numbers, adds them up, and divides by how many there were — its <strong>purpose</strong> is: \"it calculates the <strong>average (mean)</strong> of 5 numbers entered by the user.\"</li></ul>", "check": {"question": "An algorithm reads 5 numbers, adds them together, then divides the total by 5. What is its PURPOSE?", "options": ["It calculates the average (mean) of 5 numbers entered by the user", "It only checks whether each of the 5 numbers entered is a positive number", "It sorts the 5 numbers into order from smallest to largest before displaying them", "It counts how many of the 5 numbers entered by the user are even numbers, one at a time"], "answer": 0, "explain": "Adding values then dividing by how many there were is the standard method for finding an average (mean) — that is the algorithm''s purpose, not sorting, validating or counting evens."}}, {"title": "Building a trace table", "html": "<h4>Hand-tracing an algorithm, one line at a time</h4>\n<ul>\n<li>A <strong>trace table</strong> records the value of each variable <strong>every time it changes</strong>, so you can work out exactly what an algorithm does for given input(s) — without running it.</li>\n<li>Method: draw one column per variable (plus an output column). Go through the algorithm <strong>line by line</strong>. Every time a line changes a variable, write its new value in that column on a new row. For a loop, repeat this for <strong>every pass</strong>.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Algorithm</p><div class=\"code-block\">total = 0\nfor i = 1 to 3\n  total = total + i\nnext i\nprint(total)</div></div>\n<div><p class=\"code-label\">Trace table</p><div class=\"code-block\">i  | total\n1  | 1\n2  | 3\n3  | 6\n\nOutput: 6</div></div>\n</div>\n<ul><li>Never skip a pass or guess — go slowly and mechanically, exactly as the computer would.</li></ul>", "check": {"question": "What is the golden rule for completing a trace table correctly?", "options": ["Go through the algorithm line by line, recording a variable''s new value every time it changes", "Skim the algorithm once and write down whichever output looks the most likely", "Only record the very last value each variable has, once the whole algorithm has finished", "Run every loop exactly once no matter how many times the condition actually says it should repeat, to save time"], "answer": 0, "explain": "A trace table must be built mechanically, line by line, updating a variable''s column every time that line changes it — including every single pass of a loop, not just the last one."}}, {"title": "Syntax errors", "html": "<h4>Errors that break the rules of the language</h4>\n<ul>\n<li>A <strong>syntax error</strong> breaks the grammar/rules of the programming language — the program will not run (or translate) at all until it is fixed.</li>\n<li>Common examples: a missing <code>endif</code> / <code>endwhile</code>, a missing bracket, a misspelt keyword, or mismatched quotation marks.</li>\n</ul>\n<div class=\"code-block\">if age &gt;= 18 then\n  print(\"Adult\")\n// missing endif — SYNTAX ERROR: the if statement is never closed</div>\n<ul><li>The translator (interpreter/compiler) usually reports a syntax error with a line number, because it cannot understand the instruction at all.</li></ul>", "check": {"question": "Which of these is an example of a SYNTAX error?", "options": ["An if statement that is never closed with its matching endif keyword", "A loop that repeats one time too many because of an incorrect condition", "A calculation that adds two values together when it should have multiplied them", "A condition that uses AND when the algorithm actually needed to use OR instead, giving the wrong result"], "answer": 0, "explain": "A missing endif breaks the rules of the language, so the program will not run at all — that''s a syntax error. The other options all describe programs that run but give the wrong answer (logic errors)."}}, {"title": "Logic errors", "html": "<h4>Errors that run — but give the wrong answer</h4>\n<ul>\n<li>A <strong>logic error</strong> follows the rules of the language perfectly (it runs without crashing) but produces the <strong>wrong result</strong>, because the programmer''s logic was flawed.</li>\n<li>Common examples: using <code>&lt;</code> where <code>&lt;=</code> was needed (off-by-one), swapping <code>AND</code>/<code>OR</code>, adding instead of multiplying, or using the wrong variable.</li>\n</ul>\n<div class=\"code-block\">total = 0\nfor i = 1 to 10\n  total = total + i\nnext i\naverage = total + 10   // LOGIC ERROR: should be total / 10</div>\n<ul><li>Logic errors are harder to find than syntax errors because the program runs successfully — you have to <strong>trace it</strong> and compare the output to what it should be.</li></ul>", "check": {"question": "Which of these is an example of a LOGIC error?", "options": ["A while loop''s counter is never updated inside the loop, so the loop never ends", "A missing closing quotation mark on a string of text being printed to the screen", "The keyword ''pritn'' is typed instead of ''print'', so the translator cannot understand it", "An endwhile keyword is left out completely, so the while loop is never properly closed"], "answer": 0, "explain": "The loop runs without breaking any language rules, but the missing update means the condition never becomes false — the program runs, just with the wrong (infinite) behaviour. That''s a logic error. The others are all syntax errors."}}, {"title": "Finding and correcting errors: syntax vs logic", "html": "<h4>Spotting which kind of error you are looking at</h4>\n<ul>\n<li>Ask: <strong>\"Will this even run?\"</strong> If no — it''s a <strong>syntax</strong> error (fix the broken rule: add the missing keyword/bracket/quote). If it runs but the <strong>output is wrong</strong> — it''s a <strong>logic</strong> error (fix the flawed condition/calculation/variable).</li>\n</ul>\n<div class=\"code-block\">while count &lt; 10\n  print(count)\n  count = count + 1\n// missing endwhile → SYNTAX (program won''t run)\n\nwhile count &lt; 10\n  print(count)\n// missing count = count + 1 → LOGIC (infinite loop, but no syntax error)</div>\n<ul><li>An infinite loop caused by a missing increment is a classic <strong>logic</strong> error: nothing is broken grammatically, the loop condition is just never made false.</li></ul>", "check": {"question": "What is the quickest first question to ask when classifying an error as syntax or logic?", "options": ["''Will this program even run?'' — if not, it''s syntax; if it runs but is wrong, it''s logic", "''Is the error found in the first line of the algorithm, or somewhere near the very last line instead?''", "''Does the error involve a loop, or does it involve an if statement instead?''", "''Is the variable name spelled correctly throughout the whole algorithm?''"], "answer": 0, "explain": "Asking whether the program runs at all separates the two error types instantly: won''t run → syntax; runs but the output is wrong → logic. The line number, construct used and spelling don''t tell you which type it is."}}, {"title": "Completing an algorithm", "html": "<h4>Filling in a missing line or condition</h4>\n<ul>\n<li>\"Complete the algorithm\" questions give you a working algorithm with one or more lines <strong>missing</strong>, and ask you to supply exactly what belongs there so it does what is described.</li>\n<li>Method: work out what the SURROUNDING lines need to be true. Match variable names already in use exactly, and check loop/condition boundaries carefully — off-by-one is the most common slip.</li>\n</ul>\n<div class=\"code-block\">total = 0\nfor i = 1 to ____        // must repeat 5 times → \"5\"\n  total = total + i\nnext i\nprint(____)               // must show the result → \"total\"</div>", "check": {"question": "When completing a missing line in a given algorithm, what should you check most carefully?", "options": ["That your line matches the variable names already used, and that any loop bounds are exactly right", "That your line is written in whichever real programming language you personally feel the most comfortable and confident using", "That your line is as short as possible, even if it does not do quite the right job", "That your line comes before the start of the algorithm rather than in the middle of it"], "answer": 0, "explain": "A completed line must fit its surroundings exactly — using the SAME variable names already in use, and getting loop/condition boundaries exactly right (off-by-one is the classic slip)."}}, {"title": "Refining an algorithm", "html": "<h4>Making a correct algorithm better</h4>\n<ul>\n<li><strong>Refining</strong> means improving an algorithm that already works — making it more efficient, more readable, or able to cope with more cases — without changing what it is meant to do.</li>\n<li>Common refinements: replacing repeated code with a <strong>loop</strong>, adding <strong>validation</strong> so bad input can''t break it, using better variable names, or combining nested selections into one clearer condition.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Before</p><div class=\"code-block\">print(input(\"Score 1: \"))\nprint(input(\"Score 2: \"))\nprint(input(\"Score 3: \"))</div></div>\n<div><p class=\"code-label\">Refined</p><div class=\"code-block\">for i = 1 to 3\n  print(input(\"Score \" + i + \": \"))\nnext i</div></div>\n</div>\n<ul><li>The refined version does the same job, but scales to any number of scores just by changing one number.</li></ul>", "check": {"question": "What does ''refining'' an algorithm mean?", "options": ["Improving an algorithm that already works, without changing what it is meant to do", "Fixing a syntax error so that a broken program is finally able to run at all", "Rewriting the algorithm from scratch to solve a completely different problem", "Deleting most of the algorithm''s lines so that it becomes as short as it can possibly be, whatever the cost"], "answer": 0, "explain": "Refining takes a CORRECT algorithm and makes it better — more efficient, readable or robust — without changing what it does. Fixing a syntax error is correcting, not refining."}}, {"title": "Nesting: selection inside selection", "html": "<h4>An if inside another if</h4>\n<ul>\n<li><strong>Nesting</strong> means putting one construct <strong>inside</strong> another. A common form is <strong>selection inside selection</strong>: an inner <code>if</code> only runs once the outer condition has already been met.</li>\n</ul>\n<div class=\"code-block\">if age &gt;= 17 then\n  if hasLicence == \"yes\" then\n    print(\"Can drive\")\n  else\n    print(\"Needs a licence\")\n  endif\nelse\n  print(\"Too young to drive\")\nendif</div>\n<ul><li>The inner <code>if</code> is only reached at all when <code>age &gt;= 17</code> is true — this lets an algorithm test a <strong>second condition</strong> that only makes sense once the first has been satisfied.</li></ul>", "check": {"question": "In an algorithm with an if statement nested inside another if statement, when does the INNER if get checked?", "options": ["Only once the outer if''s condition has already been found to be true", "Always, no matter what the outer if''s condition works out to be", "Only if the outer if statement''s condition has been found to be false instead", "Before the outer if statement has even been reached during execution"], "answer": 0, "explain": "A nested if is only reached — and only checked — once the flow has already entered the outer if''s branch, i.e. once the outer condition is true. It cannot run before the outer if, or if the outer condition was false."}}, {"title": "Nesting: selection and iteration inside a loop", "html": "<h4>An if inside a loop (and a loop inside a loop)</h4>\n<ul>\n<li>Putting <strong>selection inside iteration</strong> lets a loop make a different decision on <strong>every pass</strong>. Putting <strong>iteration inside iteration</strong> (a loop inside a loop) repeats the inner loop <strong>completely</strong> for every single pass of the outer loop.</li>\n</ul>\n<div class=\"code-block\">for i = 1 to 5\n  n = input(\"Enter a number: \")\n  if n MOD 2 == 0 then\n    print(n + \" is even\")\n  else\n    print(n + \" is odd\")\n  endif\nnext i</div>\n<ul><li>Here the <code>if</code> is nested inside the <code>for</code> loop, so every one of the 5 numbers is tested and labelled individually.</li></ul>", "check": {"question": "An if statement is placed inside a for loop. How many times is the if statement checked?", "options": ["Once for every single pass of the for loop", "Only once, no matter how many times the for loop repeats in total", "Exactly twice, regardless of how many passes the for loop actually makes", "Never, because a for loop and an if statement cannot be nested inside each other at all"], "answer": 0, "explain": "Nesting an if inside a for loop means the if''s condition is evaluated freshly on every pass of the loop — that''s what lets the loop make a different decision each time."}}]}, "terms": {"enabled": true, "pairs": [{"term": "IPO analysis", "definition": "Identifying a problem''s Inputs, Processes and Outputs before writing any code"}, {"term": "Structure diagram", "definition": "A hierarchy chart showing how a problem is broken down into sub-tasks (top-down decomposition)"}, {"term": "Terminal (stadium) symbol", "definition": "Marks the start or the stop of a flowchart"}, {"term": "Parallelogram", "definition": "Flowchart symbol for an input or an output step"}, {"term": "Rectangle", "definition": "Flowchart symbol for a process step (a calculation or assignment)"}, {"term": "Diamond", "definition": "Flowchart symbol for a decision, splitting the flow into two branches"}, {"term": "Sub-program symbol", "definition": "Rectangle with double side bars — a call to a named subroutine"}, {"term": "Flow line (arrow)", "definition": "Shows the direction an algorithm runs in"}, {"term": "Syntax error", "definition": "Breaks the rules of the language — the program will not run"}, {"term": "Logic error", "definition": "Runs without crashing, but gives the wrong result"}, {"term": "Trace table", "definition": "Records each variable''s value, line by line, as an algorithm runs"}, {"term": "Purpose of an algorithm", "definition": "What problem it solves — worked out by tracing it and describing the pattern in its outputs"}, {"term": "Refining an algorithm", "definition": "Improving a correct algorithm (efficiency/readability) without changing what it does"}, {"term": "Nesting", "definition": "Placing one construct inside another, e.g. an if inside a loop"}, {"term": "Completing an algorithm", "definition": "Filling in a missing line so it matches its surrounding code exactly"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of these is NOT one of the three parts of IPO analysis?", "options": ["Inputs", "Processes", "Outputs", "Operators"], "answer": 3, "explain": "IPO stands for Inputs, Processes and Outputs. Operators (like MOD or AND) are not one of the three parts of this analysis."}, {"question": "Which flowchart symbol shows an input or an output step?", "options": ["Parallelogram", "Diamond", "Rectangle", "Terminal (stadium) shape"], "answer": 0, "explain": "A parallelogram represents an input or an output. Diamonds are decisions, rectangles are processes, and terminals mark start/stop."}, {"question": "Which flowchart symbol marks the start or the stop of an algorithm?", "options": ["Terminal (stadium) shape", "Rectangle with double side bars, used for a sub-program instead", "Diamond, which is actually used for decisions rather than start/stop", "Parallelogram, which is actually used for input and output instead"], "answer": 0, "explain": "The terminal (stadium/rounded) shape marks the start or stop of a flowchart. The others represent sub-programs, decisions, and input/output."}, {"question": "Which type of error stops a program from running at all?", "options": ["Logic error", "Syntax error", "Runtime warning", "Boolean error"], "answer": 1, "explain": "A syntax error breaks the rules of the language, so the program cannot even run until it is fixed. A logic error still runs, just with the wrong result."}, {"question": "Which type of error allows a program to run, but produces the wrong result?", "options": ["Syntax error", "Logic error", "Compilation error", "Translation error"], "answer": 1, "explain": "A logic error obeys the rules of the language and runs successfully, but the programmer''s flawed reasoning means the output is wrong."}, {"question": "What is the main purpose of a trace table?", "options": ["To record the value of each variable as an algorithm runs, line by line", "To list every syntax error that the translator finds anywhere in the whole algorithm before it will run", "To draw the flowchart symbols used by an algorithm", "To count how many variables an algorithm uses in total"], "answer": 0, "explain": "A trace table tracks how each variable''s value changes as the algorithm executes, one line (and one loop pass) at a time — it is a way of testing an algorithm by hand."}, {"question": "What is a structure diagram used for?", "options": ["Showing how a problem is broken down into smaller sub-tasks, as a hierarchy", "Showing the exact order that a program''s variables are declared in memory", "Showing which flowchart symbols are the correct ones to use", "Showing precisely how much memory an algorithm will use once it has been fully compiled and is running"], "answer": 0, "explain": "A structure diagram (hierarchy chart) shows top-down decomposition — how a problem splits into smaller sub-tasks. It does not show memory use, declaration order or flowchart symbol choice."}, {"question": "Which construct is being used when an if statement is placed inside another if statement?", "options": ["Nesting", "Sequencing", "Casting", "Validation"], "answer": 0, "explain": "Placing one construct inside another — such as an if inside an if, or an if inside a loop — is called nesting."}, {"question": "A for loop is missing its closing ''next i'' line. What type of error is this?", "options": ["Logic error", "Syntax error", "Design error", "Output error"], "answer": 1, "explain": "The for loop''s structure is incomplete, breaking the rules of the language — the program will not run until ''next i'' is added. That makes it a syntax error."}, {"question": "A for loop is written as ''for i = 1 to 20'' when only 10 passes were wanted. What type of error is this, once the loop DOES run?", "options": ["Logic error", "Syntax error", "Compiler error", "Interpreter error"], "answer": 0, "explain": "The loop runs perfectly happily (it follows the rules), it just repeats the wrong number of times — a flawed piece of logic, not a broken rule. That makes it a logic error."}, {"question": "What does ''refining'' an algorithm mean?", "options": ["Improving an algorithm that already works, without changing what it does", "Fixing a syntax error in a program so that a completely broken piece of code is finally able to run at all", "Correcting a logic error so the output finally becomes right", "Deleting the algorithm and starting again from a blank page"], "answer": 0, "explain": "Refining means improving a CORRECT algorithm — e.g. making it more efficient, readable or robust — not fixing an error. Fixing broken code is correcting it, not refining it."}, {"question": "Which pair correctly matches the flowchart symbol to its meaning?", "options": ["Diamond = decision, Parallelogram = input/output", "Diamond = input/output, Rectangle = decision", "Parallelogram = decision, Rectangle = sub-program", "Rectangle = start/stop, Diamond = process"], "answer": 0, "explain": "A diamond represents a decision (splitting the flow into Yes/No), and a parallelogram represents an input or output — the other pairings mix up the symbols."}]}, "fib": {"enabled": true, "questions": [{"text": "A [syntax] error breaks the rules of the language, so the program will not even run."}, {"text": "A [logic] error runs without crashing, but produces the wrong result."}, {"text": "A [trace] table is used to record the value of each variable as an algorithm runs, line by line."}, {"text": "In a flowchart, a [diamond] symbol shows a decision, splitting the flow into two branches."}, {"text": "In a flowchart, a [parallelogram] symbol shows an input or an output step."}, {"text": "In a flowchart, a [terminal] shape marks the start or the stop of the algorithm."}, {"text": "Breaking a large problem down into smaller sub-tasks, shown as a hierarchy chart, is called [decomposition]."}, {"text": "Placing one construct inside another, such as an if statement inside a loop, is called [nesting]."}]}, "tf": {"enabled": true, "questions": [{"statement": "A syntax error stops a program from running at all.", "answer": true, "explain": "Correct — a syntax error breaks the rules of the language, so the program cannot run until it is fixed."}, {"statement": "A logic error always causes the program to crash immediately.", "answer": false, "explain": "A logic error runs without crashing — it just gives the wrong result. Crashing/not running at all describes a syntax error."}, {"statement": "A trace table is used to record the value of variables as an algorithm runs.", "answer": true, "explain": "Correct — that is exactly what a trace table is for, updated line by line (and pass by pass) as the algorithm executes."}, {"statement": "In a flowchart, a diamond symbol always represents an input or output step.", "answer": false, "explain": "A diamond represents a decision. A parallelogram is used for input/output steps."}, {"statement": "A structure diagram shows a problem broken down into smaller sub-tasks as a hierarchy.", "answer": true, "explain": "Correct — this is top-down decomposition, shown as a hierarchy (like a family tree) with the whole problem at the top."}, {"statement": "IPO stands for Inputs, Processes and Outputs.", "answer": true, "explain": "Correct — analysing a problem''s inputs, processes and outputs is done before writing an algorithm."}, {"statement": "Refining an algorithm means changing what problem it solves.", "answer": false, "explain": "Refining improves a CORRECT algorithm (efficiency, readability, robustness) without changing what it is meant to do."}, {"statement": "Nesting means placing one construct, such as an if statement, inside another.", "answer": true, "explain": "Correct — an if inside an if, or an if inside a loop, are both examples of nesting."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking every error that stops a program from working must be a ''logic error''.", "truth": "A <strong>logic</strong> error still RUNS — it just gives the wrong result. An error that stops the program running at all (like a missing <code>endif</code>) is a <strong>syntax</strong> error, because it breaks the rules of the language.", "check": {"question": "A program will not run at all because of a missing bracket. What type of error is this?", "options": ["Syntax error", "Logic error", "Runtime error", "Value error"], "answer": 0, "explain": "An error that stops the program from running breaks the rules of the language — that makes it a syntax error, not a logic error."}}, {"myth": "Believing a diamond symbol in a flowchart is just another process step.", "truth": "A diamond is specifically a <strong>decision</strong> symbol — it asks a yes/no question and the flow <strong>splits into two branches</strong>. A plain process step (like a calculation) uses a <strong>rectangle</strong> instead, which has only one way in and one way out.", "check": {"question": "How many exits does a flowchart rectangle (process) symbol normally have?", "options": ["One", "Two", "Three", "Zero"], "answer": 0, "explain": "A process rectangle has a single flow of instructions in and out. Two exits (Yes/No) is the signature of a decision diamond, not a process rectangle."}}, {"myth": "Thinking a while loop''s missing counter update is a syntax error.", "truth": "The loop''s grammar is perfectly correct — <code>while</code>/<code>endwhile</code> are matched properly, so it <strong>runs</strong>. It just never becomes false, so it repeats forever. Because the program runs (just wrongly), this is a <strong>logic</strong> error, not a syntax error.", "check": {"question": "A while loop repeats forever because its counter is never updated inside the loop body. What type of error is this?", "options": ["Logic error", "Syntax error", "Formatting error", "Naming error"], "answer": 0, "explain": "The loop obeys every rule of the language and runs — it just never stops, because the condition is never made false. That is a logic error."}}, {"myth": "Confusing a structure diagram with a flowchart.", "truth": "A <strong>structure diagram</strong> is a hierarchy chart showing how a problem is <strong>decomposed</strong> into sub-tasks — it has no decisions or arrows showing execution order. A <strong>flowchart</strong> shows the actual <strong>step-by-step logic</strong> of an algorithm, including decisions (diamonds) and loops.", "check": {"question": "Which diagram shows decisions and loops using standard symbols like a diamond?", "options": ["A flowchart", "A structure diagram", "An IPO table", "A trace table"], "answer": 0, "explain": "A flowchart shows an algorithm''s step-by-step logic, including decisions and loops. A structure diagram only shows decomposition into sub-tasks, with no decisions."}}, {"myth": "Thinking ''refining'' an algorithm means fixing a mistake in it.", "truth": "Refining assumes the algorithm <strong>already works correctly</strong>. It means making it <strong>better</strong> — more efficient, more readable, or able to handle more cases — without changing what it does. Fixing a mistake so it works correctly is <strong>correcting</strong> it, a different step.", "check": {"question": "An algorithm already gives the correct answer. A programmer rewrites it to be shorter and easier to read. What is this called?", "options": ["Refining", "Correcting", "Debugging", "Testing"], "answer": 0, "explain": "Improving a CORRECT algorithm — without changing its behaviour — is refining. Correcting and debugging both imply the algorithm was wrong to begin with."}}, {"myth": "Believing a trace table only needs the FINAL value of each variable.", "truth": "A trace table must record a variable''s value <strong>every time it changes</strong> — including on <strong>every pass</strong> of a loop — not just the value it ends up with. Skipping passes is how marks are lost, even if the final answer looks right.", "check": {"question": "A loop runs 4 times, changing ''total'' on every pass. How many values of ''total'' should a full trace table show?", "options": ["Four — one for every pass of the loop", "One — just the final value", "Two — the first and the last only", "None, because totals are not usually traced"], "answer": 0, "explain": "A trace table records a value every time it changes, so a 4-pass loop needs 4 rows for ''total'' — not just the final one."}}]}, "tips": {"enabled": true, "items": [{"title": "How to answer ''complete the algorithm'' questions", "html": "<p>\"Complete the algorithm\" questions give you a working algorithm with one or two lines removed — you don''t need to write the whole thing, just work out exactly what belongs in the gap.</p>\n<ul>\n<li>Read the <strong>whole</strong> algorithm first, including the lines AFTER the gap — they often reveal what the missing line must produce.</li>\n<li>Check the <strong>variable names</strong> already used and match them <strong>exactly</strong> (case and spelling matter).</li>\n<li>Check loop and condition <strong>boundaries</strong> carefully — \"1 to 5\" vs \"1 to 4\" is the classic off-by-one slip that loses marks.</li>\n</ul>\n<p><strong>Example:</strong> if the line after a for loop is <code>print(total)</code>, the loop itself must be building up a running total called <code>total</code> — that tells you what to write inside the loop body.</p>", "check": {"question": "What should you read FIRST before deciding what belongs in a missing line of an algorithm?", "options": ["The whole algorithm, including the lines that come after the gap", "On every single line of the algorithm you are given, regardless of whether it changes anything at all", "Only the title given to the exam question itself", "The mark scheme, which is always printed just below the question"], "answer": 0, "explain": "Reading the lines AFTER the gap often reveals exactly what the missing line needs to produce, e.g. a variable that gets printed later."}}, {"title": "Classifying syntax vs logic errors fast", "html": "<p>\"Is this a syntax error or a logic error?\" is one of the most repeated question types on this topic. Use one quick test:</p>\n<ul>\n<li>Ask: <strong>\"Would this program even run?\"</strong></li>\n<li>If <strong>no</strong> — a rule of the language has been broken (missing keyword, bracket, quote) — it''s a <strong>syntax</strong> error.</li>\n<li>If <strong>yes</strong>, but the <strong>output is wrong</strong> — the language rules are fine, the programmer''s reasoning was flawed — it''s a <strong>logic</strong> error.</li>\n</ul>\n<p><strong>Watch for:</strong> a missing loop-update (infinite loop), the wrong comparison (<code>&lt;</code> instead of <code>&lt;=</code>), or a swapped <code>AND</code>/<code>OR</code> — these all still RUN, so they are logic errors, even though the result is clearly broken.</p>", "check": {"question": "A condition uses OR when it should have used AND, so the algorithm behaves incorrectly. What type of error is this?", "options": ["Logic error", "Syntax error", "Grammar error", "Compilation error"], "answer": 0, "explain": "Swapping AND and OR doesn''t break any language rule — the program runs — it just makes the wrong decision. That is a logic error."}}, {"title": "Writing a clean trace table under exam pressure", "html": "<p>Trace-table questions are marked <strong>row by row</strong> (or pass by pass), so a slow, organised table scores far better than a fast guess.</p>\n<ul>\n<li>Copy the <strong>column headers</strong> the question gives you exactly, in the same order.</li>\n<li>Go through the algorithm <strong>one line at a time</strong>. Only write a new value in a column when that line actually <strong>changes</strong> that variable.</li>\n<li>For a loop, treat each pass as its own row — never merge two passes together or skip a pass \"because it''s obvious\".</li>\n</ul>\n<p>If you lose track, restart the trace from the beginning rather than guessing the rest — a fully correct restart earns more marks than a table that goes wrong halfway through.</p>", "check": {"question": "In a trace table, when should you write a new value in a variable''s column?", "options": ["Only on the exact line where that variable''s value actually changes", "On every single line of the algorithm you are given, regardless of whether it changes anything at all", "Only once, right at the very end of the whole algorithm", "Only when the algorithm prints something to the screen"], "answer": 0, "explain": "A trace table column only gets a new entry when that specific line changes the variable — not on every line, and not just once at the end."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick <strong>one</strong> box to identify the flowchart symbol used to show a decision, such as testing IF a value meets a condition.</p>", "marks": 1, "hint": "Which shape has two exits — a Yes branch and a No branch?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Diamond</strong></li></ul>\n</div>"}, {"question": "<p>A program runs without crashing, but a shop''s discount calculator always gives an answer that is £10 too high. Tick <strong>one</strong> box to identify the type of error.</p>", "marks": 1, "hint": "The program runs successfully — it just produces the wrong number. Does that sound like a broken rule, or a flawed calculation?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Logic error</strong> — the program runs, but the calculation itself is wrong.</li></ul>\n</div>"}, {"question": "<p>State <strong>one</strong> difference between a <strong>syntax error</strong> and a <strong>logic error</strong>.</p>", "marks": 2, "hint": "Think about which one stops the program running, and which one lets it run but gives the wrong result.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>Award 1 mark for: a syntax error breaks the rules of the language, so the program will not run.</li>\n<li>Award 1 mark for: a logic error runs without crashing, but produces the wrong result.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Both sides of the contrast are needed for full marks.</li></ul>\n</div>"}, {"question": "<p>A booking system reads in a customer''s chosen seat number, checks whether that seat is already taken, works out the total price, and displays a confirmation message.</p><p>Complete the table by classifying each statement as an <strong>Input</strong>, a <strong>Process</strong> or an <strong>Output</strong>.</p>", "marks": 3, "hint": "Ask each time: is this data going IN, is something being WORKED OUT, or is a result being SHOWN?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark for each row)</h5>\n<ul>\n<li>Reading in the seat number → <strong>Input</strong></li>\n<li>Checking availability and calculating the price → <strong>Process</strong></li>\n<li>Displaying the confirmation message → <strong>Output</strong></li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to classify the described error as a <strong>syntax error</strong> or a <strong>logic error</strong>.</p>", "marks": 4, "hint": "Ask each time: would this stop the program from running at all, or does it run but give the wrong result?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Missing endif → <strong>Syntax error</strong></li>\n<li>Counter never updated (infinite loop) → <strong>Logic error</strong></li>\n<li>''whlie'' misspelt → <strong>Syntax error</strong></li>\n<li>Loop bound wrong (1 to 20 instead of 1 to 10) → <strong>Logic error</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Each row is marked independently; 2+ ticks in a row scores 0 for that row.</li></ul>\n</div>"}, {"question": "<p>Draw <strong>one</strong> line from each flowchart symbol to what it represents.</p><p>(There are more descriptions than symbols — one description is not used.)</p>", "marks": 4, "hint": "Watch the decoy: ''marks the start or stop'' describes the terminal (stadium) shape, which is not one of the four symbols listed.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per correct line)</h5>\n<ul>\n<li>Diamond → <strong>A</strong> (decision, splitting into Yes/No)</li>\n<li>Parallelogram → <strong>B</strong> (input or output)</li>\n<li>Rectangle → <strong>C</strong> (process step)</li>\n<li>Rectangle with double side bars → <strong>D</strong> (sub-program call)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>1 mark per correct line. Description E (''marks the start or stop'') is a decoy describing the terminal shape, and is not used.</li></ul>\n</div>"}, {"question": "<p>The algorithm below reads 20 numbers, one at a time.</p><pre>count = 0\nfor i = 1 to 20\n  n = input(\"Enter a number: \")\n  if n MOD 2 == 0 then\n    count = count + 1\n  endif\nnext i\nprint(count)</pre><p>State the <strong>purpose</strong> of this algorithm.</p>", "marks": 2, "hint": "Trace it with a couple of made-up numbers. What does ''count'' end up representing?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: the algorithm reads in 20 numbers entered by the user.</li>\n<li>1 mark: it counts how many of those 20 numbers are even.</li>\n</ul>\n</div>"}, {"question": "<p>The algorithm below reads four numbers, one at a time, and keeps track of the largest number seen so far.</p><pre>maxVal = 0\nfor i = 1 to 4\n  n = input(\"Enter a number: \")\n  if n &gt; maxVal then\n    maxVal = n\n  endif\nnext i\nprint(maxVal)</pre><p>The user enters, in this order: <strong>4, 9, 2, 7</strong>.</p><p>Complete the trace table to show the value of <strong>i</strong>, <strong>n</strong> and <strong>maxVal</strong> at the end of each pass of the loop.</p>", "marks": 4, "hint": "maxVal only changes when n is bigger than the current maxVal. It stays the same otherwise.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per correct row of the trace)</h5>\n<ul>\n<li>Pass 1 → i = 1, n = 4, maxVal = 4</li>\n<li>Pass 2 → i = 2, n = 9, maxVal = 9</li>\n<li>Pass 3 → i = 3, n = 2, maxVal = 9 (unchanged — 2 is not greater than 9)</li>\n<li>Pass 4 → i = 4, n = 7, maxVal = 9 (unchanged — 7 is not greater than 9)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>1 mark for each fully-correct row of the trace (all three columns right). The program finally outputs 9.</li></ul>\n</div>"}, {"question": "<p>The algorithm below should print, for each whole number from 1 to 10, whether that number is even or odd.</p><p>Complete the three gaps.</p>", "marks": 3, "hint": "The loop must cover 1 to 10; each pass tests whether the remainder after dividing by 2 EQUALS 0; a for loop is closed with ''next'' followed by its own counter.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per gap)</h5>\n<ul>\n<li>Gap 1: <strong>10</strong></li>\n<li>Gap 2: <strong>==</strong></li>\n<li>Gap 3: <strong>i</strong></li>\n</ul>\n</div>"}, {"question": "<p>State <strong>one</strong> difference between a <strong>structure diagram</strong> and a <strong>flowchart</strong>.</p>", "marks": 2, "hint": "Think about whether each one shows decisions and the order of execution, or just how the problem is split up.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: a structure diagram shows a problem broken down into sub-tasks, as a hierarchy.</li>\n<li>1 mark: a flowchart shows the step-by-step order an algorithm runs in, including decisions and loops.</li>\n</ul>\n</div>"}, {"question": "<p>The algorithm below uses a nested selection.</p><pre>mark = 55\nattendance = \"good\"\nif mark &gt;= 50 then\n  if attendance == \"good\" then\n    print(\"Pass with merit\")\n  else\n    print(\"Pass\")\n  endif\nelse\n  print(\"Fail\")\nendif</pre><p>State the output of this algorithm, and explain how the nested if statements produce it.</p>", "marks": 3, "hint": "First check whether the OUTER condition (mark) is true. Only if it is, check the INNER condition (attendance).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark: output is <strong>Pass with merit</strong></li>\n<li>1 mark: mark &gt;= 50 is true (55 &gt;= 50), so the outer if branch — and the inner if — is reached</li>\n<li>1 mark: attendance == \"good\" is also true, so the nested if branch runs and prints \"Pass with merit\"</li>\n</ul>\n</div>"}, {"question": "<p>Write an algorithm, using pseudocode, that:</p><ul><li>repeatedly asks the user to enter a whole number, until they enter a number from 1 to 100 inclusive, and</li><li>then prints the valid number.</li></ul><p>You may answer in OCR Exam Reference Language or in a high-level language you know.</p>", "marks": 4, "hint": "You don''t know in advance how many attempts the user will need, so use a condition-controlled loop (while or do…until) that repeats until the number is valid.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks — mark the logic (accept any equivalent code)</h5>\n<ul>\n<li>1 mark: uses a loop (do…until or while) to repeat the input</li>\n<li>1 mark: reads a whole number as input inside the loop</li>\n<li>1 mark: correct condition combining the lower bound (1) and upper bound (100) with AND</li>\n<li>1 mark: prints the valid number after the loop ends</li>\n</ul>\n<p>Example (ERL):</p>\n<div class=\"code-block\">do\n  num = input(\"Enter a number 1-100: \")\nuntil num >= 1 AND num <= 100\nprint(num)</div>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Any logically correct answer scores full marks — mark the logic, not the exact wording or choice of language.</li></ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box to identify what ''refining'' an algorithm means.</p>", "marks": 1, "hint": "Refining assumes the algorithm is already CORRECT — it''s about making it better, not fixing it.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Improving an algorithm that already works, without changing what it does</strong></li></ul>\n</div>"}]}}'::jsonb),
('computer-science', '2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', '{"learn": {"enabled": true, "items": [{"title": "Searching and sorting: the big picture", "html": "<h4>Two jobs a computer very often needs to do with a list</h4>\n<ul>\n<li>A <strong>search algorithm</strong> looks through a list of data to find out whether a particular value is present — and if it is, where it is.</li>\n<li>A <strong>sort algorithm</strong> rearranges a list into order (usually smallest to largest — <strong>ascending order</strong>).</li>\n<li>For this topic you need to know <strong>two</strong> search algorithms — <strong>linear search</strong> and <strong>binary search</strong> — and <strong>three</strong> sort algorithms — <strong>bubble sort</strong>, <strong>merge sort</strong> and <strong>insertion sort</strong>.</li>\n<li>For each one you need to be able to: describe its <strong>main steps</strong>, <strong>apply it by hand</strong> to a small list (showing the list after each step or pass), and <strong>identify it</strong> from a description of how it behaves. You do <strong>not</strong> need to memorise the exact pseudocode or program code for any of them.</li>\n</ul>", "check": {"question": "Which TWO kinds of algorithm does this topic cover?", "options": ["Compression algorithms, which make files smaller, and encryption algorithms, which make data secret", "Search algorithms and sort algorithms", "Validation algorithms, which check data as it is entered, and verification algorithms, which check it again later", "Translator algorithms, which convert code, and scheduling algorithms, which share out processor time"], "answer": 1, "explain": "This topic covers search algorithms (find a value in a list) and sort algorithms (put a list into order)."}}, {"title": "Linear search — how it works", "html": "<h4>Check every item, one at a time, from the start</h4>\n<ul>\n<li>A <strong>linear search</strong> starts at the <strong>first</strong> item in the list and checks it against the target value.</li>\n<li>If it matches, the search <strong>stops</strong> — the item has been found.</li>\n<li>If it does not match, the search moves on to the <strong>next</strong> item, and repeats.</li>\n<li>If the <strong>end of the list</strong> is reached with no match, the target is <strong>not in the list</strong>.</li>\n</ul>\n<div class=\"code-block\">Main steps\n1. Start at the first item in the list.\n2. Compare the current item to the target.\n3. If it matches, stop — report where it was found.\n4. If not, move to the next item.\n5. If there are no more items, report \"not found\".\n   Otherwise, go back to step 2.</div>\n<ul>\n<li>Because it checks items in whatever order they appear, a linear search will work on a list that is <strong>sorted OR unsorted</strong> — that''s its big advantage over binary search.</li>\n</ul>", "check": {"question": "Does a linear search require the list to be sorted first?", "options": ["Yes, otherwise it will keep skipping over items and might completely miss the target value it is looking for", "No — it checks items in the order they appear, so it works on a sorted or unsorted list", "Yes, but only when the list contains more than about ten items in total", "No, but only when every item in the list is a whole number rather than a decimal"], "answer": 1, "explain": "A linear search simply checks each item in turn, so the order of the list makes no difference — it works on any list."}}, {"title": "Linear search — worked example", "html": "<h4>Searching the list  12, 7, 19, 3, 25, 8  for the value 25</h4>\n<div class=\"code-block\">Index:   0    1    2    3    4    5\nValue:  12    7   19    3   25    8\n\nCheck index 0 → 12 ≠ 25 → keep going\nCheck index 1 →  7 ≠ 25 → keep going\nCheck index 2 → 19 ≠ 25 → keep going\nCheck index 3 →  3 ≠ 25 → keep going\nCheck index 4 → 25 = 25 → FOUND at index 4</div>\n<ul>\n<li>It took <strong>5</strong> comparisons to find 25, because it happens to be near the end of the list.</li>\n<li><strong>If the target is not in the list at all</strong> (e.g. searching for 6), a linear search still has to check <strong>every</strong> item — all 6 of them — before it can report \"not found\". This worst case is what makes a linear search slow on a long list.</li>\n</ul>", "check": {"question": "In the worked example, how many comparisons does the linear search make before it finds 25?", "options": ["4, since 25 is stored at index 4 and index numbers always match the comparison count exactly", "5", "6, which is the total number of items that are stored in the list being searched", "1, because a linear search always finds a matching item on its very first comparison"], "answer": 1, "explain": "The search checks index 0, 1, 2, 3 and then 4 (where 25 is found) — that''s 5 comparisons in total."}}, {"title": "Binary search — how it works", "html": "<h4>Repeatedly check the middle of a SORTED list</h4>\n<ul>\n<li>A <strong>binary search</strong> only works on a list that is already <strong>sorted</strong>. This is essential — the whole method relies on being able to rule out half the list at a time.</li>\n<li>Each pass, it checks the item exactly in the <strong>middle</strong> of the section still being searched.</li>\n<li>If the middle item <strong>matches</strong> the target, the search is over.</li>\n<li>If the target is <strong>smaller</strong> than the middle item, the whole <strong>right-hand half</strong> can be discarded (it must be further left).</li>\n<li>If the target is <strong>larger</strong> than the middle item, the whole <strong>left-hand half</strong> can be discarded.</li>\n<li>This repeats on the remaining half, and the remaining half, until the target is found or there is nothing left to check.</li>\n</ul>\n<div class=\"code-block\">Main steps\n1. The list MUST be sorted first.\n2. Look at the middle item of the current section.\n3. If it matches the target, stop — found.\n4. If the target is smaller, discard the right half and repeat on the left half.\n5. If the target is larger, discard the left half and repeat on the right half.\n6. If the section becomes empty, report \"not found\".</div>", "check": {"question": "What must be true about a list before a binary search can be used on it?", "options": ["The list must contain an even number of items, or the middle item cannot be worked out", "The list must already be sorted", "The list must contain fewer than one hundred items in total", "The list must not contain any repeated values anywhere within it"], "answer": 1, "explain": "Binary search discards half the list at a time based on order, so it only gives correct results on a list that is already sorted."}}, {"title": "Binary search — worked example", "html": "<h4>Searching the sorted list  3, 7, 8, 12, 19, 25, 31, 40  for the value 19</h4>\n<div class=\"code-block\">Index:    0   1   2   3   4   5   6   7\nValue:    3   7   8  12  19  25  31  40\n\nPass 1: low=0, high=7 → mid = (0+7) DIV 2 = 3 → value 12\n        12 &lt; 19, so discard the LEFT half → search index 4 to 7\n\nPass 2: low=4, high=7 → mid = (4+7) DIV 2 = 5 → value 25\n        25 &gt; 19, so discard the RIGHT half → search index 4 to 4\n\nPass 3: low=4, high=4 → mid = (4+4) DIV 2 = 4 → value 19\n        19 = 19 → FOUND at index 4</div>\n<ul>\n<li>It took only <strong>3</strong> comparisons to find 19 in an 8-item list — a linear search could have needed up to 8. That gap grows much bigger as the list gets longer.</li>\n</ul>", "check": {"question": "In the worked example, what happens after the first comparison (mid = 12) because 12 is LESS than the target 19?", "options": ["The whole list is searched again from the very beginning, starting again at index 0", "The right half of the list (from index 4 to 7) is searched next", "The left half of the list (from index 0 to 2) is searched next", "The search stops immediately and reports that 19 is not in the list"], "answer": 1, "explain": "Because 19 is bigger than the middle value 12, the target must be further right, so the left half is discarded and index 4–7 is searched next."}}, {"title": "Comparing linear and binary search", "html": "<h4>Same job, very different performance</h4>\n<ul>\n<li><strong>Order of the list:</strong> a linear search works on a list in <strong>any</strong> order. A binary search <strong>needs the list sorted first</strong> — and sorting a list also takes time.</li>\n<li><strong>Speed on a large list:</strong> a linear search may need to check <strong>every</strong> item (in the worst case). A binary search discards <strong>half</strong> the remaining items at every step, so it needs far fewer comparisons — the bigger the list, the bigger this advantage becomes.</li>\n<li><strong>When linear search still makes sense:</strong> for a <strong>short</strong> list, or a list that is <strong>not already sorted</strong> and will only be searched once, sorting it first just to use a binary search may cost more time than it saves.</li>\n</ul>", "check": {"question": "Why might a programmer choose a linear search instead of a binary search, even though binary search needs fewer comparisons?", "options": ["Because a linear search always gives a far more accurate and reliable result than a binary search is ever able to give", "Because the list is not already sorted, and sorting it first would take extra time that may not be worth it", "Because a linear search can be used on lists but a binary search can only be used on single values", "Because a binary search is not able to report whether a value is missing from the list at all"], "answer": 1, "explain": "Binary search needs the list sorted first. If the list isn''t already sorted (and won''t be searched many times), a linear search can be the more practical choice."}}, {"title": "Bubble sort — how it works", "html": "<h4>Repeatedly compare and swap neighbours</h4>\n<ul>\n<li>A <strong>bubble sort</strong> compares each pair of <strong>adjacent</strong> (next-door) items, from the start of the list to the end.</li>\n<li>If a pair is in the <strong>wrong order</strong>, the two items are <strong>swapped</strong>.</li>\n<li>One full run through the list like this is called a <strong>pass</strong>. Each pass \"bubbles\" the largest unsorted item along the list until it reaches its correct place at the end.</li>\n<li>The algorithm keeps making passes until a pass is completed with <strong>no swaps</strong> — that means the list is fully sorted, so it stops.</li>\n</ul>\n<div class=\"code-block\">Main steps\n1. Go through the list comparing each pair of adjacent items.\n2. If a pair is in the wrong order, swap them.\n3. Continue to the end of the list — that is one pass.\n4. If any swap was made during the pass, do another pass.\n5. If a whole pass makes no swaps, the list is sorted — stop.</div>", "check": {"question": "How does a bubble sort know that the list is now fully sorted and it can stop?", "options": ["It stops as soon as it has completed exactly one single pass through the list, no matter what", "A pass is completed in which no swaps were made", "It stops once the first item happens to be smaller than the last item in the list", "It always makes exactly the same fixed number of passes, worked out before it starts"], "answer": 1, "explain": "Bubble sort keeps making passes until one pass makes no swaps at all — that is the signal that the list is in order."}}, {"title": "Bubble sort — worked example", "html": "<h4>Sorting  5, 1, 4, 2, 8  into ascending order</h4>\n<div class=\"code-block\">Start:            5, 1, 4, 2, 8\n\nPass 1\ncompare 5,1 → swap →  1, 5, 4, 2, 8\ncompare 5,4 → swap →  1, 4, 5, 2, 8\ncompare 5,2 → swap →  1, 4, 2, 5, 8\ncompare 5,8 → no swap\nAfter Pass 1:     1, 4, 2, 5, 8   (swaps made → do another pass)\n\nPass 2\ncompare 1,4 → no swap\ncompare 4,2 → swap →  1, 2, 4, 5, 8\ncompare 4,5 → no swap\ncompare 5,8 → no swap\nAfter Pass 2:     1, 2, 4, 5, 8   (a swap was made → do another pass)\n\nPass 3\ncompare 1,2 → no swap\ncompare 2,4 → no swap\ncompare 4,5 → no swap\ncompare 5,8 → no swap\nAfter Pass 3:     1, 2, 4, 5, 8   (NO swaps made → sorted, stop)</div>\n<ul>\n<li>Notice how the largest value, 8, never has to move — and how 5 \"bubbles\" one place to the right on each of the first two passes until it reaches its final position.</li>\n</ul>", "check": {"question": "In the worked example, what does the list look like immediately after Pass 1?", "options": ["5, 1, 4, 2, 8, because nothing at all changes on the very first pass of a bubble sort", "1, 4, 2, 5, 8", "1, 2, 4, 5, 8, because the list always finishes fully sorted after only one pass", "8, 5, 4, 2, 1, because the largest item always moves to the very front of the list first"], "answer": 1, "explain": "Working through the comparisons for Pass 1 (5,1 → 5,4 → 5,2 → 5,8) leaves the list as 1, 4, 2, 5, 8."}}, {"title": "Merge sort — how it works", "html": "<h4>Divide and conquer: split, then merge back in order</h4>\n<ul>\n<li>A <strong>merge sort</strong> is a <strong>divide and conquer</strong> algorithm — it solves a big problem by breaking it into smaller versions of the same problem.</li>\n<li><strong>Divide:</strong> split the list exactly in half, then split each half in half again, and so on, until every part contains just <strong>one</strong> item. A list of one item is always \"sorted\".</li>\n<li><strong>Conquer (merge):</strong> merge pairs of sorted parts back together, always placing the <strong>smaller</strong> of the two items being compared next into the result. Keep merging larger and larger sorted parts until the whole list is back together, fully sorted.</li>\n</ul>\n<div class=\"code-block\">Main steps\n1. If the list has more than one item, split it into two halves.\n2. Repeat step 1 on each half, until every part has only one item.\n3. Merge pairs of parts back together: compare the front item of each\n   part, and move the smaller one into the result.\n4. Keep merging until the whole list has been rebuilt, in order.</div>\n<ul>\n<li>Because it never compares every possible pair of items (unlike a bubble sort), a merge sort needs far fewer comparisons on a large list — but it is more complex to write, and needs extra memory to hold the split parts while they are merged.</li>\n</ul>", "check": {"question": "What does ''divide and conquer'' mean in the context of a merge sort?", "options": ["Comparing every single pair of items in the whole list against one another, one pair at a time until finished", "Splitting the list into smaller parts, sorting/merging those parts, then combining the results", "Always removing the smallest item from the list first before doing anything else to it", "Repeatedly checking the middle item of the list and discarding a half that cannot contain it"], "answer": 1, "explain": "Divide and conquer means breaking the list into smaller parts (down to single items), then combining (merging) the results back together in order."}}, {"title": "Merge sort — worked example", "html": "<h4>Sorting  8, 3, 7, 4  with merge sort</h4>\n<div class=\"code-block\">Divide\n[8, 3, 7, 4]\n   ↓ split\n[8, 3]        [7, 4]\n   ↓ split       ↓ split\n[8] [3]       [7] [4]     ← every part now has one item (already \"sorted\")\n\nMerge\nMerge [8] and [3]  → compare 8, 3 → 3 is smaller → [3, 8]\nMerge [7] and [4]  → compare 7, 4 → 4 is smaller → [4, 7]\n\nMerge [3, 8] and [4, 7]:\n  compare 3, 4 → 3 is smaller → result so far: 3\n  compare 8, 4 → 4 is smaller → result so far: 3, 4\n  compare 8, 7 → 7 is smaller → result so far: 3, 4, 7\n  only 8 remains in the left part → copy it in → result: 3, 4, 7, 8\n\nFinal sorted list: 3, 4, 7, 8</div>\n<ul>\n<li>The FINAL merge step is the one most worth practising: keep comparing the <strong>front</strong> item of each part and taking the smaller, and once one part runs out, copy across whatever is left of the other part.</li>\n</ul>", "check": {"question": "When merging the sorted parts 3, 8 and 4, 7 back together, which value is placed into the result FIRST?", "options": ["8, because a merge always starts by comparing the two largest items from each part first", "3, because 3 is the smaller of the two front items (3 and 4) being compared", "4, because a merge always takes its first item from the second part of the pair given", "7, because that is the largest value out of all four values in the two parts put together"], "answer": 1, "explain": "The front items of each part are compared first: 3 (from the left part) and 4 (from the right part). 3 is smaller, so it is placed into the result first."}}, {"title": "Insertion sort — how it works", "html": "<h4>Build up a sorted section, one item at a time</h4>\n<ul>\n<li>An <strong>insertion sort</strong> treats the list as having two parts: a <strong>sorted section</strong> at the start, and an <strong>unsorted section</strong> after it.</li>\n<li>At the beginning, the sorted section is just the <strong>first item</strong> (a list of one item is always \"sorted\").</li>\n<li>Each step, the next item from the unsorted section is picked up and <strong>compared to the sorted items</strong>, working from the right-hand (largest) end of the sorted section.</li>\n<li>Items in the sorted section that are <strong>bigger</strong> than the new item are <strong>shifted one place to the right</strong> to make room. This stops once a smaller item is found (or there are no more items to compare with).</li>\n<li>The new item is then <strong>inserted</strong> into the gap — which grows the sorted section by one item.</li>\n</ul>\n<div class=\"code-block\">Main steps\n1. Treat the first item as a sorted section of one item.\n2. Take the next item from the unsorted section.\n3. Compare it to items in the sorted section, from the right-hand end.\n4. Shift any sorted item that is bigger one place to the right.\n5. Insert the new item into the gap this leaves.\n6. Repeat from step 2 until every item has been inserted.</div>", "check": {"question": "In an insertion sort, which direction does a new item get compared against the sorted section?", "options": ["From the left-hand (smallest) end of the sorted section, moving rightwards through it", "From the right-hand (largest) end of the sorted section, moving leftwards through it", "Against the exact middle item of the sorted section only, in a single comparison", "Against every single item in the WHOLE list, including the unsorted section as well"], "answer": 1, "explain": "A new item is compared against the sorted section starting from its right-hand (largest) end, shifting larger items rightward as it goes."}}, {"title": "Insertion sort — worked example", "html": "<h4>Sorting  6, 2, 9, 4  with insertion sort</h4>\n<div class=\"code-block\">Start:               6, 2, 9, 4\nSorted section:      [6]            unsorted: 2, 9, 4\n\nStep 1 — insert 2\n2 &lt; 6, so shift 6 right, insert 2 before it\nList:                2, 6, 9, 4\nSorted section:      [2, 6]         unsorted: 9, 4\n\nStep 2 — insert 9\n9 &gt; 6 (the rightmost sorted item), so no shifting needed — insert 9 here\nList:                2, 6, 9, 4\nSorted section:      [2, 6, 9]      unsorted: 4\n\nStep 3 — insert 4\n4 &lt; 9, shift 9 right\n4 &lt; 6, shift 6 right\n4 &gt; 2, stop shifting — insert 4 here\nList:                2, 4, 6, 9\nSorted section:      [2, 4, 6, 9]   unsorted: (none) — SORTED</div>", "check": {"question": "In the worked example, what does the list look like immediately after Step 2 (inserting 9)?", "options": ["2, 9, 6, 4, because inserting 9 always moves it to the middle of the sorted section", "2, 6, 9, 4", "9, 2, 6, 4, because 9 is the largest value seen so far and moves to the very front", "2, 4, 6, 9, because the list is already fully sorted by the end of Step 2"], "answer": 1, "explain": "9 is bigger than 6 (the rightmost sorted item), so it needs no shifting and simply stays where it is: 2, 6, 9, 4."}}, {"title": "Comparing the three sorting algorithms", "html": "<h4>Simplicity vs. efficiency</h4>\n<ul>\n<li><strong>Bubble sort</strong> is the <strong>simplest</strong> to understand and write, but it is usually the <strong>slowest</strong> on a large list — it may need many passes, each one comparing lots of adjacent pairs.</li>\n<li><strong>Merge sort</strong> (divide and conquer) is much more <strong>efficient</strong> on a large list, needing far fewer comparisons overall — but it is <strong>more complex</strong> to write, and needs extra memory to hold the parts while they are being merged.</li>\n<li><strong>Insertion sort</strong> is simple, and is particularly efficient when a list is <strong>already nearly sorted</strong> (few items need to shift very far) or when the list is <strong>small</strong> — but like bubble sort, it can be slow on a large, very unsorted list.</li>\n<li><strong>Exam skill:</strong> a question may describe a sort''s behaviour and ask you to name it, or ask you to compare two of them — always link your comparison to something concrete, such as how many comparisons are needed, or how the list is broken down.</li>\n</ul>", "check": {"question": "Which statement best compares bubble sort and merge sort?", "options": ["Bubble sort and merge sort always need exactly the same number of comparisons for any given list", "Bubble sort is simpler to write, but merge sort is usually far more efficient on a large list", "Merge sort is simpler to write, but bubble sort is usually far more efficient on a large list", "Neither algorithm can be used on a list that contains any repeated values within it"], "answer": 1, "explain": "Bubble sort is simple but usually slow on large lists; merge sort is more complex to write but needs far fewer comparisons on a large list."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Linear search", "definition": "Checks each item in turn from the start until the target is found or the list ends"}, {"term": "Binary search", "definition": "Repeatedly checks the middle item of a SORTED list and discards the half that cannot contain the target"}, {"term": "Bubble sort", "definition": "Repeatedly compares adjacent items and swaps them if they are in the wrong order"}, {"term": "Merge sort", "definition": "Divides the list in half repeatedly, then merges the sorted parts back together in order"}, {"term": "Insertion sort", "definition": "Builds a sorted section one item at a time, inserting each new item into its correct place"}, {"term": "Pass", "definition": "One complete run through the list during a sort"}, {"term": "Swap", "definition": "Exchanging two adjacent items that are in the wrong order"}, {"term": "Divide and conquer", "definition": "Breaking a problem into smaller parts, solving each, then combining the results"}, {"term": "Ascending order", "definition": "Arranged from smallest to largest"}, {"term": "Sorted data required?", "definition": "Binary search — YES; linear search, bubble sort, merge sort, insertion sort — NO"}, {"term": "Comparisons", "definition": "The number of times an algorithm checks one value against another — fewer usually means faster"}, {"term": "Middle item (binary search)", "definition": "The item checked first each pass; the half that cannot contain the target is discarded"}, {"term": "Sorted section (insertion sort)", "definition": "The part of the list, from the left, that has already been put into order"}, {"term": "Bubble sort stopping rule", "definition": "Stops once a whole pass is completed with no swaps made"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which search algorithm checks every item in a list, one at a time, starting from the beginning?", "options": ["Binary search, because it also starts by checking the very first item in the list before anything else", "Linear search", "Merge sort, since sorting always begins by looking at the very first item in the list", "Insertion sort, because building a sorted section always starts with the first item in the list"], "answer": 1, "explain": "Linear search checks each item in turn from the start until it finds the target or reaches the end. Binary search jumps to the middle instead."}, {"question": "Which search algorithm requires the list to be sorted before it can be used?", "options": ["Linear search, because checking each item in turn only works if the list is already arranged in order", "Binary search", "Bubble sort, as it is a sorting algorithm rather than a search algorithm and does not apply here", "Insertion sort, as it is also a sorting algorithm rather than a search algorithm and does not apply here"], "answer": 1, "explain": "Binary search relies on discarding half the list based on order, so the list must already be sorted before it is used."}, {"question": "A sorted list is  2, 5, 9, 14, 20, 27, 33  (indices 0–6). Using binary search for 14, which value is checked FIRST?", "options": ["27, because a binary search always begins by checking the very last item in the list", "14", "2, because a binary search always begins by checking the very first item in the list", "9, because that item sits one position before the exact middle of the list"], "answer": 1, "explain": "With 7 items (indices 0–6), the middle index is (0+6) DIV 2 = 3, which holds 14 — found on the very first check."}, {"question": "What does a bubble sort do on each pass through the list?", "options": ["It compares only the first item to the last item, swapping them if they are in the wrong order", "It compares each pair of adjacent items, swapping them if they are in the wrong order", "It cuts the list exactly in half and works on each half separately from that point on", "It picks the smallest remaining item and moves it straight to the front in one single step"], "answer": 1, "explain": "A bubble sort compares each pair of adjacent items in turn along the list, swapping any pair that is in the wrong order."}, {"question": "How does a bubble sort know when it has finished sorting the list?", "options": ["It stops as soon as it has completed exactly one single pass through the whole list", "A pass is completed in which no swaps were made", "It stops once the first item is smaller than the last item currently in the list", "It always stops after a fixed number of passes equal to half the number of items"], "answer": 1, "explain": "Bubble sort keeps repeating passes until an entire pass makes no swaps — that is the signal the list is fully sorted."}, {"question": "What is the main idea behind a merge sort?", "options": ["It repeatedly compares the very first item in the whole list against every single other item in turn until the entire list ends up in order", "It divides the list in half repeatedly until each part has one item, then merges the parts back in order", "It repeatedly swaps any two adjacent items that happen to be in the wrong order", "It builds up a sorted section of the list one item at a time, starting from the first item"], "answer": 1, "explain": "Merge sort is a divide-and-conquer algorithm: split the list down to single items, then merge the sorted parts back together in order."}, {"question": "What is the main idea behind an insertion sort?", "options": ["It divides the whole list into two separate halves, sorts each of those halves on its own, then merges the two sorted halves back together", "It builds a sorted section one item at a time, inserting each new item into its correct place", "It compares the middle item of the list to the target and discards half the list each time", "It compares every adjacent pair of items and swaps any pair found to be in the wrong order"], "answer": 1, "explain": "Insertion sort grows a sorted section from the left, inserting each new item from the unsorted section into its correct place."}, {"question": "Compared with linear search, why is binary search usually much faster on a large sorted list?", "options": ["It compares every single item in the whole list to the target all at exactly the same moment in time", "Each comparison discards half of the remaining items, so far fewer comparisons are needed overall", "It only ever needs to look at the very first item in the list before finding the target", "It sorts the list again before every single comparison it makes, which speeds it up"], "answer": 1, "explain": "Because each check rules out half of what is left, the number of comparisons needed grows very slowly as the list gets bigger — much slower than linear search."}, {"question": "A list of 6 items is searched with a linear search for a value that is NOT in the list. How many comparisons are made?", "options": ["3, because a linear search only ever needs to check half of the items before giving up", "6", "1, because a linear search always gives up after checking only the first item", "0, because a linear search cannot run at all when the target is missing from the list"], "answer": 1, "explain": "If the value is not present, every item must be checked before the search can conclude it is missing — all 6 of them."}, {"question": "Which of these best describes a ''pass'' in a bubble sort?", "options": ["The single moment at which two items are compared and, if needed, swapped with each other", "One complete run through the list, comparing and swapping adjacent pairs along the way", "The final step of the algorithm, carried out only once the whole list is already sorted", "The process of splitting the list into two halves before any comparisons are made"], "answer": 1, "explain": "A pass is one complete run through the list, during which adjacent pairs are compared (and swapped where needed)."}, {"question": "An algorithm builds up a sorted section of a list, one item at a time, inserting each new item into its correct place among the items already sorted. Which algorithm is this?", "options": ["Bubble sort, because it also works through the list one item at a time from the beginning", "Insertion sort", "Merge sort, because it also results in the list ending up fully sorted from smallest to largest", "Binary search, because it also works with a section of the list already in sorted order"], "answer": 1, "explain": "Building a sorted section one item at a time, inserting each item into its correct place, is exactly how an insertion sort works."}, {"question": "Why can a linear search be used on a list that has NOT been sorted, unlike a binary search?", "options": ["Because a linear search secretly sorts the list first, before it starts checking any items", "It checks every item in turn, so it does not rely on the list being in any particular order", "Because a linear search only ever works on lists with fewer than ten items in total", "Because a linear search does not actually check the values, only the positions of the items"], "answer": 1, "explain": "A linear search simply steps through the items in whatever order they are stored, so it works correctly whether or not the list is sorted."}]}, "fib": {"enabled": true, "questions": [{"text": "A [linear] search checks every item in a list, one at a time, from the start."}, {"text": "A [binary] search repeatedly checks the middle item of a sorted list."}, {"text": "Before a binary search can be used, the list must already be [sorted]."}, {"text": "A [bubble] sort repeatedly compares adjacent items and swaps them if they are in the wrong order."}, {"text": "A bubble sort is finished once a [pass] is completed with no swaps."}, {"text": "A [merge] sort divides the list in half repeatedly, then merges the parts back together in order."}, {"text": "An [insertion] sort builds a sorted section of the list one item at a time."}, {"text": "Splitting a problem into smaller parts, solving each, then combining the results is called divide and [conquer]."}]}, "tf": {"enabled": true, "questions": [{"statement": "A linear search can be used on a list that is not sorted.", "answer": true, "explain": "Correct — a linear search checks items in whatever order they appear, so it works on a sorted or unsorted list."}, {"statement": "A binary search can be used on a list that is not sorted.", "answer": false, "explain": "A binary search relies on the list already being sorted — otherwise discarding a ''half'' does not reliably rule out the target."}, {"statement": "A bubble sort is finished as soon as one pass makes no swaps.", "answer": true, "explain": "Correct — a pass with no swaps means every adjacent pair is already in the right order, so the list is sorted."}, {"statement": "A merge sort repeatedly compares every item in the list against every other item, like a bubble sort does.", "answer": false, "explain": "A merge sort divides the list first, then only compares items while merging two sorted parts together — it does not compare every possible pair."}, {"statement": "An insertion sort builds up a sorted section of the list, one item at a time.", "answer": true, "explain": "Correct — insertion sort grows a sorted section from the left, inserting each new item into its correct place."}, {"statement": "A binary search is generally much faster than a linear search on a large, sorted list.", "answer": true, "explain": "Correct — a binary search discards half the remaining items at every step, so it needs far fewer comparisons on a large list."}, {"statement": "A single pass of a bubble sort always fully sorts the whole list, however long the list is.", "answer": false, "explain": "One pass only guarantees the largest unsorted item reaches its correct place; longer lists usually need several passes."}, {"statement": "A merge sort splits a list into halves until each part contains only one item.", "answer": true, "explain": "Correct — that is the ''divide'' stage of a merge sort, before the sorted parts are merged back together."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking a binary search can be used straight away, on any list, without checking it first.", "truth": "A binary search only gives correct results on a list that is <strong>already sorted</strong>. If the list isn''t sorted, the algorithm still discards half of it each time, but that half might actually contain the target — so it can wrongly report ''not found''. If the list isn''t sorted, it must be sorted first (which itself takes time).", "check": {"question": "What must happen before a binary search can be correctly used on an unsorted list?", "options": ["Nothing — a binary search works correctly on a list in any order, sorted or not", "The list must be sorted first", "Every value in the list must be converted into a whole number first", "The list must be searched with a linear search first, to check the value is present"], "answer": 1, "explain": "A binary search depends on the list being in order, so an unsorted list must be sorted before it can be searched this way."}}, {"myth": "Thinking a linear search needs a sorted list, the same as a binary search does.", "truth": "A linear search checks items <strong>one at a time, in whatever order they are in</strong> — it does not rely on the list being sorted at all. This is actually one of its advantages over a binary search: it works on a sorted or unsorted list.", "check": {"question": "Does a linear search require the list to be sorted, in the same way a binary search does?", "options": ["Yes — both algorithms only work correctly on a list that has already been sorted", "No — a linear search works on a sorted or unsorted list, unlike a binary search", "Yes, but only for lists that contain more than about twenty items", "No, but only if every item in the list is unique with no repeated values"], "answer": 1, "explain": "Unlike binary search, a linear search checks items in whatever order they appear, so it works whether or not the list is sorted."}}, {"myth": "Thinking one pass of a bubble sort always finishes sorting the whole list.", "truth": "One pass only guarantees that the <strong>largest</strong> unsorted item reaches its final place at the end of the section checked. Sorting the whole list usually needs <strong>several</strong> passes — the algorithm keeps going until a pass makes no swaps at all.", "check": {"question": "Why might a bubble sort need more than one pass to fully sort a list?", "options": ["It never actually needs more than a single pass to work, no matter how long or how unsorted the list happens to be", "Because one pass only moves the largest unsorted item into its final place, not every item", "Because each pass only compares the very first two items in the whole list", "Because a bubble sort restarts from scratch and forgets any progress after each pass"], "answer": 1, "explain": "Each pass ''bubbles'' the current largest unsorted item to the end — later passes are needed to place the remaining items correctly too."}}, {"myth": "Thinking a merge sort compares every item in the list against every other item, like a less efficient sort might.", "truth": "A merge sort <strong>divides</strong> the list first, and only compares items while <strong>merging two already-sorted parts</strong> together. It never compares every possible pair of items — which is exactly why it usually needs far fewer comparisons than a bubble sort on a large list.", "check": {"question": "Does a merge sort compare every item in the list against every other item, the way a less efficient sort might?", "options": ["Yes — that is exactly how the final, fully-merged list ends up in the correct order", "No — it only compares items while merging two already-sorted parts together", "Yes, but only for the very first pass through the whole list", "No — a merge sort never compares any two items to each other at all"], "answer": 1, "explain": "Merge sort divides the list into parts first, then only compares front items while merging sorted parts — it avoids comparing every possible pair."}}, {"myth": "Thinking an insertion sort always inserts each new item at the very START of the sorted section.", "truth": "An insertion sort compares the new item against the sorted items starting from the <strong>right-hand (largest)</strong> end, shifting any bigger items along, and inserts the new item wherever that keeps the section in order — which is <strong>not always</strong> the start.", "check": {"question": "Where does an insertion sort insert a new item within the sorted section?", "options": ["Always right at the very start (the left-hand end) of the sorted section, no matter what its value happens to be", "Wherever keeps the sorted section in order, found by comparing from its right-hand end", "Always at the very end (right-hand end) of the sorted section, whatever its value", "At a completely random position, since the position does not affect the final result"], "answer": 1, "explain": "The new item is compared from the right-hand end of the sorted section, and inserted into whichever gap keeps the section correctly ordered."}}, {"myth": "Thinking the ''best'' sort algorithm is always the one with the shortest, simplest code.", "truth": "Choosing an algorithm is about <strong>performance</strong> — for example, how many comparisons it needs on a large list — not how short or simple the code looks. A bubble sort is short and simple to write, but usually needs far more comparisons than a merge sort on a large list.", "check": {"question": "Why might a programmer choose a merge sort over a bubble sort for a very large list, even though bubble sort is simpler to write?", "options": ["A merge sort is always shorter and quicker to write out in full than a bubble sort is, in absolutely every case", "A merge sort usually needs far fewer comparisons, so it performs much better on a large list", "A bubble sort cannot be used at all once a list contains more than a few items", "A merge sort is the only one of the two that can sort numbers rather than text"], "answer": 1, "explain": "Merge sort''s divide-and-conquer approach usually needs far fewer comparisons than bubble sort on a large list, even though its code is more complex."}}]}, "tips": {"enabled": true, "items": [{"title": "Identifying an algorithm from a description", "html": "<p>A common question style describes how an algorithm behaves and asks you to <strong>name</strong> it. Learn the \"signal phrases\" for each one:</p>\n<ul>\n<li>\"Checks each item in turn, from the start\" → <strong>linear search</strong>.</li>\n<li>\"List must already be sorted\" + \"checks the middle\" → <strong>binary search</strong>.</li>\n<li>\"Compares adjacent items\" + \"swaps\" → <strong>bubble sort</strong>.</li>\n<li>\"Splits the list in half\" + \"merges back together\" → <strong>merge sort</strong>.</li>\n<li>\"Builds up a sorted section\" + \"inserts each new item\" → <strong>insertion sort</strong>.</li>\n</ul>\n<p>Quote the phrase from the question in your answer where you can — it shows the examiner exactly why you chose that algorithm.</p>", "check": {"question": "A question describes an algorithm that ''splits a list in half repeatedly, then merges the parts back together in order.'' Which algorithm is this?", "options": ["Bubble sort, because it also results in a fully sorted list once it has finished running", "Merge sort", "Linear search, because it also works through the whole of the list from start to end", "Insertion sort, because it also builds the final sorted list up gradually, bit by bit"], "answer": 1, "explain": "Splitting the list into halves and merging the parts back together in order is the defining behaviour of a merge sort."}}, {"title": "Tracing a sort step by step", "html": "<p>You will often be asked to show a list''s state after each pass or step. Do it mechanically:</p>\n<ul>\n<li>Write out the <strong>full list</strong> after every pass or step — don''t skip one, even if nothing seemed to change.</li>\n<li>For a <strong>bubble sort</strong>, work through each adjacent comparison in order, writing the list again only once the whole pass is finished.</li>\n<li>For a <strong>binary search</strong>, keep track of the current <strong>low</strong>, <strong>high</strong> and <strong>mid</strong> index at every step.</li>\n</ul>\n<p><strong>Example:</strong> sorting 5, 1, 4, 2, 8 with a bubble sort, Pass 1 gives 1, 4, 2, 5, 8 and Pass 2 gives 1, 2, 4, 5, 8 — writing out both full passes, not just the final answer, is what earns the marks.</p>", "check": {"question": "When a question asks you to trace a sort, what is the safest approach?", "options": ["Work out the final sorted list in your head and write down only that final answer", "Write out the full list after every pass or step, working through it mechanically", "Only write down the passes where a swap happened, skipping any pass that made no changes", "Guess the order the sort will finish in, based on how the list looks at the start"], "answer": 1, "explain": "Trace questions are marked on showing each step correctly, so writing the full list after every pass — not just the final answer — is the reliable method."}}, {"title": "Comparing two algorithms in a longer answer", "html": "<p>\"Compare linear search and binary search\" (or similar) questions are usually worth several marks. Structure your answer around real differences:</p>\n<ul>\n<li><strong>State a difference</strong> — e.g. one needs the list sorted, the other doesn''t.</li>\n<li><strong>Explain why it matters</strong> — e.g. fewer comparisons are needed on a large list.</li>\n<li><strong>Give a judgement</strong> — e.g. when one would actually be preferred over the other in practice.</li>\n</ul>\n<p>Avoid a vague \"one is better than the other\" — always link back to something concrete, such as the number of comparisons needed or whether the data needs to be sorted first.</p>", "check": {"question": "What is the best way to structure an answer comparing two search or sort algorithms?", "options": ["Simply state which algorithm you personally think is better, without giving any further detail or reason for it", "State a concrete difference, explain why it matters, then give a judgement about when each is preferable", "List every single step of both algorithms in full, without comparing them to each other at all", "Describe only the algorithm you find easier to explain, and ignore the other one completely"], "answer": 1, "explain": "A strong comparison states a real difference, explains its effect (e.g. on speed or data requirements), and judges when each is preferable."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick <strong>one</strong> box to identify the search algorithm that requires the list to already be sorted.</p>", "marks": 1, "hint": "Which one discards half the list at a time based on order?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Binary search</strong></li></ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Only the correct option scores; 2 or more ticks scores 0.</li></ul>\n</div>"}, {"question": "<p>A linear search checks the list  4, 9, 1, 7, 3  for the value 7 (indices 0–4). Tick <strong>one</strong> box to give the number of comparisons made before 7 is found.</p>", "marks": 1, "hint": "7 is stored at index 3. How many items are checked to reach it, counting from index 0?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>4</strong> (indices 0, 1, 2 and 3 are each checked before 7 is found)</li></ul>\n</div>"}, {"question": "<p>State <strong>one</strong> difference between a linear search and a binary search, in terms of what the list must look like before the search is carried out.</p>", "marks": 2, "hint": "Think about which one needs the list sorted first, and which one does not.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>Award 1 mark for: a linear search works on a list in any order.</li>\n<li>Award 1 mark for: a binary search requires the list to already be sorted.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Both sides of the contrast are needed for full marks.</li></ul>\n</div>"}, {"question": "<p>A binary search is performed on a sorted list of 15 items, with indices 0 to 14. Calculate the index of the middle item that is checked in the FIRST comparison.</p>", "marks": 2, "hint": "Add the lowest index (0) and the highest index (14), then divide by 2, ignoring any remainder.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: (0 + 14) DIV 2</li>\n<li>1 mark: <strong>7</strong></li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to show whether the algorithm is a search algorithm or a sort algorithm.</p>", "marks": 5, "hint": "A search finds whether (and where) a value is in a list. A sort rearranges a list into order.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks (1 mark for each row)</h5>\n<ul>\n<li>Linear search → <strong>Search</strong></li>\n<li>Binary search → <strong>Search</strong></li>\n<li>Bubble sort → <strong>Sort</strong></li>\n<li>Merge sort → <strong>Sort</strong></li>\n<li>Insertion sort → <strong>Sort</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Each row is marked independently; 2 ticks in a row scores 0 for that row.</li></ul>\n</div>"}, {"question": "<p>Draw <strong>one</strong> line from each algorithm to the description of how it behaves.</p><p>(There are more descriptions than algorithms — one description is not used.)</p>", "marks": 5, "hint": "Watch the decoy: ''always checks only the first and last items'' does not describe any of these five algorithms.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks (1 mark per correct line)</h5>\n<ul>\n<li>Linear search → <strong>A</strong> (checks every item in turn from the start)</li>\n<li>Binary search → <strong>B</strong> (checks the middle of a sorted list, discards a half)</li>\n<li>Bubble sort → <strong>C</strong> (compares adjacent pairs, swaps if wrong order)</li>\n<li>Merge sort → <strong>D</strong> (splits in half repeatedly, merges parts back in order)</li>\n<li>Insertion sort → <strong>E</strong> (builds a sorted section, inserting each new item)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>1 mark per correct line. Description F is a decoy and is not used.</li></ul>\n</div>"}, {"question": "<p>Complete the paragraph about linear and binary search by selecting terms from the list. <strong>Not all terms are used.</strong></p>", "marks": 3, "hint": "Works on any order → one search type; needs the list in order first → the other search type.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark for each completed term)</h5>\n<p>A <strong>linear</strong> search checks every item in turn, and will work on a list in any order. A <strong>binary</strong> search is much faster on a large list, but the list must already be <strong>sorted</strong>.</p>\n</div>"}, {"question": "<p>A linear search is used on the list  12, 7, 19, 3, 25, 8  (indices 0–5) to find the value <strong>25</strong>.</p><p>Complete the trace table to show the index checked, the value found there, and whether it matches, for each comparison made.</p>", "marks": 5, "hint": "Start at index 0 and check each value in turn against the target, 25, until you reach a match.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks (1 mark per correct row of the trace)</h5>\n<ul>\n<li>Index 0 → value 12, No</li>\n<li>Index 1 → value 7, No</li>\n<li>Index 2 → value 19, No</li>\n<li>Index 3 → value 3, No</li>\n<li>Index 4 → value 25, Yes - found</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>1 mark for each fully-correct row (all columns right). The search finds 25 at index 4, after 5 comparisons.</li></ul>\n</div>"}, {"question": "<p>A binary search is used on the sorted list  3, 7, 8, 12, 19, 25, 31, 40  (indices 0–7) to find the value <strong>19</strong>.</p><p>Complete the trace table to show the low index, high index, mid index, the value at mid, and the result, for each comparison made.</p>", "marks": 3, "hint": "mid = (low + high) DIV 2 each time. Compare the value at mid to 19, then decide which half to search next.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per correct row of the trace)</h5>\n<ul>\n<li>Low 0, High 7, Mid 3, value 12 → too low, search right half</li>\n<li>Low 4, High 7, Mid 5, value 25 → too high, search left half</li>\n<li>Low 4, High 4, Mid 4, value 19 → found</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>1 mark for each fully-correct row. 19 is found on the third comparison, at index 4.</li></ul>\n</div>"}, {"question": "<p>Describe how a bubble sort would sort the list  5, 1, 4, 2, 8  into ascending order.</p><p>Show the list after each pass, and state how the algorithm knows when it has finished.</p>", "marks": 5, "hint": "Work through the adjacent comparisons one pass at a time, and keep going until a pass makes no swaps.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 5 marks</h5>\n<ul>\n<li>1 mark: after Pass 1 the list is 1, 4, 2, 5, 8</li>\n<li>1 mark: after Pass 2 the list is 1, 2, 4, 5, 8</li>\n<li>1 mark: Pass 3 compares every adjacent pair and makes no swaps</li>\n<li>1 mark: the algorithm stops because a pass has been completed with no swaps</li>\n<li>1 mark: the final sorted list is 1, 2, 4, 5, 8</li>\n</ul>\n</div>"}, {"question": "<p>Compare a linear search with a binary search.</p><p>In your answer you should refer to: the order the list needs to be in, and the number of comparisons needed on a large list.</p>", "marks": 6, "hint": "Cover both search types, then link the difference to how many comparisons each one needs on a large list.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 6 marks</h5>\n<ul>\n<li>1 mark: a linear search works on a list in any order</li>\n<li>1 mark: a binary search requires the list to be sorted first</li>\n<li>1 mark: a linear search checks items one by one from the start, and may need to check every item</li>\n<li>1 mark: a binary search discards half of the remaining items at each step</li>\n<li>1 mark: on a large list, a binary search generally needs far fewer comparisons and is faster</li>\n<li>1 mark: a linear search may still be preferable for a small or unsorted list, since sorting first also takes time</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Marks are for valid comparison points; other correct, relevant points may also be credited.</li></ul>\n</div>"}, {"question": "<p>An algorithm splits a list into two halves repeatedly, until each part contains only one item, then merges the parts back together in the correct order.</p><p>Name this algorithm, and describe <strong>one</strong> advantage it has over a bubble sort.</p>", "marks": 3, "hint": "Name the algorithm first, then think about how many comparisons each one needs on a large list.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark: <strong>merge sort</strong></li>\n<li>1 mark: it usually needs far fewer comparisons on a large list (is more efficient)</li>\n<li>1 mark: because dividing the list first means it does not compare every possible pair of adjacent items the way a bubble sort does</li>\n</ul>\n</div>"}]}}'::jsonb),
('computer-science', '2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', '{"learn": {"enabled": true, "items": [{"title": "What programming is made of", "html": "<h4>Every program is built from a few basic ideas</h4>\n<ul>\n<li>A <strong>program</strong> is a set of instructions a computer follows. No matter how big, it is built from a small set of fundamentals: <strong>data stored in variables and constants</strong>, <strong>operators</strong> that work on that data, and the <strong>three programming constructs</strong> — <strong>sequence</strong>, <strong>selection</strong> and <strong>iteration</strong>.</li>\n<li>In Paper 2 you read and write algorithms as <strong>pseudocode</strong>, written in OCR''s <strong>Exam Reference Language (ERL)</strong>. It looks a lot like Python, but you are not tied to any one real language.</li>\n<li>This page teaches each fundamental with a short ERL example. Learn to <strong>read</strong> the code (trace it) and <strong>write</strong> it yourself.</li>\n</ul>", "check": {"question": "What are the three programming constructs that all programs are built from?", "options": ["Variables, constants and operators, which together store and change all of the data used by the program", "Sequence, selection and iteration", "Input, processing and output, which is the order that a computer always deals with any data in", "Compiling, interpreting and assembling, which are the three ways a program can finally be translated"], "answer": 1, "explain": "The three constructs are sequence, selection and iteration. Variables/operators and input-process-output are important ideas but not the three constructs."}}, {"title": "Variables", "html": "<h4>A named store for a value that can change</h4>\n<ul>\n<li>A <strong>variable</strong> is a named location in memory that holds a value. Its value <strong>can change</strong> while the program runs — that is what \"vary\" means.</li>\n<li>You put a value into a variable using <strong>assignment</strong> (the <code>=</code> sign): the value on the <strong>right</strong> is stored in the name on the <strong>left</strong>.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Pseudocode (ERL)</p><div class=\"code-block\">score = 0\nname = input(\"Enter your name: \")\nscore = score + 10</div></div>\n<div><p class=\"code-label\">Python</p><div class=\"code-block\">score = 0\nname = input(\"Enter your name: \")\nscore = score + 10</div></div>\n</div>\n<ul>\n<li>Think of a variable as a <strong>labelled box</strong>: <code>score</code> is the label, and you can swap what''s inside at any time.</li>\n</ul>", "check": {"question": "What is a variable?", "options": ["A fixed value that is written into the program by the programmer and can never be altered while it runs", "A named store in memory whose value can change while the program runs", "A message that the program prints out onto the screen for the user to read while it is running", "A special symbol, such as + or *, that performs a calculation on two different numbers in a program"], "answer": 1, "explain": "A variable is a named store whose value can change as the program runs — unlike a constant, which stays fixed."}}, {"title": "Constants", "html": "<h4>A named value that does NOT change</h4>\n<ul>\n<li>A <strong>constant</strong> is a named value that is set once and <strong>cannot change</strong> while the program runs.</li>\n<li>Use one for a value that is fixed and used in several places — for example a rate of tax, the value of Pi, or a maximum score.</li>\n</ul>\n<div class=\"code-block\">const VAT_RATE = 0.20\nconst MAX_SCORE = 100</div>\n<ul>\n<li><strong>Why use constants?</strong> They make code <strong>easier to read</strong> (a name explains what a number means) and <strong>easier to change</strong> (edit it in <strong>one place</strong> instead of hunting for every <code>0.20</code>). Constant names are often written in CAPITALS.</li>\n</ul>", "check": {"question": "Why might a programmer use a constant instead of just typing the number 0.20 throughout their code?", "options": ["Because using a constant somehow makes the whole program run considerably faster than an ordinary plain typed-in number ever could", "Because it gives the value a clear name and can be changed in one place, making the code easier to read and update", "Because a constant is the only way to store a decimal number, as variables can only ever hold whole numbers", "Because constants are automatically kept secret from anyone who might later try to read the program''s code"], "answer": 1, "explain": "A constant gives the value a meaningful name and means a change is made in one place — improving readability and maintainability."}}, {"title": "Input, output and assignment", "html": "<h4>Getting data in, sending results out</h4>\n<ul>\n<li><strong>Input</strong> — read a value from the user with <code>input(...)</code>. It usually comes in as text, so it is often converted to a number (see 2.2.2 casting).</li>\n<li><strong>Output</strong> — display a value with <code>print(...)</code>.</li>\n<li><strong>Assignment</strong> — store a value in a variable with <code>=</code>. It works <strong>right to left</strong>: work out the right-hand side, then put the result in the variable on the left.</li>\n</ul>\n<div class=\"code-block\">age = input(\"How old are you? \")\nnextYear = age + 1\nprint(\"Next year you will be \" + nextYear)</div>\n<ul>\n<li><code>total = total + 1</code> is not a contradiction — it means \"work out the <strong>old</strong> total plus 1, then make that the <strong>new</strong> total\". This is how counters and running totals work.</li>\n</ul>", "check": {"question": "What does the statement  count = count + 1  do?", "options": ["It checks whether the variable count is currently equal to count plus one, and reports true or false", "It works out the current value of count plus 1, then stores that new value back into count", "It creates a brand new second variable, also called count, that permanently holds the value 1", "It outputs the value of count to the screen and then adds the number 1 next to it for the user"], "answer": 1, "explain": "Assignment is right-to-left: the old value of count plus 1 is calculated, then stored back into count. This is how a counter increases."}}, {"title": "Arithmetic operators", "html": "<h4>Doing maths in a program</h4>\n<ul>\n<li>The usual four: <code>+</code> add, <code>-</code> subtract, <code>*</code> multiply, <code>/</code> divide.</li>\n<li>Plus three you must know for GCSE:</li>\n<li><code>^</code> — <strong>exponent</strong> (to the power of). <code>2 ^ 3</code> = 8.</li>\n<li><code>DIV</code> — <strong>integer (whole-number) division</strong>: the whole number of times one divides into another, throwing away any remainder. <code>17 DIV 5</code> = 3.</li>\n<li><code>MOD</code> — <strong>modulus</strong>: the <strong>remainder</strong> after that division. <code>17 MOD 5</code> = 2.</li>\n</ul>\n<div class=\"code-block\">17 DIV 5   → 3      (5 goes into 17 three whole times)\n17 MOD 5   → 2      (2 is left over)\n2 ^ 3      → 8</div>", "check": {"question": "What is the result of  20 DIV 6 ?", "options": ["2, because that is the amount that is left over after taking as many whole sixes as possible out of twenty", "3", "3.33", "6"], "answer": 1, "explain": "DIV gives the whole number of times 6 divides into 20, which is 3 (the remainder of 2 is discarded). 20 MOD 6 would give the remainder, 2."}}, {"title": "MOD and DIV in action", "html": "<h4>Why the remainder is so useful</h4>\n<ul>\n<li><strong>Is a number even?</strong> A number is even if it divides by 2 with no remainder — i.e. <code>number MOD 2 == 0</code>.</li>\n<li><strong>Split into groups.</strong> To put 30 students into teams of 4: <code>30 DIV 4</code> = 7 full teams, and <code>30 MOD 4</code> = 2 students left over.</li>\n<li><strong>Get the last digit</strong> of a number: <code>number MOD 10</code>. For 253, <code>253 MOD 10</code> = 3.</li>\n</ul>\n<div class=\"code-block\">if number MOD 2 == 0 then\n  print(\"even\")\nelse\n  print(\"odd\")\nendif</div>", "check": {"question": "Which test correctly checks whether the value in  number  is even?", "options": ["number DIV 2 == 0, because DIV finds how many times 2 goes in and an even number always gives zero here", "number MOD 2 == 0", "number MOD 2 == 1, because an even number always leaves a remainder of exactly one when it is halved", "number / 2 == 0, because dividing any even number by two will always give an answer of exactly zero"], "answer": 1, "explain": "An even number leaves NO remainder when divided by 2, so number MOD 2 == 0. (MOD 2 == 1 tests for odd.)"}}, {"title": "Comparison operators", "html": "<h4>Asking true/false questions</h4>\n<ul>\n<li>Comparison operators compare two values and give a <strong>Boolean</strong> result — <strong>true</strong> or <strong>false</strong>. They are what conditions in <code>if</code> and <code>while</code> are built from.</li>\n<li><code>==</code> equal to · <code>!=</code> not equal to · <code>&lt;</code> less than · <code>&lt;=</code> less than or equal to · <code>&gt;</code> greater than · <code>&gt;=</code> greater than or equal to.</li>\n</ul>\n<div class=\"code-block\">5 &gt; 3      → true\n5 == 3     → false\n5 != 3     → true\n7 &lt;= 7     → true</div>\n<ul>\n<li><strong>Watch the trap:</strong> <code>=</code> means <strong>assign</strong> (store a value); <code>==</code> means <strong>compare</strong> (are these equal?). Using <code>=</code> where you meant <code>==</code> is one of the most common mistakes.</li>\n</ul>", "check": {"question": "What is the difference between  =  and  ==  ?", "options": ["There is no real difference between them; they both simply check whether two values are equal to each other", "= assigns a value to a variable, whereas == compares two values and gives a true or false result", "= compares two values for equality, whereas == is used to store a new value inside a variable", "= is used only with numbers and == is used only with text, but otherwise they do exactly the same job"], "answer": 1, "explain": "= stores a value in a variable (assignment); == tests whether two values are equal (comparison). Mixing them up is a classic error."}}, {"title": "Boolean operators (AND, OR, NOT)", "html": "<h4>Combining conditions</h4>\n<ul>\n<li><strong>Boolean operators</strong> join or invert conditions:</li>\n<li><code>AND</code> — true only if <strong>both</strong> sides are true.</li>\n<li><code>OR</code> — true if <strong>either</strong> side (or both) is true.</li>\n<li><code>NOT</code> — <strong>reverses</strong> a condition: <code>NOT true</code> is false.</li>\n</ul>\n<div class=\"code-block\">if age &gt;= 13 AND age &lt;= 19 then\n  print(\"You are a teenager\")\nendif\n\nif day == \"Sat\" OR day == \"Sun\" then\n  print(\"It''s the weekend\")\nendif</div>\n<ul>\n<li>These let one condition test more than one thing at once — e.g. a value being <strong>within a range</strong> uses <code>AND</code>.</li>\n</ul>", "check": {"question": "A condition is written as  score &gt;= 40 AND score &lt;= 69 . When is it true?", "options": ["When score is 40 or more, OR 69 or less, which as it happens is true for absolutely every possible score", "Only when score is both 40 or more AND 69 or less — that is, anywhere from 40 to 69 inclusive", "Only when score is exactly equal to either the number 40 or the number 69, but no other value in between", "Whenever score is either less than 40 or greater than 69, i.e. any score that sits outside that range"], "answer": 1, "explain": "AND needs BOTH sides true, so score must be ≥40 and ≤69 — the range 40 to 69 inclusive."}}, {"title": "Sequence", "html": "<h4>One step after another, in order</h4>\n<ul>\n<li><strong>Sequence</strong> is the simplest construct: instructions are carried out <strong>one after another, top to bottom, in the order they are written</strong>.</li>\n<li>Order matters — swapping two lines can change the result.</li>\n</ul>\n<div class=\"code-block\">length = 5\nwidth = 3\narea = length * width\nprint(area)</div>\n<ul>\n<li>Here each line depends on the ones before it: you can''t work out <code>area</code> until <code>length</code> and <code>width</code> exist.</li>\n</ul>", "check": {"question": "What does ''sequence'' mean as a programming construct?", "options": ["The program repeats a set of instructions over and over again until some particular condition finally becomes true", "Instructions are carried out one after another, in the order they are written", "The program chooses between two or more different paths depending on whether a condition is true or false", "The instructions are automatically sorted into alphabetical order by the computer before the program is run"], "answer": 1, "explain": "Sequence means running instructions in order, top to bottom. Repeating is iteration; choosing a path is selection."}}, {"title": "Selection (if / else)", "html": "<h4>Choosing a path based on a condition</h4>\n<ul>\n<li><strong>Selection</strong> lets a program <strong>choose</strong> what to do, based on whether a condition is true or false. It uses <code>if … then … else … endif</code>, and <code>elseif</code> for extra branches.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Pseudocode (ERL)</p><div class=\"code-block\">if mark &gt;= 70 then\n  print(\"Distinction\")\nelseif mark &gt;= 40 then\n  print(\"Pass\")\nelse\n  print(\"Fail\")\nendif</div></div>\n<div><p class=\"code-label\">Python</p><div class=\"code-block\">if mark &gt;= 70:\n  print(\"Distinction\")\nelif mark &gt;= 40:\n  print(\"Pass\")\nelse:\n  print(\"Fail\")</div></div>\n</div>\n<ul>\n<li>Only <strong>one</strong> branch runs — the first whose condition is true. (OCR also allows a <code>switch/case</code> for choosing between many fixed values.)</li>\n</ul>", "check": {"question": "In the grade example above, what is printed when mark is 55?", "options": ["Both \"Pass\" and \"Fail\" are printed, because 55 is not high enough to reach the Distinction branch at the top", "Pass", "Fail", "Distinction, because once a mark is 40 or more the program treats it as reaching the highest grade band"], "answer": 1, "explain": "55 is not ≥70, but it is ≥40, so the elseif branch runs and prints \"Pass\". Only the first matching branch runs."}}, {"title": "Iteration — count-controlled (for)", "html": "<h4>Repeat a set number of times</h4>\n<ul>\n<li><strong>Iteration</strong> means repeating instructions (a <strong>loop</strong>). A <strong>count-controlled</strong> loop repeats a <strong>known, fixed number of times</strong>, using a <strong>for</strong> loop with a counter.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Pseudocode (ERL)</p><div class=\"code-block\">for i = 1 to 5\n  print(i)\nnext i</div></div>\n<div><p class=\"code-label\">Python</p><div class=\"code-block\">for i in range(1, 6):\n  print(i)</div></div>\n</div>\n<ul>\n<li>The counter <code>i</code> starts at 1, goes up by one each time, and the loop stops after 5 — printing 1, 2, 3, 4, 5.</li>\n<li>Use a count-controlled loop when you <strong>know in advance how many times</strong> to repeat.</li>\n</ul>", "check": {"question": "When is a count-controlled (for) loop the right choice?", "options": ["When you do not know in advance how many times to repeat, and must keep going until a condition changes", "When you know in advance exactly how many times the loop should repeat", "When you only ever want the instructions inside the loop to run one single time and then stop completely", "When you need the program to choose between two different paths rather than repeating anything at all"], "answer": 1, "explain": "A count-controlled (for) loop is used when the number of repetitions is known in advance. Not knowing means a condition-controlled loop."}}, {"title": "Iteration — condition-controlled (while / do-until)", "html": "<h4>Repeat until a condition changes</h4>\n<ul>\n<li>A <strong>condition-controlled</strong> loop repeats <strong>while (or until) a condition</strong> is met — used when you <strong>don''t know in advance</strong> how many repetitions are needed.</li>\n<li><code>while … endwhile</code> checks the condition <strong>before</strong> each pass, so it may run <strong>zero</strong> times.</li>\n<li><code>do … until</code> checks the condition <strong>after</strong> each pass, so it always runs <strong>at least once</strong>.</li>\n</ul>\n<div class=\"code-block\">password = input(\"Password: \")\nwhile password != \"secret\"\n  password = input(\"Wrong. Try again: \")\nendwhile\nprint(\"Access granted\")</div>\n<ul>\n<li>Here the loop keeps asking until the right password is typed — you can''t know how many tries that will take.</li>\n</ul>", "check": {"question": "What is the key difference between a  while  loop and a  do … until  loop?", "options": ["A while loop can only ever repeat a fixed, pre-set number of times, whereas a do…until loop is the only kind of loop that is able to repeat any number of times at all", "A while loop checks its condition before each pass (so it may run zero times); do…until checks after, so it always runs at least once", "A while loop is used for numbers and a do…until loop is used for text, but otherwise they behave in exactly the same way", "A while loop chooses between two paths, whereas a do…until loop simply runs its instructions once in strict order"], "answer": 1, "explain": "A while loop tests the condition first (may run zero times); do…until tests after the body, so it always runs at least once."}}, {"title": "Count-controlled vs condition-controlled", "html": "<h4>Choosing the right loop</h4>\n<ul>\n<li>The exam often asks you to pick, or justify, the right kind of loop:</li>\n<li><strong>Count-controlled (for)</strong> — you know the number of repetitions <strong>in advance</strong> (e.g. \"do this 10 times\", \"for each of the 5 scores\").</li>\n<li><strong>Condition-controlled (while / do-until)</strong> — you <strong>don''t</strong> know the number in advance; you repeat <strong>until something happens</strong> (e.g. \"until the user enters 0\", \"while there is still input\").</li>\n</ul>\n<div class=\"code-block\">// known count → for loop\nfor i = 1 to 10\n  ...\nnext i\n\n// unknown count → while loop\nwhile guess != answer\n  ...\nendwhile</div>", "check": {"question": "A program keeps asking the user for a number until they type a value between 1 and 10. Which loop suits this best?", "options": ["A count-controlled for loop, because the program will always end up needing to run for exactly ten separate repetitions in total, no matter what the user does", "A condition-controlled loop (while or do…until), because you cannot know in advance how many tries the user will take", "A sequence with no loop at all, because asking the user for a value only ever needs to happen a single time", "A selection statement on its own, because the program simply chooses whether the entered number is valid or not"], "answer": 1, "explain": "You don''t know how many attempts the user will need, so a condition-controlled loop (repeat until valid) is right — not a fixed for loop."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Variable", "definition": "A named store whose value can change while the program runs"}, {"term": "Constant", "definition": "A named value that is fixed once set and cannot change while running"}, {"term": "Assignment ( = )", "definition": "Stores the right-hand value into the variable on the left"}, {"term": "Input / output", "definition": "input() reads a value from the user; print() displays a value"}, {"term": "+  -  *  /", "definition": "Add, subtract, multiply, divide"}, {"term": "^", "definition": "Exponent — to the power of (2 ^ 3 = 8)"}, {"term": "DIV", "definition": "Whole-number (integer) division: 17 DIV 5 = 3"}, {"term": "MOD", "definition": "Remainder after division: 17 MOD 5 = 2"}, {"term": "Comparison operators", "definition": "==  !=  <  <=  >  >=  — give a true/false result"}, {"term": "= vs ==", "definition": "= assigns a value; == compares two values for equality"}, {"term": "AND / OR / NOT", "definition": "Boolean: AND needs both true; OR needs one; NOT reverses"}, {"term": "Sequence", "definition": "Instructions carried out in order, top to bottom"}, {"term": "Selection", "definition": "Choosing a path with if / elseif / else / endif"}, {"term": "Count-controlled loop", "definition": "for loop — repeats a known number of times"}, {"term": "Condition-controlled loop", "definition": "while / do-until — repeats until a condition changes"}, {"term": "while vs do-until", "definition": "while checks before (may run 0 times); do-until checks after (runs ≥1)"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is a constant?", "options": ["A named store in memory whose value the program is free to change as often as it needs to while running", "A named value that is set once and cannot change while the program runs", "An instruction that repeats a block of code a set number of times before the program finally moves on", "A symbol such as MOD or DIV that carries out a particular calculation on the numbers on either side of it"], "answer": 1, "explain": "A constant is a named value fixed for the run of the program. A store whose value can change is a variable."}, {"question": "What is the result of  23 MOD 4 ?", "options": ["5 (which is how many whole times four divides into twenty-three, once the leftover remainder is ignored)", "3", "5.75", "4"], "answer": 1, "explain": "MOD gives the remainder: 4 goes into 23 five times (20), leaving 3. (23 DIV 4 would give 5.)"}, {"question": "Which operator gives the WHOLE number of times one value divides into another, ignoring any remainder?", "options": ["MOD", "DIV", "/", "^"], "answer": 1, "explain": "DIV is integer (whole-number) division. MOD gives the remainder, / gives a normal (possibly decimal) result, and ^ is exponent."}, {"question": "Which of these is a comparison operator?", "options": ["The MOD operator, which is used to find the remainder that is left over after one whole-number division", "!=", "AND", "^"], "answer": 1, "explain": "!= (not equal to) is a comparison operator. MOD and ^ are arithmetic; AND is a Boolean operator."}, {"question": "A program contains the line  if x = 5 then  where the programmer meant to test whether x equals 5. What is wrong?", "options": ["Nothing is wrong; a single = sign is the correct and normal way to test whether two values are equal to each other", "= is assignment; to test for equality the condition should use == ", "The condition should use MOD instead of =, because MOD is the operator that checks whether two numbers match", "The word ''then'' is missing, and once it is added the single = sign will correctly compare the two values"], "answer": 1, "explain": "= assigns a value; comparing for equality needs ==. This is a very common error."}, {"question": "The Boolean operator that is true only when BOTH of its conditions are true is:", "options": ["OR", "AND", "NOT", "MOD"], "answer": 1, "explain": "AND is true only if both sides are true. OR is true if either side is true, and NOT reverses a single condition."}, {"question": "Which construct repeats a block of instructions?", "options": ["Sequence", "Iteration", "Selection", "Assignment"], "answer": 1, "explain": "Iteration means repetition (loops). Sequence runs in order, selection chooses a path, and assignment stores a value."}, {"question": "You need to repeat a block of code exactly 8 times. Which loop is most suitable?", "options": ["A condition-controlled while loop, because it will keep checking whether it has reached eight repetitions yet", "A count-controlled for loop", "No loop at all, because eight separate copies of the code should simply be written out one after another", "A selection statement, because the program has to decide each time whether it should repeat the code again"], "answer": 1, "explain": "The number of repetitions (8) is known in advance, so a count-controlled for loop is the natural choice."}, {"question": "What does  2 ^ 4  evaluate to?", "options": ["8, because the ^ operator simply multiplies the two numbers on either side of it together in the usual way", "16", "6", "24"], "answer": 1, "explain": "^ is ''to the power of'': 2 to the power 4 = 2×2×2×2 = 16."}, {"question": "In a  do … until  loop, how many times does the body always run, at minimum?", "options": ["Zero, because the loop checks its condition before it runs the body even once, exactly like a while loop does", "At least once, because the condition is checked after the body has run", "Exactly the number stated by a counter that has to be set before the loop can begin running at all", "It can never be predicted, because a do…until loop runs its body a completely random number of times"], "answer": 1, "explain": "do…until checks the condition AFTER the body, so the body always runs at least once. A while loop can run zero times."}, {"question": "Which line correctly assigns the number 0 to a variable called  total ?", "options": ["total == 0", "total = 0", "0 = total", "total := equals(0)"], "answer": 1, "explain": "Assignment stores the right-hand value into the left-hand name: total = 0. (== is comparison, and the value must go into the variable.)"}, {"question": "A condition is  age &lt; 13 OR age &gt; 65 . For which age is it TRUE?", "options": ["age = 40, because forty comfortably sits inside the normal range that the two conditions are describing together", "age = 70", "age = 30", "age = 13"], "answer": 1, "explain": "OR is true if either side is true. 70 is greater than 65, so the condition is true. 40, 30 and 13 satisfy neither side."}]}, "fib": {"enabled": true, "questions": [{"text": "A [variable] is a named store in memory whose value can change while the program runs."}, {"text": "A [constant] is a named value that is set once and cannot change while the program runs."}, {"text": "The [MOD] operator gives the remainder after a whole-number division, so 17 MOD 5 is 2."}, {"text": "The [DIV] operator gives the whole number of times one value divides into another, so 17 DIV 5 is 3."}, {"text": "The [sequence] construct runs instructions one after another, in the order they are written."}, {"text": "The [selection] construct chooses a path using if, then and else."}, {"text": "A count-controlled (for) loop is used when you know the number of [repetitions] in advance."}, {"text": "The Boolean operator [AND] is true only when both of its conditions are true."}]}, "tf": {"enabled": true, "questions": [{"statement": "The value stored in a variable can change while the program runs.", "answer": true, "explain": "Correct — that is exactly what makes it a variable, as opposed to a constant which stays fixed."}, {"statement": "17 MOD 5 gives the answer 3.", "answer": false, "explain": "17 MOD 5 gives the remainder, which is 2. It is 17 DIV 5 that gives 3."}, {"statement": "In pseudocode, = is used to assign a value and == is used to compare two values.", "answer": true, "explain": "Correct — = stores a value in a variable; == tests whether two values are equal."}, {"statement": "A count-controlled loop is used when you do not know in advance how many times to repeat.", "answer": false, "explain": "That describes a condition-controlled loop. A count-controlled (for) loop is used when the number of repetitions IS known in advance."}, {"statement": "The AND operator is true only when both of its conditions are true.", "answer": true, "explain": "Correct — AND needs both sides true. OR needs only one side true."}, {"statement": "Selection means repeating a block of instructions many times.", "answer": false, "explain": "Repeating is iteration. Selection means choosing a path based on whether a condition is true or false."}, {"statement": "A do…until loop always runs its body at least once.", "answer": true, "explain": "Correct — the condition is checked after the body, so the body runs at least once. A while loop can run zero times."}, {"statement": "^ is the operator for finding a remainder.", "answer": false, "explain": "^ is the exponent (to the power of) operator. MOD is the operator that finds a remainder."}]}, "misc": {"enabled": true, "items": [{"myth": "Using = when you mean == (or thinking they are the same).", "truth": "<strong>=</strong> is <strong>assignment</strong> — it <em>stores</em> the right-hand value into a variable. <strong>==</strong> is <strong>comparison</strong> — it <em>asks</em> whether two values are equal and gives true/false. A condition (in an <code>if</code> or <code>while</code>) needs <code>==</code>.", "check": {"question": "Which symbol belongs in a condition that tests whether  score  equals 100?", "options": ["=, because a single equals sign is the standard way to check that two values are the same as each other", "==, because a condition compares two values and == is the comparison operator for ''is equal to''", "MOD, because you need to find the remainder before you are able to compare the score against one hundred", "!=, because that is the operator that specifically checks whether the score has reached exactly one hundred"], "answer": 1, "explain": "A condition compares values, so it needs == (equal to). A single = would try to assign, not compare."}}, {"myth": "Mixing up MOD and DIV.", "truth": "<strong>DIV</strong> gives the <strong>whole-number result</strong> of a division (how many times it goes in); <strong>MOD</strong> gives the <strong>remainder</strong> left over. For 17 and 5: <code>17 DIV 5 = 3</code> and <code>17 MOD 5 = 2</code>. A memory hook: <strong>D</strong>IV = the <strong>D</strong>ivision result; MOD = what''s left over.", "check": {"question": "What is  17 DIV 5 ?", "options": ["2, which is the amount that is left over once five has been divided into seventeen as many times as it can be", "3", "3.4", "5"], "answer": 1, "explain": "DIV gives the whole-number result: 5 goes into 17 three times, so 17 DIV 5 = 3. The remainder (2) is 17 MOD 5."}}, {"myth": "Thinking a variable and a constant are the same thing.", "truth": "Both are <strong>named stores</strong>, but a <strong>variable''s</strong> value <strong>can change</strong> as the program runs, while a <strong>constant''s</strong> value is <strong>fixed</strong> once set. Use a constant for values that should never change, like a tax rate.", "check": {"question": "Which of these should be stored as a CONSTANT rather than a variable?", "options": ["A running total of a player''s score, which needs to go up and down repeatedly as they play through the game", "The fixed rate of VAT (0.20) that is used in several places and should never change while the program runs", "The user''s latest guess in a guessing game, which is different every single time they are asked to enter one", "The current number of items in a shopping basket, which changes each time the user adds or removes something"], "answer": 1, "explain": "A fixed value used in several places (the VAT rate) suits a constant. The others all change as the program runs, so they are variables."}}, {"myth": "Confusing count-controlled and condition-controlled loops.", "truth": "A <strong>count-controlled</strong> (for) loop runs a <strong>known number of times</strong>. A <strong>condition-controlled</strong> (while / do-until) loop runs <strong>until a condition changes</strong>, when you <strong>don''t know</strong> the number in advance. Ask: ''Do I know how many times?'' Yes → for; No → while.", "check": {"question": "A loop must keep running until the user finally types the word ''quit''. Which type of loop is this?", "options": ["A count-controlled loop, because the program can always work out the exact number of repetitions before it starts", "A condition-controlled loop, because you cannot know in advance how many times the user will type before quitting", "Neither — this task cannot be done with a loop at all, and must instead be written out as a plain sequence", "A selection statement, because the program only has to decide once whether the user has typed the word quit"], "answer": 1, "explain": "The number of repetitions is unknown (it depends on the user), so it''s condition-controlled — repeat until they type ''quit''."}}, {"myth": "Reading assignment  x = x + 1  as an impossible equation.", "truth": "It is <strong>not</strong> an equation to solve — assignment works <strong>right to left</strong>. The computer works out the <strong>right-hand side using the old value</strong> of <code>x</code>, then stores the result as the <strong>new</strong> <code>x</code>. So if x was 4, <code>x = x + 1</code> makes x become 5.", "check": {"question": "If  total  currently holds 7, what does  total = total + 3  leave in  total ?", "options": ["It leaves nothing valid, because a variable can never be defined in terms of itself within a single statement", "10, because the old value 7 is added to 3 and the result is stored back into total as its new value", "3, because the number on the right of the equals sign simply replaces whatever total used to be holding", "It leaves 7 unchanged, because the two sides of the statement have to be equal for it to be allowed to run"], "answer": 1, "explain": "The right-hand side (7 + 3) is worked out first, then stored back into total, giving 10."}}, {"myth": "Thinking a while loop always runs at least once.", "truth": "A <strong>while</strong> loop checks its condition <strong>before</strong> the first pass, so if the condition is already false it runs <strong>zero</strong> times. It is the <strong>do…until</strong> loop that always runs at least once, because it checks <strong>after</strong> the body.", "check": {"question": "A while loop''s condition is false before the loop is even reached. How many times does its body run?", "options": ["Once, because every loop is guaranteed to run its body a minimum of one single time before any checking happens", "Zero times, because a while loop checks the condition before each pass and the condition is already false", "Exactly the number set by its counter, because a while loop always repeats a fixed number of times overall", "It runs forever, because a false condition means the loop can never find a reason to stop itself running"], "answer": 1, "explain": "A while loop tests first, so a condition that is already false means the body runs zero times."}}]}, "tips": {"enabled": true, "items": [{"title": "How to trace code line by line", "html": "<p>\"What does this output?\" and trace-table questions are worth a lot on Paper 2, and you get them right by being <strong>slow and mechanical</strong>, not by reading the code and guessing.</p>\n<ul>\n<li>Draw a small table with a <strong>column for each variable</strong> (and one for output).</li>\n<li>Work through <strong>one line at a time</strong>, writing the new value each time a variable changes. Never skip a loop pass.</li>\n<li>For a loop, check the <strong>condition</strong> each pass and stop the moment it is false.</li>\n</ul>\n<p><strong>Example:</strong> for <code>total = 0</code> then <code>for i = 1 to 3 … total = total + i … next i</code>, your table fills in i = 1 (total 1), i = 2 (total 3), i = 3 (total 6). Output: 6. Slow beats clever.</p>", "check": {"question": "What is the safest way to answer a ''what does this code output?'' question?", "options": ["Read the whole program quickly and write down the answer that looks the most likely based on the variable names", "Build a trace table and work through one line at a time, writing each variable''s new value as it changes", "Run the code in your head as fast as you can so you do not run out of time for the other questions on the paper", "Count the number of lines of code in the program, since that is usually equal to the value it will output"], "answer": 1, "explain": "Tracing line by line in a table, updating each variable as it changes, is the reliable method — guessing from names is not."}}, {"title": "MOD and DIV: show the working", "html": "<p>You''ll be asked to work out <code>MOD</code> and <code>DIV</code> results, and to use them (e.g. testing for even, splitting into groups). Do it in two steps:</p>\n<ul>\n<li>First find the <strong>whole number of times</strong> the divisor goes in — that''s the <strong>DIV</strong> answer.</li>\n<li>Then find what''s <strong>left over</strong> — that''s the <strong>MOD</strong> answer.</li>\n</ul>\n<p><strong>Worked:</strong> <code>30 DIV 7</code> → 7 goes into 30 four times (28), so <strong>DIV = 4</strong>; 30 − 28 = 2 left over, so <code>30 MOD 7</code> <strong>= 2</strong>. And remember the classic use: <code>n MOD 2 == 0</code> tests whether <code>n</code> is even.</p>", "check": {"question": "Using the two-step method, what are  30 DIV 7  and  30 MOD 7 ?", "options": ["DIV is 2 and MOD is 4, because 30 MOD 7 counts how many whole times seven divides into thirty altogether", "DIV is 4 and MOD is 2, because 7 goes into 30 four times (28) with 2 left over", "DIV is 4.3 and MOD is 0, because seven divides into thirty exactly with only a small decimal part remaining", "DIV is 7 and MOD is 30, because DIV always gives the divisor and MOD always gives the original number back"], "answer": 1, "explain": "7 into 30 is 4 whole times (28), so DIV = 4; 30 − 28 = 2 left over, so MOD = 2."}}, {"title": "Naming the constructs and choosing the right loop", "html": "<p>Questions frequently ask you to <strong>name</strong> the three constructs, or to <strong>choose and justify</strong> a loop. Keep the definitions crisp:</p>\n<ul>\n<li><strong>Sequence</strong> — steps in order. <strong>Selection</strong> — choose a path (<code>if</code>). <strong>Iteration</strong> — repeat (loop).</li>\n<li><strong>for</strong> loop → when you <strong>know</strong> the number of repeats. <strong>while / do-until</strong> → when you <strong>don''t</strong> (repeat until a condition changes).</li>\n</ul>\n<p>If a question says \"repeat until the user enters a valid value\" or \"keep going while there is more data\", that''s a <strong>condition-controlled</strong> loop — the count isn''t known ahead of time. \"Do this for each of the 5 items\" is <strong>count-controlled</strong>.</p>", "check": {"question": "A question asks you to justify using a while loop rather than a for loop for validating user input. What is the best justification?", "options": ["A while loop is always faster than a for loop, so it should be chosen whenever a program needs to run quickly", "You cannot know in advance how many times the user will enter invalid data, so the number of repeats is unknown", "A for loop cannot contain an if statement inside it, whereas a while loop is able to make decisions as it repeats", "A while loop uses less memory than a for loop because it does not need to store a counter variable anywhere at all"], "answer": 1, "explain": "Validation repeats an unknown number of times (until the input is valid), so a condition-controlled while loop fits — not a fixed for loop."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick <strong>one</strong> box to identify the programming construct that repeats a block of instructions.</p>", "marks": 1, "hint": "Which word means ''repeating''?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Iteration</strong></li></ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Only the correct option scores; 2 or more ticks scores 0.</li></ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box to give the value of  <strong>19 MOD 4</strong>.</p>", "marks": 1, "hint": "MOD gives the remainder. How many are left over after taking 4s out of 19?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>3</strong> (4 goes into 19 four times = 16, leaving a remainder of 3)</li></ul>\n</div>"}, {"question": "<p>State <strong>one</strong> difference between a <strong>variable</strong> and a <strong>constant</strong>.</p>", "marks": 2, "hint": "Think about which one can change its value while the program is running.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>Award 1 mark for: a variable''s value can change while the program runs.</li>\n<li>Award 1 mark for: a constant''s value is fixed and cannot change while the program runs.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Both sides of the contrast are needed for full marks.</li></ul>\n</div>"}, {"question": "<p>Give the value of each of the following:</p><p>(a) <strong>26 DIV 5</strong>  <strong>[1]</strong><br>(b) <strong>26 MOD 5</strong>  <strong>[1]</strong></p>", "marks": 2, "hint": "First find how many whole 5s are in 26 (that''s DIV), then what is left over (that''s MOD).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>(a) <strong>5</strong> — 5 goes into 26 five whole times (25)</li>\n<li>(b) <strong>1</strong> — 26 − 25 leaves a remainder of 1</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to identify the type of each operator.</p>", "marks": 4, "hint": "Arithmetic operators do maths; comparison operators compare two values; Boolean operators combine conditions.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>MOD → <strong>Arithmetic</strong></li>\n<li>!= → <strong>Comparison</strong></li>\n<li>AND → <strong>Boolean</strong></li>\n<li>&gt;= → <strong>Comparison</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Each row is marked independently; 2+ ticks in a row scores 0 for that row.</li></ul>\n</div>"}, {"question": "<p>Draw <strong>one</strong> line from each operator to what it does.</p><p>(There are more descriptions than operators — one description is not used.)</p>", "marks": 4, "hint": "Watch the decoy: ''gives the remainder'' describes MOD, which is not one of the four operators listed.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per correct line)</h5>\n<ul>\n<li>DIV → <strong>A</strong> (whole number of times one value divides into another)</li>\n<li>== → <strong>B</strong> (true when two values are equal)</li>\n<li>^ → <strong>C</strong> (raises a number to a power)</li>\n<li>OR → <strong>D</strong> (true when at least one condition is true)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>1 mark per correct line. Description E (''gives the remainder'') is a decoy describing MOD, and is not used.</li></ul>\n</div>"}, {"question": "<p>Complete the paragraph about the three programming constructs by selecting terms from the list. <strong>Not all terms are used.</strong></p>", "marks": 3, "hint": "Order → one; choosing a path → one; repeating → one. Several terms are decoys.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark for each completed term)</h5>\n<p>In a program, <strong>sequence</strong> means the instructions are carried out in order, one after another. <strong>Selection</strong> chooses which instructions to run based on whether a condition is true. <strong>Iteration</strong> repeats a block of instructions.</p>\n</div>"}, {"question": "<p>The algorithm below uses a count-controlled loop.</p><pre>total = 0\nfor i = 1 to 4\n  total = total + i\nnext i\nprint(total)</pre>\n<p>Complete the trace table to show the value of <strong>i</strong> and <strong>total</strong> at the end of each pass of the loop.</p>", "marks": 4, "hint": "Start with total = 0. Each pass adds the current i to total: 0+1, then +2, then +3, then +4.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per correct row of the trace)</h5>\n<ul>\n<li>Pass 1 → i = 1, total = 1</li>\n<li>Pass 2 → i = 2, total = 3</li>\n<li>Pass 3 → i = 3, total = 6</li>\n<li>Pass 4 → i = 4, total = 10</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>1 mark for each fully-correct row of the trace (both columns right). The program finally outputs 10.</li></ul>\n</div>"}, {"question": "<p>The algorithm below should add up the numbers from 1 to 5 and print the total.</p><p>Complete the three gaps.</p>", "marks": 3, "hint": "The loop must run for the numbers 1 to 5; each pass should add i onto the running total; finally output the total.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per gap)</h5>\n<ul>\n<li>Gap 1: <strong>5</strong></li>\n<li>Gap 2: <strong>+</strong></li>\n<li>Gap 3: <strong>total</strong></li>\n</ul>\n</div>"}, {"question": "<p>A program needs to keep asking the user to enter a password until they type the correct one.</p><p>State which type of iteration (count-controlled or condition-controlled) is most suitable, and give <strong>one</strong> reason.</p>", "marks": 2, "hint": "Do you know in advance how many attempts the user will need?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>1 mark: condition-controlled (while or do-until)</li>\n<li>1 mark: the number of repetitions is not known in advance (it depends on how many tries the user takes)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>The reason must link to the number of repetitions being unknown.</li></ul>\n</div>"}, {"question": "<p>Explain what the following algorithm outputs, and why.</p><pre>x = 10\nif x &gt; 5 AND x &lt; 20 then\n  print(\"in range\")\nelse\n  print(\"out of range\")\nendif</pre>", "marks": 3, "hint": "Work out whether BOTH parts of the AND condition are true for x = 10.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks</h5>\n<ul>\n<li>1 mark: output is <strong>in range</strong></li>\n<li>1 mark: 10 &gt; 5 is true</li>\n<li>1 mark: 10 &lt; 20 is also true, and AND requires both sides true, so the first branch runs</li>\n</ul>\n</div>"}, {"question": "<p>Write an algorithm, using pseudocode, that:</p><ul><li>asks the user to enter a whole number, and</li><li>prints <strong>\"even\"</strong> if the number is even, or <strong>\"odd\"</strong> if it is not.</li></ul><p>You may answer in OCR Exam Reference Language or in a high-level language you know.</p>", "marks": 4, "hint": "Read the number in, then use MOD 2 to test whether the remainder is 0 (even). Use selection (if…else).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks — mark the logic (accept any equivalent code)</h5>\n<ul>\n<li>1 mark: inputs a number</li>\n<li>1 mark: uses MOD 2 to find the remainder</li>\n<li>1 mark: correct selection (remainder 0 → even, else odd)</li>\n<li>1 mark: outputs the correct word in each branch</li>\n</ul>\n<p>Example (ERL):</p>\n<div class=\"code-block\">number = input(\"Enter a whole number: \")\nif number MOD 2 == 0 then\n  print(\"even\")\nelse\n  print(\"odd\")\nendif</div>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Any logically correct answer scores full marks — mark the logic, not the exact wording or choice of language.</li></ul>\n</div>"}]}}'::jsonb),
('computer-science', '2-2-2-data-types', '2.2.2 Data Types', '{"learn": {"enabled": true, "items": [{"title": "The five data types", "html": "<h4>Every value in a program has a data type</h4>\n<ul>\n<li>A <strong>data type</strong> tells the computer what <strong>kind</strong> of value is being stored, and what can be done with it. The OCR specification names <strong>five</strong> data types you must know.</li>\n<li><strong>Integer</strong> — a whole number, with no decimal part (e.g. <code>17</code>, <code>-4</code>).</li>\n<li><strong>Real</strong> (also called <strong>float</strong>) — a number that has a decimal part (e.g. <code>3.14</code>, <code>0.5</code>).</li>\n<li><strong>Boolean</strong> — one of only two values: <code>true</code> or <code>false</code>.</li>\n<li><strong>Character</strong> — a <strong>single</strong> letter, digit or symbol (e.g. <code>''A''</code>, <code>''7''</code>, <code>''!''</code>).</li>\n<li><strong>String</strong> — a <strong>sequence</strong> of characters, i.e. text of any length (e.g. <code>\"Hello\"</code>, <code>\"GCSE\"</code>).</li>\n</ul>", "check": {"question": "Which data type stores one whole number, such as 42, with no decimal part?", "options": ["Real, because a real number is simply any ordinary number that a program is able to store and work with", "Integer", "Boolean", "Character"], "answer": 1, "explain": "Integer stores a whole number with no decimal part. Real (float) is for numbers that DO have a decimal part."}}, {"title": "Integer", "html": "<h4>Whole numbers, positive or negative</h4>\n<ul>\n<li>An <strong>integer</strong> stores a <strong>whole number</strong> — it never has a decimal part.</li>\n<li>Use it for things that are naturally counted in whole units: someone''s <strong>age in complete years</strong>, a <strong>score</strong>, the <strong>number of items</strong>, a <strong>year</strong>.</li>\n</ul>\n<div class=\"code-block\">age = 15\nlives = 3\nyear = 2026</div>\n<ul>\n<li>An integer can be negative (e.g. a temperature of <code>-4</code>), but it can never store a fractional value like <code>15.5</code>.</li>\n</ul>", "check": {"question": "Which of these is most suitable for storing as an integer?", "options": ["The average height of a class of students in metres, worked out to two decimal places such as 1.63", "The number of students in a class", "The exact amount of rainfall recorded in millimetres, such as 12.7", "A single character representing a student''s exam grade, such as ''B''"], "answer": 1, "explain": "The number of students is always a whole number, so it suits an integer. Height and rainfall need decimal places (real), and a grade letter is a character."}}, {"title": "Real (float)", "html": "<h4>Numbers with a decimal part</h4>\n<ul>\n<li>A <strong>real</strong> number (also called a <strong>float</strong>) can store a value <strong>with a decimal part</strong>.</li>\n<li>Use it whenever a value could reasonably need decimal places: a <strong>height</strong>, a <strong>weight</strong>, an <strong>average</strong>, a <strong>price</strong>.</li>\n</ul>\n<div class=\"code-block\">height = 1.72\naverage = 68.5\nprice = 4.99</div>\n<ul>\n<li>Even if a real value happens to be a whole number right now (e.g. an average of <code>70.0</code>), it should still be stored as real if it might need decimal places later.</li>\n</ul>", "check": {"question": "Which of these values is a real (float) value?", "options": ["7, because seven is a perfectly ordinary number and every ordinary number counts as a real value", "3.5", "true", "''X''"], "answer": 1, "explain": "3.5 has a decimal part, so it is a real (float) value. 7 alone is a whole number (integer); true is Boolean; ''X'' is a character."}}, {"title": "Boolean", "html": "<h4>Only ever true or false</h4>\n<ul>\n<li>A <strong>Boolean</strong> stores exactly <strong>one of two values</strong>: <code>true</code> or <code>false</code>. Nothing else can be stored in it.</li>\n<li>Use it for a <strong>yes/no</strong> or <strong>on/off</strong> fact: is the player still alive, is a customer a member, has the form been filled in.</li>\n</ul>\n<div class=\"code-block\">isMember = true\ngameOver = false\nisRaining = false</div>\n<ul>\n<li>A comparison such as <code>score &gt; 50</code> also produces a Boolean result (true or false) — that is why Boolean values are what conditions in <code>if</code> and <code>while</code> are built from.</li>\n</ul>", "check": {"question": "Which data type is most suitable for storing whether a light switch is currently on?", "options": ["String, because the words ''on'' and ''off'' are pieces of text and text always has to be stored as a string", "Boolean", "Character", "Integer"], "answer": 1, "explain": "A switch has exactly two states, so it suits a Boolean (true/false) — not a string, which would need to be compared as text."}}, {"title": "Character", "html": "<h4>Exactly one letter, digit or symbol</h4>\n<ul>\n<li>A <strong>character</strong> stores <strong>a single</strong> letter, digit or symbol — never more than one.</li>\n<li>Use it for a value that can <strong>never be more than one symbol</strong>: an <strong>initial</strong>, a <strong>grade letter</strong>, a single key the user has pressed.</li>\n</ul>\n<div class=\"code-block\">initial = ''M''\ngrade = ''B''\nkey = ''!''</div>\n<ul>\n<li>Character is <strong>not</strong> the same as a short string. <code>''A''</code> is a character; <code>\"AB\"</code> or even <code>\"A\"</code> written with double quotes as text of any length is a string.</li>\n</ul>", "check": {"question": "A program stores a single letter representing a student''s exam grade (e.g. ''B''). Which data type is most suitable?", "options": ["String, because a string is able to hold letters and a single letter is nothing more than very short text", "Character", "Integer", "Boolean"], "answer": 1, "explain": "A value that is always exactly one letter, digit or symbol is a character. A string would suit text that could be more than one character."}}, {"title": "String", "html": "<h4>A sequence of characters — text of any length</h4>\n<ul>\n<li>A <strong>string</strong> stores a <strong>sequence of characters</strong> — that is, text made up of any number of characters, including none at all (an <strong>empty string</strong>, <code>\"\"</code>).</li>\n<li>Use it for <strong>names</strong>, <strong>addresses</strong>, <strong>sentences</strong> — any text that could be more than one character.</li>\n</ul>\n<div class=\"code-block\">name = \"Priya Kaur\"\naddress = \"12 Elm Road\"\nmessage = \"Well done!\"</div>\n<ul>\n<li>Strings are written in <strong>quote marks</strong> in code. Even a string of digits, such as <code>\"2026\"</code>, is text — it cannot be used in a calculation until it is cast to a number.</li>\n</ul>", "check": {"question": "Which data type is most suitable for storing a customer''s full postal address?", "options": ["Character, because character is the data type used for any piece of text that a program needs to store", "String", "Real", "Boolean"], "answer": 1, "explain": "An address is a sequence of characters of varying length, so it needs a string. Character can only hold a single symbol."}}, {"title": "Why casting is needed", "html": "<h4>Converting a value from one data type to another</h4>\n<ul>\n<li><strong>Casting</strong> means converting a value from one data type to another.</li>\n<li>The most common reason it is needed: the function <code>input(...)</code> <strong>always returns a string</strong>, even if the user types digits. To do maths with that value, it must first be cast to a number.</li>\n</ul>\n<div class=\"code-block\">age = input(\"How old are you? \")   // age is the STRING \"15\", not the number 15\nnextYear = age + 1                 // ERROR — a string cannot be added to a number</div>\n<ul>\n<li>Casting is also needed when <strong>joining a number onto text</strong> with <code>+</code> — the number must first be cast to a string, or the same error occurs.</li>\n</ul>", "check": {"question": "Why does the line  nextYear = age + 1  cause an error if age was set using input()?", "options": ["It does not cause an error, because input() always returns a whole number that is ready to be used in a calculation", "input() returns age as a string, and a string cannot be added directly to an integer without casting", "The variable age has not been given a name yet, so the computer has nowhere to store the result of the sum", "The + symbol can only be used with Boolean values, never with numbers of any kind at all"], "answer": 1, "explain": "input() always returns a string, so age holds text, not a number. It must be cast (e.g. with int()) before 1 can be added to it."}}, {"title": "The casting functions", "html": "<h4>str(), int(), float() and bool()</h4>\n<ul>\n<li><code>str(x)</code> — casts <code>x</code> to a <strong>string</strong>. Needed before joining a number onto text with <code>+</code>.</li>\n<li><code>int(x)</code> — casts <code>x</code> to an <strong>integer</strong>. If <code>x</code> has a decimal part, it is <strong>dropped</strong> (not rounded).</li>\n<li><code>float(x)</code> (sometimes written <code>real(x)</code>) — casts <code>x</code> to a <strong>real</strong> number.</li>\n<li><code>bool(x)</code> — casts <code>x</code> to a <strong>Boolean</strong>.</li>\n</ul>\n<div class=\"code-block\">age = int(input(\"Enter your age: \"))\nprint(\"Next year you will be \" + str(age + 1))</div>\n<ul>\n<li>Here <code>input()</code> gives a string, <code>int(...)</code> converts it to a whole number so <code>+ 1</code> works, and <code>str(...)</code> converts the result back to a string so it can be joined onto the message.</li>\n</ul>", "check": {"question": "What does int(8.9) evaluate to?", "options": ["9, because int() rounds a real number up or down to whichever whole number is closest to it", "8", "8.9", "0"], "answer": 1, "explain": "int() drops (truncates) the decimal part rather than rounding, so int(8.9) gives 8, not 9."}}, {"title": "Casting: reading the code", "html": "<h4>Tracing a value''s type through a program</h4>\n<ul>\n<li>Exam questions often show a short program and ask what it outputs, or why a line causes an error. Track the <strong>data type</strong> of each variable as you read, not just its value.</li>\n</ul>\n<div class=\"code-block\">price = input(\"Enter the price: \")   // price is a STRING, e.g. \"4.99\"\nprice = float(price)                // price is now a REAL, 4.99\ntotal = price * 3                   // total is a REAL, 14.97\nprint(\"Total: £\" + str(total))      // total is cast to a STRING to join it on</div>\n<ul>\n<li>If the <code>float(price)</code> line was missing, <code>price * 3</code> would try to multiply a string by a number — which fails, because <code>price</code> is still text.</li>\n</ul>", "check": {"question": "In the example above, what would happen if the line  price = float(price)  was removed?", "options": ["Nothing would change — price would still work perfectly in the calculation on the line below it", "The line total = price * 3 would fail, because price would still be a string, not a number", "The program would automatically cast price to a real number anyway, without needing that line", "The final print statement would no longer work, even though the calculation above it would be fine"], "answer": 1, "explain": "Without the cast, price stays a string, so price * 3 fails — a string cannot be used in a numeric calculation."}}, {"title": "Choosing a suitable data type", "html": "<h4>Match the data to the type</h4>\n<ul>\n<li>To choose a data type, ask: <strong>what kind of value is it, and what will be done with it?</strong></li>\n<li><strong>Age</strong> (whole years, used in maths) → <strong>integer</strong>.</li>\n<li><strong>Price</strong> (needs pence) → <strong>real</strong>.</li>\n<li><strong>\"Is a member?\"</strong> (yes/no) → <strong>Boolean</strong>.</li>\n<li><strong>Initial</strong> (always one letter) → <strong>character</strong>.</li>\n<li><strong>Name</strong> (text of any length) → <strong>string</strong>.</li>\n</ul>\n<p>When justifying a choice, always <strong>name the type</strong> and give the <strong>reason it fits this exact data</strong> — not just a general definition of the type.</p>", "check": {"question": "A program stores the number of pets a student owns. Which data type is most suitable, and why?", "options": ["Real, because a decimal point makes any number look more precise and therefore more accurate to work with", "Integer, because the number of pets is always a whole number", "String, because numbers can always be stored as text just as easily as they can be stored as numbers", "Boolean, because owning pets is something that is either completely true or completely false for a student"], "answer": 1, "explain": "The number of pets is counted in whole units, so integer is the suitable type — real and string add nothing needed here."}}, {"title": "Consequences of a poor choice", "html": "<h4>Picking the wrong type causes real problems</h4>\n<ul>\n<li><strong>Price stored as an integer</strong> — the pennies are lost. <code>£4.99</code> can only be stored as <code>4</code>, so totals become inaccurate.</li>\n<li><strong>Age stored as a string</strong> — it cannot be used directly in a calculation without casting first, and nothing stops invalid text such as <code>\"twelve\"</code> being stored.</li>\n<li><strong>Yes/no fact stored as a string</strong> (e.g. <code>\"yes\"</code>) — it cannot be combined with <code>AND</code>/<code>OR</code>/<code>NOT</code> like a real Boolean can, and has to be compared as exact text instead.</li>\n</ul>\n<p>The exam may ask you to <strong>identify the problem</strong> caused by a poor choice, or to <strong>suggest a better type</strong> and explain the improvement.</p>", "check": {"question": "A shop stores each item''s price as an integer instead of a real number. What is the most likely consequence?", "options": ["No consequence, because an integer can store exactly the same values as a real number can", "Amounts with pence, such as £3.49, cannot be stored accurately — the pennies are lost", "The program will crash immediately every single time a price is entered by the user", "Prices will be automatically converted into a string so that they can be displayed on screen"], "answer": 1, "explain": "An integer cannot hold a decimal part, so a price like £3.49 loses its pennies — this causes inaccurate totals."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Integer", "definition": "A whole number, with no decimal part"}, {"term": "Real (float)", "definition": "A number with a decimal part"}, {"term": "Boolean", "definition": "One of only two values — true or false"}, {"term": "Character", "definition": "A single letter, digit or symbol"}, {"term": "String", "definition": "A sequence of characters — text of any length"}, {"term": "Casting", "definition": "Converting a value from one data type to another"}, {"term": "Why casting is needed", "definition": "input() always returns a string, so it must be cast before use in maths"}, {"term": "int()", "definition": "Casts a value to an integer, dropping any decimal part (not rounding)"}, {"term": "float()", "definition": "Casts a value to a real number"}, {"term": "str()", "definition": "Casts a value to a string"}, {"term": "bool()", "definition": "Casts a value to a Boolean"}, {"term": "int(7.9)", "definition": "Gives 7 — the decimal part is dropped, not rounded, to give 7"}, {"term": "Age → data type", "definition": "Integer — a whole number of complete years, used in calculations"}, {"term": "Price → data type", "definition": "Real — needs decimal places (pence)"}, {"term": "\"Is a member?\" → data type", "definition": "Boolean — a yes/no fact"}, {"term": "Price stored as integer", "definition": "A poor choice — the pence are lost, e.g. £4.99 becomes 4"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which data type stores a value that has a decimal part, such as 3.75?", "options": ["Integer, because integer values are perfectly able to include a decimal point somewhere within them", "Real (float)", "Boolean", "Character"], "answer": 1, "explain": "Real (or float) stores numbers with a decimal part. Integer stores only whole numbers."}, {"question": "Which data type stores only one of two values, true or false?", "options": ["String, because the words true and false are pieces of text and so must be stored as a string", "Boolean", "Character", "Integer"], "answer": 1, "explain": "Boolean stores exactly one of two values: true or false."}, {"question": "A program stores a single letter grade such as ''A''. Which data type is most suitable?", "options": ["String, because a string is the data type that is used for holding any letters of the alphabet at all", "Character", "Integer", "Real"], "answer": 1, "explain": "A single letter, digit or symbol is stored as a character. A string is used for a sequence of more than one character."}, {"question": "What is the purpose of casting in a program?", "options": ["Rounding a real number to the nearest whole number so it can be displayed more neatly on screen", "Converting a value from one data type to another", "Comparing two values to see whether they are equal to each other", "Joining two or more separate strings together into one longer string"], "answer": 1, "explain": "Casting converts a value from one data type to another, e.g. from a string to an integer."}, {"question": "In pseudocode/Python, input() always returns a value of which data type?", "options": ["Integer, because any value the user types on the keyboard is treated as a whole number automatically", "String", "Boolean", "Real"], "answer": 1, "explain": "input() always returns a string, even if the user types digits — it must be cast before being used in maths."}, {"question": "Which function is used to convert a value into a whole number?", "options": ["str()", "int()", "bool()", "float()"], "answer": 1, "explain": "int() casts a value to an integer. str() converts to string, bool() to Boolean, float() to real."}, {"question": "What does int(7.9) evaluate to?", "options": ["8, because int() rounds a real number up or down to the nearest whole number automatically", "7", "7.9", "0"], "answer": 1, "explain": "int() drops (truncates) the decimal part rather than rounding, so int(7.9) gives 7, not 8."}, {"question": "Which function converts a number into a string, so it can be joined onto other text with +?", "options": ["int()", "str()", "float()", "bool()"], "answer": 1, "explain": "str() converts a value to a string. Joining a number directly onto text with + causes an error unless it is first cast."}, {"question": "A program stores whether a customer is a member (yes or no). Which data type is most suitable?", "options": ["String, because storing the actual words ''yes'' and ''no'' is the clearest way of recording this fact", "Boolean", "Character", "Integer"], "answer": 1, "explain": "A yes/no fact is best stored as a Boolean (true/false) — it can be used directly in a condition, unlike a string."}, {"question": "A shop''s prices are stored as integers instead of real numbers. What is the most likely consequence?", "options": ["No consequence, because an integer can store exactly the same range and precision as a real number", "Pence are lost — a price like £4.99 can only be stored as 4, losing the .99", "The program will refuse to run, since prices must always be stored as strings", "Prices will automatically be rounded to the nearest ten pounds"], "answer": 1, "explain": "Storing money as an integer discards the decimal part, so £4.99 loses its pennies — this causes inaccurate totals."}, {"question": "Which data type would be most suitable for storing a customer''s full name?", "options": ["Character, because a name is usually short and character is the type reserved for short pieces of text", "String", "Integer", "Boolean"], "answer": 1, "explain": "A name is a sequence of characters of varying length, so it needs a string. Character holds only a single symbol."}, {"question": "Which of the following is a real (float) value?", "options": ["12", "12.5", "true", "''A''"], "answer": 1, "explain": "12.5 has a decimal part, so it is a real (float) value. 12 is an integer, true is Boolean, and ''A'' is a character."}]}, "fib": {"enabled": true, "questions": [{"text": "A(n) [integer] data type stores a whole number, such as 17 or -4."}, {"text": "A [real] (float) data type stores a number with a decimal part, such as 3.14."}, {"text": "A [Boolean] data type stores only one of two values, true or false."}, {"text": "A [character] data type stores a single letter, digit or symbol."}, {"text": "A string is a [sequence] of characters, i.e. text of any length."}, {"text": "Converting a value from one data type to another is called [casting]."}, {"text": "The function [int()] converts a value into a whole number, dropping any decimal part."}, {"text": "The input() function always returns a value of type [string]."}]}, "tf": {"enabled": true, "questions": [{"statement": "An integer can store a number with a decimal part, such as 3.5.", "answer": false, "explain": "An integer stores whole numbers only. A number with a decimal part needs a real (float) data type."}, {"statement": "A Boolean value can only ever be true or false.", "answer": true, "explain": "Correct — Boolean is limited to exactly two values, true and false."}, {"statement": "A character can store more than one letter, such as ''Hi''.", "answer": false, "explain": "A character holds exactly one letter, digit or symbol. A sequence of letters like ''Hi'' needs a string."}, {"statement": "input() always returns a value as a string, even if the user types a number.", "answer": true, "explain": "Correct — input() always returns a string, which is why it often needs to be cast before use in maths."}, {"statement": "int(7.8) rounds the value to give 8.", "answer": false, "explain": "int() does not round — it truncates (drops the decimal part), so int(7.8) gives 7, not 8."}, {"statement": "str() is used to convert a number into a string so it can be joined onto text with +.", "answer": true, "explain": "Correct — a number must be cast to a string with str() before it can be joined onto text with +."}, {"statement": "Storing a price such as £4.99 as an integer keeps the value fully accurate.", "answer": false, "explain": "An integer cannot store the decimal part, so £4.99 loses its pennies and becomes inaccurate."}, {"statement": "Choosing a suitable data type for each piece of data helps keep a program''s values accurate and easy to use correctly.", "answer": true, "explain": "Correct — the right data type avoids lost accuracy (like price as integer) and avoids needing extra casting."}]}, "misc": {"enabled": true, "items": [{"myth": "Thinking int() rounds a decimal number to the nearest whole number.", "truth": "<strong>int()</strong> does not round — it <strong>truncates</strong> (drops) the decimal part, always cutting towards zero. So <code>int(7.9)</code> gives <strong>7</strong>, not 8, and <code>int(-7.9)</code> gives <strong>-7</strong>, not -8.", "check": {"question": "What does int(4.7) give?", "options": ["5, because int() always rounds a decimal number up or down to the nearest whole number", "4", "4.7", "0"], "answer": 1, "explain": "int() truncates (drops) the decimal part rather than rounding, so int(4.7) gives 4."}}, {"myth": "Thinking a character and a string of one letter are exactly the same thing.", "truth": "A <strong>character</strong> can hold only <strong>one</strong> single letter, digit or symbol. A <strong>string</strong> is a <strong>sequence</strong> of characters — it can hold one character, many characters, or even none at all. Choose character only when the data can never be more than a single symbol (e.g. a grade letter).", "check": {"question": "Which statement correctly describes the difference between character and string?", "options": ["There is no real difference between them at all; both data types are always limited to holding exactly one single letter or symbol", "Character holds exactly one symbol; string holds a sequence of any number of characters, including none", "Character is used only for storing numbers, and string is used only for storing letters of the alphabet", "String can only ever hold a single symbol, while character can hold any amount of text"], "answer": 1, "explain": "Character is limited to a single symbol; string can hold any length of text, including an empty string."}}, {"myth": "Forgetting that input() always returns a string, even when the user types digits.", "truth": "Whatever the user types into <code>input(...)</code> is stored as a <strong>string</strong> — typing 15 gives the string <code>\"15\"</code>, not the integer 15. To use it in maths it must first be <strong>cast</strong> with <code>int()</code> or <code>float()</code>.", "check": {"question": "A student types 20 in response to  input(\"Enter a number: \") . What is stored, before any casting takes place?", "options": ["The integer 20, ready to be used straight away in any calculation the program needs to do", "The string \"20\"", "The real number 20.0, because input() always adds a decimal point automatically", "Nothing is stored, because input() cannot accept numbers typed by the user at all"], "answer": 1, "explain": "input() always returns a string, so \"20\" is stored as text, not as the number 20, until it is cast."}}, {"myth": "Believing a data type choice makes no real difference as long as the value ''looks right'' when printed.", "truth": "A poor choice can quietly cause errors or lost accuracy — e.g. storing a <strong>price</strong> as an <strong>integer</strong> loses the pennies, and storing an <strong>age</strong> as a <strong>string</strong> means it cannot be used directly in a calculation without casting first.", "check": {"question": "Why does storing a price as an integer rather than a real cause a problem, even if it looks fine on screen at first?", "options": ["It does not cause any problem, since the digits displayed on screen will always still look correct", "It loses the pence, e.g. £4.99 can only be stored as 4, so totals built from it become inaccurate", "The program will refuse to display the price on screen at all if it is stored as an integer", "An integer automatically converts itself into a string the moment it is printed to the screen"], "answer": 1, "explain": "An integer cannot hold a decimal part, so a price such as £4.99 loses its pence — this makes totals inaccurate."}}, {"myth": "Thinking + always adds numbers together, even when the values are strings.", "truth": "When both values are <strong>strings</strong>, <code>+</code> <strong>joins them together</strong> rather than adding numbers. Mixing a string and a number with <code>+</code> (e.g. <code>\"Score: \" + 10</code>) causes an error unless the number is first cast to a string with <code>str()</code>.", "check": {"question": "What does \"Score: \" + str(10) produce?", "options": ["An error, because a string and a number can never be joined together no matter how it is written", "The string \"Score: 10\"", "The number 10, with the text \"Score: \" simply thrown away and ignored", "The Boolean value true, because + is used to compare two values for equality"], "answer": 1, "explain": "str(10) casts 10 to the string \"10\" first, so + can join it onto \"Score: \", giving \"Score: 10\"."}}, {"myth": "Thinking Boolean values must be typed as the words ''true'' and ''false'' in quotes, like a string.", "truth": "A real <strong>Boolean</strong> value is not text — it is not written in quote marks. <code>true</code> is a Boolean; <code>\"true\"</code> is a <strong>string</strong> that merely contains the letters t-r-u-e, and behaves completely differently in a condition.", "check": {"question": "What data type is  \"true\"  (written with quote marks), as opposed to  true  (written without)?", "options": ["It is still a Boolean value, because the word true always means the same thing no matter how it is written", "A string — quote marks always create a string, even if the text inside looks like a Boolean value", "An integer, because quote marks are used in programming to represent the number 1", "A character, because \"true\" is exactly four letters long and characters can be up to four letters"], "answer": 1, "explain": "Quote marks create a string. \"true\" is text containing the letters t-r-u-e — it is not the Boolean value true."}}]}, "tips": {"enabled": true, "items": [{"title": "Choosing a data type: ask two questions", "html": "<p>\"Choose a suitable data type\" and \"justify your choice\" questions come up often. Answer them by asking two questions about the data:</p>\n<ul>\n<li><strong>What kind of value is it?</strong> A whole number → integer. A number that could need decimal places → real. A yes/no fact → Boolean. Always exactly one symbol → character. Any other text → string.</li>\n<li><strong>What will be done with it?</strong> If it needs to be used in a calculation, it must not be a string. If it is compared with AND/OR/NOT, it should be a Boolean, not text like \"yes\".</li>\n</ul>\n<p>When justifying, name the <strong>type</strong> and give the <strong>reason specific to this data</strong> — \"integer, because the number of items is always a whole number\" scores; \"integer, because integers are a data type\" does not.</p>", "check": {"question": "A question asks you to justify storing a student''s age as an integer. Which answer is best?", "options": ["Integer, because integer is one of the five data types listed in the specification", "Integer, because age in complete years is always a whole number", "Integer, because integers can be used in any program for any kind of data at all", "Integer, because it is the first data type that most programmers usually think of"], "answer": 1, "explain": "A good justification links the TYPE to a reason specific to THIS data — age in whole years is naturally a whole number."}}, {"title": "Casting: match the function to the target type", "html": "<p>Questions may show a line of code with a cast missing, or ask you to trace a program''s data types line by line. Keep the four functions straight:</p>\n<ul>\n<li><code>int(x)</code> → integer (decimal part <strong>dropped</strong>, not rounded).</li>\n<li><code>float(x)</code> → real (decimal part kept).</li>\n<li><code>str(x)</code> → string (needed before joining a number onto text with +).</li>\n<li><code>bool(x)</code> → Boolean.</li>\n</ul>\n<p><strong>Worked trace:</strong> <code>n = input(\"Enter a number: \")</code> makes <code>n</code> a string. <code>n = int(n)</code> makes it an integer. <code>print(\"Value: \" + str(n))</code> then casts it back to a string so it can join onto the text — without that last cast, the line would fail.</p>", "check": {"question": "In the worked trace above, why is str(n) needed in the final print line?", "options": ["It is not actually needed at all — the line would carry on working in exactly the same way whether it was included or left out", "Because n is an integer by that point, and a number cannot be joined onto text with + without being cast to a string first", "Because print() is only able to display values that have already been stored using the string data type in the first place", "Because str() is required every single time any variable of any kind is used anywhere at all inside a print statement"], "answer": 1, "explain": "By that point n has been cast to an integer, so it must be cast to a string with str() before + can join it onto text."}}, {"title": "Spotting the consequence of a poor data type choice", "html": "<p>\"Explain the problem caused by storing X as Y\" questions want a <strong>specific</strong> consequence, not just \"it is wrong\". Common patterns:</p>\n<ul>\n<li><strong>Money as integer</strong> → pence are lost, so totals become inaccurate.</li>\n<li><strong>Number as string</strong> → cannot be used in a calculation without casting, and invalid values (like \"twelve\") are not prevented.</li>\n<li><strong>Yes/no fact as string</strong> → cannot be combined with AND/OR/NOT the way a real Boolean can, and must be compared as exact text.</li>\n</ul>\n<p>Always link your answer back to <strong>what the program actually needs to do</strong> with the value.</p>", "check": {"question": "A program stores whether a customer has paid as the string \"yes\" or \"no\", instead of a Boolean. What is a valid consequence to give in an exam answer?", "options": ["There is no real consequence at all, because the strings \"yes\" and \"no\" behave in exactly the same way as the Boolean values true and false", "It cannot be combined directly with AND/OR/NOT like a Boolean, and must instead be compared as exact text", "The program will not be able to store the value \"no\" at all, only ever the value \"yes\"", "Storing it as a string will make the whole program run considerably faster than storing it as a Boolean"], "answer": 1, "explain": "A string like \"yes\" cannot be used directly in a Boolean condition the way true/false can — it needs an exact text comparison."}}]}, "exam": {"enabled": true, "questions": [{"question": "<p>Tick <strong>one</strong> box to identify the data type of the value <strong>true</strong>.</p>", "marks": 1, "hint": "true and false — which data type stores exactly these two values?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Boolean</strong></li></ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Only the correct option scores; 2 or more ticks scores 0.</li></ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box to give the value of  <strong>int(9.6)</strong>.</p>", "marks": 1, "hint": "int() truncates (drops) the decimal part; it does not round.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>9</strong> — int() drops the decimal part rather than rounding, so int(9.6) gives 9, not 10.</li></ul>\n</div>"}, {"question": "<p>State the most suitable data type for each of the following pieces of data.</p><p>(a) A person''s shoe size, e.g. 8  <strong>[1]</strong><br>(b) The average speed of a car in mph, e.g. 62.4  <strong>[1]</strong></p>", "marks": 2, "hint": "Does the value ever need a decimal part, or is it always a whole number?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>(a) <strong>Integer</strong> — a shoe size is a whole number</li>\n<li>(b) <strong>Real (float)</strong> — an average speed can need a decimal part</li>\n</ul>\n</div>"}, {"question": "<p>A programmer writes the following code.</p><pre>age = input(\"Enter your age: \")\nprint(age + 5)</pre><p>Explain why this code produces an error.</p>", "marks": 2, "hint": "What data type does input() always return, and can that be added to a number directly?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks</h5>\n<ul>\n<li>Award 1 mark for: input() always returns a string, so age holds a string, not a number.</li>\n<li>Award 1 mark for: a string cannot be added directly to an integer — age would need to be cast with int() first.</li>\n</ul>\n</div>"}, {"question": "<p>Tick <strong>one</strong> box in each row to identify the most suitable data type for each variable.</p>", "marks": 4, "hint": "For each row, ask: is it always a whole number, does it need decimal places, is it a yes/no fact, or is it text?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark for each row)</h5>\n<ul>\n<li>Number of pets → <strong>Integer</strong></li>\n<li>Average rainfall → <strong>Real</strong></li>\n<li>Has a bus pass → <strong>Boolean</strong></li>\n<li>Home address → <strong>String</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Each row is marked independently; 2+ ticks in a row scores 0 for that row.</li></ul>\n</div>"}, {"question": "<p>Draw <strong>one</strong> line from each casting function to what it does.</p><p>(There are more descriptions than functions — one description is not used.)</p>", "marks": 4, "hint": "Watch the decoy: ''converts to a single character'' does not match any of the four functions listed.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark per correct line)</h5>\n<ul>\n<li>int() → <strong>A</strong> (whole number, decimal part dropped)</li>\n<li>float() → <strong>B</strong> (real/decimal number)</li>\n<li>str() → <strong>C</strong> (string)</li>\n<li>bool() → <strong>D</strong> (Boolean, true/false)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>1 mark per correct line. Description E (''converts to a single character'') is a decoy, and is not used.</li></ul>\n</div>"}, {"question": "<p>Complete the paragraph about casting by selecting terms from the list. <strong>Not all terms are used.</strong></p>", "marks": 3, "hint": "What does input() return? What is the general name for converting between types? Which function turns a value into a string?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark for each completed term)</h5>\n<p>The function <code>input()</code> always returns a value of type <strong>string</strong>. Converting a value from one data type to another is called <strong>casting</strong>. To join a number onto text using +, the number must first be converted using <strong>str()</strong>.</p>\n</div>"}, {"question": "<p>Complete the table by giving the most suitable data type for each data item.</p>", "marks": 4, "hint": "Whole number? Single symbol? Yes/no fact? Needs decimal places?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark each)</h5>\n<ul>\n<li>Number of goals → <strong>Integer</strong></li>\n<li>Exam grade letter → <strong>Character</strong></li>\n<li>In stock (yes/no) → <strong>Boolean</strong></li>\n<li>Price in pounds → <strong>Real (float)</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Each row is marked independently.</li></ul>\n</div>"}, {"question": "<p>The algorithm below asks for the price and quantity of an item, then works out and displays the total cost.</p><p>Complete the three gaps.</p>", "marks": 3, "hint": "Price needs decimal places, quantity is always a whole number, and the final total must become a string before it can be joined onto text with +.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 3 marks (1 mark per gap)</h5>\n<ul>\n<li>Gap 1: <strong>float</strong> (casts price to a real number)</li>\n<li>Gap 2: <strong>int</strong> (casts quantity to an integer)</li>\n<li>Gap 3: <strong>str</strong> (casts total to a string so it can join onto the text)</li>\n</ul>\n</div>"}, {"question": "<p>A program stores a customer''s age as a string instead of an integer.</p><p>State <strong>two</strong> problems this could cause.</p>", "marks": 2, "hint": "Think about what you can and cannot do with a string that you could do with an integer.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (1 mark for each valid problem, up to 2)</h5>\n<ul>\n<li>The age cannot be used directly in a calculation (e.g. adding 1 to find next year''s age) without casting it to an integer first.</li>\n<li>A string does not stop invalid, non-numeric data being stored, such as \"twelve\" or \"old\".</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Accept any two distinct, valid problems linked to storing age as a string.</li></ul>\n</div>"}, {"question": "<p>A program stores data about a library book: its <strong>title</strong>, the <strong>number of pages</strong>, whether it is <strong>currently on loan</strong>, and its <strong>average star rating</strong> (e.g. 4.3).</p><p>State the most suitable data type for each piece of data.</p>", "marks": 4, "hint": "Text of any length? Always a whole number? A yes/no fact? Could need a decimal part?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (1 mark each)</h5>\n<ul>\n<li>Title → <strong>String</strong></li>\n<li>Number of pages → <strong>Integer</strong></li>\n<li>Currently on loan → <strong>Boolean</strong></li>\n<li>Average star rating → <strong>Real (float)</strong></li>\n</ul>\n</div>"}]}}'::jsonb)
